class Strategy_BENEVOLENT_5(BaseStrategy):
    """
    Cooperative-first common-pool strategy with rare defensive defection under
    sustained broad defection and stressed stock.

    Memory used:
    - current stock via current_stock argument
    - opponent cooperation counts from the last two rounds via history
    - whether the player defected in the previous round via history.my_actions[-1]
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.low_stock = self.capacity / 3.0
        self.critical_stock = self.capacity / 5.0
        self.sustained_defection_threshold = math.floor((self.n - 1) / 2)
        self.broad_coop_threshold = self.n - 2
        self.very_low_coop_threshold = math.floor((self.n - 1) / 3)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        if round_number == 0:
            return Action.C
        if round_number >= self.r - 1:
            return Action.C
        if current_stock <= self.critical_stock:
            return Action.C
        if len(history.opponent_cooperators) >= 1:
            if history.opponent_cooperators[-1] >= self.broad_coop_threshold:
                return Action.C
        if current_stock <= self.low_stock and len(history.opponent_cooperators) >= 2:
            last_two = history.opponent_cooperators[-2:]
            sustained_defection = last_two[-1] <= self.sustained_defection_threshold and last_two[-2] <= self.sustained_defection_threshold
            very_low_coop_in_last_two = any((coop <= self.very_low_coop_threshold for coop in last_two))
            if sustained_defection and very_low_coop_in_last_two:
                if len(history.my_actions) >= 1 and (not bool(history.my_actions[-1])):
                    return Action.D
                return Action.D
        return Action.C

class Strategy_BENEVOLENT_6(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Opens cooperatively
    - Tracks exponentially weighted opponent cooperation (qbar)
    - Uses a strike system to punish repeated low cooperation
    - Defects more in the final third unless cooperation and stock remain healthy
    - Always cooperates in the first and last rounds
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(0, self.n_players - 1)
        self.qbar = 1.0
        self.strike = 0
        self.forced_defect_next = False
        self.last_seen_rounds = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        current_round = round_number + 1
        last_round = current_round >= self.n_rounds
        if round_number > self.last_seen_rounds:
            self.last_seen_rounds = round_number
        if round_number >= 1:
            k_prev = int(history.opponent_cooperators[-1])
            denom = self.n_opponents if self.n_opponents > 0 else 1
            q_prev = k_prev / denom
            q_prev = min(1.0, max(0.0, q_prev))
            if q_prev >= 0.5:
                self.strike = 0
            elif q_prev < 0.25:
                self.strike += 1
            else:
                self.strike = max(0, self.strike - 1)
            qbar_new = 0.7 * self.qbar + 0.3 * q_prev
            if self.n_opponents > 0:
                high_threshold = math.ceil(0.6 * self.n_opponents)
                low_threshold = math.floor(0.2 * self.n_opponents)
                if k_prev >= high_threshold:
                    qbar_new = min(1.0, qbar_new + 0.1)
                elif k_prev <= low_threshold:
                    qbar_new = max(0.0, qbar_new - 0.2)
            self.qbar = min(1.0, max(0.0, qbar_new))
            self.forced_defect_next = self.strike >= 2 and current_round < self.n_rounds - 1 and (current_stock >= 0.25 * self.capacity)
        else:
            self.qbar = min(1.0, max(0.0, self.qbar))
        if current_round == 1 or last_round:
            return Action.C
        if self.forced_defect_next:
            return Action.D
        if current_stock < 0.25 * self.capacity:
            return Action.C
        if current_stock >= 0.75 * self.capacity:
            return Action.C
        if current_round > 2 * self.n_rounds / 3:
            if self.qbar >= 0.5 and current_stock >= 0.3 * self.capacity:
                return Action.C
            return Action.D
        if self.qbar >= 0.45 and current_stock >= self.capacity * (0.35 + 0.3 * self.qbar):
            return Action.C
        return Action.D

class Strategy_BENEVOLENT_7(BaseStrategy):
    """
    Cooperative default strategy with short, cautious corrective defections
    when recent cooperation is persistently low and the stock remains healthy.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.upper_bound = 0.9 * self.capacity
        self.lower_bound = 0.6 * self.capacity
        self._coop_rate_memory = []
        self._last_action = Action.C
        self._last_defection_round = -10 ** 9

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        S = float(current_stock)
        if round_number >= self.r - 1:
            self._last_action = Action.C
            return Action.C
        if round_number == 0:
            self._last_action = Action.C
            return Action.C
        n_opponents = max(self.n - 1, 1)
        if len(history.opponent_cooperators) > 0:
            c = int(history.opponent_cooperators[-1])
            coop_rate = max(0.0, min(1.0, c / n_opponents))
        else:
            coop_rate = 1.0
        self._coop_rate_memory.append(coop_rate)
        if len(self._coop_rate_memory) > 3:
            self._coop_rate_memory = self._coop_rate_memory[-3:]
        avg_coop = float(np.mean(self._coop_rate_memory)) if self._coop_rate_memory else 1.0
        if S <= 0 or S <= self.lower_bound / 2:
            self._last_action = Action.C
            return Action.C
        if avg_coop >= 0.5:
            self._last_action = Action.C
            return Action.C
        prev_action = Action.C
        if len(history.my_actions) > 0:
            prev_action = Action.C if bool(history.my_actions[-1]) else Action.D
        if prev_action == Action.D:
            if not (coop_rate == 0.0 and S > self.lower_bound / 2):
                self._last_action = Action.C
                return Action.C
        if prev_action == Action.D and coop_rate >= 0.2:
            self._last_action = Action.C
            return Action.C
        action = Action.C
        if S >= self.upper_bound:
            if coop_rate < 0.25 and S > self.lower_bound:
                action = Action.D
        elif S > self.lower_bound:
            low_two_rounds = False
            if len(self._coop_rate_memory) >= 2:
                low_two_rounds = self._coop_rate_memory[-1] < 0.2 and self._coop_rate_memory[-2] < 0.2
            if low_two_rounds:
                action = Action.D
        elif coop_rate == 0.0 and S > self.lower_bound / 3.0:
            action = Action.D
        if prev_action == Action.D and action == Action.D:
            if not (coop_rate == 0.0 and S > self.lower_bound / 2):
                action = Action.C
        self._last_action = action
        if action == Action.D:
            self._last_defection_round = round_number
        return action

class Strategy_BENEVOLENT_8(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Cooperate in round 1.
    - In later rounds, cooperate when resource stock is healthy and recent cooperation is sufficiently high.
    - Defect when stock is depleted, or after a severe low-cooperation shock, but only for one round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self._last_start_stock = None
        self._last_k = None
        self._last_round_number = None

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        capacity = float(self.game_description.capacity)
        round_number = history.round_number
        if round_number == self.game_description.n_rounds - 1:
            self._last_start_stock = float(current_stock)
            self._last_k = int(history.opponent_cooperators[-1]) if round_number > 0 else None
            self._last_round_number = round_number
            return Action.C if current_stock > 0 else Action.D
        if round_number == 0:
            self._last_start_stock = float(current_stock)
            self._last_k = None
            self._last_round_number = round_number
            return Action.C
        k = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        prev_k = self._last_k
        prev_start_stock = self._last_start_stock
        low_stock_threshold = capacity / 8.0
        mid_stock_threshold = capacity / 4.0
        high_stock_threshold = 3.0 * capacity / 4.0
        recovery_threshold = capacity / 3.0
        majority_threshold = math.ceil((n - 1) / 2)
        action = Action.D
        if current_stock <= low_stock_threshold:
            action = Action.D
        elif current_stock >= high_stock_threshold:
            fell_last_round = False
            if prev_start_stock is not None:
                fell_last_round = current_stock < prev_start_stock
            if prev_k == 0 and fell_last_round:
                action = Action.D
            else:
                action = Action.C
        elif current_stock >= mid_stock_threshold and k >= majority_threshold and (current_stock >= recovery_threshold or k == n - 1):
            action = Action.C
        else:
            action = Action.D
        self._last_start_stock = float(current_stock)
        self._last_k = k
        self._last_round_number = round_number
        return action

class Strategy_BENEVOLENT_9(BaseStrategy):
    """
    Adaptive common-pool strategy with a cooperation target updated from
    observed opponent cooperation rates and modified by stock-based overrides.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(getattr(game_description, 'n_players', 0) or 0)
        self.n_rounds = int(getattr(game_description, 'n_rounds', 0) or 0)
        self.capacity = float(getattr(game_description, 'capacity', 0.0) or 0.0)
        self.n_opponents = max(0, self.n_players - 1)
        self.p_target = 1.0
        self.last_round_number = -1

    def _coop_rate(self, opponent_count: int) -> float:
        if self.n_opponents <= 0:
            return 0.0
        return float(opponent_count) / float(self.n_opponents)

    def _updated_target_from_history(self, history: PlayerHistory) -> float:
        p = 1.0
        try:
            rounds_done = int(history.round_number)
            if rounds_done <= 0:
                return 1.0
            opp_counts = history.opponent_cooperators
            limit = min(rounds_done, len(opp_counts))
            for r in range(limit):
                x = self._coop_rate(int(opp_counts[r]))
                if x >= 0.75:
                    p = min(1.0, p + 0.1)
                elif x >= 0.4:
                    p = p
                elif x >= 0.2:
                    p = max(0.5, p - 0.15)
                else:
                    p = max(0.2, p - 0.25)
            return float(p)
        except Exception:
            return 1.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        try:
            if history is None:
                self.p_target = 1.0
                return Action.C
            round_number = int(getattr(history, 'round_number', 0) or 0)
            S_t = float(current_stock)
            if round_number <= 0:
                self.p_target = 1.0
                self.last_round_number = round_number
                return Action.C
            p_t = self._updated_target_from_history(history)
            self.p_target = p_t
            self.last_round_number = round_number
            t = round_number + 1
            r = max(1, self.n_rounds)
            cap = self.capacity
            x_prev = None
            x_prev2 = None
            try:
                if len(history.opponent_cooperators) >= 1:
                    x_prev = self._coop_rate(int(history.opponent_cooperators[-1]))
                if len(history.opponent_cooperators) >= 2:
                    x_prev2 = self._coop_rate(int(history.opponent_cooperators[-2]))
            except Exception:
                x_prev = None
                x_prev2 = None
            action = Action.C if p_t >= 0.5 and S_t > 0.0 else Action.D
            if S_t <= 0.0:
                return Action.C
            if t == r:
                return Action.C
            if t == r - 1 and S_t > cap / 4.0:
                return Action.C
            if S_t < cap / 8.0:
                if x_prev is not None and x_prev < 0.2:
                    return Action.D
                return Action.C
            if S_t >= cap / 2.0:
                return Action.C
            if x_prev2 is not None and x_prev is not None and (x_prev2 >= 0.75) and (x_prev >= 0.75):
                return Action.C
            if x_prev2 is not None and x_prev is not None and (x_prev2 < 0.2) and (x_prev < 0.2):
                self.p_target = 0.2
                return Action.D
            return action
        except Exception:
            self.p_target = 1.0
            return Action.C

class Strategy_BENEVOLENT_10(BaseStrategy):
    """
    Near-full replenishment strategy for the common pool resource game.

    - Cooperates in the first round.
    - Defects when stock is severely depleted.
    - Cooperates in healthy/moderate stock regimes only if recent opponent
      cooperation is sufficiently high.
    - Plays conservatively in the final round based on current stock.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(0, self.n_players - 1)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        if round_number == 0:
            return Action.C
        if current_stock <= 0.0:
            return Action.D
        if round_number == self.n_rounds - 1:
            return Action.C if current_stock >= self.capacity / 2.0 else Action.D
        if self.n_opponents > 0:
            prev_opponent_cooperators = int(history.opponent_cooperators[-1])
            q_prev = prev_opponent_cooperators / float(self.n_opponents)
        else:
            q_prev = 0.0
        low_threshold = self.capacity / 4.0
        healthy_threshold = self.capacity / 2.0
        if current_stock <= low_threshold:
            return Action.D
        if current_stock >= healthy_threshold:
            return Action.C if q_prev >= 0.5 else Action.D
        return Action.C if q_prev >= 0.75 else Action.D

class Strategy_BENEVOLENT_11(BaseStrategy):
    """
    Trust-based common pool strategy:
    - Cooperate in the first and last rounds.
    - In intermediate rounds, cooperate if the stock is low, the last-round cooperation
      rate is at least 1/2, or accumulated trust is at least 1/2.
    - Trust is updated from the full history using exponential smoothing, with an
      immediate floor of 3/4 after any fully cooperative opponent round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.trust = 1.0

    def _opponent_fraction(self, k: int) -> float:
        n_players = int(self.game_description.n_players)
        n_opponents = max(n_players - 1, 1)
        if n_players == 2:
            return 1.0 if k > 0 else 0.0
        return float(k) / float(n_opponents)

    def _recompute_trust_from_history(self, history: PlayerHistory) -> float:
        trust = 1.0
        n_rounds_seen = history.round_number
        for t in range(n_rounds_seen):
            k = int(history.opponent_cooperators[t]) if t < len(history.opponent_cooperators) else 0
            q = self._opponent_fraction(k)
            trust = 0.6 * trust + 0.4 * q
            if q >= 1.0:
                trust = max(trust, 0.75)
        return trust

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_players = int(self.game_description.n_players)
        total_rounds = int(self.game_description.n_rounds)
        round_number = int(history.round_number)
        if round_number <= 0:
            self.trust = 1.0
            return Action.C
        self.trust = self._recompute_trust_from_history(history)
        if round_number >= total_rounds - 1:
            return Action.C
        if len(history.opponent_cooperators) > 0:
            last_k = int(history.opponent_cooperators[-1])
        else:
            last_k = 0
        q = self._opponent_fraction(last_k)
        capacity = float(self.game_description.capacity)
        stock = float(current_stock)
        if stock <= capacity / 2.0:
            return Action.C
        if q >= 0.5:
            return Action.C
        if self.trust >= 0.5:
            return Action.C
        return Action.D

class Strategy_BENEVOLENT_12(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Start cooperatively.
    - Track the opponent cooperation rate across the history.
    - Cooperate when the pool is healthy and the group is broadly cooperative.
    - Defect to protect the pool after clear overuse, or under severe stock stress.
    - Use a final-round safeguard that avoids leaving exploitation unanswered.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.m_opponents = max(0, self.n_players - 1)
        self.theta = math.ceil(self.m_opponents / 2) if self.m_opponents > 0 else 0
        self.quarter_capacity = self.capacity / 4.0
        self.half_capacity = self.capacity / 2.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number
        if t == 0:
            return Action.C
        m = self.m_opponents
        k = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        prev_total_coop = int(np.sum(history.opponent_cooperators[:-1])) if t > 1 else 0
        denom = (t - 1) * m
        coop_rate = prev_total_coop / denom if denom > 0 else 1.0
        action = Action.C
        low_stock = float(current_stock) < self.quarter_capacity
        high_stock = float(current_stock) >= self.half_capacity
        if low_stock and k != m:
            action = Action.D
        elif coop_rate < 0.5:
            action = Action.C if k == m else Action.D
        elif float(current_stock) <= float(self.n_players):
            action = Action.D if k < self.theta else Action.C
        else:
            action = Action.D if k == 0 else Action.C
        if high_stock and (not low_stock):
            if coop_rate < 0.5:
                action = Action.C if k == m else Action.D
            else:
                action = Action.D if k == 0 else Action.C
        if t == self.n_rounds - 1:
            action = Action.D if k == 0 else Action.C
        return action

class Strategy_BENEVOLENT_13(BaseStrategy):
    """
    Default-cooperate strategy with a temporary restraint mode under
    persistently low opponent cooperation and depleted stock.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self._prev_seen_stock = None
        self._low_coop_streak = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        last_round_index = self.n_rounds - 1
        if round_number == 0:
            self._prev_seen_stock = float(current_stock)
            self._low_coop_streak = 0
            return Action.C
        if round_number >= last_round_index:
            self._prev_seen_stock = float(current_stock)
            self._low_coop_streak = 0
            return Action.C
        n_opponents = self.n_players - 1
        if n_opponents <= 0:
            q = 1.0
        else:
            q = float(history.opponent_cooperators[-1]) / float(n_opponents)
        if q < 1.0 / 3.0:
            self._low_coop_streak += 1
        else:
            self._low_coop_streak = 0
        prev_stock = self._prev_seen_stock
        stock_increased_or_same = False
        if prev_stock is not None:
            stock_increased_or_same = float(current_stock) >= float(prev_stock)
        self._prev_seen_stock = float(current_stock)
        if current_stock <= 0.0:
            self._low_coop_streak = 0
            return Action.C
        if n_opponents > 0 and history.opponent_cooperators[-1] >= n_opponents:
            self._low_coop_streak = 0
            return Action.C
        if current_stock >= self.capacity / 2.0:
            self._low_coop_streak = 0
            return Action.C
        if q >= 0.5:
            self._low_coop_streak = 0
            return Action.C
        if stock_increased_or_same:
            self._low_coop_streak = 0
            return Action.C
        if self._low_coop_streak >= 2 and current_stock < self.capacity / 2.0 and (q < 0.5):
            return Action.D
        return Action.C

class Strategy_BENEVOLENT_14(BaseStrategy):
    """
    Starts cooperatively and only defects after two consecutive rounds of
    sustained opponent non-cooperation, provided the stock is sufficiently low.
    Cooperation is immediately restored once cooperation recovers, on the final
    round, or when stock is effectively depleted.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.eps = 1e-12

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_players = int(self.game_description.n_players)
        n_rounds = int(self.game_description.n_rounds)
        n_opponents = max(n_players - 1, 0)
        round_number = int(history.round_number)
        last_round_index = n_rounds - 1
        if round_number == 0:
            return Action.C
        if round_number >= last_round_index:
            return Action.C
        if current_stock <= self.eps:
            return Action.C
        bad_streak = 0
        if n_opponents > 0:
            for opp_coops in reversed(history.opponent_cooperators):
                if int(opp_coops) * 2 >= n_opponents:
                    break
                bad_streak += 1
        if bad_streak >= 2 and current_stock < float(self.game_description.capacity) / 3.0:
            return Action.D
        return Action.C

class Strategy_BENEVOLENT_15(BaseStrategy):
    """
    Benevolent common-pool strategy:
    - Cooperate by default.
    - Defect only when opponent cooperation is consistently low and the stock is degraded.
    - Fall back to cooperation in edge cases and when sustainability is plausible.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(self.n_players - 1, 1)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.n_players
        capacity = self.capacity
        round_number = int(history.round_number)
        if current_stock <= 0.0 or current_stock >= capacity:
            return Action.C
        if round_number == 0:
            return Action.C
        if len(history.opponent_cooperators) == 0:
            p_hat = 1.0
        else:
            observed = np.asarray(history.opponent_cooperators, dtype=float)
            denom = float(max(round_number * self.n_opponents, 1))
            p_hat = float(np.sum(observed) / denom)
        if round_number >= self.n_rounds - 1:
            return Action.C if p_hat >= 0.5 else Action.D
        if p_hat >= 0.5:
            return Action.C
        cooperative_consumption = current_stock / (2.0 * n) * ((n - 1) * p_hat + 1.0)
        r_c = current_stock - cooperative_consumption
        defect_consumption = current_stock / n + current_stock / (2.0 * n) * ((n - 1) * p_hat)
        r_d = current_stock - defect_consumption
        half_capacity = 0.5 * capacity
        quarter_capacity = 0.25 * capacity
        if r_c >= half_capacity:
            return Action.C
        if r_d >= half_capacity:
            return Action.D
        if current_stock >= quarter_capacity:
            return Action.C
        return Action.D

class Strategy_BENEVOLENT_16(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Cooperates initially and on the last round.
    - Tracks a smoothed trust signal from observed opponent cooperation.
    - Cooperates under high stock, broad cooperation, sufficient trust, or a cooperation streak.
    - Defects only under sustained low stock / low cooperation / low trust conditions.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.trust = 1.0
        self.cooperation_streak = 0
        self.last_processed_round = 0
        self.defection_condition_streak = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = int(self.game_description.n_players)
        r = int(self.game_description.n_rounds)
        capacity = float(self.game_description.capacity)
        round_number = int(history.round_number)
        if round_number > self.last_processed_round and round_number > 0:
            try:
                c_t = int(history.opponent_cooperators[-1])
            except Exception:
                c_t = 0
            n_opponents = max(n - 1, 1)
            obs_rate = c_t / n_opponents
            self.trust = 0.7 * self.trust + 0.3 * obs_rate
            if obs_rate >= 0.5:
                self.cooperation_streak += 1
            else:
                self.cooperation_streak = 0
            majority_threshold = 1 if n == 2 else math.ceil((n - 1) / 2)
            if current_stock < 0.35 * capacity and c_t < majority_threshold and (self.trust < 0.4):
                self.defection_condition_streak += 1
            else:
                self.defection_condition_streak = 0
            self.last_processed_round = round_number
        if round_number == 0:
            return Action.C
        if round_number >= r - 1:
            return Action.C
        if current_stock <= capacity / (4 * max(n, 1)):
            if self.defection_condition_streak < 2:
                return Action.C
        high_stock = current_stock >= 0.6 * capacity
        broad_cooperation_threshold = math.ceil(0.6 * max(n - 1, 0))
        broad_cooperation = False
        if round_number > 0 and len(history.opponent_cooperators) > 0:
            broad_cooperation = int(history.opponent_cooperators[-1]) >= broad_cooperation_threshold
        if high_stock:
            return Action.C
        if broad_cooperation:
            return Action.C
        if self.trust >= 0.55:
            return Action.C
        if self.cooperation_streak >= 2:
            return Action.C
        majority_threshold = 1 if n == 2 else math.ceil((n - 1) / 2)
        c_t = 0
        if round_number > 0 and len(history.opponent_cooperators) > 0:
            c_t = int(history.opponent_cooperators[-1])
        if current_stock < 0.35 * capacity and c_t < majority_threshold and (self.trust < 0.4):
            return Action.D
        return Action.C

class Strategy_BENEVOLENT_17(BaseStrategy):
    """
    Always cooperate. Records observed opponent cooperation counts, but never
    conditions the action on history or stock.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.observed_opponent_cooperators = []
        self.last_observed_stock = None

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        self.last_observed_stock = current_stock
        try:
            if history is not None and hasattr(history, 'opponent_cooperators'):
                if len(history.opponent_cooperators) > 0:
                    self.observed_opponent_cooperators.append(int(history.opponent_cooperators[-1]))
                else:
                    self.observed_opponent_cooperators.append(0)
            else:
                self.observed_opponent_cooperators.append(0)
        except Exception:
            self.observed_opponent_cooperators.append(0)
        return Action.C

class Strategy_BENEVOLENT_18(BaseStrategy):
    """
    Always cooperate in every round, regardless of history, stock, or opponent behavior.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        return Action.C

class Strategy_BENEVOLENT_19(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Cooperate by default
    - Protect the pool when stock is fragile
    - Use recent opponent cooperation to forecast whether defection is worthwhile
    - Temporarily force cooperation after short defection-heavy stretches
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(self.n_players - 1, 0)
        self.recovery_lock_remaining = 0
        self._last_seen_round = -1

    def _expected_next_stock(self, current_stock: float, avg_cooperators: float, action: Action) -> float:
        n = self.n_players
        cap = self.capacity
        if n <= 0:
            return current_stock
        own_consumption = current_stock / (2.0 * n) if action == Action.C else current_stock / n
        coop_cons = current_stock / (2.0 * n)
        defect_cons = current_stock / n
        expected_opponent_consumption = avg_cooperators * coop_cons + (self.n_opponents - avg_cooperators) * defect_cons
        total_consumption = own_consumption + expected_opponent_consumption
        remaining = current_stock - total_consumption
        if remaining < 0.0:
            remaining = 0.0
        growth = 2.0 * remaining * (1.0 - remaining / cap) if cap > 0.0 else 0.0
        next_stock = remaining + growth
        if next_stock > cap:
            next_stock = cap
        if next_stock < 0.0:
            next_stock = 0.0
        return next_stock

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        n = self.n_players
        n_opponents = self.n_opponents
        if round_number != self._last_seen_round:
            if self.recovery_lock_remaining > 0:
                self.recovery_lock_remaining -= 1
            self._last_seen_round = round_number
        if round_number == 0:
            return Action.C
        if round_number == self.n_rounds - 1:
            return Action.D if current_stock <= n / 2.0 else Action.C
        recent = history.opponent_cooperators
        if len(recent) == 0:
            avg_c = 0.0
        else:
            m = min(3, round_number)
            window = recent[-m:] if m > 0 else recent[-0:]
            avg_c = float(np.mean(window)) if len(window) > 0 else 0.0
        half_opponents = n_opponents / 2.0
        if len(recent) >= 3:
            last_three = recent[-3:]
            defection_heavy_count = int(np.sum(last_three < half_opponents))
            if defection_heavy_count >= 2:
                self.recovery_lock_remaining = 2
        if len(recent) > 0 and recent[-1] >= half_opponents:
            self.recovery_lock_remaining = 0
        if self.recovery_lock_remaining > 0:
            return Action.C
        if current_stock <= n:
            return Action.C
        if round_number == 1 and len(recent) >= 1 and (recent[-1] == 0):
            return Action.C
        if current_stock > n:
            c_next = self._expected_next_stock(current_stock, avg_c, Action.C)
            d_next = self._expected_next_stock(current_stock, avg_c, Action.D)
            if d_next < current_stock / 2.0 and c_next >= current_stock / 2.0:
                return Action.C
            if c_next > d_next:
                return Action.C
            if d_next > c_next:
                if avg_c == 0.0:
                    return Action.D
                return Action.C
            return Action.C
        return Action.C

class Strategy_BENEVOLENT_20(BaseStrategy):
    """
    Cooperation-first strategy for the Common Pool Resource Game.

    Core behavior:
    - Cooperate initially and whenever the pool is healthy and others are broadly cooperative.
    - Defect only under persistent low cooperation or severe depletion.
    - Return to cooperation quickly once the pool or cooperation rate recovers.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(0, self.n_players - 1)
        self.threshold_base = 1.0 - 1.0 / math.sqrt(2.0)

    def _threshold(self, stock: float) -> float:
        return self.threshold_base

    def _margin(self, stock: float) -> float:
        if self.capacity <= 0:
            return 0.1
        stock_ratio = stock / self.capacity
        return 0.1 + 0.2 * max(0.0, 1.0 - stock_ratio)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        if round_number == 0:
            return Action.C
        cap = self.capacity
        stock = float(current_stock)
        prev_opp_count = int(history.opponent_cooperators[-1])
        m = self.n_opponents if self.n_opponents > 0 else 1
        q = prev_opp_count / m
        threshold = self._threshold(stock)
        margin = self._margin(stock)
        low_cutoff = threshold - margin
        high_cutoff = threshold + margin
        last_round_index = self.n_rounds - 1
        is_last_round = round_number >= last_round_index
        prev_action_defected = not bool(history.my_actions[-1])
        low_count_recent = False
        if round_number >= 2:
            prev_q = int(history.opponent_cooperators[-2]) / m
            low_count_recent = prev_q < low_cutoff and q < low_cutoff
        else:
            low_count_recent = False
        all_others_cooperated = prev_opp_count >= m
        severe_depletion = stock <= cap / 8.0 if cap > 0 else False
        healthy_stock = stock >= cap / 4.0 if cap > 0 else True
        if is_last_round:
            return Action.D if severe_depletion else Action.C
        if severe_depletion:
            if q >= threshold or stock > cap / 8.0:
                return Action.C
            return Action.D
        if low_count_recent:
            if q >= low_cutoff or healthy_stock:
                return Action.C
            return Action.D
        if all_others_cooperated:
            return Action.C
        if prev_action_defected:
            if q >= high_cutoff or healthy_stock:
                return Action.C
            return Action.D
        if q >= low_cutoff and healthy_stock:
            return Action.C
        return Action.D

class Strategy_BENEVOLENT_21(BaseStrategy):
    """
    State-contingent conservation policy for the Common Pool Resource Game.

    - Cooperate by default.
    - Defect only in the final round or in very high-stock states after
      repeated low cooperation by opponents.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(self.n_players - 1, 1)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = int(history.round_number) + 1
        if t == 1:
            return Action.C
        if len(history.opponent_cooperators) == 0:
            x = 1.0
        else:
            last_coop = history.opponent_cooperators[-1]
            x = float(last_coop) / float(self.n_opponents)
        if current_stock <= 0.0:
            return Action.C
        if t >= self.n_rounds:
            if current_stock > self.capacity / 2.0 and x < 0.25:
                return Action.D
            return Action.C
        if current_stock <= self.capacity / 2.0:
            return Action.C
        if x >= 0.5:
            return Action.C
        if x < 0.25 and current_stock >= 1.5 * self.capacity:
            return Action.D
        return Action.C

class Strategy_BENEVOLENT_22(BaseStrategy):
    """
    Cooperate by default, but defect briefly after repeated recent low cooperation
    by opponents when the pool is depleted and it is not the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(self.n_players - 1, 0)
        self.low_threshold = math.ceil(self.n_opponents / 2) if self.n_opponents > 0 else 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        if round_number == 0:
            return Action.C
        if round_number >= self.n_rounds - 1:
            return Action.C
        if current_stock >= self.capacity / 3:
            return Action.C
        low_streak = 0
        for k in history.opponent_cooperators[::-1]:
            low = 1 if int(k) < self.low_threshold else 0
            if low == 1:
                low_streak += 1
            else:
                break
        if low_streak >= 2:
            return Action.D
        return Action.C

class Strategy_BENEVOLENT_23(BaseStrategy):
    """
    Cooperative default strategy with one-round forgiveness after mild
    low-cooperation signals, and defection only under repeated strain.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.forgiveness_used = False
        self._last_round_seen = -1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_players = getattr(self.game_description, 'n_players', 0)
        n_rounds = getattr(self.game_description, 'n_rounds', 0)
        capacity = float(getattr(self.game_description, 'capacity', 0.0))
        round_number = history.round_number
        current_round = round_number + 1
        if round_number == 0:
            self.forgiveness_used = False
            self._last_round_seen = round_number
            return Action.C
        if self._last_round_seen != round_number - 1:
            self._last_round_seen = round_number
            return Action.C
        if len(history.opponent_cooperators) == 0:
            self._last_round_seen = round_number
            return Action.C
        last_cooperators = int(history.opponent_cooperators[-1])
        n_opponents = max(n_players - 1, 0)
        if n_opponents <= 0:
            q = 1.0
        else:
            q = last_cooperators / n_opponents
            if q < 0.0:
                q = 0.0
            elif q > 1.0:
                q = 1.0
        if current_round >= n_rounds:
            action = Action.C
        elif current_stock >= capacity / 4.0:
            action = Action.C
            self.forgiveness_used = False
        elif q >= 0.5:
            action = Action.C
            self.forgiveness_used = False
        elif q >= 1.0 / 3.0 and (not self.forgiveness_used):
            action = Action.C
            self.forgiveness_used = True
        else:
            action = Action.D
            self.forgiveness_used = True
        self._last_round_seen = round_number
        return action

class Strategy_BENEVOLENT_24(BaseStrategy):
    """
    Conservation-oriented threshold strategy with conditional generosity.

    - Starts with cooperation.
    - Uses recent opponent cooperation averages over 3 and 2 rounds.
    - Becomes stricter after repeated low cooperation or severe stock depletion.
    - Rewards sustained cooperation and high stock levels with generosity.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(0, self.n_players - 1)

    def _opponent_rate(self, opponent_cooperators: int) -> float:
        if self.n_opponents <= 0:
            return 1.0
        return float(opponent_cooperators) / float(self.n_opponents)

    def _recent_mean(self, history: PlayerHistory, window: int) -> float:
        rounds_played = history.round_number
        if rounds_played <= 0:
            return 1.0
        start = max(0, rounds_played - window)
        rates = [self._opponent_rate(int(c)) for c in history.opponent_cooperators[start:rounds_played]]
        if not rates:
            return 1.0
        return float(np.mean(rates))

    def _last_k_all_at_least(self, history: PlayerHistory, k: int, threshold: float) -> bool:
        rounds_played = history.round_number
        if rounds_played < k:
            return False
        start = rounds_played - k
        for c in history.opponent_cooperators[start:rounds_played]:
            if self._opponent_rate(int(c)) < threshold:
                return False
        return True

    def _last_k_all_below(self, history: PlayerHistory, k: int, threshold: float) -> bool:
        rounds_played = history.round_number
        if rounds_played < k:
            return False
        start = rounds_played - k
        for c in history.opponent_cooperators[start:rounds_played]:
            if self._opponent_rate(int(c)) >= threshold:
                return False
        return True

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        cap = self.capacity
        stock = float(current_stock)
        A_t = self._recent_mean(history, 3)
        B_t = self._recent_mean(history, 2)
        prev_rate = self._opponent_rate(int(history.opponent_cooperators[-1]))
        prev_unanimous = prev_rate >= 1.0
        prev_weak = prev_rate < 0.5
        last_two_low = self._last_k_all_below(history, 2, 0.5)
        last_two_good = self._last_k_all_at_least(history, 2, 0.5)
        if stock <= cap / 8.0:
            return Action.D
        if last_two_low and (not last_two_good):
            return Action.D
        if prev_unanimous and stock >= cap / 10.0:
            return Action.C
        if stock >= 0.8 * cap:
            return Action.C
        if history.round_number >= self.n_rounds - 1:
            if B_t < 0.5 and stock < cap / 6.0:
                return Action.D
            return Action.C
        if A_t >= 0.5 and stock >= cap / 4.0:
            return Action.C
        if prev_weak and stock >= cap / 4.0:
            return Action.C
        return Action.D

class Strategy_BENEVOLENT_25(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Cooperate initially.
    - Prefer cooperation when stock is healthy or opponents showed recent cooperation.
    - Switch to defense under low stock and repeated majority defection.
    - Endgame favors cooperation unless conditions are clearly hostile.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = max(2, int(game_description.n_players))
        self.r = max(1, int(game_description.n_rounds))
        self.capacity = float(game_description.capacity)
        self.majority_threshold = math.ceil((self.n - 1) / 2)
        self.third_threshold = math.ceil((self.n - 1) / 3)
        self.low_stock_threshold = self.capacity / self.n if self.n > 0 else 0.0
        self.coop_stock_threshold = self.capacity / 2.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number
        S = float(current_stock) if current_stock is not None else 0.0
        S = max(0.0, S)
        if t == 0:
            return Action.C
        last_opp_coop = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        prev_action_is_coop = bool(history.my_actions[-1]) if len(history.my_actions) > 0 else True
        if t >= self.r - 1:
            return Action.C if S > 0 else Action.C
        majority_coop = last_opp_coop >= self.majority_threshold
        at_least_one_third_coop = last_opp_coop >= self.third_threshold
        low_stock = S <= self.low_stock_threshold
        healthy_stock = S >= self.coop_stock_threshold
        if t >= self.r - 2:
            if prev_action_is_coop and at_least_one_third_coop:
                return Action.C
            if healthy_stock:
                return Action.C
            if low_stock and (not majority_coop):
                return Action.D
            return Action.C if majority_coop else Action.D
        if majority_coop:
            return Action.C
        if healthy_stock:
            return Action.C
        if low_stock and (not majority_coop):
            return Action.D
        if S < self.coop_stock_threshold:
            if at_least_one_third_coop and prev_action_is_coop:
                return Action.C
            if last_opp_coop < self.majority_threshold:
                return Action.D
            return Action.C
        if prev_action_is_coop and at_least_one_third_coop:
            return Action.C
        return Action.D

class Strategy_BENEVOLENT_26(BaseStrategy):
    """
    Conservative common-pool strategy:
    - starts with cooperation,
    - cooperates whenever the resource is healthy or the group is mostly cooperative,
    - defects only as a short defensive response to severe overuse,
    - returns to cooperation quickly once conditions improve.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = max(2, int(game_description.n_players))
        self.n_rounds = max(1, int(game_description.n_rounds))
        self.capacity = float(game_description.capacity)
        self.target_stock = self.capacity / 2.0
        self.critical_stock = self.capacity / 4.0
        self.last_round_defection = False
        self.trust = 1.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = int(history.round_number) + 1
        n = self.n_players
        r = self.n_rounds
        S = float(current_stock) if current_stock is not None else 0.0
        if not math.isfinite(S):
            S = 0.0
        k = 0
        if history.opponent_cooperators is not None and len(history.opponent_cooperators) > 0:
            k = int(history.opponent_cooperators[-1])
        k = max(0, min(k, n - 1))
        if t == 1:
            self.last_round_defection = False
            self.trust = min(1.0, self.trust + 0.05)
            return Action.C
        severe_shortage = S <= self.critical_stock
        healthy_stock = S >= self.target_stock
        last_was_defection = bool(len(history.my_actions) > 0 and (not bool(history.my_actions[-1])))
        if last_was_defection:
            if healthy_stock:
                self.last_round_defection = False
                self.trust = min(1.0, self.trust + 0.1)
                return Action.C
            if severe_shortage and k <= 1:
                self.last_round_defection = True
                self.trust = max(0.0, self.trust - 0.1)
                return Action.D
            self.last_round_defection = False
            self.trust = min(1.0, self.trust + 0.05)
            return Action.C
        if severe_shortage:
            action = Action.C if k > 0 else Action.D
        elif t == r:
            action = Action.C if k > 0 and S >= self.target_stock / 2.0 else Action.D
        elif k >= n - 2:
            action = Action.C
        elif k == n - 3:
            action = Action.C if S >= self.target_stock / 3.0 else Action.D
        elif k <= n - 4:
            action = Action.D
        else:
            action = Action.C
        if action == Action.D:
            if self.last_round_defection and (not (severe_shortage and k <= 1)):
                action = Action.C
        if healthy_stock:
            action = Action.C
        self.last_round_defection = action == Action.D
        if action == Action.C:
            self.trust = min(1.0, self.trust + 0.05)
        else:
            self.trust = max(0.0, self.trust - 0.05)
        return action

class Strategy_BENEVOLENT_27(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Cooperate initially.
    - Stay cooperative when at least half of opponents cooperated last round.
    - Defect after repeated low cooperation, or when the stock is critically low
      and cooperation was poor.
    - Forgive immediately when cooperation recovers.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.bad_streak = 0
        self.last_action = Action.C
        self.last_seen_round = -1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_players = self.game_description.n_players
        capacity = float(self.game_description.capacity)
        round_number = history.round_number
        if round_number == 0:
            self.bad_streak = 0
            self.last_action = Action.C
            self.last_seen_round = 0
            return Action.C
        last_opponent_cooperators = int(history.opponent_cooperators[-1])
        n_opponents = max(0, n_players - 1)
        if n_opponents <= 0:
            p = 1.0
        elif n_players == 2:
            p = 1.0 if last_opponent_cooperators >= 1 else 0.0
        else:
            p = last_opponent_cooperators / n_opponents
        low_stock = current_stock < capacity / 4.0
        action = Action.C
        if current_stock <= 0.0 and p < 0.5:
            action = Action.D
            self.bad_streak += 1
        elif p >= 0.5:
            action = Action.C
            self.bad_streak = 0
        else:
            self.bad_streak += 1
            if round_number == 1:
                action = Action.D if low_stock else Action.C
            elif round_number == n_players * 0 + (self.game_description.n_rounds - 1):
                action = Action.D if low_stock else Action.C
            elif low_stock and p < 2.0 / 3.0:
                action = Action.D
            elif self.bad_streak >= 2:
                action = Action.D
            else:
                action = Action.C
        if current_stock >= capacity:
            action = Action.C
        self.last_action = action
        self.last_seen_round = round_number
        return action

class Strategy_BENEVOLENT_28(BaseStrategy):
    """
    Always cooperate in every round, regardless of stock, history, or opponent behavior.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        return Action.C

class Strategy_BENEVOLENT_29(BaseStrategy):
    """
    Unconditional cooperation strategy for the Common Pool Resource Game.
    Always plays C in every round, regardless of history or current stock.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = getattr(game_description, 'n_players', None)
        self.n_rounds = getattr(game_description, 'n_rounds', None)
        self.capacity = getattr(game_description, 'capacity', None)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history is None:
            return Action.C
        if getattr(history, 'round_number', 0) == 0:
            return Action.C
        return Action.C

class Strategy_BENEVOLENT_30(BaseStrategy):
    """
    Always cooperate in every round, regardless of history, stock, or opponents' actions.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        return Action.C

class Strategy_BENEVOLENT_31(BaseStrategy):
    """
    Default-cooperation strategy for the Common Pool Resource Game.

    - Round 1: cooperate.
    - Later rounds: compare the implied next stock after choosing C vs D
      given the observed current stock and previous opponent cooperation count.
    - Cooperate unless defecting strictly yields a better next stock.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.capacity = float(game_description.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if current_stock <= 0:
            return Action.C
        try:
            m = int(history.opponent_cooperators[-1])
        except Exception:
            return Action.C
        if m < 0 or m > max(0, self.n - 1):
            return Action.C
        n = self.n
        cap = self.capacity
        S = float(current_stock)
        if cap <= 0 or n <= 0:
            return Action.C
        x_c = S * (m + 1) / (2.0 * n)
        x_d = S * m / (2.0 * n)
        f_c = min(x_c + 2.0 * x_c * (1.0 - x_c / cap), cap)
        f_d = min(x_d + 2.0 * x_d * (1.0 - x_d / cap), cap)
        if f_d > f_c:
            return Action.D
        return Action.C

class Strategy_BENEVOLENT_32(BaseStrategy):
    """
    Cooperation-first common-pool strategy that preserves stock when prior
    rounds show overuse, while preferring cooperation under uncertainty.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.ceil_half_n = math.ceil(self.n / 2)
        self.n_opponents = max(self.n - 1, 0)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        t = round_number + 1
        if round_number == 0:
            return Action.C
        try:
            last_opp_coop = int(history.opponent_cooperators[-1])
            last_my_action = bool(history.my_actions[-1])
        except Exception:
            return Action.C
        prev_x = last_opp_coop + (1 if last_my_action else 0)
        prev_k = last_opp_coop
        prev_healthy = prev_x >= self.ceil_half_n
        if t >= self.r:
            if prev_healthy:
                return Action.C
            if prev_k >= self.n_opponents / 2.0:
                return Action.C
            return Action.D
        if current_stock <= 2 * self.n:
            if prev_k == 0 and t >= self.r:
                return Action.D
            return Action.C
        if prev_healthy:
            return Action.C
        if current_stock <= self.capacity / 4.0 or t >= self.r - 1:
            return Action.D
        return Action.C

class Strategy_SELFISH_5(BaseStrategy):
    """
    Conditional cooperators with a low-stock persistence lock:
    - Defect in the first round and the final round.
    - In intermediate rounds, cooperate only when recent opponent cooperation is high
      and the stock is sufficiently healthy.
    - If stock ever falls below one quarter of capacity, keep defecting until stock
      recovers to at least half capacity and recent cooperation is strong.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(self.n - 1, 0)
        self.low_stock_lock = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        if round_number >= self.r - 1:
            return Action.D
        last_q = 0.0
        if round_number > 0 and self.n_opponents > 0:
            last_q = float(history.opponent_cooperators[-1]) / float(self.n_opponents)
        if current_stock < self.capacity / 4.0:
            self.low_stock_lock = True
        if self.low_stock_lock:
            if current_stock >= self.capacity / 2.0 and last_q >= 2.0 / 3.0:
                self.low_stock_lock = False
            else:
                return Action.D
        if round_number == 0:
            return Action.D
        s = current_stock / self.capacity if self.capacity > 0 else 0.0
        q = last_q
        if q >= 0.5 and s >= 0.25 and (q >= 2.0 / 3.0 or s >= 0.5):
            return Action.C
        return Action.D

class Strategy_SELFISH_6(BaseStrategy):
    """
    Resource-preserving strategy for the Common Pool Resource Game.

    - Tracks an exponentially weighted average of opponent cooperation (cbar)
    - Uses a short defensive punishment mode after low cooperation
    - Cooperates only when the stock is high and opponents have been reliably cooperative
    - Never cooperates in the final round
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.cbar = 1.0
        self.punish = 0
        self.last_seen_round = 0
        self.full_coop_streak = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = float(self.game_description.capacity)
        round_number = history.round_number
        rounds_remaining = r - round_number
        if round_number > self.last_seen_round:
            start_idx = self.last_seen_round
            end_idx = round_number
            for idx in range(start_idx, end_idx):
                if idx == 0:
                    q = 1.0
                else:
                    opp_count = int(history.opponent_cooperators[idx - 1])
                    denom = max(1, n - 1)
                    q = opp_count / denom
                self.cbar = 0.75 * self.cbar + 0.25 * q
                if q <= 0.5:
                    self.punish = 2
                elif self.punish > 0:
                    self.punish -= 1
                if idx > 0 and int(history.opponent_cooperators[idx - 1]) >= max(0, n - 1):
                    self.full_coop_streak += 1
                else:
                    self.full_coop_streak = 0
            self.last_seen_round = round_number
        if rounds_remaining <= 1:
            return Action.D
        if self.punish > 0:
            return Action.D
        if current_stock < 0.6 * capacity:
            return Action.D
        if round_number == 0:
            if n == 2 and current_stock >= capacity:
                return Action.C
            return Action.D
        last_opp_coop = int(history.opponent_cooperators[-1]) if round_number > 0 else n - 1
        q_last = last_opp_coop / max(1, n - 1)
        if self.full_coop_streak >= 2 and current_stock >= 0.9 * capacity:
            return Action.C
        if current_stock >= 0.8 * capacity and self.cbar >= 0.8 and (last_opp_coop >= max(0, n - 2)):
            return Action.C
        return Action.D

class Strategy_SELFISH_7(BaseStrategy):
    """
    Selfish adaptive strategy for the Common Pool Resource Game.

    Maintains an exponentially smoothed estimate of opponent cooperation rate q,
    tracks public stock, and defects when stock is high and the estimated
    cooperation level suggests the pool can sustain it.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.q = 0.5

    def _expected_next_stock(self, stock: float, my_action: Action, q: float) -> float:
        n = max(2, self.n)
        opps = max(0, n - 1)
        if stock <= 0:
            return 0.0
        coop_cons = stock / (2.0 * n)
        defect_cons = stock / n
        expected_opp_cons = q * coop_cons + (1.0 - q) * defect_cons
        if my_action == Action.C:
            total_consumption = coop_cons + opps * expected_opp_cons
        else:
            total_consumption = defect_cons + opps * expected_opp_cons
        remaining = stock - total_consumption
        if remaining < 0.0:
            remaining = 0.0
        growth = 2.0 * remaining * (1.0 - remaining / self.capacity) if self.capacity > 0 else 0.0
        next_stock = remaining + growth
        if next_stock > self.capacity:
            next_stock = self.capacity
        if next_stock < 0.0:
            next_stock = 0.0
        return next_stock

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = max(2, self.n)
        opps = max(0, n - 1)
        if history.round_number > 0 and opps > 0:
            k = float(history.opponent_cooperators[-1])
            observed_rate = k / opps
            self.q = 0.7 * self.q + 0.3 * observed_rate
        if self.q < 0.0:
            self.q = 0.0
        elif self.q > 1.0:
            self.q = 1.0
        S = float(current_stock)
        if history.round_number == 0:
            return Action.D
        if S <= 0.0:
            return Action.C
        if history.round_number == self.r - 1:
            return Action.D if S > 0.0 else Action.C
        if S <= self.capacity / 2.0:
            return Action.C
        S_D = self._expected_next_stock(S, Action.D, self.q)
        if S > 0.6 * self.capacity and self.q >= 0.4 and (S_D >= 0.5 * self.capacity):
            return Action.D
        return Action.C

class Strategy_SELFISH_8(BaseStrategy):
    """
    Resource-conserving strategy for the Common Pool Resource Game.

    - Defaults to defection.
    - Cooperates only when stock is low and recent opponent cooperation is high.
    - Becomes more cautious permanently after two consecutive stock declines.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_players = int(game_description.n_players)
        self.n_opponents = max(self.n_players - 1, 1)
        self._prev_stocks = []
        self._tightened = False

    def _recent_q(self, history: PlayerHistory) -> float:
        """Average fraction of opponents cooperating over the last up to 3 rounds."""
        rounds_seen = history.round_number
        if rounds_seen <= 0:
            return 0.0
        k = min(3, rounds_seen)
        recent = history.opponent_cooperators[-k:]
        if self.n_opponents <= 0:
            return 0.0
        fractions = [float(x) / float(self.n_opponents) for x in recent]
        return float(np.mean(fractions)) if fractions else 0.0

    def _update_stock_memory(self, current_stock: float) -> None:
        """Store stock observations and update tightened mode if two consecutive declines occur."""
        self._prev_stocks.append(float(current_stock))
        if len(self._prev_stocks) > 3:
            self._prev_stocks = self._prev_stocks[-3:]
        if not self._tightened and len(self._prev_stocks) >= 3:
            s0, s1, s2 = (self._prev_stocks[-3], self._prev_stocks[-2], self._prev_stocks[-1])
            if s2 < s1 and s1 < s0:
                self._tightened = True

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        self._update_stock_memory(current_stock)
        round_number = history.round_number
        last_round_index = self.n_rounds - 1
        if round_number == 0 or round_number == last_round_index:
            return Action.D
        q = self._recent_q(history)
        stock = float(current_stock)
        cap = self.capacity
        if self._tightened:
            low_t = 0.9
            mid_t = 0.7
            lower_mid_t = 0.3
            upper_mid_t = 0.55
            high_band_t = 0.8
        else:
            low_t = 0.8
            mid_t = 0.6
            lower_mid_t = 0.2
            upper_mid_t = 0.45
            high_band_t = 0.7
        if stock <= lower_mid_t * cap:
            return Action.C if q >= low_t else Action.D
        if stock <= upper_mid_t * cap:
            return Action.C if q >= mid_t else Action.D
        if stock <= high_band_t * cap:
            if len(self._prev_stocks) >= 3:
                s0, s1, s2 = (self._prev_stocks[-3], self._prev_stocks[-2], self._prev_stocks[-1])
                rising_in_last_two = s2 > s1 and s1 > s0
            else:
                rising_in_last_two = False
            if q >= low_t and rising_in_last_two:
                return Action.C
            return Action.D
        return Action.D

class Strategy_SELFISH_9(BaseStrategy):
    """
    Defect initially, then cooperate only when smoothed opponent cooperation is
    at least half and the projected stock stays near the preferred regeneration zone.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(self.n_players - 1, 1)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        rounds_left = max(self.n_rounds - round_number, 0)
        if round_number == 0:
            return Action.D
        if rounds_left == 1:
            return Action.D
        opp_counts = history.opponent_cooperators
        if len(opp_counts) == 0:
            q = 0.0
        else:
            total_weight = 0.0
            weighted_sum = 0.0
            m = len(opp_counts)
            for idx in range(m):
                w = float(idx + 1)
                frac = float(opp_counts[idx]) / float(self.n_opponents)
                weighted_sum += w * frac
                total_weight += w
            q = weighted_sum / total_weight if total_weight > 0.0 else 0.0
        k = float(self.n_players - 1) * q
        s = float(current_stock)
        x_d = s * k / (2.0 * float(self.n_players))
        x_c = s * (k + 1.0) / (2.0 * float(self.n_players))
        target = 0.75 * self.capacity
        if q >= 0.5 and x_d < target and (abs(x_c - target) < abs(x_d - target)):
            return Action.C
        return Action.D

class Strategy_SELFISH_10(BaseStrategy):
    """
    Backward-looking selfish strategy for the Common Pool Resource Game.

    - Round 1: defect.
    - Later rounds: compare immediate gain plus a simple continuation value
      under cooperate vs defect, using the previous round's opponent cooperation
      count as the local predictor of others' behavior.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(getattr(game_description, 'n_players', 0) or 0)
        self.r = int(getattr(game_description, 'n_rounds', 0) or 0)
        self.capacity = float(getattr(game_description, 'capacity', 0) or 0.0)
        self.eps = 1e-12

    def _next_stock(self, stock: float, m: int) -> float:
        n = max(self.n, 2)
        cap = max(self.capacity, self.eps)
        m = max(0, min(int(m), n))
        r = stock * m / (2.0 * n)
        remaining = stock - r
        if remaining < 0.0:
            remaining = 0.0
        growth = 2.0 * remaining * (1.0 - remaining / cap)
        new_stock = remaining + growth
        if new_stock > cap:
            return cap
        if new_stock < 0.0:
            return 0.0
        return new_stock

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = max(self.n, 2)
        r = max(self.r, 1)
        if history.round_number == 0:
            return Action.D
        t = history.round_number + 1
        if t >= r:
            return Action.D
        k = 0
        if len(history.opponent_cooperators) > 0:
            k = int(history.opponent_cooperators[-1])
        k = max(0, min(k, n - 1))
        L = r - t
        stock = float(current_stock)
        if stock < 0.0:
            stock = 0.0
        cap = max(self.capacity, self.eps)
        m_c = k + 1
        m_d = k
        s_c = self._next_stock(stock, m_c)
        s_d = self._next_stock(stock, m_d)
        score_c = stock / (2.0 * n) + L * s_c / (2.0 * n)
        score_d = stock / n + L * s_d / (2.0 * n)
        if score_c > score_d + self.eps:
            return Action.C
        return Action.D

class Strategy_SELFISH_11(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Cooperate first to probe the environment.
    - Update an estimate of opponent cooperation via exponential smoothing.
    - Cooperate only when the predicted continuation value of restraint exceeds defecting.
    - Defect in the final round, when stock is depleted, or when cooperation collapses.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.q = 0.5
        self.last_k = max(self.n - 1, 0)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.n
        r = self.r
        cap = self.capacity
        t = history.round_number
        if current_stock <= 0:
            return Action.D
        if t == 0:
            return Action.C
        if t >= r - 1:
            return Action.D
        opp_count = max(n - 1, 1)
        k_prev = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else self.last_k
        k_prev = max(0, min(k_prev, n - 1))
        self.last_k = k_prev
        if k_prev == 0:
            return Action.D
        self.q = 0.7 * self.q + 0.3 * (k_prev / opp_count)
        k_hat = int(round(self.q * opp_count))
        k_hat = max(0, min(k_hat, n - 1))
        S = float(current_stock)

        def next_stock_for_total_cooperators(m: int) -> float:
            m = max(0, min(m, n))
            remaining_after_consumption = S * m / (2.0 * n) if n > 0 else 0.0
            if cap <= 0:
                return 0.0
            nxt = 3.0 * remaining_after_consumption - 2.0 * remaining_after_consumption ** 2 / cap
            return min(nxt, cap)
        m_c = k_hat + 1
        m_d = k_hat
        n_c = next_stock_for_total_cooperators(m_c)
        n_d = next_stock_for_total_cooperators(m_d)
        remaining_rounds_after_now = max(r - t - 1, 0)
        gain_c = S / (2.0 * n) + remaining_rounds_after_now * (n_c / (2.0 * n)) if n > 0 else 0.0
        gain_d = S / n + remaining_rounds_after_now * (n_d / (2.0 * n)) if n > 0 else 0.0
        if gain_c >= gain_d:
            return Action.C
        return Action.D

class Strategy_SELFISH_12(BaseStrategy):
    """
    Common pool strategy that cooperates early, defects on the last round,
    and otherwise adapts to current stock, recent opponent cooperation,
    and a declining conservation threshold.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self._eps = 1e-12

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        if round_number == 0:
            return Action.C
        if round_number >= self.r - 1:
            return Action.D
        n_opponents = max(self.n - 1, 1)
        last_opponents = int(history.opponent_cooperators[-1]) if round_number > 0 else 0
        p = last_opponents / n_opponents
        h = self.r - round_number
        denom = max(self.r - 1, 1)
        T = self.capacity * (0.25 + 0.25 * (h - 1) / denom)
        if current_stock <= self._eps:
            return Action.C
        p_last = p
        p_prev = None
        if round_number >= 2:
            prev_opponents = int(history.opponent_cooperators[-2])
            p_prev = prev_opponents / n_opponents
        last_two_both_low = False
        last_two_both_high = False
        if p_prev is not None:
            last_two_both_low = p_prev < 0.4 and p_last < 0.4
            last_two_both_high = p_prev >= 0.67 and p_last >= 0.67
        if current_stock <= T:
            return Action.C
        if last_two_both_low:
            return Action.C if current_stock < 0.9 * self.capacity else Action.D
        if last_two_both_high:
            return Action.D if current_stock > T else Action.C
        if p < 0.5:
            return Action.C if current_stock < 0.85 * self.capacity else Action.D
        return Action.D if current_stock > T else Action.C

class Strategy_SELFISH_13(BaseStrategy):
    """
    Common-pool strategy:
    - Defect on the first round.
    - In later rounds, estimate whether cooperation or defection preserves enough stock
      for future extraction, using the last observed cooperation count among opponents.
    - Always defect in the final round or when stock is depleted.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        if round_number == 0:
            return Action.D
        if current_stock <= 0.0:
            return Action.D
        rounds_left_including_current = self.n_rounds - round_number
        if rounds_left_including_current <= 1:
            return Action.D
        if len(history.opponent_cooperators) == 0:
            return Action.D
        k = int(history.opponent_cooperators[-1])
        if rounds_left_including_current >= 3:
            tau = self.capacity / 2.0
        elif rounds_left_including_current == 2:
            tau = self.capacity / 3.0
        else:
            tau = 0.0
        n = self.n_players
        x_d = current_stock * k / (2.0 * n)
        x_c = current_stock * (k + 1.0) / (2.0 * n)
        if x_d >= tau:
            return Action.D
        if x_c >= tau:
            return Action.C
        return Action.D

class Strategy_SELFISH_14(BaseStrategy):
    """
    Start by cooperating, then cooperate only when the pool is healthy and
    opponent cooperation is near-universal; otherwise defect. Always defect in
    the last two rounds.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.prev_m = 0
        self.prev_S = float(game_description.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_rounds = int(self.game_description.n_rounds)
        capacity = float(self.game_description.capacity)
        n_players = int(self.game_description.n_players)
        round_number = int(history.round_number)
        if round_number > 0 and len(history.opponent_cooperators) > 0:
            self.prev_m = int(history.opponent_cooperators[-1])
        else:
            self.prev_m = 0
        self.prev_S = float(current_stock)
        if round_number == 0:
            return Action.C
        if round_number >= max(0, n_rounds - 2):
            return Action.D
        if current_stock <= capacity / 2.0:
            return Action.D
        m = self.prev_m
        if m >= n_players - 1:
            return Action.C
        if m == n_players - 2 and current_stock >= 0.75 * capacity:
            return Action.C
        return Action.D

class Strategy_SELFISH_15(BaseStrategy):
    """
    Cooperative-start, stock-sensitive strategy that defects in the final two rounds
    and otherwise conditions on recent opponent cooperation and current stock.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(self.n_players - 1, 0)
        self.half_opponent_threshold = math.ceil(self.n_opponents / 2) if self.n_opponents > 0 else 0
        self.stock_third = self.capacity / 3.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        if round_number == 0:
            return Action.C
        if round_number >= self.n_rounds - 2:
            return Action.D
        if current_stock <= self.stock_third:
            return Action.C
        if round_number > 0 and len(history.opponent_cooperators) > 0:
            last_opponent_cooperators = int(history.opponent_cooperators[-1])
            if last_opponent_cooperators >= self.half_opponent_threshold:
                return Action.C
        return Action.D

class Strategy_SELFISH_16(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Starts by defecting.
    - Tracks an exponentially smoothed estimate of opponent cooperation (q).
    - Reconstructs stock from history each turn.
    - Defects when stock is high and cooperation is strong, cooperates when stock is low
      or when recent behavior signals collapse and recovery is needed.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.q = 1.0
        self.mode = 'exploit'
        self.reconstructed_stock = float(game_description.capacity)

    def _reconstruct_stock(self, history: PlayerHistory) -> float:
        n = max(int(self.game_description.n_players), 2)
        cap = float(self.game_description.capacity)
        stock = cap
        rounds = history.round_number
        for t in range(rounds):
            my_coop = 1 if bool(history.my_actions[t]) else 0
            opp_coop = int(history.opponent_cooperators[t]) if t < len(history.opponent_cooperators) else 0
            total_coop = my_coop + opp_coop
            remaining_after_consumption = stock * (total_coop / (2.0 * n))
            growth = 2.0 * remaining_after_consumption * (1.0 - remaining_after_consumption / cap)
            stock = min(remaining_after_consumption + growth, cap)
            if stock < 0.0:
                stock = 0.0
        return stock

    def _expected_next_stock(self, current_stock: float, expected_coop_total: float) -> float:
        n = max(int(self.game_description.n_players), 2)
        cap = float(self.game_description.capacity)
        expected_coop_total = max(0.0, min(float(n), float(expected_coop_total)))
        remaining_after_consumption = current_stock * (expected_coop_total / (2.0 * n))
        growth = 2.0 * remaining_after_consumption * (1.0 - remaining_after_consumption / cap)
        next_stock = min(remaining_after_consumption + growth, cap)
        if next_stock < 0.0:
            next_stock = 0.0
        return next_stock

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = int(self.game_description.n_players)
        r = int(self.game_description.n_rounds)
        cap = float(self.game_description.capacity)
        if history.round_number <= 0:
            self.reconstructed_stock = cap
        else:
            self.reconstructed_stock = self._reconstruct_stock(history)
        if history.round_number == 0:
            self.q = 1.0
            self.mode = 'exploit'
            return Action.D
        last_opp = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        denom = max(n - 1, 1)
        observed_rate = last_opp / denom
        self.q = 0.7 * self.q + 0.3 * observed_rate
        remaining = r - history.round_number
        recent_low = False
        recent_high = False
        if len(history.opponent_cooperators) >= 2:
            c1 = history.opponent_cooperators[-1] / denom
            c2 = history.opponent_cooperators[-2] / denom
            recent_low = c1 < 0.7 and c2 < 0.7
            recent_high = c1 > 0.9 and c2 > 0.9
        if recent_low:
            self.mode = 'recover'
            return Action.C
        if recent_high:
            self.mode = 'exploit'
            return Action.D
        S = float(self.reconstructed_stock)
        if remaining <= 1:
            self.mode = 'exploit'
            return Action.D
        if remaining == 2:
            expected_others_coop = (n - 1) * self.q
            current_payoff_c = S / (2.0 * n)
            next_stock_c = self._expected_next_stock(S, expected_others_coop + 1.0)
            future_payoff_c = next_stock_c / n
            total_c = current_payoff_c + future_payoff_c
            current_payoff_d = S / n
            next_stock_d = self._expected_next_stock(S, expected_others_coop)
            future_payoff_d = next_stock_d / n
            total_d = current_payoff_d + future_payoff_d
            if total_c > total_d:
                self.mode = 'recover' if S < 0.5 * cap else self.mode
                return Action.C
            return Action.D
        cooperation_level = observed_rate
        if S >= 0.6 * cap and cooperation_level >= max(0.0, 1.0 - 2.0 / max(n - 1, 1)):
            self.mode = 'exploit'
            return Action.D
        if S >= 0.35 * cap:
            if self.q >= 0.9:
                self.mode = 'exploit'
                return Action.D
            self.mode = 'recover' if S < 0.5 * cap else 'exploit'
            return Action.C
        self.mode = 'recover'
        if S < 0.5 * cap:
            return Action.C
        return Action.D

class Strategy_SELFISH_17(BaseStrategy):
    """
    Defect by default; cooperate only when your action is pivotal for keeping
    the resource at the preservation threshold, and never in the first or last round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(getattr(game_description, 'n_players', 0))
        self.n_rounds = int(getattr(game_description, 'n_rounds', 0))
        self.capacity = float(getattr(game_description, 'capacity', 0.0))

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(getattr(history, 'round_number', 0))
        if round_number == 0 or round_number >= self.n_rounds - 1:
            return Action.D
        if current_stock is None or current_stock <= 0:
            return Action.D
        if self.n_players <= 0 or self.capacity <= 0:
            return Action.D
        opp_counts = getattr(history, 'opponent_cooperators', None)
        if opp_counts is None or len(opp_counts) == 0:
            return Action.D
        k = int(opp_counts[-1])
        n_opponents = self.n_players - 1
        if k < 0 or k > n_opponents:
            return Action.D
        try:
            m_star = math.ceil(self.n_players * self.capacity / float(current_stock))
        except Exception:
            return Action.D
        if m_star < 0:
            m_star = 0
        elif m_star > self.n_players:
            m_star = self.n_players
        if k < m_star and k + 1 >= m_star:
            return Action.C
        return Action.D

class Strategy_SELFISH_18(BaseStrategy):
    """
    Common-pool strategy:
    - Cooperate in round 1.
    - Later: cooperate when the stock is low, defect near the end, and defect
      after strong prior cooperation if the stock remains high.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(self.n_players - 1, 0)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        rounds_left = self.n_rounds - history.round_number
        if current_stock <= self.capacity / 2:
            return Action.C
        if rounds_left <= 2:
            return Action.D
        prev_coop = 0
        if len(history.opponent_cooperators) > 0:
            prev_coop = int(history.opponent_cooperators[-1])
        high_coop_signal = False
        if self.n_players == 2:
            high_coop_signal = prev_coop == 1
        else:
            q = prev_coop / self.n_opponents if self.n_opponents > 0 else 0.0
            high_coop_signal = q >= 2.0 / 3.0
        if high_coop_signal and current_stock >= 3.0 * self.capacity / 4.0:
            return Action.D
        return Action.C

class Strategy_SELFISH_19(BaseStrategy):
    """
    Selfish common-pool strategy:
    - Defect by default.
    - Cooperate only after sustained opponent restraint, in the productive middle stock band,
      and never on the final round.
    - If stock is critically low, cooperate only under full restraint from the previous round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds
        self.capacity = float(game_description.capacity)
        self.good_streak = 0

    def _q_from_opponents(self, opponent_count: int) -> float:
        n = self.n_players
        if n <= 2:
            return 1.0 if opponent_count >= 1 else 0.0
        return opponent_count / float(n - 1)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        if round_number >= self.n_rounds - 1:
            return Action.D
        if round_number == 0:
            return Action.D
        prev_opponents = int(history.opponent_cooperators[-1])
        prev_q = self._q_from_opponents(prev_opponents)
        streak = 0
        for idx in range(round_number - 1, -1, -1):
            opp_c = int(history.opponent_cooperators[idx])
            q = self._q_from_opponents(opp_c)
            if q >= 0.8:
                streak += 1
            else:
                break
        self.good_streak = streak
        if current_stock <= self.capacity / 4.0:
            return Action.C if prev_q >= 1.0 else Action.D
        middle_band = self.capacity / 3.0 <= current_stock <= 2.0 * self.capacity / 3.0
        if middle_band and prev_q >= 0.8 and (self.good_streak >= 2):
            return Action.C
        return Action.D

class Strategy_SELFISH_20(BaseStrategy):
    """
    Selfish threshold strategy for the Common Pool Resource Game.

    - Cooperates in round 1.
    - In intermediate rounds, cooperates only if the pool is healthy and the
      previous round had sufficiently many cooperating opponents.
    - Defects in the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.mode = 'coop'
        self.last_k = None
        n = int(getattr(game_description, 'n_players', 0) or 0)
        self._coop_threshold = math.ceil(3 * (n - 1) / 4) if n >= 2 else 0
        self._capacity_third = float(getattr(game_description, 'capacity', 0)) / 3.0
        self._n_rounds = int(getattr(game_description, 'n_rounds', 0) or 0)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_rounds = self._n_rounds
        round_number = int(getattr(history, 'round_number', 0) or 0)
        if history.opponent_cooperators is not None and len(history.opponent_cooperators) > 0:
            self.last_k = int(history.opponent_cooperators[-1])
        if current_stock <= 0:
            self.mode = 'defect'
            return Action.D
        if round_number == 0:
            self.mode = 'coop'
            return Action.C
        if n_rounds > 0 and round_number >= n_rounds - 1:
            self.mode = 'defect'
            return Action.D
        if current_stock <= self._capacity_third:
            self.mode = 'defect'
            return Action.D
        if self.last_k is not None and self.last_k >= self._coop_threshold:
            self.mode = 'coop'
            return Action.C
        self.mode = 'defect'
        return Action.D

class Strategy_SELFISH_21(BaseStrategy):
    """
    Opportunistic cooperative strategy:
    - Start by cooperating in longer games, defecting immediately in 2-round games.
    - In intermediate rounds, cooperate only when the stock is low enough and
      the opponents showed at least half cooperation in the previous round.
    - Defect in the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = int(history.round_number)
        if t == 0:
            return Action.D if self.n_rounds == 2 else Action.C
        if t >= self.n_rounds - 1:
            return Action.D
        n_opponents = max(self.n_players - 1, 0)
        if n_opponents <= 0:
            rho = 0.0
        else:
            last_opponent_cooperators = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
            rho = last_opponent_cooperators / n_opponents
        stock_threshold = self.capacity / 2.0
        if current_stock <= stock_threshold and rho >= 0.5:
            return Action.C
        return Action.D

class Strategy_SELFISH_22(BaseStrategy):
    """
    Conservative exploit-and-preserve strategy for the Common Pool Resource Game.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.n_players
        r = self.n_rounds
        t = history.round_number + 1
        m = r - t + 1
        stock = float(current_stock)
        capacity = self.capacity if self.capacity > 0 else 1.0
        x = stock / capacity
        opp_count = 0
        if history.round_number > 0 and len(history.opponent_cooperators) > 0:
            opp_count = int(history.opponent_cooperators[-1])
        n_opponents = max(n - 1, 1)
        q = opp_count / n_opponents
        if m <= 2:
            return Action.D
        if history.round_number == 0:
            return Action.C if r >= 6 else Action.D
        if x < 0.4 or q < 0.5:
            return Action.D
        if q >= 0.75 and x >= 0.6:
            return Action.C
        if q >= 0.5 and x >= 0.8 and (m >= 4):
            return Action.C
        if q >= 0.8 and x >= 0.7 and (m > 2):
            return Action.C
        if q < 0.5:
            return Action.D
        return Action.D

class Strategy_SELFISH_23(BaseStrategy):
    """
    Common-pool strategy that estimates opponent cooperation with exponential
    smoothing and cooperates only when needed to keep the predicted next stock
    above a declining reserve threshold.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.q_hat = 0.5
        self.t = 1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = int(self.game_description.n_players)
        r = int(self.game_description.n_rounds)
        capacity = float(self.game_description.capacity)
        if history.round_number >= r - 1:
            self.t = history.round_number + 1
            return Action.D
        n_opponents = max(n - 1, 0)
        if history.round_number == 0 or n_opponents == 0:
            q_obs = 0.5
        else:
            last_coop = float(history.opponent_cooperators[-1])
            q_obs = last_coop / n_opponents if n_opponents > 0 else 0.5
            if q_obs < 0.0:
                q_obs = 0.0
            elif q_obs > 1.0:
                q_obs = 1.0
        self.q_hat = 0.7 * q_obs + 0.3 * self.q_hat
        if self.q_hat < 0.0:
            self.q_hat = 0.0
        elif self.q_hat > 1.0:
            self.q_hat = 1.0
        y = int(round(n_opponents * self.q_hat))
        if y < 0:
            y = 0
        elif y > n_opponents:
            y = n_opponents

        def next_stock(x: float) -> float:
            x = max(0.0, min(float(x), capacity))
            growth = 2.0 * x * (1.0 - x / capacity) if capacity > 0 else 0.0
            return min(x + growth, capacity)
        remaining_if_C = float(current_stock) * (y + 1) / (2.0 * n) if n > 0 else float(current_stock)
        remaining_if_D = float(current_stock) * y / (2.0 * n) if n > 0 else float(current_stock)
        R_C = next_stock(remaining_if_C)
        R_D = next_stock(remaining_if_D)
        if r <= 1:
            reserve = 0.0
        else:
            reserve = capacity * (r - history.round_number - 1) / (2.0 * (r - 1))
            reserve = max(0.0, min(reserve, capacity / 2.0))
        if R_D < reserve and R_C >= reserve:
            action = Action.C
        else:
            action = Action.D
        self.t = history.round_number + 1
        return action

class Strategy_SELFISH_24(BaseStrategy):
    """
    Aggressive common-pool strategy:
    - Cooperate in round 1
    - In later rounds, defect in the final round, or when opponents recently cooperated heavily
    - Otherwise cooperate only when the stock is at or below half capacity
    - Once the stock reaches zero, defect thereafter
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        if round_number == 0:
            return Action.C
        if current_stock is not None and current_stock <= 0.0:
            return Action.D
        if round_number >= self.n_rounds - 1:
            return Action.D
        c = None
        if hasattr(history, 'opponent_cooperators') and len(history.opponent_cooperators) > 0:
            c = int(history.opponent_cooperators[-1])
        if c is None:
            return Action.C
        if c >= self.n_players - 2:
            return Action.D
        half_capacity = self.capacity / 2.0
        if current_stock is not None and current_stock <= half_capacity:
            return Action.C
        return Action.D

class Strategy_SELFISH_25(BaseStrategy):
    """
    Trust-based common-pool strategy:
    - Starts by defecting.
    - Builds trust from the observed cooperation rate of opponents.
    - Defects in the last round, under low stock, or after signs of betrayal.
    - Enters a persistent fallback mode after low-cooperation rounds and only
      returns to cooperation after two consecutive high-cooperation observations.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.trust = 0.0
        self.fallback_active = False
        self.recovery_streak = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.n
        cap = self.capacity
        round_number = history.round_number
        if round_number == 0:
            self.trust = 0.0
            self.fallback_active = False
            self.recovery_streak = 0
            return Action.D
        if round_number >= self.r - 1:
            if history.opponent_cooperators.size > 0:
                c_last = int(history.opponent_cooperators[-1])
                if n > 1:
                    self.trust = 0.7 * self.trust + 0.3 * (c_last / (n - 1))
            return Action.D
        c_last = int(history.opponent_cooperators[-1]) if history.opponent_cooperators.size > 0 else 0
        if n > 1:
            self.trust = 0.7 * self.trust + 0.3 * (c_last / (n - 1))
        else:
            self.trust = 0.0
        high_coop_threshold = max(0, n - 2)
        if c_last < high_coop_threshold:
            self.fallback_active = True
            self.recovery_streak = 0
            self.trust = 0.0
        if self.fallback_active:
            if round_number >= 2 and int(history.opponent_cooperators[-1]) >= high_coop_threshold and (int(history.opponent_cooperators[-2]) >= high_coop_threshold) and (current_stock >= cap / 2.0):
                self.recovery_streak += 1
            else:
                self.recovery_streak = 0
            if self.recovery_streak >= 2:
                self.fallback_active = False
                self.recovery_streak = 0
            else:
                return Action.D
        if current_stock <= cap / 2.0:
            return Action.D
        if n > 1 and self.trust < 1.0 - 1.0 / n:
            return Action.D
        if c_last <= n - 3:
            return Action.D
        if current_stock >= 0.9 * cap and self.trust == 1.0:
            return Action.C
        if self.trust >= 1.0 - 1.0 / n:
            if current_stock >= cap / 2.0:
                return Action.C
        return Action.D

class Strategy_SELFISH_26(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Defect in round 1 and on the final round.
    - Otherwise, use the previous round's opponent cooperation and the current
      stock to estimate whether cooperating preserves enough future value to
      outweigh the immediate loss.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.opponents = max(0, self.n_players - 1)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.n_players
        cap = self.capacity
        opps = self.opponents
        round_number = int(history.round_number)
        m = self.n_rounds - round_number
        if round_number == 0:
            return Action.D
        if m <= 1:
            return Action.D
        if current_stock <= 0.0:
            return Action.D
        if len(history.opponent_cooperators) == 0:
            return Action.D
        k = int(history.opponent_cooperators[-1])
        if k <= 0:
            return Action.D
        if k > opps:
            k = opps
        denom = 2.0 * n if n > 0 else 1.0
        r_c = current_stock * (k + 1) / denom
        r_d = current_stock * k / denom
        if cap <= 0.0:
            n_c = 0.0
            n_d = 0.0
        else:
            n_c = min(3.0 * r_c - 2.0 * (r_c * r_c) / cap, cap)
            n_d = min(3.0 * r_d - 2.0 * (r_d * r_d) / cap, cap)
        immediate_loss = current_stock / denom
        future_gain = (m - 1) * (n_c - n_d)
        if future_gain > immediate_loss:
            return Action.C
        return Action.D

class Strategy_SELFISH_27(BaseStrategy):
    """
    Conditional cooperation strategy for the common pool resource game.

    - Round 1: defect.
    - Strong cooperation is only sustained after unanimous cooperation by opponents,
      or when the stock is high and the observed majority is cooperative.
    - Defaults to defection in mixed, depleted, or uncertain states.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(0, self.n_players - 1)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        if round_number == 0:
            return Action.D
        last_opponents = int(history.opponent_cooperators[-1])
        last_my_action = bool(history.my_actions[-1])
        if current_stock is None or not isinstance(current_stock, (int, float)) or (not math.isfinite(float(current_stock))):
            return Action.C if last_opponents == self.n_opponents else Action.D
        stock = float(current_stock)
        cap = self.capacity if self.capacity > 0 else 1.0
        x = stock / cap
        if round_number >= self.n_rounds - 1:
            return Action.C if last_opponents == self.n_opponents and x >= 2.0 / 3.0 else Action.D
        c = last_opponents
        d = self.n_opponents - c
        if c <= self.n_opponents / 2.0:
            if c == self.n_opponents:
                return Action.C
            if x >= 2.0 / 3.0 and c > d:
                return Action.C
            return Action.D
        if last_my_action:
            if c < self.n_opponents:
                return Action.D
            return Action.C if x >= 2.0 / 3.0 else Action.D
        if c == self.n_opponents:
            return Action.C
        if c == 0:
            return Action.D
        if x >= 2.0 / 3.0 and c >= d:
            return Action.C
        return Action.D

class Strategy_SELFISH_28(BaseStrategy):
    """
    Stock-preserving threshold strategy with conditional defection.

    - Cooperate early only when the stock is healthy.
    - Continue cooperating only if the previous round showed sufficiently high
      opponent cooperation and cooperation appears at least as stock-preserving
      as defection.
    - Defect in the final round and whenever the stock is low or opponent
      cooperation deteriorates.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.m = max(0, self.n - 1)
        self.coop_threshold = (self.n - 2) / self.m if self.m > 0 else 1.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number + 1
        S = float(current_stock)
        if t >= self.r:
            return Action.D
        if S <= 0.0 or S <= 2.0 * self.n:
            return Action.D
        if t == 1:
            return Action.C if self.capacity > 2.0 * self.n else Action.D
        if len(history.opponent_cooperators) == 0 or self.m <= 0:
            return Action.C if S > 2.0 * self.n and self.capacity > 2.0 * self.n else Action.D
        last_k = int(history.opponent_cooperators[-1])
        c = last_k / self.m if self.m > 0 else 0.0
        S_after_C = S - S / (2.0 * self.n)
        S_next_C = S_after_C + 2.0 * S_after_C * (1.0 - S_after_C / self.capacity)
        S_next_C = min(S_next_C, self.capacity)
        S_after_D = S - S / self.n
        S_next_D = S_after_D + 2.0 * S_after_D * (1.0 - S_after_D / self.capacity)
        S_next_D = min(S_next_D, self.capacity)
        if c >= self.coop_threshold and S_next_C >= S_next_D:
            return Action.C
        return Action.D

class Strategy_SELFISH_29(BaseStrategy):
    """
    Defect initially, then cooperate only after sufficiently broad prior cooperation
    and only when the current stock is not too high. Always defect in the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self._cooperation_threshold = math.ceil((self.n_players - 1) / 2)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number + 1
        if history.round_number == 0:
            return Action.D
        if current_round >= self.n_rounds:
            return Action.D
        if len(history.opponent_cooperators) == 0:
            return Action.D
        previous_opponent_cooperators = int(history.opponent_cooperators[-1])
        stock_ok = float(current_stock) <= 2.0 * self.capacity / 3.0
        if previous_opponent_cooperators >= self._cooperation_threshold and stock_ok:
            return Action.C
        return Action.D

class Strategy_SELFISH_30(BaseStrategy):
    """
    Selfish common-pool strategy:
    - Tracks opponent cooperation with an exponential moving average.
    - Defaults to defection, cooperating only when projected future value is clearly higher.
    - Always defects on the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.p = 1.0
        self._last_opponent_cooperators = None

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = int(self.game_description.n_players)
        r = int(self.game_description.n_rounds)
        capacity = float(self.game_description.capacity)
        round_number = int(history.round_number)
        if round_number >= r - 1:
            return Action.D
        if round_number == 0:
            self.p = 1.0
        else:
            last_opp = int(history.opponent_cooperators[-1])
            n_opponents = max(n - 1, 1)
            if last_opp <= 0:
                self.p = 0.0
                self._last_opponent_cooperators = 0
                return Action.D
            q = last_opp / n_opponents
            self.p = 0.7 * self.p + 0.3 * q
            self._last_opponent_cooperators = last_opp
        o = (n - 1) * self.p

        def projected_score(play_c: bool) -> tuple[float, float]:
            self_consumption = current_stock / (2 * n) if play_c else current_stock / n
            total_cooperators = o + 1.0 if play_c else o
            remaining_after_consumption = current_stock * total_cooperators / (2 * n)
            next_stock = remaining_after_consumption + 2.0 * remaining_after_consumption * (1.0 - remaining_after_consumption / capacity)
            next_stock = min(next_stock, capacity)
            score = self_consumption + (r - round_number - 1) / (2 * n) * next_stock
            return (score, next_stock)
        score_c, next_c = projected_score(True)
        score_d, next_d = projected_score(False)
        if abs(next_c - next_d) <= 1e-12:
            return Action.D
        if abs(score_c - score_d) <= 1e-12:
            return Action.D
        return Action.C if score_c > score_d else Action.D

class Strategy_SELFISH_31(BaseStrategy):
    """
    Greedy state-based strategy with retaliation and recovery:
    - First round: cooperate only in the 2-player game, otherwise defect.
    - Middle rounds: cooperate only when stock is high and opponents were highly cooperative.
    - Last round: defect.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.opponents = max(self.n_players - 1, 0)
        self.half_capacity = self.capacity / 2.0
        self.coop_threshold = 1.0 - 1.0 / self.n_players if self.n_players > 0 else 1.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = int(history.round_number)
        if t >= self.n_rounds - 1:
            return Action.D
        if t == 0:
            return Action.C if self.n_players == 2 else Action.D
        if len(history.opponent_cooperators) == 0:
            return Action.D
        k = int(history.opponent_cooperators[-1])
        m = self.opponents
        if m <= 0:
            return Action.D
        c_prev = k / m
        if float(current_stock) > self.half_capacity and c_prev > self.coop_threshold:
            return Action.C
        return Action.D

class Strategy_SELFISH_32(BaseStrategy):
    """
    Adaptive common-pool strategy that estimates opponent cooperation with
    exponential smoothing, evaluates a one-step lookahead score, and defects
    in the final round and when preservation is not worthwhile.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self._eps = 1e-09

    def _next_stock(self, remaining_stock: float) -> float:
        cap = self.capacity
        if cap <= 0:
            return 0.0
        nxt = 3.0 * remaining_stock - 2.0 * remaining_stock * remaining_stock / cap
        if nxt > cap:
            return cap
        if nxt < 0.0:
            return 0.0
        return nxt

    def _estimate_q(self, history: PlayerHistory) -> float:
        n_opponents = max(self.n - 1, 1)
        q = 0.5
        if history.round_number <= 0:
            return q
        coop_counts = history.opponent_cooperators
        rounds_seen = min(history.round_number, len(coop_counts))
        for t in range(rounds_seen):
            observed = float(coop_counts[t]) / float(n_opponents)
            if observed < 0.0:
                observed = 0.0
            elif observed > 1.0:
                observed = 1.0
            q = 0.5 * (q + observed)
            if q < 0.0:
                q = 0.0
            elif q > 1.0:
                q = 1.0
        return q

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number
        S = float(current_stock)
        if t == 0:
            return Action.C
        if t >= self.r - 1:
            return Action.D
        q = self._estimate_q(history)
        n = max(self.n, 2)
        m = max(self.r - t, 0)
        beta = float(m) / float(m + 1) if m >= 0 else 0.0
        x = float(max(n - 1, 0)) * q
        R_C = S * (1.0 + x) / (2.0 * n)
        R_D = S * x / (2.0 * n)
        S_C_next = self._next_stock(R_C)
        S_D_next = self._next_stock(R_D)
        score_C = S / (2.0 * n) + beta * S_C_next / (2.0 * n)
        score_D = S / n + beta * S_D_next / (2.0 * n)
        if q >= 0.5 and S >= self.capacity / 2.0:
            if score_C > score_D + self._eps:
                return Action.C
        return Action.D

class Strategy_SELFINTERESTED_5(BaseStrategy):
    """
    Conservative threshold-based strategy for the Common Pool Resource Game.

    - Defects in round 1 and the last round.
    - Cooperates only when stock is high, recent cooperation is sufficiently high,
      and stock has not dropped sharply relative to the previous round.
    - Uses an internal memory of the previous round's stock and own action to
      support stabilization behavior.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self._prev_stock: float | None = None
        self._prev_action: Action = Action.D
        self._forced_defect: bool = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_players = int(self.game_description.n_players)
        n_rounds = int(self.game_description.n_rounds)
        capacity = float(self.game_description.capacity)
        round_number = int(history.round_number)
        if round_number == 0 or round_number >= n_rounds - 1:
            self._prev_stock = float(current_stock)
            self._prev_action = Action.D
            self._forced_defect = True if round_number != 0 else False
            return Action.D
        k_last = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        prev_stock = self._prev_stock if self._prev_stock is not None else float(current_stock)
        k_req = math.ceil((n_players - 1) / 2)
        stock_high = float(current_stock) > 0.75 * capacity
        cooperation_high = k_last > k_req
        stock_drop_small = prev_stock - float(current_stock) < 0.25 * capacity
        can_cooperate = stock_high and cooperation_high and stock_drop_small
        if self._forced_defect:
            action = Action.C if can_cooperate else Action.D
        else:
            action = Action.C if can_cooperate else Action.D
        self._forced_defect = action == Action.D and (not can_cooperate)
        self._prev_stock = float(current_stock)
        self._prev_action = action
        return action

class Strategy_SELFINTERESTED_6(BaseStrategy):
    """
    Conservative common-pool strategy:
    - Start by cooperating.
    - Defect in the last two rounds.
    - Defect when stock is low or cooperation among opponents drops below the near-universal threshold.
    - Cooperate only when cooperation has remained very high and the stock stays healthy.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.t = 0
        self.S = self.capacity
        self.k = 0
        self.k_prev = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        self.t = history.round_number + 1
        self.S = float(current_stock)
        n_opponents = max(self.n - 1, 0)
        if history.round_number > 0 and len(history.opponent_cooperators) > 0:
            self.k = int(history.opponent_cooperators[-1])
        else:
            self.k = 0
        if history.round_number > 1 and len(history.opponent_cooperators) > 1:
            self.k_prev = int(history.opponent_cooperators[-2])
        else:
            self.k_prev = 0
        if self.t == self.r or self.t == self.r - 1:
            return Action.D
        if self.t == 1:
            return Action.C
        if self.capacity > 0 and self.S <= self.capacity / 4.0:
            return Action.D
        if self.k <= self.n - 3:
            return Action.D
        if self.k == self.n - 2:
            if self.k_prev >= self.n - 2 and self.capacity > 0 and (self.S >= self.capacity / 2.0):
                return Action.C
            return Action.D
        if self.k == self.n - 1:
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_7(BaseStrategy):
    """
    Preserves the pool early, cooperates only under recent trust and healthy stock,
    and defects in the final round or when the pool/history become unreliable.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(self.n_players - 1, 0)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        if round_number == 0:
            return Action.C
        if round_number >= self.n_rounds - 1:
            return Action.D
        stock = float(current_stock)
        cap = self.capacity
        if stock < cap / 3.0:
            return Action.D
        last_k = int(history.opponent_cooperators[-1]) if round_number >= 1 else 0
        prev_k = int(history.opponent_cooperators[-2]) if round_number >= 2 else None
        if last_k <= 0:
            return Action.D
        if round_number >= 2 and prev_k is not None:
            if last_k >= self.n_opponents and prev_k >= self.n_opponents and (stock >= cap / 2.0):
                return Action.C
        t = round_number + 1
        if t == self.n_rounds - 1:
            if last_k >= self.n_opponents and stock >= 3.0 * cap / 4.0:
                return Action.C
            return Action.D
        if 2 <= t <= self.n_rounds - 2:
            if self.n_opponents <= 0:
                return Action.D
            rho_last = last_k / self.n_opponents
            if round_number == 1:
                rho = rho_last
            else:
                rho_prev = prev_k / self.n_opponents if prev_k is not None else rho_last
                rho = (rho_last + rho_prev) / 2.0
            if rho >= 0.5 and stock >= cap / 2.0:
                return Action.C
            return Action.D
        return Action.D

class Strategy_SELFINTERESTED_8(BaseStrategy):
    """
    Common-pool strategy:
    - Start with cooperation.
    - Cooperate when the stock is fragile or when opponents were highly cooperative.
    - Defect when opponents extracted heavily and the stock is comfortably above the midpoint.
    - On the last round, defect only if the stock is clearly abundant.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self._half_capacity = self.capacity / 2.0
        self._low_stock_threshold = 2.0 * self.n
        self._opponent_count = max(0, self.n - 1)

    def _update_stock(self, stock: float, k: int, my_action: Action) -> float:
        n = self.n
        cap = self.capacity
        if n <= 0 or cap <= 0:
            return max(0.0, min(float(stock), cap))
        stock = float(stock)
        k = int(max(0, min(k, self._opponent_count)))
        coop_cons = stock / (2.0 * n)
        defect_cons = stock / n
        total_cons = k * coop_cons + max(0, self._opponent_count - k) * defect_cons + (coop_cons if my_action == Action.C else defect_cons)
        remaining = max(0.0, stock - total_cons)
        growth = 2.0 * remaining * (1.0 - remaining / cap) if cap > 0 else 0.0
        nxt = min(remaining + growth, cap)
        return max(0.0, nxt)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        stock = float(current_stock)
        if round_number == 0:
            return Action.C
        if round_number >= self.r - 1:
            return Action.D if stock > self._low_stock_threshold else Action.C
        k = 0
        if len(history.opponent_cooperators) > 0:
            k = int(history.opponent_cooperators[-1])
        if stock <= self._low_stock_threshold:
            return Action.C
        if k >= self._opponent_count:
            return Action.C
        if k <= self._opponent_count / 2.0:
            return Action.D if stock >= self._half_capacity else Action.C
        if stock < self._half_capacity:
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_9(BaseStrategy):
    """
    Adaptive build/harvest strategy for the Common Pool Resource Game.

    Core behavior:
    - Start in build mode and cooperate.
    - Defect in harvest mode or when cooperation appears unstable.
    - Force cooperation at stock exhaustion until the pool becomes positive.
    - Respond to collapse by defecting for two rounds.
    - Tighten behavior in the final two rounds.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.mode = 'build'
        self.last_seen_stock = None
        self.collapse_lock_remaining = 0
        self.prev_q = None
        self.prev_prev_q = None
        self.prev_stock_increase = True

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = float(self.game_description.capacity)
        round_number = history.round_number
        last_round = r - 1
        penultimate_round = r - 2
        n_opponents = max(1, n - 1)

        def coop_ratio_from_round(idx: int) -> float:
            if idx < 0 or idx >= len(history.opponent_cooperators):
                return 1.0
            return float(history.opponent_cooperators[idx]) / float(n_opponents)
        q_prev = coop_ratio_from_round(round_number - 1)
        q_prev2 = coop_ratio_from_round(round_number - 2)
        if self.last_seen_stock is None:
            stock_increased_prev_transition = True
        else:
            stock_increased_prev_transition = float(current_stock) > float(self.last_seen_stock)
        did_not_increase_prev_transition = not stock_increased_prev_transition
        if round_number >= last_round:
            self._update_memory_after_decision(current_stock, q_prev, did_not_increase_prev_transition)
            return Action.D
        if round_number == penultimate_round:
            if float(current_stock) > 0.75 * capacity and q_prev >= 1.0 and (q_prev2 >= 1.0):
                self._update_memory_after_decision(current_stock, q_prev, did_not_increase_prev_transition)
                return Action.C
            self._update_memory_after_decision(current_stock, q_prev, did_not_increase_prev_transition)
            return Action.D
        if float(current_stock) <= 0.0:
            self._update_memory_after_decision(current_stock, q_prev, did_not_increase_prev_transition)
            return Action.C
        if round_number > 0 and q_prev <= 0.0 and (self.collapse_lock_remaining <= 0):
            self.collapse_lock_remaining = 2
        if self.collapse_lock_remaining > 0:
            action = Action.D
            self.collapse_lock_remaining -= 1
            self._update_memory_after_decision(current_stock, q_prev, did_not_increase_prev_transition)
            return action
        next_mode = self.mode
        if self.mode == 'build':
            action = Action.C
            if float(current_stock) <= 0.5 * capacity or q_prev < 0.5 or did_not_increase_prev_transition:
                next_mode = 'harvest'
        else:
            action = Action.D
            if float(current_stock) >= 0.75 * capacity and q_prev >= 0.75 and (q_prev2 >= 0.75):
                next_mode = 'build'
        self.mode = next_mode
        self._update_memory_after_decision(current_stock, q_prev, did_not_increase_prev_transition)
        return action

    def _update_memory_after_decision(self, current_stock: float, q_prev: float, did_not_increase_prev_transition: bool) -> None:
        self.last_seen_stock = float(current_stock)
        self.prev_prev_q = self.prev_q
        self.prev_q = float(q_prev)
        self.prev_stock_increase = not did_not_increase_prev_transition

class Strategy_SELFINTERESTED_10(BaseStrategy):
    """
    Memory-light common pool strategy:
    - Defect in the first and last rounds.
    - Otherwise cooperate only when recent opponent cooperation is sufficiently high
      and the stock is in a prudent range.
    - Bias toward defection under high stock or weak recent cooperation.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.q = math.ceil((self.n_players - 1) / 2)
        self.half_capacity = self.capacity / 2.0
        self.quarter_capacity = self.capacity / 4.0
        self.three_quarter_capacity = 3.0 * self.capacity / 4.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        if round_number == 0 or round_number >= self.n_rounds - 1:
            return Action.D
        if current_stock > self.three_quarter_capacity:
            return Action.D
        last_c = int(history.opponent_cooperators[-1]) if round_number >= 1 else 0
        prev_c = int(history.opponent_cooperators[-2]) if round_number >= 2 else None
        if current_stock < self.quarter_capacity:
            if last_c >= 1:
                return Action.C
            return Action.D
        if round_number >= 2:
            if prev_c is not None and last_c >= self.q and (prev_c >= self.q) and (current_stock <= self.half_capacity):
                return Action.C
            return Action.D
        if last_c >= self.q and current_stock <= self.half_capacity:
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_11(BaseStrategy):
    """
    Strategy for the Common Pool Resource game:
    - Cooperate on the first round
    - Defect on the last round or when the stock is exhausted
    - Otherwise, estimate opponent cooperation from the previous round and
      choose the action with the higher long-run score, breaking ties toward D
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.n
        r = self.r
        cap = self.capacity
        s = float(current_stock)
        if history.round_number == 0:
            return Action.C
        if s <= 0.0:
            return Action.D
        if history.round_number >= r - 1:
            return Action.D
        remaining_rounds = r - history.round_number
        prev_k = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        if n <= 1:
            q = 0.0
        else:
            q = prev_k / float(n - 1)
        m_c = 1.0 + q * (n - 1)
        m_d = q * (n - 1)

        def next_stock(hyp_m: float) -> float:
            denom = 2.0 * n
            remaining = s * hyp_m / denom
            growth = 2.0 * remaining * (1.0 - remaining / cap) if cap > 0.0 else 0.0
            nxt = remaining + growth
            return min(nxt, cap)
        score_c = s / (2.0 * n) + (remaining_rounds - 1) * next_stock(m_c) / cap
        score_d = s / float(n) + (remaining_rounds - 1) * next_stock(m_d) / cap
        eps = 1e-12
        if score_c > score_d + eps:
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_12(BaseStrategy):
    """
    Trust- and stock-sensitive common pool strategy:
    - Cooperate in round 1
    - Defect in the final round
    - Update a running trust score h from observed opponent cooperation
    - Rebuild the pool when stock is low
    - Exploit consistently high trust / high cooperation when appropriate
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(self.n_players - 1, 0)
        self.h = 1.0
        self._prev_stock = None
        self._low_stock_streak = 0
        self._high_stock_streak = 0
        self._force_cooperate = False
        self._force_defect = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        if round_number == 0:
            self.h = 1.0
            self._prev_stock = float(current_stock)
            self._low_stock_streak = 1 if current_stock <= self.capacity / 5 else 0
            self._high_stock_streak = 1 if current_stock >= 3 * self.capacity / 4 else 0
            self._force_cooperate = False
            self._force_defect = False
            return Action.C
        last_opponent_cooperators = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        if self.n_opponents > 0:
            q = last_opponent_cooperators / self.n_opponents
        else:
            q = 0.0
        if q <= 0.0:
            self.h = 0.0
        elif q >= 1.0:
            self.h = 1.0
        else:
            self.h = 0.7 * self.h + 0.3 * q
        if current_stock <= self.capacity / 5:
            self._low_stock_streak += 1
        else:
            self._low_stock_streak = 0
        if current_stock >= 3 * self.capacity / 4:
            self._high_stock_streak += 1
        else:
            self._high_stock_streak = 0
        if self._low_stock_streak >= 2:
            self._force_cooperate = True
        if current_stock > self.capacity / 3:
            self._force_cooperate = False
        if self._high_stock_streak >= 2 and self.h < 0.5:
            self._force_defect = True
        if self.h >= 0.5:
            self._force_defect = False
        if round_number == self.n_rounds - 1:
            self._prev_stock = float(current_stock)
            return Action.D
        if self._force_cooperate:
            self._prev_stock = float(current_stock)
            return Action.C
        if self._force_defect:
            self._prev_stock = float(current_stock)
            return Action.D
        if current_stock <= self.capacity / 4:
            action = Action.C
        elif self.h >= 0.6:
            action = Action.C
        elif self.h <= 0.4:
            action = Action.D
        else:
            action = Action.C if q >= 0.5 else Action.D
        self._prev_stock = float(current_stock)
        return action

class Strategy_SELFINTERESTED_13(BaseStrategy):
    """
    Stock-preservation strategy with a rolling cooperation estimate and
    conservative defection on the final round or under weak cooperation.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.low_stock_mode = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = max(2, self.n)
        r = max(1, self.r)
        cap = max(1e-12, self.capacity)
        t = int(history.round_number) + 1
        last_round = t >= r
        if t == 1:
            return Action.C
        if last_round:
            return Action.D
        if current_stock < 0.4 * cap:
            self.low_stock_mode = True
        prev_k = 0
        if history.opponent_cooperators.size > 0:
            prev_k = int(history.opponent_cooperators[-1])
        denom = max(1, n - 1)
        q_last = prev_k / denom
        window_len = min(3, history.opponent_cooperators.size)
        if window_len > 0:
            recent_q = [int(x) / denom for x in history.opponent_cooperators[-window_len:]]
            q_bar = float(np.mean(recent_q))
            if recent_q[-1] < 0.5:
                q_bar = recent_q[-1]
        else:
            q_bar = 1.0
        if self.low_stock_mode:
            if not (q_bar >= 0.85 and current_stock >= 0.7 * cap):
                return Action.D
        if current_stock <= 0.0:
            return Action.D

        def forecast_next_stock(c: int) -> float:
            r_val = current_stock * c / (2.0 * n)
            next_stock = 3.0 * r_val - 2.0 * (r_val * r_val) / cap
            return min(next_stock, cap)
        c_coop = prev_k + 1
        c_def = prev_k
        n_c = forecast_next_stock(c_coop)
        n_d = forecast_next_stock(c_def)
        if current_stock >= 0.6 * cap and q_bar >= 0.75 and (n_c >= 0.5 * cap) and (n_c >= n_d + 0.1 * cap / r):
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_14(BaseStrategy):
    """
    Exponentially weighted reciprocity strategy for the common pool resource game.
    Starts cooperative, then becomes increasingly conservative near the end,
    with decisions driven by current stock and a smoothed estimate of opponent cooperation.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.coop_rate = 1.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = float(self.game_description.capacity)
        t = history.round_number + 1
        remaining_rounds = r - t + 1
        if current_stock <= 0:
            return Action.D
        coop_rate = 1.0
        n_opponents = max(n - 1, 1)
        rounds_played = history.round_number
        for idx in range(rounds_played):
            k = int(history.opponent_cooperators[idx])
            frac = k / n_opponents
            coop_rate = 0.6 * coop_rate + 0.4 * frac
        self.coop_rate = coop_rate
        if remaining_rounds == 1:
            return Action.D
        if t == 1:
            return Action.C
        if remaining_rounds == 2:
            return Action.D
        half_capacity = capacity / 2.0
        three_quarters_capacity = 3.0 * capacity / 4.0
        if current_stock >= half_capacity and coop_rate >= 0.5:
            return Action.C
        elif current_stock >= three_quarters_capacity and coop_rate >= 1.0 / 3.0:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_15(BaseStrategy):
    """
    Exponential-moving-estimate strategy for the common pool resource game.

    Cooperates when doing so helps keep the projected stock in the recovery range,
    defects when the pool is healthy enough to exploit, and becomes conservative
    in the final rounds if necessary to avoid collapse.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.q = 1.0
        self._last_updated_round = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = max(int(self.game_description.n_players), 2)
        r = max(int(self.game_description.n_rounds), 1)
        capacity = float(self.game_description.capacity)
        capacity = max(capacity, 1e-12)
        round_number = int(history.round_number)
        n_opponents = max(n - 1, 1)
        while self._last_updated_round < round_number:
            idx = self._last_updated_round
            opp_coop = float(history.opponent_cooperators[idx]) if idx < len(history.opponent_cooperators) else 0.0
            observed_rate = opp_coop / n_opponents
            self.q = 0.7 * self.q + 0.3 * observed_rate
            self.q = min(1.0, max(0.0, self.q))
            self._last_updated_round += 1
        if round_number == 0:
            return Action.C
        R = max(r - round_number, 1)
        S = max(float(current_stock), 0.0)
        k = int(round((n - 1) * self.q))
        k = max(0, min(n - 1, k))

        def projected_remaining_stock(action: Action) -> float:
            coop_count = k + (1 if action == Action.C else 0)
            defect_count = n - 1 - k + (1 if action == Action.D else 0)
            total_consumption = coop_count * (S / (2.0 * n)) + defect_count * (S / n)
            rem = S - total_consumption
            return max(rem, 0.0)
        rem_c = projected_remaining_stock(Action.C)
        rem_d = projected_remaining_stock(Action.D)
        if R <= 1:
            return Action.D
        if rem_d >= capacity / 2.0:
            return Action.D
        if rem_c >= capacity / 2.0:
            return Action.C
        if R <= 3:
            return Action.D if rem_d > 0.0 else Action.C

        def score(action: Action) -> float:
            rem = rem_c if action == Action.C else rem_d
            immediate = S / (2.0 * n) if action == Action.C else S / n
            next_stock = min(rem + 2.0 * rem * (1.0 - rem / capacity), capacity)
            return immediate + (R - 1.0) / R * (next_stock / (2.0 * n))
        return Action.C if score(Action.C) > score(Action.D) else Action.D

class Strategy_SELFINTERESTED_16(BaseStrategy):
    """
    Stock-aware trust-based strategy for the Common Pool Resource Game.
    Starts cooperative, updates trust from observed opponent cooperation,
    and switches to persistent defection when trust becomes too low.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.trust = 1.0
        self.last_coop_rate = 1.0
        self.persistent_defect = False
        self.last_my_action = Action.C

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        capacity = float(self.game_description.capacity)
        rounds_done = history.round_number
        rounds_remaining = self.game_description.n_rounds - rounds_done
        if rounds_done == 0:
            self.last_my_action = Action.C
            return Action.C
        n_opponents = max(0, n - 1)
        last_opponent_coop_count = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        if n_opponents > 0:
            coop_rate = max(0.0, min(1.0, last_opponent_coop_count / n_opponents))
        else:
            coop_rate = 0.0
        self.trust = 0.7 * self.trust + 0.3 * coop_rate
        self.last_coop_rate = coop_rate
        if self.last_my_action == Action.D and coop_rate >= 0.75:
            self.trust = min(1.0, self.trust + 0.2)
        if self.trust < 0.35:
            self.persistent_defect = True
        if self.persistent_defect:
            if coop_rate >= 0.75 and current_stock >= 0.8 * capacity:
                self.persistent_defect = False
            else:
                self.last_my_action = Action.D
                return Action.D
        if rounds_remaining <= 1:
            self.last_my_action = Action.D
            return Action.D
        if current_stock <= 2.0 * n:
            self.last_my_action = Action.D
            return Action.D
        if self.trust >= 0.75 and current_stock >= 0.9 * capacity:
            self.last_my_action = Action.C
            return Action.C
        if self.trust >= 0.6 and current_stock >= 0.75 * capacity and (rounds_remaining >= 3):
            self.last_my_action = Action.C
            return Action.C
        if self.trust >= 0.45 and self.last_coop_rate >= 0.5 and (current_stock >= 0.8 * capacity):
            self.last_my_action = Action.C
            return Action.C
        self.last_my_action = Action.D
        return Action.D

class Strategy_SELFINTERESTED_17(BaseStrategy):
    """
    Conditional cooperation strategy for the common pool resource game.

    - Cooperates in the first round.
    - Defects in the last round.
    - Defects when stock is low, with a sticky low-stock mode until the pool
      recovers and the group shows near-full cooperation.
    - Cooperates only when previous cooperation is strong and stock is healthy.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.last_round_seen = -1
        self.low_stock_mode = False
        self.last_observed_q = 0
        self.last_observed_stock = self.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = int(history.round_number)
        S = float(current_stock) if current_stock is not None else 0.0
        if self.capacity <= 0 or self.n <= 1 or self.r <= 1:
            return Action.D
        if t > 0:
            q = int(history.opponent_cooperators[-1])
            self.last_observed_q = q
            self.last_observed_stock = S
            self.last_round_seen = t - 1
            if S <= self.capacity / 4.0 or S <= 0.0:
                self.low_stock_mode = True
            if self.low_stock_mode and S >= self.capacity / 2.0 and (q == self.n - 1):
                self.low_stock_mode = False
        if t == 0:
            return Action.C
        if t >= self.r - 1:
            return Action.D
        if S <= 0.0:
            self.low_stock_mode = True
            return Action.D
        if self.low_stock_mode:
            q = int(history.opponent_cooperators[-1]) if t > 0 else 0
            if S >= self.capacity / 2.0 and q == self.n - 1:
                self.low_stock_mode = False
            else:
                return Action.D
        q = int(history.opponent_cooperators[-1]) if t > 0 else 0
        if S <= self.capacity / 4.0:
            self.low_stock_mode = True
            return Action.D
        elif q == self.n - 1 and S >= self.capacity / 2.0:
            return Action.C
        elif q >= self.n - 2 and S >= 3.0 * self.capacity / 4.0 and (t <= self.r - 2):
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_18(BaseStrategy):
    """
    Threshold-based common-pool strategy:
    cooperate initially, then defect unless cooperation is sustained and stock is healthy.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self._locked_defect = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.n
        r = self.r
        if current_stock is None or not np.isfinite(current_stock):
            return Action.D
        round_number = int(history.round_number)
        t = round_number + 1
        if round_number == 0:
            return Action.C
        opp = history.opponent_cooperators
        my_actions = history.my_actions
        if len(opp) != round_number or len(my_actions) != round_number:
            self._locked_defect = True
        n_opponents = max(n - 1, 1)
        for k in opp:
            if k < 0 or k > n_opponents:
                self._locked_defect = True
                break
        p_values = []
        for k in opp:
            p_values.append(float(k) / float(n_opponents))
        if self._locked_defect:
            if len(p_values) >= 2 and p_values[-1] >= 0.8 and (p_values[-2] >= 0.8):
                self._locked_defect = False
            else:
                return Action.D
        if current_stock <= 2.0 * n:
            return Action.D
        if t >= max(1, r - 1):
            return Action.D
        if len(p_values) == 0:
            return Action.D
        p = p_values[-1]
        if len(p_values) >= 2 and bool(my_actions[-1]) is True:
            prev_p = p_values[-2]
            if prev_p - p >= 0.25:
                return Action.D
        if p >= 0.8:
            field = 'high-cooperation'
        elif p >= 0.3:
            field = 'mixed'
        else:
            field = 'low-cooperation'
        allow_high_coop = False
        if len(p_values) >= 2 and bool(my_actions[-1]) is False:
            if p_values[-1] >= 0.8 and p_values[-2] >= 0.8:
                allow_high_coop = True
        if field == 'low-cooperation':
            return Action.D
        if field == 'mixed':
            if current_stock >= 0.7 * self.capacity and p >= 0.5:
                return Action.C
            return Action.D
        if current_stock >= 0.5 * self.capacity and p >= 0.8 or allow_high_coop:
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_19(BaseStrategy):
    """
    Conservative common-pool strategy:
    - Cooperate in the opening round.
    - Cooperate only under strong cooperation and healthy stock conditions.
    - Defect in the last two rounds.
    - Use a recovery gate after defection: require two consecutive good rounds.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(self.n - 1, 0)
        self.T = int(math.ceil(3 * self.n_opponents / 4)) if self.n_opponents > 0 else 0
        self.low = 0.4 * self.capacity
        self.high = 0.7 * self.capacity
        self.borderline = 0.85 * self.capacity

    def _infer_stock_at_round(self, history: PlayerHistory, idx: int) -> float | None:
        if idx < 0 or idx >= history.round_number:
            return None
        my_action = bool(history.my_actions[idx])
        payoff = float(history.my_payoffs[idx])
        if my_action:
            return payoff * (2.0 * max(self.n, 1))
        return payoff * max(self.n, 1)

    def _last_two_good_rounds(self, history: PlayerHistory) -> bool:
        if history.round_number < 2:
            return False
        for idx in (history.round_number - 1, history.round_number - 2):
            if int(history.opponent_cooperators[idx]) < self.T:
                return False
            inferred_stock = self._infer_stock_at_round(history, idx)
            if inferred_stock is None or inferred_stock < self.high:
                return False
        return True

    def _previous_two_nonreliable(self, history: PlayerHistory) -> bool:
        if history.round_number < 2:
            return False
        return int(history.opponent_cooperators[-1]) < self.T - 1 or int(history.opponent_cooperators[-2]) < self.T - 1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = int(history.round_number)
        if t == 0:
            return Action.C
        if t >= max(self.r - 2, 0):
            return Action.D
        o = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        current_stock = float(current_stock)
        if self.n == 2:
            if o >= 1 and current_stock >= self.high:
                return Action.C
            return Action.D
        if not bool(history.my_actions[-1]):
            if self._last_two_good_rounds(history):
                return Action.C
            return Action.D
        if current_stock < self.low:
            if self._last_two_good_rounds(history):
                return Action.C
            return Action.D
        if o < self.T - 1:
            if self._last_two_good_rounds(history):
                return Action.C
            return Action.D
        if o >= self.T and current_stock >= self.high:
            return Action.C
        if o == self.T - 1:
            prev_ok = False
            if history.round_number >= 2:
                prev_ok = int(history.opponent_cooperators[-2]) >= self.T - 1 and int(history.opponent_cooperators[-3]) >= self.T - 1 if history.round_number >= 3 else int(history.opponent_cooperators[-2]) >= self.T - 1
            if current_stock >= self.borderline and prev_ok:
                return Action.C
            return Action.D
        return Action.D

class Strategy_SELFINTERESTED_20(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Starts by cooperating to probe the environment.
    - Tracks smoothed opponent cooperation via q_bar.
    - Rebuilds when stock is depleted and cooperation is at least moderate.
    - Defects in the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.q_bar = 1.0
        self.mode = 'probe'

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = int(self.game_description.n_players)
        r = int(self.game_description.n_rounds)
        t = int(history.round_number)
        if t >= r - 1:
            self.mode = 'harvest'
            return Action.D
        if t == 0:
            self.mode = 'probe'
            return Action.C
        opp_count = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        denom = max(n - 1, 1)
        q = opp_count / denom
        self.q_bar = 0.7 * self.q_bar + 0.3 * q
        capacity = float(self.game_description.capacity)
        x = current_stock / capacity if capacity > 0 else 0.0
        if opp_count == 0:
            action = Action.C if x <= 0.15 else Action.D
            self.mode = 'harvest' if action == Action.D else 'build'
            return action
        if x <= 0.25:
            action = Action.C if self.q_bar >= 0.5 else Action.D
            self.mode = 'build' if action == Action.C else 'harvest'
        elif x < 0.75:
            action = Action.C if self.q_bar >= 0.5 else Action.D
            self.mode = 'build' if action == Action.C else 'harvest'
        else:
            action = Action.D if self.q_bar >= 0.25 else Action.C
            self.mode = 'harvest' if action == Action.D else 'probe'
        threshold = math.ceil((n - 1) / 2)
        if opp_count >= threshold and x < 0.9:
            action = Action.C
            self.mode = 'build'
        return action

class Strategy_SELFINTERESTED_21(BaseStrategy):
    """
    Threshold-based reciprocal strategy with memory, endgame defection,
    and stock-sensitive tie adjustments for the common pool resource game.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(0, self.n_players - 1)
        self._eps = 1e-12

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        if round_number == 0:
            return Action.C
        if round_number >= self.n_rounds - 1:
            return Action.D
        prev_opp_coops = 0
        if len(history.opponent_cooperators) > 0:
            prev_opp_coops = int(history.opponent_cooperators[-1])
        prev_all_opp_coop = prev_opp_coops >= self.n_opponents
        if round_number == self.n_rounds - 2:
            if prev_all_opp_coop and current_stock >= self.capacity / 2.0:
                return Action.C
            return Action.D
        if round_number > 0 and len(history.my_actions) > 0:
            q = float(np.mean(history.my_actions))
        else:
            q = 0.0
        if prev_opp_coops == 0:
            return Action.D
        if current_stock <= self.capacity / 4.0 and prev_opp_coops < self.n_opponents:
            return Action.D
        if prev_all_opp_coop and current_stock >= self.capacity / 2.0:
            return Action.C
        cap = self.capacity if self.capacity > self._eps else self._eps
        stock_ratio = current_stock / cap
        base_theta = math.ceil(self.n_opponents * max(0.5, 1.0 - stock_ratio))
        theta = int(base_theta)
        if q < 0.5:
            theta = min(self.n_opponents, theta + 1)
        if current_stock >= 3.0 * self.capacity / 4.0:
            border = math.ceil(self.n_opponents / 2.0)
            if prev_opp_coops >= border:
                return Action.C
        if current_stock <= self.capacity / 4.0:
            if prev_opp_coops == self.n_opponents:
                return Action.C
            return Action.D
        if prev_opp_coops >= theta:
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_22(BaseStrategy):
    """
    Start cooperative, punish low cooperation or large stock drops with defection,
    reward sustained cooperation, and defect in the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(self.n_players - 1, 1)
        self.last_round_number = 0
        self.last_stock = float(self.capacity)
        self.bad = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)

        def frac_coop(count: int) -> float:
            return float(count) / float(self.n_opponents) if self.n_opponents > 0 else 0.0
        if round_number == 0:
            self.last_round_number = 0
            self.last_stock = float(current_stock)
            self.bad = False
            return Action.C
        if round_number >= self.n_rounds - 1:
            self._update_state(history, current_stock)
            return Action.D
        q_last = frac_coop(int(history.opponent_cooperators[-1])) if round_number >= 1 else 0.0
        q_prev = frac_coop(int(history.opponent_cooperators[-2])) if round_number >= 2 else q_last
        qbar = (q_last + q_prev) / 2.0 if round_number >= 2 else q_last
        stock_drop = 0.0
        if self.last_round_number == round_number - 1:
            stock_drop = float(self.last_stock) - float(current_stock)
        elif round_number >= 2:
            stock_drop = max(0.0, float(self.last_stock) - float(current_stock))
        if q_last < 0.5 or qbar < 0.5 or stock_drop > self.capacity / 4.0:
            self.bad = True
        elif round_number >= 2 and q_last >= 0.5 and (q_prev >= 0.5):
            self.bad = False
        if self.bad:
            action = Action.D
        elif float(current_stock) < self.capacity / 2.0:
            action = Action.C if q_last >= 2.0 / 3.0 else Action.D
        else:
            action = Action.C
        self._update_state(history, current_stock)
        return action

    def _update_state(self, history: PlayerHistory, current_stock: float) -> None:
        """
        Keep lightweight internal state in sync with the most recent observed round.
        """
        self.last_round_number = int(history.round_number)
        self.last_stock = float(current_stock)

class Strategy_SELFINTERESTED_23(BaseStrategy):
    """
    Conservation-first exploitative strategy for the Common Pool Resource Game.

    - Starts by cooperating.
    - Defects on the last round.
    - Otherwise predicts opponent cooperation with a smoothed estimate and
      defects unless doing so would push the next stock below a safety floor.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.q = 1.0
        self.m_hat = max(0, self.n - 1)
        self._last_processed_round = -1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        if round_number > 0 and self._last_processed_round < round_number - 1:
            m_obs = int(history.opponent_cooperators[-1])
            n_opponents = max(1, self.n - 1)
            observed_rate = m_obs / n_opponents
            self.q = 0.7 * self.q + 0.3 * observed_rate
            self.m_hat = int(round((self.n - 1) * self.q))
            if self.m_hat < 0:
                self.m_hat = 0
            elif self.m_hat > self.n - 1:
                self.m_hat = self.n - 1
            self._last_processed_round = round_number - 1
        if round_number == 0:
            return Action.C
        h = self.r - round_number
        if h <= 1:
            return Action.D
        S = float(current_stock)
        m_hat = float(self.m_hat)
        rem_C = S * (m_hat + 1.0) / (2.0 * self.n)
        rem_D = S * m_hat / (2.0 * self.n)
        next_C = min(rem_C + 2.0 * rem_C * (1.0 - rem_C / self.capacity), self.capacity)
        next_D = min(rem_D + 2.0 * rem_D * (1.0 - rem_D / self.capacity), self.capacity)
        floor = self.capacity / 2.0 if h > 2 else 0.0
        if next_D >= floor:
            return Action.D
        return Action.C

class Strategy_SELFINTERESTED_24(BaseStrategy):
    """
    Adaptive common-pool strategy:
    cooperates when the pool remains healthy and observed opponent cooperation is high,
    but defects near the end or when cooperation/stock deteriorates.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.q = 0.5
        self.k_prev = max(0, game_description.n_players - 1)
        self._processed_rounds = 0
        self._last_observed_rate = None
        self._drop_streak = 0
        self._high_streak = 0
        self._pool_failed = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = float(self.game_description.capacity)
        if current_stock <= 0:
            self._pool_failed = True
        seen = history.round_number
        if seen > self._processed_rounds:
            for idx in range(self._processed_rounds, seen):
                if idx < len(history.opponent_cooperators):
                    k_obs = int(history.opponent_cooperators[idx])
                    k_obs = max(0, min(k_obs, max(0, n - 1)))
                else:
                    k_obs = self.k_prev
                if n == 2:
                    self.q = 1.0 if k_obs >= 1 else 0.0
                else:
                    denom = max(1, n - 1)
                    self.q = 0.7 * (k_obs / denom) + 0.3 * self.q
                observed_rate = 1.0 if n == 2 and k_obs >= 1 else k_obs / max(1, n - 1)
                if self._last_observed_rate is not None and observed_rate < self._last_observed_rate:
                    self._drop_streak += 1
                else:
                    self._drop_streak = 0
                if observed_rate >= 0.8:
                    self._high_streak += 1
                else:
                    self._high_streak = 0
                self._last_observed_rate = observed_rate
                self.k_prev = k_obs
            self._processed_rounds = seen
        t = history.round_number + 1
        if self._pool_failed or t >= r + 1:
            return Action.D
        if t == r:
            return Action.D
        denom = max(1, r - 1)
        T = max(2 * n, 0.35 * capacity + 0.25 * capacity * (1.0 - (t - 1) / denom))
        if t < r and self._high_streak >= 3 and (current_stock >= 0.6 * capacity) and (current_stock >= T):
            return Action.C
        q_required = 0.6 if self._drop_streak >= 2 else 0.5
        if t == r - 1:
            if current_stock >= T and self.q >= 0.75:
                return Action.C
            return Action.D
        if current_stock >= T and self.q >= q_required:
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_25(BaseStrategy):
    """
    Trust-based common-pool strategy:
    - Start by cooperating.
    - Cooperate only when trust is high and the stock is healthy.
    - Defect when stock is low, trust is weak, or the game is in the final round
      unless the history is fully cooperative and stock is very high.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self._eps = 1e-09

    def _compute_trust(self, history: PlayerHistory) -> float:
        q = 1.0
        n_players = self.game_description.n_players
        n_opponents = max(n_players - 1, 1)
        for k in history.opponent_cooperators:
            share = float(k) / float(n_opponents)
            q = 0.75 * q + 0.25 * share
            if share < 0.4:
                q *= 0.5
            if q < 0.0:
                q = 0.0
            elif q > 1.0:
                q = 1.0
        return q

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        capacity = float(self.game_description.capacity)
        round_number = history.round_number
        n_rounds = self.game_description.n_rounds
        if round_number == 0:
            return Action.C
        q = self._compute_trust(history)
        if round_number == n_rounds - 1:
            if q >= 1.0 - self._eps and current_stock >= 0.8 * capacity:
                return Action.C
            return Action.D
        if current_stock < 0.25 * capacity:
            return Action.D
        if q >= 0.6 and current_stock >= 0.45 * capacity:
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_26(BaseStrategy):
    """
    Common-pool strategy:
    - Start with cooperation.
    - React to the previous round's opponent cooperation count and current stock.
    - Defect in the final round, on depletion, or when cooperation weakens.
    - Prefer cooperation only when cooperation is sufficiently strong to sustain the pool.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(self.n - 1, 0)
        self.half_opponents_ceil = math.ceil(self.n_opponents / 2) if self.n_opponents > 0 else 0
        self.two_thirds_opponents_ceil = math.ceil(2 * self.n_opponents / 3) if self.n_opponents > 0 else 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        if round_number == 0:
            return Action.C
        if current_stock <= 0:
            return Action.D
        if round_number >= self.r - 1:
            return Action.D
        m = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        prev_my_action = bool(history.my_actions[-1]) if len(history.my_actions) > 0 else True
        if self.n <= 2:
            return Action.C if m >= 1 and current_stock > self.capacity / 3 else Action.D
        if self.capacity <= 0:
            return Action.D
        if current_stock == self.capacity or current_stock >= 2 * self.capacity / 3:
            return Action.C if m >= self.half_opponents_ceil else Action.D
        if current_stock <= self.capacity / 3:
            if prev_my_action and m == self.n_opponents and (current_stock > self.capacity / 3):
                return Action.C
            return Action.C if m == self.n_opponents and current_stock > self.capacity / 3 else Action.D
        if prev_my_action and m == self.n_opponents and (current_stock > self.capacity / 3):
            return Action.C
        if m >= self.two_thirds_opponents_ceil:
            return Action.C
        if m <= self.half_opponents_ceil - 1:
            return Action.D
        return Action.C if m >= self.two_thirds_opponents_ceil else Action.D

class Strategy_SELFINTERESTED_27(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Opens cooperatively.
    - Cooperates only when the stock is healthy and recent opponent cooperation is strong.
    - Defects under depletion, weak cooperation, or after apparent exploitation.
    - Becomes more conservative in the final round(s).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self._recovery_mode = False
        self._cooperative_mode = True
        self._last_seen_round = -1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        rounds = self.game_description.n_rounds
        capacity = float(self.game_description.capacity)
        round_number = history.round_number
        if round_number == 0:
            self._recovery_mode = False
            self._cooperative_mode = True
            self._last_seen_round = 0
            return Action.C
        last_opponents = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        n_opponents = max(n - 1, 1)
        c = last_opponents / n_opponents
        prev_start_stock = float(current_stock)
        if len(history.my_payoffs) > 0:
            last_payoff = float(history.my_payoffs[-1])
            last_action_was_c = bool(history.my_actions[-1]) if len(history.my_actions) > 0 else True
            if last_action_was_c:
                prev_start_stock = last_payoff * (2.0 * n)
            else:
                prev_start_stock = last_payoff * float(n)
        s_prev_remaining = min(float(current_stock), prev_start_stock)
        if current_stock <= 0.4 * capacity:
            self._cooperative_mode = False
            self._recovery_mode = True
            self._last_seen_round = round_number
            return Action.D
        if c <= 0.5:
            self._cooperative_mode = False
            self._recovery_mode = True
            self._last_seen_round = round_number
            return Action.D
        if round_number >= rounds - 1:
            action = Action.C if current_stock >= 0.85 * capacity and c >= 0.75 else Action.D
            self._last_seen_round = round_number
            return action
        if current_stock >= 0.9 * capacity and c >= 0.75:
            self._cooperative_mode = True
            self._recovery_mode = False
            self._last_seen_round = round_number
            return Action.C
        if len(history.my_actions) > 0 and bool(history.my_actions[-1]) and (c < 0.5):
            self._recovery_mode = True
            self._cooperative_mode = False
        if self._recovery_mode:
            if current_stock >= 0.75 * capacity and c >= 0.75 and (s_prev_remaining / capacity >= 0.6):
                self._recovery_mode = False
                self._cooperative_mode = True
                self._last_seen_round = round_number
                return Action.C
            self._last_seen_round = round_number
            return Action.D
        if current_stock >= 0.75 * capacity and c >= 0.75 and (s_prev_remaining / capacity >= 0.6):
            self._cooperative_mode = True
            self._last_seen_round = round_number
            return Action.C
        self._cooperative_mode = False
        self._last_seen_round = round_number
        return Action.D

class Strategy_SELFINTERESTED_28(BaseStrategy):
    """
    Cooperative-first common-pool strategy with adaptive smoothing and defensive override rules.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.q_hat = 1.0
        self._processed_rounds = 0
        self._force_defect_rounds = 0
        self._force_cooperate_rounds = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_players = int(self.game_description.n_players)
        capacity = float(self.game_description.capacity)
        n_opponents = max(1, n_players - 1)
        round_number = int(history.round_number)
        if round_number > self._processed_rounds:
            start = self._processed_rounds
            end = round_number
            for idx in range(start, end):
                if idx < 0 or idx >= len(history.opponent_cooperators):
                    continue
                coop_count = float(history.opponent_cooperators[idx])
                q = coop_count / float(n_opponents)
                if q < 0.0:
                    q = 0.0
                elif q > 1.0:
                    q = 1.0
                self.q_hat = 0.7 * self.q_hat + 0.3 * q
                if q == 0.0:
                    self._force_defect_rounds = 2
                elif q == 1.0:
                    self._force_cooperate_rounds = 2
            self._processed_rounds = round_number
        if round_number == 0:
            return Action.C
        if self._force_defect_rounds > 0:
            self._force_defect_rounds -= 1
            return Action.D
        if round_number >= int(self.game_description.n_rounds) - 1:
            return Action.D
        q_obs = 0.0
        if len(history.opponent_cooperators) > 0:
            last_count = float(history.opponent_cooperators[-1])
            q_obs = last_count / float(n_opponents)
            if q_obs < 0.0:
                q_obs = 0.0
            elif q_obs > 1.0:
                q_obs = 1.0
        q_use = self.q_hat if abs(q_obs - self.q_hat) >= 0.5 else q_obs
        if current_stock <= capacity / 3.0:
            return Action.D
        if q_use <= 1.0 / 3.0:
            return Action.D
        if self._force_cooperate_rounds > 0:
            self._force_cooperate_rounds -= 1
            return Action.C
        if q_use >= 2.0 / 3.0 and current_stock >= capacity / 2.0:
            return Action.C
        if q_use >= 0.5 and current_stock >= 2.0 * n_players:
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_29(BaseStrategy):
    """
    Common pool resource strategy with a recovery mode.

    - Round 1: cooperate.
    - Final round: defect.
    - Otherwise:
      * Defect if stock is depleted or if in recovery mode.
      * Cooperate only when the number of cooperating opponents in the previous round
        is at least ceil((n - 1) / 2) and the stock is at least half of capacity.
    Recovery mode persists after any "bad" observed round (fewer than q opponent
    cooperators) and ends only after two consecutive good rounds.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(getattr(game_description, 'n_players', 0) or 0)
        self.n_rounds = int(getattr(game_description, 'n_rounds', 0) or 0)
        self.capacity = float(getattr(game_description, 'capacity', 0) or 0.0)
        self.q = math.ceil((self.n_players - 1) / 2) if self.n_players >= 1 else 0

    def _in_recovery_mode(self, history: PlayerHistory) -> bool:
        opp = history.opponent_cooperators
        n_hist = len(opp)
        if n_hist == 0:
            return False
        trailing_good = 0
        idx = n_hist - 1
        while idx >= 0 and int(opp[idx]) >= self.q:
            trailing_good += 1
            idx -= 1
        if trailing_good >= 2:
            return False
        for h in opp:
            if int(h) < self.q:
                return True
        return False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        last_round_index = self.n_rounds - 1
        if round_number == 0:
            return Action.C
        if round_number >= last_round_index:
            return Action.D
        if self.capacity <= 0:
            return Action.D
        if current_stock <= 0:
            return Action.D
        if self._in_recovery_mode(history):
            return Action.D
        h_prev = int(history.opponent_cooperators[-1]) if round_number > 0 else 0
        x = current_stock / self.capacity
        if h_prev >= self.q and x >= 0.5:
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_30(BaseStrategy):
    """
    Cautious conditional cooperator with trust tracking and short retaliation.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.trust = 1.0
        self.freeze = 0
        self.last_stock = float(game_description.capacity)
        self._last_processed_round = -1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = max(int(self.game_description.n_players), 2)
        r = max(int(self.game_description.n_rounds), 1)
        capacity = float(self.game_description.capacity)
        round_number = int(history.round_number)
        stock = float(current_stock)
        if round_number > 0 and round_number != self._last_processed_round:
            idx = round_number - 1
            opp_coop = 0
            if 0 <= idx < len(history.opponent_cooperators):
                opp_coop = int(history.opponent_cooperators[idx])
            denom = max(n - 1, 1)
            q = opp_coop / denom
            self.trust = 0.6 * float(self.trust) + 0.4 * q
            if float(self.last_stock) > 0.0 and stock < 0.75 * float(self.last_stock):
                self.freeze = 2
            self._last_processed_round = round_number
        if round_number >= r - 1:
            self.last_stock = stock
            return Action.D
        if self.freeze > 0:
            self.freeze -= 1
            self.last_stock = stock
            return Action.D
        if stock <= 2.0 * n:
            self.last_stock = stock
            return Action.D
        if round_number == 0:
            action = Action.C if r >= 5 and capacity >= 4.0 * n else Action.D
            self.last_stock = stock
            return action
        idx = round_number - 1
        opp_coop = 0
        if 0 <= idx < len(history.opponent_cooperators):
            opp_coop = int(history.opponent_cooperators[idx])
        denom = max(n - 1, 1)
        q = opp_coop / denom
        if q < 0.5 or stock < 0.4 * capacity:
            self.freeze = 2
            action = Action.D
        elif float(self.trust) >= 0.75 and stock >= 0.6 * capacity:
            action = Action.C
        else:
            action = Action.D
        self.last_stock = stock
        return action

class Strategy_SELFINTERESTED_31(BaseStrategy):
    """
    Trust-based common-pool strategy with forgiveness and stock-sensitive overrides.
    Cooperates initially, becomes cautious when trust or observed cooperation drops,
    and defects in the final round or under low-stock conditions.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.trust = 1.0
        self.forgiveness = 0
        self.high_coop_streak = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = int(self.game_description.n_players)
        r = int(self.game_description.n_rounds)
        round_number = int(history.round_number)
        if round_number == 0:
            return Action.C
        if round_number >= r - 1:
            return Action.D
        n_opponents = max(1, n - 1)
        k_prev = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        high_coop_threshold = math.ceil((n - 1) / 2)
        low_coop_threshold = math.floor((n - 1) / 3)
        coop_rate = k_prev / n_opponents
        self.trust = 0.7 * self.trust + 0.3 * coop_rate
        if k_prev >= high_coop_threshold:
            self.high_coop_streak += 1
        else:
            self.high_coop_streak = 0
        if self.high_coop_streak >= 2:
            self.forgiveness = 0
        if k_prev == 0:
            self.forgiveness = 2
        if self.forgiveness > 0:
            self.forgiveness -= 1
            return Action.D
        capacity = float(self.game_description.capacity)
        if current_stock < capacity / 3:
            return Action.D
        if current_stock >= 3 * capacity / 4 and k_prev >= high_coop_threshold:
            return Action.C
        if current_stock <= capacity / 4 or self.trust < 0.55 or k_prev <= low_coop_threshold:
            return Action.D
        return Action.C

class Strategy_SELFINTERESTED_32(BaseStrategy):
    """
    Two-mode adaptive strategy for the Common Pool Resource Game.

    Starts in CONSERVE mode, switches to EXPLOIT when opponents overuse the
    resource or the stock becomes too low, and returns to CONSERVE only under
    strong cooperative and stock-health conditions. Always defects in the final
    round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.mode = 'CONSERVE'

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_rounds = int(self.game_description.n_rounds)
        n_players = int(self.game_description.n_players)
        capacity = float(self.game_description.capacity)
        if history.round_number == 0:
            self.mode = 'CONSERVE'
            return Action.C
        if history.round_number >= n_rounds - 1:
            self.mode = 'EXPLOIT'
            return Action.D
        if current_stock <= 0.0:
            self.mode = 'EXPLOIT'
            return Action.D
        if len(history.opponent_cooperators) == 0:
            self.mode = 'CONSERVE'
            return Action.C
        c_prev = int(history.opponent_cooperators[-1])
        denom = max(n_players - 1, 1)
        q = c_prev / denom
        previous_mode = self.mode
        if q < 0.5 or current_stock < capacity / 3.0 or (previous_mode == 'EXPLOIT' and q < 2.0 / 3.0):
            self.mode = 'EXPLOIT'
        elif q >= 2.0 / 3.0 and current_stock >= capacity / 2.0:
            self.mode = 'CONSERVE'
        elif abs(q - 0.5) <= 1e-12:
            if current_stock >= capacity / 2.0:
                self.mode = 'CONSERVE'
            else:
                self.mode = 'EXPLOIT'
        if current_stock >= capacity and q >= 0.5:
            if self.mode != 'EXPLOIT':
                self.mode = 'CONSERVE'
        return Action.C if self.mode == 'CONSERVE' else Action.D

class Strategy_OPPORTUNISTIC_5(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Starts with cooperation
    - Tracks exponentially weighted opponent cooperation
    - Uses punishment, exploitation, and stock-based thresholds
    - Defects in the final round(s) with a small second-to-last-round exception
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.q = 1.0
        self.processed_rounds = 0
        self.forced_defect_remaining = 0
        self.zero_coop_lock = False
        self.last_h = 1.0
        self.prev_h = 1.0
        self.consecutive_full_coop = 0

    def _update_state(self, history: PlayerHistory) -> None:
        n_players = self.game_description.n_players
        n_opponents = max(0, n_players - 1)
        while self.processed_rounds < history.round_number:
            idx = self.processed_rounds
            opp_coops = int(history.opponent_cooperators[idx]) if idx < len(history.opponent_cooperators) else 0
            if n_opponents > 0:
                h = opp_coops / n_opponents
            else:
                h = 0.0
            self.prev_h = self.last_h
            self.last_h = h
            self.q = 0.7 * self.q + 0.3 * h
            if abs(h - 1.0) < 1e-12:
                self.consecutive_full_coop += 1
            else:
                self.consecutive_full_coop = 0
            if abs(h) < 1e-12:
                self.zero_coop_lock = True
                self.forced_defect_remaining = max(self.forced_defect_remaining, 2)
            elif h <= 0.5 + 1e-12:
                self.forced_defect_remaining = max(self.forced_defect_remaining, 2)
            if self.forced_defect_remaining > 0:
                self.forced_defect_remaining -= 1
            if self.zero_coop_lock and self.q > 0.6 and (h >= 0.75):
                self.zero_coop_lock = False
            self.processed_rounds += 1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        self._update_state(history)
        t = history.round_number
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = float(self.game_description.capacity)
        if t == 0:
            return Action.C
        if t >= r - 1:
            return Action.D
        if t == r - 2:
            if self.q >= 0.8 and current_stock > 1.4 * n:
                return Action.C
            return Action.D
        if self.forced_defect_remaining > 0:
            return Action.D
        if self.zero_coop_lock:
            return Action.D
        if self.consecutive_full_coop >= 2:
            if current_stock < capacity / 3.0:
                return Action.C
            return Action.D
        if current_stock <= 1.0 * n:
            return Action.D
        if current_stock > 1.6 * n and self.q >= 0.5:
            return Action.C
        if current_stock > 1.0 * n and self.q >= 0.7:
            return Action.C
        if self.q >= 0.5 and t < r - 1:
            return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_6(BaseStrategy):
    """
    Contingent threshold strategy with harvest, mirror, and lock-in modes.
    Opens cooperatively, adapts to observed cooperation and stock health,
    and defects in endgame or when cooperation degrades.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.p_hat = 1.0
        self.good_streak = 0
        self.last_action = Action.C
        self.locked_defect = False
        self.opportunistic_hold = False
        self.recovery_streak = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = max(2, int(self.game_description.n_players))
        n_opponents = max(1, n - 1)
        capacity = float(self.game_description.capacity) if self.game_description.capacity is not None else 1.0
        capacity = max(capacity, 1e-09)
        t = history.round_number + 1
        rounds_remaining = int(self.game_description.n_rounds) - t + 1
        if t == 1:
            self.last_action = Action.C
            self.opportunistic_hold = False
            self.locked_defect = False
            self.good_streak = 0
            self.recovery_streak = 0
            self.p_hat = 1.0
            return Action.C
        k = int(history.opponent_cooperators[-1]) if history.opponent_cooperators.size > 0 else 0
        x = 0.0 if n_opponents <= 0 else k / n_opponents
        self.p_hat = 0.7 * self.p_hat + 0.3 * x
        tau = 0.5 + 0.25 * (1.0 - float(current_stock) / capacity)
        tau = min(0.85, max(0.35, tau))
        high_coop_threshold = int(math.ceil(0.75 * n_opponents))
        very_high_coop_threshold = int(math.ceil(0.9 * n_opponents))
        if x < 0.5:
            self.good_streak = 0
            self.recovery_streak = 0
        elif x >= 0.75:
            self.good_streak += 1
            self.recovery_streak += 1
        else:
            self.good_streak = 0
            self.recovery_streak = 0
        if self.locked_defect:
            self.last_action = Action.D
            return Action.D
        if rounds_remaining <= 2:
            self.last_action = Action.D
            return Action.D
        if rounds_remaining == 3 and current_stock >= 0.8 * capacity and (x >= 0.9) and (not self.locked_defect):
            self.locked_defect = True
            self.last_action = Action.C
            return Action.C
        if current_stock <= 0.25 * capacity:
            self.last_action = Action.D
            self.opportunistic_hold = False
            return Action.D
        if self.opportunistic_hold:
            if self.p_hat >= tau and current_stock >= 0.4 * capacity:
                self.last_action = Action.C
                return Action.C
            self.opportunistic_hold = False
        if self.last_action == Action.C and k >= high_coop_threshold:
            if self.p_hat >= tau and current_stock >= 0.4 * capacity:
                self.opportunistic_hold = True
                self.last_action = Action.C
                return Action.C
        if x >= 0.75:
            if self.good_streak >= 2 and self.p_hat >= tau and (current_stock >= 0.4 * capacity):
                self.last_action = Action.C
                return Action.C
            self.last_action = Action.D
            return Action.D
        if self.p_hat >= tau or (k >= high_coop_threshold and current_stock >= 0.5 * capacity):
            self.last_action = Action.C
            return Action.C
        if self.good_streak >= 2 and k >= very_high_coop_threshold and (current_stock >= 0.4 * capacity):
            self.last_action = Action.C
            return Action.C
        self.last_action = Action.D
        return Action.D

class Strategy_OPPORTUNISTIC_7(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Cooperate on the first round.
    - Defect on the final round.
    - Preserve the pool when stock is low or opponents are insufficiently cooperative.
    - Defect near the end only when stock is healthy and cooperation is strong.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.last_round_number = -1
        self.S_prev = float(self.capacity)
        self.current_p = 1.0 if self.n <= 2 else 1.0
        self.last_opponent_cooperators = self.n - 1 if self.n > 1 else 0

    def _compute_p(self, c: int) -> float:
        n_opponents = max(self.n - 1, 1)
        if self.n == 2:
            return 1.0 if c >= 1 else 0.0
        return float(c) / float(n_opponents)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = int(history.round_number)
        S = float(current_stock)
        if t > 0 and len(history.opponent_cooperators) >= t:
            c_last = int(history.opponent_cooperators[-1])
            self.last_opponent_cooperators = c_last
            self.current_p = self._compute_p(c_last)
            self.S_prev = S if self.last_round_number != t - 1 else self.S_prev
        if t == 0:
            self.S_prev = float(self.capacity)
            self.current_p = 1.0
            self.last_opponent_cooperators = self.n - 1 if self.n > 1 else 0
            self.last_round_number = 0
            return Action.C
        p = float(min(1.0, max(0.0, self.current_p)))
        cap = float(self.capacity)
        if t == self.r - 1:
            decision = Action.D
        elif t == self.r - 2:
            if S <= cap / 2.0:
                decision = Action.C
            elif p >= 0.75:
                decision = Action.D
            else:
                decision = Action.C
        elif S <= cap / 3.0:
            decision = Action.C
        elif p < 0.5:
            decision = Action.C
        elif p >= 0.75 and S >= cap / 2.0:
            decision = Action.D
        elif S > self.S_prev and p >= 0.5:
            decision = Action.D
        else:
            decision = Action.C
        self.S_prev = float(S)
        self.last_round_number = t
        return decision

class Strategy_OPPORTUNISTIC_8(BaseStrategy):
    """
    State-based threshold strategy with cautious cooperation, occasional exploitation,
    and recovery after defection when cooperation or stock levels improve.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.high_threshold = 0.75
        self.medium_threshold = 0.5
        self.low_threshold = 0.25

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number
        if t == 0:
            return Action.C
        if t >= self.n_rounds - 1:
            return Action.D if current_stock > self.capacity / 2.0 else Action.C
        m = self.n_players - 1
        if m <= 0:
            f = 0.0
        else:
            k = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
            if k <= 0:
                f = 0.0
            elif k >= m:
                f = 1.0
            else:
                f = k / m
        last_my_action = bool(history.my_actions[-1]) if len(history.my_actions) > 0 else True
        last_defected = not last_my_action
        low_cutoff = self.capacity / 4.0
        high_cutoff = self.capacity / 2.0
        if last_defected and current_stock <= low_cutoff:
            if f >= self.medium_threshold or current_stock > high_cutoff:
                return Action.C
            return Action.D
        if current_stock <= low_cutoff:
            action = Action.C if f >= self.high_threshold else Action.D
        elif current_stock <= high_cutoff:
            action = Action.C if f >= self.medium_threshold else Action.D
        else:
            action = Action.C if f >= self.low_threshold else Action.D
        if f >= self.high_threshold and current_stock > high_cutoff:
            action = Action.D
        return action

class Strategy_OPPORTUNISTIC_9(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Start with cooperation.
    - Avoid collapse when stock is low.
    - Exploit sustained high cooperation/high stock signals, with a two-round
      persistent mode after repeated confirmation.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(getattr(game_description, 'n_players', 0) or 0)
        self.r = int(getattr(game_description, 'n_rounds', 0) or 0)
        self.capacity = float(getattr(game_description, 'capacity', 1.0) or 1.0)
        self._exploit_remaining = 0
        self._prev_high_signal = False
        self._prev_stock_at_cap = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.n if self.n >= 2 else 2
        round_number = int(getattr(history, 'round_number', 0) or 0)
        final_round = round_number >= max(self.r - 1, 0)
        if round_number == 0:
            self._exploit_remaining = 0
            self._prev_high_signal = False
            self._prev_stock_at_cap = abs(float(current_stock) - self.capacity) <= 1e-12
            return Action.C
        opp_coops = getattr(history, 'opponent_cooperators', None)
        if opp_coops is None or len(opp_coops) == 0:
            if final_round:
                return Action.D
            self._exploit_remaining = 0
            self._prev_high_signal = False
            self._prev_stock_at_cap = abs(float(current_stock) - self.capacity) <= 1e-12
            return Action.C
        last_k = int(opp_coops[-1])
        if last_k < 0:
            last_k = 0
        max_opp = max(n - 1, 0)
        if last_k > max_opp:
            last_k = max_opp
        s = float(current_stock) / self.capacity if self.capacity > 0 else 0.0
        low_k_threshold = math.floor((n - 1) / 3)
        high_k_threshold = math.ceil(2 * (n - 1) / 3)
        mid_k_threshold = math.ceil((n - 1) / 2)
        high_signal = last_k >= high_k_threshold and s >= 0.65
        low_signal = last_k <= low_k_threshold or s <= 0.4
        cap_stuck = abs(float(current_stock) - self.capacity) <= 1e-12
        if low_signal:
            self._exploit_remaining = 0
        if not final_round and self._exploit_remaining == 0 and high_signal:
            if self._prev_high_signal:
                self._exploit_remaining = 2
            elif not self._prev_stock_at_cap:
                pass
        if final_round:
            if s <= 0.25:
                self._prev_high_signal = high_signal
                self._prev_stock_at_cap = cap_stuck
                return Action.C
            self._prev_high_signal = high_signal
            self._prev_stock_at_cap = cap_stuck
            return Action.D
        if s <= 0.25:
            self._prev_high_signal = high_signal
            self._prev_stock_at_cap = cap_stuck
            return Action.C
        if self._exploit_remaining > 0:
            self._exploit_remaining -= 1
            self._prev_high_signal = high_signal
            self._prev_stock_at_cap = cap_stuck
            return Action.D
        if s <= 0.4 or last_k <= low_k_threshold:
            action = Action.C
        elif s >= 0.65 and last_k >= high_k_threshold:
            action = Action.D
        elif last_k >= mid_k_threshold and s > 0.4:
            action = Action.D
        else:
            action = Action.C
        self._prev_high_signal = high_signal
        self._prev_stock_at_cap = cap_stuck
        if self._exploit_remaining == 0 and high_signal and self._prev_high_signal:
            self._exploit_remaining = 2
        if self._prev_stock_at_cap and high_signal and (self._exploit_remaining == 0):
            if self._prev_high_signal:
                self._exploit_remaining = 2
        return action

class Strategy_OPPORTUNISTIC_10(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Cooperates initially to support regeneration.
    - Defects when the stock is high and opponents are sufficiently cooperative.
    - Responds to sustained free-riding with a temporary defensive defection mode.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self._n = int(game_description.n_players)
        self._r = int(game_description.n_rounds)
        self._capacity = float(game_description.capacity)
        self._m = max(self._n - 1, 1)
        self._avgC = 0.0
        self._trend = 0.0
        self._last_seen_round = -1
        self._in_punishment = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        cap = self._capacity
        m = self._m
        half_stock = cap / 2.0
        quarter_stock = cap / 4.0
        if round_number == 0:
            return Action.C
        if round_number == self._r - 1:
            return Action.D if current_stock >= half_stock else Action.C
        opp = history.opponent_cooperators
        observed_rounds = len(opp)
        if observed_rounds > 0:
            opp_rates = np.asarray(opp, dtype=float) / float(m)
            avg_c = float(np.mean(opp_rates))
            last_c = int(opp[-1])
        else:
            avg_c = 0.0
            last_c = 0
        if observed_rounds >= 2:
            prev_c = int(opp[-2])
            trend = float(last_c - prev_c)
        else:
            trend = 0.0
        self._avgC = avg_c
        self._trend = trend
        self._last_seen_round = round_number - 1
        low_half_threshold = math.ceil(m / 2.0)
        strong_coop_threshold = math.ceil(2.0 * m / 3.0)
        very_high_coop_threshold = math.ceil(3.0 * m / 4.0)
        two_low_rounds = False
        if observed_rounds >= 2:
            two_low_rounds = int(opp[-1]) < low_half_threshold and int(opp[-2]) < low_half_threshold
        strong_rebound = observed_rounds >= 1 and int(opp[-1]) >= strong_coop_threshold
        stock_recovered = current_stock > half_stock
        if two_low_rounds and (not strong_rebound) and (not stock_recovered):
            self._in_punishment = True
            return Action.D
        if strong_rebound or stock_recovered:
            self._in_punishment = False
        if current_stock <= quarter_stock:
            if observed_rounds >= 1 and int(opp[-1]) >= very_high_coop_threshold:
                return Action.C
            return Action.D
        if current_stock >= half_stock:
            if avg_c >= 2.0 / 3.0 and observed_rounds >= 1 and (int(opp[-1]) >= strong_coop_threshold):
                return Action.D
            return Action.C
        if observed_rounds >= 1 and int(opp[-1]) >= low_half_threshold:
            return Action.C
        if trend > 0:
            return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_11(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Cooperate in round 1.
    - Defect in the final round.
    - Otherwise, use a stock-forecast rule based on last round's observed cooperation,
      with a low-stock recovery override.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.opponents = max(self.n - 1, 0)
        self.half_capacity = self.capacity / 2.0
        self.quarter_capacity = self.capacity / 4.0
        self.recovery_threshold = math.ceil((self.n - 1) / 2) if self.n > 1 else 0

    def _predicted_stock(self, cooperators: int, current_stock: float) -> float:
        n = max(self.n, 2)
        S = float(current_stock)
        K = max(0, min(int(cooperators), self.n))
        remaining = S * K / (2.0 * n)
        growth = 2.0 * remaining * (1.0 - remaining / self.capacity) if self.capacity > 0 else 0.0
        predicted = remaining + growth
        if predicted > self.capacity:
            predicted = self.capacity
        if predicted < 0.0:
            predicted = 0.0
        return predicted

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        if round_number == 0:
            return Action.C
        if round_number >= self.r - 1:
            return Action.D
        c = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        S = float(current_stock)
        if c <= 0:
            return Action.D
        if S <= self.quarter_capacity:
            if c >= self.recovery_threshold:
                return Action.C
            return Action.D
        predicted_if_d = self._predicted_stock(c, S)
        if predicted_if_d >= self.half_capacity:
            return Action.D
        predicted_if_c = self._predicted_stock(c + 1, S)
        if predicted_if_c >= self.half_capacity:
            return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_12(BaseStrategy):
    """
    Common-pool strategy:
    - Cooperate initially.
    - Defect after full opponent cooperation to exploit.
    - Cooperate after complete opponent defection to rebuild.
    - Otherwise respond to recent cooperation frequency and stock pressure.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(self.n - 1, 0)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number
        if t == 0:
            return Action.C
        opp_counts = history.opponent_cooperators
        last_c = int(opp_counts[-1]) if len(opp_counts) > 0 else 0
        prev_c = int(opp_counts[-2]) if len(opp_counts) > 1 else None
        s_t = float(current_stock)
        remaining = self.r - t
        denom = self.n_opponents if self.n_opponents > 0 else 1
        coop_fraction_last = last_c / denom
        recent_window = opp_counts[max(0, len(opp_counts) - 3):]
        if len(recent_window) > 0:
            recent_fracs = [int(x) / denom for x in recent_window]
            m_t = float(np.mean(recent_fracs))
        else:
            m_t = 0.0
        decision = None
        if remaining <= 2:
            if last_c > 0:
                decision = Action.D
            else:
                decision = Action.C
        else:
            if last_c == self.n_opponents:
                decision = Action.D
            elif last_c <= self.n_opponents / 2:
                decision = Action.C
            elif last_c > self.n_opponents / 2 and last_c < self.n_opponents:
                decision = Action.C if m_t >= 2.0 / 3.0 else Action.D
            elif s_t <= self.capacity / 3.0:
                decision = Action.D
            elif s_t >= 2.0 * self.capacity / 3.0 and last_c >= self.n_opponents / 2:
                decision = Action.C
            else:
                decision = Action.C if last_c >= self.n_opponents / 2 else Action.D
            if len(opp_counts) >= 2:
                last_two = opp_counts[-2:]
                if int(last_two[0]) >= 2 * self.n_opponents / 3.0 and int(last_two[1]) >= 2 * self.n_opponents / 3.0:
                    decision = Action.C
                if int(last_two[0]) <= self.n_opponents / 3.0 and int(last_two[1]) <= self.n_opponents / 3.0:
                    decision = Action.D
            if len(history.my_actions) > 0 and bool(history.my_actions[-1]) is True and (last_c == self.n_opponents):
                decision = Action.D
            if len(history.my_actions) > 0 and bool(history.my_actions[-1]) is False and (last_c == 0):
                decision = Action.C
        return decision if decision is not None else Action.C

class Strategy_OPPORTUNISTIC_13(BaseStrategy):
    """
    Threshold-based reciprocal strategy for the Common Pool Resource Game.

    - Cooperates initially only if the stock starts at capacity.
    - Uses prior-round opponent cooperation rate versus a stock-dependent
      pressure threshold.
    - Defects in low-stock and late-game regimes.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number
        S = float(current_stock)
        if self.n <= 1:
            return Action.D
        if t == 0:
            return Action.C if math.isclose(S, self.capacity, rel_tol=0.0, abs_tol=1e-12) else Action.D
        if t == self.r - 1:
            return Action.D
        if S <= self.capacity / 8.0:
            return Action.D
        if S <= self.capacity / 4.0:
            return Action.D
        last_k = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        denom = max(self.n - 1, 1)
        q = last_k / denom
        if self.capacity > 0.0:
            P = 0.35 + 0.25 * (1.0 - S / self.capacity)
        else:
            P = 0.6
        P = max(0.35, min(0.6, P))
        if t >= self.r - 2:
            return Action.C if q >= 1.0 and S >= self.capacity / 2.0 else Action.D
        return Action.C if q >= P else Action.D

class Strategy_OPPORTUNISTIC_14(BaseStrategy):
    """
    Opportunistic common-pool strategy:
    - Cooperates early and in healthy or recovering stocks when opponents cooperate.
    - Defects selectively in high-stock/high-cooperation situations.
    - Switches to caution in warning/critical zones and near the endgame.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.full_threshold = 0.8 * self.capacity
        self.safe_threshold = 0.6 * self.capacity
        self.warning_threshold = 0.4 * self.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        if round_number == 0:
            return Action.C
        n_opponents = max(self.n_players - 1, 0)
        if n_opponents > 0 and len(history.opponent_cooperators) > 0:
            last_opp_coop = int(history.opponent_cooperators[-1])
            p_hat = last_opp_coop / n_opponents
        else:
            p_hat = 0.0
        high_coop = p_hat >= 0.75
        moderate_coop = p_hat >= 0.5
        S = float(current_stock)
        in_full = S >= self.full_threshold
        in_safe = self.safe_threshold <= S < self.full_threshold
        in_warning = self.warning_threshold <= S < self.safe_threshold
        in_critical = S < self.warning_threshold
        remaining_rounds = self.n_rounds - round_number
        my_actions = history.my_actions
        last_two_my_defect_heavy = False
        if len(my_actions) >= 2:
            last_two_my_defect_heavy = not bool(my_actions[-1]) and (not bool(my_actions[-2]))
        last_two_my_coop = False
        if len(my_actions) >= 2:
            last_two_my_coop = bool(my_actions[-1]) and bool(my_actions[-2])
        high_coop_two_rounds = False
        if len(history.opponent_cooperators) >= 2 and n_opponents > 0:
            p_hat_prev = int(history.opponent_cooperators[-2]) / n_opponents
            high_coop_two_rounds = p_hat_prev >= 0.75 and high_coop
        if len(history.opponent_cooperators) == 0 or n_opponents == 0:
            return Action.C if S >= 0.7 * self.capacity else Action.D
        if remaining_rounds == 1:
            if in_critical and high_coop:
                return Action.C
            return Action.D
        if remaining_rounds <= 3:
            if in_warning or in_critical:
                return Action.C if S >= self.safe_threshold else Action.C if high_coop else Action.D
            if in_full:
                return Action.D if high_coop else Action.C
            if in_safe:
                if high_coop and last_two_my_coop:
                    return Action.D
                if moderate_coop:
                    return Action.C
                return Action.D
        if last_two_my_defect_heavy and S >= self.safe_threshold:
            if in_full and high_coop:
                return Action.D
            return Action.C
        if in_full:
            return Action.D if high_coop else Action.C
        if in_safe:
            if high_coop and last_two_my_coop:
                safe_full_recent = 0
                for a in my_actions[::-1]:
                    if bool(a):
                        safe_full_recent += 1
                    else:
                        break
                if safe_full_recent >= 2 and safe_full_recent % 3 == 2:
                    return Action.D
                return Action.C
            if moderate_coop:
                return Action.C
            return Action.D
        if in_warning:
            return Action.C if high_coop else Action.D
        if in_critical:
            return Action.C if high_coop_two_rounds else Action.D
        return Action.C if S >= 0.7 * self.capacity else Action.D

class Strategy_OPPORTUNISTIC_15(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - starts with cooperation
    - cooperates when the stock is healthy and opponents cooperate sufficiently
    - defects when the stock is depleted, cooperation is too low, or at the endgame
    - tracks recent cooperation patterns to detect streaks and fallback behavior
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = max(2, int(game_description.n_players))
        self.r = max(1, int(game_description.n_rounds))
        self.capacity = float(game_description.capacity)
        self.q = int(math.ceil((self.n - 1) / 2))
        self.high_threshold = 0.75 * self.capacity
        self.medium_threshold = 0.4 * self.capacity
        self.low_threshold = 0.4 * self.capacity
        self._prev_opponent_cooperators = None
        self._alternating_like = False
        self._consecutive_q_or_more = 0
        self._last_action = Action.C

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number
        S = float(current_stock)
        if not math.isfinite(S):
            S = 0.0
        if S < 0.0:
            S = 0.0
        if t == 0:
            self._last_action = Action.C
            self._prev_opponent_cooperators = None
            self._alternating_like = False
            self._consecutive_q_or_more = 0
            return Action.C
        opps = history.opponent_cooperators
        k = int(opps[-1]) if len(opps) > 0 else 0
        if self._prev_opponent_cooperators is not None and len(opps) >= 2:
            prev_k = int(opps[-2])
            if prev_k != k:
                self._alternating_like = True
        self._prev_opponent_cooperators = k
        if k >= self.q:
            self._consecutive_q_or_more += 1
        else:
            self._consecutive_q_or_more = 0
        is_high = S >= self.high_threshold
        is_medium = self.medium_threshold <= S < self.high_threshold
        is_low = S < self.low_threshold
        if t == self.r - 1:
            action = Action.C if S >= 2 * self.n else Action.D
            self._last_action = action
            return action
        if S <= 0.0:
            self._last_action = Action.D
            return Action.D
        if k == 0:
            action = Action.C if is_high else Action.D
            self._last_action = action
            return action
        if self._consecutive_q_or_more >= 2:
            action = Action.C if S >= self.low_threshold else Action.D
            self._last_action = action
            return action
        if k >= self.q:
            if is_low:
                action = Action.D
            else:
                action = Action.C
        elif is_high and k >= max(0, self.q - 1):
            action = Action.C
        else:
            action = Action.D
        if self._last_action == Action.C:
            if k < self.q and (not is_high):
                action = Action.D
            elif k >= self.q and is_low:
                action = Action.D
        elif k >= self.q and (is_high or is_medium):
            action = Action.C
        if self._alternating_like:
            action = Action.C if S >= self.high_threshold else Action.D
        self._last_action = action
        return action

class Strategy_OPPORTUNISTIC_16(BaseStrategy):
    """
    Common-pool strategy with adaptive preserve/harvest behavior:
    - Cooperates on the first round.
    - Defects on the final round.
    - Cooperates when the stock is at or below a dynamic sustainability threshold.
    - Otherwise defects, especially when opponents cooperated in the previous round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(0, self.n - 1)
        self.kappa = int(math.ceil(self.n_opponents / 2.0))
        self.min_sustainable = float(max(2 * self.n, 0.0))
        self.mode = 'preserve'
        self.last_observed_cooperators = None
        self.last_expected_next_stock = None

    def _theta(self, round_number: int) -> float:
        """
        Sustainability threshold for the current decision round.
        round_number is 0-based for the already-played rounds.
        """
        remaining_including_current = max(1, self.r - round_number)
        frac = self.capacity / 4.0
        theta = max(self.min_sustainable, frac * (remaining_including_current / max(1, self.r)))
        return float(theta)

    def _next_stock(self, current_stock: float, my_action: Action, opp_cooperators: int) -> float:
        """
        Compute expected next stock after one round given current stock and observed opponents' cooperation.
        """
        n = max(2, self.n)
        S = float(current_stock)
        S = max(0.0, min(S, self.capacity))
        opp_cooperators = int(max(0, min(self.n_opponents, opp_cooperators)))
        if my_action == Action.C:
            my_consumption = S / (2.0 * n)
        else:
            my_consumption = S / n
        coop_consumption = opp_cooperators * (S / (2.0 * n))
        defect_consumption = (self.n_opponents - opp_cooperators) * (S / n)
        remaining = S - my_consumption - coop_consumption - defect_consumption
        if remaining < 0.0:
            remaining = 0.0
        growth = 2.0 * remaining * (1.0 - remaining / self.capacity) if self.capacity > 0 else 0.0
        next_stock = remaining + growth
        if next_stock > self.capacity:
            next_stock = self.capacity
        if next_stock < 0.0:
            next_stock = 0.0
        return float(next_stock)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        current_stock = float(current_stock)
        if round_number == 0:
            self.mode = 'preserve'
            self.last_observed_cooperators = None
            self.last_expected_next_stock = None
            return Action.C
        if round_number >= self.r - 1:
            self.mode = 'harvest'
            return Action.D
        theta_t = self._theta(round_number)
        last_k = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        last_k = max(0, min(self.n_opponents, last_k))
        if current_stock <= theta_t:
            self.mode = 'preserve'
            expected_next = self._next_stock(current_stock, Action.C, last_k)
            self.last_observed_cooperators = last_k
            self.last_expected_next_stock = expected_next
            return Action.C
        if last_k >= self.kappa:
            self.mode = 'harvest'
            expected_next = self._next_stock(current_stock, Action.D, last_k)
            self.last_observed_cooperators = last_k
            self.last_expected_next_stock = expected_next
            return Action.D
        if current_stock > theta_t:
            self.mode = 'harvest'
            expected_next = self._next_stock(current_stock, Action.D, last_k)
            self.last_observed_cooperators = last_k
            self.last_expected_next_stock = expected_next
            return Action.D
        self.mode = 'preserve'
        expected_next = self._next_stock(current_stock, Action.C, last_k)
        self.last_observed_cooperators = last_k
        self.last_expected_next_stock = expected_next
        return Action.C

class Strategy_OPPORTUNISTIC_17(BaseStrategy):
    """
    Adaptive common-pool strategy with cooperation estimation, stock-aware
    mode switching, and endgame/punishment safeguards.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(0, self.n_players - 1)
        self.p_hat = 0.5
        self.mode = 'build'

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number + 1
        S = float(current_stock)
        if S <= 0.0:
            return Action.C
        if history.round_number > 0 and self.n_opponents > 0:
            k_t = int(history.opponent_cooperators[-1])
            q_t = k_t / self.n_opponents
            self.p_hat = 0.7 * self.p_hat + 0.3 * q_t
            if q_t >= 0.75:
                self.mode = 'build'
            elif q_t >= 0.45:
                self.mode = 'harvest'
            else:
                self.mode = 'punish'
        H = 0.8 * self.capacity
        L = 0.35 * self.capacity
        S_half = S / 2.0
        S_C = min(S - S_half + 2.0 * S_half * (1.0 - S_half / self.capacity), self.capacity)
        S_D = 0.0
        if t == 1:
            return Action.C
        if t == self.n_rounds:
            if S >= 1.8 * self.n_players or self.p_hat <= 0.55:
                return Action.D
            return Action.C
        if S < 0.15 * self.capacity:
            return Action.C
        if self.mode == 'build' and S < H:
            return Action.C
        if self.mode == 'punish':
            if S <= L:
                return Action.C
            return Action.D
        if S <= L:
            return Action.C if self.p_hat >= 0.6 else Action.D
        if S >= H:
            return Action.D if self.p_hat >= 0.7 else Action.C
        if self.p_hat >= 0.65 and S_C >= S:
            return Action.D
        if self.p_hat < 0.65:
            return Action.C
        return Action.C

class Strategy_OPPORTUNISTIC_18(BaseStrategy):
    """
    Stock-preserving common-pool strategy:
    - Cooperates initially and under uncertainty or low stock.
    - Defects only when the pool looks safe and opponents have been fully cooperative.
    - Falls back to cooperation immediately after any sign of overuse.
    - Enters a low-stock restraint mode after severe depletion.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(0, self.n_players - 1)
        self.low_stock_restraint = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = int(history.round_number)
        r_last = self.n_rounds - 1
        S = float(current_stock)
        cap = self.capacity
        n = self.n_players
        n_opp = self.n_opponents
        if t == 0:
            return Action.C
        if S <= 0.0:
            return Action.C
        if S < cap / 4.0:
            self.low_stock_restraint = True
        if self.low_stock_restraint:
            if t == r_last:
                return Action.D
            if S <= cap / 3.0:
                return Action.C
            self.low_stock_restraint = False
        if t == r_last:
            return Action.D if S > 0.0 else Action.C
        last_coop = int(history.opponent_cooperators[-1])
        last_coop = max(0, min(last_coop, n_opp))
        if n_opp <= 0:
            return Action.C
        p = last_coop / float(n_opp)
        m = n_opp - last_coop
        x = S / cap if cap > 0.0 else 0.0
        danger = 2.0 * (1.0 - x) - x / float(n) if n > 0 else 0.0
        if 0.0 < p < 1.0:
            return Action.C
        if p >= 1.0:
            prev_full_coop = False
            if history.round_number >= 2 and n_opp > 0:
                prev_prev_coop = int(history.opponent_cooperators[-2])
                prev_prev_coop = max(0, min(prev_prev_coop, n_opp))
                prev_full_coop = prev_prev_coop == n_opp
            if S >= cap / 2.0 and (prev_full_coop or history.round_number >= 1):
                return Action.D
            return Action.C
        if m >= 1 or danger >= 0.25 or S < cap / 2.0:
            return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_19(BaseStrategy):
    """
    Common pool strategy:
    - Starts by cooperating.
    - Estimates recent opponent cooperation with a weighted average of the last up to 3 rounds.
    - Protects the stock when low, exploits when stock is high and cooperation is reliable,
      and becomes conservative near the end of the game.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(self.n_players - 1, 1)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        if round_number == 0:
            return Action.C
        opp_counts = history.opponent_cooperators
        recent = opp_counts[max(0, round_number - 3):round_number]
        if len(recent) == 0:
            bar_h = 0.0
            h_last = 0.0
        else:
            h_vals = [float(x) / float(self.n_opponents) for x in recent]
            h_last = h_vals[-1]
            weights = [3.0, 2.0, 1.0][:len(h_vals)]
            weights_sum = sum(weights)
            bar_h = sum((w * h for w, h in zip(weights, reversed(h_vals)))) / weights_sum
        low_stock = current_stock <= 0.45 * self.capacity
        mid_stock = 0.45 * self.capacity < current_stock < 0.7 * self.capacity
        high_stock = current_stock >= 0.7 * self.capacity
        endgame = round_number + 1 >= max(self.n_rounds - 1, 1)
        if low_stock:
            return Action.C
        if endgame:
            if current_stock <= 0.6 * self.capacity or bar_h < 0.5:
                return Action.C
            return Action.D
        if high_stock and bar_h >= 0.6:
            return Action.D
        if mid_stock:
            if bar_h >= 0.5:
                return Action.C
            return Action.D
        if bar_h < 1.0 / 3.0:
            return Action.D
        return Action.C

class Strategy_OPPORTUNISTIC_20(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Cooperates early when the pool is large enough.
    - Exploits strong cooperation by opponents when the stock is healthy.
    - Defects when the stock is low, in the final round, or when cooperation weakens.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.m = max(0, self.n - 1)
        self.q_estimate = 0.5

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = int(history.round_number) + 1
        if self.capacity <= 0:
            return Action.D
        s_t = float(current_stock)
        if s_t <= 0:
            return Action.D
        u_t = s_t / self.capacity
        if history.round_number > 0 and len(history.opponent_cooperators) > 0 and (self.m > 0):
            k_last = int(history.opponent_cooperators[-1])
            k_last = max(0, min(k_last, self.m))
            q_obs = k_last / self.m
            self.q_estimate = 0.7 * self.q_estimate + 0.3 * q_obs
            q = self.q_estimate
        else:
            q = self.q_estimate if self.q_estimate is not None else 0.5
        if t == 1:
            return Action.C if self.capacity >= 4 * self.n else Action.D
        if t >= self.r:
            return Action.D if s_t >= self.capacity / 2 else Action.C
        if u_t <= 0.2:
            return Action.D
        if q >= 0.75 and u_t >= 0.3:
            return Action.D
        if u_t >= 0.6 and q >= 0.5:
            return Action.C
        if u_t >= 0.45 and q >= 0.6 and (t <= self.r - 2):
            return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_21(BaseStrategy):
    """
    Adaptive common-pool strategy with:
    - cooperation streak tracking
    - defensive mode after repeated low cooperation
    - opportunistic defection when cooperation is strong and stock is healthy
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.last_observed_opponents_cooperators = 0
        self.cooperation_streak = 0
        self.low_cooperation_streak = 0
        self.defensive_mode = False
        self.last_processed_round = -1

    def _p_from_k(self, k: int) -> float:
        n = self.game_description.n_players
        n_opponents = max(n - 1, 1)
        if n <= 2:
            if k <= 0:
                return 0.0
            if k >= 1:
                return 1.0
        return float(k) / float(n_opponents)

    def _update_memory(self, history: PlayerHistory) -> None:
        if history.round_number <= 0:
            return
        current_round = history.round_number - 1
        if current_round == self.last_processed_round:
            return
        k = int(history.opponent_cooperators[-1])
        p = self._p_from_k(k)
        if p >= 0.8:
            self.cooperation_streak += 1
        else:
            self.cooperation_streak = 0
        if p < 0.5:
            self.low_cooperation_streak += 1
        else:
            self.low_cooperation_streak = 0
        if self.low_cooperation_streak >= 2:
            self.defensive_mode = True
        if p >= 0.75:
            self.defensive_mode = False
        self.last_observed_opponents_cooperators = k
        self.last_processed_round = current_round

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        capacity = float(self.game_description.capacity)
        round_number = history.round_number
        if round_number == 0:
            return Action.C
        self._update_memory(history)
        if round_number >= self.game_description.n_rounds - 1:
            return Action.D
        stock = float(current_stock)
        k = self.last_observed_opponents_cooperators
        p = self._p_from_k(k)
        critical_stock = stock <= 0.25 * capacity
        fragile_stock = stock <= 0.4 * capacity
        healthy_stock = stock >= 0.6 * capacity
        safe_stock = stock >= 0.75 * capacity
        if critical_stock:
            return Action.C
        if self.defensive_mode:
            return Action.C if critical_stock else Action.D
        if self.cooperation_streak >= 2 and healthy_stock:
            return Action.D
        if p < 0.5:
            return Action.C
        if fragile_stock and p < 0.75:
            return Action.C
        if 0.5 <= p < 0.8 and stock < 0.6 * capacity:
            return Action.C
        if safe_stock and p >= 0.8:
            return Action.D
        if healthy_stock and p >= 0.9:
            return Action.D
        if p == 0.5:
            return Action.D if healthy_stock else Action.C
        return Action.C

class Strategy_OPPORTUNISTIC_22(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Starts cooperatively
    - Defects quickly when cooperation falls below a majority
    - Rewards full cooperation and abundant stock
    - Enters extraction mode in the late game unless the group remains fully aligned
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = max(2, int(game_description.n_players))
        self.r = max(1, int(game_description.n_rounds))
        self.capacity = float(game_description.capacity)
        self.theta = math.ceil((self.n - 1) / 2)
        self.low_majority = math.floor((self.n - 1) / 2)
        self.high_stock_threshold = 2.0 / 3.0 * self.capacity
        self.low_stock_threshold = 0.5 * self.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = int(history.round_number)
        if t == 0:
            return Action.C
        opp = history.opponent_cooperators
        last_k = int(opp[-1]) if len(opp) > 0 else 0
        if len(opp) > 0:
            denom = max(1, self.n - 1)
            m_t = float(np.mean(opp)) / float(denom)
        else:
            m_t = 0.0
        b_t = 0
        for val in opp[::-1]:
            if int(val) <= self.low_majority:
                b_t += 1
            else:
                break
        if b_t >= 2:
            if last_k >= self.theta:
                if current_stock >= self.high_stock_threshold and last_k == self.n - 1:
                    return Action.C
                return Action.C
            if current_stock >= self.high_stock_threshold and last_k == self.n - 1:
                return Action.C
            return Action.D
        if t >= self.r - 2:
            if last_k == self.n - 1 and current_stock >= self.high_stock_threshold:
                return Action.C
            return Action.D
        if current_stock <= self.low_stock_threshold:
            if last_k == self.n - 1:
                return Action.C
            return Action.D
        if current_stock >= self.high_stock_threshold:
            if last_k == self.n - 1:
                return Action.C
            if m_t >= 0.75:
                return Action.C
            if m_t <= 0.5:
                return Action.D
        if last_k >= self.theta:
            return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_23(BaseStrategy):
    """
    State-contingent threshold strategy for the Common Pool Resource Game.
    Uses current stock, recent opponent cooperation, running cooperation average,
    and endgame tightening to decide between cooperate and defect.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.lambda_ = 0.35

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = float(self.game_description.capacity)
        if capacity <= 0:
            return Action.D
        if n < 2:
            return Action.D
        q = max(0.0, min(1.0, float(current_stock) / capacity))
        round_t = history.round_number
        if round_t == 0:
            return Action.C if q >= 0.75 else Action.D
        opp = history.opponent_cooperators
        m = n - 1
        last_k = int(opp[-1]) if len(opp) > 0 else 0
        x_prev = 0.0 if m <= 0 else max(0.0, min(1.0, last_k / m))
        a = x_prev
        if len(opp) >= 2:
            a = float(opp[0]) / m if m > 0 else 0.0
            a = max(0.0, min(1.0, a))
            for idx in range(1, len(opp)):
                x_i = float(opp[idx]) / m if m > 0 else 0.0
                x_i = max(0.0, min(1.0, x_i))
                a = (1.0 - self.lambda_) * a + self.lambda_ * x_i
        x_eff = 0.5 * x_prev + 0.5 * a
        coop_streak = 0
        for idx in range(len(opp) - 1, -1, -1):
            x_i = float(opp[idx]) / m if m > 0 else 0.0
            if x_i >= 0.8:
                coop_streak += 1
            else:
                break
        anti_exploit = False
        if round_t >= 2 and bool(history.my_actions[-1]):
            prev_k = int(opp[-2]) if len(opp) >= 2 else last_k
            x_before = max(0.0, min(1.0, prev_k / m)) if m > 0 else 0.0
            if x_before - x_prev >= 0.25:
                anti_exploit = True
        if round_t >= r - 3:
            return Action.C if q >= 0.9 and x_eff >= 0.8 else Action.D
        if x_prev <= 0.25:
            return Action.C if q >= 0.85 and x_prev >= 0.75 else Action.D
        if x_prev >= 0.8 and coop_streak >= 2:
            return Action.C if q >= 0.6 else Action.D
        if anti_exploit:
            return Action.C if q >= 0.9 and x_prev >= 0.75 else Action.D
        if q < 0.55 or x_eff < 0.6:
            return Action.D
        if q >= 0.8 and x_eff >= 0.7:
            return Action.C
        if 0.55 <= q < 0.8:
            return Action.C if x_eff >= 0.7 and coop_streak >= 2 else Action.D
        if q <= 0.45 or x_eff <= 0.5:
            return Action.D
        if q >= 0.7 and x_eff >= 0.7:
            return Action.C
        if q >= 0.6 and x_eff >= 0.6:
            return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_24(BaseStrategy):
    """
    Conservative-foraging common pool strategy:
    - Cooperate first to preserve stock and observe opponents.
    - Defect only when cooperation is strong and the stock remains healthy.
    - Revert to cooperation when stock is low or cooperation weakens.
    - Defect unconditionally in the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.m = max(self.n - 1, 0)
        self._one_third = self.capacity / 3.0
        self._one_half = self.capacity / 2.0
        self._three_fifths = 3.0 * self.capacity / 5.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        if round_number == 0:
            return Action.C
        if round_number >= self.r - 1:
            return Action.D
        k = None
        rho = 0.0
        if len(history.opponent_cooperators) > 0:
            k = int(history.opponent_cooperators[-1])
            if self.m > 0:
                rho = k / self.m
            else:
                rho = 0.0
        S = float(current_stock)
        if S <= self._one_third:
            return Action.C
        if round_number == self.r - 2:
            if rho >= 0.5:
                return Action.D
            return Action.C
        if rho >= 2.0 / 3.0 and S >= self._one_half:
            return Action.D
        if rho >= 0.5 and S >= self._three_fifths:
            return Action.D
        if rho <= 1.0 / 3.0:
            return Action.C
        return Action.C

class Strategy_OPPORTUNISTIC_25(BaseStrategy):
    """
    Adaptive common-pool strategy with exponential smoothing of opponent cooperation.

    - Starts with cooperation.
    - Defects in the final round.
    - Uses an estimated opponent cooperation rate to forecast stock evolution.
    - Defects when the forecast suggests the stock can be sustained; otherwise cooperates.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self._eps = 1e-12
        self.last_estimated_q = 1.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = int(history.round_number)
        n = self.n_players
        r = self.n_rounds
        S = float(current_stock)
        if t == 0:
            self.last_estimated_q = 1.0
            return Action.C
        if t >= r - 1:
            self.last_estimated_q = self._estimate_q(history)
            return Action.D
        if S <= self._eps:
            self.last_estimated_q = self._estimate_q(history)
            return Action.C
        q_t = self._estimate_q(history)
        self.last_estimated_q = q_t
        opponents = max(0, n - 1)
        expected_other_consumption = opponents * (q_t * (S / (2.0 * n)) + (1.0 - q_t) * (S / n))

        def score_for(action: Action) -> float:
            own_consumption = S / (2.0 * n) if action == Action.C else S / n
            remaining = max(0.0, S - own_consumption - expected_other_consumption)
            next_stock = min(remaining + 2.0 * remaining * (1.0 - remaining / self.capacity), self.capacity)
            lambda_t = (r - t) / (r - t + 1.0)
            return own_consumption + lambda_t * next_stock
        u_c = score_for(Action.C)
        u_d = score_for(Action.D)
        if abs(u_c - u_d) <= self._eps:
            if q_t >= 0.5 and S >= self.capacity / 2.0:
                return Action.D
            return Action.C
        return Action.D if u_d > u_c else Action.C

    def _estimate_q(self, history: PlayerHistory) -> float:
        """
        Exponentially smoothed estimate of opponent cooperation.
        q_1 = 1
        q_{t+1} = 0.5 * q_t + 0.5 * (m_t / (n-1))
        """
        n = self.n_players
        opponents = max(1, n - 1)
        q = 1.0
        rounds_observed = int(history.round_number)
        if rounds_observed <= 0:
            return q
        opp = history.opponent_cooperators
        limit = min(rounds_observed, len(opp))
        for i in range(limit):
            m_t = float(opp[i])
            q = 0.5 * q + 0.5 * (m_t / opponents)
        if q < 0.0:
            return 0.0
        if q > 1.0:
            return 1.0
        return q

class Strategy_OPPORTUNISTIC_26(BaseStrategy):
    """
    Threshold strategy for the Common Pool Resource Game.

    - Opens with cooperation.
    - Defects in the final round.
    - Uses current stock and estimated opponent cooperation to decide in between.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        n = max(int(game_description.n_players), 2)
        capacity = float(game_description.capacity)
        self.n_players = n
        self.n_opponents = max(n - 1, 1)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = capacity
        self.H = math.ceil(2 * (n - 1) / 3)
        self.M = math.ceil((n - 1) / 2)
        self.L = capacity / 3.0
        self.R = 2.0 * capacity / 3.0

    def _estimate_cooperation(self, history: PlayerHistory) -> float:
        """
        Compute q_hat for the most recently observed round.
        If no prior rounds exist, returns 0.0.
        """
        rounds_played = history.round_number
        if rounds_played <= 0:
            return 0.0
        opp_counts = history.opponent_cooperators
        denom = float(self.n_opponents)
        if denom <= 0.0:
            return 0.0
        q_hat = float(opp_counts[0]) / denom
        for t in range(1, rounds_played):
            q_t = float(opp_counts[t]) / denom
            q_hat = 0.7 * q_hat + 0.3 * q_t
        return q_hat

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number + 1
        r = self.n_rounds
        n_opponents = self.n_opponents
        if t == 1:
            return Action.C
        if t == r:
            return Action.D
        q_hat_prev = self._estimate_cooperation(history)
        c_prev = int(history.opponent_cooperators[-1]) if history.round_number > 0 else 0
        if current_stock <= self.L:
            if c_prev == n_opponents:
                return Action.C
            return Action.D
        if current_stock >= self.R:
            if c_prev >= self.H or q_hat_prev >= 0.7:
                return Action.C
            return Action.D
        if c_prev >= self.M and q_hat_prev >= 0.5:
            return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_27(BaseStrategy):
    """
    Stock-based threshold strategy with:
    - cooperative mode in healthy pools,
    - defensive mode in fragile pools,
    - recovery after collapse,
    - periodic exploitation against highly cooperative opponents,
    - short backlash retaliation after low cooperation.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self._eligible_exploit_streak = 0
        self._backlash_remaining = 0
        self._last_round_seen = -1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = int(history.round_number)
        s = float(current_stock)
        n = self.n_players
        cap = self.capacity
        if t > 0 and len(history.opponent_cooperators) > 0:
            k = int(history.opponent_cooperators[-1])
            n_opponents = max(n - 1, 1)
            p = k / n_opponents
        else:
            k = 0
            p = 0.0
        if t != self._last_round_seen:
            self._last_round_seen = t
        if t == 0:
            self._eligible_exploit_streak = 0
            self._backlash_remaining = 0
            return Action.C
        if t == self.n_rounds - 1:
            return Action.D if s > 0 else Action.C
        if self._backlash_remaining > 0:
            self._backlash_remaining -= 1
            if p >= 0.8 and s >= 0.55 * cap:
                self._eligible_exploit_streak += 1
            else:
                self._eligible_exploit_streak = 0
            return Action.D
        if s <= 0.2 * cap:
            self._eligible_exploit_streak = 0
            if s == 0.0:
                return Action.C if k >= max(n - 1, 0) else Action.D
            return Action.C if p >= 0.75 else Action.D
        if p <= 0.2:
            self._backlash_remaining = 2
            self._eligible_exploit_streak = 0
            return Action.D
        exploit_condition = p >= 0.8 and s >= 0.55 * cap
        if exploit_condition:
            self._eligible_exploit_streak += 1
            if self._eligible_exploit_streak % 3 == 0:
                return Action.D
            return Action.C
        else:
            self._eligible_exploit_streak = 0
        safe_zone = s >= 0.6 * cap and p >= 0.6
        fragile_zone = s <= 0.4 * cap or p <= 0.4
        transition_zone = not safe_zone and (not fragile_zone)
        if safe_zone:
            return Action.C
        if fragile_zone:
            return Action.D
        if s >= 0.5 * cap and p >= 0.5:
            return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_28(BaseStrategy):
    """
    Cooperative-by-default common-pool strategy with adaptive opportunism:
    - Cooperate in fragile or uncertain conditions.
    - Defect when stock is safe and observed cooperation is sufficiently high.
    - Maintain a smoothed cooperation score q to slow trust and react to repeated defection.
    - Use simple memory to temporarily cooperate after unanimous defection.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(self.n_players - 1, 0)
        self.q = 1.0
        self.force_cooperate_rounds = 0
        self._last_processed_round = -1

    def _opponent_coop_rate(self, history: PlayerHistory) -> float:
        if history.round_number <= 0 or self.n_opponents <= 0:
            return 1.0
        last_count = int(history.opponent_cooperators[-1])
        if last_count <= 0:
            return 0.0
        if last_count >= self.n_opponents:
            return 1.0
        return last_count / self.n_opponents

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        stock = float(current_stock)
        if round_number > 0 and self._last_processed_round != round_number:
            c_obs = self._opponent_coop_rate(history)
            self.q = 0.8 * self.q + 0.2 * c_obs
            if self.n_opponents > 0 and int(history.opponent_cooperators[-1]) == 0:
                self.force_cooperate_rounds = max(self.force_cooperate_rounds, 2)
            self._last_processed_round = round_number
        fragile = stock < 0.35 * self.capacity or self.q < 0.5
        safe = stock >= 0.6 * self.capacity and self.q >= 0.5
        if self.n_opponents <= 0:
            return Action.D if round_number == self.n_rounds - 1 else Action.C
        if round_number == 0:
            return Action.C
        if round_number == self.n_rounds - 1:
            return Action.C if fragile else Action.D
        if stock <= 0.0:
            return Action.C
        c = self._opponent_coop_rate(history)
        if self.force_cooperate_rounds > 0 and (not safe):
            self.force_cooperate_rounds -= 1
            return Action.C
        if fragile:
            return Action.C
        if safe:
            return Action.D
        if self.q < 0.5:
            return Action.C
        return Action.C if c >= 0.5 else Action.D

class Strategy_OPPORTUNISTIC_29(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - starts cooperatively,
    - tracks opponent cooperation with an exponential moving average,
    - defects only in healthy, stable cooperation conditions,
    - enforces a brief cooldown after any defection.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(0, self.n_players - 1)
        self.coop_rate = 1.0
        self.streak = 0
        self.cooldown = 0
        self.high = math.ceil(0.8 * self.n_opponents)
        self.medium = math.ceil(0.6 * self.n_opponents)
        self.low = math.floor(0.5 * self.n_opponents)
        self.safe_stock = 0.75 * self.capacity
        self.danger_stock = 0.45 * self.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number
        if t == 0:
            return Action.C
        m = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else self.n_opponents
        m = max(0, min(m, self.n_opponents))
        denom = self.n_opponents if self.n_opponents > 0 else 1
        observed_rate = m / denom
        self.coop_rate = 0.7 * self.coop_rate + 0.3 * observed_rate
        if m >= self.high:
            self.streak += 1
        else:
            self.streak = 0
        if self.cooldown > 0:
            self.cooldown -= 1
        if t >= self.n_rounds - 1:
            return Action.D
        S = float(current_stock)
        if S <= self.danger_stock:
            return Action.C
        if self.cooldown > 0:
            return Action.C
        if S >= self.safe_stock and self.coop_rate >= 0.75 and (self.streak >= 2):
            self.cooldown = 2
            return Action.D
        if S >= self.capacity and m >= self.medium:
            self.cooldown = 2
            return Action.D
        return Action.C

class Strategy_OPPORTUNISTIC_30(BaseStrategy):
    """
    Cooperative-by-default common-pool strategy with stock-sensitive defection,
    short punishment memory, and final-round caution.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.theta_low = 0.65
        self.theta_high = 0.85
        self.s_safe = 0.75 * self.capacity
        self.s_mid = 0.5 * self.capacity
        self.s_stress = 0.35 * self.capacity
        self.punishment_mode = False
        self.consecutive_good = 0
        self.punishment_remaining = 0
        self._last_processed_round = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        n_opponents = max(self.n_players - 1, 1)
        if round_number > self._last_processed_round:
            start = max(self._last_processed_round, 0)
            end = round_number
            for idx in range(start, end):
                coop_count = int(history.opponent_cooperators[idx])
                c = coop_count / n_opponents
                if c < self.theta_low:
                    self.punishment_mode = True
                    self.punishment_remaining = 2
                    self.consecutive_good = 0
                elif c >= self.theta_high:
                    self.consecutive_good += 1
                    if self.consecutive_good >= 2:
                        self.punishment_mode = False
                        self.punishment_remaining = 0
                else:
                    self.consecutive_good = 0
                if self.punishment_remaining > 0:
                    self.punishment_remaining = max(0, self.punishment_remaining - 1)
                    if self.punishment_remaining == 0 and self.consecutive_good < 2:
                        self.punishment_mode = False
            self._last_processed_round = round_number
        if round_number == 0:
            return Action.C
        c_last = int(history.opponent_cooperators[-1]) / n_opponents
        is_final_decision = round_number == self.n_rounds - 1
        if is_final_decision:
            if current_stock >= self.s_mid:
                return Action.D
            if c_last >= self.theta_high and current_stock < self.s_mid:
                return Action.C
            return Action.D
        if self.punishment_mode or self.punishment_remaining > 0:
            if c_last >= self.theta_high and current_stock > self.s_mid or (c_last >= self.theta_low and current_stock > self.s_safe):
                self.punishment_mode = False
                self.punishment_remaining = 0
                self.consecutive_good = 2 if c_last >= self.theta_high else 0
                return Action.C
            return Action.D
        if current_stock <= self.s_stress:
            if c_last < self.theta_low:
                self.punishment_mode = True
                self.punishment_remaining = 2
                self.consecutive_good = 0
            return Action.D
        if current_stock <= self.s_mid:
            return Action.C if c_last >= self.theta_high else Action.D
        if current_stock <= self.s_safe:
            return Action.C if c_last >= self.theta_low else Action.D
        return Action.C if c_last >= self.theta_low else Action.D

class Strategy_OPPORTUNISTIC_31(BaseStrategy):
    """
    State-contingent threshold strategy for the Common Pool Resource Game.
    Cooperates initially, tracks a smoothed belief about opponent cooperation,
    and defects when cooperation is weak, the pool is vulnerable, or the game
    is in the final rounds unless a strong cooperative streak is present.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.capacity = float(game_description.capacity)
        self.n_players = int(game_description.n_players)
        self.n_opponents = max(self.n_players - 1, 1)
        self.n_rounds = int(game_description.n_rounds)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        stock = float(current_stock)
        capacity = self.capacity
        if round_number == 0:
            return Action.C
        belief = 1.0
        opponent_counts = history.opponent_cooperators
        for idx in range(round_number):
            coop_count = int(opponent_counts[idx])
            share = coop_count / self.n_opponents if self.n_opponents > 0 else 0.0
            belief = 0.7 * belief + 0.3 * share
            if share < 0.5:
                belief = min(belief, 0.4)
            if share >= 0.8:
                belief = max(belief, 0.85)
        t = round_number + 1
        if self.n_rounds >= 2 and t >= self.n_rounds - 1:
            if round_number >= 2:
                last_share = int(opponent_counts[round_number - 1]) / self.n_opponents if self.n_opponents > 0 else 0.0
                prev_share = int(opponent_counts[round_number - 2]) / self.n_opponents if self.n_opponents > 0 else 0.0
                if last_share == 1.0 and prev_share == 1.0 and (stock >= 0.8 * capacity):
                    return Action.C
            return Action.D
        last_share = int(opponent_counts[round_number - 1]) / self.n_opponents if self.n_opponents > 0 else 0.0
        if last_share == 0.0 and round_number > 1:
            return Action.D
        vulnerability = stock / capacity if capacity > 0 else 0.0
        q_t = 0.55 + 0.25 * (1.0 - vulnerability)
        if belief >= q_t and stock >= capacity / 4.0:
            return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_32(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Starts by cooperating.
    - Tracks smoothed opponent cooperation.
    - Defects only when cooperation is high and stock is comfortably high.
    - Falls back to cooperation under low stock or weak cooperation.
    - Always defects on the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self._heavy_defect_cooldown = 0
        self._last_history_len = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        cap = float(self.game_description.capacity)
        round_number = history.round_number
        remaining_rounds = r - round_number
        if round_number == 0:
            return Action.C
        opp_counts = history.opponent_cooperators
        n_opponents = max(n - 1, 1)
        e_t = (n - 1) / 2.0
        if len(opp_counts) >= 1:
            e_t = float(opp_counts[0])
            for idx in range(1, len(opp_counts)):
                e_t = round(0.6 * float(opp_counts[idx]) + 0.4 * float(e_t))
        last_o = int(opp_counts[-1]) if len(opp_counts) > 0 else 0
        rho_t = last_o / n_opponents if n_opponents > 0 else 0.0
        if len(opp_counts) >= 2:
            rho_prev = float(opp_counts[-2]) / n_opponents if n_opponents > 0 else 0.0
            if rho_prev < 0.5 and rho_t < 0.5:
                self._heavy_defect_cooldown = 2
        if self._heavy_defect_cooldown > 0:
            self._heavy_defect_cooldown -= 1
            return Action.C
        if remaining_rounds == 1:
            return Action.D
        if remaining_rounds == 2 and current_stock >= 2.0 * cap / 3.0:
            return Action.D
        high_coop_threshold = math.ceil(2.0 * (n - 1) / 3.0)
        low_coop_threshold = math.floor((n - 1) / 3.0)
        high_coop = e_t > high_coop_threshold
        medium_stock = current_stock > cap / 2.0
        low_stock = current_stock < cap / 3.0
        low_coop = e_t <= low_coop_threshold
        if high_coop and medium_stock:
            return Action.D
        elif low_stock or low_coop:
            return Action.C
        else:
            if rho_t >= 0.5 and current_stock >= 2.0 * cap / 5.0:
                return Action.D
            return Action.C

class Strategy_INDIVIDUALISTIC_5(BaseStrategy):
    """
    Common-pool strategy:
    - Cooperate in round 1.
    - Defect in the final round.
    - In the penultimate round, cooperate only under low stock.
    - In intermediate rounds, cooperate when stock is scarce, or when
      opponents were sufficiently cooperative last round and stock is not high.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        current_round = round_number + 1
        if round_number == 0:
            return Action.C
        if current_round == self.n_rounds:
            return Action.D
        if current_round == self.n_rounds - 1:
            return Action.C if current_stock <= self.capacity / 3.0 else Action.D
        n_opponents = max(self.n_players - 1, 1)
        last_opponents_coop = 0
        if len(history.opponent_cooperators) > 0:
            last_opponents_coop = int(history.opponent_cooperators[-1])
        rho = last_opponents_coop / n_opponents
        s = current_stock / self.capacity if self.capacity > 0 else 0.0
        if s <= 1.0 / 3.0:
            return Action.C
        if rho <= 1.0 / 3.0 and s <= 2.0 / 3.0:
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_6(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Cooperates early when stock and observed cooperation are strong.
    - Defects under low stock, weak cooperation, pressure shocks, and in the endgame.
    - Uses a short memory of recent stock movements to enforce temporary punishment.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.opponents = max(self.n - 1, 0)
        self.cooldown_remaining = 0
        self.last_stock_seen = None
        self.last_opponent_cooperation_rate = 0.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.n
        r = self.r
        capacity = self.capacity
        m = self.opponents
        t_index = history.round_number
        current_stock = float(current_stock)
        if history.round_number > 0 and len(history.opponent_cooperators) > 0 and (m > 0):
            k_prev = int(history.opponent_cooperators[-1])
            c_t = k_prev / m
        else:
            c_t = 0.0
        prev_stock = self.last_stock_seen
        dropped_more_than_20 = False
        increased_stock = False
        if prev_stock is not None:
            delta = current_stock - float(prev_stock)
            if delta < -0.2 * capacity:
                dropped_more_than_20 = True
            if delta > 0.0:
                increased_stock = True
        if dropped_more_than_20:
            self.cooldown_remaining = 2
        emergency_threshold = capacity / n if n > 0 else capacity
        if current_stock <= emergency_threshold:
            self.last_stock_seen = current_stock
            self.last_opponent_cooperation_rate = c_t
            if self.cooldown_remaining > 0:
                self.cooldown_remaining = max(0, self.cooldown_remaining - 1)
            return Action.D
        if history.round_number == 0:
            action = Action.C if n <= 3 and current_stock > 0.8 * capacity else Action.D
            self.last_stock_seen = current_stock
            self.last_opponent_cooperation_rate = c_t
            return action
        if t_index >= max(0, r - 3):
            if c_t == 1.0 and current_stock > 0.75 * capacity:
                action = Action.C
            else:
                action = Action.D
            self.last_stock_seen = current_stock
            self.last_opponent_cooperation_rate = c_t
            if self.cooldown_remaining > 0:
                self.cooldown_remaining = max(0, self.cooldown_remaining - 1)
            return action
        if self.cooldown_remaining > 0:
            if increased_stock and c_t >= 0.75:
                action = Action.C
            else:
                action = Action.D
            self.cooldown_remaining = max(0, self.cooldown_remaining - 1)
            self.last_stock_seen = current_stock
            self.last_opponent_cooperation_rate = c_t
            return action
        T_t = history.round_number / (r - 1) if r > 1 else 1.0
        theta_t = 0.55 - 0.15 * T_t
        sigma_t = 0.45 * capacity + 0.25 * (capacity - current_stock)
        cooperate = current_stock > sigma_t and c_t > theta_t and (current_stock > 0.5 * capacity or c_t > 0.75)
        action = Action.C if cooperate else Action.D
        self.last_stock_seen = current_stock
        self.last_opponent_cooperation_rate = c_t
        return action

class Strategy_INDIVIDUALISTIC_7(BaseStrategy):
    """
    Probing cooperation early, then adaptive extraction with conservative
    protection under low stock, endgame tightening, and smoothed belief updates
    about opponent cooperation.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.q = 1.0
        self._last_processed_round = 0

    def _expected_next_stock(self, current_stock: float, cooperate: bool) -> float:
        n = max(2, int(self.game_description.n_players))
        capacity = float(self.game_description.capacity)
        S = max(0.0, float(current_stock))
        opp_per_player = self.q * (S / (2.0 * n)) + (1.0 - self.q) * (S / n)
        total_opp = (n - 1) * opp_per_player
        my_consumption = S / (2.0 * n) if cooperate else S / n
        remaining = S - my_consumption - total_opp
        if remaining < 0.0:
            remaining = 0.0
        growth = 2.0 * remaining * (1.0 - remaining / capacity) if capacity > 0 else 0.0
        new_stock = remaining + growth
        return min(max(new_stock, 0.0), capacity)

    def _sync_belief(self, history: PlayerHistory) -> None:
        n = max(2, int(self.game_description.n_players))
        total_rounds = int(history.round_number)
        start = min(self._last_processed_round, total_rounds)
        if start >= total_rounds:
            return
        for idx in range(start, total_rounds):
            coop_count = int(history.opponent_cooperators[idx]) if idx < len(history.opponent_cooperators) else 0
            denom = max(1, n - 1)
            observed_rate = coop_count / denom
            self.q = 0.7 * self.q + 0.3 * observed_rate
            if idx >= 1 and idx < len(history.opponent_cooperators):
                prev = int(history.opponent_cooperators[idx - 1]) / denom
                curr = observed_rate
                if prev <= 0.5 and curr <= 0.5:
                    self.q = min(self.q, 0.25)
                elif prev >= 0.5 and curr >= 0.5:
                    self.q = max(self.q, 0.75)
        self._last_processed_round = total_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        self._sync_belief(history)
        n = max(2, int(self.game_description.n_players))
        r = max(1, int(self.game_description.n_rounds))
        t = int(history.round_number) + 1
        S = max(0.0, float(current_stock))
        capacity = float(self.game_description.capacity)
        if t == 1:
            return Action.C
        if t >= r:
            return Action.D
        last_coop_count = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        last_two_avg = None
        if len(history.opponent_cooperators) >= 2:
            denom = max(1, n - 1)
            last_two_avg = (int(history.opponent_cooperators[-1]) + int(history.opponent_cooperators[-2])) / (2.0 * denom)
        if last_coop_count == 0:
            if last_two_avg is None or last_two_avg <= 0.5:
                return Action.D
        if S < 0.2 * capacity:
            return Action.C if self.q >= 0.75 else Action.D
        if t == r - 1:
            return Action.C if S >= 0.85 * capacity and self.q >= 0.75 else Action.D
        if not (self.q >= 0.5 and S >= 0.35 * capacity):
            return Action.D
        next_c = self._expected_next_stock(S, cooperate=True)
        next_d = self._expected_next_stock(S, cooperate=False)
        m = r - t + 1
        if m > 2 and next_c >= next_d or (m == 2 and next_c > 0.85 * capacity):
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_8(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Round 1: cooperate
    - Final round: defect
    - Intermediate rounds: threshold-based response to current stock and prior opponent cooperation,
      with extra caution at very low stock and a limited upgrade when stock has risen for two rounds.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self._last_stock = None
        self._prev_stock = None

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        last_round_index = self.n_rounds - 1
        self._prev_stock = self._last_stock
        self._last_stock = float(current_stock)
        if round_number == 0:
            return Action.C
        if round_number >= last_round_index:
            return Action.D
        s = float(current_stock)
        cap = self.capacity
        prev_opp_coop = 0
        if len(history.opponent_cooperators) > 0:
            prev_opp_coop = int(history.opponent_cooperators[-1])
        n_opponents = max(self.n_players - 1, 1)
        p = prev_opp_coop / n_opponents
        decision = Action.D
        if s > cap / 3:
            if s >= 5 * cap / 6 and p >= 2 / 3:
                decision = Action.C
            elif s >= cap / 2 and p >= 1 / 2:
                decision = Action.C
        if s < cap / 6:
            decision = Action.D
        rising_two_rounds = False
        if self._prev_stock is not None and self._last_stock is not None:
            if self._prev_stock is not None:
                if self._prev_stock is not None:
                    rising_two_rounds = self._prev_stock is not None and self._last_stock is not None and (self._prev_stock < self._last_stock)
        if self._prev_stock is not None and self._last_stock is not None:
            pass
        if round_number >= 2 and self._prev_stock is not None:
            rising_two_rounds = False
        if decision == Action.D and s >= cap / 2 and (p >= 1 / 2):
            if self._prev_stock is not None and self._last_stock is not None:
                if self._last_stock >= self._prev_stock:
                    decision = Action.C
        return decision

class Strategy_INDIVIDUALISTIC_9(BaseStrategy):
    """
    Stock-preserving threshold strategy with aggregate reciprocity.

    - Cooperates in the first round only if the initial capacity is sufficiently high.
    - In intermediate rounds, cooperates only when both observed opponent cooperation
      and current stock are at least half of their respective benchmarks.
    - In the last round, cooperates only under full observed cooperation.
    - Defaults to defection when information is missing or the stock is depleted.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.n
        r = self.r
        capacity = self.capacity
        round_number = int(history.round_number)
        if current_stock <= 0:
            return Action.D
        if round_number == 0:
            return Action.C if capacity >= 4 * n else Action.D
        k_t = 0.0
        try:
            last_opponents = history.opponent_cooperators[-1]
            denom = max(n - 1, 1)
            k_t = float(last_opponents) / float(denom)
        except Exception:
            k_t = 0.0
        q_t = float(current_stock) / capacity if capacity > 0 else 0.0
        if round_number >= r - 1:
            return Action.C if k_t == 1.0 else Action.D
        if k_t >= 0.5 and q_t >= 0.5:
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_10(BaseStrategy):
    """
    Start cooperatively, then use stock level and observed opponent cooperation
    to decide whether to keep cooperating or switch to defection to protect the
    common pool.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(0, self.n_players - 1)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        if round_number == 0:
            return Action.C
        if self.capacity <= 0:
            return Action.D
        x = float(current_stock) / self.capacity
        x = max(0.0, min(1.0, x))
        last_opponent_coop = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        if self.n_opponents > 0:
            q = last_opponent_coop / self.n_opponents
        else:
            q = 1.0
        last_my_action = bool(history.my_actions[-1]) if len(history.my_actions) > 0 else True
        last_played_c = last_my_action is True
        if round_number >= self.n_rounds - 1:
            return Action.D if x < 0.5 else Action.C
        if x < 2.0 / max(1, self.n_players):
            return Action.D
        if q < 0.5:
            return Action.D
        if last_played_c and q >= 1.0 and (x >= 0.5):
            return Action.C
        if last_played_c and q <= 0.5:
            return Action.D
        if not last_played_c and x < 1.0 / 3.0:
            return Action.D
        if x >= 0.5:
            return Action.C
        if x >= 1.0 / 3.0:
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_11(BaseStrategy):
    """
    Trust-based common pool strategy:
    - Cooperate initially.
    - Update a smoothed trust score from opponent cooperation.
    - Defect when the pool is depleted, trust is low, majority cooperation is absent,
      the stock has dropped sharply, or in the final round.
    - Once a low-cooperation / low-stock trigger activates the reset rule, keep defecting
      until both cooperation and stock health recover.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.trust = 1.0
        self.defect_lock = False
        self.last_seen_stock = float(game_description.capacity)
        self.last_rho = 1.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = float(self.game_description.capacity)
        round_number = history.round_number
        if round_number == 0:
            self.trust = 1.0
            self.defect_lock = False
            self.last_seen_stock = float(current_stock)
            self.last_rho = 1.0
            return Action.C
        last_opponent_cooperators = int(history.opponent_cooperators[-1]) if round_number > 0 else 0
        if n > 2:
            denom = max(1, n - 1)
            rho = last_opponent_cooperators / denom
        else:
            rho = float(last_opponent_cooperators)
        self.last_rho = rho
        self.trust = 0.6 * self.trust + 0.4 * rho
        stock_ratio = current_stock / capacity if capacity > 0 else 0.0
        if rho < 0.5 or stock_ratio < 0.35:
            self.defect_lock = True
        if self.defect_lock and rho >= 0.5 and (stock_ratio >= 0.5):
            self.defect_lock = False
        next_round = round_number + 1
        if next_round >= r:
            self.last_seen_stock = float(current_stock)
            return Action.D
        if self.defect_lock:
            self.last_seen_stock = float(current_stock)
            return Action.D
        if stock_ratio < 0.35:
            self.defect_lock = True
            self.last_seen_stock = float(current_stock)
            return Action.D
        if self.trust < 0.55:
            self.last_seen_stock = float(current_stock)
            return Action.D
        if last_opponent_cooperators < math.ceil((n - 1) / 2):
            self.defect_lock = True
            self.last_seen_stock = float(current_stock)
            return Action.D
        if self.last_seen_stock - current_stock > 0.15 * capacity:
            self.last_seen_stock = float(current_stock)
            return Action.D
        self.last_seen_stock = float(current_stock)
        return Action.C

class Strategy_INDIVIDUALISTIC_12(BaseStrategy):
    """
    Adaptive self-interested strategy for the Common Pool Resource Game.

    - Cooperates in round 1.
    - Uses the previous round's observed opponent cooperation rate as a forecast.
    - Defects when stock is scarce or when defection has higher expected value.
    - In the final round, cooperates only under favorable stock and cooperation conditions.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = max(2, int(game_description.n_players))
        self.r = max(1, int(game_description.n_rounds))
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(1, self.n - 1)

    def _growth(self, x: float) -> float:
        cap = self.capacity
        if cap <= 0:
            return 0.0
        x = max(0.0, min(float(x), cap))
        return min(x + 2.0 * x * (1.0 - x / cap), cap)

    def _expected_next_stock(self, current_stock: float, q: float, my_action_is_cooperate: bool) -> float:
        n = self.n
        cap = self.capacity
        s = max(0.0, min(float(current_stock), cap))
        q = max(0.0, min(1.0, float(q)))
        other_expected = (n - 1) * (q * (s / (2.0 * n)) + (1.0 - q) * (s / n))
        my_consumption = s / (2.0 * n) if my_action_is_cooperate else s / n
        total_consumption = my_consumption + other_expected
        remaining = max(0.0, s - total_consumption)
        return self._growth(remaining)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number + 1
        s = max(0.0, min(float(current_stock), self.capacity))
        if history.round_number == 0:
            return Action.C
        last_opponents = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        q = last_opponents / self.n_opponents if self.n_opponents > 0 else 0.0
        q = max(0.0, min(1.0, q))
        if s <= self.capacity / 4.0:
            return Action.D
        if t >= self.r:
            if s >= self.capacity / 2.0 and q >= 0.5:
                return Action.C
            return Action.D
        remaining_rounds_after_this = self.r - t
        denom = remaining_rounds_after_this + 1.0
        lam = remaining_rounds_after_this / denom if denom > 0.0 else 0.0
        next_c = self._expected_next_stock(s, q, True)
        next_d = self._expected_next_stock(s, q, False)
        v_c = s / (2.0 * self.n) + lam * next_c
        v_d = s / self.n + lam * next_d
        eps = 1e-12
        if v_d > v_c + eps:
            return Action.D
        if v_c > v_d + eps:
            return Action.C
        return Action.C if s >= self.capacity / 2.0 else Action.D

class Strategy_INDIVIDUALISTIC_13(BaseStrategy):
    """
    Stock-preserving threshold strategy with short-memory retaliation.

    - Cooperates initially to probe sustainability.
    - Continues cooperating only under high observed cooperation and healthy stock.
    - Escalates to defection under depletion, repeated low cooperation, or low stock.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.coop_threshold = 0.7
        self.stock_threshold = 0.75 * self.capacity
        self.depletion_threshold = 0.55 * self.capacity
        self.very_low_stock_threshold = 0.35 * self.capacity
        self.low_coop_threshold = 0.5
        self._eps = 1e-12
        self._last_stock = None
        self._stock_increase_streak = 0
        self._same_stock_streak = 0
        self._last_bad_value = 0

    def _safe_m(self, coop_count: int) -> float:
        denom = max(self.n - 1, 1)
        return float(coop_count) / float(denom)

    def _observed_m_values(self, history: PlayerHistory) -> list[float]:
        vals: list[float] = []
        if history.opponent_cooperators is None:
            return vals
        for x in history.opponent_cooperators.tolist():
            try:
                coop_count = int(x)
                vals.append(self._safe_m(coop_count))
            except Exception:
                vals.append(0.5)
        return vals

    def _compute_avg_m(self, m_values: list[float]) -> float:
        if not m_values:
            return 1.0
        window = m_values[-3:]
        return float(np.mean(np.array(window, dtype=float)))

    def _compute_bad(self, m_values: list[float]) -> int:
        bad = 0
        for m in m_values:
            if m < self.low_coop_threshold:
                bad += 1
            else:
                bad = 0
        return int(bad)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        stock = float(current_stock)
        if self._last_stock is None:
            self._same_stock_streak = 0
            self._stock_increase_streak = 0
        else:
            if abs(stock - self._last_stock) <= self._eps:
                self._same_stock_streak += 1
            else:
                self._same_stock_streak = 0
            if stock > self._last_stock + self._eps:
                self._stock_increase_streak += 1
            else:
                self._stock_increase_streak = 0
        self._last_stock = stock
        if round_number == 0:
            return Action.C
        if self.r <= 1:
            return Action.C
        m_values = self._observed_m_values(history)
        avg_m = self._compute_avg_m(m_values)
        bad = self._compute_bad(m_values)
        if self._same_stock_streak >= 2:
            bad = self._last_bad_value
        self._last_bad_value = bad
        last_m = m_values[-1] if m_values else 1.0
        if round_number == self.r - 1:
            if last_m >= 1.0 - self._eps and stock >= self.stock_threshold:
                return Action.C
            return Action.D
        if stock <= self.very_low_stock_threshold:
            return Action.D
        if stock < self.depletion_threshold:
            if avg_m >= 1.0 - self._eps and self._stock_increase_streak >= 2:
                pass
            else:
                return Action.D
        if stock >= self.stock_threshold and avg_m >= self.coop_threshold and (bad == 0):
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_14(BaseStrategy):
    """
    Conservative common-pool strategy:
    - Cooperate in round 1.
    - In later rounds, react to current stock, opponent cooperation in the previous round,
      and whether the game is nearing the end.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self._cap_third = self.capacity / 3.0
        self._cap_half = self.capacity / 2.0
        self._cap_two_thirds = 2.0 * self.capacity / 3.0
        self._n_opponents = max(self.n - 1, 0)
        self._coop_high = math.ceil(2.0 * self._n_opponents / 3.0)
        self._coop_low = math.floor(self._n_opponents / 3.0)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number
        if t == 0:
            return Action.C
        if len(history.opponent_cooperators) > 0:
            c_prev = int(history.opponent_cooperators[-1])
        else:
            c_prev = 0
        if self._n_opponents <= 0:
            rho = 0.0
        else:
            rho = c_prev / self._n_opponents
        S = float(current_stock)
        if t >= self.r - 1:
            return Action.D if S > self._cap_third else Action.C
        if S <= self._cap_third:
            return Action.C
        if rho >= 2.0 / 3.0 and S >= self._cap_half:
            return Action.D
        if rho <= 1.0 / 3.0:
            return Action.C
        if S >= self._cap_two_thirds:
            return Action.D
        return Action.C

class Strategy_INDIVIDUALISTIC_15(BaseStrategy):
    """
    Defect by default, but cooperate when stock is low or when defection would
    push next stock below a conservation threshold. Updates a smoothed belief
    about opponent cooperation from past rounds.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.alpha = 0.5
        self.initial_p_hat = 0.5

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = int(history.round_number)
        if t == 0:
            return Action.D
        if t >= self.n_rounds - 2:
            return Action.D
        n_opponents = max(self.n_players - 1, 1)
        p_hat = self.initial_p_hat
        if len(history.opponent_cooperators) > 0:
            for c in history.opponent_cooperators:
                q = float(c) / float(n_opponents)
                p_hat = self.alpha * q + (1.0 - self.alpha) * p_hat
        c_last = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        c_last = max(0, min(c_last, n_opponents))
        S = float(current_stock)
        S = max(0.0, min(S, self.capacity))
        T = self.capacity * (0.3 + 0.2 * (1.0 - p_hat))
        opp_cons = c_last * (S / (2.0 * self.n_players)) + (n_opponents - c_last) * (S / self.n_players)
        S_rem_C = S - opp_cons - S / (2.0 * self.n_players)
        S_rem_C = max(0.0, S_rem_C)
        S_next_C = S_rem_C + 2.0 * S_rem_C * (1.0 - S_rem_C / self.capacity)
        S_next_C = min(max(S_next_C, 0.0), self.capacity)
        S_rem_D = S - opp_cons - S / self.n_players
        S_rem_D = max(0.0, S_rem_D)
        S_next_D = S_rem_D + 2.0 * S_rem_D * (1.0 - S_rem_D / self.capacity)
        S_next_D = min(max(S_next_D, 0.0), self.capacity)
        if S <= T:
            return Action.C
        if S_next_D < T and S_next_C >= T:
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_16(BaseStrategy):
    """
    Stock-Guarded Conditional Cooperation:
    - Cooperate in the first round.
    - Cooperate only when the previous round's opponent cooperation rate was at least 50%
      and the current stock is sufficiently viable.
    - Defect immediately in the final round, or whenever cooperation/support is too weak.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self._n_opponents = max(self.n_players - 1, 1)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        t = round_number + 1
        if round_number == 0:
            return Action.C
        if t >= self.n_rounds:
            return Action.D
        last_opponent_cooperators = int(history.opponent_cooperators[-1])
        x = last_opponent_cooperators / self._n_opponents if self._n_opponents > 0 else 0.0
        stock_threshold = 2.0 * self.n_players
        if float(current_stock) < stock_threshold:
            return Action.D
        if x >= 0.5:
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_17(BaseStrategy):
    """
    Conservative tit-for-survival strategy for the Common Pool Resource Game.

    Defaults to cooperation only in the first round.
    Thereafter, cooperates only when the pool is healthy and opponents
    have recently cooperated enough; otherwise defects.
    Tightens cooperation requirements after low opponent cooperation,
    and defects unconditionally if the stock becomes critically low.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.coop_threshold = 0.5
        self.low_stock_lock = False
        self.permanent_defect = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = max(2, int(self.game_description.n_players))
        rounds = max(1, int(self.game_description.n_rounds))
        capacity = float(self.game_description.capacity) if self.game_description.capacity else 1.0
        x_t = current_stock / capacity if capacity > 0 else 0.0
        if x_t < 0.35:
            self.permanent_defect = True
        if x_t < 0.5:
            self.low_stock_lock = True
        if self.low_stock_lock and x_t >= 0.7:
            self.low_stock_lock = False
        if history.round_number == 0:
            return Action.C
        if len(history.opponent_cooperators) > 0:
            n_opponents = max(1, n - 1)
            h_t = int(history.opponent_cooperators[-1])
            q_t = h_t / n_opponents
            if q_t < 0.5:
                self.coop_threshold = max(self.coop_threshold, 0.75)
        current_round = history.round_number + 1
        if current_round >= rounds - 1:
            return Action.D
        if self.permanent_defect:
            return Action.D
        if self.low_stock_lock:
            return Action.D
        if len(history.opponent_cooperators) == 0:
            return Action.D
        n_opponents = max(1, n - 1)
        h_t = int(history.opponent_cooperators[-1])
        q_t = h_t / n_opponents
        if x_t >= 0.7 and q_t >= self.coop_threshold:
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_18(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Cooperate on round 1
    - Defect on the final round
    - Use a stock threshold and opponent cooperation baseline in normal play
    - Escalate to strict defection after repeated low cooperation
    - Switch permanently to defection after two consecutive sharp stock drops
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self._permanent_defect = False
        self._prev_stock = None
        self._low_stock_streak = 0

    def _opponent_coop_rate(self, count: int) -> float:
        n_players = int(self.game_description.n_players)
        n_opponents = max(n_players - 1, 0)
        if n_opponents <= 0:
            return 0.0
        return float(count) / float(n_opponents)

    def _baseline_and_low_streak(self, history: PlayerHistory) -> tuple[float, int]:
        b = 1.0
        m = 0
        n_opponents = max(int(self.game_description.n_players) - 1, 0)
        for c in history.opponent_cooperators:
            q = 0.0 if n_opponents <= 0 else float(c) / float(n_opponents)
            b = 0.8 * b + 0.2 * q
            if q < 0.5:
                m += 1
            else:
                m = 0
        return (b, m)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_players = int(self.game_description.n_players)
        n_rounds = int(self.game_description.n_rounds)
        round_number = int(history.round_number)
        if self._prev_stock is not None:
            prev_stock = float(self._prev_stock)
            threshold_ratio = float(n_players - 1) / float(max(2 * n_players - 1, 1))
            low_now = float(current_stock) < threshold_ratio * prev_stock
            if low_now:
                self._low_stock_streak += 1
            else:
                self._low_stock_streak = 0
            if self._low_stock_streak >= 2:
                self._permanent_defect = True
        if self._permanent_defect:
            self._prev_stock = float(current_stock)
            return Action.D
        if round_number >= n_rounds - 1:
            self._prev_stock = float(current_stock)
            return Action.D
        if round_number == 0:
            self._prev_stock = float(current_stock)
            return Action.C
        baseline, low_streak = self._baseline_and_low_streak(history)
        denom = float(max(2 * n_players - 1, 1))
        theta = float(n_players) / denom * float(current_stock)
        last_count = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        q_prev = self._opponent_coop_rate(last_count)
        if low_streak >= 2:
            action = Action.C if q_prev == 1.0 and float(current_stock) > theta else Action.D
            self._prev_stock = float(current_stock)
            return action
        if float(current_stock) <= theta:
            self._prev_stock = float(current_stock)
            return Action.D
        action = Action.C if q_prev >= baseline else Action.D
        self._prev_stock = float(current_stock)
        return action

class Strategy_INDIVIDUALISTIC_19(BaseStrategy):
    """
    Adaptive common-pool strategy with exploit/preserve modes, low-stock lockout,
    and a one-round cooperative exception under near-perfect cooperation.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_opponents = max(self.n_players - 1, 1)
        self.capacity = float(game_description.capacity)
        self.last_seen_stock = None
        self.last_mode = 'exploit'

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number
        S_t = float(current_stock)
        cap = self.capacity
        if t == 0:
            self.last_seen_stock = S_t
            self.last_mode = 'exploit'
            return Action.D
        if t >= int(self.game_description.n_rounds) - 1:
            self.last_seen_stock = S_t
            self.last_mode = 'exploit'
            return Action.D
        if len(history.opponent_cooperators) > 0:
            k_prev = int(history.opponent_cooperators[-1])
            q_prev = k_prev / self.n_opponents if self.n_opponents > 0 else 0.0
        else:
            q_prev = 0.0
        S_prev = self.last_seen_stock if self.last_seen_stock is not None else S_t
        sharp_fall = S_t < 0.7 * cap or (t > 1 and S_t < S_prev - 0.15 * cap)
        if S_t <= 0.4 * cap:
            action = Action.D
            self.last_mode = 'exploit'
        else:
            if q_prev >= 2.0 / 3.0 and (not sharp_fall):
                self.last_mode = 'preserve'
            else:
                self.last_mode = 'exploit'
            if self.last_mode == 'preserve':
                if S_t >= 0.6 * cap and q_prev >= 2.0 / 3.0:
                    action = Action.C
                else:
                    action = Action.D
            elif S_t >= 0.9 * cap and q_prev == 1.0:
                action = Action.C
            else:
                action = Action.D
        self.last_seen_stock = S_t
        return action

class Strategy_INDIVIDUALISTIC_20(BaseStrategy):
    """
    State-based threshold strategy with momentum and personal-payoff protection
    for the Common Pool Resource Game.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(self.n_players - 1, 0)
        self.high_threshold = 0.75 * self.capacity
        self.medium_threshold = 0.45 * self.capacity
        self.low_threshold = 0.2 * self.capacity
        self.low_payoff_threshold = self.capacity / (4.0 * self.n_players) if self.n_players > 0 else 0.0
        self.high_payoff_threshold = self.capacity / (2.0 * self.n_players) if self.n_players > 0 else 0.0
        self.final_round_low_stock_threshold = self.capacity / (4.0 * self.n_players) if self.n_players > 0 else 0.0

    def _shift_action(self, base_action: Action, selfish_shift: int) -> Action:
        if selfish_shift == 1 and base_action == Action.C:
            return Action.D
        if selfish_shift == -1 and base_action == Action.D:
            return Action.C
        return base_action

    def _average_payoff_so_far(self, history: PlayerHistory) -> float:
        rounds_played = int(history.round_number)
        if rounds_played <= 0:
            return 0.0
        payoffs = history.my_payoffs
        if payoffs is None or len(payoffs) == 0:
            return 0.0
        return float(np.mean(payoffs))

    def _coop_rate_from_history(self, history: PlayerHistory, idx: int) -> float:
        if history.opponent_cooperators is None:
            return 0.0
        if idx < 0 or idx >= len(history.opponent_cooperators):
            return 0.0
        if self.n_opponents <= 0:
            return 0.0
        return float(history.opponent_cooperators[idx]) / float(self.n_opponents)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = int(history.round_number) + 1
        S_t = float(current_stock)
        if t == 1:
            return Action.C
        has_history = history.my_actions is not None and history.my_payoffs is not None and (history.opponent_cooperators is not None) and (len(history.my_actions) > 0) and (len(history.my_payoffs) > 0) and (len(history.opponent_cooperators) > 0)
        if not has_history:
            if t <= (self.n_rounds + 1) // 2:
                return Action.C
            return Action.C if S_t <= self.low_threshold else Action.D
        if t >= self.n_rounds:
            if S_t <= self.final_round_low_stock_threshold:
                return Action.C
            return Action.D
        avg_payoff_so_far = self._average_payoff_so_far(history)
        if avg_payoff_so_far < self.low_payoff_threshold and S_t > self.medium_threshold:
            return Action.D
        if avg_payoff_so_far > self.high_payoff_threshold and S_t < self.high_threshold:
            return Action.C
        if S_t <= self.low_threshold:
            return Action.C
        x_t = self._coop_rate_from_history(history, -1)
        prev_x = self._coop_rate_from_history(history, -2) if len(history.opponent_cooperators) >= 2 else None
        selfish_shift = 0
        if prev_x is not None:
            if x_t <= prev_x - 0.2:
                selfish_shift = 1
            elif x_t >= prev_x + 0.2:
                selfish_shift = -1
        if S_t >= self.high_threshold:
            base_action = Action.C if x_t >= 0.5 else Action.D
        elif S_t >= self.medium_threshold:
            base_action = Action.C if x_t >= 0.75 else Action.D
        else:
            base_action = Action.C if x_t >= 0.9 else Action.D
        action = self._shift_action(base_action, selfish_shift)
        if avg_payoff_so_far < self.low_payoff_threshold and S_t > self.medium_threshold:
            action = Action.D
        elif avg_payoff_so_far > self.high_payoff_threshold and S_t < self.high_threshold:
            action = Action.C
        return action

class Strategy_INDIVIDUALISTIC_21(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - start with one cooperative round,
    - track opponent cooperation with exponential smoothing,
    - protect the pool when stock is low,
    - defect at the end and generally punish weak cooperation when the stock is comfortable.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.q_hat = 1.0
        self.lambda_ = 0.7
        self.reserve = 0.45 * self.capacity
        self.comfort = 0.75 * self.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.n
        r = self.r
        S = float(current_stock)
        round_number = history.round_number
        t = round_number + 1
        if round_number == 0:
            return Action.C
        n_opponents = max(n - 1, 1)
        last_k = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        observed_rate = last_k / n_opponents
        self.q_hat = self.lambda_ * self.q_hat + (1.0 - self.lambda_) * observed_rate
        self.q_hat = max(0.0, min(1.0, self.q_hat))
        m = (n - 1) * self.q_hat
        if n <= 0:
            return Action.D
        cons_C = S / (2.0 * n) * (m + 1.0) + S / n * (n - 1.0 - m)
        cons_D = S / (2.0 * n) * m + S / n * (n - 1.0 - m + 1.0)
        R_C = S - cons_C
        R_D = S - cons_D
        N_C = min(R_C + 2.0 * R_C * (1.0 - R_C / self.capacity), self.capacity)
        N_D = min(R_D + 2.0 * R_D * (1.0 - R_D / self.capacity), self.capacity)
        if t == r:
            return Action.D
        if t == r - 1:
            return Action.D if S > self.reserve else Action.C
        if S <= self.reserve:
            return Action.C
        if S >= self.comfort and self.q_hat < 0.5:
            return Action.D
        if self.q_hat >= 0.5 and N_C > N_D:
            return Action.C
        if self.q_hat >= 0.65:
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_22(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Round 1: defect.
    - Later rounds: defect on the final round, when stock is depleted, or when opponents
      were mostly cooperative; cooperate when stock is low or opponents were mostly defecting.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.last_observed_opponent_cooperators = None

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = float(self.game_description.capacity)
        round_number = history.round_number
        if round_number == 0:
            self.last_observed_opponent_cooperators = None
            return Action.D
        c = 0
        if len(history.opponent_cooperators) > 0:
            c = int(history.opponent_cooperators[-1])
            self.last_observed_opponent_cooperators = c
        elif self.last_observed_opponent_cooperators is not None:
            c = int(self.last_observed_opponent_cooperators)
        if round_number >= max(r - 1, 0):
            return Action.D
        if current_stock <= 1e-12:
            return Action.D
        if current_stock <= capacity / 3.0:
            return Action.C
        threshold = math.ceil((n - 1) / 2.0)
        if c >= threshold:
            return Action.D
        return Action.C

class Strategy_INDIVIDUALISTIC_23(BaseStrategy):
    """
    Common pool strategy:
    - Start with defection.
    - In intermediate rounds, defect by default, but cooperate when defecting would
      collapse the stock below a safety threshold while cooperation preserves it.
    - Defect again in the final round.
    - In the penultimate round, cooperate if the stock is already very low.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        if round_number == 0:
            return Action.D
        if round_number >= self.r - 1:
            return Action.D
        if round_number == self.r - 2 and current_stock < 0.35 * self.capacity:
            return Action.C
        m = 0
        if len(history.opponent_cooperators) > 0:
            m = int(history.opponent_cooperators[-1])
        n = self.n
        S = float(current_stock)
        cap = self.capacity
        remaining_D = S * m / (2.0 * n) if n > 0 else 0.0
        next_D = remaining_D + 2.0 * remaining_D * (1.0 - remaining_D / cap) if cap > 0 else remaining_D
        remaining_C = S * (m + 1) / (2.0 * n) if n > 0 else 0.0
        next_C = remaining_C + 2.0 * remaining_C * (1.0 - remaining_C / cap) if cap > 0 else remaining_C
        if next_D < 0.55 * cap and next_C >= 0.55 * cap:
            return Action.C
        elif S >= 0.85 * cap and m <= (n - 1) / 2:
            return Action.D
        elif m >= math.ceil(3 * (n - 1) / 4) and S >= 0.7 * cap:
            return Action.D
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_24(BaseStrategy):
    """
    Selective preservation strategy for the common pool.

    - Tracks a smoothed estimate of opponent cooperation q_t.
    - Cooperates early when the pool is healthy and opponents look reliable.
    - Defects when stock is low, the horizon is short, or trust deteriorates.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.q_estimate = 1.0
        self.processed_rounds = 0
        self.last_stock_seen = None
        self.high_stock_streak = 0
        self.defect_for_rest = False

    def _update_state_from_history(self, history: PlayerHistory) -> None:
        total_rounds = history.round_number
        n_opponents = max(self.n_players - 1, 1)
        start = self.processed_rounds
        if start < 0:
            start = 0
        if start > total_rounds:
            start = total_rounds
        for idx in range(start, total_rounds):
            k_t = int(history.opponent_cooperators[idx])
            coop_share = k_t / n_opponents
            self.q_estimate = 2.0 / 3.0 * self.q_estimate + 1.0 / 3.0 * coop_share
            if coop_share < 0.5:
                self.q_estimate = min(self.q_estimate, 0.5)
        self.processed_rounds = total_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        self._update_state_from_history(history)
        t = history.round_number + 1
        S = float(current_stock)
        cap = self.capacity
        r = self.n_rounds
        if self.last_stock_seen is not None and self.last_stock_seen > 0.9 * cap and (S > 0.9 * cap):
            self.high_stock_streak += 1
        else:
            self.high_stock_streak = 1 if S > 0.9 * cap else 0
        self.last_stock_seen = S
        if S < 0.4 * cap:
            self.defect_for_rest = True
        if self.defect_for_rest:
            return Action.D
        if S <= 0.0:
            return Action.D
        if t >= r:
            return Action.D
        if history.round_number == 0:
            return Action.C if cap >= 3.0 * self.n_players else Action.D
        q_t = self.q_estimate
        allow_late_coop = self.high_stock_streak >= 2 and q_t >= 0.7
        if t == r - 1:
            if S >= 0.85 * cap and q_t >= 0.75:
                return Action.C
            return Action.D
        if t <= r - 2:
            in_time_window = t <= math.floor(0.8 * r)
            if S >= 0.7 * cap and q_t >= 0.6 and (in_time_window or allow_late_coop):
                return Action.C
            return Action.D
        return Action.D

class Strategy_INDIVIDUALISTIC_25(BaseStrategy):
    """
    Start with defection. In later rounds, estimate whether cooperation is
    needed to keep the common stock above a reserve threshold, based on the
    previous round's observed opponent cooperation and predicted next stocks.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(self.n_players - 1, 1)
        self.reserve = self.capacity / 2.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.D
        S = float(current_stock)
        if S <= 0.0:
            return Action.D
        last_opp_coop = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        last_opp_coop = max(0, min(last_opp_coop, self.n_opponents))
        q = last_opp_coop / self.n_opponents if self.n_opponents > 0 else 0.0
        if last_opp_coop == 0:
            return Action.D
        t = history.round_number + 1
        if t >= self.n_rounds:
            return Action.D
        c = q * self.n_opponents
        denom = 2.0 * self.n_players

        def next_stock(x: float) -> float:
            x = max(0.0, min(float(x), self.capacity))
            growth = 2.0 * x * (1.0 - x / self.capacity) if self.capacity > 0.0 else 0.0
            return min(x + growth, self.capacity)
        S_D = next_stock(S * c / denom)
        S_C = next_stock(S * (c + 1.0) / denom)
        if S == 0.0:
            return Action.D
        if q >= 0.5 and S_C >= self.reserve and (S_D < self.reserve or S_C > S_D):
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_26(BaseStrategy):
    """
    Conditional cooperation strategy for the common pool resource game.

    - Starts by cooperating.
    - Cooperates only when the stock is healthy and opponents are sustaining it.
    - Defects under depletion, low cooperation, or late-game uncertainty.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self._last_stock: float | None = None

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_players = max(2, int(self.game_description.n_players))
        n_rounds = max(1, int(self.game_description.n_rounds))
        capacity = float(self.game_description.capacity)
        if history.round_number == 0:
            self._last_stock = float(current_stock)
            return Action.C
        n_opponents = max(1, n_players - 1)
        prev_opponents = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        q = prev_opponents / n_opponents
        q_bar = 1.0
        if len(history.opponent_cooperators) > 0:
            for k in history.opponent_cooperators:
                q_t = int(k) / n_opponents
                q_bar = 0.7 * q_bar + 0.3 * q_t
        stock_increased = False
        if self._last_stock is not None:
            stock_increased = float(current_stock) > float(self._last_stock)
        self._last_stock = float(current_stock)
        if history.round_number >= n_rounds - 2:
            if current_stock >= 0.7 * capacity and q == 1.0:
                return Action.C
            return Action.D
        if current_stock < 0.4 * capacity or q <= 0.25:
            return Action.D
        if stock_increased and q >= 0.5:
            return Action.C
        if current_stock >= 0.6 * capacity and q >= 0.5 and (q_bar >= 0.5):
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_27(BaseStrategy):
    """
    Start cooperative, continue cooperating only under healthy stock and sustained
    high opponent cooperation, and defect in the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.m = max(self.n - 1, 0)
        self.high = math.ceil(2 * self.m / 3) if self.m > 0 else 0
        self.low_stock = self.capacity / 3.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number + 1
        if current_stock <= 0:
            return Action.D
        if t >= self.r:
            return Action.D
        if t == 1:
            return Action.C
        if current_stock < self.low_stock:
            return Action.D
        if self.m <= 0:
            return Action.D
        k = int(history.opponent_cooperators[-1]) if history.round_number > 0 else 0
        k_prev = int(history.opponent_cooperators[-2]) if history.round_number > 1 else None
        if k < self.high:
            return Action.D
        if t == 2:
            return Action.C
        if k_prev is not None and k_prev >= k:
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_28(BaseStrategy):
    """
    Hysteresis-based common-pool strategy:
    - Start cooperatively.
    - Use persistent selfish/cooperative mode updated from the previous round's
      opponent cooperation rate and current stock.
    - Defect in terminal or unrecoverable situations.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.capacity = float(game_description.capacity)
        self.n_players = int(game_description.n_players)
        self.n_opponents = max(0, self.n_players - 1)
        self.n_rounds = int(game_description.n_rounds)
        self.mode = 'selfish'

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        stock = float(current_stock)
        if round_number == 0:
            self.mode = 'selfish'
            return Action.C
        remaining_rounds = self.n_rounds - round_number
        if stock <= 0.0:
            self.mode = 'selfish'
            return Action.D
        if remaining_rounds <= 1:
            self.mode = 'selfish'
            return Action.D
        prev_count = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        if self.n_opponents > 0:
            q_prev = prev_count / self.n_opponents
        else:
            q_prev = 0.0
        if q_prev == 0.0 or stock < 0.25 * self.capacity:
            self.mode = 'selfish'
        no_recovery_practical = remaining_rounds <= 2 or stock < 0.35 * self.capacity
        if no_recovery_practical and (not (q_prev == 1.0 and stock >= 0.9 * self.capacity)):
            self.mode = 'selfish'
            return Action.D
        if self.mode == 'selfish':
            if q_prev >= 0.8 and stock >= 0.75 * self.capacity:
                self.mode = 'cooperative'
        elif not (q_prev >= 0.6 and stock >= 0.6 * self.capacity):
            self.mode = 'selfish'
        if q_prev == 1.0 and stock >= 0.9 * self.capacity:
            self.mode = 'cooperative'
            return Action.C
        return Action.C if self.mode == 'cooperative' else Action.D

class Strategy_INDIVIDUALISTIC_29(BaseStrategy):
    """
    Cautious common-pool strategy:
    - Cooperate on the first round to probe.
    - Defect on the final round.
    - Otherwise, cooperate only when the pool looks healthy and the previous round
      showed strong cooperation.
    - Enter a defect mode after any non-unanimous round and only exit after two
      consecutive unanimous cooperation observations.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self._defect_mode = False
        self._unanimous_streak = 0
        self._last_processed_round = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = int(self.game_description.n_players)
        r = int(self.game_description.n_rounds)
        capacity = float(self.game_description.capacity)
        round_number = int(history.round_number)
        if current_stock <= 1e-12:
            return Action.D
        if round_number == 0:
            return Action.C
        if round_number >= r - 1:
            return Action.D
        start_idx = min(self._last_processed_round, round_number)
        for idx in range(start_idx, round_number):
            c_obs = int(history.opponent_cooperators[idx]) if idx < len(history.opponent_cooperators) else 0
            if c_obs >= n - 1:
                self._unanimous_streak += 1
            else:
                self._unanimous_streak = 0
                self._defect_mode = True
            if self._unanimous_streak >= 2:
                self._defect_mode = False
        self._last_processed_round = round_number
        if self._defect_mode and self._unanimous_streak < 2:
            return Action.D
        c = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        if c == n - 1 and current_stock >= capacity / 2.0:
            return Action.C
        threshold = math.ceil(2.0 * (n - 1) / 3.0)
        if c >= threshold and current_stock >= 3.0 * capacity / 5.0:
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_30(BaseStrategy):
    """
    Stock-aware conditional cooperator with last-round defection and hysteresis.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(self.n_players - 1, 1)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        if round_number == 0:
            return Action.C
        if round_number >= self.n_rounds - 1:
            return Action.D
        last_opp_coop = int(history.opponent_cooperators[-1]) if round_number >= 1 else 0
        q = last_opp_coop / self.n_opponents if self.n_opponents > 0 else 0.0
        prev_q = None
        if round_number >= 2:
            prev_opp_coop = int(history.opponent_cooperators[-2])
            prev_q = prev_opp_coop / self.n_opponents if self.n_opponents > 0 else 0.0
        low_zone_threshold = self.capacity / 3.0
        high_zone_threshold = 2.0 * self.capacity / 3.0
        half_capacity = self.capacity / 2.0
        if prev_q is not None and prev_q <= 1.0 / 3.0 and (q <= 1.0 / 3.0):
            return Action.C if q >= 1.0 / 2.0 else Action.D
        if q == 1.0 and current_stock >= half_capacity and (current_stock < high_zone_threshold):
            return Action.C
        if current_stock <= low_zone_threshold:
            return Action.C if q >= 1.0 / 2.0 else Action.D
        if current_stock < high_zone_threshold:
            return Action.C if q >= 2.0 / 3.0 else Action.D
        return Action.D

class Strategy_INDIVIDUALISTIC_31(BaseStrategy):
    """
    Conservative, state-aware common-pool strategy:
    - Cooperates in round 1.
    - Defects at low stock, in the final round, or after repeated stock declines.
    - Cooperates only when recent opponent cooperation is strong enough,
      with stricter thresholds as stock falls.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(self.n - 1, 0)
        self.half_others_ceil = math.ceil(self.n_opponents / 2) if self.n_opponents > 0 else 0
        self.half_players_ceil = math.ceil(self.n / 2)
        self.near_zero_threshold = 1e-09
        self.near_capacity_threshold = 0.95 * self.capacity
        self.prev_stock = None
        self.prev_prev_stock = None
        self.last_my_action = None

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        stock = float(current_stock)
        round_number = int(history.round_number)
        rounds_remaining = max(self.r - round_number, 0)
        if round_number == 0:
            self.prev_prev_stock = self.prev_stock
            self.prev_stock = stock
            self.last_my_action = True
            return Action.C
        m = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        my_last_coop = bool(history.my_actions[-1]) if len(history.my_actions) > 0 else False
        k_prev = m + (1 if my_last_coop else 0)
        prev_unanimous_coop = m == self.n_opponents and my_last_coop
        stock_fell_two_rounds = self.prev_prev_stock is not None and self.prev_stock is not None and (stock < self.prev_stock) and (self.prev_stock < self.prev_prev_stock)
        if rounds_remaining <= 1:
            self.prev_prev_stock = self.prev_stock
            self.prev_stock = stock
            self.last_my_action = False
            return Action.D
        if stock <= self.near_zero_threshold:
            self.prev_prev_stock = self.prev_stock
            self.prev_stock = stock
            self.last_my_action = False
            return Action.D
        if stock_fell_two_rounds and (not prev_unanimous_coop):
            self.prev_prev_stock = self.prev_stock
            self.prev_stock = stock
            self.last_my_action = False
            return Action.D
        if rounds_remaining == 2:
            should_cooperate = m == self.n_opponents and k_prev == self.n and (stock <= 0.4 * self.capacity)
            self.prev_prev_stock = self.prev_stock
            self.prev_stock = stock
            self.last_my_action = should_cooperate
            return Action.C if should_cooperate else Action.D
        if stock >= 0.6 * self.capacity:
            should_cooperate = m >= self.half_others_ceil and k_prev >= self.half_players_ceil
        elif stock >= 0.2 * self.capacity:
            should_cooperate = m >= self.half_others_ceil + 1
        else:
            should_cooperate = m == self.n_opponents
        if stock >= self.near_capacity_threshold and (not should_cooperate):
            action = Action.D
        else:
            action = Action.C if should_cooperate else Action.D
        self.prev_prev_stock = self.prev_stock
        self.prev_stock = stock
        self.last_my_action = action == Action.C
        return action

class Strategy_INDIVIDUALISTIC_32(BaseStrategy):
    """
    Conservative common-pool strategy:
    - Cooperate in the first round.
    - Defect in the final rounds.
    - Otherwise cooperate only when opponent cooperation and stock level
      indicate the pool is being sustained, with a small tolerance for
      a single isolated bad round under strong cooperation.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        n = self.n_players
        total_rounds = self.n_rounds
        if round_number == 0:
            return Action.C
        next_round_index = round_number
        if next_round_index >= total_rounds - 1:
            return Action.D
        if self.capacity <= 0:
            p = 0.0
        else:
            p = float(current_stock) / self.capacity
        last_opponent_cooperators = int(history.opponent_cooperators[-1])
        n_opponents = max(n - 1, 0)
        q = last_opponent_cooperators / n_opponents if n_opponents > 0 else 0.0
        good_streak = 0
        bad_streak = 0
        for idx in range(round_number - 1, -1, -1):
            opp = int(history.opponent_cooperators[idx])
            q_prev = opp / n_opponents if n_opponents > 0 else 0.0
            if q_prev >= 0.5:
                if bad_streak > 0:
                    break
                good_streak += 1
            else:
                if good_streak > 0:
                    break
                bad_streak += 1
        if n == 2:
            if q >= 0.5 and p >= 0.4 and (bad_streak == 0):
                return Action.C
            return Action.D
        if bad_streak >= 2:
            return Action.D
        if p < 0.4:
            return Action.D
        if q >= 2.0 / 3.0 and p >= 0.6 and (bad_streak <= 1):
            return Action.C
        if q >= 0.5 and p >= 0.4 and (bad_streak == 0):
            return Action.C
        return Action.D


class Strategy_COLLECTIVE_33(BaseStrategy):
    """
    Cooperative default strategy with adaptive target tracking,
    temporary restraint after broad defection, and a preference
    for returning to cooperation as soon as conditions recover.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(0, self.n_players - 1)
        self.target = 1.0
        self.bad_streak = 0

    @staticmethod
    def _clamp(x: float, lo: float, hi: float) -> float:
        return lo if x < lo else hi if x > hi else x

    def _opponent_cooperation_rate(self, cooperating_opponents: int) -> float:
        if self.n_opponents <= 0:
            return 1.0
        return float(cooperating_opponents) / float(self.n_opponents)

    def _reconstruct_state(self, history: PlayerHistory) -> tuple[float, int]:
        target = 1.0
        bad_streak = 0
        for k in history.opponent_cooperators:
            q = self._opponent_cooperation_rate(int(k))
            target = self._clamp(0.7 * target + 0.3 * q, 0.0, 1.0)
            if q <= 0.4:
                bad_streak += 1
            else:
                bad_streak = 0
        return (target, bad_streak)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        if round_number == 0:
            self.target = 1.0
            self.bad_streak = 0
            return Action.C
        self.target, self.bad_streak = self._reconstruct_state(history)
        q_last = self._opponent_cooperation_rate(int(history.opponent_cooperators[-1]))
        q_prev = self._opponent_cooperation_rate(int(history.opponent_cooperators[-2])) if round_number >= 2 else 1.0
        T = self.target
        S = float(current_stock)
        cap = self.capacity
        if round_number >= 2:
            last_two_high = q_last >= 0.8 and q_prev >= 0.8
        else:
            last_two_high = False
        if round_number == self.n_rounds - 1:
            return Action.C if q_last >= T else Action.D
        if self.bad_streak >= 1:
            if q_last >= 0.6 and S >= cap / 2.0:
                return Action.C
            return Action.D
        if last_two_high:
            return Action.C if S >= cap / 4.0 else Action.D
        if S >= cap / 2.0:
            return Action.C if q_last >= T else Action.D
        if S >= cap / 3.0:
            threshold = min(1.0, T + 0.25)
            return Action.C if q_last >= threshold else Action.D
        return Action.C if q_last == 1.0 and S >= cap / 4.0 else Action.D

class Strategy_COLLECTIVE_34(BaseStrategy):
    """
    Cooperative-by-default strategy with a repair mode:
    - Cooperate initially.
    - Keep cooperating while the previous round met the cooperation standard.
    - Switch to repair after a failed standard and defect until two consecutive
      standard-holding rounds have been observed.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.mode = 'NORMAL'
        self.good_streak = 0
        self._eps = 1e-12
        n_players = max(2, int(game_description.n_players))
        self._threshold = math.ceil(2 * (n_players - 1) / 3)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        last_round = round_number >= self.game_description.n_rounds - 1
        if round_number == 0:
            self.mode = 'NORMAL'
            self.good_streak = 0
            return Action.C
        if current_stock <= self._eps:
            self.mode = 'REPAIR'
            self.good_streak = 0
            return Action.D
        opponent_cooperators = 0
        if len(history.opponent_cooperators) > 0:
            opponent_cooperators = int(history.opponent_cooperators[-1])
        capacity = float(self.game_description.capacity)
        healthy_stock = current_stock >= capacity
        stock_ok = healthy_stock or current_stock >= capacity / 2.0
        standard_holds = opponent_cooperators >= self._threshold and stock_ok
        if standard_holds:
            self.good_streak += 1
        else:
            self.good_streak = 0
        if self.good_streak >= 2:
            self.mode = 'NORMAL'
        elif not standard_holds:
            self.mode = 'REPAIR'
        if last_round:
            if self.mode == 'NORMAL':
                return Action.C
            return Action.C if standard_holds else Action.D
        if self.mode == 'NORMAL':
            return Action.C if standard_holds else Action.D
        return Action.C if self.good_streak >= 2 else Action.D

class Strategy_COLLECTIVE_35(BaseStrategy):
    """
    Collective Stewardship Strategy:
    - Cooperate by default when the stock is healthy.
    - Defect when the stock is low or the group has recently under-cooperated.
    - Use recent opponent cooperation to resolve the middle band.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(self.n_players - 1, 1)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        capacity = self.capacity if self.capacity > 0 else 1.0
        x = float(current_stock) / capacity
        previous_p = None
        if round_number > 0 and len(history.opponent_cooperators) > 0:
            prev_k = float(history.opponent_cooperators[-1])
            previous_p = prev_k / self.n_opponents if self.n_opponents > 0 else 0.0
        if round_number == 0:
            action = Action.C
        elif round_number == self.n_rounds - 1:
            action = Action.C if x >= 0.45 else Action.D
        else:
            if x >= 0.55:
                action = Action.C
            elif x < 0.45:
                action = Action.D
            elif round_number > 0 and previous_p is not None and (previous_p >= 0.6):
                action = Action.C
            else:
                action = Action.D
            if previous_p is not None and previous_p <= 0.25 and (x < 0.55):
                action = Action.D
            if previous_p is not None and previous_p >= 0.75 and (x >= 0.45):
                action = Action.C
        if action not in (Action.C, Action.D):
            action = Action.C
        return action

class Strategy_COLLECTIVE_36(BaseStrategy):
    """
    Cooperative default strategy with adaptive defection when observed cooperation
    falls below a stock-dependent safe band.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self._last_stock = float(game_description.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = int(self.game_description.n_players)
        capacity = float(self.game_description.capacity)
        round_number = int(history.round_number)
        stock = float(current_stock)
        self._last_stock = stock
        if stock <= 0.0:
            return Action.D
        if stock >= capacity:
            return Action.C
        if round_number == 0:
            return Action.C
        if round_number >= int(self.game_description.n_rounds) - 1:
            return Action.C if stock > 0.0 else Action.D
        n_opponents = max(0, n - 1)
        if n_opponents <= 0:
            x = 1.0
        else:
            last_k = int(history.opponent_cooperators[-1])
            if last_k < 0:
                last_k = 0
            elif last_k > n_opponents:
                last_k = n_opponents
            x = last_k / n_opponents
        t_high = 0.5
        if capacity > 0.0:
            t_low = max(0.0, 0.5 - stock / capacity / 4.0)
        else:
            t_low = 0.5
        prev_stock = float(self._last_stock)
        sharp_drop = prev_stock > 0.0 and stock < 0.75 * prev_stock
        if sharp_drop:
            t_high = min(1.0, t_high + 0.125)
            t_low = min(t_high, t_low + 0.125)
        prev_action = bool(history.my_actions[-1])
        if n_opponents > 0 and int(history.opponent_cooperators[-1]) == n_opponents:
            if stock >= capacity / 2.0:
                return Action.C
            if x >= 1.0:
                return Action.C
            return Action.D
        if n_opponents > 0 and int(history.opponent_cooperators[-1]) == 0:
            return Action.C if x > t_high else Action.D
        if x >= t_high:
            return Action.C
        if x <= t_low:
            return Action.D
        return Action.C if prev_action else Action.D

class Strategy_COLLECTIVE_37(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Starts by cooperating.
    - Uses observed cooperation rate from the previous round.
    - Cooperates in the final two rounds.
    - Becomes more cooperative when stock is low or cooperation is high.
    - Can lock into defection after repeated low cooperation, and into cooperation after repeated high cooperation.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        rounds_played = int(history.round_number)
        if rounds_played == 0:
            return Action.C
        if current_stock <= 0.0:
            return Action.C
        if rounds_played >= max(0, self.n_rounds - 2):
            return Action.C
        last_opponents = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        last_my_action_c = bool(history.my_actions[-1]) if len(history.my_actions) > 0 else True
        n_opponents = max(0, self.n_players - 1)
        if n_opponents <= 0:
            q = 1.0
        else:
            m_last = last_opponents + (1 if last_my_action_c else 0)
            q = m_last / self.n_players
        low_coop_recent = False
        high_coop_recent = False
        if rounds_played >= 2:
            prev1_op = int(history.opponent_cooperators[-1])
            prev1_my_c = bool(history.my_actions[-1])
            prev2_op = int(history.opponent_cooperators[-2])
            prev2_my_c = bool(history.my_actions[-2])
            q1 = (prev1_op + (1 if prev1_my_c else 0)) / self.n_players
            q2 = (prev2_op + (1 if prev2_my_c else 0)) / self.n_players
            low_coop_recent = q1 <= 0.5 and q2 <= 0.5
            high_coop_recent = q1 >= 0.75 and q2 >= 0.75
        if high_coop_recent:
            return Action.C
        if low_coop_recent:
            return Action.D
        if current_stock <= self.capacity / 3.0:
            return Action.C
        elif q >= 0.75:
            return Action.C
        elif q <= 0.5 and current_stock >= 2.0 * self.capacity / 3.0:
            return Action.D
        elif current_stock <= self.capacity / 2.0:
            return Action.C
        else:
            return Action.D

class Strategy_COLLECTIVE_38(BaseStrategy):
    """
    Stock-preserving threshold strategy for the common pool resource game.

    Cooperates by default, continues cooperating when observed cooperation is
    sufficient to protect the pool, and defects defensively when cooperation
    collapses or stock is too low.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(0, self.n_players - 1)
        self.sustainable_stock_threshold = min(self.capacity, 2.0 * self.n_players)

    def _k_min(self, stock: float) -> int:
        """
        Minimum number of cooperating opponents needed for the round to be
        stock-preserving under the described threshold rule.

        Falls back safely for edge cases.
        """
        if stock <= 0.0:
            return self.n_opponents + 1
        raw = (self.n_players - 2.0) / 2.0 + self.n_players / 2.0 * (1.0 - 2.0 / stock)
        k_min = int(math.ceil(raw))
        if k_min < 0:
            return 0
        if k_min > self.n_opponents:
            return self.n_opponents + 1
        return k_min

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        if round_number == 0:
            return Action.C
        if current_stock <= 0.0:
            return Action.D
        opponent_coops = history.opponent_cooperators
        last_coops = int(opponent_coops[-1]) if len(opponent_coops) > 0 else 0
        prev_coops = int(opponent_coops[-2]) if len(opponent_coops) > 1 else last_coops
        k_min = self._k_min(current_stock)
        threshold_met = last_coops >= k_min
        fallback_threshold = int(math.ceil((self.n_players - 1) / 2.0))
        fallback_met = last_coops >= fallback_threshold
        stock_ok = current_stock >= self.sustainable_stock_threshold
        if round_number == self.n_rounds - 1:
            if (threshold_met or fallback_met) and stock_ok:
                return Action.C
            return Action.D
        if (threshold_met or fallback_met) and stock_ok:
            return Action.C
        if last_coops > prev_coops and current_stock > 0.0:
            return Action.C
        return Action.D

class Strategy_COLLECTIVE_39(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Starts with cooperation.
    - Rewards high cooperation immediately.
    - Defends against low cooperation and depletion.
    - Uses stock-state overrides near capacity and scarcity.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.quorum = max(self.n - 1, 0)
        self.near_quorum = max(self.n - 2, 0)
        self.low = math.floor((self.n - 1) / 2)
        self.prev_stock = self.capacity
        self.prev_prev_stock = self.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = int(history.round_number)
        stock = float(current_stock)
        if not math.isfinite(stock):
            stock = 0.0
        if stock < 0.0:
            stock = 0.0
        if t == 0:
            self.prev_prev_stock = self.prev_stock
            self.prev_stock = stock
            return Action.C
        c_prev = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        c_prev = max(0, min(c_prev, self.n - 1))
        if t == self.r - 1:
            action = Action.C if c_prev >= self.low + 1 else Action.D
        elif t == self.r - 2:
            action = Action.C if c_prev >= self.near_quorum else Action.D
        elif stock <= 0.0:
            action = Action.D
        elif stock >= self.capacity:
            action = Action.D if c_prev == 0 else Action.C
        elif c_prev == 0:
            action = Action.D
        elif c_prev == self.quorum:
            action = Action.C
        elif stock < self.capacity / 2.0:
            action = Action.C if c_prev >= self.near_quorum else Action.D
        elif c_prev >= self.near_quorum:
            action = Action.C
        elif c_prev <= self.low:
            action = Action.D
        else:
            action = Action.C if stock >= self.prev_prev_stock else Action.D
        self.prev_prev_stock = self.prev_stock
        self.prev_stock = stock
        return action

class Strategy_COLLECTIVE_40(BaseStrategy):
    """
    Cooperative baseline with a short defensive reset when opponents repeatedly
    overuse the common pool or when stock becomes critically low.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_opponents = max(0, self.n_players - 1)
        self.capacity = float(game_description.capacity)
        self._half_opponents_threshold = math.ceil(self.n_opponents / 2) if self.n_opponents > 0 else 0
        self._recovery_threshold = math.ceil(2 * self.n_opponents / 3) if self.n_opponents > 0 else 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        stock = float(current_stock)
        if round_number == 0:
            return Action.C
        opp = history.opponent_cooperators
        if len(opp) > 0:
            last_k = int(opp[-1])
        else:
            last_k = 0
        window_size = min(3, len(opp))
        if window_size > 0:
            recent = opp[-window_size:]
            m_t = float(np.mean(recent))
        else:
            m_t = float(self.n_opponents)
        bad_t = 0
        for idx in range(len(opp) - 1, -1, -1):
            if int(opp[idx]) < self._half_opponents_threshold:
                bad_t += 1
            else:
                break
        low_stock = stock < self.capacity / 8.0 if self.capacity > 0 else False
        healthy_stock = stock >= self.capacity / 4.0 if self.capacity > 0 else True
        recovery_stock = stock >= self.capacity / 3.0 if self.capacity > 0 else True
        if round_number >= int(self.game_description.n_rounds) - 1:
            return Action.C if stock >= self.capacity / 8.0 else Action.D
        if low_stock:
            return Action.D
        if len(opp) > 0 and last_k >= self._recovery_threshold:
            return Action.C
        if bad_t >= 2:
            return Action.D
        if healthy_stock and m_t >= self.n_opponents / 2.0:
            return Action.C
        if recovery_stock:
            return Action.C
        return Action.D

class Strategy_COLLECTIVE_41(BaseStrategy):
    """
    Default-cooperation strategy with temporary defection under sustained free-riding.
    Cooperates when the pool is stressed or when cooperation is healthy; defects only
    when recent opponent cooperation has collapsed and the pool is not in recovery.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_opponents = max(0, self.n_players - 1)
        self.capacity = float(game_description.capacity)
        self.recovery_threshold = 1.0 / 3.0
        self.high_cooperation_threshold = 2.0 / 3.0
        self.moderate_cooperation_threshold = 1.0 / 2.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if self.capacity <= 0.0:
            return Action.C
        s = float(current_stock) / self.capacity
        if s <= self.recovery_threshold:
            return Action.C
        opp_counts = history.opponent_cooperators
        if len(opp_counts) == 0:
            return Action.C
        latest_count = float(opp_counts[-1])
        rho = latest_count / self.n_opponents if self.n_opponents > 0 else 0.0
        rho_bar = None
        if len(opp_counts) >= 2 and self.n_opponents > 0:
            rho_prev = float(opp_counts[-2]) / self.n_opponents
            rho_bar = 0.5 * (rho + rho_prev)
        if len(opp_counts) >= 2:
            rho_prev_raw = float(opp_counts[-2]) / self.n_opponents if self.n_opponents > 0 else 0.0
            if rho <= self.recovery_threshold and rho_prev_raw <= self.recovery_threshold and (s > self.recovery_threshold):
                return Action.D
        if rho >= self.high_cooperation_threshold:
            return Action.C
        if rho_bar is not None and rho_bar >= self.moderate_cooperation_threshold:
            return Action.C
        if rho <= self.recovery_threshold and s > self.recovery_threshold:
            return Action.D
        return Action.C

class Strategy_COLLECTIVE_42(BaseStrategy):
    """
    Common-pool strategy that cooperates early, matches sustainable group behavior,
    and applies temporary retaliation or stock-preservation lockouts after overuse.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.forced_defect_rounds = 0
        self.low_stock_lock = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.n_players
        cap = self.capacity
        if history.round_number == 0:
            return Action.C
        if current_stock <= 0:
            return Action.D
        last_opponent_cooperators = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        last_my_action = bool(history.my_actions[-1]) if len(history.my_actions) > 0 else True
        total_cooperators = last_opponent_cooperators + (1 if last_my_action else 0)
        cooperation_rate = total_cooperators / n if n > 0 else 0.0
        depletion_ratio = current_stock / cap if cap > 0 else 0.0
        if current_stock < 0.2 * cap:
            self.low_stock_lock = True
        elif self.low_stock_lock and current_stock >= 0.4 * cap and (cooperation_rate >= 0.75):
            self.low_stock_lock = False
        if self.low_stock_lock:
            return Action.D
        if cooperation_rate >= 0.75:
            self.forced_defect_rounds = 0
        elif cooperation_rate < 0.6:
            self.forced_defect_rounds = max(self.forced_defect_rounds, 2)
        if self.forced_defect_rounds > 0:
            self.forced_defect_rounds -= 1
            return Action.D
        if history.round_number == self.n_rounds - 1:
            if cooperation_rate >= 0.75 and depletion_ratio >= 0.5:
                return Action.C
            return Action.D
        if current_stock >= cap and cooperation_rate >= 0.75:
            return Action.C
        if cooperation_rate >= 0.75 and depletion_ratio >= 0.35:
            return Action.C
        return Action.D

class Strategy_COLLECTIVE_43(BaseStrategy):
    """
    State-contingent quota rule with collective memory:
    - Cooperate by default.
    - Defect only after weak recent cooperation and only when stock is still high.
    - Use a short correction mode after repeated severe-defection patterns.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.m = max(0, self.n - 1)
        self.safe_cooperators = math.ceil(self.m / 2)
        self.unsafe_defection_level = math.floor(self.m / 2) + 1
        self._seen_rounds = 0
        self._correction_rounds_remaining = 0

    def _sync_memory(self, history: PlayerHistory) -> None:
        """
        Update internal state to match any newly observed rounds in history.
        """
        total_rounds = history.round_number
        if total_rounds <= self._seen_rounds:
            return
        opp = history.opponent_cooperators
        for idx in range(self._seen_rounds, total_rounds):
            if idx >= 1:
                prev_low = opp[idx - 1] < self.safe_cooperators
                curr_low = opp[idx] < self.safe_cooperators
                if prev_low and curr_low:
                    self._correction_rounds_remaining = 2
            if self._correction_rounds_remaining > 0:
                self._correction_rounds_remaining -= 1
        self._seen_rounds = total_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        self._sync_memory(history)
        round_number = history.round_number
        current_round = round_number + 1
        if round_number == 0:
            return Action.C
        c_prev = int(history.opponent_cooperators[-1])
        capacity_half = self.capacity / 2.0
        stock_threshold = 2.0 * self.n
        if current_round == self.r:
            if current_stock > capacity_half and c_prev >= self.safe_cooperators:
                return Action.D
            return Action.C
        if self._correction_rounds_remaining > 0:
            return Action.C
        if current_stock <= stock_threshold:
            return Action.C if c_prev >= self.safe_cooperators else Action.D
        if c_prev == 0:
            return Action.D
        return Action.C

class Strategy_COLLECTIVE_44(BaseStrategy):
    """
    Adaptive common-pool strategy with three modes:
    build, guard, and repair.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.mode = 'build'
        self.repair_consecutive = 0
        self.last_seen_round = -1
        self.last_stock = None

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = int(getattr(self.game_description, 'n_players', 2) or 2)
        capacity = float(getattr(self.game_description, 'capacity', 0.0) or 0.0)
        n_opponents = max(n - 1, 0)

        def safe_k() -> int:
            try:
                if history.round_number <= 0:
                    return 0
                arr = history.opponent_cooperators
                if arr is None or len(arr) == 0:
                    return 0
                k = int(arr[-1])
                if k < 0 or k > n_opponents:
                    return 0
                return k
            except Exception:
                return 0

        def safe_prev_k() -> int:
            try:
                if history.round_number < 2:
                    return 0
                arr = history.opponent_cooperators
                if arr is None or len(arr) < 2:
                    return 0
                k = int(arr[-2])
                if k < 0 or k > n_opponents:
                    return 0
                return k
            except Exception:
                return 0

        def coop_threshold_build(k: int, s: float) -> bool:
            if n <= 2:
                return k >= 1
            return k >= max(n - 2, 0) and s >= 0.8 * capacity

        def coop_threshold_guard(k: int, s: float) -> bool:
            if n <= 2:
                return k >= 1 and s >= self.last_stock if self.last_stock is not None else k >= 1
            return k >= max(n - 1, 0) and s >= 0.7 * capacity

        def repair_recovery(k: int, s: float) -> bool:
            if n <= 2:
                return k >= 1 and s >= 0.75 * capacity
            return k >= max(n - 2, 0) and s >= 0.75 * capacity
        if history.round_number == 0:
            self.mode = 'build'
            self.repair_consecutive = 0
            self.last_seen_round = 0
            self.last_stock = float(current_stock)
            return Action.C
        s = float(current_stock)
        k = safe_k()
        prev_k = safe_prev_k()
        if k >= max(n - 1, 0):
            self.mode = 'guard'
        elif k <= max(n - 3, 0):
            self.mode = 'repair'
            self.repair_consecutive = 0
        if capacity > 0 and s <= capacity / 2 and (k != max(n - 1, 0)):
            self.mode = 'repair'
        if capacity > 0 and s >= 0.9 * capacity and (k >= max(n - 2, 0)):
            if self.mode == 'repair':
                if repair_recovery(k, s) and prev_k >= max(n - 2, 0) and (self.last_stock is not None) and (self.last_stock >= 0.75 * capacity):
                    self.mode = 'guard'
                    self.repair_consecutive = 0
                    self.last_stock = s
                    self.last_seen_round = history.round_number
                    return Action.C
                self.repair_consecutive = 1 if repair_recovery(k, s) else 0
                self.last_stock = s
                self.last_seen_round = history.round_number
                return Action.C
            if self.mode in ('build', 'guard'):
                self.last_stock = s
                self.last_seen_round = history.round_number
                return Action.C
        if self.mode == 'build':
            if coop_threshold_build(k, s):
                action = Action.C
            else:
                self.mode = 'repair'
                self.repair_consecutive = 0
                action = Action.D
        elif self.mode == 'guard':
            if coop_threshold_guard(k, s):
                action = Action.C
            elif k == max(n - 2, 0) and capacity > 0 and (s >= 0.9 * capacity):
                self.mode = 'build'
                action = Action.C
            else:
                self.mode = 'repair'
                self.repair_consecutive = 0
                action = Action.D
        else:
            if repair_recovery(k, s):
                self.repair_consecutive += 1
            else:
                self.repair_consecutive = 0
            if self.repair_consecutive >= 2:
                self.mode = 'guard'
                action = Action.C
            else:
                action = Action.D
            if capacity > 0 and s >= 0.9 * capacity and (k >= max(n - 2, 0)):
                self.mode = 'guard'
                self.repair_consecutive = 0
                action = Action.C
        self.last_stock = s
        self.last_seen_round = history.round_number
        return action

class Strategy_COLLECTIVE_45(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Starts cooperative.
    - Tracks trust from observed opponent cooperation and stock dynamics.
    - Defects under severe depletion, broad defection, or late-game mistrust.
    - Follows behavioral hints from the previous round when appropriate.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.trust = 0
        self.mode = 'cooperative'
        self.last_processed_round = 0
        self.last_stock_seen = None
        self.next_action_hint = None

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        rounds = self.game_description.n_rounds
        round_number = history.round_number
        if round_number > self.last_processed_round and round_number > 0:
            idx = round_number - 1
            k_t = int(history.opponent_cooperators[idx]) if len(history.opponent_cooperators) > idx else 0
            n_opponents = max(n - 1, 1)
            coop_rate = k_t / n_opponents
            if coop_rate >= 2 / 3:
                self.trust = min(self.trust + 1, 3)
            elif coop_rate <= 1 / 3:
                self.trust = max(self.trust - 2, -3)
            elif self.trust > 0:
                self.trust -= 1
            elif self.trust < 0:
                self.trust += 1
            if self.last_stock_seen is not None:
                prev_stock = float(self.last_stock_seen)
                curr_stock = float(current_stock)
                if curr_stock > prev_stock:
                    self.trust = min(self.trust + 1, 3)
                if prev_stock > 0 and curr_stock <= prev_stock / 2:
                    self.trust = max(self.trust - 1, -3)
            prev_action = None
            if len(history.my_actions) > idx:
                prev_action = Action.C if bool(history.my_actions[idx]) else Action.D
            self.next_action_hint = None
            if prev_action == Action.C:
                if k_t >= max(n - 2, 0):
                    self.next_action_hint = Action.C
                elif k_t == 0:
                    self.next_action_hint = Action.D
            elif prev_action == Action.D:
                threshold = 2 * (n - 1) / 3 if n > 1 else 0
                if k_t >= threshold:
                    self.next_action_hint = Action.C
            self.mode = 'cooperative' if self.trust >= 1 else 'defensive' if self.trust <= -2 else 'mixed'
            self.last_processed_round = round_number
        self.last_stock_seen = float(current_stock)
        if round_number == 0:
            return Action.C
        rounds_left = rounds - round_number
        if rounds_left <= 2:
            return Action.C if self.trust >= 2 and current_stock > 2 * n else Action.D
        if current_stock <= 2 * n:
            return Action.D
        if self.trust >= 1:
            return Action.C
        if self.trust <= -2:
            return Action.D
        if self.next_action_hint is not None:
            return self.next_action_hint
        k_t = 0
        if round_number > 0 and len(history.opponent_cooperators) > 0:
            k_t = int(history.opponent_cooperators[-1])
        n_opponents = max(n - 1, 0)
        coop_consumption = k_t * (current_stock / (2 * n)) if n > 0 else 0.0
        defect_consumption = (n_opponents - k_t) * (current_stock / n) if n > 0 else 0.0
        expected_stock_if_C = current_stock - current_stock / (2 * n) - coop_consumption - defect_consumption if n > 0 else current_stock
        expected_stock_if_D = current_stock - current_stock / n - coop_consumption - defect_consumption if n > 0 else current_stock
        return Action.C if expected_stock_if_C >= current_stock / 2 else Action.D

class Strategy_COLLECTIVE_46(BaseStrategy):
    """
    Common-pool strategy that starts with cooperation, protects low stock,
    matches observed cooperation, and avoids persistent defection.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(0, self.n_players - 1)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        if round_number == 0:
            return Action.C
        if self.n_opponents <= 0:
            return Action.C
        last_opp_cooperators = int(history.opponent_cooperators[-1])
        rho = last_opp_cooperators / self.n_opponents if self.n_opponents > 0 else 0.0
        my_prev_action = bool(history.my_actions[-1])
        stock_fell_two_rounds = False
        if round_number >= 2:
            prev_payoff = float(history.my_payoffs[-1])
            prev_prev_payoff = float(history.my_payoffs[-2])
            stock_fell_two_rounds = prev_prev_payoff >= prev_payoff and prev_payoff >= 0.0
        in_final_two = round_number >= max(0, self.n_rounds - 2)
        if in_final_two and my_prev_action and (rho > 0.0):
            return Action.C
        if last_opp_cooperators == self.n_opponents:
            return Action.C
        if last_opp_cooperators == 0:
            return Action.D
        if current_stock <= self.n_players:
            return Action.C
        if current_stock <= 0.5 * self.n_players and rho == 0.0:
            return Action.D
        if current_stock <= 2.0 * self.n_players and rho < 0.5:
            return Action.C
        if current_stock <= self.n_players and stock_fell_two_rounds:
            return Action.D if rho == 0.0 else Action.C
        if rho >= 2.0 / 3.0:
            return Action.C
        if rho < 1.0 / 3.0:
            return Action.D
        if my_prev_action is False and rho <= 0.5:
            return Action.D
        if my_prev_action is True and rho < 1.0 / 3.0:
            return Action.D
        if my_prev_action is False:
            if rho >= 0.5:
                return Action.C
            return Action.D
        if my_prev_action is True:
            if rho < 1.0 / 3.0:
                return Action.D
            return Action.C
        return Action.C

class Strategy_COLLECTIVE_47(BaseStrategy):
    """
    State-contingent stabilize-the-pool strategy.

    - Cooperates in the first round.
    - Uses the current stock to estimate the minimum cooperation needed.
    - Cooperates when the previous round met the threshold and the pool is healthy.
    - Defects in danger zones or after clear under-cooperation.
    - Uses a special late-game rule in the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        if round_number == 0:
            return Action.C
        n = max(2, self.n)
        capacity = self.capacity if self.capacity > 0 else 1.0
        stock = float(current_stock)
        last_my_action = bool(history.my_actions[-1])
        last_opp_coop = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        observed_total_last_round = last_opp_coop + (1 if last_my_action else 0)
        phi = max(0.5, 1.0 - stock / capacity)
        required = int(math.ceil(n * phi))
        opp_required = int(math.ceil((n - 1) * phi))
        if round_number == self.r - 1:
            return Action.C if stock >= capacity / 4.0 else Action.D
        if round_number == self.r - 2:
            if stock >= capacity / 2.0 and observed_total_last_round >= required:
                return Action.C
            return Action.D
        if stock <= capacity / 4.0:
            return Action.D
        if last_opp_coop < opp_required:
            return Action.D
        if observed_total_last_round >= required:
            return Action.C
        return Action.D

class Strategy_COLLECTIVE_48(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Cooperates by default
    - Defects when cooperation is too low to sustain the pool
    - Becomes stricter near the end of the game
    - Uses recent cooperation trends and stock recovery to return to cooperation
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(self.n_players - 1, 1)
        self._last_stock = None
        self._last_action = None

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number
        cap = self.capacity
        half_cap = cap / 2.0
        three_quarter_cap = 3.0 * cap / 4.0

        def rho_at(index: int):
            if history.round_number <= index:
                return None
            opp = float(history.opponent_cooperators[index])
            return opp / float(self.n_opponents) if self.n_opponents > 0 else 0.0
        if t == 0:
            self._last_stock = float(current_stock)
            self._last_action = Action.C
            return Action.C
        prev_rho = rho_at(t - 1)
        prev2_rho = rho_at(t - 2)
        prev_action = Action.C if bool(history.my_actions[-1]) else Action.D
        trend_decision = None
        if prev_rho is not None and prev2_rho is not None:
            if prev_rho >= 0.5 and prev2_rho >= 0.5:
                trend_decision = Action.C
            elif prev_rho < 0.5 and prev2_rho < 0.5:
                trend_decision = Action.D
        decision = Action.D
        if t == self.n_rounds - 1:
            decision = Action.C if current_stock >= half_cap else Action.D
        elif t >= max(self.n_rounds - 3, 0):
            if current_stock >= half_cap and prev_rho is not None and (prev_rho >= 2.0 / 3.0):
                decision = Action.C
            else:
                decision = Action.D
        elif current_stock < half_cap:
            if prev_rho is not None and prev_rho >= 1.0 and (self._last_stock is not None) and (current_stock > self._last_stock):
                decision = Action.C
            else:
                decision = Action.D
        elif current_stock >= three_quarter_cap:
            if prev_rho is not None and prev_rho > 0.0:
                decision = Action.C
            else:
                decision = Action.D
        elif self._last_action == Action.D and self._last_stock is not None and (current_stock > self._last_stock) and (current_stock >= half_cap):
            decision = Action.C
        elif current_stock >= half_cap and prev_rho is not None and (prev_rho >= 0.5):
            decision = Action.C
        elif trend_decision is not None:
            decision = trend_decision
        else:
            decision = Action.C if current_stock >= half_cap and prev_rho is not None and (prev_rho >= 0.5) else Action.D
        self._last_stock = float(current_stock)
        self._last_action = decision
        return decision

class Strategy_COLLECTIVE_49(BaseStrategy):
    """
    Shared-stock stewardship strategy with sustain, repair, and terminal protection regimes.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.m_opponents = max(self.n_players - 1, 1)
        self.healthy_threshold = 0.7 * self.capacity
        self.stressed_threshold = 0.4 * self.capacity
        self.lower_protection_threshold = 0.1 * self.capacity
        self.coop_threshold = 0.6
        self.recovery_threshold = 0.5
        self.terminal_window = 2

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number
        if t == 0:
            return Action.C
        last_count = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        q = last_count / self.m_opponents if self.m_opponents > 0 else 0.0
        recent_counts = history.opponent_cooperators[max(0, t - 2):t]
        if len(recent_counts) > 0 and self.m_opponents > 0:
            recent_qs = np.asarray(recent_counts, dtype=float) / float(self.m_opponents)
            Q = float(np.mean(recent_qs))
        else:
            Q = q
        S = float(current_stock)
        rounds_left = self.n_rounds - t + 1
        if last_count <= 0:
            if q < 0.5:
                return Action.D
        if last_count >= self.m_opponents and S >= self.stressed_threshold:
            return Action.C
        if S <= self.lower_protection_threshold:
            return Action.D
        if rounds_left <= self.terminal_window:
            if S >= self.healthy_threshold and Q >= self.coop_threshold:
                return Action.C
            return Action.D
        if S < self.stressed_threshold:
            return Action.D
        if S < self.healthy_threshold:
            if Q >= self.coop_threshold and last_count >= max(self.m_opponents - 1, 0):
                return Action.C
            return Action.D
        if S >= self.healthy_threshold:
            if last_count >= max(self.m_opponents - 1, 0) and q >= self.recovery_threshold:
                return Action.C
            if q >= self.coop_threshold:
                return Action.C
            return Action.D
        return Action.D

class Strategy_COLLECTIVE_50(BaseStrategy):
    """
    Cooperative-first strategy for the Common Pool Resource Game.

    - Cooperate initially.
    - Cooperate when the stock is healthy and the opponent cooperation rate
      from the previous round is at least 1/2.
    - Defect defensively when stock is low, or after two consecutive low-cooperation
      rounds from opponents.
    - In the last two rounds, apply a stricter stock-protection rule.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self._coop_threshold = 0.5
        self._stock_defend_threshold = self.n_players / 2.0
        self._stock_coop_threshold = 2.0 * self.n_players / 3.0
        self._opponent_count = max(self.n_players - 1, 0)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        if round_number == 0:
            return Action.C
        if self._opponent_count <= 0:
            rho = 1.0
            low_coop_streak = 0
        else:
            last_opp = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
            rho = last_opp / self._opponent_count
            low_coop_streak = 0
            if len(history.opponent_cooperators) > 0:
                idx = len(history.opponent_cooperators) - 1
                while idx >= 0 and int(history.opponent_cooperators[idx]) / self._opponent_count < self._coop_threshold:
                    low_coop_streak += 1
                    idx -= 1
        remaining_rounds = self.n_rounds - round_number
        if remaining_rounds <= 2 and current_stock < self._stock_coop_threshold:
            return Action.D
        if current_stock < self._stock_defend_threshold:
            return Action.D
        if low_coop_streak >= 2:
            if current_stock >= self._stock_coop_threshold and rho >= self._coop_threshold:
                return Action.C
            return Action.D
        if current_stock >= self._stock_coop_threshold and rho >= self._coop_threshold:
            return Action.C
        return Action.D

class Strategy_COLLECTIVE_51(BaseStrategy):
    """
    Default-to-cooperate common-pool strategy with cautious retaliation:
    - Cooperate initially and whenever cooperation is sufficiently sustainable.
    - Defect only under clear overextraction, collapse risk, or persistent distrust.
    - Use a small trust score and recent stock trend as tie-breakers.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(0, self.n_players - 1)
        self.collapse_threshold = 2.0 * self.n_players
        self.trust = 0
        self._stock_history = []

    def _predicted_remaining(self, stock: float, k_coop: int, play_cooperate: bool) -> float:
        """
        Predict remaining stock after consumption, before growth, given k cooperating opponents.
        """
        n = self.n_players
        m = self.n_opponents
        k = max(0, min(int(k_coop), m))
        opponent_consumption = k * (stock / (2.0 * n)) + (m - k) * (stock / n)
        my_consumption = stock / (2.0 * n) if play_cooperate else stock / n
        return stock - (opponent_consumption + my_consumption)

    def _threshold(self) -> int:
        """
        Sustainable cooperation threshold from the prompt.
        """
        m = self.n_opponents
        return int(math.ceil((m - 1) / 2.0)) if m > 0 else 0

    def _very_low_stock(self, stock: float) -> bool:
        """
        Heuristic for 'so low that cooperating would still leave the stock near collapse'.
        """
        return stock <= self.collapse_threshold

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number
        stock = float(current_stock)
        self._stock_history.append(stock)
        if t == 0:
            return Action.C
        k_t = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        k_t = max(0, min(k_t, self.n_opponents))
        k_star = self._threshold()
        if k_t >= k_star:
            self.trust += 1
        else:
            self.trust -= 2
        falling_two_rounds = False
        if len(self._stock_history) >= 3:
            s0, s1, s2 = (self._stock_history[-3], self._stock_history[-2], self._stock_history[-1])
            falling_two_rounds = s0 > s1 and s1 > s2
        if t == self.n_rounds - 1:
            if k_t == 0:
                return Action.D
            if self._very_low_stock(stock):
                return Action.D if self.trust < 0 else Action.C
            r_c = self._predicted_remaining(stock, k_t, True)
            r_d = self._predicted_remaining(stock, k_t, False)
            if r_d <= 0 and r_c > 0:
                return Action.C
            if r_c <= 0 and r_d > 0:
                return Action.D
            return Action.C if self.trust >= 0 else Action.D
        if stock <= self.collapse_threshold and k_t == 0:
            return Action.D
        r_c = self._predicted_remaining(stock, k_t, True)
        r_d = self._predicted_remaining(stock, k_t, False)
        if r_c <= 0 and r_d > 0:
            return Action.D
        if r_d <= 0 and r_c > 0:
            return Action.C
        if falling_two_rounds and (not (stock <= self.collapse_threshold and k_t == 0)):
            return Action.C
        if k_t >= k_star:
            return Action.C
        if k_t < k_star:
            if self.trust >= 0 and k_t == k_star - 1:
                return Action.C
            return Action.D
        return Action.C if self.trust >= 0 else Action.D

class Strategy_COLLECTIVE_52(BaseStrategy):
    """
    Stock-preserving target strategy with a small forgiveness band.
    Defaults to cooperation, defects only under sustained low stock and weak
    observed opponent cooperation, and immediately returns to cooperation once
    stock recovers.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self._last_stock: float | None = None
        self._prev_stock: float | None = None

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = int(self.game_description.n_players)
        rounds = int(self.game_description.n_rounds)
        capacity = float(self.game_description.capacity)
        stock_increased_last_round = False
        stock_decreased_last_round = False
        stock_increased_two_consecutive = False
        stock_decreased_two_consecutive = False
        if self._last_stock is not None:
            if current_stock > self._last_stock:
                stock_increased_last_round = True
            elif current_stock < self._last_stock:
                stock_decreased_last_round = True
        if self._prev_stock is not None and self._last_stock is not None:
            if self._last_stock > self._prev_stock and current_stock > self._last_stock:
                stock_increased_two_consecutive = True
            if self._last_stock < self._prev_stock and current_stock < self._last_stock:
                stock_decreased_two_consecutive = True
        self._prev_stock = self._last_stock
        self._last_stock = float(current_stock)
        t = int(history.round_number)
        if t == 0:
            return Action.C
        S_t = float(current_stock)
        if not math.isfinite(S_t):
            S_t = 0.0
        if S_t < 0.0:
            S_t = 0.0
        if capacity > 0.0 and S_t > capacity:
            S_t = capacity
        prev_k = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        n_opponents = max(n - 1, 1)
        m_prev = prev_k / n_opponents
        if t >= rounds - 1:
            benchmark = S_t / n if n > 0 else 0.0
            return Action.C if S_t >= benchmark else Action.D
        if stock_increased_two_consecutive:
            return Action.C
        if capacity > 0.0 and S_t >= 0.9 * capacity:
            return Action.C
        if capacity > 0.0 and S_t >= capacity / 2.0:
            return Action.C
        if capacity > 0.0 and S_t <= capacity / 10.0:
            if not (m_prev == 1.0 and stock_increased_last_round):
                return Action.D
        if stock_decreased_two_consecutive and m_prev <= 0.5:
            return Action.D
        if n > 1 and m_prev >= (n - 2) / (n - 1):
            return Action.C
        if capacity > 0.0 and S_t < capacity / 3.0 and (n > 1 and m_prev < (n - 3) / (n - 1)):
            return Action.D
        return Action.C

class Strategy_COLLECTIVE_53(BaseStrategy):
    """
    State-based conditional cooperation strategy for the Common Pool Resource Game.

    - Start by cooperating.
    - Cooperate when stock is high and there was at least some cooperation last round.
    - In medium/low stock, require a majority of opponents to have cooperated last round.
    - Defect when the pool is exhausted.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.target_cooperators = max(1, math.ceil((self.n - 1) / 2))
        self.low_threshold = self.capacity / 3.0
        self.high_threshold = 2.0 * self.capacity / 3.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = int(history.round_number)
        if t == 0:
            return Action.C
        if current_stock <= 0.0:
            return Action.D
        prev_coop = 0
        if len(history.opponent_cooperators) > 0:
            prev_coop = int(history.opponent_cooperators[-1])
        is_final_two_rounds = t >= max(0, self.r - 2)
        if is_final_two_rounds and current_stock < self.high_threshold:
            return Action.C if prev_coop >= self.target_cooperators else Action.D
        if current_stock <= self.low_threshold:
            return Action.C if prev_coop >= self.target_cooperators else Action.D
        if current_stock < self.high_threshold:
            return Action.C if prev_coop >= self.target_cooperators else Action.D
        return Action.C if prev_coop >= 1 else Action.D

class Strategy_COLLECTIVE_54(BaseStrategy):
    """
    State-contingent threshold strategy with preservation, reciprocity, and recovery modes.
    Begins cooperatively, then adjusts based on stock level and observed opponent cooperation.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.majority_threshold = int(math.ceil((self.n - 1) / 2))
        self.full_coop_threshold = max(0, self.n - 1)
        self.mode = 0
        self.consecutive_full_coop = 0
        self.warning_state = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number
        S = float(current_stock)
        if S <= 0.0:
            return Action.D
        if t == 0:
            self.mode = 0
            self.consecutive_full_coop = 0
            self.warning_state = False
            return Action.C
        if t == self.r - 1:
            return Action.C if (S / self.capacity if self.capacity > 0 else 0.0) >= 0.5 else Action.D
        x = S / self.capacity if self.capacity > 0 else 0.0
        m_prev = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else None
        if m_prev is None:
            return Action.C
        if m_prev >= self.full_coop_threshold:
            self.consecutive_full_coop += 1
        else:
            self.consecutive_full_coop = 0
        if m_prev < self.majority_threshold:
            if self.mode == 0:
                self.mode = 1
            elif self.mode == 1:
                self.mode = 2
            self.warning_state = True
        else:
            self.warning_state = False
            if self.consecutive_full_coop >= 2:
                if self.mode == 2:
                    self.mode = 1
                elif self.mode == 1:
                    self.mode = 0
        if x < 0.25:
            return Action.D
        if self.mode == 0:
            if x >= 0.75:
                return Action.C if m_prev >= self.majority_threshold else Action.C
            if x >= 0.5:
                return Action.C if m_prev >= self.majority_threshold else Action.D
            return Action.D
        if self.mode == 1:
            if x >= 0.5:
                return Action.C if m_prev >= self.majority_threshold else Action.D
            return Action.D
        if x < 0.5:
            return Action.C if m_prev >= self.full_coop_threshold else Action.D
        return Action.C if m_prev >= self.majority_threshold else Action.D

class Strategy_COLLECTIVE_55(BaseStrategy):
    """
    Default-cooperate common-pool strategy with escalation to defection only
    after repeated low cooperation in a risky low-stock state.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.low_coop_streak = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_players = int(self.game_description.n_players)
        n_opponents = max(n_players - 1, 1)
        capacity = float(self.game_description.capacity)
        round_number = int(history.round_number)
        last_round_index = int(self.game_description.n_rounds) - 1
        if round_number == 0:
            self.low_coop_streak = 0
            return Action.C
        last_opponent_cooperators = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        coop_rate = last_opponent_cooperators / n_opponents
        streak = 0
        if len(history.opponent_cooperators) > 0:
            for c in history.opponent_cooperators:
                rate = int(c) / n_opponents
                if rate < 0.5:
                    streak += 1
                else:
                    streak = 0
        self.low_coop_streak = streak
        if round_number == last_round_index:
            if current_stock < 0.5 * capacity and coop_rate < 0.5:
                return Action.D
            return Action.C
        if current_stock >= 0.8 * capacity or coop_rate >= 0.5 or (self.low_coop_streak == 1 and current_stock >= 0.5 * capacity):
            return Action.C
        if current_stock < 0.8 * capacity and coop_rate < 0.5 and (self.low_coop_streak >= 2):
            return Action.D
        return Action.C

class Strategy_COLLECTIVE_56(BaseStrategy):
    """
    Stock-preserving threshold strategy with retaliation, recovery,
    and low-stock protection for the Common Pool Resource Game.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.trust_counter = 0
        self.breach_counter = 0
        self.retaliation_remaining = 0
        self._processed_rounds = 0
        self._last_observed_cooperators = 0

    def _project_next_stock(self, current_stock: float, total_cooperators: int) -> float:
        n = self.n
        cap = self.capacity
        s = max(0.0, float(current_stock))
        k = max(0, min(int(total_cooperators), n))
        s_remaining = s * (k / (2.0 * n)) if n > 0 else 0.0
        growth = 2.0 * s_remaining * (1.0 - s_remaining / cap) if cap > 0 else 0.0
        return min(s_remaining + growth, cap)

    def _should_cooperate_core(self, current_stock: float, last_opponent_cooperators: int) -> bool:
        n = self.n
        next_stock_c = self._project_next_stock(current_stock, last_opponent_cooperators + 1)
        next_stock_d = self._project_next_stock(current_stock, last_opponent_cooperators)
        return next_stock_c >= next_stock_d and (last_opponent_cooperators >= n - 1 or self.trust_counter >= 2)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        n_rounds = self.r
        n_players = self.n
        while self._processed_rounds < round_number:
            idx = self._processed_rounds
            if idx < len(history.opponent_cooperators):
                observed = int(history.opponent_cooperators[idx])
            else:
                observed = 0
            self._last_observed_cooperators = observed
            if observed >= n_players - 1:
                self.trust_counter = min(self.trust_counter + 1, 2)
                self.breach_counter = 0
            else:
                self.breach_counter += 1
                self.trust_counter = 0
            self._processed_rounds += 1
        if round_number == 0:
            return Action.C
        upcoming_round_1based = round_number + 1
        if upcoming_round_1based == n_rounds - 1 or upcoming_round_1based == n_rounds:
            if self._last_observed_cooperators >= n_players - 1:
                return Action.C
            return Action.D
        if self.breach_counter >= 2 and self.retaliation_remaining <= 0:
            self.retaliation_remaining = 2
        if self.retaliation_remaining > 0:
            self.retaliation_remaining -= 1
            return Action.D
        if current_stock <= self.capacity / 4.0:
            if self._last_observed_cooperators >= n_players - 2:
                return Action.C
            return Action.D
        if self._last_observed_cooperators == n_players - 2:
            if current_stock > self.capacity / 2.0:
                return Action.C
            return Action.D
        if self._should_cooperate_core(current_stock, self._last_observed_cooperators):
            return Action.C
        return Action.D

class Strategy_COLLECTIVE_57(BaseStrategy):
    """
    Adaptive commons strategy with rebuild/maintain/protect/endgame modes,
    short-memory retaliation, and a collective floor rule.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(1, self.n_players - 1)
        self.high_threshold = 0.75
        self.low_threshold = 0.45
        self.floor_threshold = 0.3
        self.half_threshold = 0.5
        self.reliable_threshold = 0.75
        self.collective_floor_threshold = 0.8
        self.last_round_safe_threshold = 0.9
        self.protect_recovery_threshold = 0.25

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        if round_number == 0:
            return Action.C
        capacity = self.capacity if self.capacity > 0 else 1.0
        x = float(current_stock) / capacity
        last_opponents = int(history.opponent_cooperators[-1]) if round_number > 0 else 0
        c = last_opponents / self.n_opponents if self.n_opponents > 0 else 0.0
        rounds_left = self.n_rounds - round_number
        g = 0
        for idx in range(round_number - 1, -1, -1):
            if int(history.opponent_cooperators[idx]) >= self.n_opponents:
                g += 1
            else:
                break
        last_two_all_coop = False
        if round_number >= 2:
            last_two_all_coop = int(history.opponent_cooperators[-1]) >= self.n_opponents and int(history.opponent_cooperators[-2]) >= self.n_opponents
        if rounds_left == 1:
            if x >= self.last_round_safe_threshold and last_opponents >= self.n_opponents:
                return Action.C
            return Action.D
        if x < self.floor_threshold:
            if c >= self.collective_floor_threshold:
                return Action.C
            if last_two_all_coop and x >= self.protect_recovery_threshold:
                return Action.C
            return Action.D
        if x >= self.high_threshold:
            return Action.C
        if self.low_threshold <= x < self.high_threshold:
            if g >= 2:
                return Action.C
            return Action.C if c >= self.reliable_threshold else Action.D
        if last_two_all_coop and x >= self.protect_recovery_threshold:
            return Action.C
        if g >= 2 and x >= self.protect_recovery_threshold:
            return Action.C
        return Action.D

class Strategy_COLLECTIVE_58(BaseStrategy):
    """
    Stock-preserving threshold strategy with a cooperative mode, forgiveness,
    and a final-round safeguard for the common pool resource game.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.cooperative_mode = True

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.n_players
        cap = self.capacity
        round_number = int(history.round_number)
        current_round = round_number + 1
        last_round = current_round >= self.n_rounds
        if round_number == 0:
            self.cooperative_mode = True
            return Action.C
        last_opponents = int(history.opponent_cooperators[-1]) if round_number > 0 else 0
        n_opponents = max(n - 1, 0)
        if n_opponents > 0:
            if last_opponents < n_opponents / 2.0:
                self.cooperative_mode = False
            elif last_opponents >= max(n_opponents - 1, 0):
                self.cooperative_mode = True
        if current_stock <= 0.0 or current_stock <= 1e-12:
            return Action.D
        if cap <= 0.0:
            return Action.D
        if current_stock >= cap:
            return Action.C
        if self.cooperative_mode:
            high_threshold = 2.0 / 3.0 * cap
            mid_threshold = 0.5 * cap
            low_threshold = 1.0 / 3.0 * cap
        else:
            high_threshold = 0.5 * cap
            mid_threshold = 1.0 / 3.0 * cap
            low_threshold = 0.25 * cap
        if last_round and current_stock < mid_threshold:
            return Action.D
        if current_stock <= low_threshold:
            return Action.D
        if current_stock >= high_threshold:
            return Action.C
        if n_opponents > 0 and last_opponents >= n_opponents - 1 and (current_stock >= mid_threshold):
            return Action.C
        if n_opponents > 0 and last_opponents <= math.floor(n_opponents / 2) and (current_stock < high_threshold):
            return Action.D
        if n_opponents <= 0:
            return Action.C
        if last_opponents * 2 >= n_opponents:
            return Action.C
        return Action.D

class Strategy_COLLECTIVE_59(BaseStrategy):
    """
    Stock-preserving contingent cooperator for the Common Pool Resource Game.
    Cooperates by default, but defects when stock is strained or observed
    cooperation drops below preservation thresholds.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(getattr(game_description, 'n_players', 2))
        self.n_rounds = int(getattr(game_description, 'n_rounds', 1))
        self.capacity = float(getattr(game_description, 'capacity', 0.0))
        self.n_opponents = max(self.n_players - 1, 0)
        self.half_opponents_threshold = math.ceil(self.n_opponents / 2) if self.n_opponents > 0 else 0
        self.two_thirds_opponents_threshold = math.ceil(2 * self.n_opponents / 3) if self.n_opponents > 0 else 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number
        if t == 0:
            return Action.C
        if t >= self.n_rounds - 1:
            return Action.C if current_stock >= self.capacity / 2 else Action.D
        if current_stock < self.capacity / 3:
            return Action.D
        k_t = 0
        if len(history.opponent_cooperators) > 0:
            k_t = int(history.opponent_cooperators[-1])
        if k_t >= self.half_opponents_threshold and current_stock >= self.capacity / 2:
            return Action.C
        if current_stock >= 2 * self.capacity / 3 and k_t >= self.two_thirds_opponents_threshold:
            return Action.C
        return Action.D

class Strategy_COLLECTIVE_60(BaseStrategy):
    """
    Stock-preserving common-pool strategy with guarded retaliation,
    recovery mode, and endgame cooperation.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(0, self.n_players - 1)
        self.safe_half_capacity = self.capacity / 2.0
        self.endgame_opponent_threshold = int(math.ceil(self.n_opponents / 2.0)) if self.n_opponents > 0 else 0
        self.low_coop_threshold = int(math.ceil(self.n_opponents / 3.0)) if self.n_opponents > 0 else 0
        self.strong_coop_threshold = max(0, self.n_opponents - 2)
        self._recovery_rounds_left = 0
        self._last_seen_history_len = -1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_num = history.round_number
        t = round_num + 1
        if round_num == 0:
            self._last_seen_history_len = round_num
            self._recovery_rounds_left = 0
            return Action.C
        k = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        k_prev = int(history.opponent_cooperators[-2]) if len(history.opponent_cooperators) > 1 else k
        my_prev = bool(history.my_actions[-1]) if len(history.my_actions) > 0 else True
        if k < self.low_coop_threshold:
            self._recovery_rounds_left = 2
        elif self._recovery_rounds_left > 0 and k >= self.endgame_opponent_threshold:
            self._recovery_rounds_left = 0
        in_recovery = self._recovery_rounds_left > 0
        if in_recovery:
            self._recovery_rounds_left = max(0, self._recovery_rounds_left - 1)
        threshold = int(math.ceil(self.n_players - current_stock / 2.0))
        threshold = max(0, min(self.n_opponents, threshold))
        sharp_betrayal = bool(my_prev and k_prev - k >= 2)
        low_stock = current_stock <= 2.0 * self.n_players / 3.0
        very_low_stock = current_stock < self.n_players
        if t >= self.n_rounds:
            return Action.C if k == self.n_opponents else Action.D
        if t >= self.n_rounds - 1:
            return Action.C if k >= self.endgame_opponent_threshold else Action.D
        if in_recovery:
            return Action.C
        if current_stock <= 0.0:
            return Action.C
        if very_low_stock:
            return Action.C if k > 0 else Action.D
        if low_stock:
            return Action.C if k >= threshold + 1 else Action.D
        action = Action.C if k >= threshold else Action.D
        if sharp_betrayal and k < self.strong_coop_threshold:
            action = Action.D
        if k == threshold:
            if current_stock >= self.safe_half_capacity:
                action = Action.C
            else:
                action = Action.D
        return action

class Strategy_COLLECTIVE_61(BaseStrategy):
    """
    Cooperative baseline with conditional retaliation and stock-protection behavior.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.discipline = 0
        self.last_q = 1.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_players = self.game_description.n_players
        n_opponents = max(1, n_players - 1)
        rounds_total = self.game_description.n_rounds
        round_number = history.round_number
        if round_number == 0:
            self.discipline = 0
            self.last_q = 1.0
            return Action.C
        prev_coop = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        q = prev_coop / n_opponents
        self.last_q = q
        capacity = float(self.game_description.capacity) if self.game_description.capacity else 1.0
        s = current_stock / capacity if capacity > 0 else 0.0
        if round_number == rounds_total - 1:
            return Action.C if q >= 2.0 / 3.0 else Action.D
        if self.discipline > 0:
            self.discipline -= 1
            if q >= 2.0 / 3.0:
                self.discipline = 0
            return Action.D
        if s < 0.25:
            self.discipline = 2 if q < 2.0 / 3.0 else 1
            return Action.D
        if q >= 2.0 / 3.0 and s >= 0.25:
            self.discipline = 0
            return Action.C
        if q >= 0.5 and s >= 0.4:
            self.discipline = 0
            return Action.C
        if q < 1.0 / 3.0:
            self.discipline = 2
        else:
            self.discipline = 1
        return Action.D

class Strategy_COLLECTIVE_62(BaseStrategy):
    """
    Threshold-based contingent cooperation for a common pool resource game.

    Defaults to cooperation, defects only after sustained low opponent
    cooperation, and returns to cooperation as soon as a cooperative
    majority reappears.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(0, self.n_players - 1)
        self.threshold = max(1, math.ceil(self.n_opponents / 2)) if self.n_opponents > 0 else 1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        if self.n_opponents <= 0:
            return Action.C
        if round_number == 0:
            return Action.C
        if round_number >= self.n_rounds - 1:
            return Action.C if current_stock > 0 else Action.D
        if current_stock <= 0:
            return Action.C
        if current_stock <= self.capacity / 2.0:
            return Action.C
        if self.capacity > 0 and current_stock <= 0.05 * self.capacity:
            return Action.C
        last_k = int(history.opponent_cooperators[-1])
        if self.n_opponents == 1:
            return Action.C if last_k >= 1 else Action.D
        recent = history.opponent_cooperators[max(0, round_number - 3):round_number]
        if len(recent) > 0:
            c_bar = float(np.mean(recent)) / float(self.n_opponents)
        else:
            c_bar = 1.0
        if c_bar >= 0.5:
            return Action.C
        if last_k >= self.threshold:
            return Action.C
        if round_number >= 2:
            prev_k = int(history.opponent_cooperators[-2])
            if prev_k < self.threshold and last_k < self.threshold:
                return Action.D
        return Action.D if last_k < self.threshold else Action.C

class Strategy_COLLECTIVE_63(BaseStrategy):
    """
    State-based threshold strategy:
    - Start cooperatively.
    - Defect only under clear evidence of low cooperation or resource stress.
    - Use a temporary defense mode after exploitation signals.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = max(2, int(game_description.n_players))
        self.n_rounds = max(1, int(game_description.n_rounds))
        self.capacity = float(game_description.capacity)
        self.q_floor = 0.75
        self.low_coop_floor = 0.5
        self.h_floor = 0.5 * self.capacity
        self.defense_until_round = -1
        self._prev_stock = None

    def _round_cooperation_rate(self, history: PlayerHistory, round_index: int) -> float:
        n = self.n_players
        if round_index < 0 or round_index >= history.round_number or n <= 0:
            return 0.0
        my_coop = 1 if bool(history.my_actions[round_index]) else 0
        opp_coop = int(history.opponent_cooperators[round_index]) if round_index < len(history.opponent_cooperators) else 0
        total_coop = my_coop + opp_coop
        return total_coop / n

    def _two_consecutive_moderate_cooperation(self, history: PlayerHistory) -> bool:
        if history.round_number < 2:
            return False
        q1 = self._round_cooperation_rate(history, history.round_number - 1)
        q0 = self._round_cooperation_rate(history, history.round_number - 2)
        return q0 >= self.low_coop_floor and q1 >= self.low_coop_floor

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        if round_number == 0:
            self._prev_stock = float(current_stock)
            return Action.C
        prev_round_index = round_number - 1
        prev_q = self._round_cooperation_rate(history, prev_round_index)
        if prev_q >= self.q_floor or self._two_consecutive_moderate_cooperation(history):
            self.defense_until_round = -1
        if self._prev_stock is not None:
            if prev_q < self.low_coop_floor and float(current_stock) < float(self._prev_stock):
                self.defense_until_round = max(self.defense_until_round, round_number + 1)
        if round_number >= self.n_rounds - 1:
            self._prev_stock = float(current_stock)
            return Action.C if prev_q >= self.low_coop_floor else Action.D
        if round_number <= self.defense_until_round:
            self._prev_stock = float(current_stock)
            return Action.D
        if prev_q <= self.low_coop_floor:
            self._prev_stock = float(current_stock)
            return Action.D
        if float(current_stock) <= self.h_floor and prev_q < self.q_floor:
            self._prev_stock = float(current_stock)
            return Action.D
        self._prev_stock = float(current_stock)
        return Action.C

class Strategy_COLLECTIVE_64(BaseStrategy):
    """
    Adaptive common-pool strategy with cooperation thresholding, stock-based
    emergency defection, and a simple recovery rule based on the previous
    round's observed cooperation level.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(getattr(game_description, 'n_players', 0) or 0)
        self.n_rounds = int(getattr(game_description, 'n_rounds', 0) or 0)
        self.capacity = float(getattr(game_description, 'capacity', 0) or 0.0)
        self._threshold = math.ceil((max(self.n_players, 1) - 1) / 2)
        self._quarter_capacity = self.capacity / 4.0 if self.capacity else 0.0
        self._eighth_capacity = self.capacity / 8.0 if self.capacity else 0.0
        self._half_capacity = self.capacity / 2.0 if self.capacity else 0.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(getattr(history, 'round_number', 0) or 0)
        if round_number == 0:
            return Action.C
        if self.n_rounds > 0 and round_number >= self.n_rounds - 1:
            return Action.D
        stock = float(current_stock) if current_stock is not None else 0.0
        if stock <= self._eighth_capacity or stock <= self._quarter_capacity:
            return Action.D
        m_prev = None
        try:
            if hasattr(history, 'opponent_cooperators') and len(history.opponent_cooperators) > 0:
                m_prev = int(history.opponent_cooperators[-1])
        except Exception:
            m_prev = None
        if m_prev is None:
            return Action.C if stock > self._half_capacity else Action.D
        if m_prev < self._threshold:
            return Action.D
        return Action.C

class Strategy_COLLECTIVE_65(BaseStrategy):
    """
    Stock-preserving threshold strategy with cooperative default,
    escalation to defection under weak cooperation, and recovery rules
    after breakdowns or defection.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.m = max(self.n - 1, 0)
        self.coop_share = 0.5
        self.defect_share = 1.0
        self.target_coop_fraction = 0.5
        self.minimum_stock_floor = self.capacity / 2.0
        self.critical_floor = self.capacity / 4.0
        self.half_opponents_threshold = int(math.ceil(self.m / 2.0)) if self.m > 0 else 0
        self.three_quarters_opponents_threshold = int(math.ceil(3.0 * self.m / 4.0)) if self.m > 0 else 0
        self.half_players_threshold = int(math.ceil(self.n / 2.0))

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        if round_number == 0:
            return Action.C
        prev_opp_coop = int(history.opponent_cooperators[-1])
        prev_my_action = bool(history.my_actions[-1])
        if self.r - round_number <= 2:
            if current_stock >= self.minimum_stock_floor and prev_opp_coop >= self.half_opponents_threshold:
                return Action.C
            return Action.D
        if round_number >= 3:
            recent_opp = history.opponent_cooperators[-3:]
            recent_total = int(np.sum(recent_opp))
            recent_possible = 3 * self.m
            if recent_possible > 0 and recent_total < recent_possible / 2.0:
                if current_stock >= self.minimum_stock_floor and prev_opp_coop >= self.three_quarters_opponents_threshold:
                    return Action.C
                return Action.D
        if not prev_my_action:
            if current_stock >= self.minimum_stock_floor and prev_opp_coop >= self.three_quarters_opponents_threshold:
                return Action.C
            return Action.D
        if current_stock >= self.minimum_stock_floor:
            if prev_opp_coop < self.half_opponents_threshold:
                return Action.D
            return Action.C
        if self.critical_floor <= current_stock < self.minimum_stock_floor:
            expected_cooperators = prev_opp_coop + 1 if prev_my_action else prev_opp_coop
            if expected_cooperators >= self.half_players_threshold:
                return Action.C
            return Action.D
        if prev_opp_coop >= self.three_quarters_opponents_threshold:
            if prev_my_action and prev_opp_coop == 0:
                return Action.D
            return Action.C
        return Action.D

class Strategy_COLLECTIVE_66(BaseStrategy):
    """
    Cooperative default with short punishment for persistent low cooperation.
    Maintains trust, bad_streak, and punishment countdown across rounds.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.trust = 1.0
        self.bad_streak = 0
        self.punish_left = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = int(self.game_description.n_players)
        n_opponents = max(0, n - 1)
        last_round = int(history.round_number)
        final_round = last_round >= int(self.game_description.n_rounds) - 1
        if last_round == 0:
            return Action.C
        has_obs = len(history.opponent_cooperators) > 0
        k = int(history.opponent_cooperators[-1]) if has_obs else None
        if self.punish_left > 0:
            if final_round:
                self.punish_left = max(0, self.punish_left - 1)
                return Action.C
            self.punish_left -= 1
            if has_obs and k is not None:
                high_bar = math.ceil(0.8 * n_opponents)
                if k >= high_bar:
                    self.bad_streak = 0
                else:
                    self.bad_streak += 1
            return Action.D
        if not has_obs or k is None:
            return Action.C
        high_bar = math.ceil(0.8 * n_opponents)
        mid_bar = math.ceil(0.6 * n_opponents)
        if n == 2:
            if k >= 1:
                self.bad_streak = 0
                return Action.C
            if current_stock <= self.game_description.capacity / 4:
                self.bad_streak = 0
                return Action.C
            self.bad_streak += 1
            if self.bad_streak >= 2 and (not final_round):
                self.punish_left = 1
                return Action.D
            return Action.C
        q = k / n_opponents if n_opponents > 0 else 1.0
        self.trust = 0.75 * self.trust + 0.25 * q
        if k >= high_bar:
            self.bad_streak = 0
            return Action.C
        if current_stock <= self.game_description.capacity / 4:
            self.bad_streak = 0
            return Action.C
        if current_stock >= self.game_description.capacity / 2 and k >= mid_bar:
            self.bad_streak = 0
            return Action.C
        if k < mid_bar:
            self.bad_streak += 1
            if self.bad_streak >= 2 and (not final_round):
                self.punish_left = 1
                return Action.D
            return Action.C
        if k >= mid_bar and self.trust >= 0.6:
            self.bad_streak = 0
            return Action.C
        return Action.C

class Strategy_COLLECTIVE_67(BaseStrategy):
    """
    Adaptive common-pool strategy with three modes:
    cooperate, probe, and discipline.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.mode = 'cooperate'
        self.consecutive_full_coop = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = max(2, int(self.game_description.n_players))
        m = max(1, n - 1)
        cap = float(self.game_description.capacity)
        round_number = int(history.round_number)
        last_round_index = int(self.game_description.n_rounds) - 1
        if round_number == 0:
            self.mode = 'cooperate'
            self.consecutive_full_coop = 0
            return Action.C
        k = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else m
        ceil_half_m = math.ceil(m / 2)
        ceil_two_thirds_m = math.ceil(2 * m / 3)
        if m == 1:
            action = Action.C if k >= 1 and current_stock > 0 else Action.D
        elif round_number == last_round_index:
            action = Action.C if k >= ceil_half_m else Action.D
        else:
            if self.mode == 'discipline' and k == m and (current_stock >= 0.75 * cap):
                self.mode = 'cooperate'
            if current_stock <= cap / 3:
                action = Action.C if k >= ceil_two_thirds_m else Action.D
            elif current_stock >= 0.85 * cap:
                action = Action.C if k >= ceil_half_m else Action.D
            elif k == m:
                action = Action.C
            elif k >= ceil_two_thirds_m:
                action = Action.C
            else:
                action = Action.D
        if k == m and current_stock >= 0.9 * cap:
            self.mode = 'cooperate'
            self.consecutive_full_coop += 1
        elif k < m:
            self.mode = 'discipline'
            self.consecutive_full_coop = 0
        return action

class Strategy_COLLECTIVE_68(BaseStrategy):
    """
    Cautious cooperative strategy with escalation only after persistent breakdown
    and with stock-sensitive protection against overconsumption.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = max(2, int(game_description.n_players))
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(0, self.n - 1)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.n
        capacity = self.capacity
        if history.round_number == 0:
            return Action.C
        last_opp_c = int(history.opponent_cooperators[-1])
        last_my_action_c = bool(history.my_actions[-1])
        last_tot_c = last_opp_c + (1 if last_my_action_c else 0)
        last_coop_rate = last_tot_c / n if n > 0 else 0.0
        last_payoff = float(history.my_payoffs[-1])
        if last_my_action_c:
            last_round_start_stock = last_payoff * (2.0 * n)
        else:
            last_round_start_stock = last_payoff * n
        stock_decreased_last_round = current_stock < last_round_start_stock - 1e-12
        stock_rising_or_flat = current_stock >= last_round_start_stock - 1e-12
        warning_streak = 0
        for idx in range(history.round_number - 1, -1, -1):
            opp_c = int(history.opponent_cooperators[idx])
            my_c = bool(history.my_actions[idx])
            tot_c = opp_c + (1 if my_c else 0)
            coop_rate = tot_c / n if n > 0 else 0.0
            if coop_rate < 0.5:
                warning_streak += 1
            else:
                break
        if history.round_number >= 1 and history.round_number == int(self.game_description.n_rounds) - 1:
            if warning_streak >= 2 and current_stock > capacity / 2.0:
                return Action.D
            return Action.C
        if current_stock <= capacity / 3.0:
            return Action.C
        if current_stock >= 2.0 * capacity / 3.0:
            return Action.C
        if last_coop_rate >= 2.0 / 3.0:
            return Action.C
        if last_coop_rate >= 0.5 and stock_rising_or_flat:
            return Action.C
        if last_coop_rate < 0.5:
            if warning_streak == 1:
                return Action.C
        if warning_streak >= 2 and current_stock > capacity / 2.0:
            return Action.D
        return Action.C

class Strategy_COLLECTIVE_69(BaseStrategy):
    """
    Stock-preserving contingent cooperator with adaptive cooperation threshold.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(0, self.n_players - 1)
        self._processed_rounds = 0
        self._q = self._initial_q()
        self._full_coop_streak = 0

    def _initial_q(self) -> float:
        n = max(2, self.n_players)
        q = 1.0 - 1.0 / (2.0 * n) - 0.5 * (1.0 - 1.0)
        return max(0.0, min(1.0, q))

    def _target_q_from_rate(self, coop_rate: float) -> float:
        n = max(2, self.n_players)
        q = 1.0 - 1.0 / (2.0 * n) - 0.5 * (1.0 - coop_rate)
        return max(0.0, min(1.0, q))

    def _safe_rate(self, coop_count: int) -> float:
        if self.n_opponents <= 0:
            return 1.0
        return max(0.0, min(1.0, float(coop_count) / float(self.n_opponents)))

    def _update_internal_state(self, history: PlayerHistory, current_stock: float) -> None:
        total_rounds = history.round_number
        if total_rounds <= self._processed_rounds:
            return
        for r in range(self._processed_rounds, total_rounds):
            coop_rate = self._safe_rate(int(history.opponent_cooperators[r]))
            if coop_rate >= self._q:
                pass
            else:
                self._q = min(1.0, self._q + 1.0 / max(1, self.n_players))
            if coop_rate >= 1.0:
                self._full_coop_streak += 1
            else:
                self._full_coop_streak = 0
            if self._full_coop_streak >= 2 and current_stock >= self.capacity / 2.0 and (coop_rate >= 1.0):
                self._q = max(0.0, self._q - 1.0 / max(2, 2 * self.n_players))
        self._processed_rounds = total_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        self._update_internal_state(history, current_stock)
        t = history.round_number + 1
        n = max(2, self.n_players)
        half_capacity = self.capacity / 2.0
        quarter_capacity = self.capacity / 4.0
        if t == 1:
            return Action.C
        if t == self.n_rounds:
            return Action.C if current_stock >= half_capacity else Action.D
        if current_stock < quarter_capacity:
            return Action.D
        if current_stock < half_capacity:
            coop_rate_prev = self._safe_rate(int(history.opponent_cooperators[-1]))
            return Action.C if coop_rate_prev >= 0.8 else Action.D
        if self.n_opponents <= 0:
            coop_rate_prev = 1.0
        else:
            coop_rate_prev = self._safe_rate(int(history.opponent_cooperators[-1]))
        q = self._target_q_from_rate(coop_rate_prev)
        return Action.C if coop_rate_prev >= q else Action.D

class Strategy_COLLECTIVE_70(BaseStrategy):
    """
    Stock-preserving threshold strategy with adaptive cooperation target.
    Starts by cooperating, rewards sustained cooperation, and quickly reduces
    cooperation when the pool or opponents' behavior deteriorates.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = max(2, self.n_players)
        n_opponents = max(1, n - 1)
        cap = max(0.0, float(self.capacity))
        S_t = float(current_stock)
        round_number = int(history.round_number)
        if round_number == 0:
            return Action.C
        q_t = 1.0
        past_rounds = min(round_number - 1, len(history.opponent_cooperators) - 1)
        if past_rounds > 0:
            for idx in range(past_rounds):
                opp_c = int(history.opponent_cooperators[idx])
                h = opp_c / n_opponents if n_opponents > 0 else 0.0
                if h >= 0.75:
                    q_t = min(1.0, q_t + 0.1)
                elif h < 0.4:
                    q_t = max(0.0, q_t - 0.2)
        last_opp_c = int(history.opponent_cooperators[round_number - 1]) if round_number - 1 < len(history.opponent_cooperators) else 0
        h_t = last_opp_c / n_opponents if n_opponents > 0 else 0.0
        if round_number >= self.n_rounds - 1:
            if S_t >= 0.5 * cap:
                return Action.C
            return Action.D if h_t < 0.5 else Action.C
        if S_t <= cap / 4.0:
            return Action.C if h_t >= 0.8 else Action.D
        if S_t >= 0.9 * cap:
            if h_t < 0.25:
                return Action.D
            return Action.C
        if last_opp_c == 0:
            if S_t >= 0.95 * cap:
                return Action.C
            return Action.D
        own_cons_c = S_t / (2.0 * n)
        own_cons_d = S_t / n
        opp_cons = (n - 1) * h_t * (S_t / (2.0 * n)) if n > 1 else 0.0
        cons_c = opp_cons + own_cons_c
        cons_d = opp_cons + own_cons_d
        s_rem_c = max(0.0, S_t - cons_c)
        s_rem_d = max(0.0, S_t - cons_d)
        s_next_c = min(s_rem_c + 2.0 * s_rem_c * (1.0 - s_rem_c / cap), cap) if cap > 0 else 0.0
        s_next_d = min(s_rem_d + 2.0 * s_rem_d * (1.0 - s_rem_d / cap), cap) if cap > 0 else 0.0
        c_better = s_next_c >= s_next_d - 1e-12
        near_sustainable = S_t >= 0.6 * cap
        if S_t >= cap / 2.0 and h_t >= q_t - 0.15 and (c_better or near_sustainable):
            return Action.C
        return Action.D

class Strategy_COLLECTIVE_71(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Start cooperatively.
    - Cooperate when opponent cooperation is at/above majority, stable, and the pool is not clearly collapsing.
    - Defect when cooperation drops below majority, trends downward, the pool is low, or in the final rounds unless support is strong.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(self.n_players - 1, 0)
        self.last_seen_round = -1
        self.last_coop_rate = None
        self.last_trend = 0.0
        self.defensive_mode = False
        self.defensive_mode_expires_round = -1

    def _coop_rate(self, opponents_coop: int) -> float:
        if self.n_opponents <= 0:
            return 1.0
        return float(opponents_coop) / float(self.n_opponents)

    def _safe_rate(self, arr, idx: int) -> float:
        if idx < 0 or idx >= len(arr):
            return 0.0
        return self._coop_rate(int(arr[idx]))

    def _downward_trend(self, history: PlayerHistory) -> bool:
        rn = history.round_number
        if rn < 3:
            return False
        r0 = self._safe_rate(history.opponent_cooperators, rn - 1)
        r1 = self._safe_rate(history.opponent_cooperators, rn - 2)
        r2 = self._safe_rate(history.opponent_cooperators, rn - 3)
        return r2 > r1 > r0 or (r2 - r1 > 0.0 and r1 - r0 > 0.0)

    def _sharp_collapse(self, current_stock: float, coop_rate: float, prev_coop_rate: float) -> bool:
        if self.capacity <= 0:
            return False
        low_stock = current_stock <= 0.25 * self.capacity
        sharp_drop = prev_coop_rate - coop_rate >= 1.0 / max(self.n_opponents, 1)
        severe_stock = current_stock <= 0.15 * self.capacity
        return severe_stock or (low_stock and sharp_drop)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number + 1
        if history.round_number == 0:
            self.last_seen_round = 0
            self.last_coop_rate = None
            self.last_trend = 0.0
            self.defensive_mode = False
            self.defensive_mode_expires_round = -1
            return Action.C
        current_coop_rate = self._safe_rate(history.opponent_cooperators, history.round_number - 1)
        prev_coop_rate = self._safe_rate(history.opponent_cooperators, history.round_number - 2)
        trend = current_coop_rate - prev_coop_rate
        downward_trend = self._downward_trend(history)
        if self.last_seen_round != history.round_number:
            self.last_seen_round = history.round_number
            self.last_trend = trend
            self.last_coop_rate = current_coop_rate
        stock_not_clearly_collapsed = not self._sharp_collapse(current_stock, current_coop_rate, prev_coop_rate)
        low_stock_regime = self.capacity > 0 and current_stock <= 0.2 * self.capacity
        if self.defensive_mode and history.round_number <= self.defensive_mode_expires_round:
            if current_coop_rate >= 0.5 and (not downward_trend) and stock_not_clearly_collapsed:
                self.defensive_mode = False
            else:
                return Action.D
        else:
            self.defensive_mode = False
        if prev_coop_rate >= 0.5 and current_coop_rate < 0.5 and (trend < 0.0):
            self.defensive_mode = True
            self.defensive_mode_expires_round = history.round_number
            return Action.D
        if t == self.n_rounds:
            return Action.C if current_coop_rate >= 1.0 else Action.D
        if t == self.n_rounds - 1:
            if history.round_number >= 1:
                prev_round_rate = self._safe_rate(history.opponent_cooperators, history.round_number - 2)
            else:
                prev_round_rate = 0.0
            if current_coop_rate >= 2.0 / 3.0 and prev_round_rate >= 2.0 / 3.0:
                return Action.C
            return Action.D
        if current_coop_rate >= 0.5 and (not downward_trend) and stock_not_clearly_collapsed and (not low_stock_regime):
            if history.round_number >= 2:
                r1 = self._safe_rate(history.opponent_cooperators, history.round_number - 1)
                r2 = self._safe_rate(history.opponent_cooperators, history.round_number - 2)
                if r1 >= 0.5 and r2 >= 0.5 and (current_coop_rate >= 0.5):
                    return Action.C
            return Action.C
        if current_coop_rate < 0.5 or downward_trend or low_stock_regime:
            return Action.D
        if stock_not_clearly_collapsed and current_coop_rate >= 0.5:
            return Action.C
        return Action.D

class Strategy_COLLECTIVE_72(BaseStrategy):
    """
    Stock-preserving strategy with exponentially weighted belief tracking,
    dynamic mode switching (build / maintain / punish), and endgame caution.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.capacity = float(game_description.capacity)
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.p_hat = 1.0
        self.mode = 'build'
        self.last_stock = self.capacity
        self.good_streak = 0
        self.last_q = 1.0
        self.initialized = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        if round_number == 0:
            self.p_hat = 1.0
            self.mode = 'build'
            self.last_stock = float(current_stock)
            self.good_streak = 0
            self.last_q = 1.0
            self.initialized = True
            return Action.C
        if not self.initialized:
            self.p_hat = 1.0
            self.mode = 'build'
            self.last_stock = float(current_stock)
            self.good_streak = 0
            self.last_q = 1.0
            self.initialized = True
        n_opponents = max(self.n_players - 1, 0)
        coop_count = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        if n_opponents > 0:
            q_t = coop_count / n_opponents
        else:
            q_t = 1.0
        stock_now = float(current_stock)
        trend = stock_now - float(self.last_stock)
        self.p_hat = 0.7 * self.p_hat + 0.3 * q_t
        if q_t >= 0.75:
            self.good_streak += 1
        else:
            self.good_streak = 0
        remaining_rounds = self.n_rounds - round_number
        if remaining_rounds <= 2:
            action = Action.C if stock_now > 0.0 and self.p_hat >= 0.5 else Action.D
            self.last_stock = stock_now
            self.last_q = q_t
            return action
        if self.mode == 'punish':
            action = Action.D
            if self.good_streak >= 2 and stock_now >= 0.6 * self.capacity:
                self.mode = 'build'
            self.last_stock = stock_now
            self.last_q = q_t
            return action
        if q_t < 0.5 or trend < -(self.capacity / 4.0) or stock_now < 0.4 * self.capacity:
            self.mode = 'punish'
            action = Action.D
        elif stock_now >= 0.7 * self.capacity and self.p_hat >= 0.75:
            self.mode = 'build'
            action = Action.C if self.p_hat >= 0.75 and stock_now >= 0.5 * self.capacity else Action.D
        elif stock_now >= 0.45 * self.capacity and self.p_hat >= 0.6:
            self.mode = 'maintain'
            action = Action.C if self.p_hat >= 0.6 and stock_now >= 0.45 * self.capacity else Action.D
        else:
            self.mode = 'punish'
            action = Action.D
        self.last_stock = stock_now
        self.last_q = q_t
        return action

class Strategy_COLLECTIVE_73(BaseStrategy):
    """
    Conservative collective-discipline strategy for the common pool resource game.

    - Defaults to cooperation.
    - Uses controlled drawdown only when stock is high and recent cooperation is strong.
    - Avoids defection in fragile or depleted states.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = max(2, int(game_description.n_players))
        self.r = max(1, int(game_description.n_rounds))
        self.capacity = float(game_description.capacity)
        self.target = self.capacity / 2.0
        self.band = self.capacity / (4.0 * self.n)
        self.high = self.target + self.band
        self.low = self.target - self.band

    def _recent_cooperation_average(self, history: PlayerHistory) -> float:
        opp = history.opponent_cooperators
        if len(opp) == 0:
            return 1.0
        window = opp[-3:]
        denom = max(1, self.n - 1)
        qs = [float(k) / denom for k in window]
        avg = float(np.mean(qs)) if len(qs) > 0 else 1.0
        if avg < 0.0:
            return 0.0
        if avg > 1.0:
            return 1.0
        return avg

    def _trend(self, history: PlayerHistory) -> int:
        opp = history.opponent_cooperators
        if len(opp) >= 2:
            return int(opp[-1]) - int(opp[-2])
        return 0

    def _expected_next_stock(self, current_stock: float, my_action: Action, qbar: float) -> float:
        s = float(current_stock)
        n = float(self.n)
        my_consumption = s / n if my_action == Action.D else s / (2.0 * n)
        expected_opp_consumption_per_player = qbar * (s / (2.0 * n)) + (1.0 - qbar) * (s / n)
        total_consumption = my_consumption + (self.n - 1) * expected_opp_consumption_per_player
        remaining = s - total_consumption
        if remaining < 0.0:
            remaining = 0.0
        if remaining > self.capacity:
            remaining = self.capacity
        growth = 2.0 * remaining * (1.0 - remaining / self.capacity) if self.capacity > 0 else 0.0
        new_stock = remaining + growth
        if new_stock > self.capacity:
            new_stock = self.capacity
        if new_stock < 0.0:
            new_stock = 0.0
        return new_stock

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = int(history.round_number)
        stock = float(current_stock)
        if t == 0:
            return Action.C
        qbar = self._recent_cooperation_average(history)
        L = self._trend(history)
        if t >= self.r - 1:
            if t == self.r - 1:
                if stock >= self.high and qbar >= 2.0 / 3.0:
                    return Action.D
                return Action.C
            candidate = self._decide_normal(stock, qbar, L, t)
            if candidate == Action.D:
                projected = self._expected_next_stock(stock, Action.D, qbar)
                if projected < self.low:
                    return Action.C
            return candidate
        return self._decide_normal(stock, qbar, L, t)

    def _decide_normal(self, stock: float, qbar: float, L: int, t: int) -> Action:
        if stock <= self.low:
            return Action.C
        if stock <= self.target and qbar < 0.5:
            return Action.C
        if self.low < stock < self.high:
            if qbar >= 2.0 / 3.0 and L >= 0:
                if t >= self.r - 2:
                    return Action.C
                return Action.D
            return Action.C
        if stock >= self.high:
            if qbar >= 2.0 / 3.0:
                return Action.D
            return Action.C
        return Action.C

class Strategy_COLLECTIVE_74(BaseStrategy):
    """
    Cooperative-by-default strategy with stock-aware restraint:
    - Cooperate in the first round.
    - Use recent opponent cooperation and stock persistence to decide whether
      to continue cooperating or to defect to protect the common pool.
    - Re-enter cooperation quickly once opponents cooperate again and stock is healthy.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(self.n_players - 1, 0)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = int(history.round_number)
        if t == 0:
            return Action.C
        if current_stock < 0.3 * self.capacity:
            return Action.D
        prev_k = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        denom = self.n_opponents if self.n_opponents > 0 else 1
        prev_c_rate = prev_k / denom
        if t == 1:
            return Action.C if prev_c_rate >= 0.5 else Action.D
        prev_stock = None
        if len(history.my_payoffs) > 0:
            prev_my_payoff = float(history.my_payoffs[-1])
            prev_stock = float(current_stock + 0.0)
        if t >= self.n_rounds - 2:
            if prev_c_rate >= 0.5 and current_stock >= 0.8 * self.capacity:
                return Action.C
            return Action.C if prev_c_rate >= 0.5 and current_stock >= 0.6 * self.capacity else Action.D
        if prev_c_rate >= 0.5 and current_stock >= 0.6 * self.capacity:
            return Action.C
        if prev_c_rate >= 0.5 and current_stock >= 0.75 * self.capacity:
            return Action.C
        return Action.D

class Strategy_COLLECTIVE_75(BaseStrategy):
    """
    Adaptive common-pool strategy with stock-based green/yellow/red thresholds
    and a two-round recovery rule after a successful exploitation signal.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(0, self.n_players - 1)
        self.green_threshold = 0.6 * self.capacity
        self.yellow_threshold = 0.3 * self.capacity
        self.green_cutoff = math.ceil((self.n_players - 1) / 2) if self.n_players > 1 else 0
        self.yellow_cutoff = math.ceil(2 * (self.n_players - 1) / 3) if self.n_players > 1 else 0
        self._force_cooperate_rounds = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        if round_number == 0:
            return Action.C
        if len(history.my_actions) > 0 and len(history.opponent_cooperators) > 0:
            last_my_action = bool(history.my_actions[-1])
            last_opp_coop = int(history.opponent_cooperators[-1])
            if not last_my_action and last_opp_coop == self.n_opponents:
                self._force_cooperate_rounds = 2
        stock = float(current_stock)
        is_green = stock >= self.green_threshold
        is_yellow = stock >= self.yellow_threshold and stock < self.green_threshold
        is_red = stock < self.yellow_threshold
        if self._force_cooperate_rounds > 0 and (not is_red):
            self._force_cooperate_rounds -= 1
            return Action.C
        opp_coop = 0
        if len(history.opponent_cooperators) > 0:
            opp_coop = int(history.opponent_cooperators[-1])
        if is_green:
            return Action.C if opp_coop >= self.green_cutoff else Action.D
        elif is_yellow:
            return Action.C if opp_coop >= self.yellow_cutoff else Action.D
        else:
            return Action.C if opp_coop == self.n_opponents else Action.D

class Strategy_COLLECTIVE_76(BaseStrategy):
    """
    Threshold-based common-pool strategy:
    - Cooperate in round 1.
    - Defect under low stock.
    - Otherwise cooperate when prior cooperation was sufficiently high,
      with immediate repair after a defection if the previous round was
      collectively supportive enough.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.sustainability_threshold = self.capacity / 2.0
        self.low_stock_threshold = self.capacity / 4.0
        self.collective_support_threshold = math.ceil(3 * self.n_players / 4)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        if round_number == 0:
            return Action.C
        if current_stock <= self.low_stock_threshold:
            return Action.D
        if current_stock < self.sustainability_threshold:
            return Action.D
        prev_opponent_cooperators = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        last_my_action = bool(history.my_actions[-1]) if len(history.my_actions) > 0 else True
        k = prev_opponent_cooperators
        m = k + (1 if last_my_action else 0)
        q = m / self.n_players if self.n_players > 0 else 0.0
        if round_number == self.n_rounds - 1:
            if current_stock >= self.sustainability_threshold and k >= self.collective_support_threshold - 1:
                return Action.C
            return Action.D
        if not last_my_action:
            if k >= self.collective_support_threshold - 1:
                return Action.C
            return Action.D
        if k >= self.collective_support_threshold - 1 and q >= 0.75:
            return Action.C
        return Action.D

class Strategy_COLLECTIVE_77(BaseStrategy):
    """
    Conditional cooperation strategy for the common pool resource game.

    - Cooperate initially.
    - Track recent opponent cooperation and pool health.
    - Defect during severe depletion or sustained low cooperation.
    - Forgive a single small breach when cooperation is strong and the pool is still reasonably healthy.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self._low_q_streak = 0
        self._stock_lock = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_players = max(2, int(self.game_description.n_players))
        n_opponents = max(1, n_players - 1)
        capacity = float(self.game_description.capacity) if self.game_description.capacity else 0.0
        if history.round_number == 0:
            return Action.C
        last_opp_coops = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        q = last_opp_coops / n_opponents
        s = float(current_stock) / capacity if capacity > 0 else 0.0
        if q <= 1.0 / 3.0:
            self._low_q_streak += 1
        else:
            self._low_q_streak = 0
        if s < 1.0 / 8.0:
            self._stock_lock = True
        elif s >= 1.0 / 4.0:
            self._stock_lock = False
        if self._stock_lock:
            return Action.D
        if self._low_q_streak >= 2 and q < 1.0 / 2.0:
            return Action.D
        if q >= 2.0 / 3.0 and s >= 1.0 / 8.0:
            return Action.C
        if q >= 1.0 / 2.0 and s >= 1.0 / 4.0:
            return Action.C
        return Action.D

class Strategy_COLLECTIVE_78(BaseStrategy):
    """
    Conservation-first conditional strategy:
    - Cooperate in the first and last round.
    - In intermediate rounds, defect only when stock is high and recent
      opponent cooperation has been persistently low.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(self.n_players - 1, 1)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        if round_number == 0 or round_number >= self.n_rounds - 1:
            return Action.C
        if self.capacity <= 0:
            return Action.C
        rho_t = float(current_stock) / self.capacity
        recent_counts = history.opponent_cooperators[max(0, round_number - 3):round_number]
        recent_rates = [float(c) / self.n_opponents for c in recent_counts]
        missing = 3 - len(recent_rates)
        pbar_t = (sum(recent_rates) + missing * 1.0) / 3.0
        if round_number < 2:
            return Action.C
        p_last1 = float(history.opponent_cooperators[round_number - 1]) / self.n_opponents
        p_last2 = float(history.opponent_cooperators[round_number - 2]) / self.n_opponents
        if rho_t > 0.5 and pbar_t < 2.0 / 3.0 and (p_last1 < 0.5) and (p_last2 < 0.5):
            return Action.D
        return Action.C

class Strategy_COLLECTIVE_79(BaseStrategy):
    """
    Common-pool strategy:
    - Start with cooperation.
    - Cooperate when recent opponent cooperation is high and the stock is healthy.
    - Defect under weak cooperation, low stock, or during a short defensive persistence window.
    - In the final round, ignore stock and respond only to observed cooperation.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.q_star = 2.0 / 3.0
        self.m_star = 0.75 * self.capacity
        self.low_stock_threshold = 0.25 * self.capacity
        self._defend_rounds_remaining = 0
        self._last_seen_round = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        if round_number < self._last_seen_round:
            self._defend_rounds_remaining = 0
        self._last_seen_round = round_number
        if round_number == 0:
            return Action.C
        last_k = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        weak_threshold = math.floor((self.n - 1) / 3)
        if last_k <= weak_threshold:
            self._defend_rounds_remaining = max(self._defend_rounds_remaining, 2)
        if round_number == self.r - 1:
            q_prev = last_k / (self.n - 1) if self.n > 1 else 0.0
            return Action.C if q_prev >= self.q_star else Action.D
        if self._defend_rounds_remaining > 0:
            self._defend_rounds_remaining -= 1
            return Action.D
        if current_stock < self.low_stock_threshold:
            return Action.D
        if self.n == 2:
            return Action.C if last_k >= 1 and current_stock >= self.m_star else Action.D
        q_prev = last_k / (self.n - 1) if self.n > 1 else 0.0
        if q_prev >= self.q_star and current_stock >= self.m_star:
            return Action.C
        return Action.D

class Strategy_COLLECTIVE_80(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Cooperate first round
    - Use recent opponent cooperation and stock ratios to switch between
      cooperative, defensive, and hostile modes
    - Apply a special final-round rule
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(0, self.n_players - 1)
        self.last_stock_seen = float(game_description.capacity)
        self.last_opponent_coop_rate = 0.0
        self.prev_opponent_coop_rate = 0.0
        self.environment_mode = 'unknown'

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        cap = self.capacity if self.capacity > 0 else 1.0
        x_t = float(current_stock) / cap
        if self.n_opponents > 0 and round_number > 0 and (len(history.opponent_cooperators) > 0):
            rho_t = float(history.opponent_cooperators[-1]) / float(self.n_opponents)
        else:
            rho_t = 0.0
        if round_number >= 2 and len(history.opponent_cooperators) >= 2 and (self.n_opponents > 0):
            rho_last = float(history.opponent_cooperators[-1]) / float(self.n_opponents)
            rho_prev = float(history.opponent_cooperators[-2]) / float(self.n_opponents)
            if rho_last >= 2.0 / 3.0 and rho_prev >= 2.0 / 3.0:
                self.environment_mode = 'cooperative'
            elif rho_last <= 1.0 / 3.0 and rho_prev <= 1.0 / 3.0:
                self.environment_mode = 'hostile'
            else:
                self.environment_mode = 'unknown'
        if round_number == 0:
            self.last_stock_seen = float(current_stock)
            self.last_opponent_coop_rate = rho_t
            return Action.C
        if round_number == self.n_rounds - 1:
            action = Action.C if x_t >= 0.25 and rho_t >= 0.5 else Action.D
            self.last_stock_seen = float(current_stock)
            self.prev_opponent_coop_rate = self.last_opponent_coop_rate
            self.last_opponent_coop_rate = rho_t
            return action
        very_low_stock = x_t <= 1.0 / 6.0
        if very_low_stock or rho_t <= 1.0 / 3.0:
            action = Action.D
        elif x_t >= 0.5 and rho_t >= 2.0 / 3.0:
            action = Action.C
        else:
            stock_did_not_fall_sharply = True
            if self.last_stock_seen > 0:
                stock_did_not_fall_sharply = float(current_stock) >= 0.8 * self.last_stock_seen
            standard_cooperate = x_t >= 1.0 / 3.0 and rho_t >= 0.5 and stock_did_not_fall_sharply
            if self.environment_mode == 'cooperative' and x_t >= 1.0 / 3.0:
                action = Action.C
            elif self.environment_mode == 'hostile' and (not (x_t >= 0.5 and rho_t >= 2.0 / 3.0)):
                action = Action.D
            else:
                action = Action.C if standard_cooperate else Action.D
        self.last_stock_seen = float(current_stock)
        self.prev_opponent_coop_rate = self.last_opponent_coop_rate
        self.last_opponent_coop_rate = rho_t
        return action

class Strategy_COLLECTIVE_81(BaseStrategy):
    """
    Common-pool strategy:
    - Cooperate initially.
    - Maintain a trust score based on recent opponent cooperation.
    - Defect when stock is critically low.
    - Otherwise cooperate when trust and stock recovery are sufficient.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        cap = self.capacity
        stock = float(current_stock)
        g = 1.0
        opp_counts = history.opponent_cooperators
        n_opponents = max(self.n_players - 1, 1)
        for kappa in opp_counts:
            rho = float(kappa) / float(n_opponents)
            g = (2.0 * g + rho) / 3.0
        recent_rho = float(opp_counts[-1]) / float(n_opponents)
        low_stock = cap / 6.0
        medium_stock = cap / 3.0
        if recent_rho < 0.5:
            if stock < medium_stock:
                return Action.D
            return Action.C
        if stock <= low_stock:
            return Action.D
        if g >= 2.0 / 3.0 and stock >= medium_stock:
            return Action.C
        if g >= 0.5 and stock >= medium_stock:
            return Action.C
        if g >= 2.0 / 3.0 and stock > low_stock:
            return Action.C
        return Action.D

class Strategy_COLLECTIVE_82(BaseStrategy):
    """
    Stock-Guarded Reciprocity:
    - Start by cooperating.
    - Cooperate while stock is healthy and observed cooperation is sufficient.
    - Defect when stock is fragile or cooperation drops.
    - Use recover and guard modes to avoid overexploitation and test for renewed restraint.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.mode = 'build'
        n = int(getattr(game_description, 'n_players', 0))
        capacity = float(getattr(game_description, 'capacity', 0.0))
        self.m = max(0, n - 1)
        self.high = 0.7 * capacity
        self.mid = 0.45 * capacity
        self.low = 0.25 * capacity
        self.good_coop = int(math.ceil(self.m / 2)) if self.m > 0 else 0
        self.strong_coop = int(math.ceil(2 * self.m / 3)) if self.m > 0 else 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number
        if t == 0:
            self.mode = 'build'
            return Action.C
        x = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        S = float(current_stock)
        if S <= self.low:
            self.mode = 'recover'
            return Action.D
        if self.mode == 'recover':
            if S >= self.mid and x >= self.strong_coop:
                self.mode = 'build'
                return Action.C
            return Action.D
        if self.mode == 'guard':
            self.mode = 'build'
            if S >= self.mid and x >= self.good_coop:
                return Action.C
            return Action.D
        if S >= self.high:
            if x >= self.good_coop:
                self.mode = 'build'
                return Action.C
            self.mode = 'guard'
            return Action.D
        if S >= self.mid:
            if x >= self.good_coop:
                self.mode = 'build'
                return Action.C
            self.mode = 'guard'
            return Action.D
        self.mode = 'recover'
        return Action.D

class Strategy_COLLECTIVE_83(BaseStrategy):
    """
    Cooperative-by-default common pool strategy with sustainability checks,
    recent-cooperation tracking, late-game caution, and temporary defensive mode.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self._defensive_rounds_remaining = 0
        self._last_seen_round_number = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = int(self.game_description.n_players)
        r = int(self.game_description.n_rounds)
        capacity = float(self.game_description.capacity)
        n_opponents = max(n - 1, 1)
        round_number = int(history.round_number)
        if round_number == 0:
            self._defensive_rounds_remaining = 0
            self._last_seen_round_number = 0
            return Action.C
        half_capacity = capacity / 2.0
        third_capacity = capacity / 3.0
        majority_threshold = math.ceil(n_opponents / 2.0)
        three_quarter_threshold = n_opponents if n == 2 else math.ceil(0.75 * n_opponents)
        has_last = len(history.opponent_cooperators) >= 1
        has_two = len(history.opponent_cooperators) >= 2
        last_opp_coop = int(history.opponent_cooperators[-1]) if has_last else None
        prev_opp_coop = int(history.opponent_cooperators[-2]) if has_two else None
        if has_last and last_opp_coop is not None:
            if last_opp_coop >= three_quarter_threshold and current_stock >= half_capacity:
                self._defensive_rounds_remaining = 0
        if has_two and prev_opp_coop is not None and (last_opp_coop is not None):
            if prev_opp_coop < n_opponents / 2.0 and last_opp_coop < n_opponents / 2.0:
                self._defensive_rounds_remaining = max(self._defensive_rounds_remaining, 2)
        if round_number >= max(r - 2, 0):
            if current_stock >= half_capacity:
                if has_last and last_opp_coop is not None and (last_opp_coop >= three_quarter_threshold):
                    self._defensive_rounds_remaining = 0
                    return Action.C
                return Action.D
            if has_last and last_opp_coop is not None and (last_opp_coop >= max(n - 2, 0)):
                return Action.C
            return Action.D
        if self._defensive_rounds_remaining > 0:
            if has_last and last_opp_coop is not None and (last_opp_coop >= three_quarter_threshold) and (current_stock >= half_capacity):
                self._defensive_rounds_remaining = 0
                return Action.C
            self._defensive_rounds_remaining = max(0, self._defensive_rounds_remaining - 1)
            return Action.D
        if not has_last or last_opp_coop is None:
            return Action.C if current_stock >= half_capacity else Action.D
        if current_stock < half_capacity:
            return Action.C
        total_observed = len(history.opponent_cooperators)
        if total_observed <= 0:
            p_hat = 1.0
        else:
            denom = total_observed * n_opponents
            p_hat = float(np.sum(history.opponent_cooperators)) / denom if denom > 0 else 1.0
        if p_hat >= 0.75 and last_opp_coop >= max(n - 2, 0):
            return Action.C
        if history.my_actions[-1]:
            if last_opp_coop < majority_threshold:
                if current_stock < third_capacity:
                    return Action.C
                return Action.D
        elif last_opp_coop >= three_quarter_threshold and current_stock >= half_capacity:
            return Action.C
        if p_hat < 0.5 or last_opp_coop < majority_threshold:
            return Action.D
        return Action.C

class Strategy_COLLECTIVE_84(BaseStrategy):
    """
    Stock-preserving threshold policy with reciprocal punishment and recovery.
    Cooperates by default when the pool is healthy, defects temporarily when
    cooperation drops, and returns to cooperation once cooperation and stock
    recover.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self._recovery_mode = False
        self._high_coop_streak = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_players = int(self.game_description.n_players)
        n_opponents = max(1, n_players - 1)
        rounds_total = int(self.game_description.n_rounds)
        round_number = int(history.round_number)
        capacity = float(self.game_description.capacity)
        if round_number == 0:
            self._recovery_mode = False
            self._high_coop_streak = 0
            return Action.C
        last_opponent_coop = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        c_t = last_opponent_coop / n_opponents if n_opponents > 0 else 0.0
        recent_count = min(3, len(history.opponent_cooperators))
        if recent_count > 0:
            recent = history.opponent_cooperators[-recent_count:]
            h_t = float(np.mean(recent)) / n_opponents if n_opponents > 0 else 0.0
        else:
            h_t = 0.0
        if c_t >= 0.6:
            self._high_coop_streak += 1
        else:
            self._high_coop_streak = 0
        if self._high_coop_streak >= 2:
            self._recovery_mode = False
        if round_number > 0:
            last_my_action = bool(history.my_actions[-1]) if len(history.my_actions) > 0 else True
            if not last_my_action and c_t < 0.5:
                self._recovery_mode = True
        if round_number == rounds_total - 1:
            return Action.C if current_stock >= 0.6 * capacity else Action.D
        if self._recovery_mode:
            if c_t >= 0.6 and current_stock > 0.45 * capacity:
                self._recovery_mode = False
                return Action.C
            return Action.D
        if current_stock <= 0.35 * capacity:
            return Action.D
        if c_t >= 0.75 and h_t >= 0.7:
            return Action.C
        if 0.5 <= c_t < 0.75:
            return Action.C if current_stock >= 0.55 * capacity else Action.D
        if c_t < 0.5:
            self._recovery_mode = True
            self._high_coop_streak = 0
            return Action.D
        return Action.C

class Strategy_COLLECTIVE_85(BaseStrategy):
    """
    Adaptive common-pool strategy with stock-based thresholds, brief recovery
    after full cooperation, and a lockout mode after observing zero cooperation.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.last_processed_round = -1
        self.prev_band = None
        self.prev_k = None
        self.prev_action = Action.C
        self.recovery_rounds_left = 0
        self.zero_lock = False

    def _stock_band(self, stock: float):
        cap = self.capacity if self.capacity > 0 else 1.0
        if stock < 0.3 * cap:
            return 0
        if stock < 0.5 * cap:
            return 1
        if stock < 0.8 * cap:
            return 2
        return 3

    def _stock_rule(self, k: int, stock: float, final_round: bool) -> Action:
        cap = self.capacity if self.capacity > 0 else 1.0
        n_opponents = max(self.n - 1, 0)
        if stock < 0.3 * cap:
            return Action.D
        if final_round and stock >= 0.5 * cap:
            threshold = math.ceil(n_opponents / 2)
            return Action.C if k >= threshold else Action.D
        if stock < 0.5 * cap:
            return Action.C if k == n_opponents else Action.D
        if stock < 0.8 * cap:
            threshold = math.ceil(2 * n_opponents / 3)
            return Action.C if k >= threshold else Action.D
        threshold = math.ceil(n_opponents / 2)
        return Action.C if k >= threshold else Action.D

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        n_opponents = max(self.n - 1, 0)
        k = int(history.opponent_cooperators[-1]) if round_number > 0 else 0
        final_round = round_number == max(self.r - 1, 0)
        if round_number == 0:
            action = Action.C
            self.prev_band = self._stock_band(current_stock)
            self.prev_k = None
            self.prev_action = action
            return action
        if round_number != self.last_processed_round:
            if self.prev_k is not None:
                if self.prev_k == n_opponents:
                    self.recovery_rounds_left = 2
                elif self.prev_k == 0:
                    self.zero_lock = True
                    self.recovery_rounds_left = 0
            self.last_processed_round = round_number
        band = self._stock_band(current_stock)
        if self.prev_band is not None and self.prev_k is not None:
            if band == self.prev_band and k == self.prev_k:
                action = self.prev_action
                self.prev_band = band
                self.prev_k = k
                self.prev_action = action
                if self.recovery_rounds_left > 0:
                    self.recovery_rounds_left -= 1
                return action
        if self.zero_lock:
            action = self._stock_rule(k, current_stock, final_round)
            if k == n_opponents:
                self.zero_lock = False
            self.prev_band = band
            self.prev_k = k
            self.prev_action = action
            if self.recovery_rounds_left > 0:
                self.recovery_rounds_left -= 1
            return action
        if self.recovery_rounds_left > 0 and current_stock >= 0.3 * self.capacity:
            action = Action.C
        else:
            action = self._stock_rule(k, current_stock, final_round)
        self.prev_band = band
        self.prev_k = k
        self.prev_action = action
        if self.recovery_rounds_left > 0:
            self.recovery_rounds_left -= 1
        return action

class Strategy_COLLECTIVE_86(BaseStrategy):
    """
    State-contingent sustainability-threshold strategy with temporary repair
    defection after visible overuse, and a late-game bias toward cooperation.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(0, self.n - 1)
        self.defect_until_round = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_index = history.round_number
        t = round_index + 1
        if round_index == 0:
            self.defect_until_round = 0
            return Action.C
        n_players = self.n
        n_opponents = self.n_opponents
        capacity = self.capacity if self.capacity > 0 else 1.0
        x_t = current_stock / capacity
        if x_t < 0.0:
            x_t = 0.0
        elif x_t > 1.0:
            x_t = 1.0
        last_k = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        safe_zone = x_t >= 2.0 / 3.0
        broad_coop = last_k >= max(0, n_players - 1)
        substantial_free_riding = last_k <= math.floor((n_players - 1) / 2)
        if safe_zone and broad_coop:
            self.defect_until_round = 0
            if t >= self.r - 1:
                if t == self.r and current_stock <= 0:
                    return Action.D
            return Action.C
        if self.defect_until_round >= t and (not (safe_zone and broad_coop)):
            if t >= self.r - 1:
                if t == self.r:
                    return Action.C if current_stock > 0 else Action.D
                return Action.C if x_t >= 0.5 else Action.D
            return Action.D
        if t >= self.r - 1:
            if t == self.r:
                return Action.C if current_stock > 0 else Action.D
            return Action.C if x_t >= 0.5 else Action.D
        if safe_zone:
            if substantial_free_riding:
                L = max(1, math.ceil(self.r / 5))
                self.defect_until_round = max(self.defect_until_round, t + L - 1)
                return Action.D
            return Action.C
        return Action.D

class Strategy_COLLECTIVE_87(BaseStrategy):
    """
    Stock-preserving threshold strategy with:
    - cooperative opening move,
    - adaptive midgame thresholding,
    - strict endgame preservation,
    - rapid retreat when cooperation collapses or stock weakens.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.m = max(self.n - 1, 0)
        self.eps = 1e-09
        self.T_early = 3.0 * self.n
        self.T_mid = 2.5 * self.n
        self.T_late = 2.0 * self.n
        self.prev_stock: float | None = None
        self.tier: int = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number
        S = float(current_stock)
        if t == 0:
            self.prev_stock = S
            self.tier = 0
            return Action.C
        if len(history.opponent_cooperators) > 0:
            k = int(history.opponent_cooperators[-1])
        else:
            k = self.m
        c_obs = 1.0 if self.m <= 0 else k / self.m
        majority_needed = math.ceil(self.m / 2) if self.m > 0 else 0
        majority_coop = k >= majority_needed
        prev_S = self.prev_stock if self.prev_stock is not None else S
        stock_drop = prev_S - S
        dropped_sharply = stock_drop > self.n / 4.0
        if self.m > 0:
            if k < self.m / 2.0 or dropped_sharply:
                self.tier = min(self.tier + 1, 2)
            elif k == self.m and S >= prev_S - self.eps:
                self.tier = self.tier
        else:
            self.tier = 0
        if S < self.n / 2.0:
            self.prev_stock = S
            self.tier = 2
            return Action.D
        if t >= self.r - 1:
            if S >= 2.0 * self.n and majority_coop:
                self.prev_stock = S
                return Action.C
            self.prev_stock = S
            return Action.D
        if S >= self.capacity - self.eps:
            if majority_coop:
                self.prev_stock = S
                return Action.C
            self.prev_stock = S
            return Action.D
        if S >= 1.5 * self.n:
            T = self.T_early
        elif S >= self.n:
            T = self.T_mid
        else:
            T = self.T_late
        half_ok = c_obs > 0.5 or (c_obs == 0.5 and S >= 2.5 * self.n)
        cooperate = S >= T and half_ok and (not dropped_sharply)
        action = Action.C if cooperate else Action.D
        if self.tier >= 2 and S < 2.0 * self.n:
            action = Action.D
        self.prev_stock = S
        return action

class Strategy_COLLECTIVE_88(BaseStrategy):
    """
    Cooperative default strategy with brief defections only as corrective tests
    when cooperation is persistently low and the common stock is under stress.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.last_stock = None
        self.last_action = Action.C
        self.last_q_values = []

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_players = max(2, int(self.game_description.n_players))
        n_opponents = max(1, n_players - 1)
        capacity = float(self.game_description.capacity) if self.game_description.capacity is not None else 0.0
        eps = 1e-12
        round_number = history.round_number
        if round_number == 0:
            action = Action.C
            self.last_stock = float(current_stock)
            self.last_action = action
            return action
        if len(history.opponent_cooperators) > 0:
            recent_counts = history.opponent_cooperators[-2:]
            recent_qs = [float(x) / float(n_opponents) for x in recent_counts]
            Q = float(np.mean(recent_qs)) if len(recent_qs) > 0 else 1.0
        else:
            Q = 1.0
        s = float(current_stock) / capacity if capacity > eps else 0.0
        stock_increased_or_same = self.last_stock is not None and float(current_stock) >= float(self.last_stock) - eps
        if round_number >= int(self.game_description.n_rounds) - 1:
            action = Action.C
            self.last_stock = float(current_stock)
            self.last_action = action
            return action
        if float(current_stock) > 0.0 and float(current_stock) <= 1e-09:
            action = Action.C
            self.last_stock = float(current_stock)
            self.last_action = action
            return action
        if self.last_action == Action.D and (Q >= 0.5 or s <= 0.25):
            action = Action.C
            self.last_stock = float(current_stock)
            self.last_action = action
            return action
        if capacity > eps and float(current_stock) >= capacity - eps:
            if Q < 0.33:
                action = Action.D
            else:
                action = Action.C
            self.last_stock = float(current_stock)
            self.last_action = action
            return action
        if stock_increased_or_same:
            action = self.last_action
            self.last_stock = float(current_stock)
            self.last_action = action
            return action
        if float(current_stock) < float(self.last_stock) - eps and Q < 0.5:
            action = Action.D
            self.last_stock = float(current_stock)
            self.last_action = action
            return action
        if s <= 0.25 or Q >= 0.5 or (Q >= 0.33 and s >= 0.75):
            action = Action.C
        else:
            action = Action.D
        self.last_stock = float(current_stock)
        self.last_action = action
        return action

class Strategy_COLLECTIVE_89(BaseStrategy):
    """
    Stock-preserving quota strategy for the common pool resource game.

    Starts by cooperating, then keeps cooperating while the inferred group
    cooperation remains at or above a dynamic sustainability target.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self._last_stock: float | None = None
        self._last_target: int | None = None
        self._tighten: int = 0
        self._last_observed_group_coop: int | None = None

    def _compute_target(self, stock: float) -> int:
        n = int(self.game_description.n_players)
        capacity = float(self.game_description.capacity)
        if capacity <= 0:
            return 0
        m_t = 1 if n == 2 else max(1, n // 2)
        s_t = stock / capacity
        raw_target = math.ceil(n * s_t)
        raw_target = min(raw_target, max(0, n - 1))
        target = max(m_t, raw_target)
        if self._tighten > 0:
            target = min(max(0, n - 1), target + self._tighten)
        return target

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = int(self.game_description.n_players)
        capacity = float(self.game_description.capacity)
        round_number = int(history.round_number)
        if round_number == 0:
            self._last_stock = float(current_stock)
            self._last_target = self._compute_target(float(current_stock))
            self._last_observed_group_coop = None
            return Action.C
        if history.opponent_cooperators is None or len(history.opponent_cooperators) == 0:
            self._last_stock = float(current_stock)
            self._last_target = self._compute_target(float(current_stock))
            return Action.C
        k_t = int(history.opponent_cooperators[-1])
        my_prev_coop = bool(history.my_actions[-1]) if len(history.my_actions) > 0 else True
        q_t = k_t + (1 if my_prev_coop else 0)
        if self._last_observed_group_coop is not None and self._last_stock is not None and (q_t == self._last_observed_group_coop) and (float(current_stock) < float(self._last_stock)):
            self._tighten = min(max(0, n - 1), self._tighten + 1)
        current_target = self._compute_target(float(current_stock))
        prev_target = self._last_target if self._last_target is not None else current_target
        severe_threshold = capacity / (2.0 * max(1, n))
        if float(current_stock) <= 0.0:
            action = Action.D
        elif float(current_stock) <= severe_threshold and k_t < (1 if n == 2 else max(1, n // 2)):
            action = Action.D
        elif q_t >= prev_target and float(current_stock) > 0.0:
            action = Action.C
        else:
            action = Action.D
        if round_number >= int(self.game_description.n_rounds) - 1:
            if float(current_stock) <= 0.0 or q_t < current_target:
                action = Action.D
            else:
                action = Action.C
        self._last_stock = float(current_stock)
        self._last_target = current_target
        self._last_observed_group_coop = q_t if action == Action.C else k_t
        return action

class Strategy_COLLECTIVE_90(BaseStrategy):
    """
    Stock-preserving common-pool strategy.

    - Cooperates initially.
    - Defects when stock is depleted or in the danger zone.
    - Uses the previous round's cooperation rate to mirror group restraint.
    - Tightens behavior near the end of the game.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.half_capacity = self.capacity / 2.0
        self.third_capacity = self.capacity / 3.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        if round_number == 0:
            return Action.C
        if current_stock <= 0.0:
            return Action.D
        last_my_action = bool(history.my_actions[-1]) if len(history.my_actions) > 0 else True
        last_opponent_cooperators = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else None
        prev_coop_rate = None
        if last_opponent_cooperators is not None and self.n_players > 0:
            total_prev_cooperators = last_opponent_cooperators + (1 if last_my_action else 0)
            prev_coop_rate = total_prev_cooperators / self.n_players
        prev_all_coop = last_opponent_cooperators is not None and last_opponent_cooperators == max(0, self.n_players - 1) and last_my_action
        if prev_all_coop and current_stock >= self.half_capacity:
            return Action.C
        if round_number == self.n_rounds - 1:
            return Action.C if current_stock >= self.half_capacity else Action.D
        if round_number == self.n_rounds - 2:
            if prev_coop_rate is not None:
                if prev_coop_rate >= 0.5 and current_stock >= self.third_capacity:
                    return Action.C
                return Action.D
            return Action.C if current_stock > self.half_capacity else Action.D
        if current_stock >= self.capacity:
            return Action.C
        if current_stock <= self.half_capacity:
            return Action.D
        if prev_coop_rate is None:
            return Action.C if current_stock > self.half_capacity else Action.D
        if prev_coop_rate >= 0.5:
            return Action.C
        return Action.D

class Strategy_COLLECTIVE_91(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Start with cooperation.
    - Cooperate when cooperation and stock are healthy.
    - Defect under low cooperation / strained stock.
    - Use reset, collapse-recovery, escalation, and endgame rules.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.previous_action = Action.C
        self.low_coop_streak = 0
        self.high_coop_streak = 0
        self.defect_lock = False
        self.last_q = None

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        n = max(2, self.n_players)
        capacity = self.capacity
        stock = float(current_stock)
        if round_number == 0:
            self.previous_action = Action.C
            self.low_coop_streak = 0
            self.high_coop_streak = 0
            self.defect_lock = False
            self.last_q = None
            return Action.C
        opp_coop = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        denom = max(1, n - 1)
        q = opp_coop / denom
        self.last_q = q
        if q < 0.5:
            self.low_coop_streak += 1
        else:
            self.low_coop_streak = 0
        if q >= 2 / 3:
            self.high_coop_streak += 1
        else:
            self.high_coop_streak = 0
        if self.low_coop_streak >= 2:
            self.defect_lock = True
        if self.defect_lock and self.high_coop_streak >= 2:
            self.defect_lock = False
        rounds_left = self.n_rounds - round_number
        if rounds_left <= 1:
            return Action.C if q >= 2 / 3 else Action.D
        if rounds_left == 2:
            if stock >= 0.6 * capacity and q >= 0.5:
                self.previous_action = Action.C
                return Action.C
            self.previous_action = Action.D
            return Action.D
        if stock <= 0.3 * capacity:
            action = Action.C if q >= 1.0 else Action.D
            self.previous_action = action
            return action
        if self.defect_lock:
            self.previous_action = Action.D
            return Action.D
        if self.previous_action == Action.D:
            if q >= 2 / 3 and stock >= 0.8 * capacity:
                self.previous_action = Action.C
                return Action.C
            self.previous_action = Action.D
            return Action.D
        if q >= 2 / 3 and stock >= 0.8 * capacity:
            self.previous_action = Action.C
            return Action.C
        if q >= 0.5 and stock >= 0.5 * capacity:
            self.previous_action = Action.C
            return Action.C
        self.previous_action = Action.D
        return Action.D

class Strategy_COLLECTIVE_92(BaseStrategy):
    """
    Stock-preserving threshold strategy with graduated punishment and recovery.
    Cooperate by default, defect when cooperation or stock falls below sustainable levels,
    and recover cooperation promptly once the group stabilizes.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.q_bar = 1.0
        self.in_punishment = False
        self.last_round_seen = -1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = int(history.round_number)
        n = max(self.n, 2)
        capacity = float(self.capacity)
        S = float(current_stock)
        if t == 0:
            self.q_bar = 1.0
            self.in_punishment = False
            self.last_round_seen = 0
            return Action.C
        if t != self.last_round_seen:
            prev_opp_coops = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
            n_opp = max(n - 1, 1)
            q_t = max(0.0, min(1.0, prev_opp_coops / n_opp))
            self.q_bar = 0.7 * self.q_bar + 0.3 * q_t
            self.last_round_seen = t
        else:
            prev_opp_coops = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
            n_opp = max(n - 1, 1)
            q_t = max(0.0, min(1.0, prev_opp_coops / n_opp))
        q_low = 1.0 / 3.0
        q_high = 2.0 / 3.0
        q_star = 0.5
        low_stock = capacity / 4.0
        very_low_stock = capacity / (4.0 * n)
        half_stock = capacity / 2.0
        if t >= self.r - 1:
            if self.q_bar >= q_high and S >= half_stock and (S > 0):
                self.in_punishment = False
                return Action.C
            self.in_punishment = True
            return Action.D
        if S <= very_low_stock:
            self.in_punishment = True
            return Action.D
        if prev_opp_coops < (n - 1) / 3.0:
            self.in_punishment = True
        if self.in_punishment:
            if q_t >= q_high or S >= half_stock:
                self.in_punishment = False
            else:
                return Action.D
        if self.q_bar < q_low or q_t < q_low or S <= low_stock:
            self.in_punishment = True
            return Action.D
        if (self.q_bar >= q_high or q_t >= q_high) and q_t >= q_low:
            if t >= self.r - 2 and S < low_stock:
                self.in_punishment = True
                return Action.D
            self.in_punishment = False
            return Action.C
        if q_low <= self.q_bar < q_high:
            if S >= half_stock:
                return Action.C
            self.in_punishment = True
            return Action.D
        if S >= capacity and self.q_bar >= q_low:
            return Action.C
        if S > 0 and self.q_bar >= q_low:
            return Action.C
        self.in_punishment = True
        return Action.D

class Strategy_COLLECTIVE_93(BaseStrategy):
    """
    Adaptive common-pool strategy with build, hold, and recover modes.
    Starts by cooperating, then responds to previous-round cooperation rates
    and stock recovery dynamics while avoiding hard endgame defection.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.mode = 'build'
        self._last_round_number = None
        self._last_round_start_stock = None
        self._last_round_end_stock = None
        self._consecutive_full_coop = 0

    def _compute_end_stock(self, start_stock: float, my_action: bool, opp_cooperators: int) -> float:
        n = max(2, int(self.game_description.n_players))
        cap = float(self.game_description.capacity)
        if not math.isfinite(start_stock):
            start_stock = cap
        s = min(max(float(start_stock), 0.0), 2.0 * n)
        my_consumption = s / (2.0 * n) if my_action else s / n
        total_consumption = my_consumption + float(opp_cooperators) * (s / (2.0 * n)) + float(n - 1 - opp_cooperators) * (s / n)
        remaining = max(s - total_consumption, 0.0)
        growth = 2.0 * remaining * (1.0 - remaining / cap) if cap > 0 else 0.0
        new_stock = min(remaining + growth, cap)
        return max(new_stock, 0.0)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = max(2, int(self.game_description.n_players))
        cap = float(self.game_description.capacity)
        if history is None or history.round_number == 0:
            self.mode = 'build'
            self._last_round_number = 0
            self._last_round_start_stock = float(current_stock)
            self._last_round_end_stock = None
            self._consecutive_full_coop = 0
            return Action.C
        if history.opponent_cooperators is None or len(history.opponent_cooperators) == 0 or history.my_actions is None or (len(history.my_actions) == 0):
            self._last_round_number = history.round_number
            self._last_round_start_stock = float(current_stock)
            return Action.C
        prev_round_index = history.round_number - 1
        prev_k = int(history.opponent_cooperators[prev_round_index])
        prev_my_action = bool(history.my_actions[prev_round_index])
        if self._last_round_start_stock is not None:
            self._last_round_end_stock = self._compute_end_stock(float(self._last_round_start_stock), prev_my_action, prev_k)
        else:
            self._last_round_end_stock = None
        up = 0
        if self._last_round_end_stock is not None and math.isfinite(float(current_stock)):
            up = 1 if float(current_stock) > float(self._last_round_end_stock) else 0
        if prev_k == n - 1:
            self._consecutive_full_coop += 1
        else:
            self._consecutive_full_coop = 0
        s = float(current_stock)
        if not math.isfinite(s):
            s = cap
        if s <= cap / 3.0:
            self.mode = 'recover'
        if self.mode == 'recover' and self._consecutive_full_coop >= 2 and (s >= 2.0 * cap / 3.0):
            self.mode = 'hold'
        action = Action.C
        rho = 1.0 if n <= 1 else float(prev_k) / float(n - 1)
        if self.mode == 'build':
            if n == 2 and prev_k >= 1 or (n > 2 and rho >= 0.8):
                action = Action.C
            else:
                action = Action.D
                self.mode = 'recover'
        elif self.mode == 'hold':
            action = Action.C if prev_k == n - 1 else Action.D
            if action == Action.D:
                self.mode = 'recover'
        elif prev_k == n - 1 and up == 1:
            action = Action.C
        else:
            action = Action.D
        self._last_round_number = history.round_number
        self._last_round_start_stock = s
        return action

class Strategy_COLLECTIVE_94(BaseStrategy):
    """
    State-dependent cooperation strategy for the Common Pool Resource Game.

    - Cooperates initially.
    - Defects when the stock is depleted or the group recently cooperated poorly.
    - Re-enters cooperation when the stock is healthy and opponent cooperation is strong.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(0, self.n_players - 1)
        self.half_capacity = 0.5 * self.capacity
        self.quarter_capacity = 0.25 * self.capacity
        self.three_quarter_capacity = 0.75 * self.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        if round_number == 0:
            return Action.C
        if current_stock <= 0.0:
            return Action.D
        if len(history.opponent_cooperators) > 0:
            k_prev = int(history.opponent_cooperators[-1])
        else:
            k_prev = self.n_opponents
        if self.n_opponents > 0:
            prev_rate = k_prev / self.n_opponents
        else:
            prev_rate = 1.0
        if round_number == self.n_rounds - 1:
            if current_stock >= self.half_capacity and k_prev >= self.n_opponents / 2.0:
                return Action.C
            return Action.D
        if round_number == 1:
            return Action.C if k_prev >= self.n_opponents else Action.D
        if current_stock <= self.quarter_capacity:
            return Action.D
        if current_stock >= self.three_quarter_capacity:
            return Action.C
        if self.capacity > 0.0:
            q_t = 2.0 * prev_rate + 2.0 * current_stock / self.capacity - 2.0
        else:
            q_t = 0.0
        if q_t < 0.0:
            q_t = 0.0
        elif q_t > 1.0:
            q_t = 1.0
        return Action.C if q_t >= 0.5 else Action.D

class Strategy_COLLECTIVE_95(BaseStrategy):
    """
    Conservative cooperation strategy with brief punishment after low cooperation,
    prioritizing stock preservation and quick recovery to cooperation.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(self.n_players - 1, 0)
        self.half_capacity = self.capacity / 2.0
        self.third_capacity = self.capacity / 3.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        if round_number == 0:
            return Action.C
        if current_stock <= 0.0:
            return Action.D
        if current_stock >= self.capacity:
            return Action.C
        last_round_index = round_number - 1
        opp_last = int(history.opponent_cooperators[-1]) if round_number > 0 else 0
        my_last = bool(history.my_actions[-1]) if round_number > 0 else True
        if last_round_index == self.n_rounds - 1:
            if current_stock >= self.half_capacity and opp_last >= max(self.n_players - 2, 0):
                return Action.C
            return Action.D
        trigger_threshold = max(self.n_players - 2, 0)
        if opp_last < trigger_threshold:
            return Action.D
        if round_number >= 2:
            opp_prev = int(history.opponent_cooperators[-2])
            if opp_prev < trigger_threshold:
                if opp_last >= self.n_opponents and current_stock >= self.half_capacity:
                    return Action.C
                return Action.D
        if opp_last >= self.n_opponents and current_stock >= self.half_capacity:
            return Action.C
        if current_stock < self.third_capacity:
            if opp_last >= self.n_opponents and current_stock >= 2.0 * self.n_players:
                return Action.C
            return Action.D
        if current_stock < self.half_capacity:
            if opp_last >= max(self.n_players - 1, 0):
                return Action.C
            return Action.D
        if current_stock >= self.half_capacity and opp_last >= max(self.n_players - 2, 0):
            return Action.C
        return Action.C if my_last else Action.D

class Strategy_COLLECTIVE_96(BaseStrategy):
    """
    Common-pool strategy with:
    - first-round cooperation,
    - cooperation when opponent cooperation is at least majority,
    - defection when opponent cooperation is very low,
    - and a sticky defection mode after two consecutive low-cooperation rounds.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_opponents = max(0, self.n_players - 1)
        self.capacity = float(game_description.capacity)
        self.last_h = 0
        self.last_q = 1.0
        self.last_was_majority = True
        self.low_q_streak = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            self.last_h = 0
            self.last_q = 1.0
            self.last_was_majority = True
            self.low_q_streak = 0
            return Action.C
        h = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        denom = self.n_opponents if self.n_opponents > 0 else 1
        q = h / denom
        majority = q >= 0.5
        if q < 0.5:
            self.low_q_streak += 1
        else:
            self.low_q_streak = 0
        x = float(current_stock) / self.capacity if self.capacity > 0 else 0.0
        if q >= 0.5:
            action = Action.C
        elif self.low_q_streak >= 2:
            action = Action.D
        elif q <= 0.25:
            action = Action.D
        else:
            action = Action.C if x >= 0.5 else Action.D
        self.last_h = h
        self.last_q = q
        self.last_was_majority = majority
        return action

class Strategy_COLLECTIVE_97(BaseStrategy):
    """
    Cooperative resource-preservation strategy for a common-pool resource game.

    Default action is cooperation. Defection is used as a short corrective signal
    when the observed cooperation level drops below a sustainability threshold or
    the stock becomes too low.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(self.n_players - 1, 0)
        self.coop_threshold = int(math.ceil(2 * self.n_opponents / 3)) if self.n_opponents > 0 else 0
        self.stock_threshold = float(2 * self.n_players + 1)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C if current_stock >= self.stock_threshold else Action.D
        if current_stock < self.stock_threshold:
            return Action.D
        if history.round_number >= self.n_rounds - 1:
            if len(history.opponent_cooperators) > 0:
                last_k = int(history.opponent_cooperators[-1])
                return Action.C if last_k >= self.coop_threshold else Action.D
            return Action.C
        last_k = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        if last_k >= self.coop_threshold:
            return Action.C
        return Action.D

class Strategy_COLLECTIVE_98(BaseStrategy):
    """
    Adaptive cooperation strategy for the Common Pool Resource Game.

    - Cooperate in round 1.
    - In later rounds, cooperate iff the previous round's total cooperation
      met the stock-dependent threshold:
        tau = ceil(n * (1 - S / (2 * capacity)))
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        n = self.n
        capacity = self.capacity
        S = float(current_stock)
        if not math.isfinite(S):
            S = capacity
        if capacity <= 0:
            tau = n
        else:
            S = max(0.0, min(S, capacity))
            tau = math.ceil(n * (1.0 - S / (2.0 * capacity)))
        last_my_action = bool(history.my_actions[-1])
        m_prev = int(history.opponent_cooperators[-1]) + (1 if last_my_action else 0)
        return Action.C if m_prev >= tau else Action.D

class Strategy_COLLECTIVE_99(BaseStrategy):
    """
    Common-pool strategy:
    - Cooperate in the first and final rounds.
    - In intermediate rounds, adapt cooperation thresholds to current stock:
      tighter when the pool is low, more permissive when the pool is healthy.
    - If prior observation data is unavailable, cooperate only in round 1
      and defect otherwise until observations exist.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self._n_opponents = max(self.n_players - 1, 0)
        self._low_threshold = math.ceil(self._n_opponents / 3) if self._n_opponents > 0 else 0
        self._mid_threshold = math.ceil(self._n_opponents / 2) if self._n_opponents > 0 else 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        if round_number == 0:
            return Action.C
        if round_number >= self.n_rounds - 1:
            return Action.C
        if len(history.opponent_cooperators) == 0:
            return Action.D
        observed_cooperators = int(history.opponent_cooperators[-1])
        stock = float(current_stock)
        if self.n_players == 2:
            return Action.C if observed_cooperators >= 1 else Action.D
        if stock <= self.capacity / 3.0:
            return Action.C if observed_cooperators >= self._low_threshold else Action.D
        if stock <= 2.0 * self.capacity / 3.0:
            return Action.C if observed_cooperators >= self._mid_threshold else Action.D
        if observed_cooperators >= self._mid_threshold:
            return Action.C
        if observed_cooperators == self._n_opponents:
            return Action.C
        return Action.D

class Strategy_COLLECTIVE_100(BaseStrategy):
    """
    Cooperative-first strategy with short corrective defections under sustained low cooperation,
    and immediate recovery to cooperation when cooperation or stock conditions improve.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        n = int(game_description.n_players)
        if n <= 2:
            self.high_coop = 1
            self.low_coop = 0
        else:
            self.high_coop = math.ceil((n - 1) / 2)
            self.low_coop = math.floor((n - 1) / 3)
        self.capacity = float(game_description.capacity)
        self.half_capacity = self.capacity / 2.0
        self.last_my_action = Action.C
        self.last_low_opponent_coop = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        stock = float(current_stock)
        if round_number > 0 and len(history.opponent_cooperators) > 0:
            last_opponent_coop = int(history.opponent_cooperators[-1])
        else:
            last_opponent_coop = 0
        very_low_stock = stock <= 1e-12 or stock < self.half_capacity
        if round_number == 0:
            self.last_my_action = Action.C
            self.last_low_opponent_coop = False
            return Action.C
        if round_number == self.game_description.n_rounds - 1:
            if last_opponent_coop >= self.high_coop or very_low_stock:
                self.last_my_action = Action.C
                self.last_low_opponent_coop = False
                return Action.C
            self.last_my_action = Action.D
            self.last_low_opponent_coop = last_opponent_coop <= self.low_coop
            return Action.D
        if self.last_my_action == Action.D:
            if last_opponent_coop >= self.high_coop or very_low_stock:
                self.last_my_action = Action.C
                self.last_low_opponent_coop = False
                return Action.C
            if last_opponent_coop <= self.low_coop and (not very_low_stock):
                self.last_my_action = Action.D
                self.last_low_opponent_coop = True
                return Action.D
            self.last_my_action = Action.C
            self.last_low_opponent_coop = False
            return Action.C
        if last_opponent_coop >= self.high_coop or very_low_stock or last_opponent_coop > self.low_coop:
            self.last_my_action = Action.C
            self.last_low_opponent_coop = False
            return Action.C
        self.last_my_action = Action.D
        self.last_low_opponent_coop = True
        return Action.D

class Strategy_COLLECTIVE_101(BaseStrategy):
    """
    Stock-preserving threshold policy with aggregate reciprocity:
    cooperate early, reward sustained cooperation, punish over-extraction,
    and become stricter in the final rounds or under low-stock conditions.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(getattr(game_description, 'n_players', 0))
        self.n_rounds = int(getattr(game_description, 'n_rounds', 0))
        self.capacity = float(getattr(game_description, 'capacity', 1.0))
        self.n_opponents = max(self.n_players - 1, 0)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(getattr(history, 'round_number', 0))
        if round_number == 0:
            return Action.C
        opp_counts = getattr(history, 'opponent_cooperators', None)
        if opp_counts is None or len(opp_counts) == 0:
            return Action.C if round_number == 0 else Action.D
        last_k = int(opp_counts[-1])
        m_t = self.n_opponents
        if m_t > 0:
            p_t = last_k / m_t
        else:
            p_t = 1.0
        cap = self.capacity if self.capacity > 0 else 1.0
        S_t = float(current_stock)
        x_t = S_t / cap

        def clamp(val: float, lo: float, hi: float) -> float:
            return max(lo, min(hi, val))
        q_t = clamp(2.0 * p_t - 1.0, 0.0, 1.0)
        _s_t = clamp((x_t - 0.5) / 0.5, 0.0, 1.0)
        rounds_left = self.n_rounds - round_number
        if rounds_left <= 2:
            if p_t == 1.0 and x_t >= 0.5:
                return Action.C
            return Action.D
        if S_t <= cap / 8.0:
            return Action.D
        if S_t <= cap / 4.0:
            return Action.D
        if S_t >= 3.0 * cap / 4.0 and p_t >= 0.5:
            return Action.C
        if q_t >= 0.5 and x_t >= 0.25 or p_t >= 0.75:
            return Action.C
        return Action.D

class Strategy_COLLECTIVE_102(BaseStrategy):
    """
    Conditional cooperation strategy for the Common Pool Resource Game.

    - Cooperate in the first round.
    - Cooperate whenever cooperation in the previous round was strong or acceptable.
    - Defect for at most one consecutive round when cooperation is low.
    - Always cooperate in the final round or when stock is depleted.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.acceptable_threshold = int(math.ceil(self.n_players / 2))
        self.strong_threshold = max(0, self.n_players - 1)
        self.capacity_quarter = self.capacity / 4.0 if self.capacity > 0 else 0.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        if round_number == 0:
            return Action.C
        if round_number >= self.n_rounds - 1 or current_stock <= 0:
            return Action.C
        k = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        my_last_action = bool(history.my_actions[-1]) if len(history.my_actions) > 0 else True
        T = k + 1 if my_last_action else k
        strong_coop = T >= self.strong_threshold
        acceptable_coop = T >= self.acceptable_threshold
        low_coop = T < self.acceptable_threshold
        if strong_coop:
            return Action.C
        if acceptable_coop:
            return Action.C
        if low_coop:
            if my_last_action:
                return Action.D
            return Action.C
        return Action.C

class Strategy_COLLECTIVE_103(BaseStrategy):
    """
    Stock-preserving conditional cooperator with recovery, maintenance, and endgame regimes.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self._n_opponents = max(self.n_players - 1, 0)
        self._coop_threshold = (self.n_players - 2) / self._n_opponents if self._n_opponents > 0 else 1.0
        self._recovery_threshold = self.n_players / 2.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number
        S_t = float(current_stock)
        if t == 0:
            return Action.C
        if S_t == 0:
            return Action.C
        if t >= self.n_rounds - 1:
            return Action.C if S_t >= self._recovery_threshold else Action.D
        if S_t < self._recovery_threshold:
            return Action.C
        if self._n_opponents <= 0:
            return Action.C
        last_opponent_cooperators = int(history.opponent_cooperators[-1]) if history.opponent_cooperators.size > 0 else 0
        observed_coop_rate = last_opponent_cooperators / self._n_opponents
        if observed_coop_rate >= self._coop_threshold:
            return Action.C
        return Action.D

class Strategy_COLLECTIVE_104(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Cooperate in round 1.
    - Track opponent cooperation rate and expected stock regeneration.
    - Prefer cooperation when opponents are at least half cooperative and the stock path supports recovery.
    - Prefer defection when opponent cooperation is low or cooperation would clearly worsen the stock trajectory.
    - Apply mild persistence to avoid overreacting to single-round fluctuations.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(0, self.n_players - 1)
        self.last_action = Action.C
        self.low_opponent_streak = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.n_players
        opponents = self.n_opponents
        cap = self.capacity
        if history.round_number == 0:
            self.last_action = Action.C
            self.low_opponent_streak = 0
            return Action.C
        last_k = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        if opponents > 0:
            p = last_k / opponents
        else:
            p = 1.0
        if p < 0.5:
            self.low_opponent_streak += 1
        else:
            self.low_opponent_streak = 0
        if history.round_number >= self.n_rounds - 1:
            action = Action.C if p >= 0.5 else Action.D
            self.last_action = action
            return action
        effective_stock = min(float(current_stock), 2.0 * n)
        sc = effective_stock / 2.0
        next_if_all_c = sc + 2.0 * sc * (1.0 - sc / cap) if cap > 0 else sc
        next_if_all_c = min(next_if_all_c, cap)
        if p >= 0.5 and next_if_all_c >= current_stock:
            action = Action.C
        elif p < 0.5 and next_if_all_c < current_stock:
            action = Action.D
        elif p >= 0.5 and next_if_all_c < current_stock:
            action = Action.C if p >= 2.0 / 3.0 else Action.D
        else:
            action = Action.C if p >= 1.0 / 3.0 else Action.D
        if current_stock >= cap:
            action = Action.D if p == 0 else Action.C
        elif current_stock <= n:
            action = Action.D if p < 0.5 else Action.C
        if len(history.opponent_cooperators) >= 2:
            prev_k = int(history.opponent_cooperators[-2])
            prev_p = prev_k / opponents if opponents > 0 else 1.0
        else:
            prev_p = p
        prev_action = Action.C if bool(history.my_actions[-1]) else Action.D
        if prev_p >= 0.5 and prev_action == Action.C and (action == Action.D):
            action = Action.C
        if self.low_opponent_streak >= 2 and p < 0.5:
            action = Action.D
        self.last_action = action
        return action

class Strategy_COLLECTIVE_105(BaseStrategy):
    """
    Cooperative default strategy with a short corrective defection mode.

    Rules:
    - Cooperate in the first round.
    - Track the most recent round's total cooperation rate.
    - If the last round was sustainable (at least half cooperated), cooperate.
    - If cooperation drops below half, defect briefly as a signal.
    - If stock is low, require a stricter cooperation threshold (two-thirds).
    - Resume cooperation immediately once the relevant threshold is restored.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.safe_threshold = 0.5
        self.low_stock_threshold = self.capacity / 3.0 if self.capacity > 0 else 0.0
        self.strict_threshold = 2.0 / 3.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        if round_number == 0:
            return Action.C
        last_my_action = bool(history.my_actions[-1])
        last_opponent_cooperators = int(history.opponent_cooperators[-1])
        last_total_cooperators = last_opponent_cooperators + (1 if last_my_action else 0)
        if self.n_players > 0:
            last_cooperation_rate = last_total_cooperators / self.n_players
        else:
            last_cooperation_rate = 0.0
        low_streak = 0
        for idx in range(round_number - 1, -1, -1):
            opp_c = int(history.opponent_cooperators[idx])
            my_c = 1 if bool(history.my_actions[idx]) else 0
            total_c = opp_c + my_c
            rate = total_c / self.n_players if self.n_players > 0 else 0.0
            if rate < self.safe_threshold:
                low_streak += 1
            else:
                break
        if round_number == self.n_rounds - 1:
            return Action.C if last_cooperation_rate >= self.safe_threshold else Action.D
        stock_is_low = current_stock <= self.low_stock_threshold
        if stock_is_low:
            if last_cooperation_rate >= self.strict_threshold:
                return Action.C
            return Action.D
        if low_streak == 0:
            return Action.C
        if low_streak == 1:
            return Action.D
        return Action.D

class Strategy_COLLECTIVE_106(BaseStrategy):
    """
    Cooperate initially, then use a stock-aware threshold rule:
    - Rebuild when stock is low.
    - Cooperate if the previous round had at least half cooperators.
    - Otherwise defect.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(getattr(game_description, 'n_players', 0) or 0)
        self.n_rounds = int(getattr(game_description, 'n_rounds', 0) or 0)
        self.capacity = float(getattr(game_description, 'capacity', 0.0) or 0.0)
        self.threshold = math.ceil(self.n_players / 2) if self.n_players > 0 else 0
        self.low_stock_threshold = self.capacity / 3.0 if self.capacity == self.capacity else 0.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        n_players = self.n_players
        if n_players <= 0:
            return Action.C
        try:
            if current_stock <= self.low_stock_threshold:
                return Action.C
        except Exception:
            return Action.C
        k_prev = None
        try:
            opponents_coop = int(history.opponent_cooperators[-1])
            my_last_action = bool(history.my_actions[-1])
            if my_last_action:
                k_prev = opponents_coop + 1
            else:
                k_prev = opponents_coop
        except Exception:
            k_prev = None
        if k_prev is None:
            return Action.C
        if k_prev >= self.threshold:
            return Action.C
        return Action.D

class Strategy_COLLECTIVE_107(BaseStrategy):
    """
    Cooperative default strategy that conditions actions on stock health,
    recent cooperation, persistence, and endgame recovery signals.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = max(2, int(game_description.n_players))
        self.r = max(2, int(game_description.n_rounds))
        self.capacity = float(game_description.capacity)
        self.last_action = Action.C
        self.defect_cooldown = 0
        self.emergency_mode = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.n
        capacity = self.capacity
        round_number = history.round_number
        S = float(current_stock)
        if not math.isfinite(S):
            S = capacity
        S = max(0.0, min(S, capacity))
        if round_number == 0:
            self.last_action = Action.C
            self.defect_cooldown = 0
            self.emergency_mode = False
            return Action.C
        opp = history.opponent_cooperators
        last_opp_coop = int(opp[-1]) if len(opp) > 0 else 0
        last_total_coop = last_opp_coop + (1 if bool(history.my_actions[-1]) else 0)
        prev_opp_coop = int(opp[-2]) if len(opp) >= 2 else None
        prev_total_coop = None
        if prev_opp_coop is not None:
            prev_total_coop = prev_opp_coop + (1 if bool(history.my_actions[-2]) else 0)
        if self.last_action == Action.C:
            m = last_opp_coop + 1
        else:
            m = last_opp_coop
        q = m / n if n > 0 else 0.0
        low_stock = S < capacity / 3.0
        mid_stock = capacity / 3.0 <= S < capacity / 2.0
        high_stock = S >= capacity / 2.0
        sharp_fall = False
        if len(opp) >= 2:
            if int(opp[-1]) < max(0, int(opp[-2]) - 1):
                sharp_fall = True
        if len(history.my_payoffs) >= 2:
            if float(history.my_payoffs[-1]) < float(history.my_payoffs[-2]) - 1e-12:
                sharp_fall = sharp_fall or S < capacity / 2.0
        if sharp_fall and S < capacity / 2.0:
            self.emergency_mode = True
        if S >= capacity * 0.95:
            self.emergency_mode = False
        if round_number >= 1:
            prev_round_all_coop = last_total_coop >= n
            if prev_round_all_coop:
                if last_opp_coop >= max(0, n - 1):
                    self.last_action = Action.C
                    self.defect_cooldown = 0
                    return Action.C
        if last_total_coop < n / 2.0:
            self.defect_cooldown = max(self.defect_cooldown, 1)
        if self.defect_cooldown > 0:
            self.defect_cooldown -= 1
            if S >= capacity and last_total_coop >= 2.0 * n / 3.0:
                self.last_action = Action.C
                return Action.C
            self.last_action = Action.D
            return Action.D
        if len(opp) >= 2:
            if int(opp[-1]) + 1 >= math.ceil(2.0 * n / 3.0) and int(opp[-2]) + 1 >= math.ceil(2.0 * n / 3.0):
                if S > capacity / 6.0:
                    self.last_action = Action.C
                    return Action.C
        rounds_left = self.r - round_number
        if rounds_left <= 2:
            if S > capacity / 2.0:
                self.last_action = Action.C
                return Action.C
            if S < capacity / 3.0:
                if last_total_coop >= n:
                    self.last_action = Action.C
                    return Action.C
                self.last_action = Action.D
                return Action.D
            if last_total_coop >= 2.0 * n / 3.0:
                self.last_action = Action.C
                return Action.C
            self.last_action = Action.D
            return Action.D
        if self.emergency_mode:
            if last_total_coop >= n - 1 and S > capacity / 6.0:
                self.last_action = Action.C
                return Action.C
            self.last_action = Action.D
            return Action.D
        action = Action.D
        if high_stock:
            if q >= 0.5:
                action = Action.C
        elif mid_stock:
            if q >= 2.0 / 3.0:
                action = Action.C
        elif q >= 1.0:
            action = Action.C
        if last_total_coop < n / 2.0 and S < capacity:
            action = Action.D
        if last_total_coop >= n - 1 and S > 0.0:
            if S >= capacity / 3.0 or q >= 2.0 / 3.0:
                action = Action.C
        self.last_action = action
        if action == Action.D and last_total_coop < n / 2.0:
            self.defect_cooldown = max(self.defect_cooldown, 1)
        return action

class Strategy_COLLECTIVE_108(BaseStrategy):
    """
    State-based threshold strategy for the Common Pool Resource Game.

    Core idea:
    - Cooperate when stock is healthy and recent opponent cooperation is strong.
    - Defect quickly when stock is weak or cooperation collapses.
    - Use short memory smoothing and a temporary punishment after universal defection.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(self.n_players - 1, 1)
        self.half_capacity = self.capacity / 2.0
        self.third_capacity = self.capacity / 3.0
        self.two_thirds_capacity = 2.0 * self.capacity / 3.0
        self.punishment_until_round = -1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        if round_number == 0:
            return Action.C
        last_opponent_cooperators = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        last_round_rate = last_opponent_cooperators / self.n_opponents if self.n_opponents > 0 else 0.0
        recent_counts = history.opponent_cooperators[-3:] if len(history.opponent_cooperators) > 0 else np.array([], dtype=int)
        if len(recent_counts) > 0:
            recent_rates = recent_counts.astype(float) / self.n_opponents
            coop_3_round_avg = float(np.mean(recent_rates))
        else:
            coop_3_round_avg = 0.0
        if last_opponent_cooperators == 0:
            self.punishment_until_round = max(self.punishment_until_round, round_number + 2)
        if round_number == self.n_rounds - 1:
            return Action.C if current_stock >= self.half_capacity else Action.D
        if current_stock < self.third_capacity:
            return Action.D
        if round_number < self.punishment_until_round and current_stock < self.two_thirds_capacity:
            return Action.D
        if last_opponent_cooperators == self.n_opponents and current_stock >= self.half_capacity:
            return Action.C
        if coop_3_round_avg >= 2.0 / 3.0 and current_stock >= self.half_capacity:
            return Action.C
        if coop_3_round_avg <= 1.0 / 3.0:
            return Action.D
        if current_stock >= self.half_capacity and last_round_rate >= 0.5:
            return Action.C
        return Action.D

class Strategy_COLLECTIVE_109(BaseStrategy):
    """
    Stock-preserving threshold strategy with gradual punishment and recovery.
    Cooperation depends on current stock health and a memory score derived from
    recent opponent cooperation.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self._memory = 0
        self._last_seen_round = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = max(2, int(self.game_description.n_players))
        r = max(2, int(self.game_description.n_rounds))
        capacity = float(self.game_description.capacity)
        round_number = int(history.round_number)
        m = 0
        if round_number > 0:
            for k in history.opponent_cooperators[:round_number]:
                denom = max(1, n - 1)
                q = float(k) / float(denom)
                if q >= 0.75:
                    if q >= 1.0:
                        m = 3
                    else:
                        m = min(m + 1, 3)
                elif q < 0.4:
                    if q <= 0.0:
                        m = -3
                    else:
                        m = max(m - 1, -3)
        self._memory = m
        self._last_seen_round = round_number
        S_t = float(current_stock)
        if S_t <= 0.0:
            return Action.D
        if S_t < float(2 * n):
            return Action.D
        if round_number == 0:
            return Action.C if capacity >= float(2 * n) else Action.D
        if round_number == r - 1:
            return Action.C if capacity > 0.0 and S_t / capacity >= 0.3 else Action.D
        x_t = S_t / capacity if capacity > 0.0 else 0.0
        T_t = 0.35 + 0.1 * max(0, -m) - 0.05 * min(m, 2)
        if x_t >= T_t and S_t >= float(2 * n):
            return Action.C
        return Action.D

class Strategy_COLLECTIVE_110(BaseStrategy):
    """
    Stock-preserving threshold strategy with forgiving retaliation.

    - Cooperates initially.
    - Uses observed opponent cooperation rate and current stock to decide.
    - Retaliates after clear under-cooperation, but returns to cooperation
      when cooperation again supports recovery.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(self.n_players - 1, 0)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number
        if t == 0:
            return Action.C
        cap = self.capacity if self.capacity > 0 else 1.0
        s = float(current_stock)
        s = max(0.0, s)
        prev_c = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        prev_rate = prev_c / self.n_opponents if self.n_opponents > 0 else 0.0
        theta = 0.5 + s / (2.0 * cap)
        if t >= self.n_rounds - 1:
            if s <= 0.0:
                return Action.D
            return Action.C if prev_rate >= theta else Action.D
        if s < cap / 8.0:
            return Action.C if prev_c == self.n_opponents else Action.D
        if s >= 3.0 * cap / 4.0:
            if prev_rate < 0.5:
                return Action.D
            return Action.C
        if prev_rate <= 0.5:
            return Action.D
        if s >= cap / 4.0 and prev_rate >= theta:
            return Action.C
        return Action.D

class Strategy_COLLECTIVE_111(BaseStrategy):
    """
    State-contingent conditional cooperation with short punishment, recovery,
    and stock-protection overrides.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(self.n_players - 1, 1)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        if round_number == 0:
            return Action.C
        last_opp_coop = int(history.opponent_cooperators[-1]) if round_number > 0 else 0
        q = last_opp_coop / self.n_opponents if self.n_opponents > 0 else 1.0
        prev_action_is_coop = bool(history.my_actions[-1])
        t = round_number + 1
        r = self.n_rounds
        half_cap = self.capacity / 2.0
        third_cap = self.capacity / 3.0
        two_thirds_cap = 2.0 * self.capacity / 3.0
        thresh_full_like = 1.0 - 1.0 / self.n_opponents if self.n_opponents > 0 else 1.0
        thresh_one_defect = 1.0 - 2.0 / self.n_opponents if self.n_opponents > 0 else 1.0
        thresh_full_like = max(0.0, min(1.0, thresh_full_like))
        thresh_one_defect = max(0.0, min(1.0, thresh_one_defect))
        if t == r:
            return Action.C if q >= thresh_full_like else Action.D
        if t == r - 1:
            if current_stock <= half_cap:
                return Action.C
            if q >= thresh_full_like:
                return Action.C
            if current_stock > two_thirds_cap and q < thresh_one_defect:
                return Action.D
            if q >= thresh_one_defect and prev_action_is_coop:
                return Action.C
            return Action.D
        if current_stock < third_cap:
            return Action.C
        if current_stock <= half_cap:
            return Action.C
        if current_stock > two_thirds_cap and q < thresh_one_defect:
            return Action.D
        if q >= thresh_full_like:
            return Action.C
        if q >= thresh_one_defect and prev_action_is_coop:
            return Action.C
        return Action.D

class Strategy_COLLECTIVE_112(BaseStrategy):
    """
    Guarded conditional-cooperation strategy for the Common Pool Resource Game.
    It begins cooperatively, tracks a smoothed estimate of opponent cooperation,
    and becomes cautious under low stock or clear exploitation signals.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.m = max(0, self.n_players - 1)
        self.lambda_ = 0.5
        self.smoothed_cooperation = 1.0
        self.last_processed_round = 0
        self.last_observed_k = None

    def _sync_history(self, history: PlayerHistory) -> None:
        """Update internal rolling state using any newly observed rounds."""
        rn = int(history.round_number)
        start = self.last_processed_round
        if rn <= start:
            return
        for idx in range(start, rn):
            if self.m > 0 and idx < len(history.opponent_cooperators):
                k_t = int(history.opponent_cooperators[idx])
                c_t = k_t / self.m if self.m > 0 else 0.0
                self.smoothed_cooperation = (1.0 - self.lambda_) * self.smoothed_cooperation + self.lambda_ * c_t
                self.last_observed_k = k_t
            elif self.m == 0:
                self.last_observed_k = 0
            self.last_processed_round = idx + 1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        self._sync_history(history)
        t = int(history.round_number) + 1
        S_t = float(current_stock)
        capacity = self.capacity
        m = self.m
        if history.round_number == 0:
            return Action.C
        if m == 0:
            return Action.C
        if S_t < capacity / 4.0:
            if len(history.opponent_cooperators) >= 2:
                if int(history.opponent_cooperators[-1]) == m and int(history.opponent_cooperators[-2]) == m:
                    pass
                else:
                    return Action.D
            else:
                return Action.D
        last_k = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        prev_all_defect = last_k == 0
        prev_all_coop = last_k == m
        if t >= self.n_rounds:
            if S_t <= 0.0:
                return Action.D
            return Action.C if self.smoothed_cooperation >= 0.5 else Action.D
        if prev_all_defect:
            return Action.D
        if prev_all_coop and S_t >= capacity / 2.0:
            return Action.C
        if m == 1:
            if len(history.opponent_cooperators) == 0:
                return Action.C
            return Action.C if last_k == 1 else Action.D
        theta_t = max(0.5, 1.0 - (S_t / capacity if capacity > 0 else 1.0))
        if capacity > 0:
            S_half = S_t / 2.0
            S_full = min(S_t - S_half + 2.0 * S_half * (1.0 - S_half / capacity), capacity)
        else:
            S_full = 0.0
        S_def = 0.0
        required_majority = math.ceil(m / 2.0)
        if self.smoothed_cooperation >= theta_t and S_t >= capacity / 2.0 and (last_k >= required_majority or t == 2):
            return Action.C
        return Action.D

class Strategy_COLLECTIVE_113(BaseStrategy):
    """
    Collective-discipline strategy for the Common Pool Resource Game.

    - Round 1: cooperate.
    - Later rounds: cooperate when the stock is strained or the last round was sufficiently cooperative.
    - Defect only as a short corrective response when cooperation dropped and the stock is still healthy.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self._healthy_threshold = 0.8 * self.capacity
        self._strained_threshold = 0.35 * self.capacity
        self._coop_opponents_threshold = math.ceil((self.n_players - 1) / 2)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        if round_number == 0:
            return Action.C
        prev_coop_opponents = 0
        if len(history.opponent_cooperators) > 0:
            prev_coop_opponents = int(history.opponent_cooperators[-1])
        if current_stock <= self._strained_threshold:
            return Action.C
        if prev_coop_opponents >= self._coop_opponents_threshold:
            return Action.C
        if current_stock >= self._healthy_threshold:
            return Action.D
        return Action.C

class Strategy_COLLECTIVE_114(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Starts with cooperation.
    - Tracks whether opponents have recently broken unanimity.
    - Enters a short guarded mode after any non-unanimous round.
    - Reverts to cooperation after stable unanimous cooperation resumes.
    - Defends the resource when stock is low or trust has been broken.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self._guarded_remaining = 0
        self._last_seen_stock = None
        self._eps = 1e-12

    def _last_unanimous_streak(self, history: PlayerHistory) -> int:
        streak = 0
        opp = history.opponent_cooperators
        for idx in range(len(opp) - 1, -1, -1):
            if int(opp[idx]) >= self.n_players - 1:
                streak += 1
            else:
                break
        return streak

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        if round_number == 0:
            self._last_seen_stock = float(current_stock)
            return Action.C
        n_opponents = max(self.n_players - 1, 0)
        previous_opponents_cooperated = int(history.opponent_cooperators[-1]) >= n_opponents
        stock_increased = self._last_seen_stock is not None and float(current_stock) > float(self._last_seen_stock) + self._eps
        if not previous_opponents_cooperated:
            self._guarded_remaining = 2
        elif self._guarded_remaining > 0:
            streak = self._last_unanimous_streak(history)
            if streak >= 2:
                self._guarded_remaining = 0
        is_last_round = round_number == self.n_rounds - 1
        moderate_level = self.capacity / 2.0
        high_level = 3.0 * self.capacity / 4.0
        if is_last_round:
            action = Action.C if previous_opponents_cooperated else Action.D
            self._last_seen_stock = float(current_stock)
            if self._guarded_remaining > 0:
                self._guarded_remaining = max(0, self._guarded_remaining - 1)
            return action
        if previous_opponents_cooperated and stock_increased:
            action = Action.C
        elif self._guarded_remaining > 0:
            action = Action.C if previous_opponents_cooperated and stock_increased else Action.D
        else:
            if previous_opponents_cooperated:
                if current_stock >= moderate_level:
                    action = Action.C
                else:
                    action = Action.C if stock_increased else Action.D
            else:
                action = Action.D
            if current_stock < moderate_level and (not previous_opponents_cooperated):
                action = Action.D
            if current_stock >= high_level and previous_opponents_cooperated:
                action = Action.C
        if self._guarded_remaining > 0:
            self._guarded_remaining = max(0, self._guarded_remaining - 1)
        self._last_seen_stock = float(current_stock)
        return action

class Strategy_COLLECTIVE_115(BaseStrategy):
    """
    Conditional cooperation with emergency protection and collective sanctioning.

    - Round 1: cooperate.
    - Enter emergency defense when stock falls below 50% of capacity.
    - Stay in emergency defense until stock is at least 60% of capacity and
      the last observed round had at least n-2 cooperating opponents.
    - Outside emergency, cooperate after full opponent cooperation; otherwise defect.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.emergency_active = False
        self.last_seen_round = -1
        self.last_seen_opponent_coop = None

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = int(self.game_description.n_players)
        capacity = float(self.game_description.capacity)
        if history.round_number == 0:
            self.emergency_active = False
            self.last_seen_round = 0
            self.last_seen_opponent_coop = None
            return Action.C
        s = 0.0 if capacity <= 0.0 else float(current_stock) / capacity
        last_opponent_coop = int(history.opponent_cooperators[-1]) if history.round_number > 0 else 0
        if self.emergency_active:
            if s >= 0.6 and last_opponent_coop >= max(0, n - 2):
                self.emergency_active = False
            else:
                self.last_seen_round = history.round_number
                self.last_seen_opponent_coop = last_opponent_coop
                return Action.D
        if s < 0.5:
            self.emergency_active = True
            self.last_seen_round = history.round_number
            self.last_seen_opponent_coop = last_opponent_coop
            return Action.D
        if last_opponent_coop >= max(0, n - 1):
            action = Action.C
        else:
            action = Action.D
        self.last_seen_round = history.round_number
        self.last_seen_opponent_coop = last_opponent_coop
        return action

class Strategy_COLLECTIVE_116(BaseStrategy):
    """
    Adaptive common-pool strategy with stock protection, cooperation tracking,
    and temporary retaliation after low-opposition-cooperation rounds.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(0, self.n_players - 1)
        self.retaliation_mode = False
        self.coop_rate_history = []
        self._base_thr_recovery = 0.75
        self._base_thr_stable = 0.6
        self._base_thr_last = 0.5
        self._base_thr_retaliation_enter = 0.5
        self._base_thr_retaliation_exit = 0.75
        self._base_thr_critical = 0.35
        self._base_thr_buffer = 0.65
        self._base_thr_second_last_buffer = 0.55
        self._base_thr_second_last_highcoop = 0.8
        if self.n_players == 2:
            self._base_thr_recovery += 0.1
            self._base_thr_stable += 0.1
            self._base_thr_last += 0.1
            self._base_thr_retaliation_enter += 0.1
            self._base_thr_retaliation_exit += 0.1
            self._base_thr_critical += 0.1
            self._base_thr_buffer += 0.1
            self._base_thr_second_last_buffer += 0.1
            self._base_thr_second_last_highcoop += 0.1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_num = int(history.round_number)
        capacity = self.capacity
        stock = float(current_stock)
        if round_num <= 0:
            return Action.C
        if self.n_opponents > 0 and len(history.opponent_cooperators) > 0:
            last_q = float(history.opponent_cooperators[-1]) / float(self.n_opponents)
        else:
            last_q = 1.0
        if len(self.coop_rate_history) < round_num - 1 and self.n_opponents > 0:
            observed = np.asarray(history.opponent_cooperators, dtype=float) / float(self.n_opponents)
            self.coop_rate_history = list(observed.tolist())
        if round_num == 1:
            m_t = 1.0
        elif len(self.coop_rate_history) >= round_num - 1:
            m_t = float(np.mean(self.coop_rate_history[:round_num - 1])) if round_num - 1 > 0 else 1.0
        else:
            m_t = 1.0
        critical = self._base_thr_critical * capacity
        buffer = self._base_thr_buffer * capacity
        second_last_buffer = self._base_thr_second_last_buffer * capacity
        last_threshold = self._base_thr_last * capacity
        if round_num == self.n_rounds:
            action = Action.C if stock >= last_threshold else Action.D
        else:
            if last_q < self._base_thr_retaliation_enter:
                self.retaliation_mode = True
            if self.retaliation_mode:
                action = Action.D
                if last_q >= self._base_thr_retaliation_exit or stock >= buffer:
                    self.retaliation_mode = False
            elif stock <= critical:
                action = Action.D
            elif round_num == self.n_rounds - 1:
                if last_q >= self._base_thr_second_last_highcoop:
                    action = Action.C if stock >= second_last_buffer else Action.D
                else:
                    action = Action.C if stock >= second_last_buffer else Action.D
            elif stock < buffer:
                action = Action.C if last_q >= self._base_thr_recovery and m_t >= self._base_thr_recovery else Action.D
            else:
                action = Action.C if m_t >= self._base_thr_stable else Action.D
        if round_num >= 1 and self.n_opponents > 0:
            self.coop_rate_history.append(last_q)
        return action

class Strategy_COLLECTIVE_117(BaseStrategy):
    """
    Common pool resource strategy:
    - Cooperate on round 1.
    - Afterwards, cooperate when the stock is healthy and recent cooperation is sufficiently broad.
    - If the stock becomes too low, enter a defensive defection mode until recovery conditions are met.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_opponents = max(self.n_players - 1, 0)
        self.capacity = float(game_description.capacity)
        self.cooperative = True
        self._cap = self.capacity if self.capacity > 0 else 1.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        if round_number == 0:
            self.cooperative = True
            return Action.C
        o_t = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        S_t = float(current_stock)
        cap_third = self._cap / 3.0
        cap_half = self._cap / 2.0
        cap_two_thirds = 2.0 * self._cap / 3.0
        ceil_two_thirds_opps = math.ceil(2.0 * self.n_opponents / 3.0)
        ceil_half_opps = math.ceil(self.n_opponents / 2.0)
        if not self.cooperative:
            if S_t > cap_half and o_t >= ceil_half_opps:
                self.cooperative = True
            else:
                return Action.D
        if S_t <= cap_third:
            self.cooperative = False
            return Action.D
        if o_t == self.n_opponents:
            self.cooperative = True
            return Action.C
        if o_t >= ceil_two_thirds_opps and S_t >= cap_half:
            self.cooperative = True
            return Action.C
        if o_t >= ceil_half_opps and S_t >= cap_two_thirds:
            self.cooperative = True
            return Action.C
        self.cooperative = False
        return Action.D

class Strategy_COLLECTIVE_118(BaseStrategy):
    """
    Cooperative-by-default common pool strategy with stock-sensitive thresholds
    and short corrective defection when opponent cooperation drops.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(self.n_players - 1, 1)
        self.trust = True

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        if round_number == 0:
            self.trust = True
            return Action.C
        prev_k = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        rho = prev_k / self.n_opponents if self.n_opponents > 0 else 0.0
        cap = self.capacity
        s = float(current_stock)
        if rho >= 0.5:
            self.trust = True
        else:
            self.trust = False
        if round_number == self.n_rounds - 1:
            if s <= 0.5 * cap:
                return Action.C
            if rho >= 0.5:
                return Action.C
            if s >= 0.8 * cap:
                return Action.C if rho >= 0.6 else Action.D
            if s >= 0.5 * cap:
                return Action.C if rho >= 0.5 else Action.D
            if s > 0.35 * cap:
                return Action.C if rho >= 0.4 else Action.D
            return Action.C
        if s <= 0.35 * cap:
            return Action.C
        if s >= 0.8 * cap:
            return Action.C if rho >= 0.6 else Action.D
        if s >= 0.5 * cap:
            return Action.C if rho >= 0.5 else Action.D
        if s > 0.35 * cap:
            return Action.C if rho >= 0.4 else Action.D
        return Action.C

class Strategy_COLLECTIVE_119(BaseStrategy):
    """
    Stock-preserving threshold strategy with contingent correction:
    - Cooperate by default.
    - Defect only as a brief corrective response when prior cooperation was clearly too low.
    - Prefer cooperation whenever stock is low, high, or at the endgame.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.target_cooperators = math.ceil(self.n / 2)
        self.low_stock_threshold = math.ceil(self.n / 3)
        self.high_stock_threshold = 3 * self.n / 4
        self.half_capacity = self.capacity / 2.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        rounds_left_including_current = self.r - round_number
        if round_number == 0:
            return Action.C
        if rounds_left_including_current <= 1:
            return Action.C
        if rounds_left_including_current == 2:
            if current_stock <= self.half_capacity:
                return Action.C
            return self._intermediate_rule(history, current_stock)
        if current_stock <= self.low_stock_threshold:
            return Action.C
        if current_stock >= self.high_stock_threshold:
            k = self._last_opponent_cooperators(history)
            if k is not None and k < self.target_cooperators - 1:
                return Action.D
            return Action.C
        return self._intermediate_rule(history, current_stock)

    def _last_opponent_cooperators(self, history: PlayerHistory):
        if history.round_number <= 0:
            return None
        if len(history.opponent_cooperators) == 0:
            return None
        return int(history.opponent_cooperators[-1])

    def _intermediate_rule(self, history: PlayerHistory, current_stock: float) -> Action:
        k = self._last_opponent_cooperators(history)
        if k is None:
            return Action.C
        if k >= self.target_cooperators:
            return Action.C
        if k <= self.target_cooperators - 2:
            return Action.D
        return Action.C if current_stock >= self.half_capacity else Action.D

class Strategy_COLLECTIVE_120(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Starts with cooperation.
    - Uses a discipline mode triggered by heavy defection or low stock.
    - Returns to cooperation quickly after unanimous cooperation, unless the pool is empty.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.discipline_mode = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = int(self.game_description.n_players)
        capacity = float(self.game_description.capacity)
        round_number = int(history.round_number)
        if round_number == 0:
            self.discipline_mode = False
            return Action.C
        if current_stock <= 0:
            last_opp = int(history.opponent_cooperators[-1])
            if n == 2:
                self.discipline_mode = not (last_opp >= 1 and current_stock >= capacity / 2.0)
            else:
                self.discipline_mode = not (last_opp >= n - 2 and current_stock >= 2.0 * capacity / 3.0)
            return Action.C
        last_opp = int(history.opponent_cooperators[-1])
        if n == 2:
            self.discipline_mode = not (last_opp >= 1 and current_stock >= capacity / 2.0)
        elif last_opp <= n - 3 or current_stock < capacity / 2.0:
            self.discipline_mode = True
        elif last_opp >= n - 2 and current_stock >= 2.0 * capacity / 3.0:
            self.discipline_mode = False
        if round_number >= self.game_description.n_rounds - 1:
            return Action.C
        if not self.discipline_mode:
            if last_opp >= n - 2:
                return Action.C
            return Action.D
        if last_opp == n - 1 and current_stock >= 2.0 * capacity / 3.0:
            return Action.C
        return Action.D

class Strategy_COLLECTIVE_121(BaseStrategy):
    """
    Cooperative-by-default common pool strategy with stock-sensitive restraint.
    Cooperate initially, then use only the immediately previous round's observed
    opponent cooperation rate and the current stock level to decide whether to
    keep cooperating or defect for recovery.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(0, self.n_players - 1)
        self.low_band = self.capacity / 3.0
        self.high_band = 2.0 * self.capacity / 3.0
        self.emergency_band = self.capacity / 6.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        last_opponent_cooperators = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        if self.n_opponents <= 0:
            q = 1.0
        else:
            q = last_opponent_cooperators / self.n_opponents
        if current_stock <= self.emergency_band:
            threshold = 1.0
        elif current_stock < self.low_band:
            threshold = 0.8
        elif current_stock <= self.high_band:
            threshold = 0.6
        else:
            threshold = 0.5
        if q >= threshold:
            return Action.C
        return Action.D

class Strategy_COLLECTIVE_122(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Start with full cooperation.
    - Respond to previous-round opponent cooperation and current stock.
    - Defend the resource when stock is low.
    - Restore cooperation when stock is healthy.
    - Tighten cooperation in the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(self.n_players - 1, 0)
        self.majority_threshold = math.ceil(self.n_opponents / 2)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        c = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        cap = self.capacity
        S = float(current_stock)
        if history.round_number == self.n_rounds - 1:
            if S >= 0.5 * cap and c >= self.majority_threshold:
                return Action.C
            return Action.D
        if S <= 0.25 * cap:
            if c == self.n_opponents:
                return Action.C
            return Action.D
        if S >= 0.9 * cap:
            if c >= self.majority_threshold:
                return Action.C
            return Action.D
        T = self.majority_threshold
        if S < 0.75 * cap:
            T += 1
        if S < 0.5 * cap:
            T += 1
        if c >= T:
            return Action.C
        return Action.D

class Strategy_COLLECTIVE_123(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Cooperate initially.
    - Favor cooperation when the pool is healthy and the group showed restraint.
    - Defect after majority defection or when stock is critically low.
    - In the final rounds, mirror the recent majority behavior.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(0, self.n_players - 1)
        self.majority_opponents = (self.n_opponents + 1) // 2
        self.two_thirds_opponents = math.ceil(2.0 * self.n_opponents / 3.0) if self.n_opponents > 0 else 0

    def _majority_cooperated(self, opponent_count: int) -> bool:
        return opponent_count >= self.majority_opponents

    def _predict_next_stock(self, current_stock: float, total_cooperators: int) -> float:
        n = max(2, self.n_players)
        m = min(max(int(total_cooperators), 0), self.n_players)
        remaining = current_stock * (m / (2.0 * n))
        next_stock = remaining + 2.0 * remaining * (1.0 - (remaining / self.capacity if self.capacity > 0 else 0.0))
        return min(max(next_stock, 0.0), self.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        if round_number == 0:
            return Action.C
        last_opponents = int(history.opponent_cooperators[-1])
        last_majority_coop = self._majority_cooperated(last_opponents)
        rounds_remaining_including_current = self.n_rounds - round_number
        if rounds_remaining_including_current <= 2:
            return Action.C if last_majority_coop else Action.D
        if current_stock < self.capacity / 4.0:
            return Action.C if last_opponents >= self.two_thirds_opponents else Action.D
        if current_stock >= self.capacity / 2.0 and last_majority_coop:
            predicted_if_cooperate = self._predict_next_stock(current_stock, self.n_players)
            if predicted_if_cooperate >= self.capacity / 4.0:
                return Action.C
        if not last_majority_coop:
            return Action.D
        if round_number >= 2:
            prev_majority_coop = self._majority_cooperated(int(history.opponent_cooperators[-2]))
            if last_majority_coop and prev_majority_coop:
                return Action.C
        if self.n_opponents <= 0:
            return Action.C
        q_prev = last_opponents / float(self.n_opponents)
        expected_opponent_cooperators = int(round(q_prev * self.n_opponents))
        expected_opponent_cooperators = min(max(expected_opponent_cooperators, 0), self.n_opponents)
        total_cooperators_if_C = expected_opponent_cooperators + 1
        total_cooperators_if_D = expected_opponent_cooperators
        predicted_c = self._predict_next_stock(current_stock, total_cooperators_if_C)
        predicted_d = self._predict_next_stock(current_stock, total_cooperators_if_D)
        if predicted_c >= predicted_d:
            return Action.C
        return Action.D

class Strategy_COLLECTIVE_124(BaseStrategy):
    """
    Cooperative default strategy that defects only after sustained low cooperation,
    while always prioritizing cooperation when stock is scarce or the game is ending.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(self.n_players - 1, 1)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        if round_number == 0:
            return Action.C
        if round_number >= self.n_rounds - 1:
            return Action.C
        if current_stock <= self.capacity / 3.0:
            return Action.C
        if round_number < 2:
            return Action.C
        last_count = int(history.opponent_cooperators[-1])
        prev_count = int(history.opponent_cooperators[-2])
        last_p = last_count / self.n_opponents if self.n_opponents > 0 else 0.0
        prev_p = prev_count / self.n_opponents if self.n_opponents > 0 else 0.0
        if last_p >= 2.0 / 3.0:
            return Action.C
        if last_p <= 1.0 / 3.0 and prev_p <= 1.0 / 3.0:
            return Action.D
        if last_p < 0.5:
            return Action.D
        return Action.C

class Strategy_COLLECTIVE_125(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Opens with cooperation.
    - Defects under critical stock, weak cooperation, or strained conditions.
    - Cooperates when stock is healthy and cooperation is broad/consistent.
    - Includes a persistent-defection response after two weak-cooperation rounds.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.capacity = float(game_description.capacity)
        self._n_opponents = max(self.n_players - 1, 0)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.n_players
        n_opponents = self._n_opponents
        cap = self.capacity
        healthy = current_stock >= cap / 2.0
        strained = cap / 4.0 <= current_stock < cap / 2.0
        critical = current_stock < cap / 4.0
        if history.round_number == 0:
            return Action.C
        o1 = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) >= 1 else 0
        o2_available = len(history.opponent_cooperators) >= 2
        o2 = int(history.opponent_cooperators[-2]) if o2_available else 0
        broad_cooperation = o1 >= max(n - 2, 0)
        near_unanimous = o1 >= max(n - 1, 0)
        weak_cooperation = o1 <= max(n - 3, 0)
        prev_weak = False
        if len(history.opponent_cooperators) >= 2:
            o_prev2 = int(history.opponent_cooperators[-2])
            prev_weak = o_prev2 <= max(n - 3, 0)
        if prev_weak and weak_cooperation:
            if healthy and o1 >= max(n - 2, 0):
                return Action.C
            return Action.D
        last_action_was_defect = False
        if len(history.my_actions) >= 1:
            last_action_was_defect = not bool(history.my_actions[-1])
        if last_action_was_defect:
            if not critical and o1 >= max(n - 2, 0):
                return Action.C
        if critical:
            return Action.D
        if weak_cooperation:
            return Action.D
        if strained and (not near_unanimous):
            return Action.D
        if healthy and broad_cooperation:
            return Action.C
        if healthy and o1 == max(n - 2, 0) and o2_available and (o2 >= max(n - 2, 0)):
            return Action.C
        return Action.C

class Strategy_COLLECTIVE_126(BaseStrategy):
    """
    Conservative adaptive strategy for the common pool resource game.

    - Cooperates in round 1.
    - Responds to low observed cooperation with punishment.
    - Requires sustained full cooperation and adequate stock to recover.
    - Becomes stricter in the final rounds.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(0, self.n_players - 1)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if self.n_opponents <= 0:
            return Action.C
        round_number = int(history.round_number)
        if round_number == 0:
            return Action.C

        def stock_at_start_of_round(t: int) -> float:
            if t <= 0:
                return self.capacity
            prev = t - 1
            prev_payoff = float(history.my_payoffs[prev])
            prev_action = bool(history.my_actions[prev])
            if prev_action:
                return prev_payoff * 2.0 * self.n_players
            return prev_payoff * float(self.n_players)
        defect_mode = False
        recovery_streak = 0
        for t in range(round_number):
            k_t = int(history.opponent_cooperators[t])
            q_num = k_t
            q_den = self.n_opponents
            q_ge_half = 2 * q_num >= q_den
            q_ge_one = q_num >= q_den
            stock_t = stock_at_start_of_round(t)
            stock_ge_half = stock_t >= self.capacity / 2.0
            if defect_mode:
                if q_ge_one and stock_ge_half:
                    recovery_streak += 1
                else:
                    recovery_streak = 0
                if recovery_streak >= 2:
                    defect_mode = False
                    recovery_streak = 0
            elif not q_ge_half:
                defect_mode = True
                recovery_streak = 0
        if defect_mode:
            return Action.D
        k = int(history.opponent_cooperators[-1])
        q_ge_half = 2 * k >= self.n_opponents
        q_ge_one = k >= self.n_opponents
        q_ge_third = 3 * k >= self.n_opponents
        S = float(current_stock)
        stock_ge_half = S >= self.capacity / 2.0
        stock_ge_three_quarters = S >= 3.0 * self.capacity / 4.0
        recent_two_below_half = False
        if round_number >= 2:
            k1 = int(history.opponent_cooperators[-1])
            k2 = int(history.opponent_cooperators[-2])
            recent_two_below_half = (k1 + k2) * 2 < 2 * self.n_opponents
        if round_number == self.n_rounds - 1:
            return Action.C if q_ge_one and stock_ge_half else Action.D
        if round_number >= self.n_rounds - 2:
            return Action.C if q_ge_one and stock_ge_half else Action.D
        if recent_two_below_half:
            return Action.D
        if S < self.capacity / 2.0:
            return Action.C if q_ge_one else Action.D
        if stock_ge_three_quarters:
            return Action.C if q_ge_third else Action.D
        if q_ge_half and stock_ge_half:
            return Action.C
        return Action.D

class Strategy_COLLECTIVE_127(BaseStrategy):
    """
    Adaptive collective-trust strategy for the Common Pool Resource Game.
    Starts with cooperation, tracks the recent cooperation rate of opponents,
    and switches between cooperation and defection using anchor rules,
    a smoothed trust score, and a special rule for the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.m = max(0, self.n - 1)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:

        def clamp(value: float, lower: float, upper: float) -> float:
            return max(lower, min(upper, value))
        round_number = int(history.round_number)
        current_round = round_number + 1
        if round_number == 0:
            return Action.C
        score = 0.0
        if self.m > 0:
            for x in history.opponent_cooperators:
                rate = float(x) / float(self.m)
                score = clamp(0.8 * score + 0.2 * rate, 0.0, 1.0)
        if self.m > 0 and len(history.opponent_cooperators) > 0:
            opp_coop_rate = float(history.opponent_cooperators[-1]) / float(self.m)
        else:
            opp_coop_rate = 0.0
        if self.m == 1:
            last_opp_coop = bool(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else True
            return Action.C if last_opp_coop else Action.D
        trust_t = score
        target_t = clamp(0.5 + 0.5 * (trust_t - 0.5), 0.0, 1.0)
        _cooperate_t = 1 if target_t >= 0.5 else 0
        if current_round >= self.r:
            if opp_coop_rate > 0.5:
                return Action.C
            if opp_coop_rate < 0.5:
                return Action.D
            return Action.C if score >= 0.5 else Action.D
        if current_stock <= 2.0 * self.n:
            return Action.C if opp_coop_rate == 1.0 else Action.D
        if current_stock >= self.capacity * 0.8:
            if opp_coop_rate <= 0.2:
                return Action.D
            return Action.C
        if current_stock == 0.0:
            return Action.C
        if opp_coop_rate >= 0.7:
            return Action.C
        if opp_coop_rate <= 0.3:
            return Action.D
        return Action.C if score >= 0.5 else Action.D

class Strategy_COLLECTIVE_128(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Start cooperatively.
    - Cooperate when the stock is healthy and recent cooperation is near-full.
    - Defect as temporary restraint when cooperation breaks down or stock is low.
    - Re-enter cooperation promptly once the group and stock recover.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self._cooperate_threshold = self.capacity / 4.0
        self._recover_threshold = self.capacity / 2.0
        self._very_low_threshold = self.capacity / 8.0
        self._very_high_threshold = 3.0 * self.capacity / 4.0
        self._near_full_threshold = 1 if self.n_players == 2 else max(0, self.n_players - 2)
        self._full_threshold = max(0, self.n_players - 1)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number
        if t == 0:
            return Action.C
        opp_coop_last = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        my_last_action = bool(history.my_actions[-1]) if len(history.my_actions) > 0 else True
        last_full = opp_coop_last >= self._full_threshold
        last_near_full = opp_coop_last >= self._near_full_threshold
        last_poor = opp_coop_last < self._near_full_threshold
        if t >= self.n_rounds - 1:
            return Action.C if current_stock >= self._cooperate_threshold else Action.D
        if current_stock <= self._very_low_threshold:
            return Action.D
        if my_last_action is False:
            if current_stock >= self._recover_threshold and last_near_full:
                return Action.C
            return Action.D
        if last_poor:
            if current_stock >= self._recover_threshold and last_near_full:
                return Action.C
            return Action.D
        if current_stock >= self._very_high_threshold and (last_full or last_near_full):
            return Action.C
        if current_stock >= self._cooperate_threshold and last_near_full:
            return Action.C
        if t >= self.n_rounds - 2 and current_stock >= self._cooperate_threshold and last_near_full:
            return Action.C
        return Action.C if current_stock >= self._recover_threshold else Action.D

class Strategy_PROSOCIAL_33(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Cooperates by default
    - Temporarily defects when stock is dangerously low or cooperation deteriorates
    - Returns to cooperation quickly once conditions recover
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.critical_stock = self.capacity / 4.0
        self.low_stock = self.capacity / 2.0
        self.mode = 'cooperative'
        self.coop_streak = 0
        self.defect_streak = 0
        self.forgiveness_timer = 0
        self._last_seen_round = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number
        n = self.n
        r = self.r
        S = float(current_stock)
        if t < self._last_seen_round:
            self.mode = 'cooperative'
            self.coop_streak = 0
            self.defect_streak = 0
            self.forgiveness_timer = 0
        self._last_seen_round = t
        x_prev = int(history.opponent_cooperators[-1]) if t > 0 else None
        if x_prev is not None:
            if x_prev >= n - 1:
                self.coop_streak += 1
            else:
                self.coop_streak = 0
            if x_prev <= n - 3:
                self.defect_streak += 1
            else:
                self.defect_streak = 0
        if self.forgiveness_timer > 0:
            self.forgiveness_timer -= 1
        if t == 0:
            self.mode = 'cooperative'
            return Action.C
        if t == r - 1:
            return Action.C if S > 0 else Action.D
        if t >= r - 2:
            if S > 0:
                if x_prev is not None and x_prev >= n - 1:
                    return Action.C
                if x_prev is not None and x_prev < n - 2:
                    if self.forgiveness_timer == 0:
                        self.forgiveness_timer = 1
                        self.mode = 'defensive'
                        return Action.D
                    return Action.C
                return Action.C
            return Action.D
        if S <= 0:
            self.mode = 'defensive'
            return Action.D
        if S < self.critical_stock:
            if self.forgiveness_timer == 0:
                self.forgiveness_timer = 1
                self.mode = 'defensive'
                return Action.D
            self.mode = 'cooperative'
            return Action.C
        if x_prev is None:
            self.mode = 'cooperative'
            return Action.C
        if x_prev >= n - 1:
            self.mode = 'cooperative'
            return Action.C
        if x_prev == n - 2:
            if S < self.low_stock or self.defect_streak >= 2:
                self.mode = 'defensive'
                return Action.D
            self.mode = 'cooperative'
            return Action.C
        if self.forgiveness_timer == 0:
            self.forgiveness_timer = 1
            self.mode = 'defensive'
            return Action.D
        self.mode = 'cooperative'
        return Action.C

class Strategy_PROSOCIAL_34(BaseStrategy):
    """
    Always cooperate strategy for the common pool resource game.

    This strategy ignores strategic incentives and plays C in every round,
    while keeping lightweight internal records of observed opponent cooperation
    counts for bookkeeping.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.observed_opponent_cooperators = []
        self.observed_rounds = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        if round_number > self.observed_rounds:
            recent_counts = history.opponent_cooperators[self.observed_rounds:round_number]
            for count in recent_counts:
                self.observed_opponent_cooperators.append(int(count))
            self.observed_rounds = round_number
        return Action.C

class Strategy_PROSOCIAL_35(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Cooperate in round 1.
    - Thereafter, respond to the previous round's opponent cooperation rate and the current stock.
    - Be stricter when stock is very low, but return to cooperation quickly once cooperation recovers.
    - In the final round, cooperate if the previous-round opponent cooperation rate is at least half.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(self.n_players - 1, 1)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.opponent_cooperators is None or len(history.opponent_cooperators) == 0:
            return Action.C
        prev_coop = int(history.opponent_cooperators[-1])
        denom = float(self.n_opponents) if self.n_opponents > 0 else 1.0
        q = prev_coop / denom
        current_round_index = history.round_number
        is_final_round = current_round_index >= self.n_rounds - 1
        if is_final_round:
            return Action.C if q >= 0.5 else Action.D
        stock = float(current_stock)
        cap = self.capacity
        if stock <= 0.0:
            return Action.C if q >= 1.0 else Action.D
        if stock < cap / 4.0:
            return Action.C if q >= 1.0 else Action.D
        if stock >= cap / 2.0 and q >= 0.5:
            return Action.C
        if q < 0.5:
            return Action.D
        if q >= 2.0 / 3.0:
            return Action.C
        return Action.D

class Strategy_PROSOCIAL_36(BaseStrategy):
    """
    Always cooperate strategy for the common pool resource game.

    Internal state tracks:
    - m_t: number of cooperating opponents observed each round
    - p_bar: running observed opponent cooperation rate
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.opponent_cooperations: list[int] = []
        self.running_cooperation_rate: float = 0.0
        self.last_seen_round: int = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        while self.last_seen_round < round_number:
            idx = self.last_seen_round
            if 0 <= idx < len(history.opponent_cooperators):
                m_t = int(history.opponent_cooperators[idx])
            else:
                m_t = 0
            self.opponent_cooperations.append(m_t)
            n_opponents = max(self.game_description.n_players - 1, 1)
            observed_rate = m_t / n_opponents
            t = self.last_seen_round + 1
            self.running_cooperation_rate = (self.running_cooperation_rate * (t - 1) + observed_rate) / t
            self.last_seen_round += 1
        return Action.C

class Strategy_PROSOCIAL_37(BaseStrategy):
    """
    Cooperative baseline strategy with temporary defensive responses to
    low stock, repeated depletion, and sustained non-cooperation.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.capacity = float(game_description.capacity)
        self.n_players = int(game_description.n_players)
        self.n_opponents = max(0, self.n_players - 1)
        self.n_rounds = int(game_description.n_rounds)
        self.trust_score = 0
        self.stock_decrease_streak = 0
        self.emergency_active = False
        self.emergency_recovery_streak = 0
        self.severe_exploitation_active = False
        self.severe_zero_streak = 0
        self.prev_stock = None

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        if round_number == 0:
            self.prev_stock = float(current_stock)
            return Action.C
        c_prev = int(history.opponent_cooperators[-1])
        current_stock = float(current_stock)
        if c_prev >= self.n_players - 1:
            self.trust_score = min(self.trust_score + 2, 6)
        elif c_prev >= self.n_players - 2:
            self.trust_score = min(self.trust_score + 1, 6)
        elif c_prev >= 1 and c_prev <= self.n_players - 3:
            self.trust_score = max(self.trust_score - 2, -6)
        elif c_prev == 0:
            self.trust_score = max(self.trust_score - 3, -6)
        if self.prev_stock is not None and current_stock < self.prev_stock:
            self.stock_decrease_streak += 1
        else:
            self.stock_decrease_streak = 0
        if c_prev == 0:
            self.severe_zero_streak += 1
        else:
            self.severe_zero_streak = 0
        if self.severe_exploitation_active:
            half_opponents = math.ceil(self.n_opponents / 2) if self.n_opponents > 0 else 0
            if c_prev >= half_opponents:
                self.severe_exploitation_active = False
        if self.severe_zero_streak >= 2:
            self.severe_exploitation_active = True
        if self.emergency_active:
            if current_stock >= 0.5 * self.capacity and c_prev >= self.n_players - 2:
                self.emergency_recovery_streak += 1
                if self.emergency_recovery_streak >= 2:
                    self.emergency_active = False
                    self.emergency_recovery_streak = 0
            else:
                self.emergency_recovery_streak = 0
        elif current_stock < 0.35 * self.capacity or self.stock_decrease_streak >= 2:
            self.emergency_active = True
            self.emergency_recovery_streak = 0
        if round_number >= self.n_rounds - 2:
            action = Action.C if current_stock >= 0.4 * self.capacity and c_prev >= self.n_players - 2 else Action.D
            self.prev_stock = current_stock
            return action
        if self.emergency_active:
            action = Action.D
            self.prev_stock = current_stock
            return action
        if self.severe_exploitation_active:
            action = Action.D
            self.prev_stock = current_stock
            return action
        if current_stock >= 0.6 * self.capacity and self.trust_score >= -1 and (not self.emergency_active):
            action = Action.C
        else:
            action = Action.D
        self.prev_stock = current_stock
        return action

class Strategy_PROSOCIAL_38(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Starts with cooperation.
    - Stays cooperative by default.
    - Enters conservation mode only after repeated low opponent cooperation and severe stock depletion.
    - Returns to cooperation immediately when stock or cooperation improves.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.mode = 'normal'
        self.low_coop_streak = 0
        self._last_processed_round = -1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = max(2, int(self.game_description.n_players))
        r = max(1, int(self.game_description.n_rounds))
        capacity = float(self.game_description.capacity)
        round_number = int(history.round_number)
        if round_number == 0:
            self.mode = 'normal'
            self.low_coop_streak = 0
            self._last_processed_round = 0
            return Action.C
        if round_number != self._last_processed_round:
            last_opponent_cooperators = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
            n_opponents = max(1, n - 1)
            coop_rate = last_opponent_cooperators / n_opponents
            if coop_rate < 0.5:
                self.low_coop_streak += 1
            else:
                self.low_coop_streak = 0
            if self.mode == 'conservation':
                if current_stock >= 0.35 * capacity or coop_rate >= 0.5:
                    self.mode = 'normal'
            elif current_stock < 0.2 * capacity and self.low_coop_streak >= 2:
                self.mode = 'conservation'
            self._last_processed_round = round_number
        if round_number == r:
            return Action.C
        if current_stock <= 0.0:
            return Action.C
        if self.mode == 'normal':
            return Action.C
        last_opponent_cooperators = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        n_opponents = max(1, n - 1)
        coop_rate = last_opponent_cooperators / n_opponents
        if current_stock < 0.15 * capacity and coop_rate < 1.0 / 3.0:
            return Action.D
        return Action.C

class Strategy_PROSOCIAL_39(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Start by cooperating.
    - Cooperate when stock is healthy and recent cooperation is sufficiently high.
    - Defect after low-cooperation rounds and during recovery.
    - Give priority to the final round and unanimous cooperation signals.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(0, self.n_players - 1)
        self.target = 1.0 - 1.0 / self.n_players if self.n_players > 0 else 1.0
        self.floor = 0.5
        self.threshold = max(self.floor, self.target)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        if round_number == 0:
            return Action.C
        prev_opponent_cooperators = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        prev_c = 1.0 if self.n_opponents == 0 else prev_opponent_cooperators / self.n_opponents
        if round_number >= self.n_rounds - 1:
            return Action.C if current_stock != 0 else Action.D
        if self.n_opponents == 0 or prev_opponent_cooperators >= self.n_opponents:
            return Action.C if current_stock != 0 else Action.D
        if current_stock <= self.capacity / 4.0:
            return Action.D
        low_round_index = -1
        for idx in range(round_number - 1, -1, -1):
            opp_c = int(history.opponent_cooperators[idx]) if idx < len(history.opponent_cooperators) else 0
            c_val = 1.0 if self.n_opponents == 0 else opp_c / self.n_opponents
            if c_val < 0.5:
                low_round_index = idx
                break
        if low_round_index != -1:
            rounds_since_low = round_number - 1 - low_round_index
            if rounds_since_low < 2:
                if prev_c < self.threshold:
                    return Action.D
        stock_healthy = current_stock >= self.capacity / 2.0
        recent_cooperation_sufficient = prev_c >= self.threshold
        previous_round_collapsed = True
        if len(history.my_actions) > 0:
            previous_round_collapsed = False
            previous_round_collapsed = False
        if stock_healthy and recent_cooperation_sufficient and (not previous_round_collapsed):
            return Action.C
        return Action.D

class Strategy_PROSOCIAL_40(BaseStrategy):
    """
    Cooperate by default, defect only after sustained broad non-cooperation
    and only when the stock is sufficiently strained. The policy tracks recent
    opponent cooperation with an EMA plus betrayal/recovery streaks.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.last_opponent_coop = 0
        self.coop_rate_ema = 1.0
        self.betrayal_streak = 0
        self.recovery_streak = 0
        self._last_processed_round = 0

    def _escalation_active(self, current_stock: float) -> bool:
        n_players = self.game_description.n_players
        n_opponents = max(1, n_players - 1)
        high_threshold = math.ceil((n_players - 1) / 2)
        low_threshold = math.floor((n_players - 1) / 3)
        return self._last_processed_round > 1 and self.betrayal_streak >= 2 and (self.coop_rate_ema < 0.4) and (current_stock < 0.6 * float(self.game_description.capacity))

    def _update_from_history(self, history: PlayerHistory) -> None:
        round_number = history.round_number
        if round_number <= self._last_processed_round:
            return
        last_idx = round_number - 1
        if last_idx < 0:
            self._last_processed_round = round_number
            return
        n_players = self.game_description.n_players
        n_opponents = max(1, n_players - 1)
        self.last_opponent_coop = int(history.opponent_cooperators[last_idx])
        self.coop_rate_ema = 0.7 * float(self.coop_rate_ema) + 0.3 * (float(self.last_opponent_coop) / float(n_opponents))
        high_threshold = math.ceil((n_players - 1) / 2)
        low_threshold = math.floor((n_players - 1) / 3)
        if self.last_opponent_coop <= low_threshold:
            self.betrayal_streak += 1
        else:
            self.betrayal_streak = 0
        if self.last_opponent_coop >= high_threshold:
            self.recovery_streak += 1
        else:
            self.recovery_streak = 0
        self._last_processed_round = round_number

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        self._update_from_history(history)
        round_number = history.round_number
        n_rounds = self.game_description.n_rounds
        if round_number == 0:
            return Action.C
        escalation = self._escalation_active(current_stock)
        if self.recovery_streak >= 2:
            return Action.C
        if round_number == n_rounds - 1:
            if escalation and self.last_opponent_coop == 0:
                return Action.D
            return Action.C
        if round_number >= n_rounds - 2:
            if round_number >= 2:
                prev_two_zero = int(history.opponent_cooperators[-1]) == 0 and int(history.opponent_cooperators[-2]) == 0
                if prev_two_zero and escalation:
                    return Action.D
            return Action.C
        if current_stock <= float(self.game_description.capacity) / 4.0:
            if self.last_opponent_coop >= 1:
                return Action.C
            if escalation:
                return Action.D
            return Action.C
        if escalation:
            return Action.D
        return Action.C

class Strategy_PROSOCIAL_41(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Cooperates in round 1.
    - Uses the previous round's opponent cooperation rate and current stock
      to decide whether cooperation is sustainable.
    - Briefly defects after fully uncooperative opponent behavior (rho = 0),
      but returns to cooperation immediately when cooperation reappears.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(0, self.n_players - 1)
        self.cooldown_rounds = 0
        self.last_seen_round = -1
        self.last_observed_rho = 1.0
        self.trust = 1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        if round_number != self.last_seen_round:
            if round_number > 0 and len(history.opponent_cooperators) > 0:
                prev_cooperators = int(history.opponent_cooperators[-1])
                if self.n_opponents > 0:
                    rho = prev_cooperators / self.n_opponents
                else:
                    rho = 1.0
                self.last_observed_rho = rho
                self.trust = 1 if rho >= 0.5 else 0
                if rho == 0:
                    self.cooldown_rounds = 2
                elif rho >= 0.5:
                    self.cooldown_rounds = 0
            self.last_seen_round = round_number
        if round_number == 0:
            return Action.C
        rho = self.last_observed_rho
        stock = float(current_stock)
        capacity = self.capacity
        threshold_quarter = capacity / 4.0
        threshold_half = capacity / 2.0
        if stock <= 0.0:
            return Action.C
        if round_number == self.n_rounds - 1:
            if rho >= 0.5 and self.trust == 1 and (stock >= threshold_quarter):
                return Action.C
            if rho < 0.5 or stock < threshold_quarter:
                return Action.D
            return Action.C
        if rho >= 0.5:
            self.cooldown_rounds = 0
            self.trust = 1
            if rho == 1.0:
                return Action.C
            if stock >= threshold_quarter:
                return Action.C
            if stock >= threshold_half:
                return Action.C
            return Action.D
        if self.cooldown_rounds > 0:
            self.cooldown_rounds -= 1
            self.trust = 0
            return Action.D
        if rho >= 0.5 and stock >= threshold_quarter:
            return Action.C
        return Action.D

class Strategy_PROSOCIAL_42(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Cooperate by default.
    - Defect only after two consecutive rounds of low opponent cooperation.
    - Enter a short cooldown back to cooperation after punishing.
    - Always cooperate in the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.low_count = 0
        self.cooldown = 0

    def _last_opponent_rate(self, history: PlayerHistory) -> float:
        n_players = int(self.game_description.n_players)
        n_opponents = max(n_players - 1, 0)
        if history.round_number <= 0:
            return 0.0
        try:
            raw = history.opponent_cooperators[-1]
        except Exception:
            return 0.0
        if raw is None:
            return 0.0
        try:
            if isinstance(raw, float) and math.isnan(raw):
                return 0.0
        except Exception:
            pass
        try:
            k = float(raw)
        except Exception:
            return 0.0
        if n_opponents <= 0:
            return 0.0
        if k < 0.0:
            k = 0.0
        if k > float(n_opponents):
            k = float(n_opponents)
        return k / float(n_opponents)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_rounds = int(self.game_description.n_rounds)
        round_number = int(history.round_number)
        if round_number == 0:
            return Action.C
        if round_number >= n_rounds - 1:
            return Action.C
        q_prev = self._last_opponent_rate(history)
        if self.cooldown > 0:
            self.cooldown -= 1
            return Action.C
        capacity = float(self.game_description.capacity)
        if float(current_stock) <= capacity / 4.0:
            return Action.C
        if q_prev >= 0.5:
            self.low_count = 0
            return Action.C
        self.low_count += 1
        if self.low_count >= 2:
            self.low_count = 0
            self.cooldown = 2
            return Action.D
        return Action.C

class Strategy_PROSOCIAL_43(BaseStrategy):
    """
    Cooperate by default, but defect after two consecutive weakly cooperative
    rounds when the common stock is below half capacity.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.half_capacity = self.capacity / 2.0
        self.n_opponents = max(self.n_players - 1, 0)
        self.bad_threshold = self.n_opponents / 2.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = int(history.round_number)
        if t == 0 or t == self.n_rounds - 1 or current_stock <= 0.0:
            return Action.C
        if t >= 2 and current_stock < self.half_capacity:
            if len(history.opponent_cooperators) >= 2:
                bad_prev_1 = history.opponent_cooperators[-1] < self.bad_threshold
                bad_prev_2 = history.opponent_cooperators[-2] < self.bad_threshold
                if bad_prev_1 and bad_prev_2:
                    return Action.D
        return Action.C

class Strategy_PROSOCIAL_44(BaseStrategy):
    """
    Prosocial adaptive common-pool strategy:
    - Cooperate on round 1.
    - Prefer cooperation when opponents show majority cooperation and stock is healthy.
    - Defect when cooperation drops, the stock becomes too depleted, or at the endgame
      conditions require stricter protection.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.last_seen_round_number = -1
        self.running_opponent_coop_sum = 0.0
        self.running_opponent_coop_count = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_players = int(self.game_description.n_players)
        n_opponents = max(n_players - 1, 1)
        total_rounds = int(self.game_description.n_rounds)
        t = history.round_number + 1
        if history.round_number == 0:
            self.last_seen_round_number = 0
            return Action.C
        coop_counts = history.opponent_cooperators
        if len(coop_counts) > 0:
            self.running_opponent_coop_sum = float(np.sum(coop_counts))
            self.running_opponent_coop_count = int(len(coop_counts))
        last_c = int(coop_counts[-1]) if len(coop_counts) > 0 else 0
        x = last_c / n_opponents if n_opponents > 0 else 0.0
        x_bar = float(self.running_opponent_coop_sum) / (self.running_opponent_coop_count * n_opponents) if self.running_opponent_coop_count > 0 and n_opponents > 0 else 0.0
        self.last_seen_round_number = history.round_number
        majority_threshold = n_opponents / 2.0
        if t == total_rounds:
            return Action.C if x >= 0.5 and current_stock >= 3.0 * n_players else Action.D
        if current_stock <= 0.0:
            return Action.C if x == 1.0 and x_bar >= 0.5 else Action.D
        if current_stock < 2.0 * n_players:
            return Action.C if x == 1.0 and x_bar >= 0.5 else Action.D
        if x == 1.0 and x_bar >= 0.5:
            return Action.C
        if x >= 0.5 and x_bar >= 0.5 and (last_c > 0):
            return Action.C
        if last_c <= majority_threshold:
            return Action.D
        return Action.D

class Strategy_PROSOCIAL_45(BaseStrategy):
    """
    Conservative common-pool strategy:
    - Start by cooperating.
    - Defect only after repeated low cooperation and poor stock conditions.
    - Immediately return to cooperation when cooperation recovers, the stock stabilizes, or in the final two rounds.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.mode = 'cooperate'
        self.low_coop_streak = 0
        self.last_stock = float(game_description.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = max(int(self.game_description.n_players), 2)
        m = max(n - 1, 1)
        round_number = int(history.round_number)
        remaining_rounds = int(self.game_description.n_rounds) - round_number
        if remaining_rounds <= 2:
            self.mode = 'cooperate'
            self.last_stock = float(current_stock)
            return Action.C
        if round_number == 0:
            self.mode = 'cooperate'
            self.low_coop_streak = 0
            self.last_stock = float(current_stock)
            return Action.C
        prev_coop_count = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        coop_rate = prev_coop_count / m if m > 0 else 0.0
        stock_now = float(current_stock)
        stock_trend = stock_now - float(self.last_stock)
        low_threshold = math.ceil(m / 3)
        if prev_coop_count < low_threshold:
            self.low_coop_streak += 1
        else:
            self.low_coop_streak = 0
        if coop_rate >= 0.5 or stock_trend >= 0:
            self.mode = 'cooperate'
        elif self.mode == 'defect' and (coop_rate >= 0.5 or stock_trend >= 0):
            self.mode = 'cooperate'
        stock_ratio = stock_now / float(self.game_description.capacity) if self.game_description.capacity > 0 else 0.0
        cooperate = coop_rate >= 0.5 or stock_ratio >= 1.0 / 3.0 or (self.mode == 'defect' and (coop_rate >= 0.5 or stock_trend >= 0))
        defect = remaining_rounds > 2 and self.low_coop_streak >= 2 and (stock_ratio < 0.5) and (coop_rate < 1.0 / 3.0)
        if cooperate or not defect:
            action = Action.C
        else:
            action = Action.D
        if action == Action.C:
            self.mode = 'cooperate'
        else:
            self.mode = 'defect'
        self.last_stock = stock_now
        return action

class Strategy_PROSOCIAL_46(BaseStrategy):
    """
    Cooperative default strategy with short corrective defections against clear exploitation,
    while returning to cooperation immediately when opponents recover.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(0, self.n_players - 1)
        self.last_q = None
        self.last_was_defection_response = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        t = round_number + 1
        if round_number == 0:
            self.last_q = None
            self.last_was_defection_response = False
            return Action.C
        if self.n_opponents <= 0:
            return Action.C
        last_coop_count = int(history.opponent_cooperators[-1])
        q = last_coop_count / self.n_opponents
        if round_number >= 2:
            prev_coop_count = int(history.opponent_cooperators[-2])
            q_prev = prev_coop_count / self.n_opponents
        else:
            q_prev = 1.0
        near_capacity = current_stock >= 0.95 * self.capacity
        low_stock = current_stock < self.capacity / 4.0
        final_two_rounds = t >= self.n_rounds - 1
        action = Action.C
        if self.last_was_defection_response:
            if q >= 2.0 / 3.0:
                action = Action.C
            elif q < 0.5:
                action = Action.D
            else:
                action = Action.C
        elif t == 1:
            action = Action.C
        elif not near_capacity and low_stock and (q < 1.0):
            action = Action.D
        elif final_two_rounds and q < 1.0:
            action = Action.D
        elif q < 0.5:
            action = Action.D
        elif q < 2.0 / 3.0 and q_prev < 2.0 / 3.0:
            action = Action.D
        else:
            action = Action.C
        self.last_q = q
        self.last_was_defection_response = action == Action.D
        return action

class Strategy_PROSOCIAL_47(BaseStrategy):
    """
    Cooperative default strategy for the Common Pool Resource Game.

    - Cooperates in the first round.
    - Cooperates when opponent cooperation is at least 1/2, with safeguards for
      exploitation, stock collapse, and final-round behavior.
    - Uses a one-round test after observing low cooperation, then defects if
      low cooperation persists.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.half_threshold = 0.5
        self.eps = 1e-12

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.n_players
        rounds_played = history.round_number
        if rounds_played == 0:
            return Action.C
        if current_stock <= 0.0:
            return Action.D
        n_opponents = max(n - 1, 1)
        opponent_counts = history.opponent_cooperators
        q_last = float(opponent_counts[-1]) / float(n_opponents)
        q_prev = float(opponent_counts[-2]) / float(n_opponents) if rounds_played >= 2 else 1.0
        q_prev2 = float(opponent_counts[-3]) / float(n_opponents) if rounds_played >= 3 else 1.0
        if rounds_played == self.n_rounds - 1:
            if q_last >= self.half_threshold and q_prev >= self.half_threshold:
                return Action.C
            return Action.D
        collapse_threshold = self.capacity / float(2 * n) if n > 0 else self.capacity
        if current_stock <= collapse_threshold + self.eps:
            if q_last >= 1.0 - self.eps and q_prev >= 1.0 - self.eps:
                return Action.C
            return Action.D
        if q_last < self.half_threshold:
            return Action.C
        if q_last >= self.half_threshold:
            return Action.C
        return Action.C

class Strategy_PROSOCIAL_48(BaseStrategy):
    """
    Cooperative-by-default common-pool strategy with threshold-based reciprocity,
    rapid forgiveness after improved cooperation, and strong defense under depletion.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self._n_opponents = max(self.n_players - 1, 1)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = int(history.round_number)
        S = float(current_stock)
        cap = self.capacity
        if t == 0:
            return Action.C
        opp_coop = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        c = opp_coop / self._n_opponents if self._n_opponents > 0 else 1.0
        half_cap = cap / 2.0
        quarter_cap = cap / 4.0
        three_quarter_cap = 3.0 * cap / 4.0
        if t == self.n_rounds - 1:
            if S <= quarter_cap:
                return Action.C if c >= 5.0 / 6.0 else Action.D
            if c >= 2.0 / 3.0:
                return Action.C
            return Action.C if S >= half_cap else Action.D
        if S <= quarter_cap:
            return Action.C if c >= 5.0 / 6.0 else Action.D
        if S < half_cap:
            return Action.C if c >= 2.0 / 3.0 else Action.D
        if S >= three_quarter_cap and c >= 2.0 / 3.0:
            return Action.C
        if c >= 1.0 / 2.0:
            return Action.C
        if c <= 1.0 / 3.0 and S < three_quarter_cap:
            return Action.D
        return Action.C

class Strategy_PROSOCIAL_49(BaseStrategy):
    """
    Resource-protective cooperative strategy with early caution, running
    cooperation estimates, recovery mode after depletion, and a temporary
    anti-exploitation guard when the stock drops sharply despite cooperation.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.capacity = float(game_description.capacity)
        self.n_players = int(game_description.n_players)
        self.n_opponents = max(self.n_players - 1, 1)
        self.previous_stock: float | None = None
        self.recovery_rounds_remaining: int = 0
        self.zero_lock: bool = False
        self.guard_rounds_remaining: int = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number
        cap = self.capacity
        if t > 0 and len(history.opponent_cooperators) > 0:
            last_opp_coops = int(history.opponent_cooperators[-1])
            q_t = last_opp_coops / self.n_opponents if self.n_opponents > 0 else 0.0
            q_bar = float(np.mean(history.opponent_cooperators)) / self.n_opponents if self.n_opponents > 0 else 0.0
        else:
            q_t = 0.0
            q_bar = 0.0
        anti_exploit = False
        if self.previous_stock is not None and t > 0 and (len(history.opponent_cooperators) > 0):
            prev_round_q = int(history.opponent_cooperators[-1]) / self.n_opponents if self.n_opponents > 0 else 0.0
            if prev_round_q >= 0.5 and self.previous_stock - current_stock > 0.4 * cap:
                anti_exploit = True
        if anti_exploit:
            self.guard_rounds_remaining = 3
        if current_stock <= 0.0:
            self.zero_lock = True
        elif self.zero_lock and current_stock > 0.0:
            self.zero_lock = False
        if current_stock <= 0.25 * cap:
            self.recovery_rounds_remaining = max(self.recovery_rounds_remaining, 2)
        stock_coop_threshold = 0.5 * cap
        early_stock_threshold = 0.6 * cap
        if self.guard_rounds_remaining > 0:
            stock_coop_threshold = 0.6 * cap
            early_stock_threshold = 0.6 * cap
        action = Action.C
        if t == self.game_description.n_rounds - 1:
            if current_stock < 0.2 * cap and q_t < 0.35 and (q_bar < 0.35):
                action = Action.D
            else:
                action = Action.C
        elif t == 0:
            action = Action.C
        elif self.zero_lock:
            action = Action.C
        elif self.recovery_rounds_remaining > 0:
            action = Action.C
        elif t <= 3:
            action = Action.C if current_stock >= early_stock_threshold else Action.D
        elif current_stock < 0.35 * cap:
            action = Action.D
        elif current_stock >= stock_coop_threshold and q_t >= 0.5 and (q_bar >= 0.5):
            action = Action.C
        elif q_t < 0.35 or q_bar < 0.4:
            action = Action.D
        else:
            action = Action.C
        if self.recovery_rounds_remaining > 0:
            self.recovery_rounds_remaining -= 1
        if self.guard_rounds_remaining > 0:
            self.guard_rounds_remaining -= 1
        self.previous_stock = float(current_stock)
        return action

class Strategy_PROSOCIAL_50(BaseStrategy):
    """
    Cooperative-by-default common pool strategy with stock-sensitive caution,
    recovery after exploitation, and a temporary warning state after failed
    stock recovery.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(self.n_players - 1, 0)
        self.min_stock_for_coop = 2.0 * self.n_players
        self.recovery_stock_threshold = 1.5 * self.n_players
        self.capacity_half = 0.5 * self.capacity
        self.require_unanimous_recovery = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        S = float(current_stock)
        if round_number == 0:
            return Action.C
        last_opponents = int(history.opponent_cooperators[-1]) if round_number > 0 else 0
        m = self.n_opponents
        c = last_opponents / m if m > 0 else 1.0
        if round_number > 0 and bool(history.my_actions[-1]) is True and (S < self.capacity_half):
            self.require_unanimous_recovery = True
        if S <= 0.0:
            return Action.C
        if round_number == self.n_rounds - 1:
            return Action.C if c >= 0.5 and S >= self.min_stock_for_coop else Action.D
        if self.require_unanimous_recovery:
            if c == 1.0 and S >= self.recovery_stock_threshold:
                self.require_unanimous_recovery = False
                return Action.C
            return Action.D
        if c == 1.0 and S >= self.capacity_half:
            return Action.C
        if S <= self.min_stock_for_coop:
            return Action.D if c < 0.5 else Action.C
        if S >= self.min_stock_for_coop and c >= 0.5 and (S >= self.capacity_half):
            return Action.C
        if c >= 0.5 and S >= self.min_stock_for_coop:
            return Action.C
        return Action.D

class Strategy_PROSOCIAL_51(BaseStrategy):
    """
    Broadly cooperative common-pool strategy:
    - Cooperate in the first round.
    - Defect only under clear resource stress or sustained low opponent cooperation.
    - Return to cooperation quickly when the group recovers.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(self.n_players - 1, 0)
        self.critical_floor = float(2 * self.n_players)
        self.half_capacity = self.capacity / 2.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        if round_number == 0:
            return Action.C
        remaining_rounds = self.n_rounds - round_number
        if remaining_rounds < 1:
            remaining_rounds = 1
        last_opponents = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        if self.n_opponents > 0:
            q = last_opponents / self.n_opponents
        else:
            q = 1.0
        last_action_is_coop = bool(history.my_actions[-1]) if len(history.my_actions) > 0 else True
        stock = float(current_stock)
        if remaining_rounds == 1:
            if stock <= self.critical_floor:
                return Action.D
            if last_opponents <= 0:
                return Action.D
            return Action.C
        if not last_action_is_coop and q >= 2.0 / 3.0 and (stock > self.critical_floor):
            return Action.C
        if not last_action_is_coop and q >= 0.5 and (stock > self.critical_floor):
            return Action.C
        if stock <= self.critical_floor:
            return Action.D
        if remaining_rounds <= 2 and stock < self.half_capacity:
            return Action.D
        if q <= 1.0 / 3.0:
            return Action.D
        return Action.C

class Strategy_PROSOCIAL_52(BaseStrategy):
    """
    Always cooperate in every round, regardless of history or current stock.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        return Action.C

class Strategy_PROSOCIAL_53(BaseStrategy):
    """
    Always cooperate in every round, regardless of history or current stock.
    Tracks observed stock and opponent cooperation counts for monitoring only.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.observed_stocks = []
        self.observed_opponent_cooperators = []

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        self.observed_stocks.append(float(current_stock))
        if history.round_number > 0:
            self.observed_opponent_cooperators.append(int(history.opponent_cooperators[-1]))
        return Action.C

class Strategy_PROSOCIAL_54(BaseStrategy):
    """
    Guarded reciprocity for the common pool resource game:
    - start cooperatively,
    - track a smoothed estimate of opponent cooperation,
    - defect under emergency depletion or sustained low cooperation,
    - forgive quickly after strong cooperation,
    - otherwise bias toward cooperation.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(self.n_players - 1, 1)

    def _opponent_rate(self, coop_count: int) -> float:
        return float(coop_count) / float(self.n_opponents)

    def _smoothed_q(self, history: PlayerHistory) -> float:
        q = 1.0
        for coop_count in history.opponent_cooperators:
            p = self._opponent_rate(int(coop_count))
            q = 0.7 * p + 0.3 * q
        return float(q)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        if round_number == 0:
            return Action.C
        q_t = self._smoothed_q(history)
        p_prev = self._opponent_rate(int(history.opponent_cooperators[-1]))
        prev_play_c = bool(history.my_actions[-1])
        last_two_all_below_half = False
        if round_number >= 2:
            p_prev2 = self._opponent_rate(int(history.opponent_cooperators[-2]))
            last_two_all_below_half = p_prev < 0.5 and p_prev2 < 0.5
        current_round = round_number + 1
        final_round = current_round == self.n_rounds
        if current_stock <= 2.0 * self.n_players:
            return Action.D
        if current_stock <= 3.0 * self.n_players and q_t < 0.5:
            return Action.D
        if p_prev >= 2.0 / 3.0:
            return Action.C
        if final_round:
            return Action.C if q_t >= 0.5 else Action.D
        if p_prev == 0.0:
            return Action.D
        if last_two_all_below_half:
            return Action.D
        if prev_play_c and p_prev < 0.5:
            if q_t < 0.75:
                return Action.D
            return Action.C
        if q_t >= 0.75:
            return Action.C
        if q_t >= 0.5:
            return Action.C
        return Action.D

class Strategy_PROSOCIAL_55(BaseStrategy):
    """
    Default-to-cooperate common-pool strategy that defects only when recent
    cooperation is clearly below threshold and the stock is not healthy.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.depletion_threshold = 2.0 * self.n
        self.recovery_threshold = 0.75 * self.capacity
        self.required_cooperators = int(math.ceil((self.n - 1) / 2.0))

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        stock = float(current_stock)
        if round_number == 0:
            return Action.C
        if len(history.opponent_cooperators) > 0:
            k = int(history.opponent_cooperators[-1])
        else:
            k = self.required_cooperators
        if self.n <= 2:
            required = 1
        else:
            required = self.required_cooperators
        if stock <= self.depletion_threshold:
            action = Action.C
        elif k >= required or stock >= self.recovery_threshold:
            action = Action.C
        else:
            action = Action.D
        if round_number >= 1 and len(history.opponent_cooperators) >= 1:
            prev_k = int(history.opponent_cooperators[-1])
            if stock < 0.5 * self.capacity and prev_k >= required:
                action = Action.C
            if round_number >= 2 and len(history.opponent_cooperators) >= 2:
                prev2_k = int(history.opponent_cooperators[-2])
                if stock < 0.5 * self.capacity:
                    if prev_k < required and prev2_k < required:
                        action = Action.C
        current_round_index = round_number
        if current_round_index == self.r - 1:
            if not (stock > self.depletion_threshold and k < required):
                action = Action.C
            else:
                action = Action.D
        return action

class Strategy_PROSOCIAL_56(BaseStrategy):
    """
    Cooperative default strategy with temporary defensive retaliation.

    - Starts by cooperating.
    - Tracks sustained low cooperation or stock collapse to enter defense.
    - Returns to cooperation only after sustained recovery in both cooperation
      and stock level.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = max(int(self.n), 2)
        n_opponents = max(n - 1, 1)
        cap = float(self.capacity)
        if history.round_number == 0:
            return Action.C
        if history.round_number >= self.rounds - 1:
            return Action.C
        mode = 'normal'
        low_q_streak = 0
        low_s_streak = 0
        high_q_streak = 0
        high_s_streak = 0
        stock = cap
        past_rounds = history.round_number
        for t in range(past_rounds):
            k = int(history.opponent_cooperators[t]) if t < len(history.opponent_cooperators) else 0
            my_coop = bool(history.my_actions[t]) if t < len(history.my_actions) else True
            total_consumption = 0.0
            if my_coop:
                total_consumption += stock / (2.0 * n)
            else:
                total_consumption += stock / float(n)
            coop_opp = max(0, min(k, n_opponents))
            defect_opp = n_opponents - coop_opp
            total_consumption += coop_opp * (stock / (2.0 * n))
            total_consumption += defect_opp * (stock / float(n))
            remaining = stock - total_consumption
            if remaining < 0.0:
                remaining = 0.0
            growth = 2.0 * remaining * (1.0 - remaining / cap) if cap > 0 else 0.0
            next_stock = remaining + growth
            if next_stock > cap:
                next_stock = cap
            if next_stock < 0.0:
                next_stock = 0.0
            q = coop_opp / float(n_opponents) if n_opponents > 0 else 0.0
            if q < 0.4:
                low_q_streak += 1
            else:
                low_q_streak = 0
            if next_stock < 0.4 * cap:
                low_s_streak += 1
            else:
                low_s_streak = 0
            if q >= 0.6:
                high_q_streak += 1
            else:
                high_q_streak = 0
            if next_stock >= 0.7 * cap:
                high_s_streak += 1
            else:
                high_s_streak = 0
            if mode == 'normal':
                if low_q_streak >= 2 or low_s_streak >= 2:
                    mode = 'defense'
            elif high_q_streak >= 2 and high_s_streak >= 2:
                mode = 'normal'
            stock = next_stock
        latest_k = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        latest_q = latest_k / float(n_opponents) if n_opponents > 0 else 0.0
        if current_stock <= 0.0:
            return Action.C
        if mode == 'defense':
            return Action.D
        if latest_q >= 0.5 and current_stock >= 0.5 * cap:
            return Action.C
        if latest_q < 0.5 and current_stock < 0.5 * cap:
            return Action.D
        return Action.C

class Strategy_PROSOCIAL_57(BaseStrategy):
    """
    Prosocial threshold strategy for the Common Pool Resource Game.

    - Cooperate by default.
    - Defect only as a short defensive response to sustained low cooperation or severe stock collapse.
    - Never defects for more than two consecutive rounds.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(0, self.n_players - 1)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        s = float(current_stock)
        cap = self.capacity

        def opponent_rate(index: int) -> float:
            if index < 0 or index >= len(history.opponent_cooperators):
                return 0.0
            if self.n_opponents <= 0:
                return 0.0
            return float(history.opponent_cooperators[index]) / float(self.n_opponents)

        def last_my_action_is_defect() -> bool:
            return round_number > 0 and (not bool(history.my_actions[-1]))

        def last_two_my_actions_are_defects() -> bool:
            return round_number >= 2 and (not bool(history.my_actions[-1])) and (not bool(history.my_actions[-2]))

        def low_stock() -> bool:
            return s < cap / 8.0

        def enough_stock_for_cooperation() -> bool:
            return s >= cap / 4.0
        if round_number == 0:
            return Action.C
        q_last = opponent_rate(round_number - 1)
        q_prev = opponent_rate(round_number - 2) if round_number >= 2 else 1.0
        low_last = q_last < 0.5
        low_prev = q_prev < 0.5
        if round_number == 1:
            if q_last == 0.0:
                return Action.D
            return Action.C
        if last_two_my_actions_are_defects() and (not low_stock()):
            return Action.C
        if last_my_action_is_defect() and q_last >= 0.5 and enough_stock_for_cooperation():
            return Action.C
        if round_number == self.n_rounds - 1:
            if low_stock() or (low_last and low_prev) or q_last == 0.0:
                return Action.D
            return Action.C
        if low_stock():
            return Action.D
        if low_last and low_prev:
            return Action.D
        if s > 0.0 and q_last >= 0.5 and enough_stock_for_cooperation():
            return Action.C
        return Action.C

class Strategy_PROSOCIAL_58(BaseStrategy):
    """
    Cooperate by default, forgive one weak round, and defect defensively only
    after sustained weak cooperation and when the stock is already low.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.bad_streak = 0
        self._last_history_round = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_players = getattr(self.game_description, 'n_players', 0)
        n_rounds = getattr(self.game_description, 'n_rounds', 0)
        n_opponents = max(0, n_players - 1)
        if history.round_number == 0:
            self._last_history_round = 0
            return Action.C
        if history.round_number > self._last_history_round:
            prev_k = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
            threshold = math.ceil(n_opponents / 2) if n_opponents > 0 else 0
            if prev_k >= threshold:
                self.bad_streak = 0
            else:
                self.bad_streak += 1
            self._last_history_round = history.round_number
        if current_stock <= 0:
            return Action.C
        if history.round_number >= n_rounds - 1:
            return Action.C
        if self.bad_streak >= 2 and current_stock < getattr(self.game_description, 'capacity', 1) / 3.0:
            return Action.D
        return Action.C

class Strategy_PROSOCIAL_59(BaseStrategy):
    """
    Cooperative-by-default common pool strategy with trust that decays after
    weak cooperation and recovers quickly after strong cooperation.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self._last_trust = 1.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_players = int(self.game_description.n_players)
        n_rounds = int(self.game_description.n_rounds)
        capacity = float(self.game_description.capacity)
        if history.round_number == 0:
            self._last_trust = 1.0
            return Action.C
        n_opponents = max(n_players - 1, 1)
        trust = 1.0
        for k in range(history.round_number):
            x_k = float(history.opponent_cooperators[k]) / float(n_opponents)
            trust = 0.7 * trust + 0.3 * x_k
        self._last_trust = trust
        stock = float(current_stock)
        cap = capacity if capacity > 0.0 else 1.0
        stock_ratio = stock / cap
        current_round_number = history.round_number + 1
        is_final_round = current_round_number >= n_rounds
        last_x = 1.0
        if history.round_number > 0:
            last_x = float(history.opponent_cooperators[-1]) / float(n_opponents)
        if is_final_round:
            return Action.C
        if stock_ratio <= 0.2:
            if last_x >= 1.0 and trust >= 0.8:
                return Action.C
            return Action.D
        if stock_ratio >= 0.8 and trust >= 0.2:
            return Action.C
        if trust < 0.3 or stock_ratio < 0.3:
            return Action.D
        if trust >= 0.5 and stock_ratio >= 0.4:
            return Action.C
        if 0.3 <= trust < 0.5:
            if stock_ratio >= 0.6:
                return Action.C
            return Action.D
        if stock_ratio >= 0.4:
            return Action.C
        return Action.D

class Strategy_PROSOCIAL_60(BaseStrategy):
    """
    Unconditional cooperation strategy for the Common Pool Resource Game.
    Always plays C, regardless of history, stock level, or opponent behavior.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(getattr(game_description, 'n_players', 0) or 0)
        self.n_rounds = int(getattr(game_description, 'n_rounds', 0) or 0)
        self.capacity = float(getattr(game_description, 'capacity', 0.0) or 0.0)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history is None:
            return Action.C
        round_number = getattr(history, 'round_number', 0)
        if round_number == 0:
            return Action.C
        return Action.C

class Strategy_PROSOCIAL_61(BaseStrategy):
    """
    Adaptive common-pool strategy:
    cooperate by default, protect the stock under stress,
    and briefly defect only after clear repeated exploitation.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.m = max(self.n - 1, 0)
        self.coop_threshold = math.ceil(2 * self.m / 3) if self.m > 0 else 0
        self.coop_streak = 0
        self.low_stock_streak = 0
        self._processed_rounds = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        current_stock = float(current_stock)
        if round_number > self._processed_rounds:
            if round_number > 0:
                last_k = int(history.opponent_cooperators[-1])
                if last_k >= self.coop_threshold:
                    self.coop_streak += 1
                else:
                    self.coop_streak = 0
                if current_stock < self.capacity / 2.0:
                    self.low_stock_streak += 1
                else:
                    self.low_stock_streak = 0
            self._processed_rounds = round_number
        if round_number == 0:
            return Action.C
        if round_number >= self.r - 1:
            return Action.C
        if current_stock <= 2.0 * self.n:
            return Action.C
        last_k = int(history.opponent_cooperators[-1])
        c_hat = last_k / self.m if self.m > 0 else 1.0
        last_two_good = False
        if round_number >= 2 and self.m > 0:
            prev_k = int(history.opponent_cooperators[-2])
            last_two_good = last_k >= self.coop_threshold and prev_k >= self.coop_threshold
        if last_k == 0:
            if current_stock >= 3.0 * self.n and last_two_good:
                return Action.C
            return Action.D
        if c_hat >= 2.0 / 3.0 and current_stock >= self.capacity / 2.0:
            return Action.C
        if c_hat >= 0.5 and current_stock >= 3.0 * self.n and (self.low_stock_streak == 0):
            return Action.C
        if c_hat < 0.5:
            if current_stock >= 3.0 * self.capacity / 4.0 and last_k != 0:
                return Action.C
            return Action.D
        return Action.C

class Strategy_PROSOCIAL_62(BaseStrategy):
    """
    Cooperative-by-default strategy with cautious, one-round enforcement defections
    only after two consecutive low-cooperation observations and only when stock is
    comfortably above the quarter-capacity threshold.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(self.n_players - 1, 1)
        self.half_threshold = 0.5
        self.quarter_capacity = self.capacity / 4.0
        self.eighth_capacity = self.capacity / 8.0
        self.last_action = Action.C
        self.last_opponent_cooperators = None

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = getattr(history, 'round_number', 0)
        if round_number <= 0:
            self.last_action = Action.C
            self.last_opponent_cooperators = None
            return Action.C
        remaining_rounds = self.n_rounds - round_number
        if remaining_rounds <= 2:
            self.last_action = Action.C
            return Action.C
        if current_stock <= self.eighth_capacity or current_stock <= self.quarter_capacity:
            self.last_action = Action.C
            return Action.C
        opp_hist = getattr(history, 'opponent_cooperators', None)
        my_actions = getattr(history, 'my_actions', None)
        if opp_hist is None or len(opp_hist) == 0 or my_actions is None or (len(my_actions) == 0):
            self.last_action = Action.C
            return Action.C
        prev_opp_coop = int(opp_hist[-1])
        q_prev = prev_opp_coop / self.n_opponents if self.n_opponents > 0 else 1.0
        if self.last_action == Action.D:
            self.last_action = Action.C
            self.last_opponent_cooperators = prev_opp_coop
            return Action.C
        two_low_rounds = False
        if len(opp_hist) >= 2:
            two_low_rounds = (int(opp_hist[-1]) / self.n_opponents < self.half_threshold if self.n_opponents > 0 else False) and (int(opp_hist[-2]) / self.n_opponents < self.half_threshold if self.n_opponents > 0 else False)
        if two_low_rounds and current_stock > self.quarter_capacity:
            self.last_action = Action.D
            self.last_opponent_cooperators = prev_opp_coop
            return Action.D
        if q_prev > self.half_threshold:
            self.last_action = Action.C
            self.last_opponent_cooperators = prev_opp_coop
            return Action.C
        if q_prev < self.half_threshold:
            self.last_action = Action.C
            self.last_opponent_cooperators = prev_opp_coop
            return Action.C
        self.last_action = Action.C
        self.last_opponent_cooperators = prev_opp_coop
        return Action.C

class Strategy_PROSOCIAL_63(BaseStrategy):
    """
    State-based conditional cooperation with fair baseline, recovery, and emergency protection.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self._last_defected_due_to_low_q = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_players = max(2, int(self.game_description.n_players))
        n_opponents = max(1, n_players - 1)
        capacity = float(self.game_description.capacity) if self.game_description.capacity > 0 else 1.0
        round_number = history.round_number

        def update_state(action: Action, defect_due_to_low_q: bool) -> Action:
            self._last_defected_due_to_low_q = defect_due_to_low_q
            return action
        if round_number == 0:
            return update_state(Action.C, False)
        last_k = int(history.opponent_cooperators[-1])
        q = last_k / n_opponents if n_opponents > 0 else 0.0
        S = float(current_stock)
        f = S / capacity if capacity > 0 else 0.0
        last_two_zero = False
        if round_number >= 2:
            last_two_zero = int(history.opponent_cooperators[-1]) == 0 and int(history.opponent_cooperators[-2]) == 0
        last_round_index = int(self.game_description.n_rounds) - 1
        second_last_round_index = last_round_index - 1
        if round_number == last_round_index:
            return update_state(Action.C, False)
        if round_number == second_last_round_index:
            if f < 1.0 / (2.0 * n_players):
                return update_state(Action.D, False)
            return update_state(Action.C, False)
        if S <= 2.0 * n_players:
            if last_two_zero:
                return update_state(Action.D, False)
            return update_state(Action.C, False)
        if self._last_defected_due_to_low_q:
            if q >= 0.5 or f >= 0.75:
                return update_state(Action.C, False)
        tau = 0.5 + max(0.0, 0.5 - f)
        if q >= tau:
            return update_state(Action.C, False)
        return update_state(Action.D, True)

class Strategy_PROSOCIAL_64(BaseStrategy):
    """
    Cooperative-by-default resource guardian strategy with brief defensive defections
    after broad collapse, returning to cooperation as soon as cooperation recovers.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.opponents = max(0, self.n - 1)
        self.min_stock_threshold = 2.0 * self.n
        self._last_seen_round = 0
        self._protection_remaining = 0
        self._force_cooperate_rest = False

    def _opponent_rate(self, history: PlayerHistory, idx: int) -> float:
        if self.opponents <= 0:
            return 1.0
        if idx < 0 or idx >= len(history.opponent_cooperators):
            return 1.0
        return float(history.opponent_cooperators[idx]) / float(self.opponents)

    def _infer_round_stock(self, history: PlayerHistory, idx: int) -> float:
        """
        Infer the stock at the start of round idx from our payoff and action in that round.
        If unavailable or ambiguous, return current capacity as a safe fallback.
        """
        if idx < 0 or idx >= len(history.my_actions) or idx >= len(history.my_payoffs):
            return self.capacity
        payoff = float(history.my_payoffs[idx])
        action = bool(history.my_actions[idx])
        if action:
            return payoff * float(2 * self.n)
        return payoff * float(self.n)

    def _near_capacity(self, s: float) -> bool:
        return s >= 0.9 * self.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        if current_stock <= 0.0:
            self._force_cooperate_rest = True
        if self._force_cooperate_rest:
            return Action.C
        if round_number == 0:
            self._last_seen_round = 0
            self._protection_remaining = 0
            return Action.C
        last_idx = round_number - 1
        rho_last = self._opponent_rate(history, last_idx)
        last_stock_start = self._infer_round_stock(history, last_idx)
        stock_rising_or_near_capacity_twice = False
        stock_falling_two_consecutive = False
        if round_number >= 3:
            s1 = self._infer_round_stock(history, round_number - 1)
            s2 = self._infer_round_stock(history, round_number - 2)
            s3 = self._infer_round_stock(history, round_number - 3)
            stock_rising_or_near_capacity_twice = s2 >= s3 and s1 >= s2 or (self._near_capacity(s2) and self._near_capacity(s1))
            stock_falling_two_consecutive = s3 > s2 > s1
        severe_collapse = rho_last < 1.0 / 3.0 or last_stock_start < self.capacity / 4.0
        if self._protection_remaining > 0:
            self._protection_remaining -= 1
            if rho_last >= 2.0 / 3.0:
                self._protection_remaining = 0
                return Action.C
            return Action.D
        if rho_last < 1.0 / 3.0:
            self._protection_remaining = 1
            return Action.D
        if round_number >= self.r - 1:
            if rho_last >= 0.5 and current_stock > 0.0:
                return Action.C
            return Action.D
        if stock_rising_or_near_capacity_twice:
            return Action.C
        if self.opponents > 0 and history.opponent_cooperators[last_idx] >= self.opponents:
            return Action.C
        if self.opponents > 0 and history.opponent_cooperators[last_idx] * 2 == self.opponents:
            if stock_falling_two_consecutive:
                return Action.D
            return Action.C
        if current_stock <= self.min_stock_threshold:
            if rho_last < 0.5:
                return Action.D
            return Action.C
        if rho_last >= 0.5 and current_stock >= self.min_stock_threshold and (not severe_collapse):
            return Action.C
        return Action.D

class Strategy_PROSOCIAL_65(BaseStrategy):
    """
    Common-pool strategy:
    - Start by cooperating.
    - Cooperate when stock is healthy and observed cooperation is sufficiently high.
    - Defect when stock is low or cooperation has been weak for two consecutive rounds.
    - Endgame is slightly cooperative if stock remains above the critical level.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.target = max(0, self.n_players - 1)
        self.safe_stock = self.capacity / 2.0
        self.critical_stock = self.capacity / 4.0

    def _required_cooperators(self, stock: float) -> int:
        if self.safe_stock <= 0:
            return self.target
        ratio = stock / self.safe_stock
        if ratio < 0.0:
            ratio = 0.0
        elif ratio > 1.0:
            ratio = 1.0
        return int(math.ceil(self.target * ratio))

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number
        if t == 0:
            return Action.C
        prev_action_was_defect = False
        if len(history.my_actions) > 0:
            prev_action_was_defect = not bool(history.my_actions[-1])
        last_c = None
        if len(history.opponent_cooperators) > 0:
            last_c = int(history.opponent_cooperators[-1])
        if t == self.n_rounds - 1:
            action = Action.C if current_stock >= self.critical_stock else Action.D
            if prev_action_was_defect and (current_stock >= self.safe_stock or (last_c is not None and last_c == self.target)):
                action = Action.C
            return action
        required = self._required_cooperators(current_stock)
        escalation = False
        if len(history.opponent_cooperators) >= 2:
            prev_c = int(history.opponent_cooperators[-2])
            if prev_c < required and last_c is not None and (last_c < required):
                escalation = True
        if current_stock <= self.critical_stock:
            action = Action.D
        elif escalation:
            action = Action.D
        elif last_c is not None and last_c >= required:
            action = Action.C
        else:
            action = Action.D
        if prev_action_was_defect and (current_stock >= self.safe_stock or (last_c is not None and last_c == self.target)):
            action = Action.C
        return action

class Strategy_PROSOCIAL_66(BaseStrategy):
    """
    Baseline cooperation with state-sensitive restraint:
    - Prefer C by default
    - Defect only under sustained overuse, low stock, or shock/caution conditions
    - Recover to C quickly when behavior and stock improve
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.prev_stock: float | None = None
        self.caution_rounds_remaining: int = 0
        self.last_defection_avg_x: float | None = None
        self.last_action: Action = Action.C

    def _zone(self, stock: float) -> str:
        if self.capacity <= 0:
            return 'low'
        s = stock / self.capacity
        if s >= 0.7:
            return 'high'
        if s >= 0.35:
            return 'medium'
        return 'low'

    def _avg_recent_x(self, history: PlayerHistory, window: int=2) -> float | None:
        n_obs = history.round_number
        if n_obs <= 0:
            return None
        n_opponents = max(self.n_players - 1, 1)
        k = min(window, n_obs)
        vals = []
        for idx in range(n_obs - k, n_obs):
            vals.append(float(history.opponent_cooperators[idx]) / n_opponents)
        if not vals:
            return None
        return float(np.mean(np.array(vals, dtype=float)))

    def _last_three_x(self, history: PlayerHistory) -> list[float]:
        n_obs = history.round_number
        if n_obs <= 0:
            return []
        n_opponents = max(self.n_players - 1, 1)
        start = max(0, n_obs - 3)
        out = []
        for idx in range(start, n_obs):
            out.append(float(history.opponent_cooperators[idx]) / n_opponents)
        return out

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        zone = self._zone(current_stock)
        if self.prev_stock is not None and self.prev_stock > 0:
            if current_stock >= self.prev_stock:
                self.caution_rounds_remaining = 0
            elif current_stock <= 0.7 * self.prev_stock:
                self.caution_rounds_remaining = 2
        avg_x = self._avg_recent_x(history, window=2)
        last_three = self._last_three_x(history)
        persistent_coop = len(last_three) == 3 and all((x >= 0.75 for x in last_three))
        persistent_overuse = len(last_three) == 3 and all((x < 0.25 for x in last_three))
        if round_number >= self.n_rounds - 1:
            if zone != 'low':
                action = Action.C
            elif avg_x is not None and avg_x < 0.5:
                action = Action.D
            else:
                action = Action.C
        elif round_number == 0:
            action = Action.C
        else:
            action = Action.C
            if persistent_coop:
                action = Action.C
            elif self.caution_rounds_remaining > 0:
                if avg_x is not None and avg_x >= 0.5:
                    action = Action.C
                else:
                    action = Action.D
                self.caution_rounds_remaining = max(0, self.caution_rounds_remaining - 1)
            else:
                if history.round_number > 0 and bool(history.my_actions[-1]) is False:
                    if zone in ('medium', 'high'):
                        action = Action.C
                    elif self.last_defection_avg_x is not None and avg_x is not None:
                        if avg_x >= self.last_defection_avg_x + 0.2:
                            action = Action.C
                if persistent_overuse:
                    action = Action.D
                else:
                    if zone == 'high':
                        if avg_x is not None and avg_x < 0.25:
                            action = Action.D
                        else:
                            action = Action.C
                    elif zone == 'medium':
                        if avg_x is None:
                            action = Action.C
                        elif avg_x >= 0.5:
                            action = Action.C
                        elif round_number == 1:
                            x_prev = float(history.opponent_cooperators[-1]) / max(self.n_players - 1, 1)
                            action = Action.D if x_prev < 0.5 else Action.C
                        else:
                            action = Action.D
                    elif avg_x is None:
                        action = Action.C if round_number == 1 else Action.D
                    elif avg_x >= 0.75:
                        action = Action.C
                    else:
                        action = Action.D
                    if round_number == 1 and avg_x is not None:
                        x_prev = float(history.opponent_cooperators[-1]) / max(self.n_players - 1, 1)
                        if zone == 'high':
                            action = Action.D if x_prev == 0 else Action.C
                        elif zone == 'medium':
                            action = Action.C if x_prev >= 0.5 else Action.D
                        else:
                            action = Action.D if x_prev < 0.75 else Action.C
        if action == Action.D and avg_x is not None:
            self.last_defection_avg_x = float(avg_x)
        self.last_action = action
        self.prev_stock = float(current_stock)
        return action

class Strategy_PROSOCIAL_67(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Start by cooperating.
    - Reward full cooperation and broadly cooperative groups.
    - Defect under severe depletion or persistent overuse.
    - On the last round, cooperate if at least half of opponents cooperated previously.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(0, self.n_players - 1)
        self.full_cooperation_mode = False
        self.protection_mode = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        if round_number == 0:
            self.full_cooperation_mode = False
            self.protection_mode = False
            return Action.C
        is_last_round = round_number >= self.n_rounds - 1
        prev_count = 0
        if len(history.opponent_cooperators) > 0:
            prev_count = history.opponent_cooperators[-1]
            if prev_count is None:
                prev_count = 0
        try:
            prev_count = float(prev_count)
        except Exception:
            prev_count = 0.0
        if self.n_opponents > 0:
            x = prev_count / self.n_opponents
        else:
            x = 0.5
        if not math.isfinite(x):
            x = 0.5
        if x < 0.0:
            x = 0.0
        elif x > 1.0:
            x = 1.0
        critical_stock = 0.35 * self.capacity
        severe_depletion = 0.2 * self.capacity
        half_capacity = 0.5 * self.capacity
        if x >= 1.0:
            self.full_cooperation_mode = True
            self.protection_mode = False
        elif x < 0.4:
            self.protection_mode = True
            self.full_cooperation_mode = False
        elif x >= 0.75:
            self.protection_mode = False
            self.full_cooperation_mode = False
        if is_last_round:
            return Action.C if x >= 0.5 else Action.D
        if current_stock <= severe_depletion:
            self.full_cooperation_mode = False
            self.protection_mode = True
            return Action.D
        if current_stock <= critical_stock:
            if x >= 1.0:
                self.full_cooperation_mode = True
                self.protection_mode = False
                return Action.C
            self.protection_mode = True
            self.full_cooperation_mode = False
            return Action.D
        if self.protection_mode:
            if x >= 0.75 or current_stock > half_capacity:
                self.protection_mode = False
            else:
                return Action.D
        if self.full_cooperation_mode and current_stock > critical_stock:
            return Action.C
        if x >= 0.75:
            return Action.C
        if 0.4 <= x < 0.75:
            if current_stock >= half_capacity:
                return Action.C
            return Action.D
        return Action.D

class Strategy_PROSOCIAL_68(BaseStrategy):
    """
    Unconditional cooperation strategy for the Common Pool Resource Game.

    This strategy always plays Action.C, regardless of history, stock level,
    round number, or opponents' previous actions.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = getattr(game_description, 'n_players', 0)
        self.n_rounds = getattr(game_description, 'n_rounds', 0)
        self.capacity = getattr(game_description, 'capacity', 0)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        return Action.C

class Strategy_PROSOCIAL_69(BaseStrategy):
    """
    Always cooperate, regardless of history or current stock.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        return Action.C

class Strategy_PROSOCIAL_70(BaseStrategy):
    """
    Default-cooperate common pool strategy:
    - Cooperate on the first round and the last round.
    - In intermediate rounds, cooperate if recent cooperation is at or above
      the majority threshold, or if the current stock is below half capacity.
    - Optionally track repeated under-cooperation via a bad_streak signal.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(getattr(game_description, 'n_players', 0) or 0)
        self.n_rounds = int(getattr(game_description, 'n_rounds', 0) or 0)
        self.capacity = float(getattr(game_description, 'capacity', 0.0) or 0.0)
        self.n_opponents = max(self.n_players - 1, 0)
        self.threshold = int(math.ceil(self.n_opponents / 2)) if self.n_opponents > 0 else 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(getattr(history, 'round_number', 0) or 0)
        if round_number == 0:
            return Action.C
        if self.n_rounds > 0 and round_number >= self.n_rounds - 1:
            return Action.C
        half_capacity = self.capacity / 2.0
        if current_stock < half_capacity:
            return Action.C
        k = self.n_opponents
        try:
            opp = history.opponent_cooperators
            if opp is not None and len(opp) > 0:
                k = int(opp[-1])
        except Exception:
            k = self.n_opponents
        bad_streak = 0
        try:
            opp = history.opponent_cooperators
            if opp is not None and len(opp) > 0:
                for idx in range(len(opp) - 1, -1, -1):
                    if int(opp[idx]) < self.threshold:
                        bad_streak += 1
                    else:
                        break
        except Exception:
            bad_streak = 0
        if k >= self.threshold:
            return Action.C
        if bad_streak >= 2 and current_stock >= half_capacity:
            return Action.D
        return Action.C

class Strategy_PROSOCIAL_71(BaseStrategy):
    """
    Cautious reciprocal strategy for the Common Pool Resource game.

    Starts by cooperating, then uses observed cooperation rate and stock health
    to remain cooperative when conditions are stable, and applies brief
    protection defections when cooperation becomes persistently low and the
    stock is under stress.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.low_coop_streak = 0
        self.punishment_cooldown = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_players = int(self.game_description.n_players)
        capacity = float(self.game_description.capacity)
        if history.round_number == 0:
            self.low_coop_streak = 0
            self.punishment_cooldown = False
            return Action.C
        prev_opponents = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        n_opponents = max(n_players - 1, 1)
        q = prev_opponents / n_opponents
        if q < 1.0 / 3.0:
            self.low_coop_streak += 1
        else:
            self.low_coop_streak = 0
        S = float(current_stock)
        is_last_round = history.round_number >= int(self.game_description.n_rounds) - 1
        if self.punishment_cooldown:
            self.punishment_cooldown = False
            return Action.C
        if is_last_round:
            if S > 0.1 * capacity or q >= 1.0 / 3.0:
                return Action.C
            return Action.D
        if S >= 0.6 * capacity:
            return Action.C
        if q >= 0.75:
            return Action.C
        if q >= 0.5:
            return Action.C
        if S <= 0.25 * capacity and q < 0.5:
            self.punishment_cooldown = True
            return Action.D
        if self.low_coop_streak >= 2:
            self.punishment_cooldown = True
            return Action.D
        return Action.C

class Strategy_PROSOCIAL_72(BaseStrategy):
    """
    Common Pool Resource strategy:
    - Start by cooperating.
    - Track a persistent mode (cooperate/defect) based on recent low cooperation
      and low stock.
    - Defect only in sustained low-cooperation, low-stock conditions; otherwise cooperate.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.mode = 'cooperate'
        self._low_risk_streak = 0
        self._last_processed_round = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = int(self.game_description.n_players)
        r = int(self.game_description.n_rounds)
        capacity = float(self.game_description.capacity)
        round_number = int(history.round_number)
        if round_number == 0:
            self.mode = 'cooperate'
            self._low_risk_streak = 0
            self._last_processed_round = 0
            return Action.C
        if current_stock <= 0.0:
            self.mode = 'cooperate'
            self._last_processed_round = round_number
            return Action.C
        prev_low_coop = False
        prev_strong_coop = False
        prev_h = 1.0
        try:
            opp_count = int(history.opponent_cooperators[-1])
            if n > 2:
                denom = float(max(n - 1, 1))
                rho = opp_count / denom
            else:
                rho = 1.0 if opp_count > 0 else 0.0
            prev_h = current_stock / capacity if capacity > 0.0 else 0.0
            prev_low_coop = rho < 1.0 / 3.0
            prev_strong_coop = rho >= 0.5
        except Exception:
            rho = 0.0
            prev_h = current_stock / capacity if capacity > 0.0 else 0.0
            prev_low_coop = False
            prev_strong_coop = False
        low_stock = prev_h < 0.25
        if low_stock and prev_low_coop:
            self._low_risk_streak += 1
        else:
            self._low_risk_streak = 0
        if prev_strong_coop or prev_h >= 0.25:
            self.mode = 'cooperate'
            self._low_risk_streak = 0
        elif self._low_risk_streak >= 2:
            self.mode = 'defect'
        else:
            self.mode = 'cooperate'
        self._last_processed_round = round_number
        if r == 2:
            return Action.C
        h = current_stock / capacity if capacity > 0.0 else 0.0
        t = round_number + 1
        if round_number > 0 and (not hasattr(history, 'opponent_cooperators')):
            return Action.C
        if t == r:
            return Action.C
        if h >= 0.25:
            return Action.C
        if prev_strong_coop:
            return Action.C
        if t < r and h < 0.25 and prev_low_coop and (self.mode == 'defect'):
            return Action.D
        return Action.C

class Strategy_PROSOCIAL_73(BaseStrategy):
    """
    Unconditional cooperation strategy for the Common Pool Resource Game.

    Always plays C in every round, regardless of history or current stock.
    Records the number of cooperating opponents after each observed round for
    monitoring only.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.opponent_cooperator_counts = []

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        if round_number > 0 and len(history.opponent_cooperators) > 0:
            self.opponent_cooperator_counts.append(int(history.opponent_cooperators[-1]))
        return Action.C

class Strategy_PROSOCIAL_74(BaseStrategy):
    """
    Conditional cooperation strategy for the Common Pool Resource game.

    The strategy cooperates initially, then adapts to:
    - recent opponent cooperation,
    - stock preservation pressure,
    - endgame caution,
    - and simple fallback rules for depleted stock or extreme opponent behavior.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(self.n_players - 1, 1)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        if round_number == 0:
            return Action.C
        opp_counts = history.opponent_cooperators
        n_obs = len(opp_counts)
        if n_obs > 0:
            prev_k = int(opp_counts[-1])
            q_prev = prev_k / self.n_opponents
        else:
            prev_k = 0
            q_prev = 0.0
        qbar = 1.0
        for k in opp_counts:
            q_t = int(k) / self.n_opponents
            qbar = 0.7 * qbar + 0.3 * q_t
        S = float(current_stock)
        cap = self.capacity

        def clamp(x: float, lo: float, hi: float) -> float:
            return max(lo, min(hi, x))
        T = clamp(1.0 - (S / cap if cap > 0 else 0.0), 0.0, 1.0)
        H = max(T, 0.5 * qbar + 0.25)
        early_cutoff = int(math.ceil(self.n_rounds / 4))
        final_cutoff = int(math.ceil(self.n_rounds / 6))
        in_final_rounds = round_number >= self.n_rounds - final_cutoff
        if S <= cap / 4.0:
            if q_prev >= 0.5 and qbar >= 0.5:
                return Action.C
            return Action.D
        if in_final_rounds:
            if qbar >= 0.6 and S >= cap / 3.0 and (q_prev >= 0.5):
                return Action.C
            return Action.D
        if q_prev >= 1.0:
            return Action.C
        if q_prev <= 0.0:
            return Action.D
        if round_number <= early_cutoff:
            if q_prev < 0.35:
                return Action.D
            return Action.C
        if qbar >= 0.5 and q_prev >= H - 0.15:
            return Action.C
        return Action.D

class Strategy_PROSOCIAL_75(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Start with cooperation.
    - Cooperate when opponent cooperation meets the stock-dependent threshold
      and the stock is safely above the critical quarter-capacity level.
    - Defect in depleted or unstable states, with special handling for final round
      and recent cooperative streaks.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(self.n_players - 1, 0)
        self.quarter_capacity = self.capacity / 4.0
        self.half_opponents = self.n_opponents / 2.0

    def _opp_rate(self, count: int) -> float:
        if self.n_opponents <= 0:
            return 0.0
        return float(count) / float(self.n_opponents)

    def _threshold(self, stock: float) -> float:
        if self.capacity <= 0:
            return 1.0
        return 1.0 - float(stock) / self.capacity

    def _last_count(self, history: PlayerHistory, idx: int=-1) -> int:
        try:
            return int(history.opponent_cooperators[idx])
        except Exception:
            return 0

    def _recent_condition(self, history: PlayerHistory, stock: float, idx: int) -> bool:
        if history.round_number + idx < 0:
            return False
        x = self._opp_rate(self._last_count(history, idx))
        return x >= self._threshold(stock) and stock > self.quarter_capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        if round_number == 0:
            return Action.C
        stock = float(current_stock)
        last_opps = self._last_count(history, -1)
        last_rate = self._opp_rate(last_opps)
        threshold = self._threshold(stock)
        if stock <= self.quarter_capacity:
            return Action.D
        if round_number >= self.n_rounds - 1:
            if stock > self.quarter_capacity and last_rate >= 0.5:
                return Action.C
            return Action.D
        if math.isclose(stock, self.capacity, rel_tol=1e-12, abs_tol=1e-12):
            return Action.D if last_opps == 0 else Action.C
        if self.n_opponents > 0 and last_opps >= self.n_opponents:
            return Action.C
        if last_opps == 0:
            return Action.D
        if round_number >= 2:
            prev_opps = self._last_count(history, -2)
            prev_rate = self._opp_rate(prev_opps)
            if last_rate >= 0.5 and prev_rate >= 0.5:
                if stock > self.quarter_capacity:
                    return Action.C
        if round_number >= 2:
            prev_opps = self._last_count(history, -2)
            prev_rate = self._opp_rate(prev_opps)
            current_support = last_rate >= threshold
            previous_support = prev_rate >= threshold
            if not (current_support and previous_support):
                return Action.D
        if last_rate >= threshold and stock > self.quarter_capacity:
            return Action.C
        return Action.D

class Strategy_PROSOCIAL_76(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Cooperate in round 1 and in the last round.
    - Otherwise, cooperate when stock is healthy or last-round cooperation was at least half.
    - Defect only once after a clear minority-cooperation round when stock is low.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self._coop_threshold = 0.5
        self._stock_threshold = 1.2 * self.n_players

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        if round_number == 0:
            return Action.C
        if round_number >= self.n_rounds - 1:
            return Action.C
        stock = float(current_stock)
        if not math.isfinite(stock):
            stock = self.capacity
        if stock < 0.0:
            stock = 0.0
        if stock >= self._stock_threshold:
            return Action.C
        if stock <= 0.0:
            return Action.C
        last_opp_coop = 0
        if len(history.opponent_cooperators) > 0:
            last_opp_coop = int(history.opponent_cooperators[-1])
        my_last_action = bool(history.my_actions[-1]) if len(history.my_actions) > 0 else True
        m = last_opp_coop + (1 if my_last_action else 0)
        n = self.n_players if self.n_players > 0 else 1
        share = m / n
        if share >= self._coop_threshold:
            return Action.C
        if stock < self._stock_threshold and share < self._coop_threshold:
            return Action.D
        return Action.C

class Strategy_PROSOCIAL_77(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Cooperates initially.
    - Uses last-round opponent cooperation rate and current stock to decide.
    - Includes simple repair, punishment, and endgame overrides.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(0, self.n - 1)
        self.last_observed_cooperators = None
        self.last_cooperation_rate = None
        self.in_repair_round = False
        self.punishment_streak = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number
        if t == 0:
            self.in_repair_round = False
            self.punishment_streak = 0
            return Action.C
        k_last = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        self.last_observed_cooperators = k_last
        m = self.n_opponents
        if m > 0:
            c_prev = k_last / m
        else:
            c_prev = 0.0
        self.last_cooperation_rate = c_prev
        S = float(current_stock)
        cap = self.capacity
        n = max(1, self.n)
        if c_prev < 0.5:
            self.punishment_streak += 1
        else:
            self.punishment_streak = 0
        if t >= self.r - 2:
            if len(history.opponent_cooperators) >= 2:
                c_prev2 = history.opponent_cooperators[-2] / m if m > 0 else 0.0
            else:
                c_prev2 = c_prev
            if c_prev < 1.0 / 3.0 and c_prev2 < 1.0 / 3.0 and (S < cap / 3.0):
                self.in_repair_round = False
                return Action.D
            self.in_repair_round = False
            return Action.C
        if m > 0 and k_last == 0:
            self.in_repair_round = False
            return Action.D
        if m > 0 and k_last == m:
            if S < cap / 5.0:
                self.in_repair_round = False
                return Action.D
            self.in_repair_round = False
            return Action.C
        if S <= 1e-12:
            self.in_repair_round = False
            return Action.D
        if cap > 0 and S >= cap and (c_prev < 0.5):
            self.in_repair_round = False
            return Action.C
        if S <= cap / 20.0:
            if c_prev >= 2.0 / 3.0:
                self.in_repair_round = False
                return Action.C
            self.in_repair_round = False
            return Action.D
        if n > 0:
            E_consume_C = S / (2.0 * n) + k_last * S / (2.0 * n) + max(0, m - k_last) * S / n
            E_consume_D = S / n + k_last * S / (2.0 * n) + max(0, m - k_last) * S / n
        else:
            E_consume_C = 0.0
            E_consume_D = 0.0
        R_C = S - E_consume_C
        R_D = S - E_consume_D
        if c_prev < 0.5:
            self.in_repair_round = False
            if self.punishment_streak >= 2 and c_prev <= 0.0:
                return Action.D
            return Action.D
        if self.punishment_streak > 0 and c_prev >= 0.5:
            self.punishment_streak = 0
        if abs(c_prev - 0.5) <= 1e-12:
            self.in_repair_round = False
            return Action.C if S >= cap / 2.0 else Action.D
        baseline_cooperate = c_prev > 0.5 and R_C >= cap / 4.0
        if c_prev >= 0.5 and S < cap / 2.0:
            self.in_repair_round = True
            return Action.C
        if self.in_repair_round:
            self.in_repair_round = False
            return Action.C if baseline_cooperate else Action.D
        if abs(S - cap) <= 1e-12:
            self.in_repair_round = False
            return Action.C if c_prev >= 0.5 else Action.D
        if c_prev >= 0.5 and R_C >= cap / 4.0:
            self.in_repair_round = False
            return Action.C
        if c_prev >= 0.5 and S >= cap / 2.0:
            self.in_repair_round = False
            return Action.C
        self.in_repair_round = False
        return Action.D

class Strategy_PROSOCIAL_78(BaseStrategy):
    """
    Cooperative default strategy with a trust score that rewards sustained
    cooperation and briefly defects against persistent under-cooperation.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.trust_score = 1
        self.last_seen_round = -1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_rounds = self.game_description.n_rounds
        capacity = float(self.game_description.capacity)
        round_number = history.round_number
        if round_number == 0:
            self.trust_score = 1
            self.last_seen_round = 0
            return Action.C
        n_players = self.game_description.n_players
        n_opponents = max(n_players - 1, 1)
        trust = 1
        for opp_count in history.opponent_cooperators[:round_number]:
            q = float(opp_count) / float(n_opponents)
            if q == 1.0:
                trust = min(trust + 1, 3)
            elif q >= 0.75:
                trust = min(trust + 1, 3)
            elif q < 0.25:
                trust = max(trust - 1, 0)
        self.trust_score = trust
        self.last_seen_round = round_number
        last_q = float(history.opponent_cooperators[-1]) / float(n_opponents)
        last_action_defected = bool(not history.my_actions[-1])
        prev_two_low = False
        if round_number >= 2:
            q_prev1 = float(history.opponent_cooperators[-1]) / float(n_opponents)
            q_prev2 = float(history.opponent_cooperators[-2]) / float(n_opponents)
            prev_two_low = q_prev1 < 0.25 and q_prev2 < 0.25
        if round_number == n_rounds - 1:
            if prev_two_low:
                return Action.D
            return Action.C
        if current_stock <= capacity / 8.0:
            if last_q == 1.0 and trust == 3:
                return Action.C
            return Action.D
        if current_stock <= capacity / 4.0:
            if last_q == 1.0:
                return Action.C
            return Action.D
        if last_action_defected and last_q >= 0.75:
            return Action.C
        if round_number >= 2:
            if bool(not history.my_actions[-2]) and last_action_defected and (last_q == 1.0):
                self.trust_score = 2
                return Action.C
        if trust >= 1 and current_stock > 0 and (last_q >= 0.5):
            return Action.C
        return Action.D

class Strategy_PROSOCIAL_79(BaseStrategy):
    """
    Always cooperate in every round.
    Internally tracks opponent cooperation patterns and stock levels for monitoring
    only, but never switches to defection.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.last_opponent_cooperation_count = None
        self.current_stock_level = None
        self.consecutive_low_cooperation_rounds = 0
        self.max_low_cooperation_streak = 0
        n_players = getattr(game_description, 'n_players', 0)
        self.n_opponents = max(0, n_players - 1)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        self.current_stock_level = current_stock
        if history.round_number > 0:
            last_count = int(history.opponent_cooperators[-1])
            self.last_opponent_cooperation_count = last_count
            if self.n_opponents > 0:
                if last_count < self.n_opponents:
                    self.consecutive_low_cooperation_rounds += 1
                else:
                    self.consecutive_low_cooperation_rounds = 0
            else:
                self.consecutive_low_cooperation_rounds = 0
            if self.consecutive_low_cooperation_rounds > self.max_low_cooperation_streak:
                self.max_low_cooperation_streak = self.consecutive_low_cooperation_rounds
        else:
            self.last_opponent_cooperation_count = None
            self.consecutive_low_cooperation_rounds = 0
        return Action.C

class Strategy_PROSOCIAL_80(BaseStrategy):
    """
    Cooperative default strategy with temporary defections when cooperation drops
    below sustainability thresholds or the stock becomes endangered.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.half_capacity = self.capacity / 2.0
        self.quarter_capacity = self.capacity / 4.0
        self._opponent_count = max(self.n_players - 1, 1)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = int(history.round_number)
        if t == 0:
            return Action.C
        last_k = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else self._opponent_count
        last_q = last_k / self._opponent_count if self._opponent_count > 0 else 1.0
        last_my_action = bool(history.my_actions[-1]) if len(history.my_actions) > 0 else True
        recent_start = max(0, len(history.opponent_cooperators) - 3)
        recent_slice = history.opponent_cooperators[recent_start:]
        recent_good_rounds = 0
        for c in recent_slice:
            if int(c) / self._opponent_count if self._opponent_count > 0 else 1.0 >= 0.5:
                recent_good_rounds += 1
        if not last_my_action and (last_q >= 0.5 or current_stock >= self.half_capacity):
            return Action.C
        if len(recent_slice) >= 3 and recent_good_rounds >= 2:
            return Action.C
        if t == self.n_rounds - 1:
            return Action.C if last_q >= 0.5 else Action.D
        if t == self.n_rounds - 2:
            if current_stock >= self.half_capacity:
                return Action.C
            return Action.C if last_q >= 0.5 else Action.D
        if current_stock < self.quarter_capacity and last_q < 0.5:
            return Action.D
        if last_q >= 0.5:
            return Action.C
        return Action.D

class Strategy_PROSOCIAL_81(BaseStrategy):
    """
    Default-to-cooperation common-pool strategy:
    - Cooperate on the first and final rounds.
    - In intermediate rounds, defect only after two consecutive rounds of low
      opponent cooperation combined with a falling stock.
    - Resume cooperation immediately when cooperation recovers or the stock
      stops falling.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self._prev_stock = None
        self._prev_q = None
        self._last_action = Action.C

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_players = self.game_description.n_players
        n_opponents = max(0, n_players - 1)
        round_number = history.round_number
        is_first_round = round_number == 0
        is_final_round = round_number >= max(0, self.game_description.n_rounds - 1)
        if is_first_round:
            self._prev_stock = current_stock
            self._prev_q = None
            self._last_action = Action.C
            return Action.C
        if n_opponents > 0 and len(history.opponent_cooperators) > 0:
            q = float(history.opponent_cooperators[-1]) / float(n_opponents)
        else:
            q = 1.0
        if self._prev_stock is None:
            self._prev_stock = current_stock
            self._prev_q = q
            self._last_action = Action.C
            return Action.C
        if is_final_round:
            self._prev_stock = current_stock
            self._prev_q = q
            self._last_action = Action.C
            return Action.C
        if current_stock <= 0.0:
            self._prev_stock = current_stock
            self._prev_q = q
            self._last_action = Action.C
            return Action.C
        if q >= 0.5 or current_stock >= self.game_description.capacity / 2.0:
            self._prev_stock = current_stock
            self._prev_q = q
            self._last_action = Action.C
            return Action.C
        q_prev = self._prev_q if self._prev_q is not None else 1.0
        stock_falling = current_stock < self._prev_stock
        if q < 0.5 and q_prev < 0.5 and stock_falling:
            action = Action.D
        else:
            action = Action.C
        self._prev_stock = current_stock
        self._prev_q = q
        self._last_action = action
        return action

class Strategy_PROSOCIAL_82(BaseStrategy):
    """
    Prosocial common-pool strategy:
    - Always cooperate.
    - Maintains an internal forecast of future stock based on observed opponent cooperation,
      but never uses it to defect.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(getattr(game_description, 'n_players', 0) or 0)
        self.n_rounds = int(getattr(game_description, 'n_rounds', 0) or 0)
        self.capacity = float(getattr(game_description, 'capacity', 0.0) or 0.0)
        self.n_opponents = max(self.n_players - 1, 0)
        self.forecast_stock = self.capacity
        self.forecast_history = []

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(getattr(history, 'round_number', 0) or 0)
        if round_number > 0 and self.n_players > 0:
            last_k = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
            last_k = max(0, min(last_k, self.n_opponents))
            coop_fraction = last_k / self.n_opponents if self.n_opponents > 0 else 0.0
            self.forecast_history.append(coop_fraction)
            S = float(current_stock)
            S = max(0.0, S)
            my_consumption = S / (2.0 * self.n_players) if self.n_players > 0 else 0.0
            expected_opponent_consumption = 0.0
            if self.n_players > 1:
                expected_opponent_consumption = (coop_fraction * (S / (2.0 * self.n_players)) + (1.0 - coop_fraction) * (S / self.n_players)) * self.n_opponents
            remaining = S - (my_consumption + expected_opponent_consumption)
            if remaining < 0.0:
                remaining = 0.0
            growth = 2.0 * remaining * (1.0 - remaining / self.capacity) if self.capacity > 0.0 else 0.0
            forecast_next = remaining + growth
            if forecast_next > self.capacity:
                forecast_next = self.capacity
            if forecast_next < 0.0:
                forecast_next = 0.0
            self.forecast_stock = forecast_next
        else:
            self.forecast_stock = float(current_stock) if current_stock is not None else self.capacity
        return Action.C

class Strategy_PROSOCIAL_83(BaseStrategy):
    """
    Stock-sensitive reciprocal cooperation strategy for the Common Pool Resource game.

    - Start with cooperation.
    - Use the previous round's opponent cooperation rate and current stock health
      to decide whether to cooperate or defect.
    - Defect only as a brief restraint when cooperation is too low for the
      current stock condition, and return to cooperation as soon as opponents
      restore cooperation.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(self.n_players - 1, 1)
        self.healthy_threshold = 0.75 * self.capacity
        self.strained_threshold = 0.4 * self.capacity

    def _opponent_cooperation_rate(self, history: PlayerHistory) -> float:
        if history.round_number == 0:
            return 1.0
        last_cooperators = int(history.opponent_cooperators[-1])
        return last_cooperators / float(self.n_opponents)

    def _stock_state(self, current_stock: float) -> str:
        if current_stock >= self.healthy_threshold:
            return 'healthy'
        if current_stock >= self.strained_threshold:
            return 'strained'
        return 'critical'

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        if round_number == 0:
            return Action.C
        if round_number == self.n_rounds - 1:
            if current_stock >= self.strained_threshold:
                return Action.C
            last_c = self._opponent_cooperation_rate(history)
            return Action.D if last_c < 1.0 else Action.C
        c = self._opponent_cooperation_rate(history)
        stock_state = self._stock_state(current_stock)
        prev_action_is_defect = bool(history.my_actions[-1]) is False
        if prev_action_is_defect and c >= 0.75:
            return Action.C
        if stock_state == 'critical':
            return Action.C if c >= 1.0 else Action.D
        if stock_state == 'strained':
            return Action.C if c >= 0.75 else Action.D
        return Action.C if c >= 0.5 else Action.D

class Strategy_PROSOCIAL_84(BaseStrategy):
    """
    Always cooperate in every round, regardless of history or current stock.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        return Action.C

class Strategy_PROSOCIAL_85(BaseStrategy):
    """
    Conditional cooperation with repair mode, stock preservation, and late-round caution.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.repair_mode = False
        self.last_observed_opponent_cooperators = None
        self.last_seen_round = -1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = int(self.game_description.n_players)
        rounds_total = int(self.game_description.n_rounds)
        capacity = float(self.game_description.capacity)
        n_opponents = max(n - 1, 0)
        c_star = math.ceil(n_opponents / 2) if n_opponents > 0 else 0
        strict_threshold = max(c_star - 1, 0)
        round_number = int(history.round_number)
        if round_number == 0:
            self.repair_mode = False
            self.last_observed_opponent_cooperators = None
            self.last_seen_round = 0
            return Action.C
        prev_k = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        self.last_observed_opponent_cooperators = prev_k
        self.last_seen_round = round_number
        remaining_rounds = max(rounds_total - round_number, 0)
        half_capacity = capacity / 2.0
        third_capacity = capacity / 3.0
        three_quarters_capacity = 3.0 * capacity / 4.0
        low_stock = current_stock < third_capacity
        medium_stock = third_capacity <= current_stock < half_capacity
        high_stock = current_stock >= half_capacity
        very_high_stock = current_stock >= three_quarters_capacity
        if remaining_rounds <= 2:
            if high_stock and prev_k >= c_star:
                return Action.C
            return Action.D
        if low_stock or prev_k < c_star:
            if not self.repair_mode:
                self.repair_mode = True
                return Action.C if current_stock > 0 else Action.D
        if self.repair_mode:
            if high_stock and prev_k >= c_star:
                self.repair_mode = False
                return Action.C
            return Action.D
        if high_stock and prev_k >= c_star:
            return Action.C
        if very_high_stock and prev_k >= strict_threshold:
            return Action.C
        if medium_stock and prev_k == n_opponents:
            return Action.C
        return Action.D

class Strategy_PROSOCIAL_86(BaseStrategy):
    """
    Prosocial default strategy for the Common Pool Resource game.

    - Cooperate in round 1.
    - Continue cooperating when stock is healthy and prior cooperation is at least half.
    - Defect only as a restraint when stock is low and prior cooperation was weak.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(0, self.n_players - 1)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        prev_coop = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        denom = self.n_opponents if self.n_opponents > 0 else 1
        q = prev_coop / denom
        s = float(current_stock)
        half_capacity = self.capacity / 2.0
        third_capacity = self.capacity / 3.0
        if s >= half_capacity and q >= 0.5:
            return Action.C
        if s < third_capacity and q < 0.5:
            return Action.D
        return Action.C

class Strategy_PROSOCIAL_87(BaseStrategy):
    """
    Cooperative-by-default strategy that conditions cooperation on recent opponent
    cooperation and current stock stress, with quick forgiveness after renewed
    cooperation and restrained defection only after repeated weak behavior.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.low_coop_threshold = 0.5
        self.high_coop_threshold = 0.75
        self.ema_alpha = 0.3
        self.ema_decay = 1.0 - self.ema_alpha
        self.critical_stock = game_description.capacity / 3.0
        self.warning_stock = game_description.capacity / 2.0
        self.n_opponents = max(0, game_description.n_players - 1)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number
        if t == 0:
            return Action.C
        last_opp_c = int(history.opponent_cooperators[-1])
        if self.n_opponents > 0:
            coop_rate_prev = max(0.0, min(1.0, last_opp_c / self.n_opponents))
        else:
            coop_rate_prev = 1.0
        oppC_avg = 1.0
        streak_low = 0
        streak_high = 0
        for coop_count in history.opponent_cooperators:
            if self.n_opponents > 0:
                coop_rate = max(0.0, min(1.0, int(coop_count) / self.n_opponents))
            else:
                coop_rate = 1.0
            oppC_avg = self.ema_decay * oppC_avg + self.ema_alpha * coop_rate
            if coop_rate < self.low_coop_threshold:
                streak_low += 1
                streak_high = 0
            elif coop_rate >= self.high_coop_threshold:
                streak_high += 1
                streak_low = 0
            else:
                streak_low = 0
                streak_high = 0
        if t == self.game_description.n_rounds - 1:
            if coop_rate_prev < self.low_coop_threshold and current_stock <= self.critical_stock:
                return Action.D
            return Action.C
        rounds_left = self.game_description.n_rounds - t
        if rounds_left <= 3:
            if oppC_avg >= self.low_coop_threshold or streak_high > 0:
                return Action.C
            if current_stock <= self.critical_stock and streak_low >= 2:
                return Action.D
            return Action.C
        if streak_low >= 2 or (current_stock <= self.critical_stock and oppC_avg < self.low_coop_threshold):
            return Action.D
        if current_stock > self.critical_stock or oppC_avg >= self.high_coop_threshold:
            return Action.C
        if current_stock >= self.warning_stock:
            if streak_low >= 1 and oppC_avg < self.high_coop_threshold:
                return Action.D
            return Action.C
        if self.critical_stock < current_stock < self.warning_stock:
            if oppC_avg >= self.low_coop_threshold and streak_low < 2:
                return Action.C
            if streak_low == 1 and current_stock <= self.warning_stock:
                return Action.D
            return Action.C
        if oppC_avg >= self.high_coop_threshold or streak_high > 0 or coop_rate_prev >= self.high_coop_threshold:
            return Action.C
        if coop_rate_prev < self.low_coop_threshold and current_stock <= self.critical_stock:
            return Action.D
        return Action.C

class Strategy_PROSOCIAL_88(BaseStrategy):
    """
    Always cooperate in every round, regardless of history or current stock.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = getattr(game_description, 'n_players', None)
        self.n_rounds = getattr(game_description, 'n_rounds', None)
        self.capacity = getattr(game_description, 'capacity', None)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        return Action.C

class Strategy_PROSOCIAL_89(BaseStrategy):
    """
    Cooperative-start, pool-protecting strategy with simple memory of the
    previous round's opponent cooperation count.

    Rules:
    - Cooperate in round 1.
    - In later rounds, prioritize protecting low stock by cooperating when
      stock is at or below half capacity.
    - Otherwise, respond to the previous round's cooperation level:
      full cooperation -> cooperate,
      no cooperation -> defect once,
      majority cooperation -> cooperate,
      minority cooperation -> defect.
    - In the final round, defect only after a strict majority of opponents
      defected in the previous round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        if round_number == 0:
            return Action.C
        m = self.n_players - 1
        k = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        if m <= 0:
            return Action.C
        half_capacity = self.capacity / 2.0
        majority_threshold = math.ceil(m / 2)
        if round_number >= self.n_rounds - 1:
            if k < majority_threshold:
                return Action.D
            return Action.C
        if current_stock <= half_capacity:
            return Action.C
        if k == m:
            return Action.C
        if k == 0:
            return Action.D
        coop_rate = k / m
        if coop_rate >= 0.5:
            return Action.C
        return Action.D

class Strategy_PROSOCIAL_90(BaseStrategy):
    """
    Always cooperate strategy for the Common Pool Resource Game.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self._intended_action = Action.C

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        return self._intended_action

class Strategy_PROSOCIAL_91(BaseStrategy):
    """
    Cooperative default strategy for the Common Pool Resource Game.

    Core idea:
    - Cooperate initially.
    - Favor cooperation when opponents are sufficiently cooperative or the stock is healthy.
    - Use defection only as a temporary response to severe under-cooperation or rapid stock collapse.
    - Track recent stock movement and cooperation streaks to support forgiveness and repair.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self._last_stock = None
        self._prev_stock = None
        self._low_trust_streak = 0
        self._uncond_coop_lock = 0
        self._last_seen_round = -1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = float(self.game_description.capacity)
        round_number = history.round_number
        if round_number == 0:
            self._last_stock = float(current_stock)
            self._prev_stock = None
            self._low_trust_streak = 0
            self._uncond_coop_lock = 0
            self._last_seen_round = 0
            return Action.C
        n_opponents = max(n - 1, 1)
        last_opp_coop = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        x = last_opp_coop / n_opponents
        stock_now = float(current_stock)
        stock_prev = self._last_stock if self._last_stock is not None else stock_now
        stock_prev_prev = self._prev_stock if self._prev_stock is not None else stock_prev
        stock_increased_last_round = stock_now > stock_prev + 1e-12
        if stock_prev > 1e-12:
            stock_drop_frac = max(0.0, (stock_prev - stock_now) / stock_prev)
        else:
            stock_drop_frac = 0.0
        baseline = 2.0 / 3.0
        high_trust = 3.0 / 4.0
        low_trust = 1.0 / 2.0
        critical = 1.0 / 3.0
        if x < low_trust:
            self._low_trust_streak += 1
        else:
            self._low_trust_streak = 0
        if self._low_trust_streak >= 2:
            self._uncond_coop_lock = 1
        is_last_round = round_number >= r - 1
        if stock_now <= 2.0 * n:
            action = Action.C
        elif stock_drop_frac > 0.5 and x < 1.0 - 1e-12:
            action = Action.D
        elif stock_drop_frac > 0.25 and x < 2.0 / 3.0 - 1e-12:
            action = Action.D
        elif self._uncond_coop_lock > 0:
            if x >= high_trust:
                action = Action.C
                self._uncond_coop_lock = 0
            else:
                action = Action.D
        elif is_last_round:
            if x >= critical or stock_now <= 2.0 * n:
                action = Action.C
            else:
                action = Action.D
        elif x >= high_trust:
            action = Action.C
        elif x >= baseline and stock_now >= 0.6 * capacity:
            action = Action.C
        elif x >= low_trust and stock_increased_last_round:
            action = Action.C
        elif len(history.opponent_cooperators) >= 2 and history.opponent_cooperators[-2] == 0:
            action = Action.C
        elif last_opp_coop == n - 1 and stock_drop_frac <= 0.25:
            action = Action.C
        else:
            action = Action.D
        if action == Action.D and x >= baseline and (self._low_trust_streak == 0):
            if stock_now >= 0.6 * capacity or x >= high_trust:
                action = Action.C
        self._prev_stock = self._last_stock
        self._last_stock = stock_now
        self._last_seen_round = round_number
        return action

class Strategy_PROSOCIAL_92(BaseStrategy):
    """
    Guarded reciprocity with stock-based restraint:
    cooperate early, reward sustained cooperation, defect briefly after weak
    cooperation, and immediately return to cooperation when the pool is low
    or the group shows recovery.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.capacity = float(game_description.capacity)
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.moving_average = 1.0
        self.low_streak = 0
        self.last_observed_cooperation_rate = 1.0
        self.last_round_seen = 0

    def _compute_recency_state(self, history: PlayerHistory) -> tuple[float, int, float]:
        """
        Reconstruct m_t, low_t, and the most recent x_t from history.
        """
        m = 1.0
        low = 0
        last_x = 1.0
        n_opponents = max(self.n_players - 1, 1)
        for c_t in history.opponent_cooperators:
            x_t = float(c_t) / float(n_opponents)
            last_x = x_t
            m = 0.7 * m + 0.3 * x_t
            if x_t >= 0.5:
                low = 0
            else:
                low += 1
        return (m, low, last_x)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number + 1
        if history.round_number == 0:
            self.moving_average = 1.0
            self.low_streak = 0
            self.last_observed_cooperation_rate = 1.0
            self.last_round_seen = t
            return Action.C
        m_prev, low_prev, x_prev = self._compute_recency_state(history)
        self.moving_average = m_prev
        self.low_streak = low_prev
        self.last_observed_cooperation_rate = x_prev
        self.last_round_seen = t
        cap = self.capacity
        s = float(current_stock)
        if s <= cap / 8.0:
            action = Action.C
        elif s <= cap / 4.0:
            action = Action.C
        elif m_prev >= 0.7 and low_prev == 0:
            action = Action.C
        elif m_prev >= 0.4:
            action = Action.C if x_prev >= 0.5 else Action.D
        else:
            action = Action.C if x_prev >= 0.5 or s > cap / 2.0 else Action.D
        if t == self.n_rounds:
            if m_prev < 0.4 and s > cap / 2.0:
                action = Action.D
            else:
                action = Action.C
        elif t == self.n_rounds - 1:
            if m_prev < 0.4 and low_prev >= 2:
                action = Action.D
        if action == Action.D and (x_prev >= 0.5 or s > cap / 2.0):
            action = Action.C
        return action

class Strategy_PROSOCIAL_93(BaseStrategy):
    """
    Contingent common-pool strategy with conserve, stabilize, and repair modes.
    Uses observed cooperation history plus remembered previous stock to react to
    depletion, endgame pressure, and recovery signals.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self._prev_stock = float(game_description.capacity)
        self._last_seen_round = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = int(self.game_description.n_players)
        r = int(self.game_description.n_rounds)
        capacity = float(self.game_description.capacity)
        round_number = int(history.round_number)
        m = max(n - 1, 0)
        if round_number == 0:
            self._prev_stock = float(current_stock)
            self._last_seen_round = 0
            return Action.C
        opp = history.opponent_cooperators
        my_actions = history.my_actions

        def x_at(idx: int) -> float:
            if idx < 0 or idx >= len(opp) or m <= 0:
                return 1.0
            return float(opp[idx]) / float(m)
        prev_x_values = [x_at(i) for i in range(round_number)]
        b = float(np.mean(prev_x_values)) if prev_x_values else 1.0
        prev_x = x_at(round_number - 1)
        prev_prev_x = x_at(round_number - 2) if round_number >= 2 else 1.0
        q = float(current_stock) / capacity if capacity > 0 else 1.0
        T = max(0.5, b - 1.0 / 6.0)
        prev_stock = float(self._prev_stock)
        stock_dropped_20 = prev_stock > 0 and float(current_stock) < 0.8 * prev_stock
        prev_my_defect = bool(not my_actions[-1]) if len(my_actions) > 0 else False
        prev_two_high = prev_x >= 2.0 / 3.0 and prev_prev_x >= 2.0 / 3.0
        stable_coop = prev_two_high and q >= 0.5
        repair_active = False
        repair_remaining = 0
        if round_number >= 1 and prev_x < 1.0 / 3.0:
            repair_active = True
            repair_remaining = 2
        for t in range(1, round_number):
            x_prev_round = x_at(t - 1)
            if x_prev_round < 1.0 / 3.0:
                repair_active = True
                repair_remaining = 2
            elif x_prev_round >= 0.5:
                repair_active = False
                repair_remaining = 0
            elif repair_active and repair_remaining > 0:
                repair_remaining -= 1
                if repair_remaining <= 0:
                    repair_active = False
        if round_number == 1:
            action = Action.C
        else:
            final_three = round_number > r - 3
            overexploitation_response = prev_my_defect and stock_dropped_20 and (q >= 1.0 / 5.0)
            if final_three:
                if q >= 1.0 / 3.0:
                    action = Action.C
                elif prev_x < 1.0 / 3.0:
                    action = Action.D
                else:
                    action = Action.C
            elif stable_coop:
                action = Action.C
            elif overexploitation_response:
                action = Action.C
            elif repair_active:
                action = Action.C if q >= 1.0 / 4.0 else Action.D
            elif q >= 1.0 / 3.0 and (prev_x >= T or round_number == 2) and (current_stock >= 0.85 * prev_stock):
                action = Action.C
            else:
                action = Action.D
            if final_three and action == Action.D and (len(my_actions) > 0) and (not my_actions[-1]) and (prev_x >= 0.5):
                action = Action.C
        self._prev_stock = float(current_stock)
        self._last_seen_round = round_number
        return action

class Strategy_PROSOCIAL_94(BaseStrategy):
    """
    Common-pool strategy that starts cooperatively, rewards sustained cooperation,
    and becomes defensive when cooperation or stock health deteriorates.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.bad_last_round = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_players = int(self.game_description.n_players)
        n_rounds = int(self.game_description.n_rounds)
        capacity = float(self.game_description.capacity)
        if history.round_number == 0:
            self.bad_last_round = False
            return Action.C
        n_opponents = max(n_players - 1, 1)
        prev_k = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        coop_rate = prev_k / n_opponents
        healthy_stock = 0.0 if capacity <= 0 else current_stock / capacity
        current_round_index = history.round_number + 1
        is_final_round = current_round_index == n_rounds
        if current_stock <= capacity / 6.0 or current_stock <= 0.0:
            action = Action.D
        elif is_final_round:
            if coop_rate >= 0.5 and current_stock > 0.0:
                action = Action.C
            else:
                action = Action.D
        elif coop_rate < 1.0 / 3.0:
            action = Action.D
        elif self.bad_last_round and coop_rate < 0.5:
            action = Action.D
        elif healthy_stock >= 0.5 and coop_rate >= 1.0 / 3.0:
            action = Action.C
        elif healthy_stock >= 0.25 and coop_rate >= 0.5:
            action = Action.C
        else:
            action = Action.D
        self.bad_last_round = coop_rate < 0.5
        return action

class Strategy_PROSOCIAL_95(BaseStrategy):
    """
    Conservative common-pool strategy:
    - Cooperate initially and in the final round.
    - Cooperate when stock is low or cooperation has recently been sustained.
    - Use at most isolated corrective defections after repeated free-riding,
      then immediately return to cooperation.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.force_cooperate_next = False
        self.coop_streak = 0
        self.free_ride_streak = 0
        self.last_action = Action.C

    def _round_fraction(self, opponent_cooperators: int) -> float:
        n = self.game_description.n_players
        if n <= 2:
            return 1.0 if opponent_cooperators >= 1 else 0.0
        denom = max(n - 1, 1)
        return float(opponent_cooperators) / float(denom)

    def _compute_streaks(self, history: PlayerHistory) -> tuple[int, int]:
        coop_streak = 0
        free_ride_streak = 0
        for opp_c in history.opponent_cooperators[::-1]:
            f = self._round_fraction(int(opp_c))
            if f >= 0.5:
                coop_streak += 1
            else:
                break
        for opp_c in history.opponent_cooperators[::-1]:
            f = self._round_fraction(int(opp_c))
            if f <= 1.0 / 3.0:
                free_ride_streak += 1
            else:
                break
        return (coop_streak, free_ride_streak)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_rounds = self.game_description.n_rounds
        capacity = float(self.game_description.capacity)
        if history.round_number >= n_rounds - 1:
            self.force_cooperate_next = False
            self.last_action = Action.C
            self.coop_streak, self.free_ride_streak = self._compute_streaks(history)
            return Action.C
        self.coop_streak, self.free_ride_streak = self._compute_streaks(history)
        if self.force_cooperate_next:
            self.force_cooperate_next = False
            self.last_action = Action.C
            return Action.C
        if history.round_number == 0:
            self.last_action = Action.C
            return Action.C
        if current_stock <= 0.0:
            self.last_action = Action.C
            return Action.C
        if current_stock <= capacity / 3.0:
            self.last_action = Action.C
            return Action.C
        if self.coop_streak >= 2:
            self.last_action = Action.C
            return Action.C
        if self.free_ride_streak >= 2 and current_stock > 2.0 * capacity / 3.0:
            self.force_cooperate_next = True
            self.last_action = Action.D
            return Action.D
        self.last_action = Action.C
        return Action.C

class Strategy_PROSOCIAL_96(BaseStrategy):
    """
    Always cooperate in every round of the common pool resource game.
    Optionally records opponent cooperation counts as diagnostic history, but
    never uses them to change the action.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.observed_opponent_cooperators = []
        self.observed_stock = []
        self.last_action = Action.C

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number > 0 and len(history.opponent_cooperators) > 0:
            self.observed_opponent_cooperators.append(int(history.opponent_cooperators[-1]))
        self.observed_stock.append(float(current_stock))
        self.last_action = Action.C
        return Action.C

class Strategy_PROSOCIAL_97(BaseStrategy):
    """
    Conservative common-pool strategy:
    - Cooperate initially and by default.
    - Defect only when recent opponent cooperation is persistently low,
      the stock is already in the lower half, and it is not a terminal
      or critically depleted situation.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(0, self.n_players - 1)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        if round_number == 0:
            return Action.C
        if current_stock <= 0:
            return Action.C
        floor_high = 0.5
        floor_low = 1.0 / 3.0
        if round_number >= self.n_rounds - 1:
            return Action.C
        if current_stock <= self.capacity / 4.0:
            return Action.C
        m = min(3, round_number)
        if m <= 0 or self.n_opponents <= 0:
            recent_avg = 1.0
        else:
            recent_slice = history.opponent_cooperators[-m:]
            recent_avg = float(np.mean(recent_slice)) / float(self.n_opponents)
        if recent_avg >= floor_high:
            return Action.C
        if recent_avg < floor_low and current_stock < self.capacity / 2.0:
            if round_number >= 2 and self.n_opponents > 0:
                last_two = history.opponent_cooperators[-2:]
                low_threshold = floor_low * float(self.n_opponents)
                if len(last_two) == 2 and all((int(x) < low_threshold for x in last_two)):
                    return Action.D
        return Action.C

class Strategy_PROSOCIAL_98(BaseStrategy):
    """
    Cooperative default strategy with adaptive trust and recovery from exploitation.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self._trust = 0.0
        self._last_seen_round = 0

    def _clamp_trust(self, value: float) -> float:
        return max(-3.0, min(3.0, value))

    def _compute_trust(self, history: PlayerHistory) -> float:
        n_players = self.game_description.n_players
        m = max(0, n_players - 1)
        trust = 0.0
        rounds = history.round_number
        for idx in range(rounds):
            k = int(history.opponent_cooperators[idx])
            if k == m:
                trust += 1.0
            elif k >= m - 1:
                trust += 0.5
            elif k <= m / 2:
                trust -= 1.0
            else:
                trust -= 0.5
            trust = self._clamp_trust(trust)
        return trust

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_players = self.game_description.n_players
        n_rounds = self.game_description.n_rounds
        capacity = float(self.game_description.capacity)
        m = max(0, n_players - 1)
        if history.round_number != self._last_seen_round:
            self._trust = self._compute_trust(history)
            self._last_seen_round = history.round_number
        t = history.round_number + 1
        S = float(current_stock)
        k = int(history.opponent_cooperators[-1]) if history.round_number > 0 else m
        previous_action = bool(history.my_actions[-1]) if history.round_number > 0 else None
        if t == 1:
            return Action.C
        if S <= 0.0:
            return Action.C
        if S <= 2.0 * n_players:
            return Action.C if k == m else Action.D
        if t == n_rounds:
            return Action.C if S >= capacity / 4.0 and self._trust > -2.0 else Action.D
        if S <= capacity / 6.0:
            return Action.D
        if self._trust <= -2.0 and k <= m / 2.0:
            return Action.D
        if S >= capacity / 3.0 and self._trust > -2.0 and (k >= m - 1 or history.round_number == 0):
            return Action.C
        if previous_action is False and (k >= m - 1 or S >= capacity / 2.0):
            return Action.C
        return Action.C

class Strategy_PROSOCIAL_99(BaseStrategy):
    """
    Always cooperate in every round, regardless of stock level or history.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        return Action.C

class Strategy_PROSOCIAL_100(BaseStrategy):
    """
    Cooperation-first strategy with conditional restraint and short recovery mode
    after a fully defective opponent round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self._in_recovery = False
        self._recovery_left = 0
        self._last_processed_round = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = float(self.game_description.capacity)
        round_number = history.round_number
        if round_number > self._last_processed_round:
            last_c = 0.0
            if len(history.opponent_cooperators) > 0:
                m = max(n - 1, 0)
                if m > 0:
                    last_c = float(history.opponent_cooperators[-1]) / float(m)
                else:
                    last_c = 0.0
            if self._in_recovery and last_c >= 0.5:
                self._in_recovery = False
                self._recovery_left = 0
            if last_c == 0.0:
                self._in_recovery = True
                self._recovery_left = 3
            self._last_processed_round = round_number
        if round_number == 0:
            return Action.C
        if round_number == r - 1:
            return Action.C
        if current_stock <= 0.0:
            return Action.C
        if self._in_recovery:
            self._recovery_left -= 1
            if self._recovery_left <= 0:
                self._in_recovery = False
                self._recovery_left = 0
            return Action.C
        stock_ratio = current_stock / capacity if capacity > 0 else 0.0
        if stock_ratio >= 0.5:
            return Action.C
        m = n - 1
        c = 0.0
        if m > 0 and len(history.opponent_cooperators) > 0:
            c = float(history.opponent_cooperators[-1]) / float(m)
        if c >= 2.0 / 3.0:
            return Action.C
        return Action.D

class Strategy_PROSOCIAL_101(BaseStrategy):
    """
    Conditional cooperater for the common-pool resource game.

    Core idea:
    - Round 1: cooperate.
    - If stock is depleted to 0: defect until stock becomes positive again.
    - For n = 2: cooperate only if the other player cooperated last round and stock >= 4.
    - For n > 2: cooperate only under high-opponent-cooperation, sufficient stock,
      and after any low-cooperation phase only once two consecutive high rounds have occurred.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.capacity = float(game_description.capacity)
        self._two_thirds_threshold = math.ceil(2 * (self.n - 1) / 3) if self.n > 1 else 0
        self._half_opponents_threshold = (self.n - 1) / 2.0
        self._stock_threshold = 2.0 * self.n

    def _is_unanimous_cooperation(self, history: PlayerHistory) -> bool:
        if history.round_number == 0:
            return False
        return bool(history.my_actions[-1]) and int(history.opponent_cooperators[-1]) == self.n - 1

    def _is_high_opponent_cooperation(self, opp_coop_count: int) -> bool:
        return opp_coop_count >= self._two_thirds_threshold

    def _is_low_opponent_cooperation(self, opp_coop_count: int) -> bool:
        return 2 * int(opp_coop_count) < self.n - 1

    def _has_recent_low_phase_without_two_consecutive_highs(self, history: PlayerHistory) -> bool:
        """
        If there was a low-cooperation round most recently, or if after the most recent
        low-cooperation round there have not yet been two consecutive high rounds,
        return True (meaning we should defect).
        """
        rn = history.round_number
        if rn == 0:
            return False
        consecutive_highs = 0
        saw_low = False
        for idx in range(rn - 1, -1, -1):
            opp = int(history.opponent_cooperators[idx])
            if self._is_low_opponent_cooperation(opp):
                saw_low = True
                break
            if self._is_high_opponent_cooperation(opp):
                consecutive_highs += 1
            else:
                consecutive_highs = 0
                break
        if not saw_low:
            return False
        return consecutive_highs < 2

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.n
        S = float(current_stock)
        if history.round_number == 0:
            return Action.C
        if S <= 0.0:
            return Action.D
        if n == 2:
            other_cooperated_last_round = int(history.opponent_cooperators[-1]) == 1
            if other_cooperated_last_round and S >= 4.0:
                return Action.C
            return Action.D
        if self._is_unanimous_cooperation(history):
            return Action.C if S > 0.0 else Action.D
        if self._has_recent_low_phase_without_two_consecutive_highs(history):
            return Action.D
        last_opp = int(history.opponent_cooperators[-1])
        q = last_opp / float(n - 1) if n > 1 else 0.0
        if q >= 2.0 / 3.0 and S >= self._stock_threshold and (S > 0.0):
            return Action.C
        return Action.D

class Strategy_PROSOCIAL_102(BaseStrategy):
    """
    Conditional-cooperation strategy with strong default cooperation and a narrow
    emergency fallback to defection when stock is critically low and recent
    opponent cooperation has been persistently poor.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self._n_players = int(game_description.n_players)
        self._n_rounds = int(game_description.n_rounds)
        self._capacity = float(game_description.capacity)
        self._low = self._capacity / 3.0
        self._critical = self._capacity / 6.0
        self._recovery = self._capacity / 2.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        if round_number == 0:
            return Action.C
        if round_number >= self._n_rounds - 1:
            return Action.C
        opp_counts = history.opponent_cooperators
        n_opponents = self._n_players - 1
        if n_opponents <= 0:
            avg_t = 1.0
        else:
            recent = opp_counts[-2:] if round_number >= 2 else opp_counts[-1:]
            if len(recent) == 0:
                avg_t = 1.0
            else:
                fracs = [float(c) / float(n_opponents) for c in recent]
                avg_t = float(sum(fracs)) / float(len(fracs))
        stock = float(current_stock)
        if stock >= self._recovery:
            return Action.C
        if stock > self._low and avg_t >= 0.5:
            return Action.C
        if stock > self._critical and avg_t >= 1.0 / 3.0:
            return Action.C
        if stock <= self._critical and avg_t < 1.0 / 3.0:
            return Action.D
        return Action.C

class Strategy_PROSOCIAL_103(BaseStrategy):
    """
    Cooperative by default; enters a temporary protection mode when the pool is
    being overused or the stock is low, and exits protection only after sustained
    acceptable behavior.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.mode = 'normal'
        self.good_streak = 0
        self.last_stock = float(game_description.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_rounds = self.game_description.n_rounds
        n_players = self.game_description.n_players
        n_opponents = max(n_players - 1, 0)
        if history.round_number == 0:
            self.mode = 'normal'
            self.good_streak = 0
            self.last_stock = float(current_stock)
            return Action.C
        if history.round_number >= n_rounds - 1:
            self.mode = 'normal'
            self.good_streak = 0
            self.last_stock = float(current_stock)
            return Action.C
        last_k = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        q = last_k / n_opponents if n_opponents > 0 else 1.0
        x = float(current_stock) / float(self.game_description.capacity) if self.game_description.capacity else 0.0
        acceptable = q >= 0.5 and x >= 1.0 / 3.0
        stock_non_decreasing = float(current_stock) >= float(self.last_stock)
        if q < 0.5 or x < 1.0 / 3.0:
            self.mode = 'protection'
            self.good_streak = 0
        elif stock_non_decreasing and q >= 0.5:
            self.mode = 'normal'
            self.good_streak = 0
        elif self.mode == 'protection':
            self.good_streak += 1
            if self.good_streak >= 2:
                self.mode = 'normal'
                self.good_streak = 0
        else:
            self.mode = 'normal'
            self.good_streak = 0
        self.last_stock = float(current_stock)
        if self.mode == 'normal':
            return Action.C
        return Action.D

class Strategy_PROSOCIAL_104(BaseStrategy):
    """
    Cooperate by default, forgive temporary collapse, and defect only after
    repeated low-cooperation rounds combined with critically low stock.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = max(2, int(game_description.n_players))
        self.r = max(2, int(game_description.n_rounds))
        self.capacity = float(game_description.capacity)
        self.low_streak = 0
        self.last_k = None
        self.coop_threshold = self.n / 2.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        if round_number >= self.r - 2:
            if round_number > 0:
                last_opp_coop = int(history.opponent_cooperators[-1])
                last_my_action = bool(history.my_actions[-1])
                self.last_k = last_opp_coop + (1 if last_my_action else 0)
                if self.last_k < self.coop_threshold:
                    self.low_streak += 1
                else:
                    self.low_streak = 0
            return Action.C
        if round_number == 0:
            self.low_streak = 0
            self.last_k = None
            return Action.C
        last_opp_coop = int(history.opponent_cooperators[-1])
        last_my_action = bool(history.my_actions[-1])
        self.last_k = last_opp_coop + (1 if last_my_action else 0)
        if self.last_k < self.coop_threshold:
            self.low_streak += 1
        else:
            self.low_streak = 0
        stock_threshold = self.capacity / 3.0
        if self.low_streak >= 2 and float(current_stock) < stock_threshold:
            return Action.D
        return Action.C

class Strategy_PROSOCIAL_105(BaseStrategy):
    """
    Start cooperative, then become temporarily defensive only after two
    consecutive weak rounds (low opponent cooperation or low stock).
    Return to cooperation immediately once cooperation or stock recovers.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.alarm = 0
        self.last_observed_coop_rate = 1.0
        self.last_observed_stock_rate = 1.0
        self.last_defensive_mode = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_players = int(self.game_description.n_players)
        n_opponents = max(n_players - 1, 1)
        capacity = float(self.game_description.capacity) if self.game_description.capacity is not None else 1.0
        capacity = capacity if capacity > 0 else 1.0
        if history.round_number == 0:
            self.alarm = 0
            self.last_observed_coop_rate = 1.0
            self.last_observed_stock_rate = min(max(current_stock / capacity, 0.0), 1.0) if capacity > 0 else 1.0
            self.last_defensive_mode = False
            return Action.C
        prev_opp_coop = 0
        if len(history.opponent_cooperators) > 0:
            prev_opp_coop = int(history.opponent_cooperators[-1])
        coop_rate = prev_opp_coop / n_opponents if n_opponents > 0 else 1.0
        stock_rate = current_stock / capacity if capacity > 0 else 1.0
        if coop_rate < 0.0:
            coop_rate = 0.0
        elif coop_rate > 1.0:
            coop_rate = 1.0
        if stock_rate < 0.0:
            stock_rate = 0.0
        elif stock_rate > 1.0:
            stock_rate = 1.0
        weak_round = coop_rate < 2.0 / 3.0 or stock_rate < 0.5
        if weak_round:
            self.alarm += 1
        else:
            self.alarm = 0
        defensive_mode = self.alarm >= 2 and coop_rate < 0.5
        self.last_observed_coop_rate = coop_rate
        self.last_observed_stock_rate = stock_rate
        self.last_defensive_mode = defensive_mode
        if current_stock <= 0:
            return Action.C
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D if defensive_mode else Action.C
        if self.alarm == 0 or coop_rate >= 0.5:
            return Action.C
        if defensive_mode:
            return Action.D
        return Action.C

class Strategy_PROSOCIAL_106(BaseStrategy):
    """
    Always cooperates in every round.
    Tracks optional diagnostics for opponent cooperation and stock health,
    but never uses them to change the action.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(getattr(game_description, 'n_players', 0) or 0)
        self.n_rounds = int(getattr(game_description, 'n_rounds', 0) or 0)
        self.capacity = float(getattr(game_description, 'capacity', 0) or 0)
        self.lambda_ = 0.9
        self.trust_estimate = 1.0
        self.stock_health_estimate = 1.0
        self.last_observed_round = -1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(getattr(history, 'round_number', 0) or 0)
        action = Action.C
        if round_number > 0:
            last_index = round_number - 1
            if 0 <= last_index < len(history.opponent_cooperators):
                n_opponents = max(self.n_players - 1, 0)
                opp_coop = float(history.opponent_cooperators[last_index])
                if n_opponents > 0:
                    coop_rate = max(0.0, min(1.0, opp_coop / n_opponents))
                else:
                    coop_rate = 1.0
                self.trust_estimate = self.lambda_ * self.trust_estimate + (1.0 - self.lambda_) * coop_rate
            cap = self.capacity if self.capacity > 0 else 1.0
            try:
                stock_ratio = float(current_stock) / cap
            except Exception:
                stock_ratio = 0.0
            self.stock_health_estimate = max(0.0, min(1.0, stock_ratio))
            self.last_observed_round = last_index
        return action

class Strategy_PROSOCIAL_107(BaseStrategy):
    """
    Default-cooperate strategy that only defects after two consecutive rounds
    of weak opponent cooperation and only when the stock is already low.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number + 1
        if history.round_number == 0:
            return Action.C
        if t >= self.n_rounds - 1:
            return Action.C
        if current_stock <= 0:
            return Action.C
        opp_counts = history.opponent_cooperators
        n_opp = self.n_players - 1
        alarm = 0
        prev_low = 0
        if len(opp_counts) > 0 and n_opp > 0:
            q_values = []
            for count in opp_counts:
                q_values.append(float(count) / float(n_opp))
            for idx in range(len(q_values)):
                if idx == 0:
                    m_t = q_values[0]
                else:
                    m_t = 0.5 * (q_values[idx] + q_values[idx - 1])
                low_t = 1 if m_t < 0.5 else 0
                if low_t == 1:
                    alarm = alarm + 1
                else:
                    alarm = 0
            prev_low = low_t
        if alarm < 2:
            return Action.C
        if current_stock < self.capacity / 3.0:
            return Action.D
        return Action.C

class Strategy_PROSOCIAL_108(BaseStrategy):
    """
    Conservative common-pool strategy:
    - Start cooperatively.
    - Track the last up to 3 observed opponent cooperation rates.
    - Defect only when stock is low, recent support has been weak for at least
      two consecutive observed rounds, and average support is below 2/3.
    - Always cooperate on the final round and whenever stock is depleted.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.mode = 'cooperative'
        self.low_support_streak = 0
        self._recent_support_rates = []
        self._processed_rounds = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_players = int(self.game_description.n_players)
        n_rounds = int(self.game_description.n_rounds)
        capacity = float(self.game_description.capacity)
        if current_stock <= 0:
            return Action.C
        t = int(history.round_number) + 1
        while self._processed_rounds < history.round_number:
            opp_count = int(history.opponent_cooperators[self._processed_rounds])
            n_opponents = max(n_players - 1, 1)
            rate = float(opp_count) / float(n_opponents)
            self._recent_support_rates.append(rate)
            if len(self._recent_support_rates) > 3:
                self._recent_support_rates.pop(0)
            avg_support_seen = float(np.mean(np.array(self._recent_support_rates, dtype=float)))
            support_count = round(avg_support_seen * float(n_opponents))
            threshold = math.ceil(float(n_opponents) / 2.0)
            if support_count < threshold:
                self.low_support_streak += 1
            else:
                self.low_support_streak = 0
            self._processed_rounds += 1
        if t == 1:
            return Action.C
        if t == n_rounds:
            return Action.C
        if len(self._recent_support_rates) == 0:
            return Action.C
        avg_support = float(np.mean(np.array(self._recent_support_rates, dtype=float)))
        if current_stock >= capacity / 3.0:
            return Action.C
        if avg_support >= 2.0 / 3.0:
            return Action.C
        if self.low_support_streak < 2:
            return Action.C
        return Action.D

class Strategy_PROSOCIAL_109(BaseStrategy):
    """
    Adaptive common-pool strategy with cooperative and protective modes.
    Defaults to cooperation, escalates to protection when cooperation or stock
    conditions deteriorate, and returns to cooperation when recovery is observed.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self._mode = 'cooperative'
        self._last_stock = None
        self._prev_stock = None
        self._last_opponent_cooperators = None
        self._prev_opponent_cooperators = None

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = int(self.game_description.n_players)
        rounds = int(self.game_description.n_rounds)
        capacity = float(self.game_description.capacity)
        t = int(history.round_number)
        if t == 0:
            self._last_stock = float(current_stock)
            self._prev_stock = None
            self._last_opponent_cooperators = None
            self._prev_opponent_cooperators = None
            self._mode = 'cooperative'
            return Action.C
        if len(history.opponent_cooperators) > 0:
            k = int(history.opponent_cooperators[-1])
        else:
            k = None
        if k is None:
            self._prev_stock = self._last_stock
            self._last_stock = float(current_stock)
            self._prev_opponent_cooperators = self._last_opponent_cooperators
            self._last_opponent_cooperators = None
            return Action.C
        m = max(n - 1, 1)
        c = k / m
        stock_increased_last_round = False
        stock_increased_two_consecutive = False
        if self._last_stock is not None:
            stock_increased_last_round = float(current_stock) > float(self._last_stock)
        if self._prev_stock is not None and self._last_stock is not None:
            stock_increased_two_consecutive = float(self._last_stock) > float(self._prev_stock) and float(current_stock) > float(self._last_stock)
        quarter_cap = capacity / 4.0
        third_cap = capacity / 3.0
        half_opponents = m / 2.0
        high_coop_threshold = (m - 1) / m if m > 0 else 1.0
        low_coop_threshold = 1 / m if m > 0 else 1.0
        if t == rounds - 1:
            if float(current_stock) < quarter_cap and c < 0.5:
                action = Action.D
            else:
                action = Action.C
        else:
            action = Action.C
            if float(current_stock) == 0.0:
                action = Action.C
            elif c == 1.0 or c >= high_coop_threshold:
                action = Action.C
            elif c <= low_coop_threshold:
                action = Action.D
            elif float(current_stock) >= third_cap:
                action = Action.C
            elif c >= 0.5 and stock_increased_last_round:
                action = Action.C
            elif self._prev_opponent_cooperators is not None and self._prev_opponent_cooperators >= half_opponents:
                action = Action.C
            else:
                action = Action.D
            if self._mode == 'cooperative':
                if c == 0.0 or float(current_stock) < quarter_cap:
                    self._mode = 'protective'
                    action = Action.D
                else:
                    action = Action.C
            if self._mode == 'protective':
                if c >= 0.5 or stock_increased_two_consecutive:
                    self._mode = 'cooperative'
                    action = Action.C
                else:
                    action = Action.D
            if len(history.my_actions) >= 2:
                if not bool(history.my_actions[-1]) and (not bool(history.my_actions[-2])) and (c >= 0.5):
                    self._mode = 'cooperative'
                    action = Action.C
            if len(history.my_actions) >= 2 and self._last_stock is not None and (self._prev_stock is not None):
                if bool(history.my_actions[-1]) and bool(history.my_actions[-2]):
                    if float(current_stock) < float(self._last_stock) < float(self._prev_stock):
                        self._mode = 'protective'
                        action = Action.D
        self._prev_stock = self._last_stock
        self._last_stock = float(current_stock)
        self._prev_opponent_cooperators = self._last_opponent_cooperators
        self._last_opponent_cooperators = k
        if t > 0:
            if c < 0.5 or float(current_stock) < quarter_cap:
                if action == Action.D:
                    self._mode = 'protective'
        return action

class Strategy_PROSOCIAL_110(BaseStrategy):
    """
    Always cooperates in every round, regardless of history or current stock.
    Maintains simple internal monitoring of opponent cooperation counts without
    affecting the chosen action.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(getattr(game_description, 'n_players', 0) or 0)
        self.n_rounds = int(getattr(game_description, 'n_rounds', 0) or 0)
        self.capacity = float(getattr(game_description, 'capacity', 0.0) or 0.0)
        self.opponent_cooperation_history = []
        self.observed_stock_history = []
        self.last_seen_round = -1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(getattr(history, 'round_number', 0) or 0)
        opp_coops = getattr(history, 'opponent_cooperators', None)
        if opp_coops is not None and round_number > 0:
            try:
                self.opponent_cooperation_history.append(int(opp_coops[-1]))
            except Exception:
                self.opponent_cooperation_history.append(0)
        try:
            self.observed_stock_history.append(float(current_stock))
        except Exception:
            self.observed_stock_history.append(0.0)
        self.last_seen_round = round_number
        return Action.C

class Strategy_PROSOCIAL_111(BaseStrategy):
    """
    Adaptive cooperation strategy for a common pool resource game.

    - Cooperates initially.
    - Tracks a smoothed trust score from observed opponent cooperation.
    - Defects only after sustained low trust, with strong preference to return
      to cooperation when stock is low or cooperation recovers.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self._trust = 1.0
        self._bad_streak = 0
        self._forced_cooperate = False
        self._last_seen_round = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = max(2, int(self.game_description.n_players))
        r = max(1, int(self.game_description.n_rounds))
        capacity = float(self.game_description.capacity)
        round_number = history.round_number
        if round_number == 0:
            return Action.C
        if round_number > self._last_seen_round:
            idx = round_number - 1
            opp_count = None
            if len(history.opponent_cooperators) > idx:
                opp_count = int(history.opponent_cooperators[idx])
            if opp_count is not None:
                m = max(1, n - 1)
                coop_rate = 0.0 if m <= 0 else float(opp_count) / float(m)
                self._trust = 0.7 * self._trust + 0.3 * coop_rate
                if coop_rate >= 0.8:
                    self._trust = max(self._trust, 0.75)
                if coop_rate >= 1.0:
                    self._trust = 1.0
                if self._trust < 0.5:
                    self._bad_streak += 1
                else:
                    self._bad_streak = 0
                if coop_rate >= 0.5 or current_stock > capacity / 2.0:
                    self._bad_streak = 0
                if n == 2:
                    if coop_rate >= 0.5:
                        self._bad_streak = 0
                if current_stock <= capacity / 4.0:
                    self._forced_cooperate = True
            self._last_seen_round = round_number
        if self._forced_cooperate:
            return Action.C
        if current_stock <= capacity / 4.0:
            self._forced_cooperate = True
            return Action.C
        is_final_round = round_number >= r - 1
        if is_final_round:
            last_opp_count = None
            if len(history.opponent_cooperators) > 0:
                last_opp_count = int(history.opponent_cooperators[-1])
            if last_opp_count is None:
                return Action.C
            m = max(1, n - 1)
            coop_rate = 0.0 if m <= 0 else float(last_opp_count) / float(m)
            if self._trust < 0.5 and coop_rate == 0.0:
                return Action.D
            return Action.C
        if current_stock >= 0.9 * capacity and self._trust >= 0.4:
            self._bad_streak = 0
            return Action.C
        if current_stock <= capacity / 2.0:
            return Action.C
        if self._bad_streak >= 2 and self._trust < 0.5:
            return Action.D
        return Action.C

class Strategy_PROSOCIAL_112(BaseStrategy):
    """
    Cooperative-by-default common pool strategy with stock-aware cooperation,
    endgame cooperation, and brief retaliation against complete defection.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.last_opponent_cooperators = None
        self.last_stock = None
        self.last_round_number = None

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        self.last_stock = float(current_stock)
        self.last_round_number = round_number
        if round_number == 0:
            return Action.C
        last_opponents = int(history.opponent_cooperators[-1]) if round_number > 0 else 0
        self.last_opponent_cooperators = last_opponents
        n_opponents = max(self.n_players - 1, 0)
        q = last_opponents / n_opponents if n_opponents > 0 else 0.0
        S = float(current_stock)
        if S >= 0.75 * self.capacity:
            return Action.C
        if round_number >= self.n_rounds - 2:
            return Action.C
        if S < 0.4 * self.capacity and q < 1.0 / 3.0:
            return Action.D
        if q == 0:
            return Action.D
        if q >= 0.5:
            return Action.C
        return Action.D

class Strategy_PROSOCIAL_113(BaseStrategy):
    """
    Cooperative-first strategy with conditional punishment, forgiveness,
    and short-memory distrust handling for the common pool resource game.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(0, self.n_players - 1)

    def _share_from_count(self, coop_count: int) -> float:
        if self.n_opponents <= 0:
            return 1.0
        if self.n_players == 2:
            return 1.0 if coop_count > 0 else 0.0
        return float(coop_count) / float(self.n_opponents)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number
        if t == 0:
            return Action.C
        opp_counts = history.opponent_cooperators
        last_count = int(opp_counts[-1]) if len(opp_counts) >= 1 else 0
        prev_count = int(opp_counts[-2]) if len(opp_counts) >= 2 else last_count
        last3 = opp_counts[-3:] if len(opp_counts) >= 3 else opp_counts
        share_last = self._share_from_count(last_count)
        share_prev = self._share_from_count(prev_count)
        last3_c_count = int(np.sum(last3)) if len(last3) > 0 else 0
        if current_stock >= self.capacity / 2.0:
            return Action.C
        if share_last >= 0.5:
            return Action.C
        if len(opp_counts) >= 2 and share_last > share_prev:
            return Action.C
        if len(last3) >= 3 and last3_c_count >= 2:
            return Action.C
        trigger_one = share_last == 0.0 and share_prev == 0.0
        trigger_two = share_last <= 1.0 / 3.0 and current_stock < self.capacity / 2.0
        trigger_three = share_last <= 0.5 and current_stock < self.capacity / 4.0
        trigger_four = t == self.n_rounds - 1 and share_last == 0.0 and (current_stock < self.capacity / 3.0)
        if trigger_one or trigger_two or trigger_three or trigger_four:
            return Action.D
        return Action.C

class Strategy_PROSOCIAL_114(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Start with cooperation.
    - Preserve the resource when stock is low.
    - Reward broad cooperation with continued cooperation.
    - Use a short repair streak to avoid overreacting after temporary defections.
    - Defect only when cooperation has clearly collapsed and the stock is not in danger.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.repair_streak = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = int(getattr(self.game_description, 'n_players', 2) or 2)
        r = int(getattr(self.game_description, 'n_rounds', 2) or 2)
        capacity = float(getattr(self.game_description, 'capacity', 0.0) or 0.0)
        preserve_threshold = capacity / 3.0
        recovery_threshold = math.ceil((n - 1) / 2) if n > 1 else 0
        t = int(getattr(history, 'round_number', 0) or 0)
        if current_stock <= 0:
            self.repair_streak = 0
            return Action.C
        if t == 0:
            self.repair_streak = 0
            return Action.C
        k = None
        try:
            if history.opponent_cooperators is not None and len(history.opponent_cooperators) > 0:
                k = int(history.opponent_cooperators[-1])
        except Exception:
            k = None
        observed = k is not None and k >= 0
        if t == r - 1:
            if not observed or k >= 1:
                self.repair_streak = 0 if observed and k is not None and (k >= recovery_threshold) else self.repair_streak
                return Action.C
            if k == 0 and current_stock <= preserve_threshold:
                return Action.D
            return Action.C
        if current_stock <= preserve_threshold:
            self.repair_streak = 0
            return Action.C
        if not observed:
            return Action.C
        if k >= n - 1:
            self.repair_streak = 0
            return Action.C
        if k >= n - 2 and current_stock >= 2.0 * n:
            self.repair_streak = 0
            return Action.C
        if k >= recovery_threshold:
            self.repair_streak = 0
            return Action.C
        if self.repair_streak >= 2:
            if k >= recovery_threshold or current_stock >= capacity / 2.0:
                self.repair_streak = 0
                return Action.C
        self.repair_streak += 1
        if self.repair_streak == 1:
            return Action.D
        self.repair_streak = 0
        return Action.C

class Strategy_PROSOCIAL_115(BaseStrategy):
    """
    Conservative, state-aware cooperation strategy for the Common Pool Resource Game.

    - Cooperates in round 1.
    - Uses previous-round opponent cooperation and current stock to decide later rounds.
    - Tightens cooperation requirements when stock is low.
    - Relaxes after consecutive stock increases.
    - Applies stronger cooperation requirements in the final two rounds.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self._prev_stock: float | None = None
        self._prev_stock_increased: bool = False
        self._consecutive_stock_increases: int = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.n_players
        capacity = self.capacity
        round_number = history.round_number
        core_threshold = math.ceil((n - 1) / 2)
        endgame_threshold = max(0, n - 2)
        stock_increased_last_round = False
        if self._prev_stock is not None:
            stock_increased_last_round = current_stock > self._prev_stock
        if stock_increased_last_round:
            self._consecutive_stock_increases += 1
        else:
            self._consecutive_stock_increases = 0
        if round_number == 0:
            self._prev_stock = float(current_stock)
            self._prev_stock_increased = False
            return Action.C
        if len(history.opponent_cooperators) > 0:
            opp_coop_last = int(history.opponent_cooperators[-1])
        else:
            opp_coop_last = -1
        conservative_defect = current_stock < 0.75 * capacity
        if round_number >= max(0, self.n_rounds - 2):
            action = Action.C if current_stock >= 0.8 * capacity and opp_coop_last >= endgame_threshold else Action.D
            self._prev_stock = float(current_stock)
            self._prev_stock_increased = stock_increased_last_round
            return action
        if self._consecutive_stock_increases >= 2:
            if current_stock >= 0.75 * capacity and opp_coop_last >= core_threshold:
                action = Action.C
            else:
                action = Action.D
            self._prev_stock = float(current_stock)
            self._prev_stock_increased = stock_increased_last_round
            return action
        if current_stock < 0.25 * capacity:
            if stock_increased_last_round and opp_coop_last == n - 1:
                action = Action.C
            else:
                action = Action.D
            self._prev_stock = float(current_stock)
            self._prev_stock_increased = stock_increased_last_round
            return action
        if current_stock < 0.5 * capacity:
            action = Action.C if opp_coop_last == n - 1 else Action.D
            self._prev_stock = float(current_stock)
            self._prev_stock_increased = stock_increased_last_round
            return action
        if current_stock >= 0.75 * capacity and opp_coop_last >= core_threshold:
            action = Action.C
        else:
            action = Action.D if conservative_defect else Action.C
        self._prev_stock = float(current_stock)
        self._prev_stock_increased = stock_increased_last_round
        return action

class Strategy_PROSOCIAL_116(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Cooperate by default
    - Tighten cooperation requirements as stock depletes
    - Defect during collapse, then recover only under strong cooperation and sufficient stock
    - Always cooperate against unanimous cooperation
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(0, self.n_players - 1)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        cap = self.capacity
        S = float(current_stock)
        if history.round_number == 0:
            return Action.C
        prev_opp_coop = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        if self.n_opponents > 0:
            rho = prev_opp_coop / self.n_opponents
        else:
            rho = 1.0
        prev_action = Action.C
        if len(history.my_actions) > 0 and (not bool(history.my_actions[-1])):
            prev_action = Action.D
        if rho >= 1.0:
            return Action.C
        if history.round_number >= self.n_rounds - 1:
            return Action.C if S > cap / 4.0 else Action.D
        if S <= cap / 10.0:
            if rho >= 0.8 and S > cap / 4.0:
                return Action.C
            return Action.D
        if prev_action == Action.D:
            return Action.C if rho >= 0.75 and S >= cap / 3.0 else Action.D
        target = max(0.5, 1.0 - (cap - S) / cap) if cap > 0 else 0.5
        if rho >= target and S >= cap / 6.0:
            return Action.C
        if rho <= 0.0:
            return Action.D
        return Action.D

class Strategy_PROSOCIAL_117(BaseStrategy):
    """
    State-based cooperative strategy with guarded retaliation and recovery.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.q = 0
        self.last_action = Action.C
        self.last_was_defection = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = int(self.game_description.n_players)
        r = int(self.game_description.n_rounds)
        capacity = float(self.game_description.capacity)
        round_number = int(history.round_number)
        t = round_number + 1
        threshold_count = max(0, n - 2)
        threshold_rate = 0.0 if n <= 1 else threshold_count / max(1, n - 1)
        if t == 1:
            self.q = 0
            self.last_action = Action.C
            self.last_was_defection = False
            return Action.C
        prev_opponents = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        prev_rate = prev_opponents / max(1, n - 1)
        if prev_rate < threshold_rate:
            self.q += 1
        else:
            self.q = 0
        low_stock = current_stock <= 2 * n
        if low_stock:
            self.last_action = Action.D
            self.last_was_defection = True
            return Action.D
        if self.last_was_defection:
            if current_stock > 2 * n and prev_opponents >= threshold_count:
                self.q = 0
                self.last_action = Action.C
                self.last_was_defection = False
                return Action.C
        L = int(math.ceil((r - 1) / 6)) if r > 1 else 0
        in_final_segment = t > r - L
        if in_final_segment:
            action = Action.C if prev_rate >= threshold_rate else Action.D
            self.last_action = action
            self.last_was_defection = action == Action.D
            if action == Action.C:
                self.q = 0
            return action
        cooperate_now = prev_rate >= threshold_rate and current_stock >= 0.75 * capacity
        if self.q >= 2:
            action = Action.D
        elif self.q == 1:
            action = Action.D
        else:
            action = Action.C if cooperate_now else Action.D
        if action == Action.C:
            self.q = 0
        self.last_action = action
        self.last_was_defection = action == Action.D
        return action

class Strategy_PROSOCIAL_118(BaseStrategy):
    """
    Conditional cooperation strategy for the Common Pool Resource Game.

    - Starts with cooperation.
    - Cooperates readily when the stock is healthy and opponent cooperation is credible.
    - Switches to conservation when stock becomes scarce or cooperation collapses.
    - Gives a strong reciprocity boost after sustained high cooperation.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(getattr(game_description, 'n_players', 2))
        self.n_rounds = int(getattr(game_description, 'n_rounds', 2))
        self.capacity = float(getattr(game_description, 'capacity', 0.0))
        self.n_opponents = max(self.n_players - 1, 0)
        self.consecutive_high_coop = 0
        self.last_observed_round = 0
        self.last_observed_m = 0
        self.last_observed_p = 1.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        if round_number > 0 and len(history.opponent_cooperators) > 0:
            m = int(history.opponent_cooperators[-1])
            if self.n_opponents > 0:
                p = m / self.n_opponents
            else:
                p = 1.0
        else:
            m = 0
            p = 1.0
        if round_number != self.last_observed_round:
            self.last_observed_round = round_number
            self.last_observed_m = m
            self.last_observed_p = p
            if round_number > 0:
                if p >= 0.75:
                    self.consecutive_high_coop += 1
                else:
                    self.consecutive_high_coop = 0
        S = float(current_stock)
        cap = self.capacity if self.capacity > 0 else 1.0
        if round_number == 0:
            return Action.C
        if round_number >= self.n_rounds - 1:
            if p >= 0.5 or S >= 0.75 * cap:
                return Action.C
            return Action.D
        if S < 0.25 * cap:
            return Action.D
        if S < 0.5 * cap:
            return Action.C if p >= 1.0 else Action.D
        if S >= 0.9 * cap:
            return Action.C
        if self.consecutive_high_coop >= 2 and S >= 0.4 * cap:
            return Action.C
        if S >= 0.75 * cap and p >= 0.5:
            return Action.C
        return Action.D

class Strategy_PROSOCIAL_119(BaseStrategy):
    """
    Cooperative-by-default common-pool strategy with one-round corrective defection
    against sustained free-riding, while avoiding consecutive defections unless low
    cooperation persists.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.last_action = Action.C
        self.prev_opponent_cooperators = None

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_players = int(self.game_description.n_players)
        n_rounds = int(self.game_description.n_rounds)
        n_opponents = max(0, n_players - 1)
        round_number = int(history.round_number)
        if round_number == 0:
            self.last_action = Action.C
            self.prev_opponent_cooperators = None
            return Action.C
        if history.opponent_cooperators is None or len(history.opponent_cooperators) == 0:
            self.last_action = Action.C
            self.prev_opponent_cooperators = None
            return Action.C
        prev_k = int(history.opponent_cooperators[-1])
        self.prev_opponent_cooperators = prev_k
        q = 1.0 if n_opponents == 0 else prev_k / n_opponents
        if current_stock <= n_players:
            self.last_action = Action.C
            return Action.C
        if round_number >= max(0, n_rounds - 2):
            if q >= 0.5:
                self.last_action = Action.C
                return Action.C
            if current_stock > 1.5 * n_players:
                self.last_action = Action.D
                return Action.D
            self.last_action = Action.C
            return Action.C
        if q >= 0.5:
            self.last_action = Action.C
            return Action.C
        if self.last_action == Action.D and q < 0.5:
            self.last_action = Action.D
            return Action.D
        self.last_action = Action.D
        return Action.D

class Strategy_PROSOCIAL_120(BaseStrategy):
    """
    Generous default strategy for the Common Pool Resource Game:
    cooperate in healthy conditions, defect protectively when the pool is
    depleted or opponent cooperation collapses.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_opponents = max(0, self.n_players - 1)
        self.capacity = float(game_description.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        if round_number == 0:
            return Action.C
        last_cooperators = int(history.opponent_cooperators[-1])
        if self.n_opponents > 0:
            p_last = last_cooperators / self.n_opponents
        else:
            p_last = 1.0
        threshold = max(2.0 * self.n_players, 0.25 * self.capacity, 0.5 * float(current_stock))
        stock_dropped_25 = False
        if len(history.my_payoffs) >= 2:
            prev_action = bool(history.my_actions[-1])
            prev_payoff = float(history.my_payoffs[-1])
            if prev_action:
                inferred_pre_round_stock = prev_payoff * (2.0 * self.n_players)
            else:
                inferred_pre_round_stock = prev_payoff * self.n_players
            prev_prev_action = bool(history.my_actions[-2])
            prev_prev_payoff = float(history.my_payoffs[-2])
            if prev_prev_action:
                inferred_older_stock = prev_prev_payoff * (2.0 * self.n_players)
            else:
                inferred_older_stock = prev_prev_payoff * self.n_players
            if inferred_older_stock > 0:
                stock_dropped_25 = inferred_pre_round_stock <= 0.75 * inferred_older_stock
        opponent_cooperators = history.opponent_cooperators
        zero_streak = 0
        for idx in range(len(opponent_cooperators) - 1, -1, -1):
            if int(opponent_cooperators[idx]) == 0:
                zero_streak += 1
            else:
                break
        healthy_stock = float(current_stock) > threshold
        majority_cooperation = p_last >= 0.5
        if float(current_stock) <= threshold:
            return Action.D
        if round_number >= 2 and p_last < 0.5:
            return Action.D
        if stock_dropped_25:
            return Action.D
        if zero_streak >= 2:
            return Action.D
        if healthy_stock and majority_cooperation:
            return Action.C
        if round_number == 1:
            return Action.C if healthy_stock and majority_cooperation else Action.D
        if healthy_stock and p_last > 0.0:
            return Action.C
        return Action.D

class Strategy_PROSOCIAL_121(BaseStrategy):
    """
    Always cooperate in every round, regardless of stock or opponent behavior.
    Tracks observed opponent cooperation counts for monitoring only and never retaliates.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.observed_opponent_cooperators = []
        self.last_seen_round_number = -1
        self.last_seen_stock = None

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = getattr(history, 'round_number', 0)
        opp_counts = getattr(history, 'opponent_cooperators', None)
        if opp_counts is not None and round_number > 0:
            try:
                last_count = int(opp_counts[-1])
                self.observed_opponent_cooperators.append(last_count)
            except Exception:
                pass
        self.last_seen_round_number = round_number
        self.last_seen_stock = current_stock
        return Action.C

class Strategy_PROSOCIAL_122(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Open with cooperation
    - Stay cooperative while the stock is healthy
    - Under depletion, use a smoothed estimate of opponent cooperation to decide
      whether to cooperate, cautiously probe, or briefly defect for self-protection
    - Always cooperate on the final round
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(self.n_players - 1, 1)
        self.smoothed_opponent_coop = 1.0
        self.last_action = Action.C

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        n_rounds = int(self.game_description.n_rounds)
        if round_number >= n_rounds - 1:
            self.last_action = Action.C
            return Action.C
        if round_number == 0:
            self.last_action = Action.C
            return Action.C
        capacity = self.capacity if self.capacity > 0 else 1.0
        s = float(current_stock) / capacity
        p = 1.0
        opp_hist = history.opponent_cooperators
        for k in range(len(opp_hist)):
            observed_frac = float(opp_hist[k]) / float(self.n_opponents) if self.n_opponents > 0 else 0.0
            p = 0.7 * p + 0.3 * observed_frac
        self.smoothed_opponent_coop = p
        low = s <= 0.35
        critical = s <= 0.2
        if s >= 0.6:
            self.last_action = Action.C
            return Action.C
        previously_defected = len(history.my_actions) > 0 and (not bool(history.my_actions[-1]))
        if previously_defected and (s > 0.35 or p >= 0.55):
            self.last_action = Action.C
            return Action.C
        if not low:
            self.last_action = Action.C
            return Action.C
        if not critical:
            if p >= 0.6:
                self.last_action = Action.C
                return Action.C
            if len(opp_hist) >= 2:
                last_obs = int(opp_hist[-1])
                prev_obs = int(opp_hist[-2])
                if last_obs >= prev_obs:
                    self.last_action = Action.C
                    return Action.C
            else:
                self.last_action = Action.C
                return Action.C
            self.last_action = Action.C
            return Action.C
        below_half_threshold = 1 if self.n_players == 2 else self.n_opponents / 2.0
        if p < 0.45 and len(opp_hist) >= 2:
            last_obs = int(opp_hist[-1])
            prev_obs = int(opp_hist[-2])
            if last_obs < below_half_threshold and prev_obs < below_half_threshold:
                self.last_action = Action.D
                return Action.D
        self.last_action = Action.C
        return Action.C

class Strategy_PROSOCIAL_123(BaseStrategy):
    """
    Prosocial threshold strategy with smoothed cooperation monitoring,
    stock-aware escalation, and endgame cooperation bias.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_opponents = max(self.n_players - 1, 1)
        self.capacity = float(game_description.capacity)
        self.n_rounds = int(game_description.n_rounds)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        if round_number == 0:
            return Action.C
        if current_stock <= 0.0:
            return Action.D
        opp_counts = history.opponent_cooperators
        if len(opp_counts) == 0:
            return Action.C
        last_count = int(opp_counts[-1])
        last_p = last_count / self.n_opponents
        total_p = 0.0
        for c in opp_counts:
            total_p += float(c) / self.n_opponents
        h = (1.0 + total_p) / (2.0 + len(opp_counts))
        if self.capacity > 0.0:
            tau = current_stock / self.capacity
        else:
            tau = 1.0
        tau = max(0.5, min(1.0, tau))
        if round_number >= self.n_rounds - 2:
            if current_stock >= self.capacity / 4.0:
                return Action.C if last_p >= 0.5 else Action.D
            return Action.C if last_p >= 2.0 / 3.0 else Action.D
        if current_stock <= self.capacity / 4.0:
            return Action.C if last_p >= 2.0 / 3.0 and h >= 0.5 else Action.D
        if last_p >= tau and h >= 0.5:
            return Action.C
        return Action.D

class Strategy_PROSOCIAL_124(BaseStrategy):
    """
    Start cooperative, track a smoothed cooperation score q, and cooperate
    when the group shows at least moderate reciprocity or in the final round
    if the group has not been persistently uncooperative.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.q = 1.0
        self.low_stock_threshold = 1e-09

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number + 1
        r = self.game_description.n_rounds
        n = self.game_description.n_players
        m = max(n - 1, 0)
        if t == 1:
            self.q = 1.0
            return Action.C
        k = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        c_obs = k / m if m > 0 else 1.0
        self.q = 0.7 * self.q + 0.3 * c_obs
        self.q = max(0.0, min(1.0, self.q))
        all_cooperated = m > 0 and k >= m
        no_one_cooperated = k <= 0
        stock_is_low = current_stock <= self.low_stock_threshold
        if all_cooperated:
            return Action.C
        if no_one_cooperated:
            return Action.D
        if stock_is_low and c_obs < 0.75:
            return Action.D
        if c_obs >= 0.75:
            return Action.C
        if c_obs >= 0.4 and self.q >= 0.5 and (current_stock > 0):
            return Action.C
        if t == r and self.q >= 0.5 and (c_obs >= 0.4):
            return Action.C
        return Action.D

class Strategy_PROSOCIAL_125(BaseStrategy):
    """
    State-sensitive conditional cooperation strategy with restore, sustain, and protect modes.
    Cooperates early, rewards sustained cooperation, and defects only under repeated low support
    or dangerous stock depletion.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self._last_stock = None

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        cap = self.capacity
        n_opponents = max(self.n_players - 1, 1)
        if round_number == 0:
            self._last_stock = float(current_stock)
            return Action.C
        stock = float(current_stock)
        prev_action_count = len(history.opponent_cooperators)
        last_opponent_cooperators = int(history.opponent_cooperators[-1]) if prev_action_count >= 1 else 0
        last_c = last_opponent_cooperators / n_opponents
        if prev_action_count >= 2:
            prev_opponent_cooperators = int(history.opponent_cooperators[-2])
            prev_c = prev_opponent_cooperators / n_opponents
        else:
            prev_c = last_c
        low_support_last = last_c < 1.0 / 3.0
        low_support_prev = prev_c < 1.0 / 3.0
        high_support_last = last_c >= 2.0 / 3.0
        high_support_prev = prev_c >= 2.0 / 3.0
        low_support_two_rounds = low_support_last and low_support_prev
        high_support_two_rounds = high_support_last and high_support_prev
        healthy_stock = stock >= cap / 4.0
        critically_low_stock = stock < cap / 4.0
        if self._last_stock is None:
            falling_last_round = False
            falling_two_rounds = False
        else:
            falling_last_round = stock < self._last_stock
            if prev_action_count >= 2:
                falling_two_rounds = falling_last_round and low_support_prev
            else:
                falling_two_rounds = False
        self._last_stock = stock
        if stock <= 0.0:
            return Action.C
        if stock >= cap and (not low_support_two_rounds):
            return Action.C
        if round_number == self.n_rounds - 1:
            if healthy_stock or last_c >= 0.5:
                return Action.C
            return Action.D
        if healthy_stock and high_support_two_rounds:
            return Action.C
        if critically_low_stock and high_support_last:
            return Action.C
        if 1.0 / 3.0 <= last_c < 2.0 / 3.0 and falling_two_rounds:
            return Action.D
        if healthy_stock and last_c >= 1.0 / 3.0:
            return Action.C
        if critically_low_stock or low_support_two_rounds:
            return Action.D
        return Action.C

class Strategy_PROSOCIAL_126(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Start with full cooperation.
    - Track a smoothed estimate of opponent cooperation.
    - Defect only when stock is low and/or cooperation has persistently dropped.
    - Immediately revert to cooperation when opponents recover.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self._q_estimate = 1.0
        self._last_processed_round = -1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        n = self.n_players
        n_opponents = max(n - 1, 1)
        if round_number == 0:
            self._last_processed_round = 0
            self._q_estimate = 1.0
            return Action.C
        last_coop_count = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        rho_prev = last_coop_count / n_opponents
        if self._last_processed_round != round_number:
            self._q_estimate = 0.5 * self._q_estimate + 0.5 * rho_prev
            self._last_processed_round = round_number
        q = self._q_estimate
        stock = float(current_stock)
        half_n = n / 2.0
        two_thirds_n = 2.0 * n / 3.0
        if stock <= 0.0:
            return Action.D
        if round_number == self.n_rounds - 1:
            return Action.D if stock <= half_n else Action.C
        if stock <= half_n:
            return Action.D
        if stock <= two_thirds_n:
            if q >= 0.75 or rho_prev >= 0.75:
                return Action.C
            return Action.C if q >= 0.5 else Action.D
        if q <= 0.25:
            return Action.D
        return Action.C

class Strategy_PROSOCIAL_127(BaseStrategy):
    """
    Always cooperate in every round, regardless of history or current stock.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        return Action.C

class Strategy_PROSOCIAL_128(BaseStrategy):
    """
    Always cooperate strategy for the common pool resource game.

    This strategy:
    - Plays C in every round.
    - Records the number of cooperating opponents each round for monitoring only.
    - Never conditions its action on past defections, stock changes, or timing.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.opponent_cooperation_history = []
        self.my_action_history = []
        self.last_seen_round = -1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        if round_number > self.last_seen_round:
            if round_number > 0:
                self.opponent_cooperation_history.append(int(history.opponent_cooperators[-1]))
                self.my_action_history.append(bool(history.my_actions[-1]))
            self.last_seen_round = round_number
        return Action.C

class Strategy_ALTRUISTIC_33(BaseStrategy):
    """
    Always cooperate in every round, regardless of history or current stock.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = getattr(game_description, 'n_players', 0)
        self.n_rounds = getattr(game_description, 'n_rounds', 0)
        self.capacity = getattr(game_description, 'capacity', 0)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        return Action.C

class Strategy_ALTRUISTIC_34(BaseStrategy):
    """
    Generous by default, but defects only under sustained low cooperation when
    the stock is already in danger. Quickly returns to cooperation as soon as
    the group shows restraint or the stock stabilizes.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self._eps = 1e-09

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = int(history.round_number) + 1
        n = max(2, self.n)
        r = max(2, self.r)
        capacity = max(self._eps, self.capacity)
        stock = float(current_stock)
        if t == 1:
            return Action.C
        opp_last = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        opp_prev = int(history.opponent_cooperators[-2]) if len(history.opponent_cooperators) > 1 else opp_last
        n_opponents = max(1, n - 1)
        p_last = opp_last / n_opponents
        p_prev = opp_prev / n_opponents
        if len(history.my_payoffs) >= 2:
            stock_prev_proxy = stock + float(history.my_payoffs[-1])
            stock_prev2_proxy = stock_prev_proxy + float(history.my_payoffs[-2])
        elif len(history.my_payoffs) == 1:
            stock_prev_proxy = stock + float(history.my_payoffs[-1])
            stock_prev2_proxy = stock_prev_proxy
        else:
            stock_prev_proxy = stock
            stock_prev2_proxy = stock
        stock_increasing_or_stable = stock >= stock_prev_proxy - self._eps
        stock_falling_two_rounds = stock < stock_prev_proxy - self._eps and stock_prev_proxy < stock_prev2_proxy - self._eps
        stock_fallen_last_round = stock < stock_prev_proxy - self._eps
        if r > 1:
            reserve_threshold = capacity * max(0.25, 0.5 - 0.25 * ((t - 1) / (r - 1)))
        else:
            reserve_threshold = capacity * 0.25
        if len(history.my_actions) > 0 and (not bool(history.my_actions[-1])):
            if p_last >= 0.5 or stock >= stock_prev_proxy - self._eps:
                return Action.C
        if t >= r - 1:
            if not (stock < capacity / 6.0 and p_last < 0.25):
                return Action.C
        if stock <= capacity / 10.0:
            if not (p_last <= 0.25 and stock_fallen_last_round):
                return Action.C
        if p_last >= 0.5:
            return Action.C
        if stock > reserve_threshold and p_last >= 1.0 / 3.0:
            return Action.C
        if stock_increasing_or_stable:
            return Action.C
        if t > 1 and p_last < 1.0 / 3.0 and (stock <= reserve_threshold) and (stock_falling_two_rounds or p_prev < 1.0 / 3.0):
            return Action.D
        return Action.C

class Strategy_ALTRUISTIC_35(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Cooperates by default
    - Escalates to defense only under depletion and low opponent cooperation
    - Includes a limited forgiveness mechanism in critical stock states
    - Avoids long defection streaks unless the stock is critical
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self._prev_stock = None
        self._consecutive_defections = 0
        self._used_critical_forgiveness = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_players = max(2, int(self.game_description.n_players))
        capacity = float(self.game_description.capacity)
        safe_threshold = 0.75 * capacity
        vulnerable_threshold = 0.35 * capacity
        round_number = int(history.round_number)
        if round_number == 0:
            self._prev_stock = current_stock
            self._consecutive_defections = 0
            self._used_critical_forgiveness = False
            return Action.C
        last_opponent_cooperators = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        n_opponents = max(1, n_players - 1)
        c_t = last_opponent_cooperators / n_opponents
        is_safe = current_stock >= safe_threshold
        is_vulnerable = vulnerable_threshold <= current_stock < safe_threshold
        is_critical = current_stock < vulnerable_threshold
        if round_number == int(self.game_description.n_rounds) - 1:
            action = Action.D if is_critical else Action.C
        elif is_safe:
            action = Action.C
            self._used_critical_forgiveness = False
        elif is_vulnerable:
            if self._consecutive_defections >= 2:
                action = Action.C
            elif c_t >= 0.5:
                action = Action.C
            else:
                action = Action.D
        elif c_t >= 1.0 and self._prev_stock is not None and (current_stock >= self._prev_stock):
            if not self._used_critical_forgiveness:
                action = Action.C
                self._used_critical_forgiveness = True
            else:
                action = Action.D
        else:
            action = Action.D
        if not is_critical and action == Action.D and (self._consecutive_defections >= 2):
            action = Action.C
        if c_t >= 0.5 and (not is_critical):
            action = Action.C
        if action == Action.D:
            self._consecutive_defections += 1
        else:
            self._consecutive_defections = 0
            self._used_critical_forgiveness = False
        self._prev_stock = current_stock
        return action

class Strategy_ALTRUISTIC_36(BaseStrategy):
    """
    Restorative common-pool strategy:
    - Cooperate by default
    - Use a brief defection only as a bounded response to repeated exploitation
    - Fully reset to cooperation after sufficiently cooperative behavior
    - Avoid punishment in the final rounds
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.low_stock_threshold = self.capacity / 4.0
        self.very_low_stock_threshold = self.capacity / 8.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.n_players
        r = self.n_rounds
        if current_stock <= 0:
            return Action.C
        if current_stock >= self.capacity * 0.95:
            return Action.C
        round_number = history.round_number
        if round_number == 0:
            return Action.C
        last_opp = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        denom = max(n - 1, 1)
        f_last = last_opp / denom
        last_two_good = False
        last_two_bad = False
        if len(history.opponent_cooperators) >= 2:
            prev_opp = int(history.opponent_cooperators[-2])
            f_prev = prev_opp / denom
            last_two_good = f_last >= 2.0 / 3.0 and f_prev >= 2.0 / 3.0
            last_two_bad = f_last < 1.0 / 3.0 and f_prev < 1.0 / 3.0
        if round_number >= r - 2:
            return Action.C
        if f_last >= 2.0 / 3.0 or last_two_good:
            return Action.C
        if current_stock <= self.low_stock_threshold:
            if current_stock <= self.very_low_stock_threshold:
                return Action.C
            return Action.D if f_last < 2.0 / 3.0 else Action.C
        if last_two_bad:
            return Action.D
        if f_last < 1.0 / 3.0:
            return Action.D
        return Action.C

class Strategy_ALTRUISTIC_37(BaseStrategy):
    """
    Always cooperate strategy for the Common Pool Resource Game.
    Chooses Action.C in every round, regardless of history, opponent behavior,
    or current stock level.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = getattr(game_description, 'n_players', 0)
        self.n_rounds = getattr(game_description, 'n_rounds', 0)
        self.capacity = getattr(game_description, 'capacity', 0)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        return Action.C

class Strategy_ALTRUISTIC_38(BaseStrategy):
    """
    Conservative common-pool strategy:
    - Default to cooperation.
    - Defect temporarily when stock is critically low or recent opponent cooperation is weak.
    - Return to cooperation immediately once the pool and cooperation recover.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.opponents = max(self.n - 1, 1)
        self.quarter_capacity = self.capacity / 4.0
        self.half_capacity = self.capacity / 2.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = int(history.round_number)
        S = float(current_stock)
        if S <= 0.0:
            return Action.D
        if S >= self.capacity:
            return Action.C
        if t == 0:
            return Action.C if S >= self.quarter_capacity else Action.D
        last_coop_count = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else self.opponents
        coop_rate = last_coop_count / self.opponents if self.opponents > 0 else 1.0
        previous_action = bool(history.my_actions[-1]) if len(history.my_actions) > 0 else True
        previous_was_coop = previous_action
        if t >= self.r - 1:
            return Action.C if S >= self.quarter_capacity else Action.D
        if S < self.quarter_capacity:
            return Action.D
        if not previous_was_coop:
            if S >= self.half_capacity:
                return Action.C
            if S >= self.quarter_capacity and coop_rate >= 0.5:
                return Action.C
            return Action.D
        if S >= self.half_capacity and coop_rate >= 0.5:
            return Action.C
        if S >= self.quarter_capacity and coop_rate >= 0.5:
            return Action.C
        if coop_rate < 0.5:
            return Action.D
        return Action.C

class Strategy_ALTRUISTIC_39(BaseStrategy):
    """
    Cooperative-by-default strategy with stock-awareness, smoothing of opponent
    cooperation, recovery after improving stock, and cautious defensive defection
    only under severe depletion and sustained low cooperation.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self._prev_stock = None
        self._smoothed_opponent_coop = None
        self._last_round_seen = -1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_rounds = int(self.game_description.n_rounds)
        n_players = int(self.game_description.n_players)
        capacity = float(self.game_description.capacity)
        round_number = int(history.round_number)
        n_opponents = max(n_players - 1, 1)
        if round_number == 0:
            self._prev_stock = float(current_stock)
            self._last_round_seen = 0
            return Action.C
        last_opponent_count = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        last_rate = last_opponent_count / n_opponents
        if self._smoothed_opponent_coop is None:
            self._smoothed_opponent_coop = last_rate
        else:
            self._smoothed_opponent_coop = 0.7 * self._smoothed_opponent_coop + 0.3 * last_rate
        coop_signal = self._smoothed_opponent_coop if round_number >= 2 else last_rate
        if round_number >= max(n_rounds - 2, 0):
            self._prev_stock = float(current_stock)
            self._last_round_seen = round_number
            return Action.C
        if current_stock >= capacity:
            self._prev_stock = float(current_stock)
            self._last_round_seen = round_number
            return Action.C
        if self._prev_stock is not None and current_stock > self._prev_stock:
            self._prev_stock = float(current_stock)
            self._last_round_seen = round_number
            return Action.C
        if current_stock <= 0.2 * capacity:
            if coop_signal < 0.5:
                self._prev_stock = float(current_stock)
                self._last_round_seen = round_number
                return Action.D
        if current_stock >= 0.6 * capacity or coop_signal >= 0.5:
            self._prev_stock = float(current_stock)
            self._last_round_seen = round_number
            return Action.C
        if current_stock < 0.35 * capacity and coop_signal < 1.0 / 3.0:
            self._prev_stock = float(current_stock)
            self._last_round_seen = round_number
            return Action.D
        self._prev_stock = float(current_stock)
        self._last_round_seen = round_number
        return Action.C

class Strategy_ALTRUISTIC_40(BaseStrategy):
    """
    Cooperative-by-default conservation strategy for the Common Pool Resource Game.

    - Cooperate in round 1.
    - In intermediate rounds, cooperate only if recent opponent cooperation is at least
      half and stock is still reasonably healthy.
    - In the last round, cooperate only if stock is still at or above the preservation threshold.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.stock_threshold = self.capacity / 4.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        if round_number == 0:
            return Action.C
        if round_number >= self.n_rounds - 1:
            return Action.C if current_stock >= self.stock_threshold else Action.D
        if len(history.opponent_cooperators) == 0:
            m_t = 1.0
        else:
            prev_cooperators = float(history.opponent_cooperators[-1])
            opponent_count = max(self.n_players - 1, 1)
            m_t = prev_cooperators / float(opponent_count)
        if m_t >= 0.5 and current_stock >= self.stock_threshold:
            return Action.C
        return Action.D

class Strategy_ALTRUISTIC_41(BaseStrategy):
    """
    Unconditional cooperation strategy for the Common Pool Resource Game.
    Always plays C, while recording observed opponent cooperation and stock
    levels for monitoring only.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.observed_opponent_cooperators = []
        self.observed_stocks = []
        self.last_action = Action.C

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = getattr(history, 'round_number', 0)
        if round_number > 0:
            try:
                self.observed_opponent_cooperators.append(int(history.opponent_cooperators[-1]))
            except Exception:
                self.observed_opponent_cooperators.append(0)
        self.observed_stocks.append(float(current_stock) if current_stock is not None else 0.0)
        self.last_action = Action.C
        return Action.C

class Strategy_ALTRUISTIC_42(BaseStrategy):
    """
    Conservative cooperative strategy for the Common Pool Resource Game.

    Core idea:
    - Cooperate by default.
    - Use current stock as the main signal.
    - Defect only when the pool is clearly under stress or in a collapse spiral.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(self.n_players - 1, 0)
        self.prev_stock = None
        self.prev_opponent_cooperators = None
        self.prev_round_number = None
        self.deterioration_streak = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number + 1
        S = float(current_stock)
        if history.round_number == 0:
            self.prev_stock = S
            self.prev_opponent_cooperators = None
            self.prev_round_number = history.round_number
            self.deterioration_streak = 0
            return Action.C
        k_prev = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        m = self.n_opponents
        rho = k_prev / m if m > 0 else 1.0
        S_prev = self.prev_stock
        deteriorating = False
        if S_prev is not None and S_prev > 0:
            deteriorating = S < 0.8 * S_prev
        if deteriorating:
            self.deterioration_streak += 1
        else:
            self.deterioration_streak = 0
        self.prev_stock = S
        self.prev_opponent_cooperators = k_prev
        self.prev_round_number = history.round_number
        if t >= self.n_rounds:
            return Action.C if S >= 0.25 * self.capacity else Action.D
        if S < 0.25 * self.capacity:
            return Action.D
        if S >= 0.6 * self.capacity and rho >= 0.5:
            return Action.C
        if self.deterioration_streak >= 2:
            if rho >= 2.0 / 3.0 and S >= 0.7 * self.capacity:
                return Action.C
            return Action.D
        if S >= 0.6 * self.capacity and rho >= 0.5:
            return Action.C
        if S >= 0.4 * self.capacity and rho >= 2.0 / 3.0 and (not deteriorating):
            return Action.C
        if rho >= 0.5 and S >= 0.4 * self.capacity:
            return Action.C
        return Action.D

class Strategy_ALTRUISTIC_43(BaseStrategy):
    """
    Conservative cooperative strategy for the Common Pool Resource Game.

    - Starts with cooperation.
    - Prefers cooperation when the stock is healthy or opponents are sufficiently cooperative.
    - Uses limited defensive defection only when stock is under threat.
    - Recovers quickly back to cooperation after any defensive defection.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(self.n_players - 1, 1)
        self.high_threshold = 0.75 * self.capacity
        self.low_threshold = 0.35 * self.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        if round_number == 0:
            return Action.C
        last_opp_coop_count = 0
        if len(history.opponent_cooperators) > 0:
            last_opp_coop_count = int(history.opponent_cooperators[-1])
        if last_opp_coop_count < 0:
            last_opp_coop_count = 0
        elif last_opp_coop_count > self.n_opponents:
            last_opp_coop_count = self.n_opponents
        q = last_opp_coop_count / self.n_opponents if self.n_opponents > 0 else 1.0
        last_my_action = False
        if len(history.my_actions) > 0:
            last_my_action = bool(history.my_actions[-1])
        prev_defected = not last_my_action
        if round_number >= self.n_rounds - 1:
            return Action.C if q >= 1.0 / 3.0 else Action.D
        if prev_defected and (q >= 2.0 / 3.0 or current_stock >= self.high_threshold):
            return Action.C
        if current_stock >= self.high_threshold:
            return Action.C if q >= 1.0 / 3.0 else Action.D
        if current_stock >= self.low_threshold:
            return Action.C if q >= 2.0 / 3.0 else Action.D
        return Action.C if q >= 1.0 else Action.D

class Strategy_ALTRUISTIC_44(BaseStrategy):
    """
    Always cooperate in every round, regardless of history or stock level.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = getattr(game_description, 'n_players', 0)
        self.n_rounds = getattr(game_description, 'n_rounds', 0)
        self.capacity = getattr(game_description, 'capacity', 0)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        return Action.C

class Strategy_ALTRUISTIC_45(BaseStrategy):
    """
    Always cooperate strategy for the common pool resource game.

    This strategy ignores strategic incentives and always returns Action.C,
    while keeping lightweight internal monitoring of opponent cooperation.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self._opponent_cooperation_history = []
        self._observed_rounds = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = getattr(history, 'round_number', 0)
        try:
            observed_len = len(history.opponent_cooperators)
        except Exception:
            observed_len = 0
        if observed_len > self._observed_rounds:
            for idx in range(self._observed_rounds, observed_len):
                try:
                    self._opponent_cooperation_history.append(int(history.opponent_cooperators[idx]))
                except Exception:
                    self._opponent_cooperation_history.append(0)
            self._observed_rounds = observed_len
        return Action.C

class Strategy_ALTRUISTIC_46(BaseStrategy):
    """
    Common-pool strategy with early cooperation, stock-safety checks,
    reciprocity, recovery behavior, and a forgiving final-round policy.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(self.n_players - 1, 0)

    def _next_stock_if_all_cooperate(self, s: float) -> float:
        remaining = s / 2.0
        growth = 2.0 * remaining * (1.0 - remaining / self.capacity) if self.capacity > 0 else 0.0
        return min(remaining + growth, self.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number
        s = float(current_stock)
        if t == 0:
            return Action.C
        if t == self.n_rounds - 1:
            return Action.C if s >= self.capacity / 2.0 else Action.D
        if self.n_opponents > 0 and len(history.opponent_cooperators) > 0:
            k_prev = int(history.opponent_cooperators[-1])
            rho_prev = k_prev / float(self.n_opponents)
        else:
            rho_prev = 1.0
        if s < 0.75 * self.capacity:
            return Action.C if rho_prev >= 1.0 else Action.D
        s_cc = self._next_stock_if_all_cooperate(s)
        if s_cc < self.capacity / 2.0:
            return Action.D
        if rho_prev >= 2.0 / 3.0:
            return Action.C
        return Action.D

class Strategy_ALTRUISTIC_47(BaseStrategy):
    """
    Start cooperative, use temporary defection as a conservation brake when
    pressure from prior overuse builds up and the stock becomes constrained.
    Returns to cooperation quickly once the group behaves sustainably.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.alpha = 0.7
        self.pressure = 0.0
        self.last_action = Action.C
        self.last_stock = float(game_description.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = max(2, int(self.game_description.n_players))
        capacity = float(self.game_description.capacity)
        round_number = int(history.round_number)
        if round_number == 0:
            self.pressure = 0.0
            self.last_action = Action.C
            self.last_stock = float(current_stock)
            return Action.C
        prev_opp_coop = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        denom = max(n - 1, 1)
        q_prev = prev_opp_coop / denom
        self.pressure = self.alpha * self.pressure + (1.0 - q_prev)
        safe_threshold = 0.6 * capacity
        caution_threshold = 0.3 * capacity
        stock = float(current_stock)
        prev_my_action = None
        if len(history.my_actions) > 0:
            prev_my_action = Action.C if bool(history.my_actions[-1]) else Action.D
        stock_increased = stock > self.last_stock + 1e-12
        broad_cooperation = q_prev >= 0.5
        in_emergency = stock < caution_threshold
        if prev_my_action == Action.D and (not in_emergency):
            self.last_action = Action.C
            self.last_stock = stock
            return Action.C
        if prev_my_action == Action.D and (broad_cooperation or stock_increased):
            self.last_action = Action.C
            self.last_stock = stock
            return Action.C
        if round_number >= int(self.game_description.n_rounds) - 1:
            if in_emergency and self.pressure > 0.2 and (q_prev < 0.5):
                self.last_action = Action.D
                self.last_stock = stock
                return Action.D
            self.last_action = Action.C
            self.last_stock = stock
            return Action.C
        if stock >= capacity:
            self.last_action = Action.C
            self.last_stock = stock
            return Action.C
        if stock >= safe_threshold:
            self.last_action = Action.C
            self.last_stock = stock
            return Action.C
        if stock >= caution_threshold:
            if self.pressure <= 0.6:
                self.last_action = Action.C
                self.last_stock = stock
                return Action.C
            self.last_action = Action.D
            self.last_stock = stock
            return Action.D
        if self.pressure > 0.2 and (not broad_cooperation):
            self.last_action = Action.D
            self.last_stock = stock
            return Action.D
        self.last_action = Action.C
        self.last_stock = stock
        return Action.C

class Strategy_ALTRUISTIC_48(BaseStrategy):
    """
    Protective cooperativeness strategy for the Common Pool Resource Game.

    - Cooperates by default.
    - Defects only briefly after repeated low cooperation when stock is under pressure.
    - Forgives immediately when cooperation reappears or the stock recovers.
    - Avoids consecutive defections in the final two rounds.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.baseline = Action.C
        self.alarm = 2 * game_description.n_players
        self.critical = 4 * game_description.n_players
        self.trust = 0
        self.last_stock = None
        self.last_action = None

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_players = self.game_description.n_players
        n_opponents = max(n_players - 1, 0)
        half_opponents = math.ceil(n_opponents / 2)
        round_number = history.round_number
        remaining_rounds = self.game_description.n_rounds - round_number
        prev_opponents = int(history.opponent_cooperators[-1]) if round_number > 0 else None
        prev2_opponents = int(history.opponent_cooperators[-2]) if round_number > 1 else None
        prev_action = bool(history.my_actions[-1]) if round_number > 0 else None
        prev_defected = prev_action is False if round_number > 0 else False
        stock_increased = False
        if self.last_stock is not None:
            stock_increased = current_stock > self.last_stock
        widespread_defection_prev = False
        widespread_defection_prev2 = False
        if prev_opponents is not None:
            widespread_defection_prev = prev_opponents < half_opponents
        if prev2_opponents is not None:
            widespread_defection_prev2 = prev2_opponents < half_opponents
        action = Action.C
        if round_number == 0:
            action = Action.C
        elif remaining_rounds == 1:
            if prev_defected:
                action = Action.C
            elif current_stock <= self.critical and widespread_defection_prev:
                action = Action.D
            else:
                action = Action.C
        elif remaining_rounds == 2:
            if prev_defected:
                action = Action.C
            elif current_stock <= self.critical:
                action = Action.C if prev_opponents is not None and prev_opponents >= n_opponents else Action.D
            elif current_stock <= self.alarm:
                action = Action.C if prev_opponents is not None and prev_opponents >= n_opponents else Action.D
            elif widespread_defection_prev and widespread_defection_prev2:
                action = Action.D
            else:
                action = Action.C
        else:
            if current_stock <= self.critical:
                action = Action.C if prev_opponents is not None and prev_opponents >= n_opponents else Action.D
            elif current_stock <= self.alarm:
                action = Action.C if prev_opponents is not None and prev_opponents >= n_opponents else Action.D
            elif widespread_defection_prev and widespread_defection_prev2:
                action = Action.D
            else:
                action = Action.C
            if prev_defected and action == Action.D:
                if prev_opponents is not None and prev_opponents >= half_opponents or stock_increased:
                    action = Action.C
        self.last_stock = current_stock
        self.last_action = action
        self.trust = self.trust + 1 if action == Action.C else 0
        return action

class Strategy_ALTRUISTIC_49(BaseStrategy):
    """
    Always cooperates in every round, regardless of history, stock level,
    opponent behavior, or game progress.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self._always_cooperate = Action.C

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        return self._always_cooperate

class Strategy_ALTRUISTIC_50(BaseStrategy):
    """
    Generous state-based threshold strategy for the Common Pool Resource Game.
    Defaults to cooperation, but switches to temporary conservation when
    cooperation is repeatedly low and the stock is under pressure.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.trust_level = 0.0
        self.last_two_low_cooperation = False
        self.prev_low_cooperation = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.n
        rounds_played = history.round_number
        capacity = self.capacity
        alpha = 0.0 if capacity <= 0 else float(current_stock) / capacity
        if rounds_played == 0:
            return Action.C
        c_last = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        opp_count = max(n - 1, 0)
        coop_rate = c_last / opp_count if opp_count > 0 else 1.0
        my_last_action = bool(history.my_actions[-1]) if len(history.my_actions) > 0 else True
        total_last_cooperators = c_last + (1 if my_last_action else 0)
        low_overall_last_round = total_last_cooperators < n / 2.0
        self.last_two_low_cooperation = self.prev_low_cooperation and low_overall_last_round
        self.prev_low_cooperation = low_overall_last_round
        if c_last >= opp_count / 2.0:
            self.trust_level = min(self.trust_level + 1.0, 5.0)
        else:
            self.trust_level = max(self.trust_level - 1.0, -5.0)
        if rounds_played == self.r - 1:
            if alpha < 0.15 and coop_rate < 0.25:
                return Action.D
            return Action.C
        if alpha <= 0.1:
            return Action.D if c_last == 0 else Action.C
        if alpha <= 0.25:
            return Action.C if c_last >= max(n - 2, 0) else Action.D
        if low_overall_last_round:
            if alpha < 0.35 and self.last_two_low_cooperation:
                return Action.D
            if alpha >= 0.35:
                return Action.C
        if coop_rate >= 0.6:
            return Action.C
        if coop_rate >= 0.4 and alpha >= 0.5:
            return Action.C
        if coop_rate < 0.4 and alpha < 0.5:
            return Action.D
        if self.trust_level >= 0:
            return Action.C
        return Action.D

class Strategy_ALTRUISTIC_51(BaseStrategy):
    """
    Always cooperate in every round to minimize consumption and preserve the common pool.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = getattr(game_description, 'n_players', 0)
        self.n_rounds = getattr(game_description, 'n_rounds', 0)
        self.capacity = getattr(game_description, 'capacity', 0)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        return Action.C

class Strategy_ALTRUISTIC_52(BaseStrategy):
    """
    State-sensitive conservation strategy for the common pool resource game.
    Cooperates by default, and defects only when a next-state comparison shows
    that defecting preserves strictly more stock for the group.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = max(2, int(game_description.n_players))
        self.r = max(1, int(game_description.n_rounds))
        self.capacity = float(game_description.capacity) if float(game_description.capacity) > 0 else 1.0
        self.epsilon = 1e-12
        self._last_action = Action.C
        self._last_stock = self.capacity
        self._stable_cooperation_streak = 0

    def _next_stock_if_cooperate(self, x: float) -> float:
        s_c = max(0.0, x / 2.0)
        growth_c = 2.0 * s_c * (1.0 - s_c / self.capacity)
        return min(s_c + growth_c, self.capacity)

    def _next_stock_if_defect(self, x: float) -> float:
        s_d = max(0.0, x * (0.5 - 0.5 / self.n))
        growth_d = 2.0 * s_d * (1.0 - s_d / self.capacity)
        return min(s_d + growth_d, self.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        x = float(current_stock)
        if not math.isfinite(x):
            x = 0.0
        x = max(0.0, min(x, self.capacity))
        if history.round_number == 0:
            self._last_action = Action.C
            self._last_stock = x
            self._stable_cooperation_streak = 0
            return Action.C
        last_opponent_cooperators = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else -1
        n_opponents = max(0, self.n - 1)
        fully_cooperative_last_round = last_opponent_cooperators == n_opponents if last_opponent_cooperators >= 0 else False
        n_c = self._next_stock_if_cooperate(x)
        n_d = self._next_stock_if_defect(x)
        if x <= self.epsilon:
            action = Action.C
        elif history.round_number >= self.r - 1:
            action = Action.D if n_d > n_c + self.epsilon else Action.C
        elif fully_cooperative_last_round:
            action = Action.C
        elif n_c >= n_d - self.epsilon:
            action = Action.C
        else:
            action = Action.D if n_d > n_c + self.epsilon and x > self.epsilon else Action.C
        if action == Action.C:
            if fully_cooperative_last_round:
                self._stable_cooperation_streak += 1
            else:
                self._stable_cooperation_streak = 0
        else:
            self._stable_cooperation_streak = 0
        self._last_action = action
        self._last_stock = x
        return action

class Strategy_ALTRUISTIC_53(BaseStrategy):
    """
    Cautious conditional cooperator for the Common Pool Resource Game.

    - Cooperates by default.
    - Defects only after sustained evidence of broad defection and low stock.
    - Recovers to cooperation quickly after improvement in group behavior or stock.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        n = self.n_players
        capacity = self.capacity
        if round_number == 0:
            return Action.C
        if round_number >= self.n_rounds - 1:
            return Action.C
        prev_opponents_coop = int(history.opponent_cooperators[-1]) if round_number >= 1 else None
        prev2_opponents_coop = int(history.opponent_cooperators[-2]) if round_number >= 2 else None
        half_opp_threshold = math.ceil((n - 1) / 2)
        low_defection_threshold = math.floor((n - 1) / 3)
        previously_defected = False
        if round_number >= 1:
            previously_defected = not bool(history.my_actions[-1])
        if prev_opponents_coop is None:
            return Action.C
        if prev_opponents_coop >= n - 1:
            return Action.C
        if previously_defected and (prev_opponents_coop >= half_opp_threshold or current_stock >= 3.0 * capacity / 4.0):
            return Action.C
        if current_stock < capacity / 4.0:
            return Action.C if prev_opponents_coop >= n - 1 else Action.D
        if prev_opponents_coop >= half_opp_threshold:
            return Action.C
        if current_stock >= capacity / 2.0:
            return Action.C
        sustained_defection = prev_opponents_coop <= low_defection_threshold and (prev2_opponents_coop is not None and prev2_opponents_coop <= low_defection_threshold or current_stock < capacity / 3.0)
        if sustained_defection:
            return Action.D
        return Action.C

class Strategy_ALTRUISTIC_54(BaseStrategy):
    """
    Cooperative-by-default commons strategy with emergency defection only under
    clear depletion or persistent breakdown.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.quarter_capacity = self.capacity / 4.0
        self.half_capacity = self.capacity / 2.0
        self.three_quarters_capacity = 3.0 * self.capacity / 4.0
        self.n_opponents = max(self.n_players - 1, 0)
        self.bad_threshold = self.n_opponents / 2.0
        self.severe_threshold = self.n_opponents - 1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number
        if t == 0:
            return Action.C
        if t >= self.n_rounds - 1:
            return Action.D if current_stock < self.quarter_capacity else Action.C
        if current_stock < self.quarter_capacity:
            return Action.D
        if len(history.opponent_cooperators) == 0:
            m_prev = self.n_opponents
        else:
            m_prev = int(history.opponent_cooperators[-1])
        bad_prev = m_prev < self.bad_threshold
        severe_prev = m_prev <= self.severe_threshold
        if severe_prev and (not (current_stock > self.three_quarters_capacity or m_prev == self.n_opponents)):
            return Action.D
        if bad_prev and current_stock < self.half_capacity:
            return Action.D
        return Action.C

class Strategy_ALTRUISTIC_55(BaseStrategy):
    """
    Conditional cooperation with a depletion safeguard:
    cooperate by default, defect only when stock is low and recent opponent
    cooperation is weak, and always cooperate in the first and last rounds.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number
        if t == 0:
            return Action.C
        if t >= self.n_rounds - 1:
            return Action.C
        if current_stock > self.n_players:
            return Action.C
        if history.opponent_cooperators is None or len(history.opponent_cooperators) == 0:
            return Action.C
        recent_cooperators = history.opponent_cooperators[-1]
        n_opponents = self.n_players - 1
        if n_opponents <= 0:
            return Action.C
        x_t = float(recent_cooperators) / float(n_opponents)
        if x_t >= 0.5:
            return Action.C
        if current_stock <= self.n_players and x_t < 0.5:
            return Action.D
        return Action.C

class Strategy_ALTRUISTIC_56(BaseStrategy):
    """
    Stock-aware cooperative strategy with a brief defensive defection rule.
    - Cooperates by default.
    - Defects only under low stock and poor opponent cooperation.
    - Recovers to cooperation quickly once conditions improve.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(1, self.n_players - 1)
        self.half_capacity = self.capacity / 2.0
        self.quarter_capacity = self.capacity / 4.0
        self.sixth_capacity = self.capacity / 6.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        if round_number >= self.n_rounds - 1:
            return Action.C if current_stock > 0 else Action.D
        if round_number == 0:
            return Action.C
        last_opp_coop = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        q_t = last_opp_coop / self.n_opponents if self.n_opponents > 0 else 0.0
        my_last_action_is_defection = False
        if len(history.my_actions) > 0:
            my_last_action_is_defection = not bool(history.my_actions[-1])
        S_t = float(current_stock)
        if my_last_action_is_defection:
            if not (S_t < self.quarter_capacity and q_t < 1.0 / 3.0):
                return Action.C
            return Action.D
        if S_t <= self.sixth_capacity:
            if q_t >= 0.5:
                return Action.C
            return Action.D
        if S_t >= self.half_capacity and q_t >= 0.5:
            return Action.C
        return Action.D

class Strategy_ALTRUISTIC_57(BaseStrategy):
    """
    Cautious common-pool strategy:
    - Start cooperative
    - Always cooperate when the stock is fragile or in the final round
    - Otherwise cooperate when recent opponent cooperation is at/near a stock-dependent threshold
    - Defect only after clearly low cooperation and when the pool is still healthy
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(self.n_players - 1, 1)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        if round_number == 0:
            return Action.C
        if current_stock <= 2 * self.n_players:
            return Action.C
        if round_number >= self.n_rounds - 1:
            return Action.C
        last_opponent_coops = int(history.opponent_cooperators[-1]) if round_number > 0 else 0
        if self.n_players == 2:
            p = 1.0 if last_opponent_coops >= 1 else 0.0
        else:
            p = last_opponent_coops / float(self.n_opponents)
        s = current_stock / self.capacity if self.capacity > 0 else 0.0
        if s < 0.0:
            s = 0.0
        elif s > 1.0:
            s = 1.0
        threshold = 0.35 + 0.35 * s
        if p >= threshold:
            return Action.C
        if p >= threshold - 0.1:
            return Action.C
        if p < 0.25:
            return Action.C
        return Action.D

class Strategy_ALTRUISTIC_58(BaseStrategy):
    """
    Forgiving common-pool strategy:
    cooperate by default, and defect only as a temporary response to
    low stock and persistent opponent free-riding.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.capacity = float(game_description.capacity)
        self.n_players = int(game_description.n_players)
        self.n_opponents = max(self.n_players - 1, 1)
        self.memory_score = 1.0
        self.last_round_seen = -1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_rounds = int(self.game_description.n_rounds)
        capacity = float(self.capacity)
        stock = float(current_stock)
        if history.round_number == 0:
            self.memory_score = 1.0
            self.last_round_seen = 0
            return Action.C
        if stock <= 0.0:
            return Action.C
        if history.round_number >= n_rounds - 1:
            return Action.D if stock < 0.2 * capacity else Action.C
        opp_counts = history.opponent_cooperators
        opp_count = self.n_opponents
        m = 1.0
        q_values = []
        if len(opp_counts) > 0:
            denom = float(opp_count) if opp_count > 0 else 1.0
            for c in opp_counts:
                q = float(c) / denom
                q_values.append(q)
                m = 0.7 * m + 0.3 * q
        self.memory_score = m
        self.last_round_seen = history.round_number
        q_last = q_values[-1] if q_values else 1.0
        q_prev = q_values[-2] if len(q_values) >= 2 else 1.0
        low_stock = stock < 0.2 * capacity
        healthy_stock = stock >= 0.35 * capacity
        strong_coop = q_last >= 0.5
        weak_coop_two_rounds = q_last <= 0.25 and q_prev <= 0.25
        if low_stock or self.memory_score < 0.35 or weak_coop_two_rounds:
            return Action.D
        if healthy_stock and self.memory_score >= 0.5 and strong_coop:
            return Action.C
        return Action.C

class Strategy_ALTRUISTIC_59(BaseStrategy):
    """
    State-based conservation strategy with preserve, recover, and emergency modes.
    Cooperates by default, defects under severe depletion, and becomes more cautious
    after consecutive low-cooperation rounds.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        capacity = float(game_description.capacity)
        self.capacity = capacity
        self.target_stock = capacity / 2.0
        self.buffer = capacity / 4.0
        self.low = capacity / 3.0
        self.critical = capacity / 5.0
        self.previous_low_cooperation: bool = False
        self.last_observed_p: float = 1.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_players = int(self.game_description.n_players)
        n_opponents = max(n_players - 1, 0)
        round_number = int(history.round_number)
        last_round_index = round_number - 1

        def observed_p_from_history() -> float:
            if round_number <= 0:
                return 1.0
            if len(history.opponent_cooperators) <= 0:
                return 1.0
            k = int(history.opponent_cooperators[-1])
            if n_opponents <= 0:
                return 1.0
            k = max(0, min(k, n_opponents))
            return k / n_opponents
        if round_number == 0:
            self.previous_low_cooperation = False
            self.last_observed_p = 1.0
            return Action.C
        if round_number == int(self.game_description.n_rounds) - 1:
            p = observed_p_from_history()
            self.last_observed_p = p
            self.previous_low_cooperation = p < 0.5
            return Action.C
        p = observed_p_from_history()
        current_low_cooperation = p < 0.5
        previous_p = self.last_observed_p if round_number > 1 else 1.0
        capacity = self.capacity
        critical = self.critical
        low = self.low
        buffer = self.buffer
        S = float(current_stock)
        if S < critical:
            action = Action.D
        elif S <= critical:
            action = Action.D
        elif S < low:
            action = Action.C if p >= 0.75 else Action.D
        elif S <= capacity - buffer:
            cautious_mode = self.previous_low_cooperation and current_low_cooperation
            if cautious_mode:
                action = Action.D if p < 0.75 else Action.C
            else:
                action = Action.C
        else:
            action = Action.C
        self.previous_low_cooperation = current_low_cooperation
        self.last_observed_p = p
        return action

class Strategy_ALTRUISTIC_60(BaseStrategy):
    """
    Cooperative-by-default common-pool strategy with defensive defections
    against severe depletion or sustained exploitation.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_opponents = max(0, self.n_players - 1)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.half_opponents_ceil = math.ceil(self.n_opponents / 2) if self.n_opponents > 0 else 0
        self.third_opponents_ceil = math.ceil(self.n_opponents / 3) if self.n_opponents > 0 else 0
        self.quarter_capacity = self.capacity / 4.0 if self.capacity else 0.0
        self.eighth_capacity = self.capacity / 8.0 if self.capacity else 0.0
        self.third_capacity = self.capacity / 3.0 if self.capacity else 0.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = int(history.round_number)
        if t == 0:
            return Action.C
        last_opponents = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        last_my_action = bool(history.my_actions[-1]) if len(history.my_actions) > 0 else True
        previous_action_was_defect = not last_my_action
        last_round_all_cooperated = last_opponents >= self.n_opponents
        last_two_all_cooperated = False
        if len(history.opponent_cooperators) >= 2:
            last_two_all_cooperated = int(history.opponent_cooperators[-1]) >= self.n_opponents and int(history.opponent_cooperators[-2]) >= self.n_opponents and bool(history.my_actions[-1]) and bool(history.my_actions[-2])
        if t == self.n_rounds - 1:
            return Action.C if current_stock >= self.eighth_capacity else Action.D
        if current_stock < self.eighth_capacity:
            return Action.C if last_round_all_cooperated else Action.D
        if last_two_all_cooperated:
            return Action.C
        if previous_action_was_defect:
            if last_opponents >= self.half_opponents_ceil or current_stock >= self.third_capacity:
                return Action.C
            return Action.D
        if current_stock >= self.quarter_capacity and last_opponents >= self.half_opponents_ceil:
            return Action.C
        if last_opponents < self.third_opponents_ceil:
            return Action.D
        return Action.C

class Strategy_ALTRUISTIC_61(BaseStrategy):
    """
    Cooperative default strategy with temporary conservation mode when
    opponent free-riding coincides with declining stock.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.conservation_mode = False
        self.last_observed_stock = None
        self.last_action = Action.C
        self.eps = 1e-09

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = int(self.game_description.n_players)
        r = int(self.game_description.n_rounds)
        capacity = float(self.game_description.capacity)
        round_number = int(history.round_number)
        action = Action.C
        if round_number == 0:
            self.conservation_mode = False
            self.last_observed_stock = float(current_stock)
            self.last_action = Action.C
            return Action.C
        prev_cooperators = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        n_opponents = max(n - 1, 0)
        p = prev_cooperators / n_opponents if n_opponents > 0 else 1.0
        stock_now = float(current_stock)
        stock_prev = self.last_observed_stock if self.last_observed_stock is not None else stock_now
        stock_declined_last_round = stock_now < stock_prev - self.eps
        stock_low = stock_now < capacity / 2.0
        severely_low = stock_now < capacity / 3.0
        near_capacity = stock_now >= 0.9 * capacity
        half_opponents_cooperated = p >= 0.5
        if round_number >= r - 1:
            action = Action.C
            self.conservation_mode = False
        elif near_capacity:
            action = Action.C
            self.conservation_mode = False
        elif half_opponents_cooperated:
            action = Action.C
            self.conservation_mode = False
        else:
            if stock_declined_last_round or severely_low:
                action = Action.D
                self.conservation_mode = True
            else:
                action = Action.C
            if self.conservation_mode and (half_opponents_cooperated or not stock_declined_last_round or stock_now >= capacity / 2.0):
                action = Action.C
                self.conservation_mode = False
        if action == Action.D and self.last_action == Action.D:
            if not (self.conservation_mode and (stock_low or severely_low) and (not half_opponents_cooperated)):
                action = Action.C
                self.conservation_mode = False
        if action not in (Action.C, Action.D):
            action = Action.C
        self.last_observed_stock = stock_now
        self.last_action = action
        return action

class Strategy_ALTRUISTIC_62(BaseStrategy):
    """
    Generous cooperative strategy with temporary defensive defection when the
    resource is depleted or opponent cooperation collapses.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self._last_stock = None
        self._prev_stock = None

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_rounds = self.game_description.n_rounds
        capacity = float(self.game_description.capacity)
        n_players = self.game_description.n_players
        n_opponents = max(n_players - 1, 0)
        round_number = history.round_number
        critical_25 = 0.25 * capacity
        critical_35 = 0.35 * capacity
        critical_40 = 0.4 * capacity
        critical_10 = 0.1 * capacity

        def opponent_coop_rate_from_index(idx: int) -> float:
            if idx < 0 or idx >= len(history.opponent_cooperators):
                return 1.0
            if n_opponents <= 0:
                return 1.0
            return float(history.opponent_cooperators[idx]) / float(n_opponents)
        last_opp_rate = opponent_coop_rate_from_index(round_number - 1)
        prev_opp_rate = opponent_coop_rate_from_index(round_number - 2)
        low_opp_last = last_opp_rate < 0.5
        low_opp_prev = prev_opp_rate < 0.5
        two_consecutive_low_opp = low_opp_last and low_opp_prev
        last_action_defected = bool(history.my_actions[-1]) is False if round_number > 0 else False
        stock_falling_two_rounds = False
        if self._last_stock is not None and self._prev_stock is not None:
            stock_falling_two_rounds = current_stock < self._last_stock < self._prev_stock
        if round_number == 0:
            action = Action.C
        elif round_number == n_rounds - 1:
            action = Action.C if current_stock > critical_10 else Action.D
        elif round_number < 2:
            action = Action.D if current_stock <= critical_25 else Action.C
        elif last_action_defected and current_stock > critical_35 and (last_opp_rate >= 0.5):
            action = Action.C
        elif current_stock <= critical_25:
            action = Action.D
        elif stock_falling_two_rounds:
            action = Action.D if current_stock <= critical_40 else Action.C
        elif two_consecutive_low_opp:
            action = Action.D if current_stock <= critical_40 else Action.C
        else:
            action = Action.C if last_opp_rate >= 0.5 else Action.D
        self._prev_stock = self._last_stock
        self._last_stock = float(current_stock)
        return action

class Strategy_ALTRUISTIC_63(BaseStrategy):
    """
    Always cooperate in every round, regardless of history or current stock.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = getattr(game_description, 'n_players', None)
        self.n_rounds = getattr(game_description, 'n_rounds', None)
        self.capacity = getattr(game_description, 'capacity', None)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        return Action.C

class Strategy_ALTRUISTIC_64(BaseStrategy):
    """
    Conditional conservation strategy:
    - Default to cooperation.
    - Increase restraint as the stock falls.
    - Use short-lived defection only to prevent collapse from extreme exploitation.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.last_stock = None
        self.low_q_streak = 0
        self.high_q_streak = 0

    def _opponent_cooperation_ratio(self, history: PlayerHistory) -> float:
        n_opponents = max(self.n_players - 1, 1)
        if history.round_number == 0:
            return 1.0
        k = int(history.opponent_cooperators[-1])
        if self.n_players == 2:
            return 1.0 if k >= 1 else 0.0
        return k / n_opponents

    def _update_memory(self, history: PlayerHistory, current_stock: float) -> None:
        if history.round_number == 0:
            self.last_stock = float(current_stock)
            self.low_q_streak = 0
            self.high_q_streak = 0
            return
        q_prev = self._opponent_cooperation_ratio(history)
        if q_prev < 0.5:
            self.low_q_streak += 1
        else:
            self.low_q_streak = 0
        if q_prev >= 0.75:
            self.high_q_streak += 1
        else:
            self.high_q_streak = 0
        if self.last_stock is not None and float(current_stock) > float(self.last_stock):
            self.low_q_streak = 0
            self.high_q_streak = 0
        self.last_stock = float(current_stock)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_stock = float(current_stock)
        capacity = self.capacity if self.capacity > 0 else 1.0
        rho = current_stock / capacity
        self._update_memory(history, current_stock)
        if history.round_number == 0:
            return Action.C
        q_prev = self._opponent_cooperation_ratio(history)
        last_round = history.round_number >= self.n_rounds - 1
        if rho >= 0.5:
            if self.high_q_streak >= 2:
                return Action.C
            return Action.C
        if rho >= 0.25:
            if last_round:
                if rho >= 0.25:
                    return Action.C
                return Action.D if rho < 0.125 and q_prev < 0.5 else Action.C
            if self.low_q_streak >= 2:
                return Action.C if q_prev >= 0.25 else Action.D
            return Action.C if q_prev >= 0.5 else Action.D
        if rho >= 0.125:
            if last_round:
                return Action.D if rho < 0.125 and q_prev < 0.5 else Action.C
            if self.high_q_streak >= 2:
                return Action.C
            return Action.C if q_prev >= 0.75 else Action.D
        if last_round:
            return Action.D if q_prev < 0.5 and rho < 0.125 else Action.C
        if history.my_actions[-1]:
            return Action.C
        return Action.D if q_prev < 0.25 else Action.C

class Strategy_ALTRUISTIC_65(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Start with cooperation.
    - Use opponent cooperation rate and current stock to decide.
    - Apply strong endgame, low-stock, high-stock, recovery, and momentum overrides.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.opponents = max(self.n - 1, 0)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number
        if t == 0:
            return Action.C
        if t == self.r - 1:
            return Action.C
        S = float(current_stock)
        cap = self.capacity if self.capacity > 0 else 1.0
        stock_ratio = S / cap
        prev_k = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        m = self.opponents if self.opponents > 0 else 1
        c = prev_k / m
        p = 0.5 * c + 0.5 * stock_ratio
        final_three = t >= max(self.r - 3, 0)
        threshold = 0.45 if final_three else 0.55
        last_two_c = None
        if len(history.opponent_cooperators) >= 2:
            last_two_c = (int(history.opponent_cooperators[-1]) + int(history.opponent_cooperators[-2])) / (2 * m)
        prev_two_zero = False
        if len(history.opponent_cooperators) >= 2:
            prev_two_zero = int(history.opponent_cooperators[-1]) == 0 and int(history.opponent_cooperators[-2]) == 0
        prev_two_high = False
        if len(history.opponent_cooperators) >= 2:
            prev_two_high = int(history.opponent_cooperators[-1]) >= math.ceil(0.75 * m) and int(history.opponent_cooperators[-2]) >= math.ceil(0.75 * m)
        if stock_ratio >= 0.85:
            if prev_two_zero:
                return Action.D
            return Action.C
        if stock_ratio <= 0.25:
            return Action.C if c >= 1.0 else Action.D
        if prev_k == 0:
            return Action.D
        if prev_two_high:
            return Action.C
        if final_three and prev_k == 0 and (stock_ratio < 0.4):
            return Action.D
        if last_two_c is not None and last_two_c >= 0.75:
            return Action.C
        return Action.C if p >= threshold else Action.D

class Strategy_ALTRUISTIC_66(BaseStrategy):
    """
    Unconditional cooperation strategy for the Common Pool Resource Game.
    Always plays C in every round, regardless of history or current stock.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self._always_cooperate = Action.C

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        return self._always_cooperate

class Strategy_ALTRUISTIC_67(BaseStrategy):
    """
    Default-to-cooperation strategy with cautious, temporary defection only when
    repeated opponent defection is clearly reducing the common stock.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(self.n_players - 1, 0)
        self.epsilon = 1e-09

    def _next_stock(self, current_stock: float, total_consumption: float) -> float:
        s_remaining = current_stock - total_consumption
        if s_remaining < 0.0:
            s_remaining = 0.0
        growth = 2.0 * s_remaining * (1.0 - s_remaining / self.capacity) if self.capacity > 0 else 0.0
        new_stock = s_remaining + growth
        if new_stock > self.capacity:
            new_stock = self.capacity
        if new_stock < 0.0:
            new_stock = 0.0
        return float(new_stock)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number
        if t == 0 or t >= self.n_rounds - 1:
            return Action.C
        S = float(current_stock)
        if S <= 0.0:
            return Action.C
        if S <= 2.0 * self.n_players:
            if history.opponent_cooperators[-1] == 0 and len(history.my_payoffs) >= 2:
                if history.my_payoffs[-1] < history.my_payoffs[-2] - self.epsilon:
                    return Action.D
            return Action.C
        if self.capacity > 0.0 and S >= 0.9 * self.capacity:
            return Action.C
        prev_opp = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else self.n_opponents
        prev_prev_opp = int(history.opponent_cooperators[-2]) if len(history.opponent_cooperators) > 1 else self.n_opponents
        prev_majority_coop = prev_opp > self.n_opponents / 2.0
        prev_prev_majority_coop = prev_prev_opp > self.n_opponents / 2.0
        if prev_majority_coop and prev_prev_majority_coop:
            return Action.C
        low_coop_two_rounds = prev_opp < self.n_opponents / 2.0 and prev_prev_opp < self.n_opponents / 2.0
        stock_falling = False
        if len(history.my_payoffs) >= 2:
            stock_falling = history.my_payoffs[-1] < history.my_payoffs[-2] - self.epsilon
        below_half_capacity = self.capacity > 0.0 and S <= 0.5 * self.capacity
        if low_coop_two_rounds and (stock_falling or below_half_capacity):
            k = prev_opp
            m = self.n_opponents - k
            payoff_c = S / (2.0 * self.n_players) if self.n_players > 0 else 0.0
            payoff_d = S / self.n_players if self.n_players > 0 else 0.0
            total_c = (S / (2.0 * self.n_players) if self.n_players > 0 else 0.0) + k * (S / (2.0 * self.n_players) if self.n_players > 0 else 0.0) + m * (S / self.n_players if self.n_players > 0 else 0.0)
            total_d = (S / self.n_players if self.n_players > 0 else 0.0) + k * (S / (2.0 * self.n_players) if self.n_players > 0 else 0.0) + m * (S / self.n_players if self.n_players > 0 else 0.0)
            s_next_c = self._next_stock(S, total_c)
            s_next_d = self._next_stock(S, total_d)
            if payoff_c > 0.0 and s_next_c >= s_next_d - self.epsilon:
                return Action.C
            if payoff_c <= 0.0:
                return Action.D
            if s_next_c + self.epsilon < s_next_d and stock_falling:
                return Action.D
            return Action.C
        k = prev_opp
        m = self.n_opponents - k
        payoff_c = S / (2.0 * self.n_players) if self.n_players > 0 else 0.0
        payoff_d = S / self.n_players if self.n_players > 0 else 0.0
        total_c = (S / (2.0 * self.n_players) if self.n_players > 0 else 0.0) + k * (S / (2.0 * self.n_players) if self.n_players > 0 else 0.0) + m * (S / self.n_players if self.n_players > 0 else 0.0)
        total_d = (S / self.n_players if self.n_players > 0 else 0.0) + k * (S / (2.0 * self.n_players) if self.n_players > 0 else 0.0) + m * (S / self.n_players if self.n_players > 0 else 0.0)
        s_next_c = self._next_stock(S, total_c)
        s_next_d = self._next_stock(S, total_d)
        if payoff_c <= 0.0:
            return Action.D
        if payoff_c == payoff_d or abs(s_next_c - s_next_d) <= self.epsilon:
            return Action.C
        if s_next_c >= s_next_d - self.epsilon:
            return Action.C
        return Action.D if s_next_c + self.epsilon < s_next_d and stock_falling else Action.C

class Strategy_ALTRUISTIC_68(BaseStrategy):
    """
    Stock-preservation strategy with bounded forgiveness and collapse recovery.
    Cooperates by default, defects only under sustained low cooperation and low stock.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(1, self.n_players - 1)
        self.min_trend_window = 3
        self.coop_rate_step = 1.0 / self.n_opponents
        self.stability_threshold = 1.0 / (2.0 * self.n_opponents)

    def _coop_rate(self, opponents_coop: int) -> float:
        return float(opponents_coop) / self.n_opponents

    def _moving_average(self, values: list[float]) -> float:
        return float(np.mean(values)) if values else 0.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number
        r = self.n_rounds
        S_t = float(current_stock)
        if t == 0:
            return Action.C
        opp_counts = history.opponent_cooperators
        x_vals = [self._coop_rate(int(c)) for c in opp_counts]
        x_last = x_vals[-1] if len(x_vals) >= 1 else 0.0
        x_prev = x_vals[-2] if len(x_vals) >= 2 else 0.0
        x_prev2 = x_vals[-3] if len(x_vals) >= 3 else 0.0
        last_up_to_3 = x_vals[-3:] if len(x_vals) >= 3 else x_vals[:]
        xbar = self._moving_average(last_up_to_3)
        if len(x_vals) >= 6:
            recent_avg = self._moving_average(x_vals[-3:])
            prior_avg = self._moving_average(x_vals[-6:-3])
            trend = recent_avg - prior_avg
        else:
            trend = 0.0
        stability = 1 if abs(x_last - x_prev) <= self.stability_threshold else 0
        if t == r - 1:
            if x_last > 0.0:
                return Action.C
            return Action.D if S_t <= self.capacity / 4.0 else Action.C
        if S_t <= 2.0 * self.n_players or S_t <= self.capacity / 8.0:
            return Action.C
        late_window = min(3, r - 1)
        if t >= r - late_window:
            if xbar >= 1.0 / 3.0 or S_t >= self.capacity / 2.0:
                return Action.C
            if S_t < self.capacity / 8.0 and xbar < 1.0 / 3.0:
                return Action.D
            return Action.C
        if x_last >= 1.0 / 3.0 and x_last < 2.0 / 3.0:
            return Action.C
        if x_last < 1.0 / 3.0:
            improvement = x_last - x_prev
            if improvement >= self.stability_threshold:
                return Action.C
        if xbar >= 2.0 / 3.0:
            return Action.C
        if S_t >= 0.8 * self.capacity:
            return Action.C
        if stability == 1 and xbar >= 0.5:
            return Action.C
        if xbar < 1.0 / 3.0 and S_t < 0.6 * self.capacity:
            return Action.D
        if x_last < 1.0 / 3.0 and x_prev < 1.0 / 3.0 and (trend <= 0.0):
            return Action.D
        return Action.C

class Strategy_ALTRUISTIC_69(BaseStrategy):
    """
    Cooperate by default, defect to protect against collapse or sustained
    majority free-riding, and harvest cautiously on the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(self.n_players - 1, 0)
        self.low_stock_threshold = self.capacity / 4.0 if self.capacity else 0.0
        self.majority_cutoff = self.n_opponents // 2

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        current_round = round_number + 1
        if round_number == 0:
            return Action.C
        if current_round >= self.n_rounds:
            return Action.C if current_stock > self.low_stock_threshold else Action.D
        if current_stock <= self.low_stock_threshold:
            return Action.D
        if round_number >= 2:
            last = int(history.opponent_cooperators[-1])
            prev = int(history.opponent_cooperators[-2])
            if last <= self.majority_cutoff and prev <= self.majority_cutoff:
                return Action.D
        return Action.C

class Strategy_ALTRUISTIC_70(BaseStrategy):
    """
    Conservation-first common-pool strategy:
    start by cooperating, keep cooperating when the stock is healthy,
    and use at most brief defection when the pool is depleted and recent
    cooperation has collapsed.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = max(2, int(game_description.n_players))
        self.n_rounds = max(1, int(game_description.n_rounds))
        self.capacity = float(game_description.capacity) if game_description.capacity is not None else 0.0
        self.rescue_threshold = self.capacity / 2.0 if self.capacity > 0 else 0.0
        self.coop_threshold = self.capacity / 2.0 if self.capacity > 0 else 0.0
        self.last_action: Action | None = None

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        S = float(current_stock) if current_stock is not None else 0.0
        if round_number == 0:
            self.last_action = Action.C
            return Action.C
        if history.opponent_cooperators is None or len(history.opponent_cooperators) == 0:
            opp_coop_last = self.n_players - 1
        else:
            opp_coop_last = int(history.opponent_cooperators[-1])
        is_final_round = round_number >= self.n_rounds - 1
        if S <= 0.0:
            self.last_action = Action.C
            return Action.C
        if is_final_round:
            if S >= self.rescue_threshold or opp_coop_last >= (self.n_players - 1) / 2.0:
                self.last_action = Action.C
                return Action.C
            self.last_action = Action.C
            return Action.C
        if S >= self.coop_threshold:
            self.last_action = Action.C
            return Action.C
        if opp_coop_last >= (self.n_players - 1) / 2.0:
            self.last_action = Action.C
            return Action.C
        if self.last_action == Action.D:
            action = Action.C
        else:
            action = Action.D if S < self.rescue_threshold else Action.C
        self.last_action = action
        return action

class Strategy_ALTRUISTIC_71(BaseStrategy):
    """
    Cooperative default strategy with temporary defensive defection in collapse risk.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(0, self.n_players - 1)
        self.half_opponents = self.n_opponents / 2.0
        self.last_action = Action.C
        self.last_stock = None
        self.defect_cooldown = 0
        self.collapse_streak = 0
        self.overuse_streak = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number
        S = float(current_stock)
        cap = self.capacity if self.capacity > 0 else 1.0
        high_zone = 0.7 * cap
        low_zone = 0.35 * cap
        danger_zone = 0.2 * cap
        recovery_threshold = 0.15 * cap
        prev_opp_coop = int(history.opponent_cooperators[-1]) if t > 0 else self.n_opponents
        prev_my_action = bool(history.my_actions[-1]) if t > 0 else True
        if self.last_stock is not None:
            if S < self.last_stock - 1e-12:
                self.collapse_streak += 1
            else:
                self.collapse_streak = 0
            if S < low_zone:
                self.overuse_streak += 1
            else:
                self.overuse_streak = 0
        if t == 0:
            action = Action.C
            self.last_action = action
            self.last_stock = S
            return action
        rounds_left = self.n_rounds - t
        in_final_two = rounds_left <= 2
        in_last_round = rounds_left <= 1
        coop_prev = prev_opp_coop
        coop_ratio_prev = coop_prev / self.n_opponents if self.n_opponents > 0 else 1.0
        if S >= high_zone:
            action = Action.C
        elif S >= low_zone:
            if coop_prev >= self.half_opponents:
                action = Action.C
            else:
                action = Action.C if random.random() < 0.75 else Action.D
        elif coop_prev >= self.half_opponents:
            action = Action.C
        else:
            action = Action.D
        if prev_my_action is False and self.last_stock is not None:
            if S - self.last_stock >= recovery_threshold:
                action = Action.C
                self.defect_cooldown = 0
        if self.collapse_streak >= 2 and coop_prev < self.half_opponents:
            action = Action.D
            self.defect_cooldown = 1
        if self.defect_cooldown > 0:
            if action == Action.D:
                action = Action.D
            else:
                action = Action.C
            self.defect_cooldown -= 1
        if S < low_zone and coop_prev < self.half_opponents:
            if self.defect_cooldown == 0:
                action = Action.D
                self.defect_cooldown = 2
        if in_final_two:
            if S > danger_zone:
                action = Action.C
            elif S >= low_zone and coop_prev >= self.half_opponents:
                action = Action.C
            elif not in_last_round:
                if action == Action.D and S > danger_zone:
                    action = Action.C
            elif S > danger_zone and self.overuse_streak < 2:
                action = Action.C
        if action not in (Action.C, Action.D):
            action = Action.C
        self.last_action = action
        self.last_stock = S
        return action

class Strategy_ALTRUISTIC_72(BaseStrategy):
    """
    Unconditional cooperation strategy for the common pool resource game.
    Always plays C in every round, regardless of history or current stock.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        return Action.C

class Strategy_ALTRUISTIC_73(BaseStrategy):
    """
    Stock-preserving conditional cooperation strategy.

    Default to cooperation, but evaluate whether cooperating is likely to keep the
    common stock within a sustainable band using the last observed opponent mix.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self._n_opponents = max(self.n - 1, 0)
        self._half_capacity = 0.5 * self.capacity
        self._low_capacity = 0.2 * self.capacity
        self._high_capacity = 0.8 * self.capacity
        self._min_capacity_threshold = max(self._half_capacity, 0.4 * self.capacity)

    def _project_next_stock(self, current_stock: float, my_action: Action, coop_opponents: int) -> float:
        s = float(current_stock)
        if s <= 0.0 or self.n <= 0 or self.capacity <= 0.0:
            return 0.0
        coop_opponents = int(coop_opponents)
        if coop_opponents < 0:
            coop_opponents = 0
        elif coop_opponents > self._n_opponents:
            coop_opponents = self._n_opponents
        if my_action == Action.C:
            total_consumption = s / (2.0 * self.n) + coop_opponents * (s / (2.0 * self.n)) + (self._n_opponents - coop_opponents) * (s / self.n)
        else:
            total_consumption = s / self.n + coop_opponents * (s / (2.0 * self.n)) + (self._n_opponents - coop_opponents) * (s / self.n)
        remaining = s - total_consumption
        if remaining < 0.0:
            remaining = 0.0
        if remaining > self.capacity:
            remaining = self.capacity
        growth = 2.0 * remaining * (1.0 - remaining / self.capacity) if self.capacity > 0.0 else 0.0
        next_stock = remaining + growth
        if next_stock > self.capacity:
            next_stock = self.capacity
        elif next_stock < 0.0:
            next_stock = 0.0
        return next_stock

    def _threshold(self, current_stock: float) -> float:
        s = float(current_stock)
        dynamic = 1.2 * s * (self._n_opponents / self.n) if self.n > 0 else 0.0
        return max(self._half_capacity, 0.4 * self.capacity, dynamic)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = int(history.round_number)
        s = float(current_stock)
        if s <= 0.0:
            return Action.D if t == self.r - 1 else Action.C
        if t == 0:
            return Action.C
        if t >= self.r - 1:
            return Action.C
        if s >= self._high_capacity:
            return Action.C
        last_coop = 0
        if len(history.opponent_cooperators) > 0:
            last_coop = int(history.opponent_cooperators[-1])
        if self._n_opponents > 0:
            if last_coop < 0:
                last_coop = 0
            elif last_coop > self._n_opponents:
                last_coop = self._n_opponents
        else:
            last_coop = 0
        if s <= self._low_capacity:
            next_c = self._project_next_stock(s, Action.C, last_coop)
            next_d = self._project_next_stock(s, Action.D, last_coop)
            if next_c >= next_d or next_c >= self._threshold(s):
                return Action.C
            return Action.D
        threshold = self._threshold(s)
        projected_c = self._project_next_stock(s, Action.C, last_coop)
        if projected_c >= threshold:
            return Action.C
        projected_d = self._project_next_stock(s, Action.D, last_coop)
        if projected_d > projected_c and projected_d >= self._low_capacity:
            return Action.D
        return Action.C

class Strategy_ALTRUISTIC_74(BaseStrategy):
    """
    Cautious cooperative strategy for the Common Pool Resource Game.

    Core idea:
    - Start by cooperating.
    - Keep cooperating through normal fluctuations.
    - Defect only when the stock is severely depleted and cooperation is unlikely
      to preserve recovery.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(self.n_players - 1, 1)
        self.majority_threshold = int(math.ceil(self.n_opponents / 2))
        self.capacity_third = self.capacity / 3.0
        self.capacity_sixth = self.capacity / 6.0
        self.capacity_half = self.capacity / 2.0

    def _safe_last(self, arr, default=None):
        try:
            if len(arr) > 0:
                return arr[-1]
        except Exception:
            pass
        return default

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        S = float(current_stock)
        if round_number == 0:
            return Action.C
        last_opp_coop = self._safe_last(history.opponent_cooperators, None)
        prev_opp_coop = None
        if round_number >= 2:
            prev_opp_coop = self._safe_last(history.opponent_cooperators[:-1], None)
        if last_opp_coop is None:
            return Action.C
        if round_number >= max(self.n_rounds - 2, 0):
            if S < self.capacity_sixth:
                return Action.D
            return Action.C
        if S < self.capacity_sixth:
            return Action.D
        if S > self.capacity_third:
            return Action.C
        if last_opp_coop >= self.majority_threshold:
            return Action.C
        if prev_opp_coop is not None and prev_opp_coop < self.majority_threshold:
            if S <= self.capacity_third:
                return Action.D
        try:
            if round_number >= 2:
                prev_stock = float(history.my_payoffs[-2])
                _ = prev_stock
        except Exception:
            pass
        if S >= self.capacity_sixth:
            return Action.C
        return Action.D

class Strategy_ALTRUISTIC_75(BaseStrategy):
    """
    Always cooperate in every round, regardless of stock level or opponent behavior.
    Tracks opponent cooperation only for diagnostic bookkeeping.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self._opponent_coop_count_history = []
        self._opponent_coop_running_sum = 0.0
        self._opponent_coop_running_avg = 0.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = getattr(history, 'round_number', 0)
        if round_number > 0:
            last_count = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
            self._opponent_coop_count_history.append(last_count)
            self._opponent_coop_running_sum += last_count
            self._opponent_coop_running_avg = self._opponent_coop_running_sum / len(self._opponent_coop_count_history) if self._opponent_coop_count_history else 0.0
        return Action.C

class Strategy_ALTRUISTIC_76(BaseStrategy):
    """
    Cooperative-by-default common pool strategy that only defects as a temporary
    conservation brake when the stock is depleted or repeatedly under-supported.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.bad_streak = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_players = self.game_description.n_players
        n_rounds = self.game_description.n_rounds
        capacity = float(self.game_description.capacity)
        round_number = history.round_number
        current_round = round_number + 1
        if round_number == 0:
            self.bad_streak = 0
            return Action.C
        k_t = int(history.opponent_cooperators[-1]) if round_number > 0 else 0
        T_t = capacity / 2.0
        R_t = 0.8 * capacity
        q_t = (n_players - 1) / 2.0
        severe_depletion = current_stock <= T_t
        persistent_exploitation = current_stock < R_t and k_t < q_t
        final_round_conservation = current_round == n_rounds and current_stock < capacity
        if persistent_exploitation:
            self.bad_streak += 1
        else:
            self.bad_streak = 0
        if severe_depletion:
            return Action.D
        if final_round_conservation:
            return Action.D
        if self.bad_streak >= 2:
            return Action.D
        return Action.C

class Strategy_ALTRUISTIC_77(BaseStrategy):
    """
    Always cooperate, regardless of history, opponents' behavior, or stock level.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = getattr(game_description, 'n_players', 0)
        self.n_rounds = getattr(game_description, 'n_rounds', 0)
        self.capacity = getattr(game_description, 'capacity', 0)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        _ = history.round_number
        _ = current_stock
        return Action.C

class Strategy_ALTRUISTIC_78(BaseStrategy):
    """
    Cooperative-by-default resource conservation strategy.

    - Opens with cooperation.
    - Cooperates whenever opponents show at least moderate cooperation,
      the stock is healthy, or it is the final round.
    - Uses a short defensive defection only after consecutive low-cooperation
      rounds when the stock is strained or critical.
    - Returns to cooperation immediately when conditions improve.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(self.n_players - 1, 1)
        self._last_stock: float | None = None

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        if round_number == 0:
            self._last_stock = float(current_stock)
            return Action.C
        if round_number >= self.n_rounds - 1:
            self._last_stock = float(current_stock)
            return Action.C
        prev_opponent_cooperators = int(history.opponent_cooperators[-1])
        q = prev_opponent_cooperators / self.n_opponents if self.n_opponents > 0 else 0.0
        prev_low_cooperation = False
        if round_number >= 2:
            prev_prev_opponent_cooperators = int(history.opponent_cooperators[-2])
            prev_q = prev_prev_opponent_cooperators / self.n_opponents if self.n_opponents > 0 else 0.0
            prev_low_cooperation = prev_q < 1.0 / 3.0
        critical_stock = current_stock <= self.capacity / 4.0
        strained_stock = current_stock <= self.capacity / 2.0
        stock_increased = self._last_stock is not None and current_stock > self._last_stock
        previous_action_was_defect = bool(history.my_actions[-1] == 0)
        if stock_increased:
            self._last_stock = float(current_stock)
            return Action.C
        if previous_action_was_defect and q >= 1.0 / 3.0:
            self._last_stock = float(current_stock)
            return Action.C
        if q >= 1.0 / 3.0:
            self._last_stock = float(current_stock)
            return Action.C
        if current_stock > self.capacity / 2.0:
            self._last_stock = float(current_stock)
            return Action.C
        if q < 1.0 / 3.0 and strained_stock and (prev_low_cooperation or critical_stock):
            self._last_stock = float(current_stock)
            return Action.D
        self._last_stock = float(current_stock)
        return Action.C

class Strategy_ALTRUISTIC_79(BaseStrategy):
    """
    Cooperative default strategy with one-round memory:
    - Cooperate on the first round.
    - Cooperate whenever the stock is healthy and opponents were at least moderately cooperative.
    - Defect only when the stock is dangerously low, or in the final round if the stock is already depleted.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.opponents = max(1, self.n_players - 1)
        self.half_capacity = self.capacity / 2.0
        self.quarter_capacity = self.capacity / 4.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number
        if t == 0:
            return Action.C
        if current_stock < self.quarter_capacity:
            return Action.D
        if t >= self.n_rounds - 1:
            return Action.C if current_stock >= self.quarter_capacity else Action.D
        last_opponents = 0
        if len(history.opponent_cooperators) > 0:
            last_opponents = int(history.opponent_cooperators[-1])
        q_t = last_opponents / self.opponents if self.opponents > 0 else 0.0
        if current_stock >= self.half_capacity and q_t >= 0.5:
            return Action.C
        if current_stock >= self.half_capacity:
            return Action.C
        if q_t < 0.5:
            return Action.D
        return Action.C

class Strategy_ALTRUISTIC_80(BaseStrategy):
    """
    Cautious cooperater that only defects briefly under sustained low stock and
    weak observed cooperation, with a stronger crisis override at very low stock.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        n = max(self.n, 2)
        capacity = self.capacity
        current_round = round_number + 1
        remaining_after_current = self.r - current_round
        weak_coop_threshold = (n - 1) / 2.0
        low_stock_threshold = capacity / 2.0 if capacity > 0 else 0.0
        crisis_stock_threshold = capacity / 4.0 if capacity > 0 else 0.0
        if round_number == 0:
            return Action.C
        if current_round >= self.r:
            return Action.C
        prev_coop_count = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) >= 1 else n - 1
        prev_prev_coop_count = int(history.opponent_cooperators[-2]) if len(history.opponent_cooperators) >= 2 else prev_coop_count
        weak_prev = prev_coop_count < weak_coop_threshold
        weak_prev_prev = prev_prev_coop_count < weak_coop_threshold
        low_stock = float(current_stock) <= low_stock_threshold
        crisis_stock = float(current_stock) <= crisis_stock_threshold
        if crisis_stock:
            if weak_prev and weak_prev_prev:
                return Action.D
            return Action.C
        if current_round == self.r - 1:
            if remaining_after_current <= 1:
                return Action.C
            if low_stock and weak_prev:
                return Action.D
            return Action.C
        if low_stock and weak_prev:
            return Action.D
        return Action.C

class Strategy_ALTRUISTIC_81(BaseStrategy):
    """
    Always cooperate in every round, ignoring history and current stock.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        return Action.C

class Strategy_ALTRUISTIC_82(BaseStrategy):
    """
    Cautious commons-preservation strategy:
    cooperate by default, repair after low cooperation, and only use a short
    defensive defection in fragile low-stock conditions.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.caution_threshold = self.capacity / 3.0
        self.collapse_threshold = self.capacity / 8.0
        self.last_stock = None
        self.low_coop_streak = 0
        self.stock_nondec_streak = 0
        self.stock_dec_streak = 0
        self.defensive_d_used_in_low_state = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        if round_number == 0:
            self.last_stock = float(current_stock)
            self.low_coop_streak = 0
            self.stock_nondec_streak = 0
            self.stock_dec_streak = 0
            self.defensive_d_used_in_low_state = False
            return Action.C
        rounds_left_including_current = self.n_rounds - round_number
        if rounds_left_including_current <= 2:
            self._update_stock_memory(current_stock)
            self.low_coop_streak = 0 if self._half_or_more_cooperated(history) else self.low_coop_streak + 1
            return Action.C
        opp_coop = int(history.opponent_cooperators[-1]) if round_number > 0 else 0
        n_opponents = max(self.n_players - 1, 0)
        half_opponents = (n_opponents + 1) // 2
        half_or_more = opp_coop >= half_opponents
        if half_or_more:
            self.low_coop_streak = 0
        else:
            self.low_coop_streak += 1
        self._update_stock_memory(current_stock)
        S = float(current_stock)
        T = self.caution_threshold
        L = self.collapse_threshold
        if S >= T:
            self.defensive_d_used_in_low_state = False
            return Action.C
        if L <= S < T:
            self.defensive_d_used_in_low_state = False
            if half_or_more:
                return Action.C
            if self.low_coop_streak <= 1:
                return Action.C
            if self.stock_dec_streak >= 2 and (not half_or_more):
                self.defensive_d_used_in_low_state = True
                return Action.D
            return Action.C
        if S < L:
            if S <= 0.0:
                self.defensive_d_used_in_low_state = False
                return Action.C
            if S < self.last_stock if self.last_stock is not None else False:
                if self.low_coop_streak >= 2 and (not self.defensive_d_used_in_low_state):
                    self.defensive_d_used_in_low_state = True
                    return Action.D
            if self.defensive_d_used_in_low_state:
                if self.last_stock is not None and S >= self.last_stock:
                    self.defensive_d_used_in_low_state = False
                return Action.C
            return Action.C
        return Action.C

    def _update_stock_memory(self, current_stock: float) -> None:
        current_stock = float(current_stock)
        if self.last_stock is None:
            self.last_stock = current_stock
            self.stock_nondec_streak = 0
            self.stock_dec_streak = 0
            return
        if current_stock >= self.last_stock:
            self.stock_nondec_streak += 1
            self.stock_dec_streak = 0
        else:
            self.stock_dec_streak += 1
            self.stock_nondec_streak = 0
        self.last_stock = current_stock

    def _half_or_more_cooperated(self, history: PlayerHistory) -> bool:
        round_number = history.round_number
        if round_number <= 0:
            return True
        n_opponents = max(self.n_players - 1, 0)
        opp_coop = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) else 0
        half_opponents = (n_opponents + 1) // 2
        return opp_coop >= half_opponents

class Strategy_ALTRUISTIC_83(BaseStrategy):
    """
    Common-pool strategy:
    - Start cooperatively.
    - End cooperatively.
    - Cooperate when stock is low or opponents are broadly cooperative.
    - Defect once after broadly defective behavior, then reassess.
    - Use inferred previous stock from own last payoff/action when available.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(self.n_players - 1, 0)
        self._eps = 1e-09

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        if round_number == 0:
            return Action.C
        if round_number >= self.n_rounds - 1:
            return Action.C
        S = float(current_stock)
        cap = self.capacity
        eps = self._eps
        if S >= cap - eps:
            return Action.C
        prev_opp_coops = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        if self.n_opponents > 0:
            rho = prev_opp_coops / self.n_opponents
        else:
            rho = 1.0
        prev_stock = None
        if len(history.my_actions) > 0 and len(history.my_payoffs) > 0:
            last_action = bool(history.my_actions[-1])
            last_payoff = float(history.my_payoffs[-1])
            if last_action:
                prev_stock = last_payoff * (2.0 * self.n_players)
            else:
                prev_stock = last_payoff * float(self.n_players)
        if S <= cap / 3.0:
            return Action.C
        if rho >= 2.0 / 3.0:
            return Action.C
        safe = cap / 2.0
        if rho >= 0.5:
            if S >= safe:
                return Action.C
            else:
                if prev_stock is not None:
                    if S > prev_stock + eps:
                        return Action.C
                    return Action.D
                return Action.C
        return Action.D

class Strategy_ALTRUISTIC_84(BaseStrategy):
    """
    Defensive cooperative strategy for the Common Pool Resource Game.

    Defaults to cooperation, tracks opponent cooperation with exponential smoothing,
    and uses short defensive defections only when stock is collapsing and observed
    cooperation is low. Prioritises endgame cooperation and fast recovery after
    depleted-stock periods.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.p_hat = 1.0
        self.trust = 1.0
        self.low_count = 0
        self._last_seen_round = 0
        self._defect_one_round = False
        self._recovery_lock = 0
        self._wait_one_round = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        S = float(current_stock)
        if round_number > self._last_seen_round and round_number > 0:
            idx = round_number - 1
            n_opponents = max(self.n_players - 1, 1)
            k_t = int(history.opponent_cooperators[idx])
            observed_rate = k_t / n_opponents
            self.p_hat = 0.7 * self.p_hat + 0.3 * observed_rate
            self.trust = 0.7 * self.trust + 0.3 * observed_rate
            if S >= 0.8 * self.capacity:
                self.low_count = 0
            elif S <= 0.4 * self.capacity:
                self.low_count += 1
            if k_t >= (self.n_players - 1 + 1) // 2:
                self._wait_one_round = False
            else:
                self._wait_one_round = True
            self._last_seen_round = round_number
        if self.low_count >= 2 and S > 0:
            self._recovery_lock = max(self._recovery_lock, 2)
        rounds_left = self.n_rounds - round_number
        if round_number == 0:
            return Action.C
        if S <= 0:
            return Action.C
        if self._recovery_lock > 0:
            self._recovery_lock -= 1
            self._defect_one_round = False
            return Action.C
        if rounds_left <= 2:
            if S > 0 and (not (S <= 0.2 * self.capacity and self.p_hat < 0.25)):
                self._defect_one_round = False
                return Action.C
        if self._defect_one_round and S > 0.25 * self.capacity:
            self._defect_one_round = False
        if S >= 0.75 * self.capacity:
            self._defect_one_round = False
            return Action.C
        if S <= 0.25 * self.capacity:
            if self.p_hat >= 0.5:
                self._defect_one_round = False
                return Action.C
            if not self._defect_one_round:
                self._defect_one_round = True
                return Action.D
            self._defect_one_round = False
            return Action.C
        if 0.25 * self.capacity < S < 0.75 * self.capacity:
            if not self._wait_one_round and self.p_hat >= 0.35:
                self._defect_one_round = False
                return Action.C
            if self._wait_one_round:
                self._wait_one_round = False
                self._defect_one_round = False
                return Action.C
            if self.p_hat >= 0.35:
                self._defect_one_round = False
                return Action.C
            self._defect_one_round = True
            return Action.D
        self._defect_one_round = False
        return Action.C

class Strategy_ALTRUISTIC_85(BaseStrategy):
    """
    Conservative common-pool strategy:
    - Cooperates by default.
    - Switches to restraint when sustained low cooperation is observed.
    - Defects only as a defensive measure when stock is already below the warning threshold.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(self.n_players - 1, 1)
        self.s_safe = self.capacity / 2.0
        self.s_warn = self.capacity / 3.0
        self.lookback = max(2, self.n_rounds // 4)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        if round_number == 0:
            return Action.C
        recent_len = min(self.lookback, round_number)
        recent_counts = history.opponent_cooperators[-recent_len:] if recent_len > 0 else np.array([], dtype=int)
        if recent_len > 0:
            recent_avg_rate = float(np.mean(recent_counts)) / self.n_opponents
        else:
            recent_avg_rate = 1.0
        low_cooperation_mode = recent_avg_rate < 1.0 / 3.0
        last_count = int(history.opponent_cooperators[-1]) if round_number > 0 else self.n_opponents
        last_rate = last_count / self.n_opponents
        rebound = last_rate >= 2.0 / 3.0
        if rebound:
            return Action.C
        if current_stock <= self.s_warn:
            if current_stock <= 0:
                return Action.C
            if low_cooperation_mode:
                return Action.D
            return Action.C
        if low_cooperation_mode:
            return Action.C
        if last_rate >= 0.5:
            return Action.C
        n = self.n_players
        S = float(current_stock)
        k_t = max(0, min(last_count, self.n_opponents))
        defectors = self.n_opponents - k_t
        own_consumption = S / (2.0 * n)
        coop_opp_consumption = k_t * (S / (2.0 * n))
        defect_opp_consumption = defectors * (S / n)
        S_after = S - own_consumption - coop_opp_consumption - defect_opp_consumption
        if S_after < 0.0:
            S_after = 0.0
        growth = 2.0 * S_after * (1.0 - S_after / self.capacity) if self.capacity > 0 else 0.0
        S_next_c = min(S_after + growth, self.capacity)
        if S_next_c >= S:
            return Action.C
        if S_next_c < self.s_warn:
            return Action.D
        return Action.C

class Strategy_ALTRUISTIC_86(BaseStrategy):
    """
    Default-cooperate common pool strategy with conservation-triggered defection.
    Defects only after repeated low cooperation, when stock is still comfortably above midpoint,
    and reverts immediately to cooperation once cooperation recovers.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.c_prev = None
        self.low_streak = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_players = int(getattr(self.game_description, 'n_players', 0) or 0)
        n_rounds = int(getattr(self.game_description, 'n_rounds', 0) or 0)
        capacity = float(getattr(self.game_description, 'capacity', 0.0) or 0.0)
        n_opponents = max(0, n_players - 1)
        low_threshold = math.floor(n_opponents / 3)
        half_opponents = math.ceil(n_opponents / 2) if n_opponents > 0 else 0
        round_number = 0
        try:
            round_number = int(history.round_number)
        except Exception:
            return Action.C
        if round_number == 0:
            self.c_prev = None
            self.low_streak = 0
            return Action.C
        if n_rounds > 0 and round_number >= max(0, n_rounds - 2):
            try:
                self.c_prev = int(history.opponent_cooperators[-1])
            except Exception:
                self.c_prev = None
            self.low_streak = 0
            return Action.C
        try:
            c_prev = int(history.opponent_cooperators[-1])
        except Exception:
            self.c_prev = None
            return Action.C
        self.c_prev = c_prev
        if current_stock is None or not isinstance(current_stock, (int, float)):
            return Action.C
        if current_stock <= 1e-12 or (capacity > 0.0 and current_stock <= capacity * 1e-09):
            self.low_streak = 0
            return Action.C
        if c_prev <= low_threshold:
            self.low_streak += 1
        else:
            self.low_streak = 0
        if c_prev >= half_opponents:
            self.low_streak = 0
            return Action.C
        if current_stock > (capacity / 2.0 if capacity > 0.0 else float('inf')) and self.low_streak >= 2 and (c_prev <= low_threshold):
            return Action.D
        return Action.C

class Strategy_ALTRUISTIC_87(BaseStrategy):
    """
    Always cooperate strategy for the Common Pool Resource Game.
    This strategy ignores history and current stock and always returns Action.C.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        return Action.C

class Strategy_ALTRUISTIC_88(BaseStrategy):
    """
    Generous cooperation with stock-aware restraint:
    - Cooperate by default.
    - Defect only as a temporary defensive response when stock is low and recent cooperation is weak.
    - Return to cooperation quickly once the group cooperates moderately or stock recovers.
    - Always cooperate in the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(0, self.n_players - 1)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        if round_number == 0:
            return Action.C
        if round_number >= self.n_rounds - 1:
            return Action.C
        half_capacity = self.capacity / 2.0
        quarter_capacity = self.capacity / 4.0
        prev_cooperators = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        k = self.n_opponents
        rho = 1.0 if k == 0 else prev_cooperators / k
        if self.capacity <= 0:
            threshold = 0
        else:
            threshold = int(math.ceil(k * max(0.0, 2.0 - 2.0 * float(current_stock) / self.capacity)))
        if threshold < 0:
            threshold = 0
        elif threshold > k:
            threshold = k
        if prev_cooperators == k:
            return Action.C
        if current_stock >= half_capacity:
            return Action.C
        if current_stock <= quarter_capacity:
            return Action.D
        if rho >= 0.5:
            return Action.C
        if prev_cooperators >= threshold:
            return Action.C
        if current_stock < half_capacity and rho < 0.5 and (prev_cooperators < threshold):
            return Action.D
        return Action.C

class Strategy_ALTRUISTIC_89(BaseStrategy):
    """
    Conservative restorative strategy with stock-protection override.

    - Cooperates in the opening round.
    - Defects only under stock stress or when the standard reciprocity threshold is not met.
    - Gives priority to cooperation in ambiguous cases.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(getattr(game_description, 'n_players', 0) or 0)
        self.n_rounds = int(getattr(game_description, 'n_rounds', 0) or 0)
        self.capacity = float(getattr(game_description, 'capacity', 0.0) or 0.0)
        self.n_opponents = max(0, self.n_players - 1)
        self.half_opponents_threshold = math.ceil(self.n_opponents / 2) if self.n_opponents > 0 else 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = int(getattr(history, 'round_number', 0) or 0)
        if t == 0:
            return Action.C
        cap = self.capacity
        stock = float(current_stock)
        if cap > 0.0 and stock < cap / 8.0:
            return Action.D
        if t >= self.n_rounds - 1:
            return Action.C
        last_opponents = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        prev_two_low = False
        if len(history.opponent_cooperators) >= 2 and self.n_opponents > 0:
            prev_two_low = int(history.opponent_cooperators[-1]) < self.half_opponents_threshold and int(history.opponent_cooperators[-2]) < self.half_opponents_threshold
        if prev_two_low:
            if cap > 0.0 and stock < cap / 4.0:
                return Action.D
            return Action.C
        if cap > 0.0 and stock >= cap / 4.0 and (last_opponents >= self.half_opponents_threshold):
            return Action.C
        return Action.C

class Strategy_ALTRUISTIC_90(BaseStrategy):
    """
    Unconditional cooperator for the common pool resource game.
    Always plays C regardless of history, stock, or round number.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        return Action.C

class Strategy_ALTRUISTIC_91(BaseStrategy):
    """
    Mostly cooperative common-pool strategy with defensive defections when
    the pool is depleted and recent group cooperation is persistently weak.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(self.n_players - 1, 1)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        rounds_remaining = self.n_rounds - round_number
        if round_number == 0:
            return Action.C
        last_opp_coop = int(history.opponent_cooperators[-1]) if round_number > 0 else 0
        last_coop_rate = last_opp_coop / self.n_opponents
        low_coop_streak = 0
        for idx in range(round_number - 1, -1, -1):
            coop_rate = int(history.opponent_cooperators[idx]) / self.n_opponents
            if coop_rate < 0.5:
                low_coop_streak += 1
            else:
                break
        cap_5 = self.capacity / 5.0
        cap_4 = self.capacity / 4.0
        cap_3 = self.capacity / 3.0
        if rounds_remaining == 1:
            return Action.D if current_stock < cap_5 and last_coop_rate < 0.5 else Action.C
        if rounds_remaining == 2:
            if current_stock >= cap_5:
                return Action.C
            return Action.C if last_coop_rate >= 0.5 else Action.D
        if bool(history.my_actions[-1]) is False:
            if last_coop_rate >= 2.0 / 3.0 or current_stock >= cap_3:
                return Action.C
        if last_coop_rate >= 0.75:
            return Action.C
        if last_coop_rate >= 0.5 and current_stock >= cap_5:
            return Action.C
        if current_stock >= cap_4:
            return Action.C
        if current_stock < cap_4 and last_coop_rate >= 2.0 / 3.0:
            return Action.C
        if low_coop_streak >= 2 and current_stock < cap_3:
            return Action.D
        return Action.C

class Strategy_ALTRUISTIC_92(BaseStrategy):
    """
    Conservative, recovery-biased common-pool strategy with adaptive cooperation memory.
    Defaults to cooperation, defects only when stock is stressed and recent opponent
    cooperation is persistently low, while avoiding long retaliation after shocks.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.p = 1.0
        self.last_observed_coop_rate = 1.0
        self.prev_observed_coop_rate = 1.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_players = int(self.game_description.n_players)
        n_rounds = int(self.game_description.n_rounds)
        capacity = float(self.game_description.capacity)
        n_opponents = max(n_players - 1, 1)
        round_number = int(history.round_number)
        if round_number == 0:
            self.p = 1.0
            self.last_observed_coop_rate = 1.0
            self.prev_observed_coop_rate = 1.0
            return Action.C
        p_est = 1.0
        coop_rates = []
        for k in history.opponent_cooperators:
            rate = float(k) / float(n_opponents)
            coop_rates.append(rate)
            p_est = 0.7 * p_est + 0.3 * rate
        self.p = p_est
        last_rate = coop_rates[-1] if coop_rates else 1.0
        prev_rate = coop_rates[-2] if len(coop_rates) >= 2 else last_rate
        self.last_observed_coop_rate = last_rate
        self.prev_observed_coop_rate = prev_rate
        stock = float(current_stock)
        cap = capacity
        low_stock = stock < 0.75 * cap
        very_low_stock = stock <= 0.2 * cap
        stressed_stock = stock < 0.5 * cap
        final_round = round_number >= n_rounds - 1
        final_two_rounds = round_number >= n_rounds - 2
        if final_round:
            if stock < 0.25 * cap and last_rate < 0.5:
                return Action.D
            return Action.C
        if final_two_rounds and last_rate >= 0.8:
            return Action.C
        if last_rate >= 0.8:
            if very_low_stock:
                return Action.C if last_rate >= 0.5 else Action.D
            return Action.C
        if len(coop_rates) >= 2 and last_rate <= prev_rate - 0.4:
            if stressed_stock:
                return Action.D
            return Action.C
        if not low_stock:
            return Action.C
        if self.p >= 0.6:
            return Action.C
        return Action.D

class Strategy_ALTRUISTIC_93(BaseStrategy):
    """
    Cooperative default strategy with short, state-based defensive defection
    when the shared stock shows signs of destabilization.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self._prev_stock = None
        self._punitive_carry = 0
        self._last_action = Action.C

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        emergency_threshold = 2 * n
        round_number = history.round_number
        n_rounds = self.game_description.n_rounds

        def coop_rate_from_index(idx: int) -> float:
            if idx < 0 or idx >= len(history.opponent_cooperators):
                return 1.0
            opponents = max(n - 1, 1)
            return float(history.opponent_cooperators[idx]) / float(opponents)
        c_prev = coop_rate_from_index(round_number - 1)
        c_prev2 = coop_rate_from_index(round_number - 2)
        prev_stock = self._prev_stock
        stock_dropped = prev_stock is not None and current_stock < prev_stock
        if round_number == n_rounds - 1:
            if current_stock <= emergency_threshold and c_prev < 0.5:
                action = Action.D
            else:
                action = Action.C
            self._prev_stock = current_stock
            self._last_action = action
            if action == Action.C:
                self._punitive_carry = 0
            return action
        if round_number <= 1:
            action = Action.C
            self._prev_stock = current_stock
            self._last_action = action
            self._punitive_carry = 0
            return action
        recovered = prev_stock is not None and current_stock > prev_stock or c_prev >= 2.0 / 3.0
        if self._punitive_carry > 0:
            if recovered:
                action = Action.C
                self._punitive_carry = 0
            else:
                action = Action.D
                self._punitive_carry = 0
            self._prev_stock = current_stock
            self._last_action = action
            return action
        emergency = False
        if current_stock <= emergency_threshold:
            emergency = True
        if c_prev == 0:
            emergency = True
        if c_prev < 0.5 and c_prev2 < 0.5:
            emergency = True
        if stock_dropped and c_prev <= 1.0 / 3.0:
            emergency = True
        if emergency:
            action = Action.D
            self._punitive_carry = 1
        elif c_prev >= 2.0 / 3.0:
            action = Action.C
        elif current_stock > emergency_threshold and c_prev >= 0.5:
            action = Action.C
        else:
            action = Action.C
        self._prev_stock = current_stock
        self._last_action = action
        return action

class Strategy_ALTRUISTIC_94(BaseStrategy):
    """
    Conservative common-pool strategy:
    cooperate by default, defect only as a brief protective response when
    stock is low, cooperation collapses, or depletion is accelerating.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(self.n_players - 1, 0)
        self.critical_stock = 2.0 * self.n_players
        self.healthy_stock = 0.7 * self.capacity
        self.warning_stock = 0.4 * self.capacity

    def _reconstruct_round_stock(self, action_bool: bool, payoff: float) -> float | None:
        """
        Reconstruct the stock level for a round from my action and payoff.
        Returns None if reconstruction is not reliable.
        """
        if payoff is None:
            return None
        if payoff < 0:
            return None
        denom = 2.0 * self.n_players if action_bool else float(self.n_players)
        if denom <= 0:
            return None
        return payoff * denom

    def _safe_last_stock(self, history: PlayerHistory) -> float | None:
        if history.round_number <= 0:
            return None
        try:
            return self._reconstruct_round_stock(bool(history.my_actions[-1]), float(history.my_payoffs[-1]))
        except Exception:
            return None

    def _safe_prev_stock(self, history: PlayerHistory) -> float | None:
        if history.round_number <= 1:
            return None
        try:
            return self._reconstruct_round_stock(bool(history.my_actions[-2]), float(history.my_payoffs[-2]))
        except Exception:
            return None

    def _opponent_coop_ratio(self, coop_count: int) -> float:
        if self.n_opponents <= 0:
            return 1.0
        return float(coop_count) / float(self.n_opponents)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        S = float(current_stock)
        if round_number == 0:
            return Action.C
        last_coop = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else self.n_opponents
        bottom_third = math.floor(self.n_opponents / 3) if self.n_opponents > 0 else 0
        one_third = self.n_opponents / 3.0 if self.n_opponents > 0 else 0.0
        last_stock = self._safe_last_stock(history)
        prev_stock = self._safe_prev_stock(history)
        decreasing_two_rounds = prev_stock is not None and last_stock is not None and (prev_stock > last_stock > S)
        severe_depletion = decreasing_two_rounds and S < self.warning_stock
        if round_number >= self.n_rounds - 1:
            if S <= self.critical_stock or severe_depletion or (last_coop <= bottom_third and S < self.warning_stock):
                return Action.D
            return Action.C
        if S > self.healthy_stock:
            return Action.C
        if S <= 1e-12:
            return Action.C
        if S <= self.critical_stock:
            if last_coop <= bottom_third:
                return Action.D
            return Action.C
        if S < self.warning_stock:
            if last_coop <= bottom_third or severe_depletion:
                return Action.D
            return Action.C
        if last_coop < one_third:
            return Action.D
        if last_coop <= bottom_third:
            return Action.D
        return Action.C

class Strategy_ALTRUISTIC_95(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Cooperate in round 1.
    - Use the previous round's opponent cooperation rate q and current stock S
      to switch between cooperation and defection.
    - Track consecutive low-cooperation rounds to defend the resource when
      exploitation persists.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)

    def _cooperation_rate(self, opponent_cooperators: int) -> float:
        n = self.n_players
        if n <= 2:
            return 1.0 if opponent_cooperators > 0 else 0.0
        denom = n - 1
        if denom <= 0:
            return 0.0
        return float(opponent_cooperators) / float(denom)

    def _low_coop_streak(self, history: PlayerHistory) -> int:
        streak = 0
        rounds = history.round_number
        if rounds <= 0:
            return 0
        for idx in range(rounds - 1, -1, -1):
            q = self._cooperation_rate(int(history.opponent_cooperators[idx]))
            if q < 0.4:
                streak += 1
            else:
                break
        return streak

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        n_rounds = self.n_rounds
        capacity = self.capacity
        S = float(current_stock)
        prev_opponents = int(history.opponent_cooperators[-1])
        q = self._cooperation_rate(prev_opponents)
        low_coop_streak = self._low_coop_streak(history)
        current_round_index = history.round_number + 1
        is_last_round = current_round_index >= n_rounds
        if is_last_round:
            if q < 0.2 and S <= 0.4 * capacity:
                return Action.D
            return Action.C
        if S >= 0.8 * capacity:
            return Action.C
        if q >= 0.6:
            return Action.C
        if q >= 0.4:
            if S > 0.35 * capacity or q >= 0.5:
                return Action.C
            return Action.D
        if q >= 0.2:
            if S >= 0.6 * capacity:
                return Action.C
            return Action.D
        if S <= 0.5 * capacity and low_coop_streak >= 2:
            return Action.D
        return Action.C

class Strategy_ALTRUISTIC_96(BaseStrategy):
    """
    Conservative common-pool strategy:
    - Cooperates by default
    - Enters temporary recovery mode after severe stock depletion
    - Defects only as a protective response to repeated low cooperation when the stock is not secure
    - Prefers cooperation in endgame unless exploitation is severe and stock is nearly exhausted
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = max(2, int(game_description.n_players))
        self.r = max(1, int(game_description.n_rounds))
        self.capacity = float(game_description.capacity)
        self.low_stock_threshold = self.capacity / 4.0
        self.safe_stock_threshold = max(self.capacity / 2.0, self.n / 2.0)
        self.endgame_rounds = int(math.ceil(self.r / 4.0))
        self.near_exhaustion_threshold = self.capacity / 10.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number + 1
        S_t = float(current_stock)
        if S_t <= 0.0:
            return Action.C
        if history.round_number == 0:
            return Action.C
        opp_count = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        n_opponents = max(1, self.n - 1)
        x_prev = opp_count / n_opponents
        if t > self.r - self.endgame_rounds:
            if S_t >= self.low_stock_threshold:
                return Action.C
            if S_t <= self.near_exhaustion_threshold and x_prev < 1.0 / 3.0:
                return Action.D
            return Action.C
        if S_t < self.low_stock_threshold:
            if S_t < self.safe_stock_threshold:
                return Action.C
        if x_prev >= 0.5 or S_t >= self.safe_stock_threshold:
            return Action.C
        return Action.D

class Strategy_ALTRUISTIC_97(BaseStrategy):
    """
    Unconditional cooperation strategy for the Common Pool Resource Game.
    Always chooses C, regardless of history, stock level, or opponent behavior.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        return Action.C

class Strategy_ALTRUISTIC_98(BaseStrategy):
    """
    Purely cooperative common-pool strategy.

    Always plays Cooperate (Action.C) in every round, while recording the
    observed number of cooperating opponents for internal monitoring only.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.observed_opponent_cooperations = []
        self.rounds_played = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number > 0:
            last_count = int(history.opponent_cooperators[-1])
            self.observed_opponent_cooperations.append(last_count)
            self.rounds_played = history.round_number
        return Action.C

class Strategy_ALTRUISTIC_99(BaseStrategy):
    """
    Generous cooperation-first strategy with temporary conservation defections
    when the pool is stressed and recent opponent behavior is sufficiently
    uncooperative.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(getattr(game_description, 'n_players', 0))
        self.n_rounds = int(getattr(game_description, 'n_rounds', 0))
        self.capacity = float(getattr(game_description, 'capacity', 0.0))
        self.n_opponents = max(self.n_players - 1, 0)
        self.majority_threshold = int(math.ceil(self.n_opponents / 2)) if self.n_opponents > 0 else 0
        self.half_capacity = self.capacity / 2.0
        self.quarter_capacity = self.capacity / 4.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = int(history.round_number) + 1
        S = float(current_stock)
        if t == 1:
            return Action.C
        if t >= self.n_rounds:
            return Action.C
        m = 0
        if history.round_number > 0 and len(history.opponent_cooperators) > 0:
            m = int(history.opponent_cooperators[-1])
        if S >= self.half_capacity:
            return Action.C
        if m >= self.majority_threshold:
            return Action.C
        if t >= self.n_rounds - 2:
            return Action.D if S < self.quarter_capacity else Action.C
        return Action.D

class Strategy_ALTRUISTIC_100(BaseStrategy):
    """
    Default-cooperate common pool strategy with brief defensive defection
    when the stock is low and recent cooperation is poor.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(self.n_players - 1, 1)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        if round_number == 0:
            return Action.C
        last_opponent_cooperators = int(history.opponent_cooperators[-1])
        q = last_opponent_cooperators / self.n_opponents if self.n_opponents > 0 else 0.0
        is_last_round = round_number >= self.n_rounds - 1
        last_action = Action.C
        if round_number > 0:
            last_action = Action.C if bool(history.my_actions[-1]) else Action.D
        stock = float(current_stock)
        cap = self.capacity
        if q >= 1.0:
            return Action.C
        if q >= 0.75 and stock >= 0.15 * cap:
            return Action.C
        if is_last_round:
            if stock < 0.1 * cap and q == 0.0:
                return Action.D
            return Action.C
        if stock <= 0.05 * cap:
            return Action.C if q > 0.0 else Action.D
        if last_action == Action.D and (stock >= 0.3 * cap or q >= 0.5):
            return Action.C
        if stock < 0.2 * cap and q < 0.5:
            return Action.D
        if stock >= 0.4 * cap and q >= 0.5:
            return Action.C
        return Action.C

class Strategy_ALTRUISTIC_101(BaseStrategy):
    """
    Conservative common-pool strategy:
    cooperate by default, defect only as a temporary stabilization move when
    stock is low, cooperation is weak, and the pool has been shrinking for
    multiple rounds.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(self.n_players - 1, 0)
        self.last_action = Action.C
        self.last_inferred_stock = float(self.capacity)
        self.last_stock_trend = 0

    def _infer_previous_stock(self, history: PlayerHistory) -> float | None:
        if history.round_number <= 0:
            return None
        idx = history.round_number - 1
        payoff = float(history.my_payoffs[idx])
        my_action = bool(history.my_actions[idx])
        factor = 2.0 * self.n_players if my_action else float(self.n_players)
        if factor <= 0:
            return None
        return payoff * factor

    def _infer_stock_trend_last_round(self, history: PlayerHistory) -> int:
        """
        Returns:
            +1 if stock increased last round
            -1 if stock decreased last round
             0 if unknown or approximately flat
        """
        if history.round_number <= 0:
            return 0
        prev_stock = self._infer_previous_stock(history)
        if prev_stock is None:
            return 0
        current_stock = float(self.last_inferred_stock) if history.round_number > 1 else None
        if current_stock is None:
            return 0
        diff = current_stock - prev_stock
        eps = 1e-12
        if diff > eps:
            return 1
        if diff < -eps:
            return -1
        return 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        r = self.n_rounds
        n = self.n_players
        S = float(current_stock)
        eps = 1e-12
        if history.round_number == 0:
            self.last_action = Action.C
            self.last_inferred_stock = S
            self.last_stock_trend = 0
            return Action.C
        if history.round_number >= max(r - 2, 0):
            self.last_action = Action.C
            self.last_inferred_stock = S
            self.last_stock_trend = 0
            return Action.C
        if S <= eps:
            self.last_action = Action.C
            self.last_inferred_stock = S
            self.last_stock_trend = 0
            return Action.C
        if S >= self.capacity - eps:
            self.last_action = Action.C
            self.last_inferred_stock = S
            self.last_stock_trend = 1
            return Action.C
        if self.n_opponents > 0:
            k = int(history.opponent_cooperators[-1])
            p = k / self.n_opponents
        else:
            p = 1.0
        prev_stock = self._infer_previous_stock(history)
        stock_increased_last_round = False
        stock_decreased_last_round = False
        stock_decreased_two_in_a_row = False
        if prev_stock is not None:
            diff_last = S - prev_stock
            stock_increased_last_round = diff_last > eps
            stock_decreased_last_round = diff_last < -eps
            if history.round_number >= 2:
                prev2_idx = history.round_number - 2
                prev2_payoff = float(history.my_payoffs[prev2_idx])
                prev2_action = bool(history.my_actions[prev2_idx])
                prev2_factor = 2.0 * n if prev2_action else float(n)
                if prev2_factor > 0:
                    stock_t_minus_2 = prev2_payoff * prev2_factor
                    diff_prev = prev_stock - stock_t_minus_2
                    stock_decreased_two_in_a_row = diff_prev < -eps and stock_decreased_last_round
        if S > self.capacity / 2.0:
            action = Action.C
        elif p >= 0.5:
            action = Action.C
        elif stock_increased_last_round:
            action = Action.C
        elif stock_decreased_last_round and stock_decreased_two_in_a_row and (p < 0.5):
            action = Action.D
        else:
            action = Action.C
        self.last_action = action
        self.last_inferred_stock = S
        self.last_stock_trend = 1 if stock_increased_last_round else -1 if stock_decreased_last_round else 0
        return action

class Strategy_ALTRUISTIC_102(BaseStrategy):
    """
    Fully cooperative common-pool strategy:
    always play C, regardless of stock level, history, or opponent behavior.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.last_observed_stock = None
        self.last_observed_opponent_cooperators = None

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        self.last_observed_stock = float(current_stock)
        if history.round_number == 0:
            self.last_observed_opponent_cooperators = None
            return Action.C
        if history.opponent_cooperators is not None and len(history.opponent_cooperators) > 0:
            self.last_observed_opponent_cooperators = int(history.opponent_cooperators[-1])
        else:
            self.last_observed_opponent_cooperators = None
        return Action.C

class Strategy_ALTRUISTIC_103(BaseStrategy):
    """
    Conservative commons strategy:
    - Cooperate by default.
    - Defect only as a temporary conservation move when opponents mostly defect
      and the pool is near depletion.
    - Immediately return to cooperation when the environment improves.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self._last_round_stock_before_decision = None
        self._last_round_seen = -1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = int(self.game_description.n_players)
        r = int(self.game_description.n_rounds)
        capacity = float(self.game_description.capacity)
        round_number = int(history.round_number)
        if round_number <= 0:
            self._last_round_stock_before_decision = float(current_stock)
            self._last_round_seen = round_number
            return Action.C
        n_opponents = max(1, n - 1)
        last_opp_coop = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        p = last_opp_coop / n_opponents
        prev_action = bool(history.my_actions[-1]) if len(history.my_actions) > 0 else True
        S = float(current_stock)
        S_prev = self._last_round_stock_before_decision
        if S_prev is None:
            S_prev = S
        low_stock_threshold = max(2.0 * n, 0.4 * capacity)
        action = Action.C
        if round_number >= max(0, r - 2):
            if S > 2.0 * n:
                action = Action.C
            elif p <= 1.0 / 3.0:
                action = Action.D
            else:
                action = Action.C
        elif p >= 0.5:
            action = Action.C
        elif p <= 1.0 / 3.0 and S <= low_stock_threshold and (S < S_prev):
            action = Action.D
        else:
            action = Action.C
        if not prev_action and (p >= 0.5 or S >= S_prev):
            action = Action.C
        self._last_round_stock_before_decision = float(current_stock)
        self._last_round_seen = round_number
        return action

class Strategy_ALTRUISTIC_104(BaseStrategy):
    """
    Unconditional cooperater in the common pool resource game.
    Always plays C, regardless of history, stock level, or opponent behavior.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = getattr(game_description, 'n_players', None)
        self.n_rounds = getattr(game_description, 'n_rounds', None)
        self.capacity = getattr(game_description, 'capacity', None)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        _ = history.round_number
        _ = current_stock
        return Action.C

class Strategy_ALTRUISTIC_105(BaseStrategy):
    """
    Cooperative default strategy with short corrective defection when
    opponents repeatedly over-extract from a low stock.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.recovery_rounds_remaining = 0
        self.defect_next_round = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        last_round_index = self.n_rounds - 1
        m = max(self.n_players - 1, 1)
        if round_number >= last_round_index:
            return Action.C
        if current_stock < self.capacity / 4.0:
            self.recovery_rounds_remaining = max(self.recovery_rounds_remaining, 2)
        last_q = None
        prev_q = None
        if round_number >= 1:
            last_opponents = int(history.opponent_cooperators[-1])
            last_q = last_opponents / m
        if round_number >= 2:
            prev_opponents = int(history.opponent_cooperators[-2])
            prev_q = prev_opponents / m
        if last_q is not None and last_q >= 2.0 / 3.0:
            self.defect_next_round = False
        if self.recovery_rounds_remaining > 0:
            self.recovery_rounds_remaining -= 1
            return Action.C
        if current_stock >= self.capacity / 2.0:
            return Action.C
        if self.defect_next_round:
            self.defect_next_round = False
            return Action.D
        if last_q is not None and prev_q is not None:
            if last_q < 1.0 / 3.0 and prev_q < 1.0 / 3.0:
                self.defect_next_round = True
                return Action.D
        if last_q is not None:
            if last_q >= 2.0 / 3.0:
                return Action.C
            if last_q <= 1.0 / 3.0 and current_stock <= self.capacity / 3.0:
                return Action.D
        return Action.C

class Strategy_ALTRUISTIC_106(BaseStrategy):
    """
    Stewardship strategy for the Common Pool Resource Game.

    Policy:
    - Cooperate in the first round.
    - Cooperate in the last round.
    - Cooperate whenever the stock is healthy.
    - Defect only as a conservation response when stock is low and prior
      opponent cooperation was weak.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(getattr(game_description, 'n_players', 0) or 0)
        self.n_rounds = int(getattr(game_description, 'n_rounds', 0) or 0)
        self.capacity = float(getattr(game_description, 'capacity', 0) or 0.0)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(getattr(history, 'round_number', 0) or 0)
        if round_number == 0:
            return Action.C
        if self.n_rounds > 0 and round_number >= self.n_rounds - 1:
            return Action.C
        q_prev = 1.0
        opp_counts = getattr(history, 'opponent_cooperators', None)
        n_opponents = max(self.n_players - 1, 0)
        if opp_counts is not None and len(opp_counts) > 0 and (n_opponents > 0):
            prev_k = opp_counts[-1]
            try:
                q_prev = float(prev_k) / float(n_opponents)
            except Exception:
                q_prev = 1.0
        if self.capacity <= 0:
            return Action.C
        stock = float(current_stock)
        if stock >= 0.5 * self.capacity:
            return Action.C
        if stock >= 0.25 * self.capacity:
            return Action.D if q_prev < 0.25 else Action.C
        return Action.C if q_prev >= 0.5 else Action.D

class Strategy_ALTRUISTIC_107(BaseStrategy):
    """
    Default-to-cooperate common-pool strategy with short-lived conservation
    defections when the stock is low and the most recent round showed strong
    opponent defection.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(self.n_players - 1, 0)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_rounds = self.n_rounds
        capacity = self.capacity
        n_opponents = self.n_opponents
        if current_stock <= 0:
            return Action.C
        if current_stock >= capacity:
            return Action.C
        round_number = history.round_number
        if round_number == 0:
            return Action.C
        last_cooperators = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        if n_opponents <= 0:
            f_t = 0.0
        else:
            last_defectors = n_opponents - last_cooperators
            f_t = last_defectors / n_opponents
        substantial_defection = f_t >= 0.5
        majority_cooperation = f_t < 0.5
        all_cooperated = last_cooperators >= n_opponents
        all_defected = last_cooperators <= 0
        if all_cooperated:
            return Action.C
        if round_number >= n_rounds - 1:
            if current_stock < capacity / 3 and substantial_defection:
                return Action.D
            return Action.C
        if current_stock >= capacity / 2:
            return Action.C
        if all_defected:
            return Action.D if current_stock < capacity / 2 else Action.C
        if substantial_defection:
            return Action.D
        if majority_cooperation:
            return Action.C
        return Action.C

class Strategy_ALTRUISTIC_108(BaseStrategy):
    """
    Always cooperates to minimize extraction from the common pool resource.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = getattr(game_description, 'n_players', 0)
        self.n_rounds = getattr(game_description, 'n_rounds', 0)
        self.capacity = getattr(game_description, 'capacity', 0)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        return Action.C

class Strategy_ALTRUISTIC_109(BaseStrategy):
    """
    Always cooperate strategy for the Common Pool Resource Game.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self._n_players = int(game_description.n_players)
        self._n_rounds = int(game_description.n_rounds)
        self._capacity = float(game_description.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        return Action.C

class Strategy_ALTRUISTIC_110(BaseStrategy):
    """
    Always cooperate in every round, regardless of history or current stock.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        return Action.C

class Strategy_ALTRUISTIC_111(BaseStrategy):
    """
    Always cooperate in every round, regardless of history, stock, or opponents' actions.
    Records the number of cooperating opponents each round for internal bookkeeping only.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.opponent_cooperator_history = []
        self.my_action_history = []

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number > 0:
            try:
                self.opponent_cooperator_history.append(int(history.opponent_cooperators[-1]))
            except Exception:
                self.opponent_cooperator_history.append(0)
        action = Action.C
        self.my_action_history.append(action)
        return action

class Strategy_ALTRUISTIC_112(BaseStrategy):
    """
    Conservative common-pool strategy:
    cooperate by default, but defect temporarily when the stock is too low
    or when opponents have been persistently under-cooperative.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.low_count = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        threshold = 2 * n
        m = max(n - 1, 0)
        if history.round_number == 0:
            self.low_count = 0
            return Action.C
        last_opponent_cooperators = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        if m > 0 and last_opponent_cooperators < m / 2:
            self.low_count += 1
        else:
            self.low_count = 0
        if current_stock <= threshold or self.low_count >= 2:
            return Action.D
        return Action.C

class Strategy_ALTRUISTIC_113(BaseStrategy):
    """
    Conservative common-pool strategy:
    - Cooperate by default.
    - Defect only as a last-resort conservation move when stock is collapsing
      and opponent cooperation has nearly vanished.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(0, self.n_players - 1)
        self._seen_stocks = []
        self._recent_actions = []

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        S = float(current_stock)
        if len(self._seen_stocks) < round_number + 1:
            self._seen_stocks.append(S)
        else:
            self._seen_stocks[round_number] = S
        if round_number == 0:
            c = 1.0
            prev_opponents = 0
        else:
            prev_opponents = int(history.opponent_cooperators[-1])
            c = prev_opponents / self.n_opponents if self.n_opponents > 0 else 1.0

        def stock_change(idx: int) -> float:
            if idx <= 0 or idx >= len(self._seen_stocks):
                return 0.0
            return self._seen_stocks[idx] - self._seen_stocks[idx - 1]
        last_change = stock_change(round_number)
        prev_change = stock_change(round_number - 1)
        rising_two = last_change > 0 and prev_change > 0
        falling_two = last_change < 0 and prev_change < 0
        healthy = S >= 0.6 * self.capacity
        moderate = S >= 0.35 * self.capacity
        low = S >= 0.25 * self.capacity
        very_low = S < 0.25 * self.capacity
        if round_number == 0:
            action = Action.C
        else:
            action = Action.C
            if healthy:
                action = Action.C
            elif moderate:
                if c >= 0.5 or last_change > 0:
                    action = Action.C
                else:
                    action = Action.C
            elif low:
                if c >= 2.0 / 3.0 and S >= 0.35 * self.capacity:
                    action = Action.C
                else:
                    action = Action.C
            elif c < 1.0 / 3.0 and S < 0.25 * self.capacity:
                action = Action.D
            else:
                action = Action.C
            if rising_two and S >= 0.2 * self.capacity:
                action = Action.C
            if falling_two and S < 0.35 * self.capacity:
                if c < 2.0 / 3.0:
                    action = Action.C if S >= 0.25 * self.capacity else Action.D if c < 1.0 / 3.0 else Action.C
            majority_defected_last_round = prev_opponents < self.n_opponents / 2.0
            if majority_defected_last_round and S >= 0.25 * self.capacity:
                action = Action.C
            if c >= 0.5 and S > 0.35 * self.capacity:
                action = Action.C
            if round_number >= self.n_rounds - 2:
                if round_number == self.n_rounds - 1:
                    if S < 0.15 * self.capacity and c == 0:
                        action = Action.D
                    else:
                        action = Action.C
                elif S < 0.2 * self.capacity and c < 1.0 / 3.0:
                    action = Action.D
                else:
                    action = Action.C
        self._recent_actions.append(action)
        return action

class Strategy_ALTRUISTIC_114(BaseStrategy):
    """
    Unconditional cooperation strategy for the Common Pool Resource Game.

    The strategy always chooses C (cooperate) in every round, regardless of
    history, current stock, or opponents' past behavior, to minimize depletion
    of the common pool.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = getattr(game_description, 'n_players', 0)
        self.n_rounds = getattr(game_description, 'n_rounds', 0)
        self.capacity = getattr(game_description, 'capacity', 0)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        return Action.C

class Strategy_ALTRUISTIC_115(BaseStrategy):
    """
    Altruistic conservation strategy for the Common Pool Resource Game.

    - Cooperate initially.
    - Prefer cooperation when opponent cooperation is moderate or better.
    - Defect defensively when stock is low and recent cooperation is poor.
    - Become more conservative after a stock drop, and more forgiving after
      a stock increase.
    - Cooperate in the final rounds unless collapse risk is clear.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = max(2, int(game_description.n_players))
        self.r = max(1, int(game_description.n_rounds))
        self.capacity = float(game_description.capacity)
        self.opponent_count = max(1, self.n - 1)
        self.min_sustainable = 2.0 * self.n

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        if round_number == 0:
            return Action.C
        last_opp_coop = int(history.opponent_cooperators[-1])
        p_last = last_opp_coop / self.opponent_count if self.opponent_count > 0 else 1.0
        prev_stock = float(current_stock)
        if round_number >= 1:
            last_my_action = bool(history.my_actions[-1])
            last_payoff = float(history.my_payoffs[-1]) if len(history.my_payoffs) > 0 else 0.0
            denom = 2.0 * self.n if last_my_action else float(self.n)
            if denom > 0.0:
                prev_stock = max(0.0, last_payoff * denom)
        stock_drop = prev_stock - float(current_stock)
        near_collapse = float(current_stock) <= self.min_sustainable
        healthy_stock = float(current_stock) > self.min_sustainable
        high_stock = float(current_stock) >= 0.7 * self.capacity
        very_high_stock = float(current_stock) >= 0.85 * self.capacity
        rounds_left = self.r - round_number
        if rounds_left <= 1:
            if near_collapse and p_last < 0.5:
                return Action.D
            return Action.C
        if rounds_left <= 2 and high_stock:
            return Action.C
        if near_collapse:
            action = Action.C if p_last >= 0.5 else Action.D
        elif healthy_stock:
            action = Action.C if p_last >= 0.25 else Action.D
        else:
            action = Action.C if p_last >= 0.5 else Action.D
        if stock_drop > 1e-09:
            if p_last < 2.0 / 3.0:
                action = Action.D
        elif p_last >= 1.0 / 3.0:
            action = Action.C
        if p_last >= 0.5 and stock_drop > 1e-09:
            action = Action.C
        if p_last < 0.5 and (not healthy_stock):
            action = Action.D
        if very_high_stock and p_last >= 1.0 / 3.0:
            action = Action.C
        return action

class Strategy_ALTRUISTIC_116(BaseStrategy):
    """
    Cooperative-by-default common-pool strategy with threshold-based safeguarding,
    short retaliation, and recovery-oriented forgiveness.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(self.n_players - 1, 1)
        self.t_high = 0.75 * self.capacity
        self.t_mid = 0.5 * self.capacity
        self.t_low = 0.25 * self.capacity
        self.last_action_was_d: bool = False
        self.tighten_next_round: bool = False
        self.defect_streak: int = 0
        self.last_seen_stock: float | None = None

    def _opponent_fraction_cooperated(self, history: PlayerHistory) -> float:
        if history.round_number == 0:
            return 1.0
        last = int(history.opponent_cooperators[-1])
        denom = self.n_opponents if self.n_opponents > 0 else 1
        return max(0.0, min(1.0, last / denom))

    def _strict_majority_defected_last_round(self, history: PlayerHistory) -> bool:
        if history.round_number == 0:
            return False
        coop = int(history.opponent_cooperators[-1])
        return coop * 2 < self.n_opponents

    def _strict_majority_defected_two_in_a_row(self, history: PlayerHistory) -> bool:
        if history.round_number < 2:
            return False
        last1 = int(history.opponent_cooperators[-1])
        last2 = int(history.opponent_cooperators[-2])
        return last1 * 2 < self.n_opponents and last2 * 2 < self.n_opponents

    def _all_opponents_cooperated_last_round(self, history: PlayerHistory) -> bool:
        if history.round_number == 0:
            return False
        return int(history.opponent_cooperators[-1]) >= self.n_opponents

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number
        if self.last_seen_stock is not None:
            if current_stock >= 1.2 * self.last_seen_stock:
                self.tighten_next_round = False
            elif current_stock <= 0.8 * self.last_seen_stock:
                self.tighten_next_round = True
        self.last_seen_stock = float(current_stock)
        if t == 0 or t >= self.n_rounds - 1:
            self.last_action_was_d = False
            return Action.C
        if history.round_number < 2:
            c = self._opponent_fraction_cooperated(history)
            if current_stock >= self.t_high or c >= 0.5:
                self.last_action_was_d = False
                return Action.C
        c = self._opponent_fraction_cooperated(history)
        last_c = int(history.opponent_cooperators[-1]) if history.round_number > 0 else self.n_opponents
        prev_c = int(history.opponent_cooperators[-2]) if history.round_number > 1 else self.n_opponents
        stock_increased_last_round = False
        if history.round_number > 1 and len(history.my_payoffs) > 0:
            stock_increased_last_round = current_stock >= self.last_seen_stock if self.last_seen_stock is not None else False
        strict_majority_defected_last_round = self._strict_majority_defected_last_round(history)
        strict_majority_defected_two_in_a_row = self._strict_majority_defected_two_in_a_row(history)
        if c >= 0.5:
            self.last_action_was_d = False
            self.defect_streak = 0
            return Action.C
        if self.last_action_was_d:
            if current_stock < self.t_mid and c < 0.5:
                self.last_action_was_d = True
                self.defect_streak += 1
                return Action.D
            self.last_action_was_d = False
            self.defect_streak = 0
            return Action.C
        if current_stock >= self.t_high:
            self.last_action_was_d = False
            self.defect_streak = 0
            return Action.C
        t_high = self.t_high
        t_mid = self.t_mid
        t_low = self.t_low
        if self.tighten_next_round:
            t_high = min(self.capacity, t_high + 0.05 * self.capacity)
            t_mid = min(t_high, t_mid + 0.05 * self.capacity)
            t_low = min(t_mid, t_low + 0.05 * self.capacity)
        if current_stock >= t_high:
            action = Action.C
        elif current_stock >= t_mid:
            if c >= 0.5:
                action = Action.C
            elif c == 0.0 and prev_c == 0:
                action = Action.D
            else:
                action = Action.C
        elif current_stock >= t_low:
            if c >= 0.75:
                action = Action.C
            else:
                action = Action.D
        elif c == 1.0 and stock_increased_last_round:
            action = Action.C
        elif strict_majority_defected_last_round or strict_majority_defected_two_in_a_row:
            action = Action.D
        else:
            action = Action.C
        if action == Action.D and current_stock < t_low and (c >= 0.5):
            action = Action.C
        if action == Action.D:
            self.last_action_was_d = True
            self.defect_streak += 1
            self.tighten_next_round = False
        else:
            self.last_action_was_d = False
            self.defect_streak = 0
        return action

class Strategy_ALTRUISTIC_117(BaseStrategy):
    """
    Unconditional cooperator in every round, regardless of history or stock.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = getattr(game_description, 'n_players', 0)
        self.n_rounds = getattr(game_description, 'n_rounds', 0)
        self.capacity = getattr(game_description, 'capacity', 0)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        return Action.C

class Strategy_ALTRUISTIC_118(BaseStrategy):
    """
    Protective cooperation strategy with adaptive trust.

    - Cooperates by default.
    - Defects as a brake when stock is critically low or recent cooperation is poor.
    - Uses an internal trust level updated from observed opponent cooperation.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.trust = 1.0
        self._last_seen_round = -1
        self._last_action = Action.C

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        cap = float(self.game_description.capacity)
        t = history.round_number
        safe_floor = cap / 4.0
        half_cap = cap / 2.0
        three_quarters_cap = 3.0 * cap / 4.0
        eighth_cap = cap / 8.0
        if t == self._last_seen_round:
            return self._last_action
        if t == 0:
            self._last_seen_round = t
            self._last_action = Action.C
            return Action.C
        if len(history.opponent_cooperators) > 0:
            k = int(history.opponent_cooperators[-1])
            opponents = max(1, n - 1)
            q = k / opponents
            if q >= 2.0 / 3.0:
                self.trust = min(1.0, self.trust + 0.25)
            elif q < 1.0 / 3.0:
                self.trust = max(0.0, self.trust - 0.35)
        prev_defected = False
        if len(history.my_actions) > 0:
            prev_defected = not bool(history.my_actions[-1])
        if prev_defected and current_stock > half_cap:
            self.trust = max(self.trust, 0.5)
        action = Action.C
        if t == r:
            action = Action.C
        elif t == r - 1:
            action = Action.D if current_stock < safe_floor else Action.C
        elif current_stock <= safe_floor:
            action = Action.D
        elif current_stock > three_quarters_cap:
            action = Action.C
        elif current_stock > half_cap:
            if len(history.opponent_cooperators) > 0:
                k = int(history.opponent_cooperators[-1])
                if k >= math.ceil((n - 1) / 2):
                    action = Action.C
                else:
                    action = Action.C if self.trust >= 0.5 else Action.D
            else:
                action = Action.C if self.trust >= 0.5 else Action.D
        else:
            action = Action.C if self.trust >= 0.5 else Action.D
        if action == Action.D and prev_defected and (current_stock > eighth_cap):
            action = Action.C
        self._last_seen_round = t
        self._last_action = action
        return action

class Strategy_ALTRUISTIC_119(BaseStrategy):
    """
    Cooperative default strategy for the Common Pool Resource Game.

    Behaviour:
    - Starts and ends cooperatively.
    - Cooperates whenever stock is very low or uncertainty is high.
    - Defects only as a short corrective signal after repeated low cooperation
      and sufficiently depleted stock.
    - Returns to cooperation quickly when cooperation or stock recovers.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        if round_number == 0:
            return Action.C
        if round_number >= self.n_rounds - 1:
            return Action.C
        if current_stock <= 0.0 or current_stock <= 2.0 * self.n_players:
            return Action.C
        capacity = self.capacity if self.capacity > 0.0 else 1.0
        stock_fraction = current_stock / capacity
        n_opponents = max(self.n_players - 1, 1)

        def coop_rate(idx: int) -> float:
            if idx < 0:
                return 1.0
            if idx >= len(history.opponent_cooperators):
                return 1.0
            return float(history.opponent_cooperators[idx]) / float(n_opponents)
        x_prev = coop_rate(round_number - 1)
        x_prev2 = coop_rate(round_number - 2)
        last_my_action = bool(history.my_actions[-1]) if round_number >= 1 else True
        prev_my_action = bool(history.my_actions[-2]) if round_number >= 2 else True
        if not last_my_action:
            if x_prev >= 0.5 or stock_fraction >= 0.5 or x_prev2 >= 0.5:
                return Action.C
            if not prev_my_action:
                return Action.C
            return Action.D
        if x_prev >= 2.0 / 3.0:
            return Action.C
        if x_prev >= 1.0 / 2.0:
            return Action.C
        if x_prev2 >= 1.0 / 2.0:
            return Action.C
        if x_prev < 1.0 / 2.0 and x_prev2 < 1.0 / 2.0:
            if stock_fraction < 1.0 / 3.0:
                return Action.D
        if x_prev < 1.0 / 3.0 and stock_fraction < 1.0 / 4.0:
            return Action.D
        return Action.C

class Strategy_ALTRUISTIC_120(BaseStrategy):
    """
    Unconditional cooperator for the Common Pool Resource Game.

    This strategy always plays C in every round.
    It keeps lightweight internal statistics on opponent cooperation rates
    for monitoring only, and never uses them to defect.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(getattr(game_description, 'n_players', 0) or 0)
        self.n_rounds = int(getattr(game_description, 'n_rounds', 0) or 0)
        self.capacity = float(getattr(game_description, 'capacity', 0.0) or 0.0)
        self.opponent_cooperation_history = []
        self.average_opponent_cooperation_rate = 0.0
        self.last_observed_stock = None

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        try:
            self.last_observed_stock = float(current_stock)
        except Exception:
            self.last_observed_stock = 0.0
        round_number = int(getattr(history, 'round_number', 0) or 0)
        if round_number > 0 and hasattr(history, 'opponent_cooperators'):
            opponents = max(self.n_players - 1, 0)
            last_count = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
            last_count = max(0, min(last_count, opponents))
            rate = last_count / opponents if opponents > 0 else 0.0
            self.opponent_cooperation_history.append(rate)
            if self.opponent_cooperation_history:
                self.average_opponent_cooperation_rate = float(np.mean(np.array(self.opponent_cooperation_history, dtype=float)))
            else:
                self.average_opponent_cooperation_rate = 0.0
        return Action.C

class Strategy_ALTRUISTIC_121(BaseStrategy):
    """
    Cooperative default strategy with collapse-triggered temporary defection and
    fast recovery back to cooperation.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self._prev_low_collapse_signal = False
        self._last_action = Action.C

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_rounds = self.game_description.n_rounds
        n_players = self.game_description.n_players
        capacity = float(self.game_description.capacity)
        t = history.round_number
        if t == 0:
            action = Action.C
            self._prev_low_collapse_signal = False
            self._last_action = action
            return action
        if t >= n_rounds - 1:
            action = Action.C
            self._prev_low_collapse_signal = False
            self._last_action = action
            return action
        if current_stock <= 0.0:
            action = Action.C
            self._prev_low_collapse_signal = False
            self._last_action = action
            return action
        m = max(1, n_players - 1)
        prev_opp_coop = int(history.opponent_cooperators[-1])
        p = prev_opp_coop / m
        low_extreme = current_stock <= 0.1 * capacity
        low_collapse = current_stock < 0.25 * capacity and p < 0.4
        moderate_low = current_stock < 0.35 * capacity and p < 0.5
        if self._last_action == Action.D and (p >= 0.5 or current_stock >= 0.35 * capacity):
            action = Action.C
        elif low_extreme:
            action = Action.D if p < 0.25 else Action.C
        elif low_collapse:
            if self._prev_low_collapse_signal:
                action = Action.D
            else:
                action = Action.C
        elif moderate_low:
            action = Action.D
        else:
            action = Action.C
        self._prev_low_collapse_signal = low_collapse
        self._last_action = action
        return action

class Strategy_ALTRUISTIC_122(BaseStrategy):
    """
    Cooperative-by-default strategy with brief retaliation only after
    two consecutive rounds of all-opponent defection and declining stock.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.punished = False

    def _reconstruct_round_stock(self, payoff: float, my_action: bool) -> float:
        n = max(2, int(self.game_description.n_players))
        if my_action:
            return payoff * (2.0 * n)
        return payoff * float(n)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_rounds = int(self.game_description.n_rounds)
        round_number = int(history.round_number)
        if round_number >= max(0, n_rounds - 2):
            self.punished = False
            return Action.C
        if round_number == 0:
            self.punished = False
            return Action.C
        last_opponents = int(history.opponent_cooperators[-1])
        n_opponents = max(0, int(self.game_description.n_players) - 1)
        if last_opponents > 0:
            self.punished = False
        elif round_number >= 2:
            prev_opponents = int(history.opponent_cooperators[-2])
            last_my_action = bool(history.my_actions[-1])
            prev_my_action = bool(history.my_actions[-2])
            last_payoff = float(history.my_payoffs[-1])
            prev_payoff = float(history.my_payoffs[-2])
            stock_last_round_start = self._reconstruct_round_stock(last_payoff, last_my_action)
            stock_prev_round_start = self._reconstruct_round_stock(prev_payoff, prev_my_action)
            declining = stock_last_round_start < stock_prev_round_start
            all_defect_two_rounds = last_opponents == 0 and prev_opponents == 0
            self.punished = bool(all_defect_two_rounds and declining)
        else:
            self.punished = False
        if current_stock <= 0.0:
            self.punished = False
            return Action.C
        if current_stock <= float(self.game_description.capacity) / 4.0 and (not self.punished):
            return Action.C
        return Action.D if self.punished else Action.C

class Strategy_ALTRUISTIC_123(BaseStrategy):
    """
    Cooperative default strategy with stock-sensitive, reactive defection.
    It cooperates unless opponent cooperation is clearly insufficient or
    the pool is under severe stress.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(self.n_players - 1, 0)
        self.threshold_opponents = math.ceil(self.n_opponents / 2) if self.n_opponents > 0 else 0
        self.target_cooperators = math.ceil((self.n_players + 1) / 2)
        self._trend_window = min(5, self.n_rounds if self.n_rounds > 0 else 1)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        n_rounds_left = self.n_rounds - round_number
        if round_number == 0:
            return Action.C
        last_k = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        trend = float(last_k)
        if len(history.opponent_cooperators) > 1:
            window = min(self._trend_window, len(history.opponent_cooperators))
            weights = np.arange(1, window + 1, dtype=float)
            recent = np.array(history.opponent_cooperators[-window:], dtype=float)
            trend = float(np.dot(recent, weights) / np.sum(weights))
        healthy_stock = self.capacity > 0 and current_stock >= 0.75 * self.capacity
        moderate_stock = self.capacity > 0 and 0.4 * self.capacity <= current_stock < 0.75 * self.capacity
        low_stock = self.capacity > 0 and current_stock < 0.4 * self.capacity
        very_low_stock = self.capacity > 0 and current_stock <= 0.1 * self.capacity
        if very_low_stock or current_stock <= 1e-12:
            return Action.C if last_k > 0 else Action.D
        if n_rounds_left <= 2:
            if healthy_stock:
                return Action.C
            if current_stock <= 0.1 * self.capacity:
                return Action.C if last_k > 0 else Action.D
            if last_k >= self.threshold_opponents or trend >= self.threshold_opponents:
                return Action.C
            return Action.D
        if healthy_stock:
            return Action.C
        if trend >= self.threshold_opponents:
            return Action.C
        if moderate_stock:
            return Action.C if last_k >= self.threshold_opponents else Action.D
        if low_stock:
            return Action.C if last_k >= self.threshold_opponents else Action.D
        return Action.C if last_k >= self.threshold_opponents else Action.D

class Strategy_ALTRUISTIC_124(BaseStrategy):
    """
    Stock-preserving threshold policy with forgiveness.
    Cooperates by default, using brief defensive defection only when opponent
    cooperation has been repeatedly low and the pool is under pressure.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(0, self.n_players - 1)
        self.midpoint = self.capacity / 2.0
        self.third = self.capacity / 3.0
        self.quarter = self.capacity / 4.0
        self._last_internal_action = Action.C

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        S = float(current_stock)
        cap = self.capacity
        m = self.n_opponents
        if round_number <= 0:
            self._last_internal_action = Action.C
            return Action.C
        prev_opponents = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        prev_rate = prev_opponents / m if m > 0 else 1.0
        prev_prev_rate = None
        if round_number >= 2 and len(history.opponent_cooperators) >= 2:
            prev_prev_opponents = int(history.opponent_cooperators[-2])
            prev_prev_rate = prev_prev_opponents / m if m > 0 else 1.0
        last_my_action = bool(history.my_actions[-1]) if len(history.my_actions) > 0 else True
        last_was_defection = not last_my_action
        if round_number >= self.n_rounds - 1:
            action = Action.C if S > 0 else Action.D
            self._last_internal_action = action
            return action
        action = Action.C
        if S >= self.midpoint:
            action = Action.C
        elif prev_rate >= 2.0 / 3.0:
            action = Action.C
        elif S >= self.third and prev_rate >= 0.5:
            action = Action.C
        elif prev_rate == 0.0:
            action = Action.D
        elif S < self.quarter and prev_rate < 0.5:
            action = Action.D
        else:
            action = Action.C
        if last_was_defection:
            if round_number >= 2 and prev_prev_rate is not None:
                weak_two_rounds = prev_rate < 0.5 and prev_prev_rate < 0.5
            else:
                weak_two_rounds = False
            stock_falling_fast = S < self.third
            if not (weak_two_rounds and stock_falling_fast):
                if prev_rate > 0.0 or S >= self.midpoint:
                    action = Action.C
        if prev_rate == 0.0:
            if last_was_defection:
                action = Action.C if prev_rate > 0.0 or S >= self.midpoint else Action.D
            else:
                action = Action.D
        if S < self.quarter:
            if prev_rate > 0.0:
                action = Action.C
            else:
                action = Action.D if round_number % 2 == 0 else Action.C
        if action == Action.D and S > 0:
            if prev_rate >= 0.5 or S >= self.third:
                action = Action.C
        self._last_internal_action = action
        return action

class Strategy_ALTRUISTIC_125(BaseStrategy):
    """
    Protective cooperative strategy for the common pool resource game.

    Core idea:
    - Cooperate by default.
    - Defect only when the stock is low and recent opponent cooperation is weak.
    - Recover quickly back to cooperation after signs of restraint.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.capacity = float(game_description.capacity)
        self.n_players = int(game_description.n_players)
        self.n_opponents = max(0, self.n_players - 1)
        self.last_stock = float(game_description.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_rounds_seen = history.round_number
        stock = float(current_stock)
        cap = self.capacity
        n_opp = self.n_opponents
        stock_increasing_or_stable = stock >= self.last_stock - 1e-12
        self.last_stock = stock
        if n_rounds_seen == 0:
            return Action.C
        opp_hist = history.opponent_cooperators
        if n_rounds_seen <= 0:
            recent_rate = 1.0
            last_coop_frac = 1.0
        else:
            window = min(3, n_rounds_seen)
            recent_counts = opp_hist[-window:]
            if n_opp > 0:
                recent_rate = float(np.mean(recent_counts) / n_opp) if len(recent_counts) > 0 else 1.0
                last_coop_frac = float(opp_hist[-1] / n_opp) if len(opp_hist) > 0 else 1.0
            else:
                recent_rate = 1.0
                last_coop_frac = 1.0
        if n_opp > 0:
            majority_threshold = n_opp / 2.0
            near_majority_threshold = max(0.0, (n_opp - 1) / 2.0)
            high_coop_threshold = 0.75
        else:
            majority_threshold = 0.0
            near_majority_threshold = 0.0
            high_coop_threshold = 1.0
        last_majority_coop = opp_hist[-1] >= majority_threshold if len(opp_hist) > 0 else True
        last_near_majority_coop = opp_hist[-1] >= near_majority_threshold if len(opp_hist) > 0 else True
        cap_safe = cap if cap > 1e-12 else 1.0
        stock_ratio = stock / cap_safe
        if stock <= 1e-12:
            return Action.D
        if n_rounds_seen >= self.game_description.n_rounds - 1:
            if stock_ratio <= 0.05 and recent_rate < 0.25 and (not last_majority_coop):
                return Action.D
            return Action.C
        if recent_rate >= high_coop_threshold or last_majority_coop:
            return Action.C
        if stock_increasing_or_stable and recent_rate >= 0.25:
            return Action.C
        if stock <= cap / 4.0:
            if recent_rate >= 0.75 or last_majority_coop:
                return Action.C
            return Action.D
        if stock <= cap / 3.0:
            if recent_rate >= 0.5 or last_near_majority_coop:
                return Action.C
            return Action.D
        if recent_rate >= 0.25 or last_near_majority_coop:
            return Action.C
        return Action.D

class Strategy_ALTRUISTIC_126(BaseStrategy):
    """
    Conservative-but-forgiving cooperation strategy for the common pool resource game.

    Core idea:
    - Start by cooperating.
    - Keep cooperating when the group cooperates enough and the stock is healthy.
    - Defect as a restraint response to sustained low cooperation or depleted stock.
    - Use a one-round forgiveness/test mechanism after a cooperative period.
    - Be especially cooperative in the final stage unless the group and stock are both weak.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(self.n_players - 1, 1)
        self.last_action = Action.C
        self.prev_stock = self.capacity
        self.prev_was_low_stock = False
        self.final_stage_forgiveness_used = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        if round_number == 0:
            self.last_action = Action.C
            self.prev_stock = float(current_stock)
            self.prev_was_low_stock = float(current_stock) < self.capacity / 3.0
            self.final_stage_forgiveness_used = False
            return Action.C
        last_opponents = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        c_t = last_opponents / self.n_opponents if self.n_opponents > 0 else 0.0
        prev_c = None
        if len(history.opponent_cooperators) >= 2:
            prev_opponents = int(history.opponent_cooperators[-2])
            prev_c = prev_opponents / self.n_opponents if self.n_opponents > 0 else 0.0
        s_t = float(current_stock)
        cap = self.capacity
        half_cap = cap / 2.0
        third_cap = cap / 3.0
        in_final_three = round_number >= max(self.n_rounds - 3, 0)
        is_last_round = round_number == self.n_rounds - 1
        if s_t < third_cap:
            action = Action.D
        elif self.prev_was_low_stock and self.prev_stock < third_cap:
            action = Action.D
        elif is_last_round:
            action = Action.C if c_t >= 0.5 or s_t >= half_cap else Action.D
        elif in_final_three:
            if c_t >= 2.0 / 3.0 and s_t >= half_cap:
                action = Action.C
                self.final_stage_forgiveness_used = False
            elif self.final_stage_forgiveness_used and c_t < 2.0 / 3.0:
                action = Action.D
            elif c_t < 2.0 / 3.0:
                action = Action.C
                self.final_stage_forgiveness_used = True
            else:
                action = Action.C if c_t >= 0.5 else Action.D
        elif prev_c is not None and prev_c >= 0.5 and (c_t < 0.5):
            action = Action.C
        elif s_t >= half_cap and c_t >= 0.5:
            action = Action.C
        else:
            action = Action.D
        self.last_action = action
        self.prev_stock = s_t
        self.prev_was_low_stock = s_t < third_cap
        if not in_final_three or (c_t >= 2.0 / 3.0 and s_t >= half_cap):
            self.final_stage_forgiveness_used = False
        return action

class Strategy_ALTRUISTIC_127(BaseStrategy):
    """
    Always cooperate strategy for the Common Pool Resource Game.

    This strategy ignores opponent behavior and current stock for decision-making
    and returns cooperation in every round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = getattr(game_description, 'n_players', 0)
        self.n_rounds = getattr(game_description, 'n_rounds', 0)
        self.capacity = getattr(game_description, 'capacity', 0)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        return Action.C

class Strategy_ALTRUISTIC_128(BaseStrategy):
    """
    Generous common-pool conservation strategy:
    - Cooperate by default
    - Defect only as a brief response to low stock and low observed cooperation
    - Revert to cooperation quickly once cooperation or stock recovers
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(self.n - 1, 0)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = int(history.round_number)
        S = float(current_stock)
        if S <= 0.0:
            return Action.D
        if self.n <= 1:
            return Action.C
        prev_cooperators = int(history.opponent_cooperators[-1]) if t > 0 and len(history.opponent_cooperators) > 0 else 0
        m = self.n_opponents
        f_prev = prev_cooperators / m if m > 0 else 1.0
        prev_my_action = bool(history.my_actions[-1]) if t > 0 and len(history.my_actions) > 0 else True
        if t == 0:
            return Action.C
        if t >= self.r - 1:
            return Action.D if S <= self.n else Action.C
        if S <= self.n:
            return Action.C if prev_cooperators > 0 else Action.D
        if S >= 1.5 * self.n:
            return Action.C
        if not prev_my_action:
            if f_prev >= 0.5 or S >= 1.5 * self.n:
                return Action.C
        if S >= 2.0 * self.n or f_prev >= 0.5:
            return Action.C
        return Action.D

class Strategy_BENEVOLENT_33(BaseStrategy):
    """
    Always cooperates in every round, while recording opponent cooperation counts
    for monitoring purposes only.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self._opponent_cooperation_history = []

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_players = getattr(self.game_description, 'n_players', 0)
        n_rounds = getattr(self.game_description, 'n_rounds', 0)
        n_opponents = max(0, n_players - 1)
        round_number = getattr(history, 'round_number', 0)
        if hasattr(history, 'opponent_cooperators') and round_number > 0:
            try:
                last_count = history.opponent_cooperators[-1]
                if isinstance(last_count, (int, np.integer)):
                    self._opponent_cooperation_history.append(int(last_count))
                else:
                    self._opponent_cooperation_history.append(int(last_count))
            except Exception:
                pass
        if round_number <= 0:
            return Action.C
        if n_rounds and round_number >= n_rounds:
            return Action.C
        _ = current_stock
        if round_number > 0 and len(self._opponent_cooperation_history) > 0:
            latest = self._opponent_cooperation_history[-1]
            if latest < 0:
                return Action.C
            if latest > n_opponents:
                return Action.C
        return Action.C

class Strategy_BENEVOLENT_34(BaseStrategy):
    """
    Always cooperate in every round, regardless of history or stock state.
    Tracks basic game metadata and last seen round for compatibility with
    concurrent instances and dynamic-state interfaces.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.last_round_seen = -1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        self.last_round_seen = history.round_number
        return Action.C

class Strategy_BENEVOLENT_35(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Starts cooperative.
    - Tracks short-term cooperation and trust.
    - Defects when stock is low or cooperation collapses.
    - Returns to cooperation quickly after broad cooperation resumes.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(getattr(game_description, 'n_players', 0) or 0)
        self.r = int(getattr(game_description, 'n_rounds', 0) or 0)
        self.capacity = float(getattr(game_description, 'capacity', 0.0) or 0.0)
        self.n_opponents = max(self.n - 1, 0)
        self.good_streak = 0
        self.low_trust = 0
        self.last_round_cooperators = None

    def _thresholds(self):
        broad = max(self.n - 1, 1) if self.n == 2 else max(self.n - 1, 0)
        mid = int(math.ceil(2 * self.n / 3)) if self.n > 0 else 0
        half = int(math.ceil(self.n / 2)) if self.n > 0 else 0
        return (broad, mid, half)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        broad_thr, mid_thr, half_thr = self._thresholds()
        if history is None:
            return Action.D if current_stock < self.capacity / 4 else Action.C
        round_number = int(getattr(history, 'round_number', 0) or 0)
        stock = float(current_stock if current_stock is not None else 0.0)
        if round_number == 0:
            self.good_streak = 0
            self.low_trust = 0
            self.last_round_cooperators = None
            return Action.C
        try:
            k = int(history.opponent_cooperators[-1])
            prev_k = int(history.opponent_cooperators[-2]) if round_number >= 2 else None
        except Exception:
            k = None
            prev_k = None
        is_final_round = round_number >= max(self.r - 1, 0)
        if k is not None:
            if k >= broad_thr:
                self.good_streak += 1
            else:
                self.good_streak = 0
            if k < mid_thr:
                self.low_trust += 1
            else:
                self.low_trust = 0
            self.last_round_cooperators = k
        low_stock = stock < self.capacity / 4 if self.capacity > 0 else False
        if self.good_streak >= 2 and (not low_stock):
            return Action.C
        if self.low_trust >= 2 and (not (k is not None and k >= broad_thr and (stock >= self.capacity / 2))):
            return Action.D
        if is_final_round:
            if low_stock:
                return Action.D
            if prev_k is not None and prev_k < half_thr:
                return Action.D
            return Action.C
        if k is None:
            return Action.D if low_stock else Action.C
        if low_stock:
            return Action.D
        if k >= broad_thr:
            return Action.C
        if k >= mid_thr and stock >= self.capacity / 2:
            return Action.C
        if stock >= 3 * self.capacity / 4 and k >= half_thr:
            return Action.C
        return Action.D

class Strategy_BENEVOLENT_36(BaseStrategy):
    """
    Default to cooperation, punish poor cooperation or depleted stock with a
    single defection, and forgive quickly once cooperation or stock recovers.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(0, self.n_players - 1)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        if round_number == 0:
            return Action.C if current_stock > 0 else Action.D
        if round_number >= self.n_rounds - 1:
            return Action.C if current_stock > 0 else Action.D
        last_opponent_coops = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        if self.n_opponents > 0:
            q = last_opponent_coops / self.n_opponents
        else:
            q = 0.0
        s = float(current_stock)
        prev_action = bool(history.my_actions[-1]) if len(history.my_actions) > 0 else True
        if not prev_action:
            if q == 1.0 or s >= self.capacity / 2.0:
                return Action.C
            return Action.C
        if q >= 0.5 and s >= self.capacity / 4.0:
            return Action.C
        return Action.D

class Strategy_BENEVOLENT_37(BaseStrategy):
    """
    Cooperative default strategy with bounded corrective defection.

    Plays C in the first and last rounds, and generally cooperates unless the
    previous round showed clear overuse of the pool. Defection is limited to
    short corrective bursts, never more than 2 consecutive rounds.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.coop_threshold = math.ceil((self.n_players - 1) / 2)
        self.max_consecutive_d = 2

    def _current_consecutive_d(self, history: PlayerHistory) -> int:
        count = 0
        for a in history.my_actions[::-1]:
            if bool(a) is False:
                count += 1
            else:
                break
        return count

    def _infer_stock_from_round(self, history: PlayerHistory, round_index: int) -> float:
        if round_index < 0 or round_index >= history.round_number:
            return float('nan')
        payoff = float(history.my_payoffs[round_index])
        my_action = bool(history.my_actions[round_index])
        if my_action:
            denom = 1.0 / (2.0 * self.n_players) if self.n_players > 0 else 0.0
        else:
            denom = 1.0 / self.n_players if self.n_players > 0 else 0.0
        if denom <= 0.0:
            return float('nan')
        return payoff / denom

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number + 1
        r = self.n_rounds
        if t == 1 or t >= max(1, r - 1):
            return Action.C
        consecutive_d = self._current_consecutive_d(history)
        if consecutive_d >= self.max_consecutive_d:
            return Action.C
        prev_cooperators = int(history.opponent_cooperators[-1]) if history.round_number > 0 else self.n_players - 1
        previous_stock = self._infer_stock_from_round(history, history.round_number - 2) if history.round_number >= 2 else float('nan')
        last_stock = self._infer_stock_from_round(history, history.round_number - 1) if history.round_number >= 1 else float('nan')
        stock_increased = False
        if not math.isnan(previous_stock) and (not math.isnan(last_stock)):
            stock_increased = last_stock > previous_stock + 1e-12
        if history.round_number > 0 and (not bool(history.my_actions[-1])):
            if prev_cooperators < self.coop_threshold and (not stock_increased):
                if consecutive_d < 1 and current_stock > self.capacity / 4.0:
                    return Action.D
            return Action.C
        if prev_cooperators >= self.coop_threshold:
            return Action.C
        if current_stock <= self.capacity / 4.0:
            return Action.C
        return Action.D

