class Strategy_BENEVOLENT_41(BaseStrategy):
    """
    Adaptive cooperative strategy for the Common Pool Resource Game.

    - Starts by cooperating.
    - Cooperates when the stock is healthy.
    - Becomes more selective as the pool depletes.
    - Defects only in clearly critical situations, and forgives immediately
      when cooperation recovers.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_players = int(self.game_description.n_players)
        n_rounds = int(self.game_description.n_rounds)
        capacity = float(self.game_description.capacity)
        round_number = int(history.round_number)
        if round_number == 0:
            return Action.C
        n_opponents = max(n_players - 1, 1)
        last_opp_coop = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        rho = last_opp_coop / n_opponents if n_players > 2 else 1.0 if last_opp_coop > 0 else 0.0
        p = 0.0 if capacity <= 0 else float(current_stock) / capacity
        p = max(0.0, min(1.0, p))
        last_my_action = bool(history.my_actions[-1]) if len(history.my_actions) > 0 else True
        prev_rho = int(history.opponent_cooperators[-2]) / n_opponents if len(history.opponent_cooperators) >= 2 and n_players > 2 else (1.0 if len(history.opponent_cooperators) >= 2 and history.opponent_cooperators[-2] > 0 else 0.0) if len(history.opponent_cooperators) >= 2 else None
        if round_number >= n_rounds - 1:
            if p < 0.2 and rho < 1.0 / 3.0:
                return Action.D
            return Action.C
        if rho >= 2.0 / 3.0:
            return Action.C
        if not last_my_action and rho >= 2.0 / 3.0:
            return Action.C
        if p >= 0.5:
            return Action.C
        if 0.3 <= p < 0.5:
            if rho >= 0.5:
                return Action.C
            return Action.D
        if 0.15 <= p < 0.3:
            if rho < 2.0 / 3.0:
                return Action.D
            return Action.C
        if p < 0.15:
            if len(history.opponent_cooperators) >= 2:
                if history.opponent_cooperators[-1] == n_opponents and history.opponent_cooperators[-2] == n_opponents:
                    return Action.C
            return Action.D
        if p < 0.3 and rho < 1.0 / 3.0:
            return Action.D
        if p < 0.1 and rho < 1.0:
            return Action.D
        if n_players == 2:
            if p < 0.1 and last_opp_coop == 0:
                return Action.D
            return Action.C
        return Action.C

class Strategy_BENEVOLENT_42(BaseStrategy):
    """
    Trust-based common-pool strategy:
    - Starts with cooperation
    - Tracks a smoothed trust score from observed opponent cooperation
    - Defects under persistent uncooperativeness or low stock
    - Becomes more cooperative in recovery and endgame situations
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        if round_number == 0:
            return Action.C
        n_opponents = max(self.n_players - 1, 1)
        last_count = int(history.opponent_cooperators[-1]) if round_number > 0 else 0
        recent_cooperation = last_count / n_opponents
        trust = 1.0
        for count in history.opponent_cooperators:
            p = float(count) / n_opponents
            trust = 0.7 * trust + 0.3 * p
        stock = float(current_stock)
        cap = self.capacity
        if round_number >= self.n_rounds - 2:
            if recent_cooperation >= 0.5 or trust >= 0.6:
                return Action.C
            return Action.D
        if recent_cooperation < 1.0 / 3.0:
            return Action.D
        if stock <= cap / 4.0:
            if recent_cooperation >= 0.5:
                return Action.C
            return Action.D
        if recent_cooperation >= 2.0 / 3.0:
            if stock > cap / 8.0:
                return Action.C
            return Action.D
        if trust >= 0.5 and recent_cooperation >= 0.5:
            return Action.C
        return Action.D

class Strategy_BENEVOLENT_43(BaseStrategy):
    """
    Always cooperate in every round, regardless of history or current stock.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        return Action.C

class Strategy_BENEVOLENT_44(BaseStrategy):
    """
    Stock-Protection Reciprocity:
    Begin cooperatively, continue cooperating in healthy or recovering pools,
    and defect only as a restrained response to sustained overextraction.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.prev_stock = None

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        if round_number == 0:
            self.prev_stock = float(current_stock)
            return Action.C
        n_opponents = max(self.n_players - 1, 1)
        prev_coop_count = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        coop_rate = prev_coop_count / n_opponents
        if self.prev_stock is None:
            delta_s = 0.0
        else:
            delta_s = float(current_stock) - float(self.prev_stock)
        self.prev_stock = float(current_stock)
        s = float(current_stock)
        cap = self.capacity
        if s >= 0.8 * cap:
            return Action.C
        if round_number == self.n_rounds - 1:
            return Action.C if coop_rate >= 0.25 else Action.D
        if s <= 0.2 * cap:
            if coop_rate < 0.25:
                return Action.D
            return Action.C
        if delta_s >= 0:
            return Action.C if coop_rate >= 0.2 else Action.D
        if s < 0.45 * cap and coop_rate < 0.2:
            return Action.D
        if coop_rate < 0.25 and s < 0.5 * cap:
            return Action.D
        return Action.C

