class Strategy_BENEVOLENT_99(BaseStrategy):
    """
    Conservative common-pool strategy:
    - Cooperate initially.
    - Continue cooperating when opponents have cooperated at least half the time
      and the projected post-round stock remains sufficiently healthy.
    - In the final round, cooperate only if the last observed opponent cooperation
      rate is at least half.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(self.n_players - 1, 1)
        self.half_capacity_threshold = self.capacity / 4.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        if round_number == 0:
            return Action.C
        last_cooperators = int(history.opponent_cooperators[-1])
        rho = last_cooperators / self.n_opponents if self.n_opponents > 0 else 0.0
        if round_number >= self.n_rounds - 1:
            return Action.C if rho >= 0.5 else Action.D
        s = float(current_stock)
        n = float(self.n_players)
        m = float(self.n_opponents)
        expected_opponent_consumption_per_opponent = rho * (s / (2.0 * n)) + (1.0 - rho) * (s / n)
        expected_total_opponent_consumption = m * expected_opponent_consumption_per_opponent
        r_c = s - s / (2.0 * n) - expected_total_opponent_consumption
        _r_d = s - s / n - expected_total_opponent_consumption
        if rho >= 0.5 and r_c >= self.half_capacity_threshold:
            return Action.C
        return Action.D

class Strategy_BENEVOLENT_100(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Cooperate by default
    - Defect when stock is low
    - Cooperate under sufficiently cooperative opponent behavior
    - Be more defensive on the final round based on stock level
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(self.n_players - 1, 1)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        if round_number == 0:
            return Action.C
        if self.capacity > 0:
            stock_level = float(current_stock) / self.capacity
        else:
            stock_level = 0.0
        if round_number > 0 and len(history.opponent_cooperators) > 0:
            last_cooperators = int(history.opponent_cooperators[-1])
        else:
            last_cooperators = 0
        if self.n_players <= 2:
            coop_rate = 1.0 if last_cooperators >= 1 else 0.0
        else:
            coop_rate = last_cooperators / float(self.n_players - 1)
        if round_number == self.n_rounds - 1:
            return Action.C if stock_level >= 0.5 else Action.D
        if stock_level <= 0.25:
            return Action.D
        if coop_rate >= 0.5:
            return Action.C
        if coop_rate >= 1.0 / 3.0 and stock_level >= 0.5:
            return Action.C
        return Action.D

class Strategy_BENEVOLENT_101(BaseStrategy):
    """
    Always cooperate in every round, regardless of history or current stock.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        return Action.C

class Strategy_BENEVOLENT_102(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Cooperate initially and in the final round.
    - Defect only briefly when cooperation is low and stock is still high.
    - Use a trust level to bias toward cooperation after sustained trust.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self._trust_level = 0.0
        self._last_seen_round = -1
        self._last_action = Action.C

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = float(self.game_description.capacity)
        round_number = history.round_number
        last_round_index = r - 1
        if round_number == 0 or round_number <= self._last_seen_round:
            self._trust_level = 0.0
            self._last_seen_round = -1
            self._last_action = Action.C
        if round_number >= last_round_index:
            self._last_seen_round = round_number
            self._last_action = Action.C
            return Action.C
        if round_number == 0:
            self._last_seen_round = round_number
            self._last_action = Action.C
            return Action.C
        try:
            k = int(history.opponent_cooperators[-1])
        except Exception:
            k = 0
        m = max(1, n - 1)
        p = k / m
        if p >= 1.0:
            self._trust_level = min(3.0, self._trust_level + 1.0)
        elif p >= 0.75:
            self._trust_level = min(3.0, self._trust_level + 0.5)
        elif p < 0.5:
            self._trust_level = max(-3.0, self._trust_level - 1.0)
        if current_stock <= 2.0 * n:
            action = Action.C
        elif self._trust_level >= 0.0:
            action = Action.C
        elif p >= 0.75:
            action = Action.C
        elif p >= 0.5 and current_stock >= 0.6 * capacity:
            action = Action.C
        elif self._last_action == Action.D and (p >= 0.5 or current_stock <= 0.8 * capacity):
            action = Action.C
        else:
            action = Action.D
        self._last_seen_round = round_number
        self._last_action = action
        return action

class Strategy_BENEVOLENT_103(BaseStrategy):
    """
    Always cooperate strategy for the Common Pool Resource Game.
    Chooses Action.C in every round, regardless of history or current stock.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        return Action.C

class Strategy_BENEVOLENT_104(BaseStrategy):
    """
    Defensive common-pool strategy:
    - Cooperate initially
    - Cooperate near the end, when stock is weak, or when cooperation is broadly present
    - Defect only as a brief response to two consecutive low-cooperation rounds
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.low_streak = 0
        self.last_action = Action.C
        n = max(0, int(getattr(game_description, 'n_players', 0)))
        self._half_threshold = math.ceil(n / 2)
        self._two_thirds_threshold = math.ceil(2 * n / 3)
        self._capacity_third = float(getattr(game_description, 'capacity', 0)) / 3.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        n_rounds = int(getattr(self.game_description, 'n_rounds', 0))
        capacity = float(getattr(self.game_description, 'capacity', 0))
        if round_number == 0:
            self.low_streak = 0
            self.last_action = Action.C
            return Action.C
        prev_opponent_cooperators = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        prev_my_action = bool(history.my_actions[-1]) if len(history.my_actions) > 0 else True
        prev_total_cooperators = prev_opponent_cooperators + (1 if prev_my_action else 0)
        if round_number >= max(0, n_rounds - 1):
            self.low_streak = 0
            self.last_action = Action.C
            return Action.C
        if current_stock <= self._capacity_third:
            self.low_streak = 0
            self.last_action = Action.C
            return Action.C
        if prev_total_cooperators >= self._two_thirds_threshold:
            self.low_streak = 0
            self.last_action = Action.C
            return Action.C
        if prev_total_cooperators >= self._half_threshold:
            self.low_streak = 0
            self.last_action = Action.C
            return Action.C
        self.low_streak += 1
        if self.low_streak >= 2 and current_stock > self._capacity_third and (self.last_action == Action.C):
            self.low_streak = 0
            self.last_action = Action.D
            return Action.D
        self.last_action = Action.C
        return Action.C

class Strategy_BENEVOLENT_105(BaseStrategy):
    """
    Cooperative default strategy with trust tracking, forgiveness, and
    stock-safety protection against collapse.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.trust = 0.5
        self.cooperation_lock = False
        self.middle_streak = 0
        self.falling_streak = 0
        self.last_observed_q = 1.0
        self.last_round_stock = None
        self.last_triggered_defection = False

    def _clamp(self, x: float, lo: float, hi: float) -> float:
        return max(lo, min(hi, x))

    def _post_round_stock(self, stock: float, self_consumption: float, q_others: float) -> float:
        """
        Estimate post-round stock using the game rules and last observed cooperation ratio.
        """
        n = max(2, self.n_players)
        stock = float(stock)
        opp_count = max(0, n - 1)
        opp_consumption_per_player = stock / (2.0 * n) * q_others + stock / n * (1.0 - q_others)
        total_consumption = self_consumption + opp_count * opp_consumption_per_player
        remaining = stock - total_consumption
        growth = 2.0 * remaining * (1.0 - remaining / self.capacity) if self.capacity > 0 else 0.0
        new_stock = remaining + growth
        return min(new_stock, self.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        stock = float(current_stock)
        if round_number == 0:
            self.last_round_stock = stock
            self.last_observed_q = 1.0
            self.cooperation_lock = True
            return Action.C
        n_opponents = max(0, self.n_players - 1)
        last_opp_coop = int(history.opponent_cooperators[-1]) if n_opponents > 0 else 0
        q = 1.0 if n_opponents == 0 else self._clamp(last_opp_coop / n_opponents, 0.0, 1.0)
        self.last_observed_q = q
        if q >= 1.0:
            self.trust = self._clamp(self.trust + 0.1, 0.0, 1.0)
            self.trust = self._clamp(self.trust + 0.2, 0.0, 1.0)
            self.cooperation_lock = True
        elif q >= 0.75:
            self.trust = self._clamp(self.trust + 0.05, 0.0, 1.0)
            self.cooperation_lock = False
        elif q <= 0.25:
            self.trust = self._clamp(self.trust - 0.15, 0.0, 1.0)
            self.cooperation_lock = False
        else:
            self.cooperation_lock = False
        if 0.25 < q < 0.75:
            self.middle_streak += 1
        else:
            self.middle_streak = 0
        if self.last_round_stock is not None and stock < self.last_round_stock:
            self.falling_streak += 1
        else:
            self.falling_streak = 0
        self.last_round_stock = stock
        if round_number >= self.n_rounds - 1:
            if stock <= 0.1 * self.capacity:
                return Action.D
            return Action.C
        c_stock = self._post_round_stock(stock, stock / (2.0 * self.n_players), q)
        d_stock = self._post_round_stock(stock, stock / self.n_players, q)
        threshold = 0.25 * self.capacity
        very_low = 0.1 * self.capacity
        c_below = c_stock < threshold
        d_below = d_stock < threshold
        if c_below and (not d_below):
            return Action.D
        if c_below and d_below:
            return Action.D if stock <= very_low else Action.C
        if self.cooperation_lock and q >= 0.75:
            return Action.C
        if q >= 1.0:
            return Action.C
        if q >= 0.75:
            return Action.C
        if q <= 0.25:
            if self.trust < 0.35:
                return Action.D
            return Action.C
        if 0.25 < q < 0.75:
            if self.middle_streak >= 3 and self.falling_streak >= 3:
                return Action.D
            return Action.C
        return Action.C

class Strategy_BENEVOLENT_106(BaseStrategy):
    """
    Conservative cooperative strategy with brief punishment and rapid rehabilitation.

    - Cooperates in the opening round.
    - Prefers cooperation when stock is healthy or opponents show recent cooperation.
    - Defects briefly only under persistent low cooperation and low stock.
    - Avoids long defection cycles and returns to cooperation quickly once recovery appears.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.last_choice = Action.C
        self.last_defect_round = -10 ** 9

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        n = max(2, self.n)
        capacity = max(1e-12, float(self.capacity))
        stock = float(current_stock)
        if round_number == 0:
            self.last_choice = Action.C
            return Action.C
        opp_counts = history.opponent_cooperators
        n_opponents = max(1, n - 1)

        def coop_rate_from_count(count: int) -> float:
            return float(count) / float(n_opponents)
        last_count = int(opp_counts[-1]) if len(opp_counts) >= 1 else 0
        last_rate = coop_rate_from_count(last_count)
        recent_counts = opp_counts[-3:] if len(opp_counts) >= 3 else opp_counts
        recent_rates = [coop_rate_from_count(int(c)) for c in recent_counts]
        avg_recent = float(np.mean(recent_rates)) if len(recent_rates) > 0 else last_rate
        prev_rate = coop_rate_from_count(int(opp_counts[-2])) if len(opp_counts) >= 2 else last_rate
        prev2_rate = coop_rate_from_count(int(opp_counts[-3])) if len(opp_counts) >= 3 else prev_rate
        high_stock = stock >= 0.75 * capacity
        moderate_stock = 0.25 * capacity <= stock < 0.75 * capacity
        low_stock = stock < 0.25 * capacity
        severe_low_stock = stock < 0.2 * capacity
        remaining_rounds = self.r - round_number
        if remaining_rounds <= 1:
            if stock >= 0.2 * capacity:
                self.last_choice = Action.C
                return Action.C
            if last_rate <= 0.0 and stock < 0.2 * capacity:
                self.last_choice = Action.D
                self.last_defect_round = round_number
                return Action.D
            self.last_choice = Action.C
            return Action.C
        if remaining_rounds == 2 and stock >= 0.2 * capacity:
            self.last_choice = Action.C
            return Action.C
        if high_stock:
            self.last_choice = Action.C
            return Action.C
        if self.last_choice == Action.D:
            if not (last_rate < 1.0 / 3.0 and stock < capacity / 3.0):
                self.last_choice = Action.C
                return Action.C
        if avg_recent >= 2.0 / 3.0:
            self.last_choice = Action.C
            return Action.C
        if moderate_stock:
            if avg_recent >= 1.0 / 3.0:
                self.last_choice = Action.C
                return Action.C
            if round_number - self.last_defect_round >= 2:
                self.last_choice = Action.D
                self.last_defect_round = round_number
                return Action.D
            self.last_choice = Action.C
            return Action.C
        if low_stock:
            persistent_defection = avg_recent < 1.0 / 3.0 and prev_rate < 1.0 / 3.0
            if persistent_defection and (self.last_choice != Action.D or round_number - self.last_defect_round >= 2):
                self.last_choice = Action.D
                self.last_defect_round = round_number
                return Action.D
            self.last_choice = Action.C
            return Action.C
        if avg_recent < 1.0 / 3.0:
            if prev_rate < 1.0 / 3.0 or prev2_rate < 1.0 / 3.0:
                if self.last_choice != Action.D and round_number - self.last_defect_round >= 2:
                    self.last_choice = Action.D
                    self.last_defect_round = round_number
                    return Action.D
        self.last_choice = Action.C
        return Action.C

class Strategy_BENEVOLENT_107(BaseStrategy):
    """
    Always cooperates in every round, regardless of history or current stock.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        return Action.C

class Strategy_BENEVOLENT_108(BaseStrategy):
    """
    Always cooperates, regardless of history or current stock.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        return Action.C

class Strategy_BENEVOLENT_109(BaseStrategy):
    """
    Cooperative-by-default common pool strategy:
    - Start with cooperation.
    - Continue cooperating when recent opponent cooperation is at least a majority
      and the stock remains healthy.
    - Defect when the stock is too depleted or cooperation has collapsed.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(self.n_players - 1, 0)
        self.majority_threshold = math.ceil(self.n_opponents / 2) if self.n_opponents > 0 else 0
        self.extreme_depletion_threshold = self.capacity / max(2 * self.n_players, 1)
        self.healthy_stock_threshold = self.capacity / 2.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        stock = float(current_stock)
        if stock <= 0.0 or stock <= self.extreme_depletion_threshold:
            return Action.D
        if round_number == 0:
            return Action.C
        last_cooperators = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        if round_number >= self.n_rounds - 1:
            return Action.C if last_cooperators >= self.majority_threshold else Action.D
        if len(history.opponent_cooperators) >= 2:
            prev_cooperators = int(history.opponent_cooperators[-2])
            if prev_cooperators < self.majority_threshold and last_cooperators < self.majority_threshold:
                return Action.D
        if last_cooperators >= self.majority_threshold and stock >= self.healthy_stock_threshold:
            return Action.C
        return Action.D

class Strategy_BENEVOLENT_110(BaseStrategy):
    """
    Cooperate by default, and defect only as a corrective move when depletion
    is already likely. The strategy tracks the last observed opponent cooperation
    count and uses current stock to steer toward the sustainable middle region.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.m = max(self.n - 1, 0)
        self.half_capacity = self.capacity / 2.0
        self.quarter_capacity = self.capacity / 4.0
        self.three_quarter_capacity = 3.0 * self.capacity / 4.0
        self.sixth_capacity = self.capacity / 6.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        if round_number == 0:
            return Action.C
        if round_number >= self.r - 1:
            return Action.D if current_stock <= self.sixth_capacity else Action.C
        if len(history.opponent_cooperators) == 0:
            k_prev = self.m
        else:
            k_prev = int(history.opponent_cooperators[-1])
        if self.n <= 0:
            return Action.C
        S = float(current_stock)
        if S <= self.quarter_capacity:
            return Action.C
        if k_prev <= self.m / 3.0:
            return Action.C if S >= self.three_quarter_capacity else Action.D
        if k_prev >= 2.0 * self.m / 3.0:
            return Action.C
        denom_c = 2.0 * self.n
        denom_d = float(self.n)
        S_C = S - (k_prev + 1.0) * S / denom_c - (self.m - k_prev) * S / denom_d
        S_D = S - k_prev * S / denom_c - (self.m - k_prev + 1.0) * S / denom_d
        dist_c = abs(S_C - self.half_capacity)
        dist_d = abs(S_D - self.half_capacity)
        if dist_c <= dist_d:
            return Action.C
        return Action.D

class Strategy_BENEVOLENT_111(BaseStrategy):
    """
    State-dependent reciprocity with a protection floor:
    - Cooperate initially.
    - Cooperate when the previous round had a cooperative majority and stock is not low.
    - Defect under low stock or when cooperation was insufficient.
    - Maintain a defensive mode after observing insufficient cooperation.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.m = max(0, self.n - 1)
        self.f_threshold = int(math.ceil(self.m / 2)) if self.m > 0 else 0
        self._last_seen_round = -1
        self._defect_mode = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = int(history.round_number) + 1
        if history.round_number == 0:
            self._defect_mode = False
            self._last_seen_round = 0
            return Action.C
        c_prev = None
        if hasattr(history, 'opponent_cooperators') and len(history.opponent_cooperators) > 0:
            c_prev = int(history.opponent_cooperators[-1])
        if c_prev is None:
            action = Action.C if current_stock >= 0.5 * self.capacity * (t / max(1, self.r)) else Action.D
            self._defect_mode = action == Action.D
            self._last_seen_round = history.round_number
            return action
        majority_threshold = self.f_threshold
        cooperative_majority = c_prev >= majority_threshold
        if current_stock <= self.capacity / 4.0:
            self._defect_mode = True
            self._last_seen_round = history.round_number
            return Action.D
        if t >= self.r:
            action = Action.C if cooperative_majority else Action.D
            self._defect_mode = not cooperative_majority
            self._last_seen_round = history.round_number
            return action
        if not cooperative_majority:
            self._defect_mode = True
        else:
            self._defect_mode = False
        if current_stock >= 0.75 * self.capacity and cooperative_majority:
            self._last_seen_round = history.round_number
            return Action.C
        if self._defect_mode:
            self._last_seen_round = history.round_number
            return Action.D
        stock_threshold = 0.5 * self.capacity * (t / max(1, self.r))
        action = Action.C if cooperative_majority and current_stock >= stock_threshold else Action.D
        self._last_seen_round = history.round_number
        return action

class Strategy_BENEVOLENT_112(BaseStrategy):
    """
    Benevolent common-pool strategy:
    - Cooperates by default.
    - Uses a brief defection signal only when stock is low and prior cooperation collapsed.
    - Returns to cooperation immediately once cooperation or stock recovers.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(0, self.n_players - 1)
        self.half_capacity = self.capacity / 2.0
        self.quarter_capacity = self.capacity / 4.0
        self.two_thirds_threshold = 2.0 / 3.0
        self.one_third_threshold = 1.0 / 3.0
        self.half_threshold = 0.5

    def _opponent_coop_ratio(self, history: PlayerHistory) -> float:
        if history.round_number <= 0 or self.n_opponents <= 0:
            return 1.0
        last_coop = int(history.opponent_cooperators[-1])
        if self.n_players == 2:
            return 1.0 if last_coop >= 1 else 0.0
        denom = float(self.n_opponents)
        return max(0.0, min(1.0, last_coop / denom))

    def _previous_severe_collapse(self, history: PlayerHistory) -> bool:
        if history.round_number <= 0 or self.n_opponents <= 0:
            return False
        if self.n_players == 2:
            return int(history.opponent_cooperators[-1]) <= 0
        return self._opponent_coop_ratio(history) < self.one_third_threshold

    def _previous_half_cooperation(self, history: PlayerHistory) -> bool:
        if history.round_number <= 0 or self.n_opponents <= 0:
            return True
        if self.n_players == 2:
            return int(history.opponent_cooperators[-1]) >= 1
        return self._opponent_coop_ratio(history) >= self.half_threshold

    def _previous_two_thirds_cooperation(self, history: PlayerHistory) -> bool:
        if history.round_number <= 0 or self.n_opponents <= 0:
            return True
        if self.n_players == 2:
            return int(history.opponent_cooperators[-1]) >= 1
        return self._opponent_coop_ratio(history) >= self.two_thirds_threshold

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        stock = float(current_stock)
        if history.round_number == 0:
            return Action.C
        if stock >= self.capacity:
            return Action.C
        if history.round_number > 0 and self._previous_two_thirds_cooperation(history):
            return Action.C
        prev_severe_collapse = self._previous_severe_collapse(history)
        prev_half_coop = self._previous_half_cooperation(history)
        prev_coop_ratio = self._opponent_coop_ratio(history)
        if history.round_number >= self.n_rounds - 1:
            if stock < self.quarter_capacity and prev_severe_collapse:
                return Action.D
            return Action.C
        if stock >= self.half_capacity:
            return Action.C
        if stock >= self.quarter_capacity:
            if prev_half_coop:
                return Action.C
            if prev_coop_ratio >= self.two_thirds_threshold:
                return Action.C
            return Action.D
        if stock <= 0.0:
            if prev_severe_collapse and history.round_number > 1:
                return Action.D
            return Action.C
        if prev_severe_collapse:
            return Action.D
        return Action.C

class Strategy_BENEVOLENT_113(BaseStrategy):
    """
    Always cooperate in every round, regardless of history, stock, or round number.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self._n_players = getattr(game_description, 'n_players', 0)
        self._n_rounds = getattr(game_description, 'n_rounds', 0)
        self._capacity = getattr(game_description, 'capacity', 0)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        return Action.C

class Strategy_BENEVOLENT_114(BaseStrategy):
    """
    Always cooperate in every round, regardless of history, stock level, or opponents' behavior.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        return Action.C

class Strategy_BENEVOLENT_115(BaseStrategy):
    """
    Cooperative default strategy for the Common Pool Resource Game.

    - Starts with C.
    - Uses the aggregate cooperation of opponents from the previous round.
    - Defects only temporarily after repeated low cooperation, with stricter
      recovery rules when the stock is low.
    - Always cooperates in the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.coop_threshold = int(math.ceil((self.n_players - 1) / 2))
        self.low_stock_threshold = self.capacity / 2.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        if round_number >= self.n_rounds - 1:
            return Action.C
        if round_number == 0:
            return Action.C
        last_c = int(history.opponent_cooperators[-1])
        prev_c = int(history.opponent_cooperators[-2]) if round_number >= 2 else None
        last_action = bool(history.my_actions[-1])
        prev_action = bool(history.my_actions[-2]) if round_number >= 2 else None
        last_good = last_c >= self.coop_threshold
        prev_good = prev_c >= self.coop_threshold if prev_c is not None else False
        low_stock = float(current_stock) < self.low_stock_threshold
        if last_action == Action.C:
            if low_stock:
                if not last_good and prev_c is not None and (not prev_good) or last_c == 0:
                    return Action.D
                return Action.C
            else:
                if prev_c is not None and (not last_good) and (not prev_good):
                    return Action.D
                if last_c == 0 and prev_c is not None and (prev_c == 0):
                    return Action.D
                return Action.C
        if last_action == Action.D:
            if low_stock:
                if last_good and prev_c is not None and prev_good:
                    return Action.C
                return Action.D
            else:
                if last_good:
                    return Action.C
                if prev_action == Action.D:
                    return Action.C
                return Action.D
        return Action.C

class Strategy_BENEVOLENT_116(BaseStrategy):
    """
    Cooperative default strategy with brief, state-sensitive defection:
    start with C, defect only as a short conservation response to low stock
    or low opponent cooperation, and return to C quickly as conditions improve.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(self.n_players - 1, 1)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        if round_number == 0:
            return Action.C
        in_final_two_rounds = round_number >= max(self.n_rounds - 2, 0)
        if in_final_two_rounds:
            return Action.C
        last_my_action = bool(history.my_actions[-1])
        last_two_defections = False
        if round_number >= 2:
            last_two_defections = not bool(history.my_actions[-1]) and (not bool(history.my_actions[-2]))
        last_opponent_cooperators = int(history.opponent_cooperators[-1])
        q_t = last_opponent_cooperators / self.n_opponents if self.n_opponents > 0 else 1.0
        if last_two_defections:
            return Action.C
        if self.capacity > 0 and current_stock < self.capacity / 5.0:
            return Action.D
        if not last_my_action:
            if q_t >= 0.5 or (self.capacity > 0 and current_stock >= self.capacity / 2.0):
                return Action.C
            return Action.D
        if q_t >= 0.5 and (self.capacity <= 0 or current_stock >= self.capacity / 3.0):
            return Action.C
        return Action.D

class Strategy_BENEVOLENT_117(BaseStrategy):
    """
    Cooperative baseline strategy with temporary defensive defections when
    opponents repeatedly overexploit the common pool or stock becomes low.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(0, self.n_players - 1)
        self._floor_third = math.floor(self.n_opponents / 3) if self.n_opponents > 0 else 0
        self._ceil_half = math.ceil(self.n_opponents / 2) if self.n_opponents > 0 else 0
        self._stock_trigger_threshold = self.capacity / 3.0 if self.capacity > 0 else 0.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number
        if t == 0 or t >= self.n_rounds - 1:
            return Action.C
        if t >= 1 and current_stock <= self._stock_trigger_threshold:
            last_cooperators = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) >= 1 else self.n_opponents
            if last_cooperators < self._ceil_half:
                return Action.D
        if t >= 2 and len(history.opponent_cooperators) >= 2:
            k_t1 = int(history.opponent_cooperators[-1])
            k_t2 = int(history.opponent_cooperators[-2])
            if k_t1 <= self._floor_third and k_t2 <= self._floor_third:
                return Action.D
        return Action.C

class Strategy_BENEVOLENT_118(BaseStrategy):
    """
    Adaptive cooperation strategy for the Common Pool Resource Game.

    - Starts by cooperating.
    - Cooperates on the final round.
    - Otherwise, cooperates when the number of cooperating opponents in the
      previous round meets a dynamic threshold based on majority rule and
      current stock health.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(getattr(game_description, 'n_players', 0) or 0)
        self.n_rounds = int(getattr(game_description, 'n_rounds', 0) or 0)
        self.capacity = float(getattr(game_description, 'capacity', 0.0) or 0.0)
        self.n_opponents = max(0, self.n_players - 1)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(getattr(history, 'round_number', 0) or 0)
        if round_number == 0:
            return Action.C
        if self.n_rounds > 0 and round_number >= self.n_rounds - 1:
            return Action.C
        if self.capacity > 0 and current_stock >= self.capacity:
            return Action.C
        opp_hist = getattr(history, 'opponent_cooperators', None)
        if opp_hist is None or len(opp_hist) == 0:
            return Action.C
        prev_cooperators = int(opp_hist[-1])
        if self.n_players == 2:
            tau = 1
        else:
            m = self.n_opponents
            tau = math.ceil(m / 2) if m > 0 else 0
            if self.capacity > 0:
                if current_stock < 0.15 * self.capacity:
                    tau = 0
                elif current_stock < 0.3 * self.capacity:
                    tau = max(0, tau - 1)
        return Action.C if prev_cooperators >= tau else Action.D

class Strategy_BENEVOLENT_119(BaseStrategy):
    """
    Forgiving common-pool strategy:
    - Start by cooperating.
    - Cooperate when stock is low or depleted.
    - Defect only after two consecutive previous rounds with opponent cooperation below 1/2,
      and only while stock is above half capacity.
    - Always cooperate on the last round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_players = int(game_description.n_players)
        self.n_opponents = max(self.n_players - 1, 1)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        if round_number == 0:
            return Action.C
        if round_number >= self.n_rounds - 1:
            return Action.C
        if current_stock <= 0:
            return Action.C
        if current_stock <= self.capacity / 2:
            return Action.C
        bad_streak = 0
        coop_counts = history.opponent_cooperators
        idx = round_number - 1
        while idx >= 0:
            rho = 0.0
            if self.n_opponents > 0:
                rho = float(coop_counts[idx]) / float(self.n_opponents)
            if rho < 0.5:
                bad_streak += 1
                idx -= 1
            else:
                break
        if bad_streak >= 2:
            return Action.D
        return Action.C

class Strategy_BENEVOLENT_120(BaseStrategy):
    """
    Unconditional cooperation strategy for the Common Pool Resource Game.
    Always plays C, regardless of history, stock level, or opponent behavior.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(getattr(game_description, 'n_players', 0) or 0)
        self.n_rounds = int(getattr(game_description, 'n_rounds', 0) or 0)
        self.capacity = float(getattr(game_description, 'capacity', 0) or 0.0)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        return Action.C

class Strategy_BENEVOLENT_121(BaseStrategy):
    """
    Stock-aware conditional cooperator:
    - Cooperate in round 1.
    - Thereafter, cooperate only when the stock is healthy enough and the
      previous round's observed cooperation rate was at least 1/2.
    - Otherwise defect immediately to protect the common pool.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self._capacity = float(game_description.capacity)
        self._n_players = int(game_description.n_players)
        self._conservation_threshold = 2.0 / 3.0 * self._capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        stock_ok = float(current_stock) >= self._conservation_threshold
        n_opponents = max(self._n_players - 1, 1)
        last_opponent_cooperators = int(history.opponent_cooperators[-1])
        q = last_opponent_cooperators / n_opponents
        if stock_ok and q >= 0.5:
            return Action.C
        return Action.D

class Strategy_BENEVOLENT_122(BaseStrategy):
    """
    Always cooperate: play C in every round, regardless of history or stock.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self._cooperate = Action.C

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        return self._cooperate

class Strategy_BENEVOLENT_123(BaseStrategy):
    """
    Always cooperate in every round, regardless of history or current stock.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        return Action.C

class Strategy_BENEVOLENT_124(BaseStrategy):
    """
    Cautious cooperative commons-preservation strategy.

    - Cooperates in the first round.
    - Prefers cooperation when the pool is healthy or recovering.
    - Temporarily defects only when opponents are persistently exploitative
      and the stock is drifting toward collapse.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.safety_threshold = self.capacity / 4.0
        self.stability_tolerance = 0.02 * self.capacity
        self.soft_recovery_threshold = self.capacity / 3.0
        self.n_opponents = max(self.n - 1, 1)
        self.last_action = Action.C
        self.defensive_mode = False
        self.prev_seen_stock = None
        self.prev_predicted_next_stock = None

    def _predicted_next_stock_if_cooperate(self, current_stock: float, opp_cooperators: int) -> float:
        n = self.n
        capacity = self.capacity
        S = max(0.0, float(current_stock))
        coop_count_total = int(opp_cooperators) + 1
        defect_count_total = n - coop_count_total
        per_coop = S / (2.0 * n) if n > 0 else 0.0
        per_defect = S / n if n > 0 else 0.0
        total_consumption = coop_count_total * per_coop + defect_count_total * per_defect
        remaining = max(0.0, S - total_consumption)
        growth = 2.0 * remaining * (1.0 - remaining / capacity) if capacity > 0 else 0.0
        next_stock = min(remaining + growth, capacity)
        return max(0.0, next_stock)

    def _predicted_remaining_if_cooperate(self, current_stock: float, opp_cooperators: int) -> float:
        n = self.n
        S = max(0.0, float(current_stock))
        coop_count_total = int(opp_cooperators) + 1
        defect_count_total = n - coop_count_total
        per_coop = S / (2.0 * n) if n > 0 else 0.0
        per_defect = S / n if n > 0 else 0.0
        total_consumption = coop_count_total * per_coop + defect_count_total * per_defect
        return max(0.0, S - total_consumption)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        S = max(0.0, float(current_stock))
        if round_number == 0:
            self.last_action = Action.C
            self.prev_seen_stock = S
            self.prev_predicted_next_stock = None
            self.defensive_mode = False
            return Action.C
        opp_last = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        coop_rate_last = opp_last / self.n_opponents if self.n_opponents > 0 else 0.0
        predicted_next_if_c = self._predicted_next_stock_if_cooperate(S, opp_last)
        predicted_remaining_if_c = self._predicted_remaining_if_cooperate(S, opp_last)
        stock_dropped_sharply = False
        stock_stable_or_increasing = False
        if self.prev_seen_stock is not None:
            delta = S - float(self.prev_seen_stock)
            stock_stable_or_increasing = delta >= -1e-12
            stock_dropped_sharply = delta < -self.stability_tolerance
        if stock_stable_or_increasing:
            self.defensive_mode = False
        if round_number >= self.r - 1:
            if S <= 0.0:
                self.last_action = Action.C
                self.prev_seen_stock = S
                self.prev_predicted_next_stock = predicted_next_if_c
                return Action.C
            persistent_defection = False
            if len(history.opponent_cooperators) >= 3:
                recent = history.opponent_cooperators[-3:]
                persistent_defection = all(((x / self.n_opponents if self.n_opponents > 0 else 0.0) < 0.5 for x in recent))
            if persistent_defection and S <= self.safety_threshold / 2.0:
                self.last_action = Action.D
                self.prev_seen_stock = S
                self.prev_predicted_next_stock = predicted_next_if_c
                return Action.D
            self.last_action = Action.C
            self.prev_seen_stock = S
            self.prev_predicted_next_stock = predicted_next_if_c
            return Action.C
        if S <= self.safety_threshold:
            action = Action.C if predicted_remaining_if_c > 0.0 else Action.D
            if S == 0.0:
                action = Action.C
        else:
            coop_last_two = False
            if len(history.opponent_cooperators) >= 2:
                last_two = history.opponent_cooperators[-2:]
                coop_last_two = all(((x / self.n_opponents if self.n_opponents > 0 else 0.0) >= 2.0 / 3.0 for x in last_two))
            if coop_rate_last >= 0.5:
                action = Action.C
            elif coop_last_two and S > self.soft_recovery_threshold:
                action = Action.C
            elif stock_dropped_sharply and coop_rate_last < 0.5 and (S < self.soft_recovery_threshold):
                self.defensive_mode = True
                action = Action.D
            elif self.defensive_mode:
                if coop_rate_last >= 0.5 or S > self.soft_recovery_threshold:
                    self.defensive_mode = False
                    action = Action.C
                else:
                    action = Action.D
            elif predicted_next_if_c >= S - self.stability_tolerance:
                action = Action.C
            else:
                action = Action.D
        if stock_stable_or_increasing and action == Action.D and (S > 0.0):
            action = Action.C
        self.last_action = action
        self.prev_seen_stock = S
        self.prev_predicted_next_stock = predicted_next_if_c
        return action

class Strategy_BENEVOLENT_125(BaseStrategy):
    """
    Cautious conditional cooperator for the Common Pool Resource Game.

    - Cooperates in round 1 and the final round.
    - Tracks recent opponent cooperation rates.
    - Defects only when the stock is low and opponents have shown
      sustained low cooperation for the last two available rounds.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(1, self.n_players - 1)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        if round_number == 0:
            return Action.C
        if round_number >= self.n_rounds - 1:
            return Action.C
        if current_stock > self.capacity / 3.0:
            return Action.C
        opp_counts = history.opponent_cooperators
        if len(opp_counts) == 0:
            return Action.C
        recent_counts = opp_counts[-3:]
        recent_rates = [float(x) / float(self.n_opponents) for x in recent_counts]
        rho_bar = float(np.mean(recent_rates)) if len(recent_rates) > 0 else 1.0
        if rho_bar >= 1.0 / 3.0:
            return Action.C
        last_two = opp_counts[-2:]
        if len(last_two) < 2:
            return Action.C
        low_last_two = True
        threshold = float(self.n_opponents) / 3.0
        for count in last_two:
            rho = float(count) / float(self.n_opponents)
            if rho >= 1.0 / 3.0:
                low_last_two = False
                break
        if low_last_two:
            return Action.D
        return Action.C

class Strategy_BENEVOLENT_126(BaseStrategy):
    """
    Cooperative default strategy for the Common Pool Resource Game.

    - Cooperate by default.
    - Track streaks of opponent cooperation from history.
    - Defect at most one round after sustained low cooperation and only when
      the stock is still sufficiently healthy.
    - Recover to cooperation immediately after meaningful improvement.
    - Cooperate in the final round, with a special edge-case rule for r=2.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.mode = 'cooperative'
        self.bad_streak = 0
        self.good_streak = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_rounds = self.game_description.n_rounds
        capacity = float(self.game_description.capacity)
        round_number = history.round_number

        def update_streaks_from_last_round() -> None:
            if round_number <= 0:
                return
            n_players = max(int(self.game_description.n_players), 2)
            n_opponents = max(n_players - 1, 1)
            last_cooperators = int(history.opponent_cooperators[-1])
            q = last_cooperators / n_opponents
            if q >= 0.75:
                self.good_streak += 1
                self.bad_streak = 0
            elif q <= 0.5:
                self.bad_streak += 1
                self.good_streak = 0
            else:
                self.good_streak = 0
                self.bad_streak = 0
        self.good_streak = 0
        self.bad_streak = 0
        for t in range(round_number):
            n_players = max(int(self.game_description.n_players), 2)
            n_opponents = max(n_players - 1, 1)
            q = float(history.opponent_cooperators[t]) / n_opponents
            if q >= 0.75:
                self.good_streak += 1
                self.bad_streak = 0
            elif q <= 0.5:
                self.bad_streak += 1
                self.good_streak = 0
            else:
                self.good_streak = 0
                self.bad_streak = 0
        if round_number == 0:
            self.mode = 'cooperative'
            return Action.C
        if current_stock <= 0.0:
            self.mode = 'cooperative'
            return Action.C
        if round_number == n_rounds - 1:
            if n_rounds == 2:
                if current_stock < capacity / 3.0 and self.bad_streak >= 2:
                    self.mode = 'defecting'
                    return Action.D
            self.mode = 'cooperative'
            return Action.C
        n_players = max(int(self.game_description.n_players), 2)
        n_opponents = max(n_players - 1, 1)
        last_q = float(history.opponent_cooperators[-1]) / n_opponents
        if history.my_actions[-1] is False and last_q >= 0.75:
            self.mode = 'cooperative'
            return Action.C
        threshold_stock = capacity / 3.0
        if current_stock >= threshold_stock:
            if self.bad_streak >= 2:
                self.mode = 'defecting'
                return Action.D
            self.mode = 'cooperative'
            return Action.C
        if self.good_streak >= 1:
            self.mode = 'cooperative'
            return Action.C
        if self.bad_streak >= 2:
            self.mode = 'defecting'
            return Action.D
        self.mode = 'cooperative'
        return Action.C

class Strategy_BENEVOLENT_127(BaseStrategy):
    """
    Unconditional cooperation strategy for the common pool resource game.
    Always plays C in every round, including when the stock is depleted.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        return Action.C

class Strategy_BENEVOLENT_128(BaseStrategy):
    """
    Always cooperate in every round.
    Records the observed number of cooperating opponents, but does not
    change its action based on history or stock.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.observed_opponent_cooperators = []

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_players = getattr(self.game_description, 'n_players', 0)
        n_opponents = max(0, n_players - 1)
        if history.round_number > 0:
            last_count = int(history.opponent_cooperators[-1])
            if last_count < 0:
                last_count = 0
            elif last_count > n_opponents:
                last_count = n_opponents
            self.observed_opponent_cooperators.append(last_count)
        return Action.C

class Strategy_SELFISH_33(BaseStrategy):
    """
    Common pool strategy:
    - Defect by default.
    - Cooperate only when the stock is fragile and recent behavior suggests
      near-universal cooperation.
    - Never cooperate in the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        last_round_index = self.r - 1
        if round_number == 0:
            return Action.D
        if round_number >= last_round_index:
            return Action.D
        S = float(current_stock)
        cap = self.capacity
        n = self.n
        m = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        prev_my_action = bool(history.my_actions[-1]) if len(history.my_actions) > 0 else False
        k = m + 1 if prev_my_action else m
        if len(history.opponent_cooperators) >= 2:
            c = int(history.opponent_cooperators[-2])
        else:
            c = m
        n_opponents = n - 1
        if m < 0 or m > n_opponents or c < 0 or (c > n_opponents):
            return Action.D
        cap_half = cap / 2.0
        cap_quarter = cap / 4.0
        cap_eighth = cap / 8.0
        if S >= cap_half:
            return Action.D
        if S > cap_quarter and k <= n - 2:
            return Action.D
        if S <= cap_eighth and k >= n - 1:
            return Action.C
        if cap_eighth < S < cap_quarter and k >= n - 1 and (c >= n - 2):
            return Action.C
        return Action.D

class Strategy_SELFISH_34(BaseStrategy):
    """
    Defect-oriented common-pool strategy with state-sensitive cooperation:
    - Never cooperate in the last round.
    - In the second-to-last round, cooperate only when the stock is low and
      prior opponents were sufficiently cooperative.
    - Earlier rounds: cooperate mainly to preserve a low stock; otherwise defect
      when opponents are defecting or when the stock is still high.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity) if game_description.capacity else 1.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = int(history.round_number)
        r = self.n_rounds
        capacity = self.capacity if self.capacity > 0 else 1.0
        x = float(current_stock) / capacity
        q = 1.0
        if t > 0:
            try:
                prev_coop = float(history.opponent_cooperators[-1])
                denom = float(max(self.n_players - 1, 1))
                q = prev_coop / denom
            except Exception:
                q = 0.0
        if x < 0.0:
            x = 0.0
        elif x > 1.0:
            x = 1.0
        if q < 0.0:
            q = 0.0
        elif q > 1.0:
            q = 1.0
        if t >= r - 1:
            return Action.D
        if t == r - 2:
            if x <= 0.25 and q >= 0.5:
                return Action.C
            return Action.D
        if x <= 0.25:
            return Action.C
        elif q <= 0.25:
            return Action.D
        elif q >= 0.75 and x >= 0.6:
            return Action.D
        elif 0.25 < x < 0.6:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_35(BaseStrategy):
    """
    Threshold-based common-pool strategy:
    - Defect in round 1 and in the final round.
    - In intermediate rounds, defect when the stock is high.
    - When stock is medium or low, cooperate only if recent cooperation is sufficiently strong.
    - If stock is depleted, cooperate while waiting for recovery signals, but revert to defect
      as soon as stock recovers or cooperation falls below the relevant threshold.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.two_thirds_capacity = 2.0 * self.capacity / 3.0
        self.one_third_capacity = self.capacity / 3.0
        self.half_ceiling = math.ceil(self.n / 2.0)
        self.no_history_fallback = Action.D

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        if round_number == 0:
            return Action.D
        if round_number >= self.r - 1:
            return Action.D
        try:
            c_prev = int(history.opponent_cooperators[-1])
            last_my_action = bool(history.my_actions[-1])
        except Exception:
            return self.no_history_fallback
        m_prev = c_prev + 1 if last_my_action else c_prev
        if current_stock <= 0.0:
            if m_prev >= self.half_ceiling:
                return Action.C
            return Action.D
        if current_stock > self.two_thirds_capacity:
            return Action.D
        if self.one_third_capacity < current_stock <= self.two_thirds_capacity:
            if m_prev == self.n and c_prev >= self.n - 1:
                return Action.C
            return Action.D
        if current_stock <= self.one_third_capacity:
            if m_prev >= self.half_ceiling:
                return Action.C
            return Action.D
        return self.no_history_fallback

class Strategy_SELFISH_36(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Starts cooperative
    - Tracks an exponential moving average of opponent cooperation
    - Defects in the final round
    - Uses stock and recent cooperation thresholds to decide whether to cooperate
    - Falls back to defection under low support or low stock
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.p_hat = 0.5
        self.last_coop_share = None
        self.last_processed_round = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_players = int(self.game_description.n_players)
        n_rounds = int(self.game_description.n_rounds)
        opponents = max(n_players - 1, 1)
        current_round = int(history.round_number) + 1
        if history.round_number > self.last_processed_round:
            start = self.last_processed_round
            end = history.round_number
            for idx in range(start, end):
                obs = float(history.opponent_cooperators[idx]) / float(opponents)
                self.p_hat = 0.7 * self.p_hat + 0.3 * obs
                self.last_coop_share = obs
            self.last_processed_round = history.round_number
        stock_ratio = 0.0
        if self.game_description.capacity > 0:
            stock_ratio = float(current_stock) / float(self.game_description.capacity)
        if current_round >= n_rounds:
            return Action.D
        if current_round == 1:
            return Action.C
        last_obs = None
        prev_obs = None
        if history.round_number >= 1:
            last_obs = float(history.opponent_cooperators[-1]) / float(opponents)
        if history.round_number >= 2:
            prev_obs = float(history.opponent_cooperators[-2]) / float(opponents)
        recent_support = self.p_hat
        if last_obs is not None:
            recent_support = 0.5 * (last_obs + self.p_hat)
        if current_round == n_rounds - 1:
            if stock_ratio >= 0.7 and last_obs is not None and (prev_obs is not None) and (last_obs >= 0.75) and (prev_obs >= 0.75):
                return Action.C
            return Action.D
        if stock_ratio < 0.2:
            return Action.D
        if stock_ratio >= 0.35 and recent_support >= 0.5 and (last_obs is not None) and (last_obs >= 0.5):
            return Action.C
        return Action.D

class Strategy_SELFISH_37(BaseStrategy):
    """
    Common Pool Resource strategy:
    - Defect in the first round and the last round.
    - In intermediate rounds, cooperate when the stock is low, or when it is moderate
      and opponents were sufficiently uncooperative in the immediately previous round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        last_round_index = self.n_rounds - 1
        if round_number == 0 or round_number == last_round_index:
            return Action.D
        prev_opponent_cooperators = 0
        if len(history.opponent_cooperators) > 0:
            prev_opponent_cooperators = int(history.opponent_cooperators[-1])
        n_opponents = max(self.n_players - 1, 1)
        q = prev_opponent_cooperators / n_opponents
        if current_stock <= self.capacity / 3.0:
            return Action.C
        if current_stock <= self.capacity / 2.0 and q < 0.5:
            return Action.C
        return Action.D

class Strategy_SELFISH_38(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Cooperate in the first round.
    - Defect in the last round.
    - Otherwise switch based on current stock and previous round's observed cooperation.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.last_round_index = max(self.r - 1, 0)
        self.half_capacity = self.capacity / 2.0
        self.coop_threshold_low = math.ceil((self.n - 1) / 2) if self.n > 1 else 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = int(history.round_number)
        if t == 0:
            return Action.C
        if t >= self.last_round_index:
            return Action.D
        if current_stock <= 0.0:
            return Action.D
        c_prev = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        if current_stock <= self.half_capacity:
            return Action.C if c_prev >= self.coop_threshold_low else Action.D
        else:
            return Action.C if c_prev == max(self.n - 1, 0) else Action.D

class Strategy_SELFISH_39(BaseStrategy):
    """
    Default to defection, and cooperate only when the current stock is low enough
    that preserving the common pool is instrumentally useful for future rounds.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self._quarter = self.capacity / 4.0
        self._half = self.capacity / 2.0
        self._ceil_half_n = math.ceil(self.n / 2.0)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number
        if t == 0 or t == self.r - 1:
            return Action.D
        last_my_action = bool(history.my_actions[-1])
        m = int(history.opponent_cooperators[-1])
        k_total_last_round = m + (1 if last_my_action else 0)
        stock = float(current_stock)
        if stock < self._quarter:
            return Action.C
        if stock < self._half:
            return Action.C if k_total_last_round > self._ceil_half_n else Action.D
        if stock > self._half:
            return Action.C if k_total_last_round > self.n - 1 else Action.D
        return Action.D

class Strategy_SELFISH_40(BaseStrategy):
    """
    Adaptive conditional cooperator for the common pool resource game.
    Starts with cooperation, then conditions on observed opponent cooperation,
    current stock, and remaining horizon with a strict endgame rule.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(0, self.n_players - 1)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        rounds_remaining = self.n_rounds - round_number
        if round_number == 0:
            return Action.C
        if rounds_remaining <= 1:
            return Action.D
        last_cooperators = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        if self.n_opponents > 0:
            q_last = last_cooperators / self.n_opponents
        else:
            q_last = 0.0
        if len(history.opponent_cooperators) > 0 and self.n_opponents > 0:
            q_rates = [int(x) / self.n_opponents for x in history.opponent_cooperators]
            avg_q = float(np.mean(q_rates)) if len(q_rates) > 0 else 0.0
        else:
            avg_q = 0.0
        threshold = max(0.5, avg_q + 0.1)
        if rounds_remaining == 2:
            if q_last == 1.0 and current_stock >= self.capacity:
                return Action.C
            return Action.D
        if current_stock <= self.capacity / 3.0:
            return Action.D
        if q_last >= threshold and current_stock >= self.capacity / 2.0 and (rounds_remaining >= 3):
            return Action.C
        return Action.D

class Strategy_SELFISH_41(BaseStrategy):
    """
    Stock-sensitive conditional cooperator/defector for the common pool resource game.

    Rules:
    - Round 1: cooperate if the game lasts more than 2 rounds, otherwise defect.
    - Final round: always defect.
    - Intermediate rounds: cooperate when stock is low, or when opponents were
      sufficiently uncooperative and stock is not safely high; otherwise defect.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.midpoint = self.capacity / 2.0
        self.upper_threshold = 3.0 * self.capacity / 4.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        if round_number >= self.n_rounds - 1:
            return Action.D
        if round_number == 0:
            return Action.C if self.n_rounds > 2 else Action.D
        opponents = getattr(history, 'opponent_cooperators', None)
        if opponents is None or len(opponents) == 0:
            return Action.C if float(current_stock) <= self.midpoint else Action.D
        x = opponents[-1]
        try:
            x_int = int(x)
        except Exception:
            x_int = 0
        n_opponents = self.n_players - 1
        if n_opponents <= 0:
            q = 0.0
        else:
            q = x_int / float(n_opponents)
        S = float(current_stock)
        if S <= self.midpoint:
            return Action.C
        if q < 0.5 and S <= self.upper_threshold:
            return Action.C
        return Action.D

class Strategy_SELFISH_42(BaseStrategy):
    """
    Common Pool Resource strategy:
    - Round 1: Defect.
    - Middle rounds: Cooperate only when stock is low enough and enough opponents cooperated last round,
      with a fast-collapse override for severe depletion.
    - Final round: Defect.
    - If prior-round information is unavailable, defect.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history is None:
            return Action.D
        round_number = getattr(history, 'round_number', 0)
        if round_number == 0:
            return Action.D
        if round_number >= self.n_rounds - 1:
            return Action.D
        try:
            prev_opponent_cooperators = history.opponent_cooperators[-1]
        except Exception:
            return Action.D
        n_opponents = self.n_players - 1
        if n_opponents <= 0:
            return Action.D
        try:
            q = float(prev_opponent_cooperators) / float(n_opponents)
        except Exception:
            return Action.D
        S = float(current_stock)
        cap = self.capacity
        if S <= cap / 5.0 and prev_opponent_cooperators >= 1:
            return Action.C
        if S <= cap / 3.0 and q >= 2.0 / 3.0:
            return Action.C
        return Action.D

class Strategy_SELFISH_43(BaseStrategy):
    """
    Hysteresis-based common pool strategy.

    - Defect on the first and last round.
    - In a low-stock regime, cooperate.
    - In a high-stock regime, defect.
    - In the middle band, follow the previous round's cooperation level among opponents.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(self.n_players - 1, 0)
        self.lower_threshold = self.capacity / 3.0
        self.upper_threshold = self.capacity / 2.0
        self.majority_threshold = math.ceil(self.n_opponents / 2.0) if self.n_opponents > 0 else 0
        self.stock_estimate = self.capacity
        self.last_round_seen = -1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        stock = float(current_stock)
        self.stock_estimate = stock
        self.last_round_seen = round_number
        if round_number == 0:
            return Action.D
        if round_number >= self.n_rounds - 1:
            return Action.D
        if stock <= self.lower_threshold:
            return Action.C
        if stock >= self.upper_threshold:
            return Action.D
        prev_cooperators = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        if prev_cooperators >= self.majority_threshold:
            return Action.D
        return Action.C

class Strategy_SELFISH_44(BaseStrategy):
    """
    Defect on the first and final rounds. In intermediate rounds, cooperate
    only as a recovery move when the stock is low or when opponents were not
    cooperating enough in the previous round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        if round_number == 0:
            return Action.D
        if round_number >= self.n_rounds - 1:
            return Action.D
        if len(history.opponent_cooperators) == 0:
            return Action.D
        if current_stock <= self.capacity / 3.0:
            return Action.C
        c = int(history.opponent_cooperators[-1])
        denom = max(self.n_players - 1, 1)
        f = c / denom
        if f >= 0.5:
            return Action.D
        return Action.C

class Strategy_SELFISH_45(BaseStrategy):
    """
    Stock-preservation threshold strategy with opponent-conditioned escalation.
    Cooperate early, keep cooperating only under strong opponent cooperation and
    healthy stock, and defect when exploitation or depletion is detected.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(self.n_players - 1, 1)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        current_round = round_number + 1
        if round_number == 0:
            return Action.C
        if current_stock <= 0:
            return Action.D
        last_opponent_cooperators = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        p_prev = last_opponent_cooperators / self.n_opponents if self.n_opponents > 0 else 0.0
        if current_round == self.n_rounds:
            if p_prev == 1.0 and current_stock >= self.capacity / 2.0:
                return Action.C
            return Action.D
        if current_stock < self.n_players:
            return Action.D
        if p_prev < 0.5:
            return Action.D
        last_my_action = bool(history.my_actions[-1]) if len(history.my_actions) > 0 else True
        if not last_my_action:
            if not (current_stock >= self.capacity / 2.0 and p_prev == 1.0):
                return Action.D
        if p_prev >= 0.75 and current_stock >= self.capacity / 4.0:
            return Action.C
        return Action.D

class Strategy_SELFISH_46(BaseStrategy):
    """
    Common-pool strategy that starts cooperatively, defects in the final round,
    and otherwise conditions cooperation on recent opponent cooperation and
    stock levels, with safeguards against collapse and overconsumption.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(self.n_players - 1, 1)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        if round_number == 0:
            return Action.C
        if round_number + 1 >= self.n_rounds:
            return Action.D
        last_opp_coop = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        q = last_opp_coop / self.n_opponents if self.n_opponents > 0 else 0.0
        s = current_stock / self.capacity if self.capacity > 0 else 0.0
        remaining_rounds = self.n_rounds - (round_number + 1)
        if q == 0.0:
            return Action.C if s >= 0.8 else Action.D
        if s <= 0.15:
            if remaining_rounds <= 2:
                return Action.C if q >= 0.8 and s >= 0.2 else Action.D
            return Action.C if q >= 0.8 else Action.D
        if s >= 0.85:
            return Action.C if q >= 2.0 / 3.0 else Action.D
        if q == 1.0 and s >= 0.7:
            return Action.C
        if q >= 2.0 / 3.0 and (s >= 1.0 / 3.0 or q >= 0.5):
            return Action.C
        return Action.D

class Strategy_SELFISH_47(BaseStrategy):
    """
    Cooperative common-pool strategy with an adaptive NORMAL/PUNITIVE mode,
    an exponential moving average of opponent cooperation, and late-game
    conservatism.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self._n = int(getattr(game_description, 'n_players', 2))
        self._r = int(getattr(game_description, 'n_rounds', 2))
        self._capacity = float(getattr(game_description, 'capacity', 0.0))
        self._n_opponents = max(self._n - 1, 1)
        self._q_hat = 1.0
        self._mode = 'NORMAL'
        self._punitive_streak = 0
        self._high_q_streak = 0
        self._processed_rounds = 0

    def _theta(self, stock: float) -> float:
        cap = self._capacity
        if stock >= 0.55 * cap:
            return 0.55 * cap
        if stock >= 0.4 * cap:
            return 0.4 * cap
        return 0.25 * cap

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        cap = self._capacity
        n_opponents = self._n_opponents
        if round_number > self._processed_rounds:
            start = self._processed_rounds
            end = round_number
            opp_counts = history.opponent_cooperators
            for idx in range(start, end):
                q_t = float(opp_counts[idx]) / float(n_opponents) if n_opponents > 0 else 1.0
                self._q_hat = 0.7 * self._q_hat + 0.3 * q_t
                if q_t < 0.6:
                    self._mode = 'PUNITIVE'
                    self._high_q_streak = 0
                else:
                    if q_t >= 0.8:
                        self._high_q_streak += 1
                    else:
                        self._high_q_streak = 0
                    if self._high_q_streak >= 2:
                        self._mode = 'NORMAL'
            self._processed_rounds = round_number
        if round_number == 0:
            self._punitive_streak = 0
            return Action.C
        if current_stock <= 0.0:
            self._punitive_streak = 0
            return Action.D
        last_q = 1.0
        if round_number > 0 and len(history.opponent_cooperators) > 0:
            last_q = float(history.opponent_cooperators[-1]) / float(n_opponents) if n_opponents > 0 else 1.0
        late = self._r - round_number <= 3
        theta = self._theta(current_stock)
        if current_stock < 0.1 * cap:
            if round_number >= 2 and len(history.opponent_cooperators) >= 2:
                q1 = float(history.opponent_cooperators[-1]) / float(n_opponents) if n_opponents > 0 else 1.0
                q2 = float(history.opponent_cooperators[-2]) / float(n_opponents) if n_opponents > 0 else 1.0
                if not (abs(q1 - 1.0) < 1e-12 and abs(q2 - 1.0) < 1e-12):
                    self._punitive_streak = 0
                    return Action.D
            else:
                self._punitive_streak = 0
                return Action.D
        if round_number >= self._r - 1:
            self._punitive_streak = 0
            return Action.D
        if round_number >= self._r - 3:
            if self._q_hat >= 0.85 and current_stock >= 0.55 * cap:
                self._punitive_streak = 0
                return Action.C
            self._punitive_streak = 0
            return Action.D
        if self._mode == 'PUNITIVE':
            if self._q_hat >= 0.8 and current_stock >= theta:
                self._punitive_streak += 1
                if self._punitive_streak >= 2:
                    if last_q < 0.6:
                        self._mode = 'PUNITIVE'
                    return Action.C
                return Action.D
            else:
                self._punitive_streak = 0
                return Action.D
        if not late and self._q_hat >= 0.7 and (current_stock >= theta):
            self._punitive_streak = 0
            return Action.C
        self._punitive_streak = 0
        return Action.D

class Strategy_SELFISH_48(BaseStrategy):
    """
    Threshold-based common-pool strategy:
    - Defect at the endgame.
    - Cooperate in low-stock zones to help recovery.
    - Otherwise react to previous-round cooperation, with a selfish bias toward defecting
      when signals conflict.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(getattr(game_description, 'n_players', 0) or 0)
        self.n_rounds = int(getattr(game_description, 'n_rounds', 0) or 0)
        self.capacity = float(getattr(game_description, 'capacity', 0) or 0.0)
        self.low = 0.25 * self.capacity
        self.high = 0.75 * self.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        m = self.n_rounds - int(getattr(history, 'round_number', 0))
        S = float(current_stock)
        if S <= 0.0:
            return Action.D
        if m <= 1:
            return Action.D
        if history.round_number == 0:
            return Action.C if self.n_rounds > 2 else Action.D
        opp_count = self.n_players - 1
        if opp_count <= 0:
            q = 1.0
        else:
            prev_opp = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) else 0
            q = prev_opp / float(opp_count)
            if q < 0.0:
                q = 0.0
            elif q > 1.0:
                q = 1.0
        if m == 2:
            return Action.C if S < self.high else Action.D
        if S <= self.low:
            return Action.C
        if S >= self.high and q >= 0.6:
            return Action.D
        if q < 0.5:
            return Action.D
        if q > 0.5:
            return Action.C
        return Action.D

class Strategy_SELFISH_49(BaseStrategy):
    """
    Conditional conservation strategy:
    - Defect by default.
    - Cooperate only when the stock is high and opponents cooperated enough in the prior round.
    - Always defect in the first, penultimate, and final rounds.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(getattr(game_description, 'n_players', 0) or 0)
        self.n_rounds = int(getattr(game_description, 'n_rounds', 0) or 0)
        self.capacity = float(getattr(game_description, 'capacity', 0.0) or 0.0)
        self.n_opponents = max(self.n_players - 1, 0)
        self.high_stock_threshold = 0.75 * self.capacity
        self.mid_stock_threshold = 0.5 * self.capacity
        self.low_stock_threshold = self.capacity / 3.0 if self.capacity is not None else 0.0
        self.high_coop_threshold = math.ceil(5 * self.n_opponents / 6) if self.n_opponents > 0 else 0
        self.mid_coop_threshold = math.ceil(2 * self.n_opponents / 3) if self.n_opponents > 0 else 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(getattr(history, 'round_number', 0) or 0)
        if round_number == 0:
            return Action.D
        if self.n_rounds - round_number <= 2:
            return Action.D
        if current_stock <= 0.0:
            return Action.D
        if current_stock <= self.low_stock_threshold:
            return Action.D
        if len(history.opponent_cooperators) == 0:
            return Action.D
        last_cooperators = int(history.opponent_cooperators[-1])
        if current_stock >= self.high_stock_threshold and last_cooperators >= self.high_coop_threshold:
            return Action.C
        if current_stock >= self.mid_stock_threshold and last_cooperators >= self.mid_coop_threshold:
            return Action.C
        return Action.D

class Strategy_SELFISH_50(BaseStrategy):
    """
    Conservative common-pool strategy:
    - Cooperate in round 1.
    - Cooperate only when all opponents cooperated last round and stock is high enough.
    - Defect in the final two rounds.
    - Enter recovery mode after a failed cooperation condition, and stay defecting
      until two consecutive "good" observations are seen.
    - A hard floor forces defection when stock is too low.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.recovery_mode = False
        self.recovery_good_streak = 0
        self.hard_floor_mode = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        n = self.n_players
        cap = self.capacity
        if round_number >= max(0, self.n_rounds - 2):
            return Action.D
        if round_number == 0:
            self.recovery_mode = False
            self.recovery_good_streak = 0
            self.hard_floor_mode = False
            return Action.C
        prev_k = 0
        if len(history.opponent_cooperators) > 0:
            prev_k = int(history.opponent_cooperators[-1])
        good_prev = prev_k == n - 1 and current_stock >= 0.9 * cap
        if self.hard_floor_mode:
            if current_stock <= cap / 3.0:
                self.recovery_good_streak = 0 if not good_prev else self.recovery_good_streak + 1
                return Action.D
            if not (current_stock > cap / 2.0 and self.recovery_good_streak >= 2):
                self.recovery_good_streak = 0 if not good_prev else self.recovery_good_streak + 1
                return Action.D
            self.hard_floor_mode = False
            self.recovery_mode = False
            self.recovery_good_streak = 0
        if current_stock <= cap / 3.0:
            self.hard_floor_mode = True
            self.recovery_mode = True
            self.recovery_good_streak = 0 if not good_prev else 1
            return Action.D
        if self.recovery_mode:
            if good_prev:
                self.recovery_good_streak += 1
            else:
                self.recovery_good_streak = 0
            if self.recovery_good_streak >= 2:
                self.recovery_mode = False
                self.recovery_good_streak = 0
            return Action.D
        if good_prev:
            return Action.C
        self.recovery_mode = True
        self.recovery_good_streak = 0
        return Action.D

class Strategy_SELFISH_51(BaseStrategy):
    """
    Conditional-grab strategy for the Common Pool Resource Game.

    Policy:
    - Round 1: defect.
    - Later rounds:
      - Defect in the last round.
      - Cooperate if stock is at/below a safety floor.
      - Cooperate if observed opponent cooperation was below 1/2.
      - Otherwise defect.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = int(history.round_number)
        if t == 0:
            return Action.D
        m = self.n_rounds - t + 1
        if m <= 1:
            return Action.D
        if current_stock <= 0:
            return Action.D
        floor = self.capacity / 3.0 if m >= 3 else self.capacity / 4.0
        if current_stock <= floor:
            return Action.C
        c_prev = 0
        if len(history.opponent_cooperators) > 0:
            c_prev = int(history.opponent_cooperators[-1])
        n_opponents = max(self.n_players - 1, 1)
        q = c_prev / n_opponents
        if c_prev == 0:
            return Action.C
        if c_prev >= n_opponents:
            return Action.D if current_stock > self.capacity / 3.0 else Action.C
        if q < 0.5:
            return Action.C
        return Action.D

class Strategy_SELFISH_52(BaseStrategy):
    """
    Defect by default, cooperate only when doing so is the difference between
    the stock recovering to at least half capacity next round and not recovering.
    Never cooperate in the first or last round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self._two_n = 2.0 * self.n_players

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number + 1
        if t == 1 or t == self.n_rounds:
            return Action.D
        m = 0
        if history.opponent_cooperators.size > 0:
            m = int(history.opponent_cooperators[-1])
        s = float(current_stock)
        k = self.capacity
        if self._two_n <= 0.0 or k <= 0.0 or s <= 0.0:
            return Action.D
        r_c = s * (m + 1.0) / self._two_n
        r_d = s * m / self._two_n
        if r_c >= k / 2.0 and r_d < k / 2.0:
            return Action.C
        return Action.D

class Strategy_SELFISH_53(BaseStrategy):
    """
    Adaptive common-pool strategy with:
    - cooperative opening when future rounds matter,
    - exponentially weighted memory of opponent cooperation,
    - stock-based thresholds,
    - endgame tightening,
    - recovery/defection locks after low cooperation or low stock,
    - occasional selfish test behavior when cooperation seems stable.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.hist_rate = 1.0
        self.alpha = 0.7
        self.low_coop_lock = False
        self.low_coop_consecutive = 0
        self.low_stock_lock = False
        self.test_mode_pending = False
        self.last_action_was_cooperate = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        m = self.r - round_number
        if round_number > 0:
            last_opp_c = int(history.opponent_cooperators[-1])
            n_opp = max(self.n - 1, 1)
            opp_rate = last_opp_c / n_opp
            self.hist_rate = self.alpha * opp_rate + (1.0 - self.alpha) * self.hist_rate
            if opp_rate < 0.5:
                self.low_coop_lock = True
                self.low_coop_consecutive = 0
            else:
                if opp_rate >= 2.0 / 3.0:
                    self.low_coop_consecutive += 1
                else:
                    self.low_coop_consecutive = 0
                if self.low_coop_consecutive >= 2:
                    self.low_coop_lock = False
            if current_stock < self.capacity / 4.0:
                self.low_stock_lock = True
            elif current_stock > self.capacity / 2.0:
                self.low_stock_lock = False
            self.last_action_was_cooperate = bool(history.my_actions[-1])
        if round_number == 0:
            if self.r > 1 and self.capacity >= 2.0 * self.n:
                self.last_action_was_cooperate = True
                return Action.C
            self.last_action_was_cooperate = False
            return Action.D
        if m <= 1:
            self.last_action_was_cooperate = False
            return Action.D
        if self.low_stock_lock:
            self.last_action_was_cooperate = False
            return Action.D
        if self.low_coop_lock:
            self.last_action_was_cooperate = False
            return Action.D
        cap = self.capacity
        S = float(current_stock)
        hr = float(self.hist_rate)
        if m == 2:
            if S == cap and hr == 1.0:
                self.last_action_was_cooperate = True
                return Action.C
            self.last_action_was_cooperate = False
            return Action.D
        if m == 3:
            if S >= 3.0 * cap / 4.0 and hr == 1.0:
                self.last_action_was_cooperate = True
                return Action.C
            self.last_action_was_cooperate = False
            return Action.D
        if S <= cap / 4.0:
            self.last_action_was_cooperate = False
            return Action.D
        if hr < 0.5:
            self.last_action_was_cooperate = False
            return Action.D
        if hr >= 2.0 / 3.0 and S >= cap / 2.0:
            if self.last_action_was_cooperate:
                self.last_action_was_cooperate = True
                return Action.C
            if not self.test_mode_pending:
                self.test_mode_pending = True
                self.last_action_was_cooperate = False
                return Action.D
            if self.test_mode_pending:
                self.test_mode_pending = False
                self.last_action_was_cooperate = True
                return Action.C
        if S >= 3.0 * cap / 4.0 and hr >= 2.0 / 3.0:
            self.last_action_was_cooperate = True
            return Action.C
        if S >= cap / 2.0 and hr >= 3.0 / 4.0:
            self.last_action_was_cooperate = True
            return Action.C
        self.last_action_was_cooperate = False
        return Action.D

class Strategy_SELFISH_54(BaseStrategy):
    """
    Threshold-based adaptive strategy:
    - Defect on the first and last rounds, or whenever stock is depleted.
    - Otherwise, cooperate only if the observed cooperation among opponents
      in the previous round is sufficiently high relative to the current stock.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = int(history.round_number)
        if t == 0 or t >= self.r or current_stock <= 0:
            return Action.D
        n_opponents = max(self.n - 1, 0)
        if n_opponents <= 0:
            return Action.D
        last_opponents_coop = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        rho = last_opponents_coop / n_opponents
        expected_cooperators = round(rho * n_opponents)
        if current_stock <= 0:
            return Action.D
        k = math.ceil(self.n * self.capacity / current_stock - 1)
        if k <= 0:
            return Action.C if expected_cooperators >= n_opponents else Action.D
        if expected_cooperators >= k and k <= n_opponents:
            return Action.C
        return Action.D

class Strategy_SELFISH_55(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Cooperate initially to probe sustainability.
    - Use the last observed cooperation rate to estimate whether preserving stock
      is likely to improve future extraction.
    - Defect when stock is depleted, in the final round, or when projections are
      not clearly favorable to cooperation.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)

    def _growth(self, x: float) -> float:
        if x <= 0.0:
            return 0.0
        g = x + 2.0 * x * (1.0 - x / self.capacity)
        return min(g, self.capacity)

    def _project_stock(self, start_stock: float, coop_rate: float, my_action_coop: bool, steps: int):
        """
        Project stock forward for 'steps' rounds assuming the same cooperation
        rate persists. Returns a list of projected stocks after each round.
        """
        stocks = []
        s = max(0.0, float(start_stock))
        n_opponents = max(0, self.n - 1)
        for _ in range(max(0, steps)):
            if s <= 0.0:
                stocks.append(0.0)
                s = 0.0
                continue
            expected_k = int(round(n_opponents * coop_rate))
            if expected_k < 0:
                expected_k = 0
            elif expected_k > n_opponents:
                expected_k = n_opponents
            opp_coop_consumption = expected_k * (s / (2.0 * self.n)) if self.n > 0 else 0.0
            opp_def_consumption = (n_opponents - expected_k) * (s / self.n) if self.n > 0 else 0.0
            my_consumption = s / (2.0 * self.n) if my_action_coop else s / self.n
            remaining = s - (opp_coop_consumption + opp_def_consumption + my_consumption)
            if remaining < 0.0:
                remaining = 0.0
            s = self._growth(remaining)
            stocks.append(s)
        return stocks

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = int(history.round_number)
        s = float(current_stock)
        if t == 0:
            return Action.C
        if s <= 0.0:
            return Action.D
        if t >= self.r - 1:
            return Action.D
        n_opponents = self.n - 1
        if n_opponents <= 0:
            return Action.D
        prev_count = None
        try:
            prev_count = int(history.opponent_cooperators[-1])
        except Exception:
            prev_count = None
        if prev_count is None:
            return Action.D
        prev_count = max(0, min(prev_count, n_opponents))
        p_hat = prev_count / n_opponents if n_opponents > 0 else 0.0
        k_hat = int(round(n_opponents * p_hat))
        k_hat = max(0, min(k_hat, n_opponents))
        delta_now = s / (2.0 * self.n)
        opp_coop_cons = k_hat * (s / (2.0 * self.n))
        opp_def_cons = (n_opponents - k_hat) * (s / self.n)
        rem_c = s - (opp_coop_cons + opp_def_cons + s / (2.0 * self.n))
        rem_d = s - (opp_coop_cons + opp_def_cons + s / self.n)
        rem_c = max(0.0, rem_c)
        rem_d = max(0.0, rem_d)
        next_c = self._growth(rem_c)
        next_d = self._growth(rem_d)
        if next_d >= next_c:
            return Action.D
        remaining_rounds = self.r - t - 1
        if remaining_rounds <= 0:
            return Action.D
        proj_c = self._project_stock(next_c, p_hat, True, remaining_rounds)
        proj_d = self._project_stock(next_d, p_hat, False, remaining_rounds)
        future_gain = 0.0
        for sc, sd in zip(proj_c, proj_d):
            future_gain += sc / (2.0 * self.n) - sd / self.n
        if future_gain > delta_now and p_hat >= 0.5:
            return Action.C
        return Action.D

class Strategy_SELFISH_56(BaseStrategy):
    """
    Defect by default, cooperate only in vulnerable stock ranges when the
    previous round showed sufficiently high opponent cooperation. Never
    cooperate in the first or final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(self.n_players - 1, 1)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        if round_number == 0:
            return Action.D
        if round_number >= self.n_rounds - 1:
            return Action.D
        if self.capacity <= 0:
            x = 0.0
        else:
            x = float(current_stock) / self.capacity
        prev_opponent_cooperators = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        if prev_opponent_cooperators <= 0:
            return Action.D
        q = prev_opponent_cooperators / self.n_opponents if self.n_opponents > 0 else 0.0
        if x >= 2.0 / 3.0:
            return Action.D
        if x >= 1.0 / 3.0:
            return Action.C if q >= 0.5 else Action.D
        return Action.C if q >= 2.0 / 3.0 else Action.D

class Strategy_SELFISH_57(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Tracks the current stock level via the observed state argument.
    - Uses the last observed opponent cooperation count as a forecast.
    - Defaults to defection when it appears safe for future extraction,
      but cooperates when further defection would threaten the reserve.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(self.n_players - 1, 0)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        stock = float(current_stock)
        if round_number >= self.n_rounds - 1:
            return Action.D
        if stock <= 0.0:
            return Action.D
        if stock <= self.capacity / 4.0:
            return Action.C
        if round_number == 0:
            o = self.n_opponents
        else:
            o = int(history.opponent_cooperators[-1])
        if o <= self.n_opponents / 2.0:
            return Action.C
        rounds_remaining = self.n_rounds - round_number
        if rounds_remaining > 4:
            target = self.capacity / 2.0
        elif rounds_remaining in (3, 4):
            target = self.capacity / 3.0
        elif rounds_remaining == 2:
            target = self.capacity / 4.0
        else:
            target = self.capacity / 4.0
        if self.n_players <= 0 or self.capacity <= 0.0:
            return Action.C
        remaining_after_defect = stock * (o / (2.0 * self.n_players))
        growth = 2.0 * remaining_after_defect * (1.0 - remaining_after_defect / self.capacity)
        next_stock_if_defect = min(remaining_after_defect + growth, self.capacity)
        return Action.D if next_stock_if_defect >= target else Action.C

class Strategy_SELFISH_58(BaseStrategy):
    """
    Cautious reciprocal extractor for the Common Pool Resource Game.

    Cooperates in the opening round, then continues cooperating only when the
    stock is high and the previous round showed broadly cooperative opponents.
    Otherwise defects, with a short lockout after total opponent defection.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(self.n - 1, 0)
        self.high_threshold = 0.75 * self.capacity
        self.stable_threshold = math.ceil(self.n_opponents / 2)
        self.last_round_threshold = self.r - 1
        self.final_two_threshold = self.r - 2
        self._defect_lock = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = int(history.round_number)
        S = float(current_stock)
        if not math.isfinite(S):
            S = 0.0
        if S < 0.0:
            S = 0.0
        if self.capacity > 0.0 and S > self.capacity:
            S = self.capacity
        if t == 0:
            self._defect_lock = 0
            return Action.C
        if len(history.opponent_cooperators) > 0:
            c_prev = int(history.opponent_cooperators[-1])
        else:
            c_prev = 0
        if c_prev < 0:
            c_prev = 0
        if c_prev > self.n_opponents:
            c_prev = self.n_opponents
        if c_prev == 0:
            self._defect_lock = max(self._defect_lock, 2)
        if self.capacity > 0.0 and abs(S - self.capacity) <= 1e-12:
            self._defect_lock = 0
        if t >= self.final_two_threshold and S < 0.9 * self.capacity:
            return Action.D
        if t == self.last_round_threshold and (not (abs(S - self.capacity) <= 1e-12 and c_prev == self.n_opponents)):
            return Action.D
        if self._defect_lock > 0 and abs(S - self.capacity) > 1e-12:
            self._defect_lock -= 1
            return Action.D
        if S >= 2.0 * self.n and S >= self.high_threshold and (c_prev >= self.stable_threshold):
            if c_prev == self.n_opponents and S >= 2.0 * self.n:
                return Action.C
            return Action.C
        return Action.D

class Strategy_SELFISH_59(BaseStrategy):
    """
    Common-pool strategy using a forecasted continuation score:
    cooperate only when the predicted long-run gain exceeds defection,
    the previous round was sufficiently cooperative, and the stock is low
    enough to justify rebuilding. Otherwise defect.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.n_players
        r = self.n_rounds
        cap = self.capacity
        if n <= 1 or r <= 0:
            return Action.D
        if current_stock <= 0.0:
            return Action.D
        round_number = history.round_number
        if round_number >= r:
            return Action.D
        m = r - round_number
        if round_number == 0:
            k = n - 1
        else:
            k = int(history.opponent_cooperators[-1])
        if round_number == r - 1:
            return Action.D
        if k == 0:
            return Action.D
        if k == n - 1 and current_stock <= cap / 2.0:
            return Action.C
        denom = 2.0 * n
        x_c = current_stock * (k + 2.0) / denom
        x_d = current_stock * k / denom
        if cap > 0.0:
            r_c = min(3.0 * x_c - 2.0 * x_c * x_c / cap, cap)
            r_d = min(3.0 * x_d - 2.0 * x_d * x_d / cap, cap)
        else:
            r_c = 0.0
            r_d = 0.0
        u_c = current_stock / (2.0 * n) + (m - 1.0) / (2.0 * n) * r_c
        u_d = current_stock / n + (m - 1.0) / (2.0 * n) * r_d
        if u_c > u_d and k >= n - 2 and (current_stock <= cap / 2.0):
            return Action.C
        return Action.D

class Strategy_SELFISH_60(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Start cooperatively.
    - Use the previous round's observed opponent cooperation rate and current stock
      to estimate whether cooperation preserves more future value than defection.
    - Defect near the end unless the stock is essentially full.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.half_capacity = self.capacity / 2.0
        self.epsilon = 1e-09

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number
        n = max(2, self.n)
        r = max(2, self.r)
        cap = self.capacity
        S = float(current_stock)
        if t == 0:
            return Action.C
        if S <= 0.0:
            return Action.D
        if t == r - 1:
            return Action.C if S >= cap - self.epsilon else Action.D
        if t == r - 2 and S < cap - self.epsilon:
            return Action.D
        prev_idx = t - 1
        prev_k = 0
        if len(history.opponent_cooperators) > prev_idx:
            prev_k = int(history.opponent_cooperators[prev_idx])
        n_opponents = max(1, n - 1)
        prev_k = max(0, min(prev_k, n_opponents))
        m_t = prev_k / n_opponents
        x_t = (1.0 + m_t) / 2.0
        if prev_k == 0:
            return Action.C if S >= cap - self.epsilon else Action.D
        if prev_k == n_opponents and S > self.half_capacity:
            return Action.C
        if m_t < 0.5 or S < self.half_capacity:
            return Action.D
        cons_c = S * (x_t / 2.0 + (1.0 - x_t))
        r_c = S - cons_c
        n_c = min(r_c + 2.0 * r_c * (1.0 - r_c / cap), cap)
        cons_d = S * (x_t / 2.0 + (1.0 - x_t) + 1.0 / (2.0 * n))
        r_d = S - cons_d
        n_d = min(r_d + 2.0 * r_d * (1.0 - r_d / cap), cap)
        if t <= r - 3:
            beta = 1.0
        elif t == r - 2:
            beta = 0.5
        else:
            beta = 0.0
        payoff_c = S / (2.0 * n) + beta * n_c
        payoff_d = S / n + beta * n_d
        if S >= cap - self.epsilon:
            return Action.C
        return Action.C if payoff_c >= payoff_d else Action.D

class Strategy_SELFISH_61(BaseStrategy):
    """
    Defect by default, but cooperate selectively when the estimated opponent
    cooperation rate is high and preserving the common stock is necessary.
    The strategy maintains an exponentially smoothed estimate of opponent
    cooperation initialized at 1/2.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self._p_hat = 0.5
        self._last_updated_round = 0

    def _update_estimate(self, history: PlayerHistory) -> None:
        """Update the cooperation estimate using any newly observed rounds."""
        n_players = max(2, int(self.game_description.n_players))
        n_opponents = max(1, n_players - 1)
        current_rounds = history.round_number
        if current_rounds <= self._last_updated_round:
            return
        start = self._last_updated_round
        end = current_rounds
        for idx in range(start, end):
            opp_coops = 0
            if idx < len(history.opponent_cooperators):
                opp_coops = int(history.opponent_cooperators[idx])
            observed_rate = opp_coops / n_opponents
            self._p_hat = 0.7 * self._p_hat + 0.3 * observed_rate
        self._last_updated_round = current_rounds

    def _project_next_stock(self, current_stock: float, my_action: Action) -> float:
        """Project next stock after one round under expected opponent behavior."""
        n_players = max(2, int(self.game_description.n_players))
        capacity = float(self.game_description.capacity)
        n_opponents = max(1, n_players - 1)
        s = max(0.0, float(current_stock))
        p = min(1.0, max(0.0, float(self._p_hat)))
        consume_c = s / (2.0 * n_players)
        consume_d = s / float(n_players)
        my_consume = consume_c if my_action == Action.C else consume_d
        expected_opp_consume = n_opponents * (p * consume_c + (1.0 - p) * consume_d)
        remaining = s - my_consume - expected_opp_consume
        if remaining < 0.0:
            remaining = 0.0
        growth = 2.0 * remaining * (1.0 - remaining / capacity) if capacity > 0.0 else 0.0
        next_stock = remaining + growth
        return min(next_stock, capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_rounds = int(self.game_description.n_rounds)
        capacity = float(self.game_description.capacity)
        self._update_estimate(history)
        t = history.round_number + 1
        if t == 1:
            return Action.D
        if t == n_rounds:
            return Action.D
        if current_stock <= 0.0:
            return Action.D
        if self._p_hat <= 1.0 / 3.0:
            return Action.D
        if t >= max(1, n_rounds - 1):
            return Action.D
        if self._p_hat >= 2.0 / 3.0 and current_stock <= 0.5 * capacity:
            return Action.C
        reserve = capacity * (n_rounds - t) / max(1, n_rounds)
        next_d = self._project_next_stock(current_stock, Action.D)
        next_c = self._project_next_stock(current_stock, Action.C)
        if next_d < reserve <= next_c:
            return Action.C
        return Action.D

class Strategy_SELFISH_62(BaseStrategy):
    """
    Conditional cooperation strategy for the Common Pool Resource Game.

    Cooperates only when the stock is high, the recent cooperation rate is
    sufficiently strong, and a simple forecast suggests cooperation is
    sustainable. Otherwise defects.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(getattr(game_description, 'n_players', 0) or 0)
        self.n_rounds = int(getattr(game_description, 'n_rounds', 0) or 0)
        self.capacity = float(getattr(game_description, 'capacity', 0.0) or 0.0)

    def _growth(self, x: float) -> float:
        cap = self.capacity
        if cap <= 0.0:
            return 0.0
        return min(x + 2.0 * x * (1.0 - x / cap), cap)

    def _opponent_rate(self, history: PlayerHistory) -> float:
        n_opponents = self.n_players - 1
        if n_opponents <= 0 or history.round_number <= 0:
            return 0.0
        last_coop = int(history.opponent_cooperators[-1])
        if self.n_players == 2:
            return 1.0 if last_coop >= 1 else 0.0
        return max(0.0, min(1.0, last_coop / n_opponents))

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.n_players
        r = self.n_rounds
        cap = self.capacity
        S = float(current_stock)
        if n < 2 or r < 2 or cap <= 0.0 or (not math.isfinite(S)):
            return Action.D
        round_num = history.round_number
        if round_num >= r - 1:
            return Action.D
        if round_num == r - 2:
            p_prev = self._opponent_rate(history)
            if S >= 0.8 * cap and p_prev >= 2.0 / 3.0:
                return Action.C
            return Action.D
        if round_num == 0:
            return Action.D
        if len(history.opponent_cooperators) < 1:
            return Action.D
        last_k = int(history.opponent_cooperators[-1])
        n_opponents = n - 1
        if last_k < 0 or last_k > n_opponents:
            return Action.D
        p = self._opponent_rate(history)
        if S < 0.4 * cap:
            return Action.D
        if round_num >= 2 and len(history.opponent_cooperators) >= 2:
            prev_p = self._opponent_rate(PlayerHistory(my_actions=history.my_actions[:-1], my_payoffs=history.my_payoffs[:-1], opponent_cooperators=history.opponent_cooperators[:-1]))
            if p < 0.5 or prev_p < 0.5:
                return Action.D
        elif p < 0.5:
            return Action.D
        if abs(S - cap) <= 1e-12:
            if p >= 2.0 / 3.0:
                return Action.C
            return Action.D
        if S < 0.6 * cap:
            return Action.D
        if p < 0.5:
            return Action.D
        try:
            coop_cons = S / (2.0 * n)
            defect_cons = S / n
            L = p * n_opponents * coop_cons + (1.0 - p) * n_opponents * defect_cons
            R_c = S - (coop_cons + L)
            G_c = self._growth(R_c)
            if G_c >= S:
                return Action.C
        except Exception:
            return Action.D
        return Action.D

class Strategy_SELFISH_63(BaseStrategy):
    """
    Threshold strategy for the Common Pool Resource Game.

    Rule:
    - Always defect on the last round.
    - Otherwise cooperate if the stock is at or below 2n.
    - Otherwise cooperate if the previous opponent cooperation rate was below 1/2.
    - Otherwise defect.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(self.n_players - 1, 1)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        if round_number >= self.n_rounds - 1:
            return Action.D
        if current_stock <= 2.0 * self.n_players:
            return Action.C
        if round_number == 0:
            return Action.D
        last_opponent_cooperators = 0
        if len(history.opponent_cooperators) > 0:
            last_opponent_cooperators = int(history.opponent_cooperators[-1])
        q_prev = last_opponent_cooperators / self.n_opponents if self.n_opponents > 0 else 0.5
        if q_prev < 0.5:
            return Action.C
        return Action.D

class Strategy_SELFISH_64(BaseStrategy):
    """
    Stock-sensitive strategy with short memory of opponent cooperation.
    It defects initially and in the final round, cooperates when the pool is
    depleted or when cooperation has collapsed for two consecutive rounds, and
    otherwise follows a threshold rule based on recent opponent cooperation.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.q_bar = 1.0
        self.collapse = 0
        self._last_processed_round = 0
        self._last_q_bar_update_round = -1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        n_players = self.game_description.n_players
        n_opponents = max(n_players - 1, 1)
        final_round = self.game_description.n_rounds - 1
        if round_number == final_round:
            return Action.D
        if round_number == 0:
            self._last_processed_round = 0
            self._last_q_bar_update_round = -1
            self.q_bar = 1.0
            self.collapse = 0
            return Action.D
        start_round = max(self._last_processed_round, 1)
        end_round = round_number
        for t in range(start_round, end_round):
            if t - 1 < 0 or t - 1 >= len(history.opponent_cooperators):
                continue
            coop_count = int(history.opponent_cooperators[t - 1])
            q = coop_count / n_opponents
            self.q_bar = (self.q_bar + q) / 2.0
            if q < 0.5:
                self.collapse += 1
            else:
                self.collapse = 0
        self._last_processed_round = round_number
        low = self.game_description.capacity / 3.0
        high = 2.0 * self.game_description.capacity / 3.0
        if current_stock <= low:
            return Action.C
        if self.collapse >= 2:
            return Action.C
        if current_stock >= high and self.q_bar >= 0.75 and (self.collapse == 0):
            return Action.D
        if self.q_bar >= 0.75:
            return Action.D
        return Action.C

class Strategy_SELFISH_65(BaseStrategy):
    """
    Selfish lookahead strategy for the Common Pool Resource Game.

    The strategy starts by defecting, then estimates opponent cooperation
    and compares the discounted future value of cooperating vs defecting.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.q = 0.5
        self._cum_opponent_cooperators = 0
        self._cum_observations = 0

    def _growth(self, x: float) -> float:
        if x <= 0.0:
            return 0.0
        cap = self.capacity if self.capacity > 0 else 1.0
        grown = x + 2.0 * x * (1.0 - x / cap)
        return min(grown, cap)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number + 1
        n = self.n
        r = self.r
        cap = self.capacity
        if t == 1 or t >= r or current_stock <= 0.0 or (n <= 1):
            return Action.D
        if history.round_number > 0:
            last_c = int(history.opponent_cooperators[-1])
            opponents = max(n - 1, 1)
            self._cum_opponent_cooperators += last_c
            self._cum_observations += opponents
            cumulative_q = self._cum_opponent_cooperators / self._cum_observations if self._cum_observations > 0 else 0.5
            last_rate = last_c / opponents
            self.q = 0.7 * self.q + 0.3 * last_rate
            self.q = 0.5 * self.q + 0.5 * cumulative_q
        q_t = min(max(self.q, 0.0), 1.0)
        opponents = max(n - 1, 1)
        own_c = current_stock / (2.0 * n)
        own_d = current_stock / n
        expected_opp_consumption = opponents * (q_t * own_c + (1.0 - q_t) * own_d)
        r_c = current_stock - own_c - expected_opp_consumption
        r_d = current_stock - own_d - expected_opp_consumption
        r_c = max(r_c, 0.0)
        r_d = max(r_d, 0.0)
        lam = (r - t) / r if r > 0 else 0.0
        if lam < 0.0:
            lam = 0.0
        u_c = own_c + lam * self._growth(r_c)
        u_d = own_d + lam * self._growth(r_d)
        if u_d >= u_c:
            return Action.D
        return Action.C

class Strategy_SELFISH_66(BaseStrategy):
    """
    Adaptive common-pool strategy that cooperates only when the stock is high
    and observed cooperation suggests the resource can be preserved for future
    rounds; otherwise defects.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(0, self.n_players - 1)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = int(history.round_number) + 1
        T = self.n_rounds
        S = float(current_stock)
        rounds_left = T - t + 1
        if t >= T:
            return Action.D
        if t == 1:
            if T >= 4 and self.capacity > 0 and (S >= 0.9 * self.capacity):
                return Action.C
            return Action.D
        c_hat = 0.0
        has_last_round_info = False
        if len(history.opponent_cooperators) > 0 and self.n_opponents > 0:
            k = float(history.opponent_cooperators[-1])
            c_hat = k / float(self.n_opponents)
            has_last_round_info = True
        if self.capacity > 0:
            if S <= 0.25 * self.capacity:
                return Action.D
            if S >= 0.85 * self.capacity and rounds_left >= 3:
                return Action.C
        if not has_last_round_info:
            if self.capacity > 0 and S >= 0.95 * self.capacity and (rounds_left >= 3):
                return Action.C
            return Action.D
        if rounds_left <= 2:
            if self.capacity > 0 and S >= 0.95 * self.capacity and (c_hat >= 0.75):
                return Action.C
            return Action.D
        if c_hat >= 2.0 / 3.0:
            if S <= 0.3 * self.capacity:
                return Action.D
            return Action.C
        if 1.0 / 3.0 <= c_hat < 2.0 / 3.0:
            if S >= 0.7 * self.capacity and rounds_left >= 3:
                return Action.C
            return Action.D
        return Action.D

class Strategy_SELFISH_67(BaseStrategy):
    """
    Threshold strategy with one-step stock forecasting:
    - Start with defection.
    - In non-final rounds, cooperate only when past opponent cooperation is high,
      stock is sufficiently healthy, and the forecasted selfish one-step score favors C.
    - Otherwise defect.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(self.n - 1, 0)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.n
        capacity = self.capacity
        stock = float(current_stock)
        if history.round_number == 0:
            return Action.D
        if history.round_number >= self.r - 1:
            return Action.D
        if stock <= 0.0:
            return Action.D
        if history.opponent_cooperators is None or len(history.opponent_cooperators) == 0:
            return Action.D
        last_opps = history.opponent_cooperators[-1]
        try:
            m = int(last_opps)
        except Exception:
            return Action.D
        if n == 2:
            q = 1.0 if m >= 1 else 0.0
        else:
            denom = float(n - 1)
            q = m / denom if denom > 0.0 else 0.0
        if q < 0.0:
            q = 0.0
        elif q > 1.0:
            q = 1.0
        if q < 0.5:
            return Action.D
        if stock < capacity / 4.0:
            return Action.D
        cons_opp = q * (n - 1) * stock / (2.0 * n) + (1.0 - q) * (n - 1) * stock / float(n)
        cons_C = stock / (2.0 * n) + cons_opp
        cons_D = stock / float(n) + cons_opp
        R_C = max(stock - cons_C, 0.0)
        R_D = max(stock - cons_D, 0.0)
        Snext_C = min(R_C + 2.0 * R_C * (1.0 - R_C / capacity), capacity) if capacity > 0.0 else 0.0
        Snext_D = min(R_D + 2.0 * R_D * (1.0 - R_D / capacity), capacity) if capacity > 0.0 else 0.0
        score_C = stock / (2.0 * n) + Snext_C / (2.0 * n)
        score_D = stock / float(n) + Snext_D / (2.0 * n)
        if score_C > score_D:
            return Action.C
        return Action.D

class Strategy_SELFISH_68(BaseStrategy):
    """
    Cooperate initially, then defect only when the pool is healthy,
    the opponents were sufficiently cooperative last round, and there
    is more than one round left. Always defect in the last round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.stock_threshold = 0.6 * self.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        m = self.n_rounds - history.round_number
        if m <= 1:
            return Action.D
        if current_stock < self.stock_threshold:
            return Action.C
        n_opponents = max(self.n_players - 1, 1)
        last_opponent_cooperators = int(history.opponent_cooperators[-1])
        q = last_opponent_cooperators / n_opponents
        if q < 0.5:
            return Action.C
        return Action.D

class Strategy_SELFISH_69(BaseStrategy):
    """
    Adaptive common-pool strategy with endgame defection, reciprocal memory,
    and one-time recovery cooperation after a stock collapse.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self._q = 0.0
        self._last_stock_low = False
        self._last_round_seen = -1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = float(self.game_description.capacity)
        t = history.round_number
        if t != self._last_round_seen:
            self._last_round_seen = t
        if t == 0:
            self._last_stock_low = current_stock <= 0.1 * capacity
            return Action.D
        if t >= r - 1:
            self._last_stock_low = current_stock <= 0.1 * capacity
            return Action.D
        opp = history.opponent_cooperators
        num_prev_rounds = len(opp)
        q = 0.0
        if num_prev_rounds > 0:
            denom = max(n - 1, 1)
            first_c = float(opp[0]) / denom
            q = first_c
            for idx in range(1, num_prev_rounds):
                c_frac = float(opp[idx]) / denom
                q = 0.7 * q + 0.3 * c_frac
        s = 0.0 if capacity <= 0 else float(current_stock) / capacity
        low_stock = current_stock <= 0.1 * capacity
        if low_stock and (not self._last_stock_low) and (t < r - 1):
            self._last_stock_low = low_stock
            self._q = q
            return Action.C
        if q >= 1.0 - 1e-12 and s >= 0.8:
            self._last_stock_low = low_stock
            self._q = q
            return Action.D
        if q <= 1e-12 and s > 0.2:
            self._last_stock_low = low_stock
            self._q = q
            return Action.D
        if q >= 0.4 and s <= 0.35 + 0.4 * q:
            action = Action.C
        else:
            action = Action.D
        self._last_stock_low = low_stock
        self._q = q
        return action

class Strategy_SELFISH_70(BaseStrategy):
    """
    Conservative adaptive strategy for the Common Pool Resource Game.

    - Starts with defection.
    - Keeps an exponentially smoothed belief q about opponent cooperation.
    - Defects by default, but cooperates when stock is low and defection would
      likely push the pool into dangerous depletion.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.q = 0.5

    def _project_next_stock(self, stock: float, my_action: Action, predicted_cooperators: int) -> float:
        n = max(2, int(self.game_description.n_players))
        capacity = float(self.game_description.capacity)
        opponents = n - 1
        my_consumption = stock / n if my_action == Action.D else stock / (2.0 * n)
        coop_consumption = stock / (2.0 * n)
        defect_consumption = stock / n
        predicted_cooperators = max(0, min(opponents, int(predicted_cooperators)))
        opponent_total = predicted_cooperators * coop_consumption + (opponents - predicted_cooperators) * defect_consumption
        s_after = stock - (my_consumption + opponent_total)
        growth = 2.0 * s_after * (1.0 - s_after / capacity) if capacity > 0 else 0.0
        s_next = min(s_after + growth, capacity)
        return max(0.0, s_next)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = max(2, int(self.game_description.n_players))
        capacity = float(self.game_description.capacity)
        t = int(history.round_number)
        remaining_rounds = max(1, int(self.game_description.n_rounds) - t)
        if current_stock <= 0.0:
            return Action.D
        if t == 0:
            return Action.D
        if remaining_rounds == 1:
            return Action.D
        opponents = n - 1
        if opponents > 0 and len(history.opponent_cooperators) > 0:
            c_prev = float(history.opponent_cooperators[-1])
            observed_frac = c_prev / opponents
            self.q = 0.7 * float(self.q) + 0.3 * observed_frac
        else:
            self.q = float(self.q)
        k = int(round(self.q * opponents))
        k = max(0, min(opponents, k))
        if current_stock <= 2.0 * n:
            return Action.C
        s_next_d = self._project_next_stock(current_stock, Action.D, k)
        if current_stock <= 0.45 * capacity and s_next_d < 0.35 * capacity:
            return Action.C
        return Action.D

class Strategy_SELFISH_71(BaseStrategy):
    """
    Dynamic projection strategy for the Common Pool Resource Game.

    - Round 1: defect.
    - Later rounds: estimate opponent cooperation from recent history, then
      compare projected total payoff of cooperating vs defecting under a
      fixed-rate forecast of opponent behavior.
    - Several hard edge-case rules override the projection.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.cap = float(game_description.capacity)
        self.n_opponents = max(self.n - 1, 1)
        self._eps = 1e-12

    def _cooperation_rate(self, opponent_cooperators: int) -> float:
        return float(opponent_cooperators) / float(self.n_opponents)

    def _recent_q(self, history: PlayerHistory) -> float:
        rounds = history.round_number
        if rounds <= 0:
            return 0.0
        if rounds >= 2:
            slice_data = history.opponent_cooperators[-2:]
        else:
            slice_data = history.opponent_cooperators[:]
        if len(slice_data) == 0:
            return 0.0
        rates = [self._cooperation_rate(int(x)) for x in slice_data]
        return float(np.mean(rates)) if len(rates) > 0 else 0.0

    def _next_stock(self, current_stock: float, total_cooperators: float) -> float:
        r_remaining = float(current_stock) * float(total_cooperators) / (2.0 * float(self.n))
        if r_remaining < 0.0:
            r_remaining = 0.0
        growth = 2.0 * r_remaining * (1.0 - r_remaining / self.cap) if self.cap > 0 else 0.0
        new_stock = r_remaining + growth
        if new_stock > self.cap:
            new_stock = self.cap
        if new_stock < 0.0:
            new_stock = 0.0
        return float(new_stock)

    def _project_payoff(self, stock: float, rounds_left: int, q: float, first_action: Action) -> float:
        total = 0.0
        s = float(stock)
        action = first_action
        for _ in range(max(rounds_left, 0)):
            if action == Action.C:
                immediate = s / (2.0 * self.n)
                expected_total_cooperators = q * self.n_opponents + 1.0
            else:
                immediate = s / float(self.n)
                expected_total_cooperators = q * self.n_opponents
            total += immediate
            s = self._next_stock(s, expected_total_cooperators)
            action = Action.C
        return float(total)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number + 1
        rounds_left = self.r - t + 1
        if t <= 1:
            return Action.D
        if t >= self.r:
            return Action.D
        q = self._recent_q(history)
        last_rate = self._cooperation_rate(int(history.opponent_cooperators[-1])) if history.round_number > 0 else 0.0
        if q <= self._eps:
            return Action.D
        if current_stock <= self.cap / 4.0:
            if history.round_number >= 2:
                r1 = self._cooperation_rate(int(history.opponent_cooperators[-1]))
                r2 = self._cooperation_rate(int(history.opponent_cooperators[-2]))
                if r1 >= 2.0 / 3.0 and r2 >= 2.0 / 3.0:
                    return Action.C
            return Action.D
        if last_rate < 0.5:
            return Action.D
        if last_rate >= 2.0 / 3.0 and current_stock > self.cap / 2.0:
            return Action.C
        if abs(q - 1.0) <= self._eps and t < self.r:
            projected_stock_if_d = self._next_stock(current_stock, self.n_opponents * 1.0)
            if projected_stock_if_d < self.cap / 4.0:
                return Action.C
            return Action.D
        payoff_c = self._project_payoff(current_stock, rounds_left, q, Action.C)
        payoff_d = self._project_payoff(current_stock, rounds_left, q, Action.D)
        if payoff_c > payoff_d:
            return Action.C
        if payoff_d > payoff_c:
            return Action.D
        return Action.D

class Strategy_SELFISH_72(BaseStrategy):
    """
    Selfish baseline for the common pool resource game:
    cooperate once at the start, defect when the pool is low or cooperation is insufficient,
    and defect in the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.H = 0.7 * self.capacity
        self.L = 0.35 * self.capacity
        self.M = 0.85
        self._last_action = Action.D
        self._last_seen_stock = float(self.capacity)
        self._initialized = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = int(history.round_number)
        stock = float(current_stock)
        if t >= self.r - 1:
            self._last_seen_stock = stock
            self._last_action = Action.D
            self._initialized = True
            return Action.D
        if t == 0:
            self._last_seen_stock = stock
            self._last_action = Action.C
            self._initialized = True
            return Action.C
        opp_coop = 0
        if len(history.opponent_cooperators) > 0:
            opp_coop = int(history.opponent_cooperators[-1])
        if self.n <= 2:
            rho = 1.0 if opp_coop >= 1 else 0.0
        else:
            denom = self.n - 1
            rho = opp_coop / denom if denom > 0 else 0.0
        if stock <= self.L:
            self._last_seen_stock = stock
            self._last_action = Action.D
            self._initialized = True
            return Action.D
        if rho >= self.M and stock >= self.H:
            self._last_seen_stock = stock
            self._last_action = Action.C
            self._initialized = True
            return Action.C
        if rho <= 0.5:
            self._last_seen_stock = stock
            self._last_action = Action.D
            self._initialized = True
            return Action.D
        if self._last_action == Action.C and self._initialized and (self._last_seen_stock > stock):
            action = Action.C
        else:
            action = Action.D
        self._last_seen_stock = stock
        self._last_action = action
        self._initialized = True
        return action

class Strategy_SELFISH_73(BaseStrategy):
    """
    Adaptive dynamic-programming strategy for the Common Pool Resource Game.

    It estimates opponent cooperation from the previous round, predicts the
    resulting stock transition under cooperate/defect, and compares the
    immediate + future expected value of both actions.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = max(2, int(game_description.n_players))
        self.r = max(1, int(game_description.n_rounds))
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(1, self.n - 1)
        self._eps = 1e-09
        self._last_round_number = -1
        self._last_observed_k = None
        self._zero_streak = 0
        self._unanimous_streak = 0

    def _next_stock(self, stock: float, p: float) -> tuple[float, float]:
        stock = float(stock)
        p = min(max(float(p), 0.0), 1.0)
        r_c = stock * (1.0 + p) / 2.0
        r_d = stock * p

        def evolve(x: float) -> float:
            x = max(0.0, float(x))
            if self.capacity <= 0.0:
                return 0.0
            growth = 2.0 * x * (1.0 - x / self.capacity)
            return min(max(x + growth, 0.0), self.capacity)
        return (evolve(r_c), evolve(r_d))

    def _value(self, stock: float, future_rounds: int, p: float, memo: dict) -> float:
        key = (round(float(stock), 10), int(future_rounds), round(float(p), 10))
        if key in memo:
            return memo[key]
        l = int(future_rounds)
        x = float(stock)
        if l <= 0:
            val = 0.0
        elif l == 1:
            val = l * x / self.n
        else:
            s_c, s_d = self._next_stock(x, p)
            val_c = x / (2.0 * self.n) + self._value(s_c, l - 1, p, memo)
            val_d = x / self.n + self._value(s_d, l - 1, p, memo)
            val = max(val_c, val_d)
        memo[key] = val
        return val

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = int(history.round_number) + 1
        stock = float(current_stock)
        if history.round_number > 0:
            k_prev = int(history.opponent_cooperators[-1])
            k_prev = max(0, min(k_prev, self.n_opponents))
            if k_prev == 0:
                self._zero_streak += 1
            else:
                self._zero_streak = 0
            if k_prev == self.n_opponents:
                self._unanimous_streak += 1
            else:
                self._unanimous_streak = 0
            self._last_observed_k = k_prev
        else:
            self._zero_streak = 0
            self._unanimous_streak = 0
            self._last_observed_k = None
        if t >= self.r:
            self._last_round_number = history.round_number
            return Action.D
        if history.round_number == 0 or self._last_observed_k is None:
            p = 0.5
        else:
            p = self._last_observed_k / self.n_opponents if self.n_opponents > 0 else 0.5
        p = min(max(float(p), 0.0), 1.0)
        memo: dict = {}
        s_c_next, s_d_next = self._next_stock(stock, p)
        future_rounds = max(self.r - t, 0)
        u_c = stock / (2.0 * self.n) + self._value(s_c_next, future_rounds, p, memo)
        u_d = stock / self.n + self._value(s_d_next, future_rounds, p, memo)
        if self._zero_streak >= 2:
            self._last_round_number = history.round_number
            return Action.D
        unanimous_override = self._unanimous_streak >= 2
        if u_c > u_d + self._eps:
            choice = Action.C
        elif abs(u_c - u_d) <= self._eps and unanimous_override:
            choice = Action.C
        else:
            choice = Action.D
        self._last_round_number = history.round_number
        return choice

class Strategy_SELFISH_74(BaseStrategy):
    """
    Stock-preserving threshold strategy for the Common Pool Resource Game.
    Cooperates early, then conditions cooperation on high stock and recent
    opponent cooperation; defects aggressively when stock or cooperation falls.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(self.n_players - 1, 0)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = int(history.round_number)
        S = float(current_stock)
        if S <= 0.0:
            return Action.D
        if t == 0:
            return Action.C
        if t == self.n_rounds - 1:
            return Action.D
        last_my_action = bool(history.my_actions[-1]) if len(history.my_actions) > 0 else True
        has_opponent_data = len(history.opponent_cooperators) > 0
        if not has_opponent_data:
            return Action.C if S >= 0.8 * self.capacity else Action.D
        k = int(history.opponent_cooperators[-1])
        if self.n_opponents > 0:
            q = k / self.n_opponents
        else:
            q = 0.0
        high_stock = S >= 0.8 * self.capacity
        mid_high_stock = S >= 0.75 * self.capacity
        low_stock = S < 0.6 * self.capacity
        if last_my_action:
            if low_stock or q < 0.5:
                return Action.D
            return Action.C if mid_high_stock else Action.D
        if high_stock and q >= 0.75:
            return Action.C
        return Action.D

class Strategy_SELFISH_75(BaseStrategy):
    """
    Opens with cooperation, defects in the final two rounds, and in the middle
    defects only when the previous round had a sufficiently large cooperative
    quorum and the stock is at least half the capacity; otherwise cooperates.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.stable_quorum = int(math.ceil((self.n_players - 1) / 2))
        self.high_stock = self.capacity / 2.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        if round_number == 0:
            return Action.C
        if round_number >= self.n_rounds - 2:
            return Action.D
        last_opponent_cooperators = 0
        if len(history.opponent_cooperators) > 0:
            last_opponent_cooperators = int(history.opponent_cooperators[-1])
        if last_opponent_cooperators >= self.stable_quorum and float(current_stock) >= self.high_stock:
            return Action.D
        return Action.C

class Strategy_SELFISH_76(BaseStrategy):
    """
    Defect on the first and last rounds.
    In intermediate rounds, estimate opponent cooperation from recent history,
    then cooperate only if defection would threaten future reserve stock.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        if round_number == 0:
            return Action.D
        if round_number >= self.n_rounds - 1:
            return Action.D
        n = max(2, self.n_players)
        n_opponents = max(1, n - 1)
        last_round_count = int(history.opponent_cooperators[-1]) if round_number > 0 else 0
        last_round_rate = last_round_count / n_opponents
        if len(history.opponent_cooperators) > 0:
            cumulative_rate = float(np.mean(history.opponent_cooperators)) / n_opponents
        else:
            cumulative_rate = 0.0
        p = 0.5 * (last_round_rate + cumulative_rate)
        if p < 0.0:
            p = 0.0
        elif p > 1.0:
            p = 1.0
        m = self.n_rounds - round_number
        if m <= 1:
            return Action.D
        reserve = self.capacity * (m - 1) / m if m > 0 else self.capacity
        s = float(current_stock)
        s_c = s * (1.0 + (n - 1) * p) / (2.0 * n)
        s_d = s * ((n - 1) * p) / (2.0 * n)
        if s_d >= reserve:
            return Action.D
        if s_c >= reserve:
            return Action.C
        return Action.D

class Strategy_SELFISH_77(BaseStrategy):
    """
    Stock-preservation threshold strategy with default defection,
    adaptive cooperation under low-stock pressure, and short-run exploitation bias.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = max(2, int(game_description.n_players))
        self.r = max(2, int(game_description.n_rounds))
        self.capacity = float(game_description.capacity)
        self.x_hat = 1.0
        self._last_stock = None

    def _expected_next_stock(self, stock: float, coop_rate: float, self_action: Action) -> float:
        n = self.n
        cap = self.capacity
        stock = max(0.0, float(stock))
        coop_rate = min(1.0, max(0.0, float(coop_rate)))
        c_pay = stock / (2.0 * n)
        d_pay = stock / n
        opp_expected = coop_rate * c_pay + (1.0 - coop_rate) * d_pay
        if self_action == Action.C:
            total_consumption = c_pay + (n - 1) * opp_expected
        else:
            total_consumption = d_pay + (n - 1) * opp_expected
        remaining = max(0.0, stock - total_consumption)
        new_stock = remaining + 2.0 * remaining * (1.0 - remaining / cap) if cap > 0 else remaining
        return min(new_stock, cap)

    def _threshold(self, round_number: int) -> float:
        frac = round_number / max(1, self.r)
        if frac < 1.0 / 3.0:
            return 0.35 * self.capacity
        if frac < 2.0 / 3.0:
            return 0.25 * self.capacity
        return 0.15 * self.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number
        S = float(current_stock)
        cap = self.capacity
        n = self.n
        eps = 1e-12
        if t == 0:
            self._last_stock = S
            return Action.C if S <= 0.4 * cap else Action.D
        last_opp = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        n_opp = max(1, n - 1)
        x_t = min(1.0, max(0.0, last_opp / n_opp))
        self.x_hat = 0.7 * self.x_hat + 0.3 * x_t
        if self._last_stock is not None:
            prev = float(self._last_stock)
            if S < 0.8 * prev:
                self.x_hat -= 0.1
            elif S > prev:
                self.x_hat += 0.05
        self.x_hat = min(1.0, max(0.0, self.x_hat))
        self._last_stock = S
        if S <= 0.1 * cap:
            return Action.C
        if S >= cap and t < self.r:
            return Action.D
        if last_opp == 0 and S > 0.15 * cap:
            return Action.D
        if t >= self.r - 1:
            return Action.D if S >= 0.5 * cap else Action.C
        if t >= math.ceil(0.8 * self.r):
            return Action.C if S < 0.2 * cap else Action.D
        if last_opp / n_opp >= 0.6 and S > 0.25 * cap:
            return Action.D
        if len(history.opponent_cooperators) >= 2:
            prev_opp = int(history.opponent_cooperators[-2])
            prev_rate = min(1.0, max(0.0, prev_opp / n_opp))
            if prev_rate < 0.4 and x_t < 0.4:
                return Action.C if S < 0.2 * cap else Action.D
        if t < math.ceil(self.r / 3):
            if S < 0.4 * cap:
                return Action.C
            return Action.D
        E_C = self._expected_next_stock(S, self.x_hat, Action.C)
        E_D = self._expected_next_stock(S, self.x_hat, Action.D)
        tau_t = self._threshold(t)
        if abs(E_C - E_D) <= eps:
            return Action.D
        if E_D < tau_t and E_C >= E_D:
            return Action.C
        return Action.D

class Strategy_SELFISH_78(BaseStrategy):
    """
    Conservative resource-preservation strategy with a moving estimate of
    opponent cooperation and a short-run punishment/recovery mechanism.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.m = 1.0
        self.low = 0
        self._last_processed_round = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = float(self.game_description.capacity)
        round_number = history.round_number
        if round_number <= 0:
            if r == 2:
                return Action.C if current_stock == capacity and self.m == 1.0 else Action.D
            return Action.C
        start = self._last_processed_round
        end = round_number
        if end > start:
            for idx in range(start, end):
                c_prev = int(history.opponent_cooperators[idx]) if idx < len(history.opponent_cooperators) else 0
                if round_number > 1 or idx > 0:
                    denom = max(n - 1, 1)
                    self.m = 0.7 * self.m + 0.3 * (c_prev / denom)
                if self.m < 0.5:
                    self.low += 1
                else:
                    self.low = 0
            self._last_processed_round = end
        t = round_number + 1

        def above_with_tie(value: float, threshold: float) -> bool:
            eps = 1e-12
            if value > threshold + eps:
                return True
            if abs(value - threshold) <= eps:
                return current_stock >= 0.75 * capacity
            return False
        if t >= r - 1:
            if above_with_tie(self.m, 5 / 6) and current_stock >= 0.75 * capacity:
                return Action.C
            return Action.D
        if t == r:
            return Action.D
        if current_stock <= capacity / 4:
            return Action.D
        if self.low >= 2:
            if self.m >= 2 / 3 and current_stock >= capacity / 2:
                return Action.C
            return Action.D
        if t == 1:
            if r == 2:
                return Action.C if current_stock == capacity else Action.D
            return Action.C
        if above_with_tie(self.m, 2 / 3) and current_stock >= capacity / 2:
            return Action.C
        if above_with_tie(self.m, 1 / 2) and current_stock >= 3 * capacity / 4:
            return Action.C
        return Action.D

class Strategy_SELFISH_79(BaseStrategy):
    """
    Stateful common-pool strategy:
    - Start by cooperating.
    - Defect in the final round.
    - In intermediate rounds, cooperate only when stock and observed cooperation are high.
    - Enter defect_mode after low cooperation or low stock, and only exit when recovery is strong.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.defect_mode = False
        self._last_move = None

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = float(self.game_description.capacity)
        round_number = history.round_number
        high_stock = 0.75 * capacity
        low_stock = 0.4 * capacity
        high_coop = 2.0 / 3.0
        very_high_coop = 5.0 / 6.0
        if round_number == 0:
            self.defect_mode = False
            self._last_move = Action.C
            return Action.C
        if round_number >= r - 1:
            self._last_move = Action.D
            return Action.D
        opponents = max(n - 1, 1)
        prev_cooperators = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        f = prev_cooperators / opponents
        if current_stock <= capacity / (4.0 * max(n, 1)):
            self.defect_mode = True
        elif f < 0.5:
            self.defect_mode = True
        if self.defect_mode:
            if current_stock >= high_stock and f >= high_coop:
                self.defect_mode = False
            else:
                self._last_move = Action.D
                return Action.D
        if current_stock >= high_stock and f >= high_coop:
            self._last_move = Action.C
            return Action.C
        if current_stock >= low_stock and f >= very_high_coop:
            self._last_move = Action.C
            return Action.C
        self._last_move = Action.D
        return Action.D

class Strategy_SELFISH_80(BaseStrategy):
    """
    Default defect, conditional repair strategy for the common pool resource game.

    Defects by default, with early-round cooperation only after universal
    opponent cooperation, and maintenance cooperation only when stock is high
    and cooperation is clearly more sustainable than defection.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        S = float(current_stock)
        m = self.r - round_number
        if round_number == 0:
            return Action.D
        if m <= 2:
            return Action.D
        if S <= self.capacity / 6.0:
            return Action.D
        if S <= self.capacity / 3.0:
            return Action.D
        if round_number == 1:
            n_opponents = max(self.n - 1, 1)
            last_k = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
            if last_k >= n_opponents:
                return Action.C
            return Action.D
        if m <= 4 and S < self.capacity / 2.0:
            return Action.D
        n_opponents = self.n - 1
        if n_opponents <= 0:
            return Action.D
        last_k = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        q = last_k / n_opponents
        R_C = S * (q + 1.0) / (2.0 * self.n)
        R_D = S * q / (2.0 * self.n)
        S_C = R_C + 2.0 * R_C * (1.0 - R_C / self.capacity) if self.capacity > 0 else R_C
        S_D = R_D + 2.0 * R_D * (1.0 - R_D / self.capacity) if self.capacity > 0 else R_D
        S_C = min(S_C, self.capacity)
        S_D = min(S_D, self.capacity)
        cooperation_threshold = 1.0 - 2.0 / n_opponents
        if q >= cooperation_threshold and S >= self.capacity / 2.0 and (S_C - S_D >= self.capacity / (8.0 * self.n)) and (m > 2):
            return Action.C
        return Action.D

class Strategy_SELFISH_81(BaseStrategy):
    """
    Threshold-style strategy for the Common Pool Resource Game.

    Round 1:
    - Cooperate if n = 2, otherwise defect.

    Middle rounds:
    - Uses the previous round's opponent cooperators and current stock to choose
      the action that keeps the post-consumption stock closest to capacity / 2.
    - Includes special overrides for very low stock and near-full cooperation.

    Last round:
    - Defect.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.target_stock = self.capacity / 2.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.n
        r = self.r
        cap = self.capacity
        S = float(current_stock)
        if history.round_number == 0:
            return Action.C if n == 2 else Action.D
        if history.round_number >= r - 1:
            return Action.D
        k = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        if k < 0:
            k = 0
        if k > max(0, n - 1):
            k = max(0, n - 1)
        if S <= cap / 4.0:
            return Action.D if k == 0 else Action.C
        if k == n - 1 and S >= cap / 2.0:
            return Action.D
        denom = 2.0 * n
        if denom <= 0:
            return Action.D
        xC = S * (k + 1) / denom
        xD = S * k / denom
        h = self.target_stock
        distC = abs(xC - h)
        distD = abs(xD - h)
        if distD < distC:
            return Action.D
        if distC < distD:
            return Action.C
        return Action.D

class Strategy_SELFISH_82(BaseStrategy):
    """
    Cooperative-first strategy for the common pool resource game.

    Round 1 starts with cooperation. Later rounds compare a one-step selfish
    value of cooperating vs defecting, using the observed opponent cooperation
    rate from the previous round and a simple endgame / scarcity fallback.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self._n_minus_1 = max(self.n - 1, 1)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.n
        capacity = self.capacity
        round_number = history.round_number
        if round_number == 0:
            return Action.C
        S = float(current_stock)
        if S <= 0.0:
            return Action.D
        L = self.r - round_number
        if L <= 1:
            return Action.D
        last_k = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        p = last_k / self._n_minus_1
        if len(history.opponent_cooperators) >= 2:
            prev_k = int(history.opponent_cooperators[-2])
            if last_k == 0 and prev_k == 0:
                return Action.D
        if S <= capacity / max(n, 1) and p < 1.0:
            return Action.D
        if round_number == 1 and len(history.opponent_cooperators) == 1:
            p = 1.0
        m_C = 1.0 + p * (n - 1)
        m_D = p * (n - 1)
        R_C = S * m_C / (2.0 * n)
        R_D = S * m_D / (2.0 * n)
        N_C = min(R_C + 2.0 * R_C * (1.0 - (R_C / capacity if capacity > 0 else 0.0)), capacity)
        N_D = min(R_D + 2.0 * R_D * (1.0 - (R_D / capacity if capacity > 0 else 0.0)), capacity)
        V_C = S / (2.0 * n) + (L - 1) * N_C / (2.0 * n)
        V_D = S / n + (L - 1) * N_D / (2.0 * n)
        if p < 0.5 and S < capacity:
            return Action.D
        if V_C >= V_D:
            return Action.C
        return Action.D

class Strategy_SELFISH_83(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Cooperates initially.
    - Keeps cooperating only when the stock is healthy and opponents have been sufficiently cooperative.
    - Becomes more demanding after sharp stock drops.
    - Defects when the pool is depleted or near the endgame unless conditions are exceptionally favorable.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self._last_seen_stock = self.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number
        cap = self.capacity
        n_players = self.n_players
        n_opponents = max(n_players - 1, 1)
        previous_stock_drop = self._last_seen_stock - float(current_stock)
        self._last_seen_stock = float(current_stock)
        if t == 0:
            return Action.C
        if len(history.opponent_cooperators) > 0:
            c_last = int(history.opponent_cooperators[-1])
        else:
            c_last = 0
        p = c_last / n_opponents if n_opponents > 0 else 1.0
        if t == self.n_rounds - 1:
            return Action.C if current_stock == cap and p == 1.0 else Action.D
        if t == self.n_rounds - 2 and current_stock < 0.8 * cap:
            return Action.D
        if current_stock <= 0.25 * cap:
            return Action.D
        if current_stock <= 0.5 * cap:
            return Action.D
        if previous_stock_drop > 0.2 * cap:
            return Action.C if current_stock >= 0.85 * cap and p == 1.0 else Action.D
        return Action.C if current_stock >= 0.75 * cap and p >= 2.0 / 3.0 else Action.D

class Strategy_SELFISH_84(BaseStrategy):
    """
    Defect by default, and cooperate only when the pool is healthy,
    opponent cooperation is highly reliable, and enough rounds remain.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self._p_hat = 0.5
        self._last_seen_rounds = 0
        self._last_stock = None
        self._low_stock_streak = 0

    def _estimate_p_hat(self, history: PlayerHistory) -> float:
        p_hat = 0.5
        prev_count = None
        n_opponents = max(0, self.game_description.n_players - 1)
        if history.round_number <= 0 or n_opponents == 0:
            return p_hat
        for count in history.opponent_cooperators:
            count_int = int(count)
            p_obs = count_int / n_opponents if n_opponents > 0 else 0.0
            p_hat = 0.5 * p_hat + 0.5 * p_obs
            if prev_count is not None and prev_count - count_int >= 2:
                p_hat = min(p_hat, p_obs)
            prev_count = count_int
        return float(p_hat)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = int(self.game_description.n_players)
        r = int(self.game_description.n_rounds)
        capacity = float(self.game_description.capacity)
        if history.round_number == 0:
            self._p_hat = 0.5
            self._last_stock = float(current_stock)
            self._low_stock_streak = 1 if float(current_stock) < 0.2 * capacity else 0
            return Action.D
        p_hat = self._estimate_p_hat(history)
        self._p_hat = p_hat
        if self._last_stock is not None and float(current_stock) < 0.2 * capacity and (float(self._last_stock) < 0.2 * capacity):
            self._low_stock_streak = 2
        elif float(current_stock) < 0.2 * capacity:
            self._low_stock_streak = 1
        else:
            self._low_stock_streak = 0
        self._last_stock = float(current_stock)
        rounds_played = int(history.round_number)
        L = r - rounds_played
        if L <= 1:
            return Action.D
        if current_stock <= 0.0:
            return Action.D
        if rounds_played == 0:
            return Action.D
        if self._low_stock_streak >= 2 and (not (p_hat >= 0.9 and current_stock >= 0.6 * capacity)):
            return Action.D
        threshold_ok = p_hat >= 0.75
        if n == 2:
            threshold_ok = p_hat >= 0.999999
        if not (L >= 3 and threshold_ok and (current_stock >= 0.6 * capacity)):
            return Action.D
        xC = (n - 1) * p_hat + 1.0
        xD = (n - 1) * p_hat

        def next_stock(x: float) -> float:
            R = float(current_stock) * x / (2.0 * n)
            val = 3.0 * R - 2.0 * (R * R) / capacity
            if val > capacity:
                return capacity
            if val < 0.0:
                return 0.0
            return float(val)
        nC = next_stock(xC)
        nD = next_stock(xD)
        if nC >= nD and nC >= 0.9 * float(current_stock):
            return Action.C
        return Action.D

class Strategy_SELFISH_85(BaseStrategy):
    """
    Selfish common-pool strategy with exact stock tracking from history.
    Defects by default, but cooperates when stock is low enough to protect
    future rounds or when the previous round's cooperation was sufficiently high.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.low_band = 0.6 * self.capacity
        self.high_band = 0.85 * self.capacity
        self.very_low_band = 0.3 * self.capacity
        self.very_high_band = 0.9 * self.capacity
        self._estimated_stock = float(self.capacity)

    def _next_stock(self, stock: float, my_action: Action, coop_opponents: int) -> float:
        n = max(self.n, 2)
        s = float(stock)
        coop_opponents = int(coop_opponents)
        if my_action == Action.C:
            my_consumption = s / (2.0 * n)
        else:
            my_consumption = s / float(n)
        opp_coop_consumption = coop_opponents * (s / (2.0 * n))
        opp_def_consumption = (n - 1 - coop_opponents) * (s / float(n))
        total_consumption = my_consumption + opp_coop_consumption + opp_def_consumption
        remaining = s - total_consumption
        if remaining < 0.0:
            remaining = 0.0
        growth = 2.0 * remaining * (1.0 - remaining / self.capacity) if self.capacity > 0.0 else 0.0
        new_stock = remaining + growth
        if new_stock < 0.0:
            new_stock = 0.0
        elif new_stock > self.capacity:
            new_stock = self.capacity
        return float(new_stock)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        stock = float(current_stock) if current_stock is not None else float(self._estimated_stock)
        if stock < 0.0:
            stock = 0.0
        elif stock > self.capacity:
            stock = self.capacity
        self._estimated_stock = stock
        if round_number == 0:
            return Action.D
        if round_number >= self.r - 1:
            return Action.D
        last_coop_opponents = 0
        if len(history.opponent_cooperators) > 0:
            last_coop_opponents = int(history.opponent_cooperators[-1])
        if stock < self.very_low_band:
            return Action.C
        if stock > self.very_high_band:
            next_if_d = self._next_stock(stock, Action.D, last_coop_opponents)
            if next_if_d < self.low_band:
                return Action.C
            return Action.D
        if stock < self.low_band:
            return Action.C
        if stock > self.high_band:
            return Action.D
        if last_coop_opponents >= (self.n - 1) / 2.0:
            return Action.C
        return Action.D

class Strategy_SELFISH_86(BaseStrategy):
    """
    Start by cooperating, then conditionally cooperate only when opponents were
    sufficiently cooperative, the stock is healthy, and recent defections have
    not persisted. Always defect in the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.defection_streak = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        if round_number == 0:
            self.defection_streak = 0
            return Action.C
        if round_number == self.n_rounds - 1:
            return Action.D
        n_opponents = max(self.n_players - 1, 0)
        if n_opponents > 0 and len(history.opponent_cooperators) > 0:
            q = float(history.opponent_cooperators[-1]) / n_opponents
        else:
            q = 0.0
        x = current_stock / self.capacity if self.capacity > 0 else 0.0
        prev_stock_start = current_stock
        if len(history.my_payoffs) > 0 and len(history.my_actions) > 0:
            last_payoff = float(history.my_payoffs[-1])
            last_action = bool(history.my_actions[-1])
            if last_action:
                prev_stock_start = last_payoff * 2.0 * self.n_players
            else:
                prev_stock_start = last_payoff * float(self.n_players)
        stock_drop_last_round = max(prev_stock_start - current_stock, 0.0)
        cooperate_conditions = q >= 0.5 and x >= 0.5 and (stock_drop_last_round <= self.capacity / 4.0) and (self.defection_streak < 2)
        if cooperate_conditions:
            self.defection_streak = 0
            return Action.C
        self.defection_streak += 1
        return Action.D

class Strategy_SELFISH_87(BaseStrategy):
    """
    Threshold-based common-pool strategy:
    - Starts cooperatively only in longer games (r >= 4).
    - Cooperates only under high stock, sufficient prior cooperation, and with
      enough rounds remaining.
    - Defects permanently after low cooperation or depleted stock.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self._n = int(game_description.n_players)
        self._r = int(game_description.n_rounds)
        self._capacity = float(game_description.capacity)
        self._mode = 'cooperate' if self._r >= 4 else 'defect'
        self._c_last = max(self._n - 1, 0)
        self._seen_rounds = 0
        self._min_c_last_to_cooperate = math.ceil(2 * max(self._n - 1, 0) / 3)
        self._min_prev_coops_to_keep_coop = math.ceil(max(self._n - 1, 0) / 2)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        current_stock = float(current_stock)
        n_opponents = max(self._n - 1, 0)
        if round_number > self._seen_rounds:
            start_idx = self._seen_rounds
            end_idx = round_number
            opp = history.opponent_cooperators
            for idx in range(start_idx, end_idx):
                if idx < len(opp):
                    c = int(opp[idx])
                    if c < self._min_prev_coops_to_keep_coop:
                        self._mode = 'defect'
                    else:
                        self._mode = 'cooperate'
                    self._c_last = c
            self._seen_rounds = round_number
        t = round_number + 1
        L = self._r - t + 1
        if L <= 1:
            self._mode = 'defect'
            return Action.D
        if current_stock < 0.5 * self._capacity:
            self._mode = 'defect'
            return Action.D
        if self._mode == 'defect':
            return Action.D
        if current_stock < 0.75 * self._capacity:
            self._mode = 'defect'
            return Action.D
        if self._c_last < self._min_c_last_to_cooperate:
            self._mode = 'defect'
            return Action.D
        if L < 3:
            self._mode = 'defect'
            return Action.D
        if current_stock >= 0.9 * self._capacity and self._c_last >= n_opponents:
            return Action.C
        return Action.C

class Strategy_SELFISH_88(BaseStrategy):
    """
    Common-pool strategy:
    - Cooperate in the first round
    - Defect in the last round
    - Defect when stock is low
    - Cooperate only when prior cooperation was sufficiently high and stock is rich
    - Otherwise defect
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(0, self.n_players - 1)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number + 1
        r = self.n_rounds
        cap = self.capacity
        if t >= r:
            return Action.D
        if history.round_number == 0:
            return Action.C
        if current_stock <= cap / 4.0:
            return Action.D
        k = 0
        if len(history.opponent_cooperators) > 0:
            k = int(history.opponent_cooperators[-1])
        if self.n_opponents > 0:
            q = k / self.n_opponents
        else:
            q = 0.0
        if q >= 0.5 and current_stock >= cap / 2.0:
            return Action.C
        if q == 1.0:
            return Action.C
        return Action.D

class Strategy_SELFISH_89(BaseStrategy):
    """
    Trust-then-punish strategy for the Common Pool Resource Game.

    - Starts by cooperating.
    - Tracks whether the last observed round was fully cooperative.
    - Cooperates when in trust mode and the stock is healthy.
    - Defects after any meaningful defection, and only returns to cooperation
      after two consecutive fully cooperative rounds with sufficient stock.
    - Defects in the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.capacity = float(game_description.capacity)
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.mode = 'trust'
        self.recent_streak = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        half_capacity = self.capacity / 2.0
        eps = 1e-12
        if round_number == 0:
            self.mode = 'trust'
            self.recent_streak = 0
            return Action.C
        n_opponents = max(self.n_players - 1, 0)
        last_k = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        if n_opponents > 0:
            p_last = last_k / n_opponents
        else:
            p_last = 1.0
        if p_last >= 1.0 - eps:
            self.recent_streak += 1
        else:
            self.recent_streak = 0
            self.mode = 'punish'
        current_round_index = round_number + 1
        is_last_round = current_round_index >= self.n_rounds
        is_penultimate_round = current_round_index == self.n_rounds - 1
        if current_stock <= 0.0 + eps:
            return Action.D
        if is_last_round:
            return Action.D
        if self.mode == 'punish':
            if self.recent_streak >= 2 and current_stock >= half_capacity - eps:
                self.mode = 'trust'
                return Action.C
            return Action.D
        if is_penultimate_round and p_last >= 1.0 - eps:
            return Action.C
        if current_stock >= half_capacity - eps:
            return Action.C
        return Action.D

class Strategy_SELFISH_90(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Cooperate in round 1.
    - Defect in the last round, when stock is exhausted, or when no opponents cooperated.
    - Otherwise choose C only when the current stock is high and cooperation is likely to preserve future stock;
      else defect.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.permanent_defect = False
        self.default_action = Action.C
        self.last_seen_payoff_gap = False

    def _next_stock(self, stock: float, k_opponents_coop: int, my_action: Action) -> float:
        n = max(2, self.n)
        cap = max(1e-12, self.capacity)
        k = max(0, min(int(k_opponents_coop), n - 1))
        if stock <= 0.0:
            return 0.0
        if my_action == Action.C:
            total_consumption = (k + 1) * stock / (2.0 * n) + (n - 1 - k) * stock / n
        else:
            total_consumption = k * stock / (2.0 * n) + (n - k) * stock / n
        remaining = stock - total_consumption
        if remaining < 0.0:
            remaining = 0.0
        growth = 2.0 * remaining * (1.0 - remaining / cap)
        nxt = remaining + growth
        if nxt > cap:
            nxt = cap
        if nxt < 0.0:
            nxt = 0.0
        return nxt

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = int(history.round_number) + 1
        n = max(2, self.n)
        cap = max(1e-12, self.capacity)
        S_t = float(current_stock)
        if t == 1:
            self.default_action = Action.C
            return Action.C
        if t >= self.r or S_t <= 0.0 or self.permanent_defect:
            return Action.D
        k_t = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        k_t = max(0, min(k_t, n - 1))
        if len(history.my_payoffs) > 0:
            my_last_action = bool(history.my_actions[-1])
            last_payoff = float(history.my_payoffs[-1])
            coop_payoff = S_t / (2.0 * n)
            defect_payoff = S_t / n
            if coop_payoff < defect_payoff:
                self.last_seen_payoff_gap = True
                self.default_action = Action.D
        if self.last_seen_payoff_gap and S_t > 1e-12:
            if S_t < 0.15 * cap and k_t > 0:
                pass
            else:
                return Action.D
        if t == 2 and len(history.opponent_cooperators) > 0 and (int(history.opponent_cooperators[-1]) == 0):
            self.permanent_defect = True
            return Action.D
        if k_t == 0:
            return Action.D
        s_next_c = self._next_stock(S_t, k_t, Action.C)
        s_next_d = self._next_stock(S_t, k_t, Action.D)
        if S_t / n >= S_t / (2.0 * n) + 1e-12 and s_next_d >= s_next_c:
            return Action.D
        threshold = math.ceil((n - 1) / 2)
        if S_t >= cap / 2.0 and k_t >= threshold and (s_next_c >= s_next_d):
            return Action.C
        if S_t < cap / 2.0:
            if s_next_c > s_next_d + 1e-09 and k_t >= threshold:
                return Action.C
            return Action.D
        return Action.D

class Strategy_SELFISH_91(BaseStrategy):
    """
    Common-pool strategy:
    - Cooperate in round 1.
    - Defect in the final round.
    - In middle rounds, cooperate if enough opponents cooperated previously
      or if the stock is low; otherwise defect.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(self.n_players - 1, 0)
        self.low_stock_threshold = self.capacity / 3.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        if round_number == 0:
            return Action.C
        if round_number >= self.n_rounds - 1:
            return Action.D
        try:
            prev_opponent_cooperators = int(history.opponent_cooperators[-1])
        except Exception:
            return Action.C
        if self.n_opponents <= 0:
            q = 1.0
        else:
            q = prev_opponent_cooperators / float(self.n_opponents)
        if float(current_stock) <= self.low_stock_threshold:
            return Action.C
        if q >= 0.5:
            return Action.C
        return Action.D

class Strategy_SELFISH_92(BaseStrategy):
    """
    Selfish recovery strategy for the Common Pool Resource Game.

    Default behavior is to defect.
    Cooperate only as a short-term recovery move when:
    - stock is in the low-stock zone,
    - opponents cooperated strongly enough in the previous round,
    - and stock did not shrink relative to the previous round.

    Cooperation is immediately abandoned once any condition fails.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.n_players
        r = self.n_rounds
        capacity = self.capacity
        if history.round_number == 0:
            return Action.D
        if current_stock <= 0:
            return Action.D
        if history.round_number >= r - 1:
            return Action.D
        if len(history.opponent_cooperators) == 0:
            return Action.D
        last_opponent_cooperators = int(history.opponent_cooperators[-1])
        n_opponents = max(n - 1, 0)
        if n_opponents <= 0:
            return Action.D
        if last_opponent_cooperators <= 1:
            return Action.D
        rho = last_opponent_cooperators / n_opponents
        low_stock_zone = current_stock <= capacity / 2.0
        if history.round_number < 2:
            stock_did_not_shrink = False
        else:
            previous_stock = float(current_stock + float(history.my_payoffs[-1]) * 0.0)
            stock_did_not_shrink = False
        if not low_stock_zone:
            return Action.D
        if rho < 2.0 / 3.0:
            return Action.D
        if not stock_did_not_shrink:
            return Action.D
        return Action.C

class Strategy_SELFISH_93(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Opens with cooperation.
    - Uses a stock-and-history-based base rule.
    - Enters a short punishment window after weak opponent cooperation.
    - Allows recovery when stock has rebuilt.
    - Defaults to defection when conditions are ambiguous.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(getattr(game_description, 'n_players', 2))
        self.r = int(getattr(game_description, 'n_rounds', 2))
        self.capacity = float(getattr(game_description, 'capacity', 1.0))
        self._punishment_remaining = 0
        self._depletion_mode = False
        self._last_seen_round = -1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        n = max(2, self.n)
        r = max(2, self.r)
        capacity = self.capacity if self.capacity > 0 else 1.0
        if round_number == 0:
            self._punishment_remaining = 0
            self._depletion_mode = False
            self._last_seen_round = 0
            return Action.C
        k_prev = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        prev_stock = float(current_stock)
        if prev_stock <= 0.0:
            self._depletion_mode = True
        if self._last_seen_round != round_number - 1:
            self._punishment_remaining = max(0, self._punishment_remaining)
        self._last_seen_round = round_number
        if round_number == r - 1:
            if prev_stock < 0.2 * capacity and k_prev == n - 1:
                self._punishment_remaining = 0
                self._depletion_mode = False
                return Action.C
            self._punishment_remaining = 0
            return Action.D
        if k_prev <= n / 2.0:
            remaining = min(3, r - round_number)
            if remaining > self._punishment_remaining:
                self._punishment_remaining = remaining
        if self._punishment_remaining > 0:
            if prev_stock >= 0.9 * capacity and k_prev == n - 1:
                self._punishment_remaining = 0
                self._depletion_mode = False
                return Action.C
            self._punishment_remaining = max(0, self._punishment_remaining - 1)
            return Action.D
        if self._depletion_mode:
            if prev_stock >= 0.8 * capacity and k_prev >= n - 2:
                self._depletion_mode = False
            else:
                return Action.D
        if prev_stock >= 0.75 * capacity:
            if n == 2:
                if k_prev >= 1:
                    return Action.C
                return Action.D
            if k_prev >= n - 2:
                return Action.C
        return Action.D

class Strategy_SELFISH_94(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Cooperate in the first round.
    - Defect in the final round.
    - Otherwise, respond to stock levels and observed opponent cooperation patterns.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(self.n_players - 1, 0)
        self._third_capacity = self.capacity / 3.0
        self._half_capacity = self.capacity / 2.0
        self._defect_threshold_last = math.ceil(self.n_opponents / 2.0)
        self._cooperate_threshold_last = math.floor(self.n_opponents / 3.0)
        self._avg_threshold = self.n_opponents / 2.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        if round_number == 0:
            return Action.C
        if round_number >= self.n_rounds - 1:
            return Action.D
        if current_stock <= self._third_capacity:
            return Action.C
        c_last = int(history.opponent_cooperators[-1]) if round_number > 0 else 0
        total_opponent_cooperations = int(np.sum(history.opponent_cooperators))
        c_avg = total_opponent_cooperations / round_number if round_number > 0 else 0.0
        if c_last >= self._defect_threshold_last and c_avg >= self._avg_threshold:
            return Action.D
        if c_last <= self._cooperate_threshold_last or c_avg < self._avg_threshold:
            return Action.C
        if current_stock > self._half_capacity:
            return Action.D
        return Action.C

class Strategy_SELFISH_95(BaseStrategy):
    """
    Adaptive common-pool strategy:
    cooperate when stock is healthy and opponents were cooperative,
    defect under low cooperation, low stock, or endgame pressure.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self._midpoint = self.capacity / 2.0
        self._tight_threshold = self.capacity / 2.0 - self.capacity / (4.0 * max(self.n_players, 1))
        self._loose_threshold = self.capacity / 2.0 + self.capacity / (4.0 * max(self.n_players, 1))
        self._n_opponents = max(self.n_players - 1, 1)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number
        if t <= 0:
            return Action.C if self.capacity >= self._midpoint else Action.D
        last_opponent_coop = int(history.opponent_cooperators[-1])
        p_last = last_opponent_coop / self._n_opponents
        rounds_remaining = self.n_rounds - t
        endgame = rounds_remaining <= 1
        short_horizon = rounds_remaining <= 2
        prev_stock = current_stock
        if len(history.my_payoffs) >= 1:
            prev_stock = current_stock
        if t >= 2:
            prev_p = int(history.opponent_cooperators[-2]) / self._n_opponents
        else:
            prev_p = p_last
        two_low_rounds = False
        if t >= 2:
            low1 = int(history.opponent_cooperators[-1]) / self._n_opponents < 0.5
            low2 = int(history.opponent_cooperators[-2]) / self._n_opponents < 0.5
            two_low_rounds = low1 and low2
        two_full_rounds = False
        if t >= 2:
            full1 = int(history.opponent_cooperators[-1]) / self._n_opponents >= 1.0
            full2 = int(history.opponent_cooperators[-2]) / self._n_opponents >= 1.0
            two_full_rounds = full1 and full2
        threshold = self._midpoint
        if p_last >= 1.0:
            threshold = self._tight_threshold
        elif p_last <= 0.5:
            threshold = self._loose_threshold
        stock_at_threshold = abs(current_stock - threshold) <= 1e-12
        if endgame:
            if self.n_players == 2:
                return Action.C if current_stock >= self._midpoint and p_last >= 1.0 else Action.D
            if current_stock >= self._midpoint and p_last >= 0.75:
                return Action.C
            return Action.D
        if two_low_rounds and current_stock < self._midpoint:
            return Action.D
        if p_last < 0.5:
            return Action.D
        if two_full_rounds and current_stock >= self._midpoint:
            return Action.C
        if current_stock < self._midpoint:
            return Action.D
        if stock_at_threshold:
            return Action.C if p_last >= 1.0 else Action.D
        if short_horizon and p_last < 1.0:
            return Action.D
        if current_stock >= threshold and p_last >= 0.5:
            if current_stock >= 0.9 * self.capacity and p_last >= 0.5:
                return Action.C
            return Action.C
        return Action.D

class Strategy_SELFISH_96(BaseStrategy):
    """
    Common-pool strategy that defects early, exploits sustained cooperation while
    the pool is healthy, switches to conservation when the stock becomes fragile,
    and defects in the final two rounds to take immediate payoff.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.mode = 'exploit'

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = float(self.game_description.capacity)
        round_number = history.round_number
        rounds_left = r - round_number
        if round_number == 0:
            return Action.D
        prev_opp_coop = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        n_opponents = max(n - 1, 1)
        coop_rate = prev_opp_coop / n_opponents
        if current_stock <= 0.5 * capacity:
            self.mode = 'conserve'
            return Action.C
        if rounds_left <= 2:
            return Action.D if current_stock > 0 else Action.C
        if self.mode == 'conserve' and current_stock >= 0.8 * capacity and (coop_rate >= 0.5):
            self.mode = 'exploit'
        if self.mode == 'exploit':
            if coop_rate >= 0.5 and current_stock >= 0.5 * capacity:
                return Action.D
            self.mode = 'conserve'
            return Action.C
        return Action.C

class Strategy_SELFISH_97(BaseStrategy):
    """
    Defect by default; cooperate only after sustained evidence that opponents
    are mostly cooperating and the common pool remains sufficiently rich.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.good_streak = 0
        self.force_defect = False
        self.defect_next_round = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_players = int(self.game_description.n_players)
        n_rounds = int(self.game_description.n_rounds)
        capacity = float(self.game_description.capacity)
        rounds_played = int(history.round_number)
        round_index_1_based = rounds_played + 1
        if current_stock < capacity / 4.0:
            self.force_defect = True
        if rounds_played > 0:
            last_opponents = int(history.opponent_cooperators[-1])
            n_opponents = max(n_players - 1, 1)
            p_last = last_opponents / n_opponents
            if p_last >= 2.0 / 3.0:
                self.good_streak += 1
            else:
                self.good_streak = 0
            if p_last < 0.5:
                self.good_streak = 0
                self.defect_next_round = True
            else:
                self.defect_next_round = False
        if round_index_1_based == 1 or round_index_1_based == n_rounds:
            return Action.D
        if self.defect_next_round:
            self.defect_next_round = False
            return Action.D
        if self.force_defect:
            return Action.D
        if self.good_streak >= 2 and current_stock >= capacity / 2.0 and (round_index_1_based <= n_rounds - 2):
            return Action.C
        return Action.D

class Strategy_SELFISH_98(BaseStrategy):
    """
    Tit-for-one-step cooperative threshold strategy for the Common Pool Resource Game.

    - Round 1: defect.
    - Thereafter: cooperate only if the previous round was fully cooperative by all
      opponents, current stock is at least 3/4 of capacity, and we are not in the
      final two rounds.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.stock_threshold = 0.75 * self.capacity
        self._previous_round_fully_cooperative = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        if round_number == 0:
            self._previous_round_fully_cooperative = False
            return Action.D
        last_opponent_cooperators = int(history.opponent_cooperators[-1])
        self._previous_round_fully_cooperative = last_opponent_cooperators >= max(0, self.n_players - 1)
        next_round_index = round_number + 1
        if next_round_index >= self.n_rounds - 1:
            return Action.D
        if self._previous_round_fully_cooperative and float(current_stock) >= self.stock_threshold:
            return Action.C
        return Action.D

class Strategy_SELFISH_99(BaseStrategy):
    """
    Conservative common-pool strategy:
    cooperate only when stock is healthy and opponents have recently been highly cooperative,
    otherwise defect. Becomes stricter near the end of the game and after any low-cooperation round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.H = 3.0 * self.n
        self.M = 2.0 * self.n
        self.L = 1.5 * self.n
        self.n_opponents = max(self.n - 1, 0)
        self.unanimous_threshold = self.n_opponents
        self.strong_coop_threshold = math.ceil(0.8 * self.n_opponents) if self.n_opponents > 0 else 0
        self.half_coop_threshold = math.ceil(self.n_opponents / 2) if self.n_opponents > 0 else 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number + 1

        def unanimous_last_two() -> bool:
            if history.round_number < 2:
                return False
            return int(history.opponent_cooperators[-1]) == self.n_opponents and int(history.opponent_cooperators[-2]) == self.n_opponents

        def recent_low_coop_override() -> bool:
            if history.round_number >= 1:
                if int(history.opponent_cooperators[-1]) < self.half_coop_threshold:
                    return True
            if history.round_number >= 2:
                if int(history.opponent_cooperators[-2]) < self.half_coop_threshold:
                    return True
            return False
        if recent_low_coop_override():
            return Action.D
        if t == 1:
            return Action.C if self.capacity >= 4.0 * self.n else Action.D
        if self.n_opponents <= 0:
            return Action.D
        k_prev = int(history.opponent_cooperators[-1]) if history.round_number > 0 else 0
        q_prev = k_prev / self.n_opponents if self.n_opponents > 0 else 0.0
        if t == self.r:
            if current_stock >= self.L and q_prev == 1.0:
                return Action.C
            return Action.D
        if t == self.r - 1:
            if current_stock >= self.H and unanimous_last_two():
                return Action.C
            return Action.D
        if current_stock < self.M:
            return Action.D
        if current_stock < self.H:
            if q_prev == 1.0 and unanimous_last_two():
                return Action.C
            return Action.D
        if q_prev >= 0.75 and k_prev >= self.strong_coop_threshold:
            return Action.C
        return Action.D

class Strategy_SELFISH_100(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Cooperate initially.
    - Defect under low stock, low opponent cooperation, near the endgame, or after sustained decline.
    - Cooperate only when the stock is healthy, opponents are highly cooperative, and enough rounds remain.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        n_players = self.n_players
        n_opponents = max(n_players - 1, 0)
        remaining_rounds = self.n_rounds - round_number
        if round_number == 0:
            return Action.C
        if remaining_rounds <= 1:
            return Action.D
        capacity = self.capacity if self.capacity > 0 else 1.0
        s = float(current_stock) / capacity
        prev_k = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        q = prev_k / n_opponents if n_opponents > 0 else 0.0
        if remaining_rounds == 2:
            return Action.C if q >= 1.0 and s >= 0.75 else Action.D
        if len(history.opponent_cooperators) >= 3:
            q_prev = history.opponent_cooperators[-2] / n_opponents if n_opponents > 0 else 0.0
            q_prev_prev = history.opponent_cooperators[-3] / n_opponents if n_opponents > 0 else 0.0
            if q_prev_prev > q_prev > q:
                return Action.D
        if len(history.opponent_cooperators) >= 2:
            q_prev = history.opponent_cooperators[-2] / n_opponents if n_opponents > 0 else 0.0
            if q_prev < 0.75 and q < 0.75:
                return Action.D
        if s <= 0.35 or q < 0.5:
            return Action.D
        if len(history.opponent_cooperators) >= 2:
            prev_prev_k = int(history.opponent_cooperators[-2])
            prev_prev_q = prev_prev_k / n_opponents if n_opponents > 0 else 0.0
            if prev_prev_q < 0.5:
                return Action.D
        if 0.35 < s < 0.5:
            return Action.C if q >= 1.0 and remaining_rounds > 3 else Action.D
        if s >= 0.5 and q >= 0.75 and (remaining_rounds > 2):
            return Action.C
        return Action.D

class Strategy_SELFISH_101(BaseStrategy):
    """
    Cautious common-pool strategy:
    - Always defects on the first, penultimate, and final rounds.
    - Defects when stock is exhausted or cooperation has recently collapsed.
    - Cooperates only when recent opponent cooperation is sufficiently high
      and the remaining stock is still safe enough to preserve.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self._capacity = float(game_description.capacity)
        self._n_players = int(game_description.n_players)
        self._n_opponents = max(0, self._n_players - 1)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = int(history.round_number) + 1
        r = int(self.game_description.n_rounds)
        m = r - t + 1
        if t == 1:
            return Action.D
        if m <= 2:
            return Action.D
        if current_stock <= 0:
            return Action.D
        opp_n = self._n_opponents
        if opp_n <= 0:
            return Action.D
        observed_rounds = int(history.round_number)
        if observed_rounds <= 0:
            return Action.D
        coop_fracs = []
        recent_len = min(3, observed_rounds)
        start_idx = observed_rounds - recent_len
        for idx in range(start_idx, observed_rounds):
            cnt = int(history.opponent_cooperators[idx])
            frac = cnt / opp_n
            if frac < 0.0:
                frac = 0.0
            elif frac > 1.0:
                frac = 1.0
            coop_fracs.append(frac)
        while len(coop_fracs) < 3:
            coop_fracs.insert(0, 0.0)
        q_bar = float(np.mean(np.array(coop_fracs, dtype=np.float64)))
        if observed_rounds >= 2:
            last_two = history.opponent_cooperators[-2:]
            frac1 = int(last_two[0]) / opp_n
            frac2 = int(last_two[1]) / opp_n
            if frac1 < 0.5 and frac2 < 0.5:
                return Action.D
        high_coop = q_bar >= 2.0 / 3.0
        moderate_coop = q_bar >= 0.5
        stock_safe = current_stock >= self._capacity / 4.0
        if high_coop and current_stock > 0 or (moderate_coop and stock_safe and (m >= 3)):
            return Action.C
        return Action.D

class Strategy_SELFISH_102(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Starts cooperatively only in sufficiently large/long games.
    - Defects in the final round.
    - Cooperates only when the pool is high, others were sufficiently cooperative,
      and the stock has not dropped sharply.
    - Enters a defensive defecting mode after two consecutive bad observations,
      and exits only after recovery.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.opponent_threshold = 1.0 if self.n_players == 2 else 2.0 / 3.0
        self.round_threshold = 0.5
        self._last_observed_stock = None
        self._bad_streak = 0
        self._locked_defect = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        stock = float(current_stock)
        if stock <= 0.0:
            return Action.D
        comp_stock = self.capacity if stock >= self.capacity else stock
        if round_number <= 0:
            rho_prev = 0.0
            opp_coop_prev = 0
        else:
            opp_coop_prev = int(history.opponent_cooperators[-1])
            denom = max(self.n_players - 1, 1)
            rho_prev = opp_coop_prev / denom
        current_bad = comp_stock < 0.6 * self.capacity or rho_prev < 0.5
        if current_bad:
            self._bad_streak += 1
        else:
            self._bad_streak = 0
        recovered = comp_stock >= 0.85 * self.capacity and rho_prev >= self.opponent_threshold
        if self._locked_defect:
            if recovered:
                self._locked_defect = False
        elif self._bad_streak >= 2 and (not recovered):
            self._locked_defect = True
        if round_number >= self.n_rounds - 1:
            self._last_observed_stock = stock
            return Action.D
        if self._locked_defect:
            self._last_observed_stock = stock
            return Action.D
        if round_number == 0:
            action = Action.C if self.n_rounds >= 6 and self.capacity >= 4.0 * self.n_players else Action.D
            self._last_observed_stock = stock
            return action
        prev_stock = self._last_observed_stock
        stock_did_not_fall_much = True
        if prev_stock is not None and prev_stock > 0.0:
            stock_did_not_fall_much = comp_stock >= 0.85 * prev_stock
        if comp_stock >= 0.85 * self.capacity and rho_prev >= self.opponent_threshold and stock_did_not_fall_much:
            action = Action.C
        else:
            action = Action.D
        self._last_observed_stock = stock
        return action

class Strategy_SELFISH_103(BaseStrategy):
    """
    Exponentially weighted stock-preserving threshold strategy.

    Tracks an estimate q of opponent cooperation, starts by defecting,
    and cooperates only when stock is low, opponents appear sufficiently
    cooperative, and cooperation is predicted to preserve more future stock
    than defection.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.q = 1.0
        self.eps = 1e-09

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.n
        r = self.r
        capacity = self.capacity
        round_number = int(history.round_number)
        if round_number > 0:
            opp_count = int(history.opponent_cooperators[-1])
            n_opponents = max(n - 1, 1)
            observed_fraction = opp_count / n_opponents
            self.q = 0.7 * self.q + 0.3 * observed_fraction
        if round_number == 0:
            return Action.D
        if round_number >= r - 1:
            return Action.D
        S = float(current_stock)
        if S <= 0.0:
            return Action.D
        q = float(self.q)
        xD = 1.0 + (n - 1) * (1.0 - q)
        xC = (n - 1) * (1.0 - q)
        RD = S * (n - xD) / (2.0 * n)
        RC = S * (n - xC) / (2.0 * n)
        nextD = RD + 2.0 * RD * (1.0 - RD / capacity) if capacity > 0.0 else RD
        nextC = RC + 2.0 * RC * (1.0 - RC / capacity) if capacity > 0.0 else RC
        nextD = min(nextD, capacity)
        nextC = min(nextC, capacity)
        should_cooperate = S < 0.35 * capacity and q >= 0.5 and (nextC - nextD > self.eps) and (nextD < 0.6 * capacity)
        return Action.C if should_cooperate else Action.D

class Strategy_SELFISH_104(BaseStrategy):
    """
    Conditional cooperation strategy for the Common Pool Resource Game.

    - Cooperate in the first round.
    - Defect in the last round.
    - In between, use stock pressure and prior-round opponent cooperation
      to decide whether to preserve the pool or exploit it.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(0, self.n_players - 1)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        if round_number == 0:
            return Action.C
        tau = self.n_rounds - round_number
        if tau <= 1:
            return Action.D
        if self.n_opponents > 0 and len(history.opponent_cooperators) > 0:
            k = int(history.opponent_cooperators[-1])
            rho = k / self.n_opponents
        else:
            rho = 0.0
        cap = self.capacity
        x = float(current_stock) / cap if cap > 0 else 0.0
        if x <= 1.0 / 3.0:
            return Action.C if rho >= 2.0 / 3.0 else Action.D
        if x < 2.0 / 3.0:
            return Action.C if rho >= 0.5 else Action.D
        if rho == 1.0 and tau >= 3:
            return Action.C
        return Action.D

class Strategy_SELFISH_105(BaseStrategy):
    """
    Conditional common-pool strategy:
    - Round 1: defect
    - Middle rounds: cooperate if stock is at or below half capacity;
      otherwise defect when at least half of opponents cooperated last round,
      else cooperate
    - Final round: defect
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.capacity = float(game_description.capacity)
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.n_opponents = max(0, self.n_players - 1)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        if round_number == 0:
            return Action.D
        if round_number >= self.n_rounds - 1:
            return Action.D
        q = 0.0
        try:
            if len(history.opponent_cooperators) > 0 and self.n_opponents > 0:
                prev_cooperators = float(history.opponent_cooperators[-1])
                q = prev_cooperators / float(self.n_opponents)
        except Exception:
            q = 0.0
        if float(current_stock) <= self.capacity / 2.0:
            return Action.C
        if q >= 0.5:
            return Action.D
        return Action.C

class Strategy_SELFISH_106(BaseStrategy):
    """
    Common-pool strategy:
    - Defect in the first and final rounds.
    - Defect when the pool is empty or highly stocked.
    - Cooperate only when recent opponent cooperation and stock level justify preservation.
    - Enter a defensive defect mode after a sharp cooperation drop until cooperation recovers.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.opponents = max(self.n_players - 1, 0)
        self.half_threshold = math.ceil(self.opponents / 2) if self.opponents > 0 else 0
        self.three_quarter_threshold = math.ceil(3 * self.opponents / 4) if self.opponents > 0 else 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        if round_number == 0:
            return Action.D
        if round_number >= self.n_rounds - 1:
            return Action.D
        if history.opponent_cooperators is None or len(history.opponent_cooperators) == 0:
            return Action.D
        last_coop = int(history.opponent_cooperators[-1])
        prev_coop = int(history.opponent_cooperators[-2]) if len(history.opponent_cooperators) >= 2 else last_coop
        coop_avg = (last_coop + prev_coop) / 2.0 if len(history.opponent_cooperators) >= 2 else float(last_coop)
        if len(history.opponent_cooperators) >= 2 and last_coop <= prev_coop - 2:
            return Action.D
        if last_coop < self.half_threshold:
            return Action.D
        stock = float(current_stock)
        if stock <= 0.0:
            return Action.D
        if self.capacity <= 0.0:
            return Action.D
        if stock > 0.75 * self.capacity:
            return Action.D
        if stock > 0.5 * self.capacity:
            return Action.C if coop_avg >= self.half_threshold else Action.D
        if stock > 0.25 * self.capacity:
            return Action.C if coop_avg >= self.three_quarter_threshold else Action.D
        all_opponents = self.opponents
        if all_opponents <= 0:
            return Action.C
        if len(history.opponent_cooperators) >= 2:
            if int(history.opponent_cooperators[-1]) == all_opponents and int(history.opponent_cooperators[-2]) == all_opponents:
                return Action.C
            return Action.D
        return Action.C if last_coop == all_opponents else Action.D

class Strategy_SELFISH_107(BaseStrategy):
    """
    Exploit by default, cooperate only in the middle rounds when the stock is
    still healthy and almost all opponents cooperated in the previous round.
    Never cooperate in the first round or the last two rounds.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.high_stock_threshold = 0.7 * self.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        if round_number == 0:
            return Action.D
        if round_number >= max(0, self.n_rounds - 2):
            return Action.D
        last_k = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        if current_stock >= self.high_stock_threshold and last_k >= self.n_players - 2:
            return Action.C
        return Action.D

class Strategy_SELFISH_108(BaseStrategy):
    """
    Conservative common-pool strategy:
    - Cooperate in round 1.
    - Default to defection.
    - Cooperate only after sustained, high opponent cooperation and a healthy stock.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self._q = 1.0
        self._good_streak = 0
        self._prev_current_stock = None
        self._last_seen_round = -1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = max(2, int(self.game_description.n_players))
        n_opponents = max(1, n - 1)
        capacity = float(self.game_description.capacity)
        round_number = int(history.round_number)
        coop_threshold = 1.0 if n == 2 else 2.0 / 3.0
        if round_number == 0:
            self._q = 1.0
            self._good_streak = 0
            self._prev_current_stock = float(current_stock)
            self._last_seen_round = 0
            return Action.C
        q = 1.0
        good_streak = 0
        prev_stock = self._prev_current_stock
        if prev_stock is None:
            prev_stock = float(current_stock)
        for k in range(round_number - 1):
            c_prev = int(history.opponent_cooperators[k])
            coop_rate = c_prev / n_opponents if n_opponents > 0 else 0.0
            if k == 0:
                stock_drop_ok = True
            else:
                stock_drop_ok = True
            if coop_rate >= coop_threshold and stock_drop_ok:
                good_streak += 1
            else:
                good_streak = 0
            q = 0.7 * q + 0.3 * coop_rate
        last_c_prev = int(history.opponent_cooperators[-1])
        last_coop_rate = last_c_prev / n_opponents if n_opponents > 0 else 0.0
        q = 0.7 * q + 0.3 * last_coop_rate
        if self._prev_current_stock is not None:
            stock_drop = float(self._prev_current_stock) - float(current_stock)
            if last_coop_rate >= coop_threshold and stock_drop <= capacity / 10.0:
                good_streak = good_streak + 1
            else:
                good_streak = 0
        elif last_coop_rate >= coop_threshold:
            good_streak = good_streak + 1
        else:
            good_streak = 0
        if float(current_stock) >= 3.0 * capacity / 4.0:
            if q == 1.0 and round_number >= 2:
                if len(history.opponent_cooperators) >= 2:
                    if int(history.opponent_cooperators[-1]) == n_opponents and int(history.opponent_cooperators[-2]) == n_opponents:
                        self._q = q
                        self._good_streak = good_streak
                        self._prev_current_stock = float(current_stock)
                        self._last_seen_round = round_number
                        return Action.C
        if float(current_stock) <= capacity / 4.0:
            self._q = q
            self._good_streak = good_streak
            self._prev_current_stock = float(current_stock)
            self._last_seen_round = round_number
            return Action.D
        if round_number >= int(self.game_description.n_rounds) - 1:
            self._q = q
            self._good_streak = good_streak
            self._prev_current_stock = float(current_stock)
            self._last_seen_round = round_number
            return Action.D
        if float(current_stock) >= capacity / 2.0 and q >= 2.0 / 3.0 and (good_streak >= 2):
            action = Action.C
        else:
            action = Action.D
        self._q = q
        self._good_streak = good_streak
        self._prev_current_stock = float(current_stock)
        self._last_seen_round = round_number
        return action

class Strategy_SELFISH_110(BaseStrategy):
    """
    Reserve-driven harvesting strategy for the common pool resource game.

    - Defect on the final round.
    - Prefer cooperation when stock is low.
    - Exploit when stock is comfortably high.
    - In the middle band, use the previous round's opponent cooperation count
      to estimate which action better preserves the reserve target.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = max(2, int(game_description.n_players))
        self.r = max(1, int(game_description.n_rounds))
        self.capacity = float(game_description.capacity)
        self.reserve = self.capacity / 3.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = int(history.round_number)
        if t >= self.r - 1:
            return Action.D
        if t == 0:
            if self.n == 2:
                return Action.C if current_stock <= self.reserve else Action.D
            return Action.D
        S = float(current_stock)
        L = self.reserve
        if S <= L:
            return Action.C
        if S >= 2.0 * L:
            return Action.D
        c_prev = 0
        if history.opponent_cooperators.size > 0:
            c_prev = int(history.opponent_cooperators[-1])
        n_opponents = self.n - 1
        c_prev = max(0, min(c_prev, n_opponents))
        d_prev = n_opponents - c_prev
        cons_C = S / (2.0 * self.n) + c_prev * (S / (2.0 * self.n)) + d_prev * (S / self.n)
        cons_D = S / self.n + c_prev * (S / (2.0 * self.n)) + d_prev * (S / self.n)
        R_C = S - cons_C
        R_D = S - cons_D
        if self.capacity > 0:
            next_C = min(R_C + 2.0 * R_C * (1.0 - R_C / self.capacity), self.capacity)
            next_D = min(R_D + 2.0 * R_D * (1.0 - R_D / self.capacity), self.capacity)
        else:
            next_C = R_C
            next_D = R_D
        if next_C >= L and next_D < L:
            return Action.C
        return Action.D

class Strategy_SELFISH_111(BaseStrategy):
    """
    Defection-biased common pool strategy that cooperates only after sustained
    evidence of near-universal cooperation and a healthy stock, while always
    defecting in the last two rounds.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.trust = 0
        self.last_m = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = int(self.game_description.n_players)
        r = int(self.game_description.n_rounds)
        capacity = float(self.game_description.capacity)
        round_number = int(history.round_number)
        rem = r - round_number
        if round_number > 0 and len(history.opponent_cooperators) > 0:
            last_m = int(history.opponent_cooperators[-1])
        else:
            last_m = 0
        trust = 0
        if round_number > 0 and len(history.opponent_cooperators) > 0:
            threshold = max(0, n - 1)
            for idx in range(len(history.opponent_cooperators) - 1, -1, -1):
                if int(history.opponent_cooperators[idx]) >= threshold:
                    trust += 1
                else:
                    break
        self.trust = trust
        self.last_m = last_m
        if rem <= 2:
            return Action.D
        if round_number == 0:
            return Action.C if r > 2 else Action.D
        if current_stock < 0.5 * capacity:
            return Action.D
        if trust >= 2 and last_m >= n - 1:
            return Action.C
        if trust == 1 and last_m >= n - 1 and (current_stock >= 0.85 * capacity):
            return Action.C
        return Action.D

class Strategy_SELFISH_112(BaseStrategy):
    """
    Threshold-based conditional cooperation strategy for the Common Pool Resource Game.

    Cooperates only when the stock is high enough to justify preserving the pool,
    with extra retaliation and endgame defection bias.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        r = int(history.round_number)
        capacity = self.capacity
        S = float(current_stock)
        if not math.isfinite(S):
            S = 0.0
        if S < 0.0:
            S = 0.0
        if r == 0:
            if S == capacity:
                return Action.C
            return Action.D
        rounds_left = self.n_rounds - r
        if rounds_left <= 1:
            return Action.D
        if rounds_left == 2:
            last_coop_rate = 0.0
            if len(history.opponent_cooperators) > 0:
                last_opps = int(history.opponent_cooperators[-1])
                denom = max(self.n_players - 1, 1)
                last_coop_rate = last_opps / denom
            broad_coop = last_coop_rate >= 0.5
            if S == capacity and broad_coop:
                return Action.C
            return Action.D
        thr_high = 0.75 * capacity
        thr_recovery = 2.0 / 3.0 * capacity
        thr_retaliation = 0.9 * capacity
        last_opps = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        denom = max(self.n_players - 1, 1)
        last_coop_rate = last_opps / denom
        last_my_action = bool(history.my_actions[-1]) if len(history.my_actions) > 0 else False
        stock_increased_last_round = False
        if len(history.my_payoffs) >= 2:
            prev_payoff = float(history.my_payoffs[-1])
            prev_prev_payoff = float(history.my_payoffs[-2])
            stock_increased_last_round = prev_payoff >= prev_prev_payoff
            if S >= thr_recovery:
                stock_increased_last_round = True
        if last_my_action and last_coop_rate < 0.5 and (S < thr_retaliation):
            return Action.D
        if last_coop_rate >= 0.5 and stock_increased_last_round and (S >= thr_recovery):
            if S > thr_recovery:
                return Action.C
            if S == thr_recovery:
                return Action.D
        if S > thr_high:
            return Action.C
        return Action.D

class Strategy_SELFISH_113(BaseStrategy):
    """
    Conservation-threshold strategy with a free-riding bias:
    - Defect in the first round and the last round.
    - Otherwise, respond to the current stock level and the previous round's
      opponent cooperation rate.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(self.n_players - 1, 1)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        if round_number == 0:
            return Action.D
        if round_number >= self.n_rounds - 1:
            return Action.D
        last_opponent_cooperators = 0
        if len(history.opponent_cooperators) > 0:
            last_opponent_cooperators = int(history.opponent_cooperators[-1])
        q = last_opponent_cooperators / self.n_opponents if self.n_opponents > 0 else 0.0
        s = float(current_stock)
        c = self.capacity
        if s >= 0.75 * c:
            return Action.D
        elif s >= 0.5 * c:
            return Action.D if q >= 0.5 else Action.C
        elif s >= 0.25 * c:
            return Action.C if q >= 2.0 / 3.0 else Action.D
        else:
            return Action.C

class Strategy_SELFISH_114(BaseStrategy):
    """
    Opportunistic common-pool strategy:
    - Defect in the first and last rounds.
    - In intermediate rounds, cooperate only when defecting is predicted to
      reduce the stock below a dynamic protection threshold.
    - Update the estimate of opponent cooperation from the most recent round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(0, self.n_players - 1)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        if round_number == 0:
            return Action.D
        if round_number >= self.n_rounds - 1:
            return Action.D
        last_cooperators = 0
        if len(history.opponent_cooperators) > 0:
            last_cooperators = int(history.opponent_cooperators[-1])
        if self.n_opponents > 0:
            q = last_cooperators / self.n_opponents
        else:
            q = 1.0
        if round_number == 1 and len(history.opponent_cooperators) == 1:
            q = 1.0
        low_stock_threshold = 0.15 * self.capacity
        if current_stock <= low_stock_threshold:
            if q >= 0.25:
                return Action.C
            return Action.D
        if round_number + 1 <= self.n_rounds / 2:
            threshold = 0.5 * self.capacity
        else:
            threshold = 0.35 * self.capacity
        if self.n_players > 0:
            predicted_remaining_defect = current_stock * ((self.n_players - 1) * q) / (2.0 * self.n_players)
        else:
            predicted_remaining_defect = 0.0
        if len(history.opponent_cooperators) >= 2 and self.n_opponents > 0:
            prev_q = int(history.opponent_cooperators[-2]) / self.n_opponents
            if q - prev_q >= 0.35:
                if predicted_remaining_defect >= threshold:
                    return Action.D
        if predicted_remaining_defect < threshold:
            return Action.C
        if len(history.opponent_cooperators) >= 2 and self.n_opponents > 0:
            recent_qs = [int(x) / self.n_opponents for x in history.opponent_cooperators[-min(3, len(history.opponent_cooperators)):]]
            if min(recent_qs) >= 0.75 and predicted_remaining_defect >= threshold:
                return Action.D
        return Action.D

class Strategy_SELFISH_115(BaseStrategy):
    """
    Start with defection, then probe for sustained cooperation and a healthy stock.
    Permanently switch to exploitation/defection if cooperation collapses or the pool
    becomes too depleted.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.mode = 'probe'
        self.trusted_rounds = 0
        self.fallback = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_players = self.game_description.n_players
        n_rounds = self.game_description.n_rounds
        capacity = float(self.game_description.capacity)
        t = history.round_number + 1
        m = n_rounds - t + 1
        stock = float(current_stock)
        if stock < 0.0:
            stock = 0.0
        if history.round_number == 0:
            return Action.D
        if self.fallback:
            return Action.D
        opp_count = n_players - 1
        last_opp_cooperators = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        q = last_opp_cooperators / opp_count if opp_count > 0 else 0.0
        if m <= 1 or stock <= 0.0:
            self.fallback = True
            self.mode = 'exploit'
            self.trusted_rounds = 0
            return Action.D
        if q <= 1.0 / 3.0 or stock < 0.5 * capacity:
            self.fallback = True
            self.mode = 'exploit'
            self.trusted_rounds = 0
            return Action.D
        if q <= 1.0 / 3.0 or stock < 0.5 * capacity:
            self.mode = 'exploit'
            self.trusted_rounds = 0
        elif q >= 2.0 / 3.0 and stock >= 0.75 * capacity:
            self.trusted_rounds += 1
            if self.trusted_rounds >= 2:
                self.mode = 'preserve'
            else:
                self.mode = 'probe'
        else:
            self.trusted_rounds = 0
            if self.mode != 'exploit':
                self.mode = 'probe'
        if self.mode == 'exploit':
            return Action.D
        if self.mode == 'preserve':
            if m >= 3 and stock >= 0.75 * capacity and (q >= 2.0 / 3.0) and (self.trusted_rounds >= 2):
                return Action.C
            return Action.D
        return Action.D

class Strategy_SELFISH_116(BaseStrategy):
    """
    Defect in the first and last rounds. Otherwise, cooperate only when the
    current stock is at or below half capacity, the recent opponent behavior
    suggests a cooperative majority, and projected stock outcomes favor
    cooperation by a clear margin.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.half_capacity = self.capacity / 2.0
        self.eps = 1e-09

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.n
        capacity = self.capacity
        S = float(current_stock)
        if history.round_number == 0:
            return Action.D
        if history.round_number >= self.r - 1:
            return Action.D
        k = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        if n <= 1:
            p = 0.0
            majority_threshold = 0
        else:
            p = k / float(n - 1)
            majority_threshold = math.ceil((n - 1) / 2)
        if S > self.half_capacity:
            return Action.D
        if k < majority_threshold:
            return Action.D
        if n <= 0 or capacity <= 0:
            return Action.D
        cC = S / (2.0 * n)
        cD = S / n
        o = (n - 1) * (p * (S / (2.0 * n)) + (1.0 - p) * (S / n))
        R_C = S - cC - o
        R_D = S - cD - o
        N_C = min(R_C + 2.0 * R_C * (1.0 - R_C / capacity), capacity)
        N_D = min(R_D + 2.0 * R_D * (1.0 - R_D / capacity), capacity)
        if N_C <= N_D + self.eps:
            return Action.D
        if N_C < self.half_capacity - self.eps:
            return Action.D
        return Action.C

class Strategy_SELFISH_117(BaseStrategy):
    """
    Common pool strategy:
    - Start with cooperation.
    - Defect in the final round.
    - Otherwise adapt to current stock and prior-round opponent cooperation,
      with a defensive lockout after two weak-cooperation rounds.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        n = self.n_players
        cap = self.capacity if self.capacity > 0 else 1.0
        if round_number == 0:
            return Action.C
        if round_number >= self.n_rounds - 1:
            return Action.D
        x = current_stock / cap if cap > 0 else 0.0
        last_c = int(history.opponent_cooperators[-1]) if round_number >= 1 else 0
        if round_number >= 2:
            prev_c = int(history.opponent_cooperators[-2])
            weak_threshold = (n - 1) / 2.0
            if prev_c <= weak_threshold and last_c <= weak_threshold:
                if not (x >= 0.75 and last_c >= n - 2):
                    return Action.D
        if x < 0.45:
            return Action.C if last_c == n - 1 else Action.D
        if x < 0.75:
            return Action.C if last_c >= n - 2 else Action.D
        return Action.D if last_c >= n - 2 else Action.C

class Strategy_SELFISH_118(BaseStrategy):
    """
    Conservative threshold strategy with a final-round defection rule and
    optional memory-based lock overrides.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        if round_number == 0:
            return Action.D
        if round_number >= self.n_rounds - 1:
            return Action.D
        cap = self.capacity
        s = float(current_stock)
        prev_c = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        if prev_c == 0 and s >= 0.25 * cap:
            return Action.D
        if prev_c == max(0, self.n_players - 1) and s < 0.75 * cap:
            return Action.C
        if s >= 0.75 * cap:
            return Action.D
        if s < 0.25 * cap:
            return Action.C
        if prev_c >= self.n_players - 2:
            return Action.C
        return Action.D

class Strategy_SELFISH_119(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Cooperate initially.
    - Keep cooperating only when stock is ample and opponents are mostly cooperative.
    - Switch to defection after strong free-riding or depletion signals.
    - Allow recovery if the pool is restored and cooperation history is good.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self._permanent_defect = False
        self._last_seen_round = -1
        self._last_q = 1.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        if round_number == 0:
            self._permanent_defect = False
            self._last_seen_round = 0
            self._last_q = 1.0
            return Action.C
        if round_number >= self.r:
            self._last_seen_round = round_number
            return Action.D
        if current_stock < self.capacity / 4.0:
            self._permanent_defect = True
        opp_hist = history.opponent_cooperators
        observed_rounds = len(opp_hist)
        if observed_rounds > 0:
            coop_rate = float(np.mean(opp_hist / max(1, self.n - 1)))
        else:
            coop_rate = 1.0
        if current_stock >= self.capacity and coop_rate >= 0.75:
            self._permanent_defect = False
        if observed_rounds >= 2:
            prev_obs = int(opp_hist[-2])
            last_obs = int(opp_hist[-1])
            if last_obs <= prev_obs - 2:
                self._permanent_defect = True
        if round_number == self.r - 1:
            self._last_seen_round = round_number
            return Action.D
        if self._permanent_defect:
            self._last_seen_round = round_number
            return Action.D
        if observed_rounds == 0:
            q = self._last_q
        else:
            last_opponent_coops = int(opp_hist[-1])
            if len(history.my_actions) > 0 and bool(history.my_actions[-1]):
                q = (last_opponent_coops + 1) / max(1, self.n)
            else:
                q = last_opponent_coops / max(1, self.n)
        if self._last_seen_round >= 0 and round_number > self._last_seen_round + 1:
            q = self._last_q
        self._last_q = float(q)
        self._last_seen_round = round_number
        T = 0.0 if round_number == self.r - 1 else self.capacity / 2.0
        if self.n == 2:
            cooperate = current_stock >= T and q >= 1.0 and (round_number <= self.r - 2)
        else:
            cooperate = current_stock >= T and q >= 0.75 and (round_number <= self.r - 2)
        return Action.C if cooperate else Action.D

class Strategy_SELFISH_120(BaseStrategy):
    """
    Selfish stock-preserving strategy for the Common Pool Resource Game.

    - Opens cautiously depending on player count.
    - Cooperates only when recent opponent cooperation is strong enough and
      the stock is still comfortably above a safety threshold.
    - Defects immediately when cooperation drops below the threshold, when
      stock is depleted, or in the final round unless opponents were fully
      cooperative previously.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(self.n_players - 1, 1)
        self.coop_threshold = 2.0 / 3.0
        self.low_stock_threshold = self.capacity / 4.0
        self.high_stock_threshold = self.capacity / 2.0

    def _safe_last_opponent_count(self, history: PlayerHistory):
        if history.round_number <= 0:
            return None
        try:
            return int(history.opponent_cooperators[-1])
        except Exception:
            return None

    def _opponent_coop_rate(self, last_count):
        if last_count is None or self.n_opponents <= 0:
            return None
        return float(last_count) / float(self.n_opponents)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        stock = float(current_stock)
        if stock <= 0.0:
            return Action.D
        t = int(history.round_number)
        last_count = self._safe_last_opponent_count(history)
        last_rate = self._opponent_coop_rate(last_count)
        if t == 0:
            return Action.D if self.n_players <= 3 else Action.C
        if t >= self.n_rounds - 1:
            if last_count is not None and last_count >= self.n_opponents:
                return Action.C
            return Action.D
        if last_rate is None:
            return Action.D
        if last_rate < self.coop_threshold:
            return Action.D
        if stock <= self.low_stock_threshold:
            return Action.D
        if last_rate >= self.coop_threshold and stock > self.low_stock_threshold:
            if stock > self.high_stock_threshold:
                return Action.C
            if last_count is not None and last_count >= math.ceil(self.coop_threshold * self.n_opponents):
                return Action.C
        return Action.D

class Strategy_SELFISH_121(BaseStrategy):
    """
    Common pool strategy:
    - Round 1: cooperate
    - Final round: defect
    - Intermediate rounds: defect only when stock is sufficiently high
      and the observed opponent cooperation rate in the previous round was high enough.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        n = self.n_players
        r = self.n_rounds
        capacity = self.capacity
        if round_number == 0:
            return Action.C
        if round_number >= r - 1:
            return Action.D
        if n <= 1 or capacity <= 0.0:
            return Action.C
        x = float(current_stock) / capacity
        last_opponents = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        n_opponents = max(n - 1, 1)
        q = last_opponents / n_opponents
        if x <= 0.4:
            return Action.C
        if x >= 0.8 and q >= 0.5:
            return Action.D
        threshold_x = 0.6
        threshold_q = 0.5
        if x > threshold_x and q >= threshold_q:
            return Action.D
        if x < threshold_x or q < threshold_q:
            return Action.C
        if abs(x - threshold_x) <= 1e-12:
            return Action.D if q > threshold_q else Action.C
        return Action.C

class Strategy_SELFISH_122(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Cooperates early and when the pool is healthy.
    - Defects under low stock, weak opponent cooperation, or late-game pressure.
    - Uses recent cooperation rates and inferred stock trend to decide recovery.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(1, self.n_players - 1)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        cap = self.capacity
        stock = float(current_stock)
        if round_number == 0:
            return Action.C
        last_my_action = bool(history.my_actions[-1])
        last_q = None
        prev_q = None
        if len(history.opponent_cooperators) >= 1:
            last_q = float(history.opponent_cooperators[-1]) / float(self.n_opponents)
        if len(history.opponent_cooperators) >= 2:
            prev_q = float(history.opponent_cooperators[-2]) / float(self.n_opponents)
        last_stock = None
        if len(history.my_payoffs) >= 1:
            last_payoff = float(history.my_payoffs[-1])
            multiplier = 2.0 * self.n_players if last_my_action else float(self.n_players)
            last_stock = last_payoff * multiplier
        remaining_rounds = self.n_rounds - round_number
        if remaining_rounds <= 1:
            if stock == cap and last_q is not None and (last_q >= 1.0):
                return Action.C
            return Action.D
        if remaining_rounds <= 2 and stock < cap:
            return Action.D
        last_two_below_half = len(history.opponent_cooperators) >= 2 and float(history.opponent_cooperators[-1]) / float(self.n_opponents) < 0.5 and (float(history.opponent_cooperators[-2]) / float(self.n_opponents) < 0.5)
        last_two_at_least_half = len(history.opponent_cooperators) >= 2 and float(history.opponent_cooperators[-1]) / float(self.n_opponents) >= 0.5 and (float(history.opponent_cooperators[-2]) / float(self.n_opponents) >= 0.5)
        if stock < 0.5 * cap:
            return Action.D
        if last_stock is not None and stock < 0.75 * last_stock:
            return Action.D
        if last_two_below_half:
            return Action.D
        if stock < 0.6 * cap:
            if not (last_two_at_least_half and stock >= 0.75 * cap):
                return Action.D
        if stock < 0.5 * cap:
            return Action.D
        if last_my_action is False and last_stock is not None:
            if stock - last_stock >= cap / 8.0:
                if last_q is not None and last_q >= 0.5 and (stock >= 0.75 * cap):
                    pass
                else:
                    return Action.D
        if stock < 0.5 * cap:
            return Action.D
        if last_q is None:
            return Action.C
        if last_q < 0.5:
            return Action.D
        if last_q > 0.5:
            return Action.C
        if last_stock is not None:
            if stock >= last_stock:
                return Action.C
            return Action.D
        return Action.D

class Strategy_SELFISH_123(BaseStrategy):
    """
    Cautious common-pool strategy:
    - Cooperate initially,
    - Defect under stock pressure,
    - Punish sharp drops in opponent cooperation,
    - Resume cooperation only when the pool is healthy and enough opponents cooperate.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(0, self.n_players - 1)
        self.coop_threshold = math.ceil(self.n_opponents / 2) if self.n_opponents > 0 else 0
        self._permanently_defect = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        current_stock = float(current_stock)
        if round_number == 0:
            return Action.C
        if current_stock <= self.capacity / 4:
            self._permanently_defect = True
        if self._permanently_defect:
            return Action.D
        last_coop_count = int(history.opponent_cooperators[-1]) if round_number > 0 else 0
        prev_coop_count = int(history.opponent_cooperators[-2]) if round_number > 1 else last_coop_count
        punishment_triggered = False
        if round_number > 1 and prev_coop_count - last_coop_count >= 2:
            punishment_triggered = True
        in_punishment = False
        if round_number > 1:
            for idx in range(1, round_number):
                if int(history.opponent_cooperators[idx - 1]) - int(history.opponent_cooperators[idx]) >= 2:
                    in_punishment = True
            if in_punishment and last_coop_count >= self.coop_threshold:
                in_punishment = False
        if punishment_triggered:
            return Action.D
        if last_coop_count >= self.coop_threshold and current_stock > self.capacity / 2:
            current_round = round_number + 1
            if current_round == self.n_rounds:
                if current_stock >= self.capacity / 2:
                    return Action.C
                return Action.D
            return Action.C
        if in_punishment:
            return Action.D
        if current_stock <= self.capacity / 2:
            return Action.D
        return Action.D

class Strategy_SELFISH_124(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Cooperate in round 1.
    - Afterwards, predict next stock under C/D using opponents' last observed behavior.
    - Prefer defection when it keeps the pool in the recovery region,
      otherwise cooperate to avoid over-depleting the stock.
    - Defect in the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)

    def _next_stock(self, stock: float, k: int, my_cooperate: bool) -> float:
        """
        Predict next stock if opponents repeat last round behavior.

        k: number of cooperating opponents in the previous round.
        my_cooperate: True for C, False for D.
        """
        n = self.n
        cap = self.capacity
        n_opp = max(0, n - 1)
        my_consumption = stock / (2.0 * n) if my_cooperate else stock / n
        opp_coop_consumption = k * (stock / (2.0 * n))
        opp_def_consumption = (n_opp - k) * (stock / n)
        total_consumption = opp_coop_consumption + opp_def_consumption + my_consumption
        remaining = stock - total_consumption
        if remaining < 0.0:
            remaining = 0.0
        growth = 2.0 * remaining * (1.0 - remaining / cap) if cap > 0.0 else 0.0
        new_stock = remaining + growth
        if new_stock > cap:
            new_stock = cap
        if new_stock < 0.0:
            new_stock = 0.0
        return new_stock

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        if round_number == 0:
            return Action.C
        if round_number >= self.r - 1:
            return Action.D
        k = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        n_opp = max(1, self.n - 1)
        q = k / n_opp
        half_cap = 0.5 * self.capacity
        three_quarters_cap = 0.75 * self.capacity
        s_c = self._next_stock(current_stock, k, my_cooperate=True)
        s_d = self._next_stock(current_stock, k, my_cooperate=False)
        d_good = s_d >= half_cap
        c_good = s_c >= half_cap
        if d_good:
            return Action.D
        elif c_good and (not d_good):
            return Action.C
        elif s_c < half_cap and s_d < half_cap:
            return Action.C if current_stock < half_cap else Action.D
        elif q >= 0.5 and current_stock >= three_quarters_cap:
            return Action.D
        else:
            if q < 0.25 or current_stock <= 0.6 * self.capacity:
                return Action.C
            return Action.D

class Strategy_SELFISH_125(BaseStrategy):
    """
    Common-pool strategy:
    - Round 1 and final round: defect.
    - In middle rounds, cooperate only under favorable stock/cooperation conditions,
      with an additional safeguard against stock drops unless opponents were unanimous.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.prev_stock = None

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.n_players
        r = self.n_rounds
        cap = self.capacity
        round_number = int(history.round_number)
        previous_stock = self.prev_stock
        self.prev_stock = float(current_stock)
        if round_number == 0:
            return Action.D
        if round_number >= r - 1:
            return Action.D
        if current_stock <= 0 or cap <= 0:
            return Action.D
        if history.opponent_cooperators is None or len(history.opponent_cooperators) == 0:
            return Action.D
        m = int(history.opponent_cooperators[-1])
        m = max(0, min(m, max(0, n - 1)))
        if previous_stock is not None and float(current_stock) < float(previous_stock) and (m != n - 1):
            return Action.D
        ratio = float(current_stock) / cap if cap > 0 else 0.0
        if ratio <= 1.0 / 3.0:
            return Action.C if m >= n - 2 else Action.D
        elif ratio <= 2.0 / 3.0:
            return Action.C if m == n - 1 else Action.D
        else:
            return Action.D

class Strategy_SELFISH_126(BaseStrategy):
    """
    Stock-preserving threshold strategy with adaptive cooperation floor based on
    recent opponent cooperation and a conservative late-game bias toward defection.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(0, self.n_players - 1)
        self.base_floor = 0.35
        self.tight_floor = 0.45
        self.high_stock_threshold = 0.8 * self.capacity
        self.very_high_stock_threshold = 0.9 * self.capacity
        self.low_stock_threshold = self.capacity / 6.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        m = max(1, self.n_opponents)
        if round_number == 0:
            return Action.C
        if round_number >= self.n_rounds - 1:
            return Action.C if current_stock <= 0 else Action.D
        if current_stock <= self.low_stock_threshold:
            return Action.D
        last_count = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        x_t = last_count / m
        floor = self.base_floor
        if x_t < 0.5:
            floor = self.tight_floor
        elif len(history.opponent_cooperators) >= 2:
            prev_count = int(history.opponent_cooperators[-2])
            prev_x = prev_count / m
            if x_t >= 0.75 and prev_x >= 0.75:
                floor = self.base_floor
        threshold = max(0.5, min(1.0, 1.0 - 1.0 / (2.0 * m) + (x_t - 0.5) / 4.0))
        high_stock_cutoff = 1.0 - 1.0 / (2.0 * m)
        if current_stock >= self.high_stock_threshold and x_t >= high_stock_cutoff:
            return Action.C
        if current_stock >= self.very_high_stock_threshold and x_t >= max(high_stock_cutoff, 1.0 - 1.0 / m):
            return Action.C
        L_t = current_stock / self.capacity if self.capacity > 0 else 0.0
        if L_t > floor and x_t > threshold:
            return Action.C
        return Action.D

class Strategy_SELFISH_127(BaseStrategy):
    """
    Stock-band strategy with persistence adjustment:
    - Starts with defection.
    - Responds to stock level bands and recent opponent cooperation rates.
    - Gives special treatment to extreme stock states and the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        capacity = float(game_description.capacity)
        self.high = 0.7 * capacity
        self.mid = 0.4 * capacity
        self.low = 0.2 * capacity
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.n_opponents = max(0, self.n_players - 1)

    def _opponent_rate(self, cooperators: int) -> float:
        if self.n_opponents <= 0:
            return 0.0
        return cooperators / self.n_opponents

    def _persistent_adjustment(self, history: PlayerHistory) -> float:
        if history.round_number < 2:
            return 0.0
        last_two = history.opponent_cooperators[-2:]
        r1 = self._opponent_rate(int(last_two[0]))
        r2 = self._opponent_rate(int(last_two[1]))
        if r1 >= 0.6 and r2 >= 0.6:
            return 0.1
        if r1 < 0.4 and r2 < 0.4:
            return -0.1
        return 0.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        S = float(current_stock)
        round_number = history.round_number
        if S == 0.0:
            return Action.D
        if S == float(self.game_description.capacity):
            if round_number >= 2:
                if bool(history.my_actions[-1]) and bool(history.my_actions[-2]) and (int(history.opponent_cooperators[-1]) == self.n_opponents) and (int(history.opponent_cooperators[-2]) == self.n_opponents):
                    return Action.C
            return Action.D
        if round_number == 0:
            return Action.D
        if round_number == self.n_rounds - 1:
            return Action.C if S <= self.low else Action.D
        c_last = int(history.opponent_cooperators[-1]) if round_number > 0 else 0
        c_rate = self._opponent_rate(c_last)
        c_rate += self._persistent_adjustment(history)
        c_rate = max(0.0, min(1.0, c_rate))
        if S >= self.high:
            return Action.D
        elif S <= self.low:
            return Action.C
        elif S <= self.mid:
            return Action.C if c_rate >= 0.6 else Action.D
        else:
            return Action.D if c_rate >= 0.4 else Action.C

class Strategy_SELFISH_128(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Start by defecting.
    - In the final round, always defect.
    - Otherwise, cooperate only when stock is sufficiently low and prior opponent cooperation was high enough.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        total_rounds = self.n_rounds
        if round_number >= total_rounds - 1:
            return Action.D
        if round_number == 0:
            return Action.D
        if current_stock <= 0.0:
            return Action.D
        n_opponents = self.n_players - 1
        if n_opponents <= 0:
            return Action.D
        last_k = int(history.opponent_cooperators[-1])
        q = last_k / n_opponents
        low_threshold = self.capacity / 3.0
        mid_threshold = 2.0 * self.capacity / 3.0
        if current_stock <= low_threshold:
            return Action.C if q >= 0.5 else Action.D
        elif current_stock <= mid_threshold:
            return Action.C if q == 1.0 else Action.D
        else:
            return Action.D

class Strategy_SELFINTERESTED_33(BaseStrategy):
    """
    Common-pool strategy:
    - Cooperate in round 1
    - Defect in the last round
    - In between, cooperate when stock is low or when prior-round cooperation was sufficiently strong
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self._one_third_capacity = self.capacity / 3.0
        self._two_thirds_capacity = 2.0 * self.capacity / 3.0
        self._middle_threshold = math.ceil(2.0 * self.n / 3.0)
        self._all_but_one_threshold = max(0, self.n - 1)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        if round_number == 0:
            return Action.C
        if round_number >= self.r - 1:
            return Action.D
        if current_stock <= 0.0:
            return Action.D
        S = float(current_stock)
        prev_my_cooperated = bool(history.my_actions[-1])
        prev_opp_cooperators = int(history.opponent_cooperators[-1])
        k_prev = prev_opp_cooperators + (1 if prev_my_cooperated else 0)
        if S <= self._one_third_capacity:
            return Action.C
        if S >= self._two_thirds_capacity:
            return Action.C if k_prev >= self._all_but_one_threshold else Action.D
        return Action.C if k_prev >= self._middle_threshold else Action.D

class Strategy_SELFINTERESTED_34(BaseStrategy):
    """
    State-dependent threshold strategy with guarded cooperation, punishment,
    and endgame harvesting.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(self.n_players - 1, 0)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        n = self.n_players
        cap = self.capacity
        stock = float(current_stock)
        if round_number >= self.n_rounds - 1:
            return Action.D
        if round_number == 0:
            return Action.C if cap >= 4.0 * n else Action.D
        if stock <= 2.0 * n:
            return Action.D
        last_coop = int(history.opponent_cooperators[-1]) if round_number > 0 else 0
        denom = self.n_opponents if self.n_opponents > 0 else 1
        x = last_coop / denom
        if round_number == self.n_rounds - 2:
            return Action.C if x >= 1.0 and stock >= 0.9 * cap else Action.D
        last_two_high = False
        if round_number >= 2:
            prev1 = int(history.opponent_cooperators[-1])
            prev2 = int(history.opponent_cooperators[-2])
            last_two_high = prev1 / denom >= 0.75 and prev2 / denom >= 0.75
        if x >= 0.75:
            return Action.C
        if x >= 0.4:
            if stock >= 0.8 * cap:
                return Action.C
            if last_two_high and stock >= 0.9 * cap:
                return Action.C
            return Action.D
        return Action.D

class Strategy_SELFINTERESTED_36(BaseStrategy):
    """
    Threshold-based conditional cooperator:
    - Cooperate on the first round.
    - Defect on the final round.
    - In between, cooperate when stock is low, or when opponents were sufficiently
      cooperative and stock is not too high; become stricter in the final two rounds.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(self.n_players - 1, 0)
        self.coop_threshold = math.ceil(self.n_opponents / 2) if self.n_opponents > 0 else 0
        self.half_capacity = self.capacity / 2.0
        self.three_quarters_capacity = 3.0 * self.capacity / 4.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        if current_stock <= 0:
            return Action.D
        if round_number == 0:
            return Action.C
        if round_number >= self.n_rounds - 1:
            return Action.D
        m = 0
        if len(history.opponent_cooperators) > 0:
            m = int(history.opponent_cooperators[-1])
        if current_stock <= self.half_capacity:
            return Action.C
        if round_number >= self.n_rounds - 2:
            if m >= self.coop_threshold and current_stock <= self.three_quarters_capacity:
                return Action.C
            return Action.D
        if m >= self.coop_threshold and current_stock <= self.three_quarters_capacity:
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_37(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Cooperate in round 1.
    - Avoid defection when the stock is critically low unless recovery has occurred.
    - Otherwise use a forward-looking comparison of projected future stock under
      cooperation vs defection, requiring sufficiently many cooperating opponents
      in the previous informative round.
    - Defect in the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(self.n - 1, 0)
        self.quorum = math.ceil((self.n - 1) / 2) if self.n > 1 else 0

    def _predict_next_stock(self, current_stock: float, cooperators_count: int) -> float:
        """
        Predict next-round stock after a round with a given number of cooperators
        (including self), using the specified consumption/growth dynamics.
        """
        S = max(0.0, float(current_stock))
        c = max(0, min(int(cooperators_count), self.n))
        denom = 2.0 * self.n
        if denom <= 0:
            return min(S, self.capacity)
        S_rem = S * (c / denom)
        if S_rem < 0.0:
            S_rem = 0.0
        if self.capacity > 0.0:
            growth = 2.0 * S_rem * (1.0 - S_rem / self.capacity)
        else:
            growth = 0.0
        next_stock = S_rem + growth
        if next_stock > self.capacity:
            next_stock = self.capacity
        if next_stock < 0.0:
            next_stock = 0.0
        return next_stock

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number + 1
        S = float(current_stock)
        cap = self.capacity
        if history.round_number == 0:
            return Action.C
        if t >= self.r:
            return Action.D
        if cap > 0.0 and S < cap / 3.0:
            return Action.D
        if cap > 0.0 and S < cap / 2.0:
            return Action.D
        if history.round_number == 1:
            x_pred = self.n_opponents
        else:
            x_pred = int(history.opponent_cooperators[-1])
        if x_pred < self.quorum:
            return Action.D
        c_C = x_pred + 1
        c_D = x_pred
        S_next_C = self._predict_next_stock(S, c_C)
        S_next_D = self._predict_next_stock(S, c_D)
        h = self.r - t
        if h * (S_next_C - S_next_D) > S:
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_38(BaseStrategy):
    """
    State-contingent threshold strategy:
    - Cooperate initially.
    - Continue cooperating only when opponent cooperation is at least half,
      stock is stable/non-decreasing relative to the last observed stock,
      stock is safely above 2n, and the game is not in the final round.
    - Defect in the final round, whenever stock is too low, or after the pool
      has fallen by at least 25% from its initial capacity.
    - Once defection is triggered by a stock collapse, remain defecting until
      cooperation recovers and the stock is again safely above the threshold.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self._last_stock = None
        self._permanent_defect = False
        self._min_stock_seen = float('inf')

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = int(self.game_description.n_players)
        r = int(self.game_description.n_rounds)
        threshold = 2.0 * n
        capacity = float(self.game_description.capacity)
        round_number = int(history.round_number)
        if current_stock < self._min_stock_seen:
            self._min_stock_seen = current_stock
        if capacity > 0 and self._min_stock_seen <= 0.75 * capacity:
            self._permanent_defect = True
        if round_number == 0:
            self._last_stock = current_stock
            return Action.C
        if round_number >= r - 1:
            self._last_stock = current_stock
            return Action.D
        if len(history.opponent_cooperators) > 0:
            k = int(history.opponent_cooperators[-1])
        else:
            k = 0
        m = max(n - 1, 1)
        p = k / m
        if current_stock < threshold:
            self._last_stock = current_stock
            return Action.D
        if self._permanent_defect:
            self._last_stock = current_stock
            return Action.D
        last_stock = self._last_stock
        stock_not_falling = True if last_stock is None else current_stock >= last_stock
        if p >= 0.5 and stock_not_falling and (current_stock >= threshold):
            action = Action.C
        else:
            action = Action.D
        self._last_stock = current_stock
        return action

class Strategy_SELFINTERESTED_39(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Cooperate early and when the pool is healthy.
    - Track smoothed opponent cooperation.
    - Defect under scarcity, retaliation, or in the final two rounds.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.m = 1.0
        self.prev_p = 1.0
        self.punish_mode = False
        self.consecutive_defects = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        n_opponents = max(self.n_players - 1, 1)
        if round_number == 0:
            self.m = 1.0
            self.prev_p = 1.0
            self.punish_mode = False
            self.consecutive_defects = 0
            return Action.C
        last_opponents = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) else 0
        p_t = max(0.0, min(1.0, last_opponents / n_opponents))
        self.m = 0.7 * self.m + 0.3 * p_t
        cap = self.capacity if self.capacity > 0 else 1.0
        s = float(current_stock)
        q = 0.25 + 0.5 * (1.0 - s / cap)
        q = max(0.25, min(0.75, q))
        if round_number >= self.n_rounds - 2:
            self.punish_mode = False
            self.consecutive_defects += 1
            self.prev_p = p_t
            return Action.D
        if s < cap / 8.0:
            self.punish_mode = True
            self.consecutive_defects += 1
            self.prev_p = p_t
            return Action.D
        if s < cap / 4.0:
            self.punish_mode = True
            self.consecutive_defects += 1
            self.prev_p = p_t
            return Action.D
        if self.prev_p - p_t >= 0.4:
            self.punish_mode = True
        if self.punish_mode:
            if self.m >= min(1.0, q + 0.1):
                self.punish_mode = False
                self.consecutive_defects = 0
            else:
                self.consecutive_defects += 1
                self.prev_p = p_t
                return Action.D
        if s > 3.0 * cap / 4.0 and self.m >= 0.6:
            self.consecutive_defects = 0
            self.prev_p = p_t
            return Action.C
        if self.m >= q and s >= cap / 4.0:
            self.consecutive_defects = 0
            self.prev_p = p_t
            return Action.C
        if self.consecutive_defects >= 2 and self.m >= q:
            self.consecutive_defects = 0
            self.prev_p = p_t
            return Action.C
        self.consecutive_defects += 1
        self.prev_p = p_t
        return Action.D

class Strategy_SELFINTERESTED_40(BaseStrategy):
    """
    Start with cooperation, then cooperate only after sustained full cooperation
    and while the stock remains healthy; defect otherwise, and always defect
    on the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.full_streak = 0
        self.repair_streak = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_players = max(2, int(self.game_description.n_players))
        n_rounds = max(1, int(self.game_description.n_rounds))
        capacity = float(self.game_description.capacity)
        round_number = int(history.round_number)
        if round_number == 0:
            self.full_streak = 0
            self.repair_streak = 0
            return Action.C
        t = round_number + 1
        remaining_after_current = n_rounds - t
        last_full = 0
        if round_number > 0:
            idx = round_number - 1
            while idx >= 0 and int(history.opponent_cooperators[idx]) == n_players - 1:
                last_full += 1
                idx -= 1
        self.full_streak = last_full
        self.repair_streak = min(self.full_streak, 2)
        if t == n_rounds:
            return Action.D
        if current_stock <= capacity / 2.0:
            return Action.D
        if round_number > 0 and int(history.opponent_cooperators[-1]) == n_players - 1:
            if self.full_streak >= 2:
                return Action.C
            if self.full_streak == 1 and remaining_after_current >= 3:
                return Action.C
        return Action.D

class Strategy_SELFINTERESTED_41(BaseStrategy):
    """
    Common-pool strategy:
    - Start by cooperating.
    - Cooperate only when the pool is healthy and the opponents showed a cooperative majority.
    - Defect in the last round, on low stock, or when cooperation is not sustained.
    - Use a sticky recovery rule: require two consecutive cooperative-majority rounds to exit defect mode.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.majority_threshold = math.ceil((self.n_players - 1) / 2)
        self.defect_mode = False
        self.permanent_defect = False
        self.consecutive_coop_majority = 0
        self.last_seen_round = -1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        if round_number == 0:
            self.defect_mode = False
            self.permanent_defect = False
            self.consecutive_coop_majority = 0
            self.last_seen_round = 0
            return Action.C
        prev_opponents_coop = int(history.opponent_cooperators[-1])
        if prev_opponents_coop >= self.majority_threshold:
            self.consecutive_coop_majority += 1
        else:
            self.consecutive_coop_majority = 0
            self.defect_mode = True
        if current_stock <= 0.0:
            self.permanent_defect = True
            self.defect_mode = True
            self.last_seen_round = round_number
            return Action.D
        if round_number >= self.n_rounds - 1:
            self.defect_mode = True
            self.last_seen_round = round_number
            return Action.D
        if round_number >= self.n_rounds - 2 and (not (not self.defect_mode and self.consecutive_coop_majority >= 2)):
            self.defect_mode = True
            self.last_seen_round = round_number
            return Action.D
        if current_stock <= self.capacity / 3.0:
            self.defect_mode = True
            self.last_seen_round = round_number
            return Action.D
        if self.defect_mode:
            if self.consecutive_coop_majority >= 2 and current_stock > self.capacity / 3.0:
                self.defect_mode = False
            else:
                self.last_seen_round = round_number
                return Action.D
        if prev_opponents_coop >= self.majority_threshold and current_stock > self.capacity / 3.0:
            self.last_seen_round = round_number
            return Action.C
        self.defect_mode = True
        self.last_seen_round = round_number
        return Action.D

class Strategy_SELFINTERESTED_42(BaseStrategy):
    """
    Conditional resource-protection strategy:
    - Cooperate in round 1.
    - Defect in the last round.
    - In intermediate rounds, cooperate only when the stock is stressed
      and observed opponent cooperation has been sufficiently high.
    - Uses an exponentially smoothed cooperation estimate q_t.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self._n_players = int(game_description.n_players)
        self._n_opponents = max(self._n_players - 1, 1)
        self._capacity = float(game_description.capacity)
        self._stress_threshold = self._capacity / 3.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        n_rounds = int(self.game_description.n_rounds)
        if round_number == 0:
            return Action.C
        if round_number >= n_rounds - 1:
            return Action.D
        last_opp_coop = 0
        if len(history.opponent_cooperators) > 0:
            last_opp_coop = int(history.opponent_cooperators[-1])
        x_prev = last_opp_coop / self._n_opponents if self._n_opponents > 0 else 0.0
        q = 0.5
        opp_hist = history.opponent_cooperators
        if len(opp_hist) > 0:
            for k in opp_hist:
                x = int(k) / self._n_opponents if self._n_opponents > 0 else 0.0
                q = 0.7 * q + 0.3 * x
        if current_stock <= self._stress_threshold and q >= 0.5 and (x_prev >= 0.5):
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_43(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Start with cooperation.
    - Continue cooperating when stock is healthy and opponents showed broad restraint.
    - Defect quickly when stock is low, cooperation is weak, or the game is near the end.
    - Permanently defect after sustained weak cooperation.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(0, self.n - 1)
        self.low_coop_threshold = math.ceil(self.n_opponents / 2) if self.n_opponents > 0 else 0
        self.critical_stock = 2.0 * self.n
        self.near_capacity_tol = max(1e-09, 1e-06 * max(1.0, self.capacity))
        self.near_capacity_level = self.capacity - self.near_capacity_tol
        self.permanent_defect = False
        self.low_coop_streak = 0
        self.last_threshold = self.capacity

    def _threshold(self, round_number: int) -> float:
        if self.r <= 1:
            base = self.capacity
        else:
            base = self.capacity * (1.0 - round_number / (self.r - 1)) + 2.0 * self.n
        return min(self.capacity, max(2.0 * self.n, float(base)))

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = int(history.round_number) + 1
        S = float(current_stock)
        if history.round_number == 0:
            self.last_threshold = self._threshold(0)
            return Action.C
        if len(history.opponent_cooperators) > 0:
            k_prev = int(history.opponent_cooperators[-1])
        else:
            k_prev = None
        if k_prev is not None:
            if k_prev < self.low_coop_threshold:
                self.low_coop_streak += 1
            else:
                self.low_coop_streak = 0
            if self.low_coop_streak >= 2:
                self.permanent_defect = True
        T_t = self._threshold(t - 1)
        self.last_threshold = T_t
        if self.permanent_defect:
            return Action.D
        if S <= self.critical_stock:
            return Action.D
        if t >= self.r:
            if k_prev is None:
                return Action.C if S > self.capacity / 2.0 else Action.D
            return Action.D if self.n_opponents - k_prev > 0 else Action.C
        if S < T_t:
            return Action.D
        if k_prev is not None:
            if k_prev == self.n_opponents and S >= self.capacity / 2.0:
                return Action.C
            if self.capacity <= 2.0 * self.n + self.near_capacity_tol:
                return Action.C if k_prev == self.n_opponents else Action.D
            if k_prev >= self.low_coop_threshold and S >= T_t:
                return Action.C
        if k_prev is None:
            return Action.C if S > self.capacity / 2.0 else Action.D
        return Action.D

class Strategy_SELFINTERESTED_44(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Starts with cooperation.
    - Defects in the final round.
    - Cooperates when the stock is low.
    - Defects after clearly uncooperative rounds.
    - Returns to cooperation only after two consecutive good rounds.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.last_total_cooperators = 0
        self.good_streak = 0
        self.mode = Action.C

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = int(self.game_description.n_players)
        r = int(self.game_description.n_rounds)
        capacity = float(self.game_description.capacity)
        if history.round_number > 0:
            last_my_action = bool(history.my_actions[-1])
            last_opponent_cooperators = int(history.opponent_cooperators[-1])
            self.last_total_cooperators = last_opponent_cooperators + (1 if last_my_action else 0)
            threshold_good = math.ceil(0.8 * n)
            threshold_bad = math.floor(0.6 * n)
            if self.last_total_cooperators >= threshold_good:
                self.good_streak += 1
            else:
                self.good_streak = 0
            if self.last_total_cooperators <= threshold_bad:
                self.mode = Action.D
            elif self.good_streak >= 2:
                self.mode = Action.C
        if history.round_number == 0:
            self.mode = Action.C
            self.last_total_cooperators = 0
            self.good_streak = 0
            return Action.C
        if history.round_number >= r - 1:
            self.mode = Action.D
            return Action.D
        safe_capacity = capacity / 4.0 if capacity > 0 else 0.0
        if current_stock <= safe_capacity:
            self.mode = Action.C
            return Action.C
        threshold_good = math.ceil(0.8 * n)
        threshold_bad = math.floor(0.6 * n)
        good_round = self.last_total_cooperators >= threshold_good
        bad_round = self.last_total_cooperators <= threshold_bad
        if bad_round:
            self.good_streak = 0
            self.mode = Action.D
            return Action.D
        if good_round:
            if self.good_streak >= 2:
                self.mode = Action.C
                return Action.C
            return self.mode
        return self.mode

class Strategy_SELFINTERESTED_45(BaseStrategy):
    """
    Cooperate initially, keep cooperating only under strong reciprocal cooperation
    and sufficient stock, and defect in the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        if round_number == 0:
            return Action.C
        if round_number >= self.n_rounds - 1:
            return Action.D
        n = self.n_players
        n_opponents = max(0, n - 1)
        threshold = self.capacity / max(1, 2 * n)
        h1 = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) >= 1 else 0
        h2 = int(history.opponent_cooperators[-2]) if round_number >= 2 and len(history.opponent_cooperators) >= 2 else 0
        if current_stock <= threshold:
            return Action.D
        if h1 <= n - 3:
            return Action.D
        if round_number >= 2:
            if h1 < n - 2 or h2 < n - 2:
                return Action.D
        return Action.C

class Strategy_SELFINTERESTED_46(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Start by cooperating to test reciprocity.
    - Track recent opponent cooperation to estimate whether the pool can be sustained.
    - Cooperate when stock is healthy and the group appears cooperative.
    - Defect quickly when stock is low, cooperation collapses, or endgame extraction is preferable.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.m = max(self.n - 1, 0)

    def _clamp(self, value: float, low: float, high: float) -> float:
        return max(low, min(high, value))

    def _stock_ratio(self, current_stock: float) -> float:
        cap = self.capacity
        if cap <= 0:
            return 0.0
        return float(current_stock) / cap

    def _coop_rate(self, history: PlayerHistory) -> float:
        if history.round_number == 0 or self.m <= 0:
            return 1.0
        last = int(history.opponent_cooperators[-1])
        return self._clamp(last / self.m, 0.0, 1.0)

    def _last_two_high(self, history: PlayerHistory) -> bool:
        if history.round_number < 2 or self.m <= 0:
            return False
        prev = int(history.opponent_cooperators[-1]) / self.m
        prev2 = int(history.opponent_cooperators[-2]) / self.m
        return prev >= 0.5 and prev2 >= 0.5

    def _last_two_low(self, history: PlayerHistory) -> bool:
        if history.round_number < 2 or self.m <= 0:
            return False
        prev = int(history.opponent_cooperators[-1]) / self.m
        prev2 = int(history.opponent_cooperators[-2]) / self.m
        return prev < 0.5 and prev2 < 0.5

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.n
        cap = self.capacity
        ratio = self._stock_ratio(current_stock)
        if history.round_number == 0:
            return Action.C if cap > 0 else Action.D
        if ratio < 0.2:
            return Action.D
        coop_rate = self._coop_rate(history)
        if n == 2:
            if history.opponent_cooperators[-1] >= 1 and ratio >= 0.5:
                return Action.C
            return Action.D
        threshold = self._clamp(0.5 + 0.25 * (0.5 - coop_rate), 0.35, 0.65)
        if self._last_two_high(history):
            threshold = max(0.3, threshold - 0.05)
        if self._last_two_low(history):
            threshold = min(0.75, threshold + 0.1)
        if int(history.opponent_cooperators[-1]) == 0 and ratio < 0.85:
            return Action.D
        if history.round_number == self.r - 1:
            if ratio >= 0.9 and coop_rate == 1.0:
                return Action.C
            return Action.D
        if ratio >= 0.95 and coop_rate >= 0.25:
            return Action.C
        if ratio >= threshold and (coop_rate >= 0.5 or ratio >= 0.8):
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_47(BaseStrategy):
    """
    Thresholded best-response strategy with memory of the previous round's
    opponent cooperation count.

    - Round 1: cooperate.
    - Last round: defect.
    - Otherwise: estimate whether cooperating preserves more continuation value
      than defecting, using the previous round's opponent cooperation rate as a
      forecast. Falls back to a simple threshold rule when needed.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(0, self.n - 1)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = int(history.round_number)
        if t == 0:
            return Action.C
        if t >= self.r - 1:
            return Action.D
        S_t = float(current_stock)
        if S_t <= 0.0:
            return Action.D
        if len(history.opponent_cooperators) > 0 and self.n_opponents > 0:
            prev_c = float(history.opponent_cooperators[-1])
            x_t = prev_c / float(self.n_opponents)
            x_t = min(1.0, max(0.0, x_t))
        else:
            x_t = 1.0
        opp_expected_consumption = self.n_opponents * (x_t * S_t / (2.0 * self.n) + (1.0 - x_t) * S_t / float(self.n))
        q_c = opp_expected_consumption + S_t / (2.0 * self.n)
        q_d = opp_expected_consumption + S_t / float(self.n)
        s_c = max(0.0, S_t - q_c)
        s_d = max(0.0, S_t - q_d)

        def grow(s: float) -> float:
            if s <= 0.0:
                return 0.0
            new_s = s + 2.0 * s * (1.0 - s / self.capacity)
            return min(new_s, self.capacity)
        s_c_next = grow(s_c)
        s_d_next = grow(s_d)
        alpha_t = 1.0
        v_c = S_t / (2.0 * self.n) + alpha_t * s_c_next
        v_d = S_t / float(self.n) + alpha_t * s_d_next
        if v_c >= v_d:
            return Action.C
        if self.n_opponents > 0:
            if x_t >= 0.5:
                return Action.C
            return Action.D
        return Action.C

class Strategy_SELFINTERESTED_48(BaseStrategy):
    """
    Threshold-based common-pool strategy:
    - Cooperate in round 1.
    - In intermediate rounds, cooperate only if the previous round's observed
      opponent cooperation is sufficient to keep the pool weakly nondecreasing.
    - Defect in the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        if round_number == 0:
            return Action.C
        if round_number >= self.n_rounds - 1:
            return Action.D
        S = float(current_stock)
        if S <= 0.0:
            return Action.D
        if len(history.opponent_cooperators) == 0:
            return Action.D
        k = int(history.opponent_cooperators[-1])
        cap = self.capacity
        n = self.n_players
        if cap <= 0.0 or S <= 0.0:
            x_min = 1
        else:
            ratio = S / cap
            radicand = max(0.0, 9.0 - 8.0 * ratio)
            threshold_value = n * cap / (2.0 * S) * (3.0 - math.sqrt(radicand))
            if not math.isfinite(threshold_value):
                x_min = n + 1
            else:
                x_min = int(math.ceil(threshold_value))
                if x_min < 1:
                    x_min = 1
        if x_min > n:
            return Action.D
        if k + 1 >= x_min:
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_49(BaseStrategy):
    """
    State-based conditional strategy with a cooperation threshold,
    recovery behavior under low stock, and a short retaliation mode
    after opponent defection.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self._last_seen_round = -1
        self._retaliation_remaining = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        rounds = self.game_description.n_rounds
        capacity = float(self.game_description.capacity)
        round_idx = history.round_number
        high_stock = capacity / 2.0
        critical_stock = capacity / 4.0
        cooperation_bar = 0.5
        retaliation_bar = 2.0 / 3.0
        n_opponents = max(1, n - 1)
        if history.round_number > 0 and len(history.opponent_cooperators) > 0:
            last_opponent_cooperators = float(history.opponent_cooperators[-1])
            coop_share = last_opponent_cooperators / float(n_opponents)
        else:
            coop_share = 0.0
        if history.round_number > self._last_seen_round:
            self._last_seen_round = history.round_number
            if history.round_number > 0 and coop_share < cooperation_bar:
                self._retaliation_remaining = max(self._retaliation_remaining, 2)
        if history.round_number == 0:
            return Action.C if capacity >= 3.0 * n else Action.D
        if history.round_number == rounds - 1:
            if coop_share == 1.0 and current_stock >= high_stock:
                return Action.C
            return Action.D
        if self._retaliation_remaining > 0:
            self._retaliation_remaining -= 1
            if current_stock >= high_stock and coop_share >= retaliation_bar:
                return Action.C
            return Action.D
        if current_stock < critical_stock:
            return Action.D
        if current_stock < high_stock:
            return Action.D
        if coop_share >= cooperation_bar and current_stock >= high_stock:
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_50(BaseStrategy):
    """
    Two-mode strategy for the Common Pool Resource Game:
    start cooperative, switch to defection on weak stock or opponent cooperation,
    and return to cooperation only after sustained recovery.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.mode = 'COOPERATE'

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_rounds = int(self.game_description.n_rounds)
        n_players = int(self.game_description.n_players)
        n_opponents = max(n_players - 1, 1)
        round_number = int(history.round_number)

        def coop_rate(round_index_from_end: int) -> float:
            if round_number <= round_index_from_end:
                return 1.0
            idx = round_index_from_end
            opponents = history.opponent_cooperators[idx]
            return float(opponents) / float(n_opponents)
        if round_number == 0:
            self.mode = 'COOPERATE'
            return Action.C
        if round_number == n_rounds - 1:
            self.mode = 'DEFECT'
            return Action.D
        q_prev = coop_rate(-1)
        q_prev2 = coop_rate(-2) if round_number > 1 else 1.0
        stock_ok_for_cooperate = current_stock >= 0.8 * float(self.game_description.capacity)
        stock_bad_for_cooperate = current_stock < 0.7 * float(self.game_description.capacity)
        if self.mode == 'COOPERATE':
            trigger = stock_bad_for_cooperate or q_prev < 0.6 or (round_number > 1 and q_prev < 0.7 and (q_prev2 < 0.7))
            if trigger:
                self.mode = 'DEFECT'
                return Action.D
            return Action.C
        recovered = stock_ok_for_cooperate and q_prev >= 0.75 and (round_number <= 1 or q_prev2 >= 0.75)
        if recovered:
            self.mode = 'COOPERATE'
        return Action.D

class Strategy_SELFINTERESTED_51(BaseStrategy):
    """
    Adaptive common-pool strategy with trust-based cooperation,
    retaliation against low cooperation, and stock-aware decision making.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.mode = 'cooperate'
        self.trust = 1.0
        self.retaliation_timer = 0
        self.q_history = []

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = max(2, int(self.game_description.n_players))
        r = max(2, int(self.game_description.n_rounds))
        capacity = float(self.game_description.capacity)
        t = int(history.round_number)
        if t == 0:
            self.mode = 'cooperate'
            self.trust = 1.0
            self.retaliation_timer = 0
            return Action.C
        opp_count = max(1, n - 1)
        last_q = float(history.opponent_cooperators[-1]) / opp_count
        self.q_history.append(last_q)
        self.trust = 0.6 * float(self.trust) + 0.4 * float(last_q)
        if self.trust < 0.0:
            self.trust = 0.0
        elif self.trust > 1.0:
            self.trust = 1.0
        if current_stock <= capacity / 3.0:
            if self.retaliation_timer > 0:
                self.retaliation_timer = max(0, self.retaliation_timer - 1)
            return Action.C
        if last_q <= 0.25:
            self.mode = 'defect'
            self.retaliation_timer = 2
        if len(self.q_history) >= 2 and self.q_history[-1] >= 0.75 and (self.q_history[-2] >= 0.75):
            self.mode = 'cooperate'
            self.retaliation_timer = 0
        if t == r - 1:
            return Action.D
        if self.mode == 'defect' and self.retaliation_timer > 0:
            self.retaliation_timer -= 1
            return Action.D
        S = float(current_stock)
        trust = min(1.0, max(0.0, float(self.trust)))
        opp_cons = (n - 1) * S * (trust / (2.0 * n) + (1.0 - trust) / n)
        cons_C = S / (2.0 * n) + opp_cons
        R_C = max(0.0, S - cons_C)
        next_C = min(R_C + 2.0 * R_C * (1.0 - R_C / capacity), capacity) if capacity > 0 else 0.0
        cons_D = S / n + opp_cons
        R_D = max(0.0, S - cons_D)
        next_D = min(R_D + 2.0 * R_D * (1.0 - R_D / capacity), capacity) if capacity > 0 else 0.0
        if t == r - 2 and math.isclose(next_C, next_D, rel_tol=1e-12, abs_tol=1e-12):
            return Action.C if S <= capacity / 2.0 else Action.D
        if next_C >= next_D + 0.05 * capacity or trust >= 0.75:
            self.mode = 'cooperate'
            return Action.C
        self.mode = 'defect'
        return Action.D

class Strategy_SELFINTERESTED_52(BaseStrategy):
    """
    Conservative adaptive strategy for the Common Pool Resource Game.

    - Round 1: defect.
    - Final round: defect.
    - Otherwise:
      * High stock (>= 70% capacity): defect.
      * Low stock (<= 40% capacity): cooperate only if opponent cooperation was high.
      * Medium stock: cooperate only if cooperation is sufficiently high and non-decreasing.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self._last_x_prev = 1.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = float(self.game_description.capacity)
        if history.round_number == 0:
            return Action.D
        n_opponents = max(n - 1, 0)
        if n_opponents > 0 and len(history.opponent_cooperators) > 0:
            c = int(history.opponent_cooperators[-1])
            x = c / n_opponents
        else:
            x = 1.0
        x_prev = self._last_x_prev if self._last_x_prev is not None else 1.0
        remaining_rounds = r - history.round_number
        if remaining_rounds <= 1:
            self._last_x_prev = x
            return Action.D
        stock = float(current_stock)
        high_threshold = 0.7 * capacity
        low_threshold = 0.4 * capacity
        if stock >= high_threshold:
            action = Action.D
        elif stock <= low_threshold:
            if remaining_rounds <= 2:
                action = Action.C if x >= 0.7 and x_prev >= 0.7 and (stock > 0.0) else Action.D
            else:
                action = Action.C if x >= 0.7 else Action.D
        elif remaining_rounds <= 2:
            action = Action.D
        else:
            action = Action.C if x >= 0.5 and x >= x_prev else Action.D
        self._last_x_prev = x
        return action

class Strategy_SELFINTERESTED_53(BaseStrategy):
    """
    Common pool resource strategy with stock-aware thresholds, history adjustment,
    and run-length protection against repeated low cooperation.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self._last_stock = float(game_description.capacity)
        self._prev_rho = None
        self._prev_prev_rho = None

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        capacity = float(self.game_description.capacity)
        n_opponents = max(n - 1, 1)
        if history.round_number == 0:
            self._last_stock = float(current_stock)
            self._prev_prev_rho = None
            self._prev_rho = None
            return Action.C
        last_k = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        rho = last_k / n_opponents
        if self._prev_rho is not None:
            self._prev_prev_rho = self._prev_rho
        self._prev_rho = rho
        stock_fell = float(current_stock) < float(self._last_stock)
        low_two_in_a_row = self._prev_prev_rho is not None and self._prev_rho is not None and (self._prev_prev_rho < 0.5) and (self._prev_rho < 0.5)
        low_threshold = 0.5
        middle_threshold = 2.0 / 3.0
        if stock_fell:
            low_threshold = 1.0 / 3.0
            middle_threshold = 1.0 / 2.0
        if low_two_in_a_row and (not (rho >= 2.0 / 3.0 or current_stock <= 0.4 * capacity)):
            self._last_stock = float(current_stock)
            return Action.D
        if current_stock <= 0.4 * capacity:
            action = Action.C if rho >= low_threshold else Action.D
            self._last_stock = float(current_stock)
            return action
        if history.round_number == self.game_description.n_rounds - 1:
            self._last_stock = float(current_stock)
            return Action.D
        if current_stock <= 0.6 * capacity:
            action = Action.C if rho >= low_threshold else Action.D
        elif current_stock < 0.85 * capacity:
            action = Action.C if rho >= middle_threshold else Action.D
        else:
            action = Action.C if rho == 1.0 else Action.D
        self._last_stock = float(current_stock)
        return action

class Strategy_SELFINTERESTED_54(BaseStrategy):
    """
    Adaptive cooperation strategy for the Common Pool Resource Game.

    - Cooperates in round 1.
    - Then uses current stock and last-round opponent cooperation rate.
    - Becomes conservative when stock is low or opponents free-ride.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(0, self.n_players - 1)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        if round_number == 0:
            return Action.C
        cap = self.capacity if self.capacity > 0 else 1.0
        x = float(current_stock) / cap
        last_coop = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        if self.n_players == 2:
            p = 1.0 if last_coop >= 1 else 0.0
        else:
            denom = self.n_players - 1
            p = last_coop / denom if denom > 0 else 0.0
        all_opp_coop = last_coop >= self.n_opponents if self.n_opponents > 0 else True
        no_opp_coop = last_coop <= 0
        final_round = round_number >= self.n_rounds - 1
        if final_round:
            if x >= 0.8 and p == 1.0:
                return Action.C
            return Action.D
        if no_opp_coop:
            return Action.D
        if all_opp_coop and x >= 0.15:
            return Action.C
        if all_opp_coop and x < 0.15:
            return Action.D
        if x <= 0.25:
            return Action.D
        if x >= 0.75:
            return Action.C if p >= 0.5 else Action.D
        if p >= 0.5:
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_55(BaseStrategy):
    """
    Self-interested stock-preserving strategy for the Common Pool Resource Game.

    - Round 1: cooperate.
    - Later rounds: compare a one-step-plus-continuation score for C vs D,
      based on last-round opponent cooperation and current stock.
    - Final round or zero stock: defect.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        if round_number == 0:
            return Action.C
        if self.r <= 1:
            return Action.D
        t = round_number + 1
        if t >= self.r:
            return Action.D
        s = float(current_stock)
        if s <= 0.0:
            return Action.D
        o = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        if o < 0:
            o = 0
        n_opponents = max(self.n - 1, 0)
        if o > n_opponents:
            o = n_opponents
        m = self.r - t
        if m <= 0:
            return Action.D
        n = max(self.n, 1)
        capacity = self.capacity if self.capacity > 0.0 else 1.0
        k_c = o + 1
        k_d = o
        r_c = s * k_c / (2.0 * n)
        r_d = s * k_d / (2.0 * n)
        s_c = r_c + 2.0 * r_c * (1.0 - r_c / capacity)
        s_d = r_d + 2.0 * r_d * (1.0 - r_d / capacity)
        if s_c > capacity:
            s_c = capacity
        if s_d > capacity:
            s_d = capacity
        if s_c < 0.0:
            s_c = 0.0
        if s_d < 0.0:
            s_d = 0.0
        score_c = s / (2.0 * n) + m * s_c / (2.0 * n)
        score_d = s / n + m * s_d / (2.0 * n)
        return Action.C if score_c >= score_d else Action.D

class Strategy_SELFINTERESTED_56(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Cooperate first to try to sustain the resource.
    - Defect on the final round.
    - Defect when the stock is depleted.
    - Otherwise, respond to the previous round's cooperation rate:
      high cooperation sustains cooperation, low cooperation triggers defection,
      and mixed behavior is resolved by a stock-based projection.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number
        if t == 0:
            return Action.C
        if t >= self.n_rounds - 1:
            return Action.D
        if current_stock <= 0.0:
            return Action.D
        if len(history.opponent_cooperators) == 0:
            return Action.C
        q = int(history.opponent_cooperators[-1])
        n_opponents = self.n_players - 1
        if n_opponents <= 0:
            return Action.C
        p = q / n_opponents
        if p >= 2.0 / 3.0 and current_stock >= self.capacity / 3.0:
            return Action.C
        if p <= 1.0 / 3.0:
            return Action.D
        hC = q + 1
        hD = q

        def next_stock(h: int) -> float:
            consumed = current_stock * h / (2.0 * self.n_players)
            projected = 3.0 * consumed - 2.0 * (consumed * consumed) / self.capacity
            return min(projected, self.capacity)
        return Action.C if next_stock(hC) >= next_stock(hD) else Action.D

class Strategy_SELFINTERESTED_57(BaseStrategy):
    """
    Common pool strategy:
    - Cooperate in round 1.
    - Use recent opponent cooperation and current stock to decide.
    - Defect in the final round if possible.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.critical = self.capacity / 4.0
        self.target = self.capacity / 2.0
        self.high = 3.0 * self.capacity / 4.0
        self.memory_window = 3

    def _weighted_opponent_cooperation_rate(self, history: PlayerHistory) -> float:
        """
        Weighted average cooperation rate of opponents over the last 2-3 rounds,
        giving more weight to recent rounds.
        """
        opp_counts = history.opponent_cooperators
        rounds_seen = len(opp_counts)
        if rounds_seen <= 0:
            return 0.0
        window = min(self.memory_window, rounds_seen)
        start = rounds_seen - window
        total_weight = 0.0
        weighted_sum = 0.0
        for idx in range(window):
            round_idx = start + idx
            weight = float(idx + 1)
            opp_coop = float(opp_counts[round_idx])
            denom = float(max(self.n_players - 1, 1))
            rate = opp_coop / denom
            weighted_sum += weight * rate
            total_weight += weight
        if total_weight <= 0.0:
            return 0.0
        return weighted_sum / total_weight

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number >= self.n_rounds - 1:
            return Action.D if current_stock > 0.0 else Action.C
        stock = float(current_stock)
        q = self._weighted_opponent_cooperation_rate(history)
        if stock <= self.critical:
            return Action.C
        if q >= 0.5:
            return Action.D if stock >= self.high else Action.C
        return Action.D if stock > self.critical else Action.C

class Strategy_SELFINTERESTED_58(BaseStrategy):
    """
    Cooperate in round 1, then conditionally cooperate only after full opponent
    cooperation and sufficiently high stock, while always defecting in the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        n = self.n_players
        if round_number == 0:
            return Action.C
        if round_number >= self.n_rounds - 1:
            return Action.D
        if len(history.opponent_cooperators) == 0:
            return Action.D
        last_opponent_cooperators = int(history.opponent_cooperators[-1])
        full_cooperation = last_opponent_cooperators >= max(0, n - 1)
        high_stock = float(current_stock) >= self.capacity / 2.0
        if full_cooperation and high_stock:
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_59(BaseStrategy):
    """
    Score-based cooperation strategy for the Common Pool Resource Game.

    - Round 1: cooperate.
    - Later rounds: estimate next-round stock under C and D using the
      previous round's opponent cooperation count, then choose the action
      with the higher continuation-adjusted score.
    - Ties and several edge cases default to defection.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)

    def _next_stock(self, remaining: float) -> float:
        cap = self.capacity
        if cap <= 0.0:
            return 0.0
        nxt = 3.0 * remaining - 2.0 * (remaining * remaining) / cap
        if nxt > cap:
            return cap
        return nxt

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t0 = history.round_number
        if t0 == 0:
            return Action.C
        if t0 >= self.r - 1:
            return Action.D
        k = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else self.n - 1
        if k <= 0:
            return Action.D
        n = self.n
        S = float(current_stock)
        cap = self.capacity
        t = t0 + 1
        rounds_left_after_this_one = self.r - t
        if rounds_left_after_this_one < 0:
            rounds_left_after_this_one = 0
        remaining_c = S * (k + 1) / (2.0 * n) if n > 0 else 0.0
        remaining_d = S * k / (2.0 * n) if n > 0 else 0.0
        next_c = self._next_stock(remaining_c)
        next_d = self._next_stock(remaining_d)
        payoff_c = S / (2.0 * n) if n > 0 else 0.0
        payoff_d = S / n if n > 0 else 0.0
        score_c = payoff_c + rounds_left_after_this_one * next_c
        score_d = payoff_d + rounds_left_after_this_one * next_d
        return Action.C if score_c > score_d else Action.D

class Strategy_SELFINTERESTED_60(BaseStrategy):
    """
    Conditional cooperators: cooperate early, then continue cooperating only when
    recent cooperation is high, stock is healthy, and the stock is not trending down.
    Defection becomes more likely near the end of the horizon.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self._eps = 1e-12
        self._prev_stock = None
        self._prev_prev_stock = None
        self._last_action = None

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        n = max(2, self.n_players)
        r = max(2, self.n_rounds)
        cap = self.capacity
        if round_number == 0:
            self._prev_stock = float(current_stock)
            self._prev_prev_stock = None
            self._last_action = Action.C
            return Action.C
        decision_round = round_number + 1
        last_opponents = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        my_last_coop = 1 if bool(history.my_actions[-1]) else 0
        f_prev = (last_opponents + my_last_coop) / n
        denom = max(1, r - 1)
        theta_t = 1.0 - 0.5 * ((decision_round - 1) / denom)
        prev_stock = self._prev_stock if self._prev_stock is not None else float(current_stock)
        prev_prev_stock = self._prev_prev_stock
        nondecreasing = float(current_stock) >= prev_stock - self._eps
        two_consecutive_declines = prev_prev_stock is not None and float(current_stock) < prev_stock - self._eps and (prev_stock < prev_prev_stock - self._eps)
        endgame_len = int(math.ceil(r / 4))
        in_endgame = decision_round > r - endgame_len
        unanimous_enough = f_prev >= 1.0 - 1.0 / n
        if decision_round >= r:
            action = Action.D
        elif in_endgame and (not (float(current_stock) >= cap - self._eps and unanimous_enough)):
            action = Action.D
        else:
            healthy_stock = float(current_stock) >= 2.0 / 3.0 * cap - self._eps
            high_cooperation = f_prev > theta_t + self._eps or (abs(f_prev - theta_t) <= self._eps and nondecreasing)
            if healthy_stock and high_cooperation and (not two_consecutive_declines):
                action = Action.C
            else:
                action = Action.D
        self._prev_prev_stock = self._prev_stock
        self._prev_stock = float(current_stock)
        self._last_action = action
        return action

class Strategy_SELFINTERESTED_61(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Starts cooperative
    - Updates an estimated opponent cooperation rate q via exponential smoothing
    - Uses stock-based safety thresholds, trust thresholds, endgame logic,
      and a temporary forced-defection response to low-cooperation streaks
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.q = 1.0
        self.streak = 0
        self.forced_defect_rounds = 0
        self._processed_rounds = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        capacity = float(self.game_description.capacity)
        rounds_total = self.game_description.n_rounds
        round_number = history.round_number
        n_opponents = max(n - 1, 1)
        while self._processed_rounds < round_number:
            idx = self._processed_rounds
            k_t = int(history.opponent_cooperators[idx]) if idx < len(history.opponent_cooperators) else 0
            coop_rate = k_t / n_opponents
            self.q = 0.7 * self.q + 0.3 * coop_rate
            if k_t <= (n - 1) / 2:
                self.streak += 1
            else:
                self.streak = 0
            if self.streak >= 2:
                self.forced_defect_rounds = 2
            self._processed_rounds += 1
        if round_number == 0:
            return Action.C
        if self.forced_defect_rounds > 0:
            if not (self.q >= 0.9 and current_stock >= 0.8 * capacity):
                self.forced_defect_rounds -= 1
                return Action.D
        remaining_rounds = rounds_total - round_number
        if remaining_rounds <= 3:
            if self.q >= 0.8 and current_stock >= 0.6 * capacity:
                return Action.C
            return Action.D
        if current_stock <= 2 * n:
            return Action.D
        if self.q < 0.5:
            return Action.D
        if current_stock >= 0.8 * capacity and self.q >= 0.75:
            return Action.C
        if current_stock >= 0.6 * capacity and self.q >= 0.85:
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_62(BaseStrategy):
    """
    Conservative common-pool strategy with:
    - early cooperation when the horizon is long,
    - punishment after low cooperation,
    - late-game tightening,
    - a single endgame trust bonus when the pool is full and everyone cooperated.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.punish: bool = False
        self.late_game_bonus_used: bool = False
        self.last_seen_round: int = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = int(self.game_description.n_players)
        r = int(self.game_description.n_rounds)
        capacity = float(self.game_description.capacity)
        round_number = int(history.round_number)
        t = round_number + 1
        m = max(n - 1, 0)
        majority_coop = math.ceil(m / 2) if m > 0 else 0
        high_trust = math.ceil(2 * m / 3) if m > 0 else 0
        low_trust = math.floor(m / 3) if m > 0 else 0
        c_prev = int(history.opponent_cooperators[-1]) if round_number > 0 else 0
        S = float(current_stock)
        if round_number < self.last_seen_round:
            self.punish = False
            self.late_game_bonus_used = False
        self.last_seen_round = round_number
        action = Action.D
        if t >= r:
            action = Action.D
        elif round_number == 0:
            action = Action.D if r == 2 else Action.C
        elif self.punish:
            action = Action.D
        elif t >= r - 2:
            if c_prev == m and S == capacity and (not self.late_game_bonus_used):
                action = Action.C
                self.late_game_bonus_used = True
            else:
                action = Action.D
        elif c_prev >= majority_coop and S >= (capacity / 2.0 if capacity > 0 else 0.0) and (t <= r - 2):
            action = Action.C
        else:
            action = Action.D
        if c_prev >= high_trust:
            self.punish = False
        elif c_prev <= low_trust:
            self.punish = True
        elif self.punish and c_prev < high_trust:
            self.punish = True
        return action

class Strategy_SELFINTERESTED_63(BaseStrategy):
    """
    Threshold-based common-pool strategy:
    - Cooperate in round 1.
    - Defect in the final round.
    - In intermediate rounds, cooperate only when stock and recent cooperation
      meet the round-dependent threshold.
    - After a round with zero cooperating opponents, enter a defensive fallback
      mode that defects until cooperation recovers sufficiently or stock rises
      above half capacity.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.m = max(0, self.n_players - 1)
        self.half_opponents = math.ceil(self.m / 2) if self.m > 0 else 0
        self.three_quarter_opponents = math.ceil(3 * self.m / 4) if self.m > 0 else 0
        self.half_capacity = self.capacity / 2.0
        self.quarter_capacity = self.capacity / 4.0
        self.fallback_active = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        last_c = int(history.opponent_cooperators[-1]) if round_number > 0 else 0
        if round_number == 0:
            self.fallback_active = False
            return Action.C
        if round_number >= self.n_rounds - 1:
            self.fallback_active = False
            return Action.D
        if last_c == 0:
            self.fallback_active = True
        if self.fallback_active:
            if current_stock > self.half_capacity or last_c >= self.half_opponents:
                self.fallback_active = False
            else:
                return Action.D
        if current_stock <= self.quarter_capacity:
            return Action.C if last_c == self.m else Action.D
        if current_stock >= self.half_capacity:
            return Action.C if last_c >= self.half_opponents else Action.D
        return Action.C if last_c >= self.three_quarter_opponents else Action.D

class Strategy_SELFINTERESTED_64(BaseStrategy):
    """
    Common pool strategy:
    - Cooperate in round 1.
    - In later rounds, predict the next stock under cooperate vs defect
      assuming opponents repeat their last observed behavior.
    - Cooperate when the predicted stock gain from cooperation outweighs
      the immediate extra payoff from defecting.
    - Use low-stock and last-round overrides as specified.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(self.n_players - 1, 0)
        self.low_stock_threshold = self.capacity / 4.0 if self.capacity > 0 else 0.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        if round_number == 0:
            return Action.C
        if round_number >= self.n_rounds - 1:
            return Action.D
        if len(history.opponent_cooperators) > 0:
            x = int(history.opponent_cooperators[-1])
        else:
            x = self.n_opponents
        if current_stock <= self.low_stock_threshold:
            return Action.C
        if x == 0:
            return Action.D
        n = self.n_players
        cap = self.capacity
        S = float(current_stock)
        if n <= 0 or cap <= 0:
            return Action.D
        denom = 2.0 * n
        R_C = S * (1.0 + x) / denom
        R_D = S * x / denom

        def next_stock(remaining: float) -> float:
            growth = 2.0 * remaining * (1.0 - remaining / cap)
            nxt = remaining + growth
            if nxt > cap:
                return cap
            if nxt < 0.0:
                return 0.0
            return nxt
        N_C = next_stock(R_C)
        N_D = next_stock(R_D)
        if N_C - N_D > S / denom:
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_65(BaseStrategy):
    """
    Stock-conserving common-pool strategy:
    - Cooperate early
    - Defect in the final round
    - Cooperate in low-stock or highly cooperative environments
    - Defect when stock is rich and last-round cooperation was weak
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        if round_number >= self.r - 1:
            return Action.D
        if round_number == 0:
            return Action.C
        S = float(current_stock)
        if not math.isfinite(S):
            S = self.capacity
        if len(history.opponent_cooperators) == 0:
            c = None
        else:
            c = int(history.opponent_cooperators[-1])
        if S <= self.capacity / 2.0:
            return Action.C
        if c is not None and c == self.n - 1:
            return Action.C
        if c is not None and S >= 3.0 * self.capacity / 4.0 and (c <= self.n - 2):
            return Action.D
        return Action.C

class Strategy_SELFINTERESTED_66(BaseStrategy):
    """
    Conservative common-pool strategy:
    - Cooperate in the first round.
    - Defect when stock is depleted, cooperation is falling, or the last round makes preservation irrelevant.
    - Cooperate only when stock is healthy and opponent cooperation is sufficiently strong.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(1, self.n_players - 1)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number
        if t == 0:
            return Action.C
        opponent_coops = history.opponent_cooperators
        rho_t = 0.0
        rho_prev = 0.0
        if len(opponent_coops) >= 1:
            rho_t = float(opponent_coops[-1]) / float(self.n_opponents)
        if len(opponent_coops) >= 2:
            rho_prev = float(opponent_coops[-2]) / float(self.n_opponents)
        if current_stock <= self.capacity / 4.0:
            return Action.D
        if t == self.n_rounds - 1:
            if current_stock < 2.0 * self.capacity / float(self.n_players + 1) or rho_t < 0.5:
                return Action.D
            return Action.C
        if current_stock >= 3.0 * self.capacity / 4.0 and rho_prev >= 0.5 and (rho_t >= 0.5):
            return Action.C
        if rho_t < rho_prev and rho_t < 0.5:
            return Action.D
        threshold = max(0.0, 2.0 * current_stock / (float(self.n_players) * self.capacity) - 0.5)
        if current_stock >= self.capacity / 2.0 and rho_t >= threshold:
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_67(BaseStrategy):
    """
    Adaptive common-pool strategy with three modes: build, punish, probe.
    Cooperates under strong recent cooperation and healthy stock, punishes broad defection,
    and probes recovery after punishment.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.mode = 'build'
        self.prev_coop_rate = None
        self.prev2_coop_rate = None

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_players = max(1, int(self.game_description.n_players))
        capacity = float(self.game_description.capacity) if self.game_description.capacity else 1.0
        round_number = history.round_number
        if round_number == 0:
            self.mode = 'build'
            self.prev_coop_rate = None
            self.prev2_coop_rate = None
            return Action.C
        last_opp = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        last_my = 1 if bool(history.my_actions[-1]) else 0
        coop_count = last_opp + last_my
        coop_rate = coop_count / n_players
        stock_ratio = current_stock / capacity if capacity > 0 else 0.0
        prev_coop_rate = self.prev_coop_rate
        prev2_coop_rate = self.prev2_coop_rate
        if self.mode == 'punish':
            if coop_rate >= 0.75 and stock_ratio >= 0.5:
                self.mode = 'probe'
        elif self.mode == 'probe':
            if coop_rate >= 0.75:
                self.mode = 'build'
            else:
                self.mode = 'punish'
        elif self.mode == 'build':
            if prev_coop_rate is not None and prev2_coop_rate is not None:
                if prev_coop_rate < 0.5 and prev2_coop_rate < 0.5:
                    self.mode = 'punish'
        is_last_round = round_number >= self.game_description.n_rounds - 1
        if coop_rate == 0:
            self.mode = 'punish'
            chosen = Action.D
        elif stock_ratio < 1.0 / 3.0 and coop_rate != 1:
            self.mode = 'punish'
            chosen = Action.D
        elif prev_coop_rate == 1 and prev2_coop_rate == 1:
            chosen = Action.C
        elif is_last_round and prev_coop_rate != 1:
            chosen = Action.D
        elif self.mode == 'punish':
            chosen = Action.D
        elif self.mode == 'probe':
            chosen = Action.C
        elif coop_rate >= 0.75 and stock_ratio >= 0.5:
            chosen = Action.C
        else:
            chosen = Action.D
        self.prev2_coop_rate = self.prev_coop_rate
        self.prev_coop_rate = coop_rate
        return chosen

class Strategy_SELFINTERESTED_68(BaseStrategy):
    """
    State-based threshold strategy with harvest, stabilize, exploitation, retaliation,
    and endgame defection phases for the common pool resource game.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.m = self.n // 2

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number
        n = self.n
        r = self.r
        cap = self.capacity
        m = self.m
        S = float(current_stock)
        if t == 0:
            return Action.D if n == 2 else Action.C
        if t >= r - 1:
            return Action.D
        last_opp_coop = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        my_last_action = bool(history.my_actions[-1]) if len(history.my_actions) > 0 else False
        total_coop_last = last_opp_coop + (1 if my_last_action else 0)
        if S <= 2 * n:
            return Action.D
        if t == r - 2:
            return Action.C if S >= cap / 2 and total_coop_last >= m else Action.D
        if total_coop_last >= m + 1:
            return Action.C if S > 3 * n else Action.D
        if total_coop_last < m:
            return Action.D
        if total_coop_last >= m:
            return Action.C
        if total_coop_last <= m - 2:
            return Action.D
        return Action.C if S >= 3 * n else Action.D

class Strategy_SELFINTERESTED_69(BaseStrategy):
    """
    Common Pool Resource strategy:
    - Cooperate in round 1.
    - Defect in the last round.
    - Use stock/cooperation thresholds in between.
    - Enter recovery mode after defecting for low cooperation, and stay there
      until both cooperation and stock recovery conditions are met together.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.previous_stock = None
        self.in_recovery = False
        self.last_action = None
        self.majority_threshold = math.ceil((self.n_players - 1) / 2)
        self.low_coop_threshold = math.floor((self.n_players - 1) / 3)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        if round_number == 0:
            self.previous_stock = float(current_stock)
            self.last_action = Action.C
            return Action.C
        if round_number >= self.n_rounds - 1:
            self.previous_stock = float(current_stock)
            self.last_action = Action.D
            return Action.D
        c = int(history.opponent_cooperators[-1]) if round_number > 0 else 0
        S = float(current_stock)
        prev_S = self.previous_stock
        if self.in_recovery:
            if c >= self.majority_threshold and S >= self.capacity / 2:
                self.in_recovery = False
            else:
                self.previous_stock = S
                self.last_action = Action.D
                return Action.D
        action = Action.D
        if S <= self.capacity / 3:
            action = Action.D
        elif c >= self.majority_threshold and S >= self.capacity / 2:
            action = Action.C
        elif c <= self.low_coop_threshold:
            action = Action.D
            self.in_recovery = True
        elif prev_S is not None and S > prev_S and (c >= self.majority_threshold):
            action = Action.C
        else:
            action = Action.D
        self.previous_stock = S
        self.last_action = action
        return action

class Strategy_SELFINTERESTED_70(BaseStrategy):
    """
    Conditional cooperation strategy with repair mode:
    - Start cooperatively
    - Defect only when cooperation is very high and stock is healthy
    - Enter short repair periods after cooperation weakens
    - Defect in the final round
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.last_k = None
        self.prev_k = None
        self.repair = 0
        self.S = self.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number
        self.S = float(current_stock)

        def my_was_coop(round_index: int) -> int:
            if round_index < 0 or round_index >= len(history.my_actions):
                return 0
            return 1 if bool(history.my_actions[round_index]) else 0
        if t > 0:
            last_opponents = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
            self.last_k = last_opponents + my_was_coop(t - 1)
            if t > 1:
                prev_opponents = int(history.opponent_cooperators[-2]) if len(history.opponent_cooperators) > 1 else 0
                self.prev_k = prev_opponents + my_was_coop(t - 2)
        if t == 0:
            return Action.C
        if t == self.r - 1:
            return Action.D
        if self.repair > 0:
            self.repair -= 1
            return Action.C
        k = self.last_k if self.last_k is not None else 0
        coop_rate = k / self.n if self.n > 0 else 0.0
        if k <= math.floor(self.n / 2):
            self.repair = 2
            return Action.C
        if self.prev_k is not None and self.prev_k - k >= 2:
            self.repair = 2
            return Action.C
        if coop_rate >= 0.8 and self.S >= 0.7 * self.capacity:
            return Action.D
        return Action.C

class Strategy_SELFINTERESTED_71(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Start by cooperating.
    - Defect on the final round.
    - In intermediate rounds, cooperate only when cooperation was sufficiently high
      in the previous round and stock is not too depleted.
    - Recover to cooperation immediately after two consecutive defections if the
      observed cooperation rate becomes very high.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(0, self.n_players - 1)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        if round_number == 0:
            return Action.C
        if round_number >= self.n_rounds - 1:
            return Action.D
        capacity = self.capacity if self.capacity > 0 else 1.0
        s = current_stock / capacity
        last_opp_coop = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        rho = last_opp_coop / self.n_opponents if self.n_opponents > 0 else 0.0
        last_my_action = bool(history.my_actions[-1]) if len(history.my_actions) > 0 else True
        prev_my_action = bool(history.my_actions[-2]) if len(history.my_actions) > 1 else True
        two_consecutive_defections = not last_my_action and (not prev_my_action)
        if s < 1.0 / 6.0:
            if rho >= 1.0 and round_number < self.n_rounds - 1:
                return Action.C
            return Action.D
        if two_consecutive_defections and rho >= 5.0 / 6.0:
            return Action.C
        if rho < 0.5:
            if rho >= 5.0 / 6.0:
                return Action.C
            return Action.D
        if rho >= 5.0 / 6.0 and s >= 0.25 or (rho >= 2.0 / 3.0 and s >= 0.5):
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_72(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Cooperate in round 1.
    - Defect in the final two rounds.
    - Otherwise, estimate opponents' recent cooperation and choose between
      cooperation and defection based on predicted stock recovery.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.n_players
        r = self.n_rounds
        cap = self.capacity
        s = float(current_stock)
        if history.round_number == 0:
            return Action.C
        if history.round_number >= max(0, r - 2):
            return Action.D
        n_opponents = max(0, n - 1)
        prev_opp_coops = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        if n_opponents > 0:
            p = prev_opp_coops / n_opponents
        else:
            p = 0.0
        if p < 0.0:
            p = 0.0
        elif p > 1.0:
            p = 1.0
        if n > 0:
            own_c = s / (2.0 * n)
            own_d = s / float(n)
            expected_opponent_consumption = (n - 1) * s * (2.0 - p) / (2.0 * n)
        else:
            own_c = 0.0
            own_d = 0.0
            expected_opponent_consumption = 0.0

        def predict_next_stock(own_consumption: float) -> float:
            remaining = s - own_consumption - expected_opponent_consumption
            if remaining < 0.0:
                remaining = 0.0
            if remaining > cap:
                remaining = cap
            growth = 2.0 * remaining * (1.0 - remaining / cap) if cap > 0 else 0.0
            nxt = remaining + growth
            return min(nxt, cap)
        r_c = predict_next_stock(own_c)
        r_d = predict_next_stock(own_d)
        if p < 0.5:
            return Action.C
        if r_d >= cap / 2.0:
            return Action.D
        if r_c < cap / 2.0:
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_73(BaseStrategy):
    """
    Self-interested common-pool strategy:
    - Cooperate on the first round.
    - Defect in the final two rounds.
    - Otherwise, update an internal belief p about opponent cooperation and
      cooperate only when the stock is low/medium and the belief is high enough.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.p = 1.0
        self._last_updated_round = -1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_players = max(2, int(self.game_description.n_players))
        n_rounds = int(self.game_description.n_rounds)
        capacity = float(self.game_description.capacity)
        round_number = int(history.round_number)
        if round_number > 0 and self._last_updated_round != round_number:
            opp_counts = history.opponent_cooperators
            if len(opp_counts) > 0:
                last_count = float(opp_counts[-1])
                n_opponents = max(1, n_players - 1)
                rho = last_count / float(n_opponents)
                self.p = 0.5 * self.p + 0.5 * rho
            self._last_updated_round = round_number
        if round_number == 0:
            return Action.C
        if round_number >= max(0, n_rounds - 2):
            return Action.D
        if capacity <= 0:
            return Action.D
        stock = float(current_stock)
        if stock < capacity / 3.0:
            return Action.C if self.p >= 2.0 / 3.0 else Action.D
        if stock < 2.0 * capacity / 3.0:
            threshold = 0.5 + 1.0 / (2.0 * n_players)
            return Action.C if self.p >= threshold else Action.D
        return Action.D

class Strategy_SELFINTERESTED_74(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Cooperate in round 1.
    - Then estimate opponent cooperation with exponential smoothing.
    - Compare a one-step continuation proxy for C vs D and choose the better action.
    - Default to D on ties or terminal/degenerate cases.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(getattr(game_description, 'n_players', 0))
        self.r = int(getattr(game_description, 'n_rounds', 0))
        self.capacity = float(getattr(game_description, 'capacity', 0.0))
        self.p_prev = 0.5

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = max(2, self.n)
        current_stock = float(current_stock)
        if history.round_number == 0:
            return Action.C
        if current_stock <= 0.0:
            return Action.D
        t = history.round_number + 1
        L = self.r - t + 1
        if L <= 1:
            return Action.D
        opp_count = 0
        n_opponents = n - 1
        if n_opponents > 0 and len(history.opponent_cooperators) > 0:
            opp_count = int(history.opponent_cooperators[-1])
            if opp_count < 0:
                opp_count = 0
            elif opp_count > n_opponents:
                opp_count = n_opponents
            if opp_count == 0:
                q = 0.0
            elif opp_count == n_opponents:
                q = 1.0
            else:
                q = opp_count / n_opponents
        else:
            q = 0.5
        p = 0.7 * self.p_prev + 0.3 * q
        if p < 0.0:
            p = 0.0
        elif p > 1.0:
            p = 1.0
        self.p_prev = p
        S = current_stock
        cap = self.capacity if self.capacity > 0.0 else 1.0
        opp_c = S / (2.0 * n)
        opp_d = S / n
        E_opp = (n - 1) * (p * opp_c + (1.0 - p) * opp_d)

        def next_stock_after_remaining(R: float) -> float:
            if R < 0.0:
                R = 0.0
            elif R > cap:
                R = cap
            growth = 2.0 * R * (1.0 - R / cap)
            new_stock = R + growth
            if new_stock > cap:
                new_stock = cap
            elif new_stock < 0.0:
                new_stock = 0.0
            return new_stock
        R_C = S - (E_opp + opp_c)
        S_C = next_stock_after_remaining(R_C)
        R_D = S - (E_opp + opp_d)
        S_D = next_stock_after_remaining(R_D)
        V_C = opp_c + (L - 1) * (S_C / (2.0 * n))
        V_D = opp_d + (L - 1) * (S_D / (2.0 * n))
        if V_C > V_D:
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_75(BaseStrategy):
    """
    Common-pool strategy:
    - Round 1: cooperate.
    - Near the end: defect on the final round.
    - Otherwise, cooperate when stock is low or recent opponent cooperation is weak.
    - For n=2, use a simpler threshold rule with final-round defection.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(self.n_players - 1, 0)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = int(history.round_number) + 1
        S = float(current_stock)
        if history.round_number == 0:
            return Action.C
        if t == self.n_rounds:
            return Action.D
        if len(history.opponent_cooperators) == 0:
            return Action.C
        if self.n_players == 2:
            opp_coop_last = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
            if opp_coop_last >= 1 and S >= 0.75 * self.capacity:
                return Action.D
            return Action.C
        frac_last = int(history.opponent_cooperators[-1]) / self.n_opponents
        if len(history.opponent_cooperators) < 2:
            if S < 0.5 * self.capacity:
                return Action.C
            if frac_last < 0.5:
                return Action.C
            return Action.C
        frac_prev = int(history.opponent_cooperators[-2]) / self.n_opponents
        both_recent_high = frac_last >= 0.5 and frac_prev >= 0.5
        if not both_recent_high:
            return Action.C
        if S < 0.5 * self.capacity:
            return Action.C
        if frac_last < 0.5:
            return Action.C
        if S < 0.75 * self.capacity:
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_76(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Start with cooperation.
    - Estimate opponent cooperation with a weighted running average.
    - Use a one-step stock projection to compare C vs D.
    - Apply override rules for strong cooperation or persistent defection.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(0, self.n_players - 1)
        self.half_capacity = self.capacity / 2.0
        self.p_estimate = 1.0
        self.recent_low_count = 0
        self.force_defect_active = False
        self.high_coop_threshold = (self.n_players - 1) / self.n_players if self.n_players > 0 else 1.0
        if self.n_players > 1:
            self.low_coop_threshold = (self.n_players - 2) / (self.n_players - 1)
        else:
            self.low_coop_threshold = 0.0

    def _growth(self, stock_after_consumption: float) -> float:
        s = max(0.0, float(stock_after_consumption))
        next_stock = s + 2.0 * s * (1.0 - s / self.capacity) if self.capacity > 0 else s
        return min(next_stock, self.capacity)

    def _estimate_opponent_coop(self, history: PlayerHistory) -> float:
        if self.n_opponents <= 0:
            return 0.0
        rounds_played = history.round_number
        if rounds_played <= 0:
            return 1.0
        counts = np.asarray(history.opponent_cooperators, dtype=float)
        if counts.size == 0:
            return self.p_estimate
        frac = counts / float(self.n_opponents)
        long_run = float(np.mean(frac)) if frac.size > 0 else 1.0
        if frac.size >= 2:
            recent = float(np.mean(frac[-2:]))
            if abs(recent - long_run) >= 0.25:
                weighted = 0.6 * recent + 0.4 * long_run
                return float(min(1.0, max(0.0, weighted)))
        return float(min(1.0, max(0.0, long_run)))

    def _update_override_state(self, history: PlayerHistory) -> None:
        if history.round_number <= 0 or self.n_opponents <= 0:
            self.recent_low_count = 0
            self.force_defect_active = False
            self.p_estimate = 1.0
            return
        self.p_estimate = self._estimate_opponent_coop(history)
        last_frac = float(history.opponent_cooperators[-1]) / float(self.n_opponents)
        if last_frac < self.low_coop_threshold:
            self.recent_low_count += 1
        else:
            self.recent_low_count = 0
        if self.recent_low_count >= 2:
            self.force_defect_active = True
        if self.force_defect_active and self.p_estimate >= self.low_coop_threshold:
            self.force_defect_active = False
            self.recent_low_count = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.n_players
        r = self.n_rounds
        S = float(current_stock)
        if history.round_number == 0:
            return Action.C
        self._update_override_state(history)
        t = history.round_number + 1
        rounds_remaining = r - t + 1
        if rounds_remaining <= 1:
            return Action.D if S > 0.0 else Action.C
        if self.force_defect_active:
            return Action.D
        last_frac = 0.0
        if self.n_opponents > 0 and history.opponent_cooperators.size > 0:
            last_frac = float(history.opponent_cooperators[-1]) / float(self.n_opponents)
        if last_frac >= self.high_coop_threshold and S > self.half_capacity:
            return Action.C
        p_t = float(min(1.0, max(0.0, self.p_estimate)))
        m_c = 1.0 + p_t * (n - 1)
        m_d = p_t * (n - 1)
        s_c_prime = S - S / (2.0 * n) * m_c
        s_d_prime = S - S / (2.0 * n) * m_d - S / n
        s_c_hat = self._growth(s_c_prime)
        s_d_hat = self._growth(s_d_prime)
        u_c = S / (2.0 * n) + (rounds_remaining - 1) * s_c_hat / (2.0 * n)
        u_d = S / n + (rounds_remaining - 1) * s_d_hat / (2.0 * n)
        if abs(u_c - u_d) <= 1e-12:
            return Action.C if S >= self.half_capacity else Action.D
        if S <= self.half_capacity * 0.25 and p_t >= self.high_coop_threshold:
            return Action.C
        return Action.C if u_c > u_d else Action.D

class Strategy_SELFINTERESTED_77(BaseStrategy):
    """
    Adaptive common-pool strategy with cooperative probing, defensive fallback,
    and recovery based on observed opponent cooperation and current stock.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        n = max(2, int(game_description.n_players))
        r = max(1, int(game_description.n_rounds))
        capacity = float(game_description.capacity)
        if n == 2:
            self.high_threshold = 1
            self.recover_threshold = 1
            self.low_threshold = 0
        else:
            self.high_threshold = math.ceil(2 * (n - 1) / 3)
            self.recover_threshold = math.ceil((n - 1) / 2)
            self.low_threshold = math.floor((n - 1) / 3)
        self.safe_stock = capacity / 2.0
        self.recovery_stock = 3.0 * capacity / 4.0
        self.mode = 'cooperative'
        self.consecutive_defensive_cooperations = 0
        self.last_action = None
        self.n_rounds = r

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number
        n_rounds = self.n_rounds
        if t >= n_rounds - 1:
            self.mode = 'defensive'
            self.consecutive_defensive_cooperations = 0
            self.last_action = Action.D
            return Action.D
        if t == 0:
            self.mode = 'cooperative'
            self.consecutive_defensive_cooperations = 0
            self.last_action = Action.C
            return Action.C
        c_t = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        n_players = max(2, int(self.game_description.n_players))
        stock = float(current_stock)
        action = Action.D
        if stock <= self.safe_stock:
            self.mode = 'defensive'
            self.consecutive_defensive_cooperations = 0
            action = Action.D
        elif self.mode == 'defensive':
            if c_t >= self.high_threshold and stock >= self.recovery_stock:
                action = Action.C
                self.consecutive_defensive_cooperations += 1
                if self.consecutive_defensive_cooperations >= 2:
                    self.mode = 'cooperative'
                    self.consecutive_defensive_cooperations = 0
            else:
                action = Action.D
                self.consecutive_defensive_cooperations = 0
        else:
            if c_t >= self.recover_threshold:
                action = Action.C
            elif c_t <= self.low_threshold:
                action = Action.D
            elif c_t >= (n_players - 1) / 2:
                action = Action.C
            else:
                action = Action.D
            if action == Action.D and c_t < self.recover_threshold:
                self.mode = 'defensive'
                self.consecutive_defensive_cooperations = 0
        self.last_action = action
        return action

class Strategy_SELFINTERESTED_78(BaseStrategy):
    """
    Two-level trigger strategy with a stock floor and opponent-cooperation quorum.

    Rules:
    - Defect if stock is depleted or below the floor.
    - Cooperate in round 1 if stock is above the floor.
    - In later rounds, cooperate only if the previous round had a quorum of
      cooperating opponents and stock is still above the floor.
    - Defect in the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(getattr(game_description, 'n_players', 0))
        self.n_rounds = int(getattr(game_description, 'n_rounds', 0))
        self.capacity = float(getattr(game_description, 'capacity', 0.0))
        self.n_opponents = max(self.n_players - 1, 0)
        self.quorum = math.ceil(self.n_opponents / 2) if self.n_opponents > 0 else 0
        self.floor = self.capacity / 3.0
        self.last_k_prev = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(getattr(history, 'round_number', 0))
        n_rounds = self.n_rounds if self.n_rounds > 0 else int(getattr(self.game_description, 'n_rounds', 0))
        is_first_round = round_number == 0
        is_last_round = n_rounds > 0 and round_number >= n_rounds - 1
        if current_stock is None or current_stock <= 0.0:
            self.last_k_prev = 0
            return Action.D
        if is_last_round:
            k_prev = self._get_prev_cooperators(history)
            self.last_k_prev = k_prev
            return Action.D
        if current_stock <= self.floor:
            k_prev = self._get_prev_cooperators(history)
            self.last_k_prev = k_prev
            return Action.D
        if is_first_round:
            return Action.C
        k_prev = self._get_prev_cooperators(history)
        self.last_k_prev = k_prev
        if k_prev >= self.quorum:
            return Action.C
        return Action.D

    def _get_prev_cooperators(self, history: PlayerHistory) -> int:
        opp = getattr(history, 'opponent_cooperators', None)
        if opp is None:
            return int(self.last_k_prev)
        try:
            if len(opp) == 0:
                return int(self.last_k_prev)
            value = opp[-1]
            if value is None:
                return int(self.last_k_prev)
            return int(value)
        except Exception:
            return int(self.last_k_prev)

class Strategy_SELFINTERESTED_79(BaseStrategy):
    """
    Common Pool Resource strategy:
    - Round 1: cooperate.
    - Later rounds: cooperate when stock is depleted or opponent cooperation is weak,
      with hard overrides for the final round, zero-cooperation history, and full
      cooperation under very healthy stock.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(0, self.n_players - 1)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        if round_number == 0:
            return Action.C
        if round_number >= self.n_rounds - 1:
            return Action.D
        prev_opp_coop = 0
        if len(history.opponent_cooperators) > 0:
            prev_opp_coop = int(history.opponent_cooperators[-1])
        if self.n_opponents > 0:
            q = prev_opp_coop / self.n_opponents
        else:
            q = 0.0
        h = self.n_rounds - round_number
        denom = max(1, self.n_rounds - 1)
        theta = 0.45 + 0.25 * (h - 1) / denom
        low_stock = current_stock < 0.7 * self.capacity
        weak_cooperation = q < theta
        if prev_opp_coop == 0:
            return Action.C
        if self.n_opponents > 0 and prev_opp_coop >= self.n_opponents and (current_stock >= 0.85 * self.capacity):
            return Action.D
        if low_stock or weak_cooperation:
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_80(BaseStrategy):
    """
    Common Pool Resource strategy:
    - Cooperate on the first round.
    - Then cooperate only when stock is sufficiently high and prior opponent cooperation was at least half.
    - Defect in low-stock, unstable, or last-round depletion situations.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.safe_cooperation_level = 2.0 * self.n / 3.0
        self.low_stock_threshold = float(self.n)
        self.half_opponents = (self.n - 1) / 2.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = int(history.round_number)
        S = float(current_stock)
        if t == 0:
            return Action.C
        has_prev_opp = len(history.opponent_cooperators) > 0
        c_prev = int(history.opponent_cooperators[-1]) if has_prev_opp else None
        if S <= self.low_stock_threshold:
            return Action.D
        is_last_round = t >= self.r - 1
        if is_last_round and S < self.capacity:
            return Action.D
        if is_last_round and S >= self.capacity:
            if has_prev_opp and c_prev >= self.half_opponents:
                return Action.C
            return Action.D
        if not has_prev_opp:
            return Action.C if S >= self.safe_cooperation_level else Action.D
        if S >= self.safe_cooperation_level and c_prev >= self.half_opponents:
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_81(BaseStrategy):
    """
    Stock-and-cooperation threshold policy with guarded probing,
    gradual retaliation, and late-game tightening.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = max(2, int(game_description.n_players))
        self.r = max(2, int(game_description.n_rounds))
        self.capacity = float(game_description.capacity)
        self._last_round_seen = -1
        self._punish_mode = False
        self._punish_streak = 0
        self._cooperative_recovery_streak = 0

    def _expected_next_stock(self, s_t: float, opponent_rate: float, my_share: float) -> float:
        remaining = s_t - s_t * (my_share + opponent_rate * (self.n - 1) / (2 * self.n))
        growth = 2.0 * remaining * (1.0 - remaining / self.capacity) if self.capacity > 0 else 0.0
        return min(remaining + growth, self.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number
        n = self.n
        r = self.r
        cap = self.capacity
        if t != self._last_round_seen:
            self._last_round_seen = t
        if t == 0:
            self._punish_mode = False
            self._punish_streak = 0
            self._cooperative_recovery_streak = 0
            return Action.C
        last_k = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        n_opponents = max(1, n - 1)
        c_t = last_k / n_opponents
        past_rates = history.opponent_cooperators[:max(0, t - 1)] / n_opponents if t > 1 else np.array([], dtype=float)
        c_bar_t = float(np.mean(past_rates)) if len(past_rates) > 0 else c_t
        trend_t = c_t - c_bar_t if t > 2 else 0.0
        S_t = float(current_stock)
        if t == r - 1:
            self._punish_mode = False
            return Action.D
        if S_t <= 0.0:
            self._punish_mode = True
            self._punish_streak += 1
            self._cooperative_recovery_streak = 0
            return Action.D
        if S_t <= cap / (2.0 * n):
            self._punish_mode = True
            self._punish_streak += 1
            self._cooperative_recovery_streak = 0
            return Action.D
        if S_t < cap / 3.0 and c_t < 1.0:
            self._punish_mode = True
            self._punish_streak += 1
            self._cooperative_recovery_streak = 0
            return Action.D
        late_start = max(1, r - 1 - min(3, r - 1))
        if t >= late_start and c_t < 1.0:
            self._punish_mode = True
            self._punish_streak += 1
            self._cooperative_recovery_streak = 0
            return Action.D
        if self._punish_mode or c_t < 0.5:
            self._punish_mode = True
            self._punish_streak += 1
            if c_t >= 0.5:
                self._cooperative_recovery_streak += 1
            else:
                self._cooperative_recovery_streak = 0
            recovered = self._cooperative_recovery_streak >= 2 or (S_t >= cap / 2.0 and c_t > 0.5)
            if recovered:
                self._punish_mode = False
                self._punish_streak = 0
                self._cooperative_recovery_streak = 0
            else:
                return Action.D
        s_c = self._expected_next_stock(S_t, c_t, 1.0 / (2.0 * n))
        s_d = self._expected_next_stock(S_t, c_t, 1.0 / n)
        incentive = s_c - s_d
        cooperate = c_t >= 0.5 and S_t >= cap / 2.0 and (c_bar_t >= 0.5 or trend_t >= 0.0) and (incentive >= S_t / (2.0 * n))
        if abs(incentive - S_t / (2.0 * n)) <= 1e-12:
            return Action.C if c_t >= 1.0 else Action.D
        return Action.C if cooperate else Action.D

class Strategy_SELFINTERESTED_82(BaseStrategy):
    """
    Conservative common-pool strategy:
    - Cooperate on round 1.
    - Defect on the final round.
    - In between, cooperate only when stock is healthy and recent opponent cooperation
      is strong and sustained.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = int(history.round_number)
        n = max(2, self.n_players)
        threshold_low_stock = self.capacity / 3.0 if self.capacity > 0 else 0.0
        threshold_recover_stock = self.capacity / 2.0 if self.capacity > 0 else 0.0
        if t == 0:
            return Action.C
        if t >= self.n_rounds - 1:
            return Action.D
        opp = history.opponent_cooperators
        last1 = int(opp[-1]) if t >= 1 else 0
        last2 = int(opp[-2]) if t >= 2 else None
        recent_window = opp[max(0, t - 3):t]
        if len(recent_window) > 0:
            recent_avg = float(np.mean(recent_window))
        else:
            recent_avg = 0.0
        high_threshold = max(0, n - 2)
        all_coop_threshold = max(0, n - 1)
        if current_stock < threshold_low_stock:
            return Action.D
        if last2 is not None and last1 >= all_coop_threshold and (int(last2) >= all_coop_threshold):
            return Action.C
        if last1 >= high_threshold and recent_avg >= high_threshold and (current_stock >= threshold_recover_stock):
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_83(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Cooperates early to preserve the stock.
    - Tracks smoothed opponent cooperation and recent drops in cooperation.
    - Defects in the endgame, under low stock, or during retaliation cooldowns.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.m = 0.5
        self.prev_q = None
        self.cooldown_until_round = 0
        self._processed_rounds = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_players = self.game_description.n_players
        n_rounds = self.game_description.n_rounds
        round_number = history.round_number
        remaining_rounds = n_rounds - round_number
        capacity = float(self.game_description.capacity)
        x = 0.0 if capacity <= 0 else current_stock / capacity
        if round_number > self._processed_rounds:
            start = self._processed_rounds
            end = round_number
            n_opponents = max(n_players - 1, 1)
            for idx in range(start, end):
                q = float(history.opponent_cooperators[idx]) / float(n_opponents)
                if self.prev_q is not None:
                    if self.prev_q - q >= 0.25 and x < 0.85:
                        self.cooldown_until_round = max(self.cooldown_until_round, idx + 3)
                self.m = 0.65 * self.m + 0.35 * q
                self.prev_q = q
            self._processed_rounds = round_number
        if remaining_rounds <= 1:
            return Action.D
        if round_number == 0:
            return Action.C
        if x <= 0.15:
            return Action.D
        if round_number < self.cooldown_until_round and x < 0.85:
            return Action.D
        if x >= 0.8 and self.m >= 0.6 and (remaining_rounds > 1):
            return Action.C
        threshold = 0.42 + 0.3 * (1.0 - self.m) + 0.1 / max(remaining_rounds, 1) - 0.12 * x
        if x >= threshold and x >= 0.25 and (self.m >= 0.4):
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_84(BaseStrategy):
    """
    Common Pool Resource strategy with opening cooperation, endgame defection,
    and stock-aware cooperation conditioned on recent opponent behavior.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.high_stock = 0.7 * self.capacity
        self.low_stock = 0.35 * self.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = int(history.round_number) + 1
        n = self.n_players
        r = self.n_rounds
        S = float(current_stock)
        if S <= 0.0:
            return Action.D
        if t == 1:
            return Action.C
        if t == r:
            return Action.D
        if t == r - 1:
            return Action.D
        if history.opponent_cooperators.size == 0:
            return Action.C
        last_k = int(history.opponent_cooperators[-1])
        n_opponents = max(n - 1, 1)
        if n <= 2:
            coop_rate = 1.0 if last_k > 0 else 0.0
        else:
            coop_rate = last_k / n_opponents
        if S <= self.low_stock:
            if coop_rate >= 0.75:
                return Action.C
            return Action.D
        if S >= self.high_stock and coop_rate >= 0.5:
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_85(BaseStrategy):
    """
    Threshold-based common-pool strategy with short-term memory:
    - Cooperate on round 1.
    - Defect on the final round.
    - Use recent cooperation levels and stock thresholds to decide in between.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = max(2, int(game_description.n_players))
        self.r = max(2, int(game_description.n_rounds))
        self.capacity = float(game_description.capacity)
        self.low_coop_threshold = int(math.ceil((self.n - 1) / 3))
        self.high_coop_threshold = int(math.ceil((self.n - 1) / 2))
        self.low_stock_threshold = self.capacity / 6.0
        self.mid_stock_threshold = self.capacity / 3.0

    def _avg_last_two_cooperators(self, history: PlayerHistory) -> int:
        if history.round_number >= 2:
            last_two = history.opponent_cooperators[-2:]
            return int(math.floor(float(np.mean(last_two))))
        if history.round_number >= 1:
            return int(history.opponent_cooperators[-1])
        return 0

    def _last_two_low(self, history: PlayerHistory) -> bool:
        if history.round_number < 2:
            return False
        return history.opponent_cooperators[-1] < self.low_coop_threshold and history.opponent_cooperators[-2] < self.low_coop_threshold

    def _last_two_high(self, history: PlayerHistory) -> bool:
        if history.round_number < 2:
            return False
        return history.opponent_cooperators[-1] >= self.high_coop_threshold and history.opponent_cooperators[-2] >= self.high_coop_threshold

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        if round_number == 0:
            return Action.C
        if round_number >= self.r - 1:
            return Action.D
        stock = float(current_stock)
        q = self._avg_last_two_cooperators(history)
        if self._last_two_low(history):
            if stock <= self.low_stock_threshold:
                return Action.C if q >= self.low_coop_threshold else Action.D
            if history.opponent_cooperators[-1] >= self.high_coop_threshold:
                return Action.C
            return Action.D
        if self._last_two_high(history):
            if stock >= self.mid_stock_threshold:
                return Action.C
            return Action.D
        if stock <= self.low_stock_threshold:
            return Action.C if q >= self.low_coop_threshold else Action.D
        if q >= self.high_coop_threshold and stock >= self.mid_stock_threshold:
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_86(BaseStrategy):
    """
    State-based threshold strategy for the Common Pool Resource Game.

    Uses current stock and the previous round's opponent cooperation rate,
    with a short defensive lock after poor cooperation or low stock.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self._capacity = float(game_description.capacity)
        self._n = int(game_description.n_players)
        self._r = int(game_description.n_rounds)
        self._m = max(self._n - 1, 0)
        self._T = int(math.ceil(self._r / 5))
        self._defensive_lock_until_round = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number + 1
        cap = self._capacity
        if current_stock <= 0.0:
            return Action.D
        if history.round_number > 0 and self._m > 0:
            k_prev = int(history.opponent_cooperators[-1])
            c_prev = k_prev / self._m
        elif history.round_number > 0 and self._m == 0:
            c_prev = 0.0
        else:
            c_prev = None
        if history.round_number > 0:
            if current_stock < 0.5 * cap or (c_prev is not None and c_prev < 0.5):
                self._defensive_lock_until_round = max(self._defensive_lock_until_round, t + 1)
            elif current_stock >= 0.65 * cap and (c_prev is None or c_prev >= 0.5):
                self._defensive_lock_until_round = 0
        if t == self._r:
            return Action.D
        if t == self._r - 1:
            if current_stock >= 0.75 * cap and c_prev is not None and (c_prev >= 0.5):
                return Action.C
            return Action.D
        if t == 1:
            return Action.C if self._n == 2 else Action.D
        if t <= self._T:
            if c_prev is not None and c_prev >= 2.0 / 3.0:
                return Action.C
            return Action.D
        if self._defensive_lock_until_round >= t and current_stock < 0.65 * cap:
            return Action.D
        if current_stock < 0.5 * cap:
            return Action.D
        elif current_stock < 0.8 * cap:
            if c_prev is not None and c_prev >= 2.0 / 3.0:
                return Action.C
            return Action.D
        else:
            if c_prev is not None and c_prev >= 0.5:
                return Action.C
            return Action.D

class Strategy_SELFINTERESTED_87(BaseStrategy):
    """
    Adaptive trust-based strategy for the Common Pool Resource Game.

    Policy:
    - Starts by cooperating.
    - Updates an internal trust score from observed opponent cooperation.
    - Defects in the final round, under low stock, or after recent low cooperation.
    - Cooperates only when trust, stock, and endgame conditions are favorable.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.trust = 0.5
        self.last_c = None
        self._processed_rounds = 0
        self._low_cooperation_lock = False

    def _update_internal_state(self, history: PlayerHistory) -> None:
        total_rounds = history.round_number
        n_players = self.game_description.n_players
        n_opponents = max(n_players - 1, 0)
        while self._processed_rounds < total_rounds:
            idx = self._processed_rounds
            if n_opponents > 0:
                c = float(history.opponent_cooperators[idx]) / float(n_opponents)
            else:
                c = 0.0
            self.trust = 0.7 * self.trust + 0.3 * c
            self.last_c = c
            if c < 0.5:
                self._low_cooperation_lock = True
            elif c >= 0.75:
                self._low_cooperation_lock = False
            self._processed_rounds += 1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        self._update_internal_state(history)
        n_players = self.game_description.n_players
        n_rounds = self.game_description.n_rounds
        capacity = float(self.game_description.capacity)
        t = history.round_number + 1
        remaining_rounds = n_rounds - t + 1
        if history.round_number == 0:
            return Action.C
        if remaining_rounds == 1:
            return Action.D
        x = 0.0 if capacity <= 0 else float(current_stock) / capacity
        if current_stock <= capacity / float(max(2 * n_players, 1)):
            return Action.D
        if self._low_cooperation_lock:
            return Action.D
        if history.round_number >= 2:
            last1 = history.opponent_cooperators[-1]
            last2 = history.opponent_cooperators[-2]
            n_opponents = max(n_players - 1, 0)
            if n_opponents > 0:
                c1 = float(last1) / float(n_opponents)
                c2 = float(last2) / float(n_opponents)
            else:
                c1 = 0.0
                c2 = 0.0
            if c1 == 1.0 and c2 == 1.0 and (x >= 0.4):
                return Action.C
        if self.trust >= 0.65 and x >= 0.25:
            if remaining_rounds > 2 or (remaining_rounds == 2 and self.trust >= 0.8):
                return Action.C
        return Action.D

class Strategy_SELFINTERESTED_88(BaseStrategy):
    """
    Conditional cooperation strategy for the Common Pool Resource Game:
    - Cooperate in round 1.
    - In intermediate rounds, cooperate only when recent opponent cooperation
      is high and the stock remains healthy.
    - Defect in the last round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(self.n_players - 1, 1)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        if round_number == 0:
            return Action.C
        if round_number >= self.n_rounds - 1:
            return Action.D
        if current_stock <= 0.0:
            return Action.D
        if history.opponent_cooperators is None or len(history.opponent_cooperators) == 0:
            return Action.D
        if round_number > len(history.opponent_cooperators):
            return Action.D
        prev_opp_count = float(history.opponent_cooperators[-1])
        q = prev_opp_count / float(self.n_opponents)
        available = min(3, len(history.opponent_cooperators))
        if available <= 0:
            return Action.D
        recent = history.opponent_cooperators[-available:].astype(float) / float(self.n_opponents)
        m = float(np.mean(recent)) if available > 0 else 0.0
        support = max(q, m)
        cap = self.capacity
        if current_stock <= cap / 4.0:
            return Action.D
        elif support >= 3.0 / 4.0 and current_stock >= cap / 2.0:
            return Action.C
        elif support >= 2.0 / 3.0 and current_stock >= 3.0 * cap / 5.0:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_89(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Cooperates initially.
    - Defects when the stock is exhausted or the game is near its end.
    - Cooperates when the stock is under pressure.
    - Defects when recent opponent cooperation is high and the stock is healthy.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(self.n_players - 1, 1)
        self._weights = (1.0, 2.0, 4.0)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        stock = float(current_stock)
        if round_number == 0:
            return Action.C
        if stock <= 0.0:
            return Action.D
        if round_number >= self.n_rounds - 1:
            return Action.D
        if stock <= self.capacity / 3.0:
            return Action.C
        history_len = round_number
        use_len = 3 if history_len >= 3 else history_len
        if use_len <= 0:
            q = 0.0
        else:
            recent = history.opponent_cooperators[-use_len:]
            weights = self._weights[:use_len]
            weighted_sum = 0.0
            total_weight = 0.0
            for w, c in zip(weights, recent):
                weighted_sum += float(w) * float(c)
                total_weight += float(w)
            denom = self.n_opponents * total_weight
            q = weighted_sum / denom if denom > 0.0 else 0.0
        if q >= 2.0 / 3.0 and stock >= self.capacity / 2.0:
            return Action.D
        return Action.C

class Strategy_SELFINTERESTED_90(BaseStrategy):
    """
    Conditional cooperation strategy for the common pool resource game.

    - Cooperates in the first round.
    - Defects in the final round.
    - In between, cooperates only when stock is high and previous opponent
      cooperation was near-unanimous; otherwise defects.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(getattr(game_description, 'n_players', 0) or 0)
        self.n_rounds = int(getattr(game_description, 'n_rounds', 0) or 0)
        self.capacity = float(getattr(game_description, 'capacity', 0) or 0.0)
        self.low_stock_threshold = 0.35 * self.capacity
        self.high_stock_threshold = 0.65 * self.capacity
        self.mid_stock_threshold = 0.5 * self.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(getattr(history, 'round_number', 0) or 0)
        if self.n_rounds > 0 and round_number >= self.n_rounds - 1:
            return Action.D
        if round_number == 0:
            return Action.C
        stock = float(current_stock)
        if not math.isfinite(stock):
            stock = 0.0
        prev_k = None
        try:
            opp = history.opponent_cooperators
            if len(opp) > 0:
                prev_k = int(opp[-1])
        except Exception:
            prev_k = None
        if prev_k is None:
            return Action.C if stock >= self.high_stock_threshold else Action.D
        n_opponents = max(self.n_players - 1, 0)
        if stock <= self.low_stock_threshold:
            if prev_k == n_opponents:
                return Action.C
            return Action.D
        if stock >= self.high_stock_threshold and prev_k >= max(self.n_players - 2, 0):
            return Action.C
        if prev_k == n_opponents and stock >= self.mid_stock_threshold:
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_91(BaseStrategy):
    """
    State-contingent threshold strategy with harvest/stabilize/exploit behavior.
    Tracks an exponentially weighted cooperation estimate and a defect-recovery mode.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self._E = 1.0
        self._mode = 'normal'
        self._last_seen_rounds = 0
        self._last_p = 1.0

    def _opponent_count(self) -> int:
        return max(0, self.game_description.n_players - 1)

    def _theta(self, stock: float) -> float:
        cap = float(self.game_description.capacity)
        if cap <= 0:
            return 1.0
        return 0.5 + stock / (2.0 * cap)

    def _update_from_history(self, history: PlayerHistory, current_stock: float) -> None:
        """
        Update internal belief state from any newly observed rounds.
        We only have aggregate opponent cooperation counts, so we use the
        most recent unseen round to update E and mode.
        """
        n_opp = self._opponent_count()
        if history.round_number <= self._last_seen_rounds:
            return
        start = self._last_seen_rounds
        for idx in range(start, history.round_number):
            k = int(history.opponent_cooperators[idx]) if idx < len(history.opponent_cooperators) else 0
            p = 0.0 if n_opp <= 0 else k / n_opp
            self._E = 0.5 * self._E + 0.5 * p
            self._last_p = p
        self._last_seen_rounds = history.round_number
        theta = self._theta(current_stock)
        if self._last_p < theta:
            self._mode = 'defect'
        elif self._E >= theta and current_stock >= float(self.game_description.capacity) / 3.0:
            self._mode = 'normal'

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_rounds = int(self.game_description.n_rounds)
        cap = float(self.game_description.capacity)
        self._update_from_history(history, current_stock)
        if history.round_number >= n_rounds - 1:
            return Action.D
        if current_stock <= 0.0 or current_stock <= cap / 6.0:
            self._mode = 'defect'
            return Action.D
        if history.round_number == 0:
            return Action.C
        theta = self._theta(current_stock)
        coop_threshold = cap / 3.0
        if len(history.opponent_cooperators) >= 2:
            n_opp = self._opponent_count()
            if n_opp > 0:
                last_two_all_coop = int(history.opponent_cooperators[-1]) == n_opp and int(history.opponent_cooperators[-2]) == n_opp
                if last_two_all_coop and current_stock >= coop_threshold:
                    self._mode = 'normal'
                    return Action.C
        if self._mode == 'defect':
            if self._E >= theta and current_stock >= coop_threshold:
                self._mode = 'normal'
                return Action.C
            return Action.D
        if current_stock >= coop_threshold and self._E >= theta:
            return Action.C
        self._mode = 'defect'
        return Action.D

class Strategy_SELFINTERESTED_92(BaseStrategy):
    """
    Stock-aware threshold strategy:
    - Cooperate in round 1.
    - Defect in the final round.
    - Otherwise cooperate when stock is low or when last-round cooperation was below half;
      defect only when stock is above one-third of capacity and cooperation was at least half.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self._half_players = self.n_players / 2.0
        self._capacity_third = self.capacity / 3.0 if self.capacity is not None else 0.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = int(history.round_number)
        if t == 0:
            return Action.C
        if t >= self.n_rounds - 1:
            return Action.D
        last_opponent_cooperators = 0
        if len(history.opponent_cooperators) > 0:
            last_opponent_cooperators = int(history.opponent_cooperators[-1])
        last_my_action_is_cooperate = False
        if len(history.my_actions) > 0:
            last_my_action_is_cooperate = bool(history.my_actions[-1])
        k = last_opponent_cooperators + (1 if last_my_action_is_cooperate else 0)
        s = float(current_stock)
        if s <= self._capacity_third:
            return Action.C
        if k < self._half_players:
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_93(BaseStrategy):
    """
    Trust- and stock-aware common-pool strategy:
    starts cooperatively, tracks opponent cooperation as a smoothed trust signal,
    defects in low-stock or low-trust situations, and re-enters cooperation only
    after sufficient trust and stock recovery.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(getattr(game_description, 'n_players', 0) or 0)
        self.r = int(getattr(game_description, 'n_rounds', 0) or 0)
        self.capacity = float(getattr(game_description, 'capacity', 0.0) or 0.0)
        self.safe = self.capacity / 3.0 if self.capacity > 0 else 0.0
        self.low = self.capacity / 6.0 if self.capacity > 0 else 0.0
        self.late_round_window = int(math.ceil(self.r / 4)) if self.r > 0 else 0
        self.trust = 1.0
        self.forced_defect_mode = False
        self._processed_rounds = 0

    def _update_trust_from_history(self, history: PlayerHistory) -> None:
        n_opponents = max(self.n - 1, 0)
        while self._processed_rounds < history.round_number:
            idx = self._processed_rounds
            k = int(history.opponent_cooperators[idx]) if idx < len(history.opponent_cooperators) else 0
            if n_opponents <= 0:
                rho = 1.0
            elif self.n == 2:
                rho = 1.0 if k > 0 else 0.0
            else:
                rho = k / n_opponents
            self.trust = 0.75 * self.trust + 0.25 * rho
            self._processed_rounds += 1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        if round_number <= 0:
            return Action.C
        self._update_trust_from_history(history)
        next_round = round_number + 1
        last_round = next_round >= self.r
        in_late_window = self.late_round_window > 0 and next_round > self.r - self.late_round_window
        last_k = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        n_opponents = max(self.n - 1, 0)
        if n_opponents <= 0:
            rho = 1.0
            all_cooperated = True
            none_cooperated = False
        elif self.n == 2:
            rho = 1.0 if last_k > 0 else 0.0
            all_cooperated = last_k >= 1
            none_cooperated = last_k <= 0
        else:
            rho = last_k / n_opponents
            all_cooperated = last_k >= n_opponents
            none_cooperated = last_k <= 0
        effective_trust = self.trust
        coop_threshold_low = 0.8
        coop_threshold_high = 0.6
        if in_late_window and effective_trust >= 0.9:
            coop_threshold_low += 0.1
            coop_threshold_high += 0.1
        if self.forced_defect_mode:
            if current_stock >= self.safe and effective_trust >= 0.7 and (not last_round):
                self.forced_defect_mode = False
            else:
                return Action.D
        if last_round:
            self.forced_defect_mode = True
            return Action.D
        if all_cooperated:
            return Action.C
        if none_cooperated and (not (current_stock >= self.safe and effective_trust >= 0.7)):
            self.forced_defect_mode = True
            return Action.D
        if current_stock <= self.low:
            self.forced_defect_mode = True
            return Action.D
        if current_stock < self.safe:
            if effective_trust >= coop_threshold_low:
                return Action.C
            self.forced_defect_mode = True
            return Action.D
        if effective_trust >= coop_threshold_high:
            return Action.C
        self.forced_defect_mode = True
        return Action.D

class Strategy_SELFINTERESTED_94(BaseStrategy):
    """
    Stateful threshold strategy with one-step punishment:
    - Start by cooperating.
    - Update a trust score from the previous round's cooperation and stock trend.
    - Cooperate only when trust is positive, recent cooperation was sufficiently high,
      stock is healthy, and it is not the final round.
    - Defect otherwise.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.last_stock = float(game_description.capacity)
        self.trust = 0
        self.prev_coop_rate = 0.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        last_round_index = self.game_description.n_rounds - 1
        t = history.round_number
        if t == 0:
            return Action.C
        k = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        if n > 2:
            coop_rate = k / max(1, n - 1)
        else:
            coop_rate = float(k)
        if coop_rate >= 2.0 / 3.0 and current_stock >= self.last_stock:
            self.trust = min(2, self.trust + 1)
        else:
            self.trust = max(-2, self.trust - 1)
        self.prev_coop_rate = coop_rate
        self.last_stock = float(current_stock)
        if t >= last_round_index:
            return Action.D
        if current_stock <= self.game_description.capacity / 4.0:
            return Action.D
        if self.trust >= 1 and self.prev_coop_rate >= 0.5:
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_95(BaseStrategy):
    """
    Common pool strategy:
    - Cooperate in round 1.
    - Adapt to current stock level, opponent cooperation rate, and the last two observed cooperation rates.
    - Bias toward cooperation when the pool is healthy and opponents are sufficiently cooperative;
      otherwise defect, especially near the end of the game.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        n = self.n_players
        r = self.n_rounds
        S = float(current_stock)
        n_opponents = max(n - 1, 0)
        last_k = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        p = last_k / n_opponents if n_opponents > 0 else 0.0
        m = r - history.round_number
        last_two_p = []
        if len(history.opponent_cooperators) >= 2:
            prev_k = int(history.opponent_cooperators[-2])
            prev_p = prev_k / n_opponents if n_opponents > 0 else 0.0
            last_two_p = [prev_p, p]
        safe_threshold = 0.75 * self.capacity
        warning_threshold = 0.4 * self.capacity
        if m <= 1:
            action = Action.D if S > 0 else Action.C
        elif m == 2:
            if S < safe_threshold and p >= 0.5:
                action = Action.C
            else:
                action = Action.D
        elif S >= safe_threshold:
            action = Action.C if p >= 0.5 else Action.D
        elif S >= warning_threshold:
            action = Action.C if p >= 0.75 else Action.D
        else:
            action = Action.C if p >= 1.0 else Action.D
        if len(last_two_p) == 2 and last_two_p[0] == 1 and (last_two_p[1] == 1) and (S >= warning_threshold):
            action = Action.C
        elif len(last_two_p) == 2 and last_two_p[0] == 0 and (last_two_p[1] == 0) and (p == 0):
            action = Action.D
        return action

class Strategy_SELFINTERESTED_96(BaseStrategy):
    """
    Probe with cooperation early, reward only broad cooperation while stock is healthy,
    and defect by default near the end or when cooperation/trust is weak.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.trust = 1
        self.consecutive_high_coop = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = float(self.game_description.capacity)
        round_number = history.round_number
        current_round = round_number + 1
        if current_round >= r:
            return Action.D
        if round_number == 0:
            return Action.C
        opp_coop = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        n_opponents = max(n - 1, 0)
        coop_rate = opp_coop / n_opponents if n_opponents > 0 else 0.0
        high_cooperation = coop_rate >= 0.5
        very_high_cooperation = coop_rate >= 0.75
        stock_healthy = current_stock >= capacity / 2.0
        stock_strained = current_stock < capacity / 3.0
        last_my_action = bool(history.my_actions[-1]) if len(history.my_actions) > 0 else False
        if last_my_action and (not high_cooperation):
            self.trust = 0
        if very_high_cooperation:
            self.consecutive_high_coop += 1
            if self.consecutive_high_coop >= 2:
                self.trust = 1
        else:
            self.consecutive_high_coop = 0
        if stock_strained or not stock_healthy:
            return Action.D
        if current_round > r - 2:
            return Action.D
        if self.trust == 0 and self.consecutive_high_coop < 2:
            return Action.D
        if high_cooperation and stock_healthy and (current_round <= r - 2):
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_97(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Starts cooperatively.
    - Tracks opponent cooperation with an exponentially weighted score p.
    - Defects late, when the pool is weak, or when cooperation/stock conditions deteriorate.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.p = 1.0
        self._prev_stock = None

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = float(self.game_description.capacity)
        round_number = history.round_number
        if round_number > 0:
            opp_count = int(history.opponent_cooperators[-1])
            n_opponents = max(1, n - 1)
            observed_coop_rate = opp_count / n_opponents
            self.p = 0.6 * self.p + 0.4 * observed_coop_rate
        stock_fell = False
        if self._prev_stock is not None:
            stock_fell = current_stock < self._prev_stock
        if round_number == r - 1:
            action = Action.D
        elif current_stock <= capacity / 4.0:
            action = Action.D
        elif round_number == 0:
            action = Action.C
        elif self.p >= 0.75 and current_stock >= capacity / 3.0:
            action = Action.C
        elif self.p >= 0.6 and current_stock >= capacity / 2.0 and (not stock_fell):
            action = Action.C
        else:
            action = Action.D
        self._prev_stock = float(current_stock)
        return action

class Strategy_SELFINTERESTED_98(BaseStrategy):
    """
    Common pool strategy:
    - Start with cooperation.
    - Defect in the last round or under low stock/low observed cooperation.
    - Cooperate under strong stock/cooperation conditions.
    - Otherwise use a middle rule.
    - Track a simple punishment mode after sharp cooperation drops.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.in_punishment_mode = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        if round_number == 0:
            self.in_punishment_mode = False
            return Action.C
        n_opponents = self.n_players - 1
        if n_opponents <= 0:
            return Action.D
        if len(history.opponent_cooperators) < 1:
            return Action.D
        last_coop_count = int(history.opponent_cooperators[-1])
        c = last_coop_count / n_opponents
        s = 0.0 if self.capacity <= 0 else float(current_stock) / float(self.capacity)
        if round_number >= self.n_rounds - 1:
            self.in_punishment_mode = False
            return Action.D
        if len(history.opponent_cooperators) >= 2:
            prev_coop_count = int(history.opponent_cooperators[-2])
            prev_c = prev_coop_count / n_opponents
            if prev_c - c >= 0.25 and c < 0.75:
                self.in_punishment_mode = True
        if self.in_punishment_mode:
            if c >= 0.75 and s >= 0.5:
                self.in_punishment_mode = False
            else:
                return Action.D
        if s <= 0.25 or c <= 0.4:
            return Action.D
        if s >= 0.6 and c >= 0.75:
            return Action.C
        if c >= 0.5 and s >= 0.4:
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_99(BaseStrategy):
    """
    Threshold-based common-pool strategy with shock response, endgame caution,
    and simple persistence rules based on observed opponent cooperation.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(self.n_players - 1, 0)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        cap = self.capacity
        n_rounds = self.n_rounds
        m = self.n_opponents
        if round_number == 0:
            return Action.C
        last_k = int(history.opponent_cooperators[-1]) if round_number >= 1 else 0
        last_c = last_k / m if m > 0 else 0.0
        prev_c = None
        if round_number >= 2:
            prev_k = int(history.opponent_cooperators[-2])
            prev_c = prev_k / m if m > 0 else 0.0
        two_recent_below_half = round_number >= 2 and prev_c is not None and (prev_c < 0.5) and (last_c < 0.5)
        two_recent_at_least_75 = round_number >= 2 and prev_c is not None and (prev_c >= 0.75) and (last_c >= 0.75)
        if round_number >= max(n_rounds - 2, 1):
            if cap > 0.0 and current_stock >= 0.9 * cap and (last_c >= 0.5):
                return Action.C
            return Action.D
        if cap > 0.0 and current_stock <= cap / 4.0:
            return Action.D
        if two_recent_below_half or last_c < 0.5:
            return Action.D
        if cap > 0.0 and current_stock >= 0.75 * cap and (last_c >= 0.5):
            return Action.C
        if two_recent_at_least_75 and current_stock >= 0.5 * cap:
            return Action.C
        tau = 0.5 + 0.25 * (current_stock / cap) if cap > 0.0 else 0.5
        if last_c >= tau:
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_100(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Opens with defection.
    - Defends the pool when stock is low.
    - Uses recent opponent cooperation to switch between cooperation and defection.
    - Forces defection in the penultimate and final rounds per specification.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self._low_stock_threshold = self.capacity / 3.0
        self._high_stock_threshold = self.capacity / 2.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        next_round = round_number + 1
        if round_number == 0:
            return Action.D
        if next_round >= self.n_rounds:
            return Action.D
        if next_round == self.n_rounds - 1:
            if round_number >= 1 and len(history.opponent_cooperators) >= 1:
                prev_coop_count = int(history.opponent_cooperators[-1])
                n_opponents = max(self.n_players - 1, 1)
                coop_rate = prev_coop_count / n_opponents
            else:
                coop_rate = 1.0
            if current_stock <= self._high_stock_threshold and coop_rate < 0.5:
                return Action.C
            return Action.D
        if current_stock <= self._low_stock_threshold:
            return Action.C
        if current_stock >= self._high_stock_threshold:
            return Action.D
        n_opponents = max(self.n_players - 1, 1)
        if len(history.opponent_cooperators) >= 1:
            c_prev = int(history.opponent_cooperators[-1])
            coop_rate = c_prev / n_opponents
        else:
            coop_rate = 1.0
        sharp_up = False
        sharp_down = False
        if len(history.opponent_cooperators) >= 2:
            c_last = int(history.opponent_cooperators[-1])
            c_prev = int(history.opponent_cooperators[-2])
            delta = c_last - c_prev
            jump_threshold = max(2, int(math.ceil(n_opponents / 3.0)))
            sharp_up = delta >= jump_threshold
            sharp_down = -delta >= jump_threshold
        if sharp_up and current_stock >= self._high_stock_threshold:
            return Action.D
        if sharp_down and self._low_stock_threshold < current_stock < self._high_stock_threshold:
            return Action.C
        if coop_rate >= 0.5:
            return Action.D
        return Action.C

class Strategy_SELFINTERESTED_101(BaseStrategy):
    """
    Common-pool strategy with stock thresholds, opponent cooperation tracking,
    and internal modes: balanced, protect, exploit.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.L = self.capacity / 3.0
        self.M = self.capacity / 2.0
        self.H = 2.0 * self.capacity / 3.0
        self.mode = 'balanced'

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        stock = float(current_stock)
        if stock <= 0.0:
            return Action.D
        if round_number == 0:
            if self.r == 2:
                return Action.D
            if stock >= self.H:
                return Action.C
            return Action.D
        last_c = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        n_opponents = max(self.n - 1, 1)
        rho = last_c / n_opponents
        last_two_low = False
        if len(history.opponent_cooperators) >= 2:
            prev_c = int(history.opponent_cooperators[-2])
            prev_rho = prev_c / n_opponents
            last_two_low = prev_rho <= 1.0 / 3.0 and rho <= 1.0 / 3.0
        if round_number >= self.r - 1:
            self.mode = 'protect' if rho <= 1.0 / 3.0 or stock <= self.L else self.mode
            return Action.D
        if last_two_low:
            self.mode = 'protect'
            if not (rho >= 2.0 / 3.0 and stock > self.L):
                return Action.D
        if self.mode in ('exploit', 'protect'):
            if rho >= 2.0 / 3.0 and stock > self.H and (self.mode == 'exploit'):
                return Action.D
            if self.mode == 'protect':
                if rho >= 2.0 / 3.0 and stock > self.L:
                    pass
                else:
                    return Action.D
        if stock <= self.L:
            self.mode = 'protect'
            return Action.D
        if rho >= 2.0 / 3.0:
            if stock >= self.H:
                self.mode = 'exploit'
                return Action.D
            self.mode = 'balanced'
            return Action.C
        if rho <= 1.0 / 3.0:
            self.mode = 'protect'
            return Action.D
        if stock >= self.M and round_number <= math.floor(self.r / 2):
            self.mode = 'exploit'
            return Action.D
        self.mode = 'balanced'
        return Action.C

class Strategy_SELFINTERESTED_102(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Opens with cooperation except in 2-round games, where it defects immediately.
    - Cooperates in low-stock danger zones.
    - Defects in high-stock regions or when recent cooperation is weak.
    - Uses only the immediately previous round's cooperation count and the observed stock trend.
    - Always defects in the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self._previous_stock = None
        self._previous_round_number = None

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = int(self.game_description.n_players)
        r = int(self.game_description.n_rounds)
        capacity = float(self.game_description.capacity)
        round_number = int(history.round_number)
        current_turn = round_number + 1
        prev_stock = self._previous_stock
        fell = False
        rose = False
        if prev_stock is not None:
            eps = 1e-12
            fell = current_stock < prev_stock - eps
            rose = current_stock > prev_stock + eps
        if current_turn >= r:
            self._previous_stock = current_stock
            self._previous_round_number = round_number
            return Action.D
        if round_number == 0:
            action = Action.D if r == 2 else Action.C
            self._previous_stock = current_stock
            self._previous_round_number = round_number
            return action
        k = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        threshold = (n - 1) / 2.0
        low_region = capacity / 3.0
        high_region = 2.0 * capacity / 3.0
        mid_region = capacity / 2.0
        if current_stock <= low_region:
            action = Action.C
        elif current_stock >= high_region:
            action = Action.D
        else:
            is_tie = abs(k - threshold) <= 1e-12
            if is_tie:
                action = Action.C if current_stock <= mid_region else Action.D
            elif fell and k < threshold:
                action = Action.D
            elif rose and k >= threshold:
                action = Action.C
            else:
                action = Action.C if k >= threshold else Action.D
        self._previous_stock = current_stock
        self._previous_round_number = round_number
        return action

class Strategy_SELFINTERESTED_103(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Opens with cooperation.
    - Defects in the terminal round.
    - Uses opponent cooperation rate and stock level to decide.
    - Tracks short escalation windows for sustained high/low cooperation.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self._processed_rounds = 0
        self._forced_coop_remaining = 0
        self._forced_defect_remaining = 0
        self._last_obs_rate = None

    def _sync_state(self, history: PlayerHistory) -> None:
        target = history.round_number
        if target <= self._processed_rounds:
            return
        n_rounds = self.game_description.n_rounds
        n_opponents = max(self.game_description.n_players - 1, 0)
        for idx in range(self._processed_rounds, target):
            if idx < 0 or idx >= len(history.opponent_cooperators):
                continue
            obs = history.opponent_cooperators[idx]
            if obs is None or n_opponents <= 0:
                self._last_obs_rate = None
                continue
            rate = float(obs) / float(n_opponents)
            self._last_obs_rate = rate
            if rate >= 2.0 / 3.0:
                self._forced_coop_remaining = 2
                self._forced_defect_remaining = 0
            elif rate < 1.0 / 3.0:
                self._forced_defect_remaining = 2
                self._forced_coop_remaining = 0
            if self._forced_coop_remaining > 0:
                self._forced_coop_remaining -= 1
            if self._forced_defect_remaining > 0:
                self._forced_defect_remaining -= 1
            if idx >= n_rounds - 1:
                self._forced_coop_remaining = 0
                self._forced_defect_remaining = 0
        self._processed_rounds = target

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        self._sync_state(history)
        n_rounds = self.game_description.n_rounds
        capacity = float(self.game_description.capacity) if self.game_description.capacity else 1.0
        s = float(current_stock) / capacity if capacity > 0 else 0.0
        if history.round_number >= n_rounds - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        if len(history.opponent_cooperators) == 0:
            return Action.D
        last_obs = history.opponent_cooperators[-1]
        n_opponents = self.game_description.n_players - 1
        if last_obs is None or n_opponents <= 0:
            return Action.D
        x = float(last_obs) / float(n_opponents)
        if s <= 0.25:
            return Action.D
        if self._forced_coop_remaining > 0:
            return Action.C
        if self._forced_defect_remaining > 0:
            return Action.D
        if s >= 0.75 and x >= 0.5:
            return Action.C
        if x > 0.5:
            coop_signal = True
        elif abs(x - 0.5) <= 1e-12:
            coop_signal = s >= 0.5
        else:
            coop_signal = False
        if coop_signal and s >= 1.0 / 3.0:
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_104(BaseStrategy):
    """
    Cooperative when the pool is healthy and the group is nearly fully cooperative;
    defects on the last round, when stock is depleted, or after repeated weak cooperation.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(self.n_players - 1, 0)
        self.all_but_one_threshold = max(self.n_players - 2, 0)
        self.low_stock_lock = False
        self.weak_cooperation_lock = False
        self.consecutive_weak_rounds = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        if round_number == 0:
            return Action.C
        if round_number >= self.n_rounds - 1:
            return Action.D
        last_k = int(history.opponent_cooperators[-1]) if round_number > 0 else 0
        if last_k <= self.n_players - 3:
            self.consecutive_weak_rounds += 1
        else:
            self.consecutive_weak_rounds = 0
        if self.consecutive_weak_rounds >= 2:
            self.weak_cooperation_lock = True
        if current_stock < self.capacity / 4.0:
            self.low_stock_lock = True
        elif self.low_stock_lock:
            if current_stock >= self.capacity / 2.0 and last_k >= self.all_but_one_threshold:
                self.low_stock_lock = False
        if self.weak_cooperation_lock and last_k >= self.all_but_one_threshold:
            self.weak_cooperation_lock = False
        if self.low_stock_lock or self.weak_cooperation_lock:
            return Action.D
        if current_stock >= self.capacity / 2.0 and last_k >= self.all_but_one_threshold:
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_105(BaseStrategy):
    """
    Adaptive common-pool strategy with trust tracking and punish/open modes.
    Cooperates initially, reacts to observed cooperation levels, and defects
    under low trust, low stock, punishment mode, or near the final rounds.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.trust = 1.0
        self.mode = 'open'
        self._high_q_streak = 0
        self._last_processed_round = 0

    def _effective_stock(self, stock: float) -> float:
        capacity = float(self.game_description.capacity)
        if stock >= capacity:
            return capacity
        if stock < 0.0:
            return 0.0
        return stock

    def _process_new_history(self, history: PlayerHistory, current_stock: float) -> None:
        n_players = self.game_description.n_players
        n_opponents = max(0, n_players - 1)
        start = self._last_processed_round
        end = history.round_number
        if end <= start:
            return
        for t in range(start, end):
            coop_count = int(history.opponent_cooperators[t]) if t < len(history.opponent_cooperators) else 0
            if n_opponents > 0:
                q = coop_count / n_opponents
            else:
                q = 0.0
            self.trust = 0.7 * self.trust + 0.3 * q
            if q == 1.0:
                self.trust = min(1.0, self.trust + 0.1)
            if q == 0.0:
                self.mode = 'punish'
                self._high_q_streak = 0
            elif q < 0.4:
                self.mode = 'punish'
                self._high_q_streak = 0
            elif q >= 0.6:
                self._high_q_streak += 1
                if self._high_q_streak >= 2 and self._effective_stock(current_stock) >= 0.5 * float(self.game_description.capacity):
                    self.mode = 'open'
            else:
                self._high_q_streak = 0
        self._last_processed_round = end

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_rounds = self.game_description.n_rounds
        round_number = history.round_number
        stock = self._effective_stock(current_stock)
        self._process_new_history(history, stock)
        if round_number == 0:
            return Action.C
        if stock <= 0.0:
            return Action.D
        if round_number == n_rounds - 1 or round_number == n_rounds - 2:
            return Action.D
        if stock < 0.35 * float(self.game_description.capacity):
            return Action.D
        if self.mode == 'punish':
            return Action.D
        if self.trust >= 0.55 and stock >= 0.6 * float(self.game_description.capacity):
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_106(BaseStrategy):
    """
    Conditional common-pool strategy:
    - Cooperate first round.
    - Defect on the final round.
    - Otherwise adapt to remaining rounds, current stock, and recent opponent cooperation.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.last_m = 0
        self.prev_m = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.n
        r = self.r
        capacity = self.capacity
        round_number = int(history.round_number)
        rounds_remaining = r - round_number
        if rounds_remaining <= 1:
            if round_number > 0 and len(history.opponent_cooperators) > 0:
                self.prev_m = self.last_m
                self.last_m = int(history.opponent_cooperators[-1])
            else:
                self.prev_m = self.last_m
                self.last_m = 0
            return Action.D
        if round_number == 0:
            return Action.C
        if len(history.opponent_cooperators) > 0:
            m = int(history.opponent_cooperators[-1])
        else:
            m = 0
        self.prev_m = self.last_m
        self.last_m = m
        stock = float(current_stock)

        def consecutive_full_cooperation() -> bool:
            return self.last_m == n - 1 and self.prev_m == n - 1
        if rounds_remaining == 2:
            if stock <= capacity / 3.0 and m == n - 1:
                return Action.C
            return Action.D
        if stock <= capacity / 4.0:
            return Action.C if m == n - 1 else Action.D
        if stock <= capacity / 2.0:
            return Action.C if m >= n - 2 else Action.D
        if stock <= 3.0 * capacity / 4.0:
            threshold = math.ceil((n - 1) / 2.0)
            return Action.C if m >= threshold else Action.D
        return Action.C if consecutive_full_cooperation() else Action.D

class Strategy_SELFINTERESTED_107(BaseStrategy):
    """
    Trust-based common-pool strategy:
    - Start by cooperating.
    - Defect in the last round or when stock is low.
    - Track opponent cooperation with an exponentially smoothed trust score.
    - Resume cooperation only when trust and stock recover sufficiently.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.initial_trust = 1.0

    def _compute_trust(self, history: PlayerHistory) -> float:
        """
        Reconstruct trust from the observed history.
        Trust starts at 1 and is updated after each completed round:
        T <- 0.6*T + 0.4*f_t
        where f_t is the fraction of opponents who cooperated in round t.
        """
        T = self.initial_trust
        n_opponents = max(self.n_players - 1, 1)
        for c in history.opponent_cooperators:
            coop_count = int(c) if c is not None else 0
            if coop_count < 0:
                coop_count = 0
            if coop_count > n_opponents:
                coop_count = n_opponents
            f_t = coop_count / n_opponents
            if not math.isfinite(f_t):
                f_t = 0.0
            T = 0.6 * T + 0.4 * f_t
        return T

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = int(history.round_number)
        n_opponents = max(self.n_players - 1, 1)
        if t == 0:
            return Action.C
        if t >= self.n_rounds - 1:
            return Action.D
        T = self._compute_trust(history)
        S = float(current_stock)
        if not math.isfinite(S):
            S = 0.0
        coop_count_prev = 0
        if len(history.opponent_cooperators) > 0:
            coop_count_prev = int(history.opponent_cooperators[-1])
            if coop_count_prev < 0:
                coop_count_prev = 0
            if coop_count_prev > n_opponents:
                coop_count_prev = n_opponents
        majority_threshold = math.ceil(n_opponents / 2)
        high_stock = S >= 0.75 * self.capacity
        medium_stock = S >= 0.6 * self.capacity
        low_stock = S <= 0.45 * self.capacity
        if coop_count_prev < majority_threshold:
            if not (T >= 2.0 / 3.0 and high_stock):
                return Action.D
            return Action.C
        if low_stock:
            return Action.D
        if T >= 2.0 / 3.0 and high_stock:
            return Action.C
        if T >= 0.5 and medium_stock and (coop_count_prev >= majority_threshold):
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_108(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Cooperates first round.
    - Defects on the final round.
    - In between, conditions cooperation on current stock and the most recent
      observed opponent cooperation rate.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(self.n_players - 1, 0)
        self.last_observed_q = 0.0
        self.last_seen_stock = self.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        self.last_seen_stock = float(current_stock)
        round_number = history.round_number
        if round_number == 0:
            return Action.C
        if round_number > 0 and len(history.opponent_cooperators) > 0 and (self.n_opponents > 0):
            last_opp_coops = int(history.opponent_cooperators[-1])
            self.last_observed_q = max(0.0, min(1.0, last_opp_coops / self.n_opponents))
        else:
            self.last_observed_q = 0.0
        q = self.last_observed_q
        s = self.last_seen_stock
        cap = self.capacity
        if round_number >= self.n_rounds - 1:
            return Action.D
        if s <= 0.5 * cap:
            return Action.C if q >= 2.0 / 3.0 else Action.D
        if s <= 0.85 * cap:
            return Action.C if q >= 0.5 else Action.D
        if q == 1.0:
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_109(BaseStrategy):
    """
    Three-mode common-pool strategy:
    - Cooperate on the first round.
    - Match observed restraint and protect the stock when depleted.
    - Defect in the final round.
    - Apply short punishment after sharp cooperation drops.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self._prev_rho = None
        self._punishment_remaining = 0
        self._last_processed_round = -1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_players = self.game_description.n_players
        n_opponents = max(n_players - 1, 1)
        capacity = float(self.game_description.capacity)
        n_rounds = self.game_description.n_rounds
        round_number = history.round_number
        if round_number <= 0:
            self._prev_rho = None
            self._punishment_remaining = 0
            self._last_processed_round = round_number
            return Action.C
        if round_number >= n_rounds - 1:
            self._last_processed_round = round_number
            return Action.D
        last_cooperators = int(history.opponent_cooperators[-1])
        last_cooperators = max(0, min(last_cooperators, n_opponents))
        rho_prev = last_cooperators / n_opponents if n_opponents > 0 else 0.0
        if self._prev_rho is not None:
            if rho_prev <= self._prev_rho - 0.25:
                self._punishment_remaining = 2
        action = Action.D
        if self._punishment_remaining > 0:
            if rho_prev >= 0.5:
                self._punishment_remaining = 0
            else:
                self._punishment_remaining -= 1
                self._prev_rho = rho_prev
                self._last_processed_round = round_number
                return Action.D
        if current_stock <= capacity / 3.0:
            action = Action.D
        elif rho_prev >= 0.5:
            action = Action.C
        elif rho_prev >= 1.0 / 3.0 and current_stock >= capacity / 2.0:
            action = Action.C
        else:
            action = Action.D
        if action == Action.C and rho_prev < 1.0 / 3.0:
            action = Action.D
        self._prev_rho = rho_prev
        self._last_processed_round = round_number
        return action

class Strategy_SELFINTERESTED_110(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - cooperates when opponent cooperation is at least moderate and stock is healthy
    - defects under low cooperation, low stock, or near the end unless trust is high
    - responds persistently to two consecutive low-cooperation observations
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.high_trust = 2.0 / 3.0
        self.medium_trust = 1.0 / 2.0
        self.low_stock = self.capacity / 4.0
        self.safe_stock = self.capacity / 2.0
        self.final_rounds = min(3, max(self.r - 1, 0))

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number
        S_t = float(current_stock)
        if t == 0:
            return Action.C if S_t >= self.safe_stock else Action.D
        n_opponents = max(self.n - 1, 1)
        last_k = int(history.opponent_cooperators[-1])
        rho_t = last_k / n_opponents
        if history.round_number >= 2:
            prev_k = int(history.opponent_cooperators[-2])
            prev_rho = prev_k / n_opponents
            if prev_rho < self.medium_trust and rho_t < self.medium_trust:
                return Action.D
        if self.final_rounds > 0 and t >= self.r - self.final_rounds:
            return Action.C if rho_t >= self.high_trust and S_t >= self.safe_stock else Action.D
        cons_others = last_k * (S_t / (2.0 * self.n)) + (self.n - 1 - last_k) * (S_t / self.n)
        s_rem_c = S_t - cons_others - S_t / (2.0 * self.n)
        s_next_c = min(s_rem_c + 2.0 * s_rem_c * (1.0 - s_rem_c / self.capacity), self.capacity)
        s_rem_d = S_t - cons_others - S_t / self.n
        s_next_d = min(s_rem_d + 2.0 * s_rem_d * (1.0 - s_rem_d / self.capacity), self.capacity)
        if rho_t >= self.medium_trust and S_t >= self.low_stock and (s_next_c >= self.safe_stock or s_next_c >= s_next_d):
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_111(BaseStrategy):
    """
    Start cooperatively, then continue cooperating only under sustained near-universal
    cooperation and sufficiently healthy stock. Defect immediately after weak or unstable
    cooperation, and always defect in the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.opponent_count = max(0, self.n_players - 1)
        self.coop_threshold = max(0, self.n_players - 2)
        self.full_coop_threshold = max(0, self.n_players - 1)

    def _strong_cooperation(self, o1, o2) -> bool:
        """
        True if the immediately previous round was fully cooperative among opponents,
        and the round before that too if available.
        """
        if o1 is None or o1 < self.full_coop_threshold:
            return False
        if o2 is not None and o2 < self.full_coop_threshold:
            return False
        return True

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        if round_number == 0:
            return Action.C
        o1 = int(history.opponent_cooperators[-1]) if round_number >= 1 else None
        o2 = int(history.opponent_cooperators[-2]) if round_number >= 2 else None
        current_round_index = round_number
        last_round_index = self.n_rounds - 1
        penultimate_round_index = self.n_rounds - 2
        if current_stock <= self.capacity / 6.0:
            return Action.C if self._strong_cooperation(o1, o2) else Action.D
        if current_stock <= self.capacity / 3.0:
            return Action.C if self._strong_cooperation(o1, o2) else Action.D
        if current_round_index == last_round_index:
            return Action.D
        if current_round_index == penultimate_round_index:
            if o1 is None or o1 < self.full_coop_threshold or current_stock < self.capacity / 2.0:
                return Action.D
        if o1 is None or o1 < self.coop_threshold:
            return Action.D
        if o2 is not None and o2 < self.coop_threshold:
            return Action.D
        return Action.C

class Strategy_SELFINTERESTED_112(BaseStrategy):
    """
    Cooperative-until-breakdown strategy with stock-sensitive tightening.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(0, self.n_players - 1)
        self.full_threshold = self.n_opponents
        self.tolerance = 0 if self.n_players <= 3 else 1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number
        if t == 0:
            return Action.C
        opp_cooperators = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        current_stock = float(current_stock)
        critical_stock = current_stock <= self.capacity / 4.0
        low_stock = current_stock < self.capacity / 2.0
        if critical_stock:
            action = Action.D
        elif low_stock:
            action = Action.C if opp_cooperators >= self.full_threshold else Action.D
        else:
            threshold = self.full_threshold - self.tolerance
            if threshold < 0:
                threshold = 0
            action = Action.C if opp_cooperators >= threshold else Action.D
        if t == self.n_rounds - 1:
            if not (current_stock > self.capacity / 2.0 and opp_cooperators >= (self.full_threshold if low_stock else max(0, self.full_threshold - self.tolerance))):
                action = Action.D
        return action

class Strategy_SELFINTERESTED_113(BaseStrategy):
    """
    Common-pool resource strategy:
    - Round 1: cooperate
    - Round r: defect
    - Intermediate rounds: score-based with stock-aware overrides and simple trend memory
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.last_action = Action.C
        self.prev_stock = None
        self.prev_trend = None

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        if self.prev_stock is not None:
            if current_stock > self.prev_stock:
                self.prev_trend = 'up'
            elif current_stock < self.prev_stock:
                self.prev_trend = 'down'
            else:
                self.prev_trend = 'flat'
        self.prev_stock = float(current_stock)
        if round_number >= self.r - 1:
            self.last_action = Action.D
            return Action.D
        if round_number == 0:
            self.last_action = Action.C
            return Action.C
        n = max(self.n, 2)
        capacity = max(self.capacity, 1e-12)
        S = float(current_stock)
        q = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else n - 1
        if round_number == 1:
            p = 1.0
        else:
            denom = max(n - 1, 1)
            p = q / denom
            if p < 0.0:
                p = 0.0
            elif p > 1.0:
                p = 1.0
        R = max(self.r - round_number, 1)
        rem_C = S * (1.0 + p) / 2.0
        rem_D = S * p / 2.0
        next_C = min(capacity, rem_C + 2.0 * rem_C * (1.0 - rem_C / capacity))
        next_D = min(capacity, rem_D + 2.0 * rem_D * (1.0 - rem_D / capacity))
        score_C = S / (2.0 * n) + (R - 1) * next_C / (2.0 * n)
        score_D = S / n + (R - 1) * next_D / (2.0 * n)
        action = Action.C
        if score_D > score_C and next_D > capacity / 4.0:
            action = Action.D
        elif score_D == score_C:
            action = Action.D
        if S <= capacity / 4.0:
            action = Action.C
        if len(history.opponent_cooperators) >= 2:
            if history.opponent_cooperators[-1] == n - 1 and history.opponent_cooperators[-2] == n - 1:
                if S > capacity / 2.0:
                    action = Action.D
        if self.prev_trend == 'down' and action == Action.D:
            action = Action.C
        elif self.prev_trend == 'up':
            pass
        self.last_action = action
        return action

class Strategy_SELFINTERESTED_114(BaseStrategy):
    """
    Adaptive cooperation strategy for the Common Pool Resource Game.

    Core idea:
    - Cooperate initially.
    - Defect in the final round.
    - Cooperate when stock is low or the opponent group is broadly cooperative.
    - Enter a short defection mode after a poorly cooperative round, unless stock is at risk.
    - Maintain cooperation when two consecutive rounds show strong cooperation.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        n_players = int(getattr(game_description, 'n_players', 0))
        self.n_opponents = max(0, n_players - 1)
        self.capacity = float(getattr(game_description, 'capacity', 0.0))
        self.n_rounds = int(getattr(game_description, 'n_rounds', 0))
        self.half_threshold = math.ceil(self.n_opponents / 2) if self.n_opponents > 0 else 0
        self.two_thirds_threshold = math.ceil(2 * self.n_opponents / 3) if self.n_opponents > 0 else 0
        self.low_stock_threshold = self.capacity / 4.0
        self.mid_stock_threshold = self.capacity / 2.0
        self.last_seen_round = -1
        self.forced_defect_remaining = 0
        self.coop_lock = False

    def _count_recent_coop_rounds(self, history: PlayerHistory, k: int) -> int:
        if history.round_number <= 0 or k <= 0:
            return 0
        start = max(0, history.round_number - k)
        recent = history.opponent_cooperators[start:history.round_number]
        count = 0
        for x in recent:
            if int(x) >= self.two_thirds_threshold:
                count += 1
        return count

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        if round_number < 0:
            round_number = 0
        if round_number > self.last_seen_round:
            if round_number > 0:
                last_opp_coops = int(history.opponent_cooperators[-1])
                if last_opp_coops < self.half_threshold:
                    self.forced_defect_remaining = 2
                elif self.forced_defect_remaining > 0:
                    self.forced_defect_remaining = max(0, self.forced_defect_remaining - 1)
                if round_number >= 2:
                    prev_1 = int(history.opponent_cooperators[-1])
                    prev_2 = int(history.opponent_cooperators[-2])
                    if prev_1 >= self.two_thirds_threshold and prev_2 >= self.two_thirds_threshold:
                        self.coop_lock = True
                    else:
                        self.coop_lock = False
                else:
                    self.coop_lock = False
            self.last_seen_round = round_number
        if round_number == 0:
            return Action.C
        if round_number >= self.n_rounds - 1:
            return Action.D
        stock = float(current_stock)
        if stock < 0.0:
            stock = 0.0
        if stock <= self.low_stock_threshold:
            self.forced_defect_remaining = 0
            return Action.C
        if self.forced_defect_remaining > 0:
            self.forced_defect_remaining = max(0, self.forced_defect_remaining - 1)
            return Action.D
        if self.coop_lock:
            recent_two = self._count_recent_coop_rounds(history, 2)
            if recent_two == 2:
                return Action.C
            self.coop_lock = False
        if current_stock <= self.low_stock_threshold:
            return Action.C
        if history.round_number > 0:
            x = int(history.opponent_cooperators[-1])
        else:
            x = 0
        if x > self.half_threshold:
            return Action.C
        if x < self.half_threshold:
            return Action.D
        if stock > self.mid_stock_threshold:
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_115(BaseStrategy):
    """
    Common-pool strategy:
    - Cooperate initially.
    - Defect in the final round.
    - Prioritize collapse avoidance, then recovery, then exploitation, then the
      standard stock/opponent-threshold rule.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(0, self.n_players - 1)
        self._last_stock: float | None = None
        self._recovering: bool = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        n_rounds = self.n_rounds
        capacity = self.capacity
        if round_number >= n_rounds - 1:
            self._recovering = False
            self._last_stock = float(current_stock)
            return Action.D
        if round_number == 0:
            self._recovering = False
            self._last_stock = float(current_stock)
            return Action.C
        last_cooperators = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        if self.n_opponents > 0:
            q = last_cooperators / self.n_opponents
        else:
            q = 0.0
        if self._last_stock is not None and float(current_stock) < self._last_stock - 1e-12:
            self._recovering = True
        m = n_rounds - round_number
        if m < 1:
            m = 1
        floor_level = capacity * (m - 1) / (m + 1) if m + 1 != 0 else 0.0
        stock = float(current_stock)
        if stock <= capacity / 2:
            self._recovering = True
            self._last_stock = stock
            return Action.C
        if self._recovering:
            if stock <= floor_level and q < 0.5:
                self._last_stock = stock
                return Action.C
            self._recovering = False
        if stock >= 0.75 * capacity and q >= 2.0 / 3.0:
            self._last_stock = stock
            return Action.D
        action = Action.C if stock <= floor_level or q < 0.5 else Action.D
        self._last_stock = stock
        return action

class Strategy_SELFINTERESTED_116(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Cooperates in round 1
    - Defects in the final round
    - Uses stock level, observed opponent cooperation, trust memory, and recent stock trend
      to decide between cooperation and defection in intermediate rounds.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.previous_stock = None
        self.previous_q = None
        self.trust = 'neutral'

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        remaining_rounds = self.n_rounds - round_number

        def compute_q() -> float:
            if round_number == 0:
                return 0.0
            n_opponents = max(self.n_players - 1, 1)
            return float(history.opponent_cooperators[-1]) / float(n_opponents)
        if round_number > 0:
            q_last = compute_q()
            self.previous_q = q_last
            if q_last <= 0.25:
                self.trust = 'low'
            elif round_number >= 2:
                q_prev = float(history.opponent_cooperators[-2]) / float(max(self.n_players - 1, 1))
                if q_prev >= 0.75 and q_last >= 0.75:
                    self.trust = 'high'
                elif self.trust != 'low' and q_last >= 0.5:
                    self.trust = 'neutral'
            elif self.trust != 'low' and q_last >= 0.5:
                self.trust = 'neutral'
        if round_number == 0:
            self.previous_stock = float(current_stock)
            return Action.C
        if remaining_rounds <= 1:
            self.previous_stock = float(current_stock)
            return Action.D
        q = self.previous_q if self.previous_q is not None else compute_q()
        S = float(current_stock)
        cap = self.capacity
        if remaining_rounds == 2:
            action = Action.D if S >= cap / 2.0 else Action.C
            self.previous_stock = float(current_stock)
            return action
        if self.trust == 'low':
            if q >= 0.5:
                self.trust = 'neutral'
            else:
                self.previous_stock = float(current_stock)
                return Action.C
        if self.trust == 'high' and S >= 2.0 * cap / 3.0:
            self.previous_stock = float(current_stock)
            return Action.D
        if S <= cap / 3.0:
            action = Action.C
        elif S >= 2.0 * cap / 3.0 and q >= 0.8:
            action = Action.D
        elif q >= 0.75 and S >= cap / 2.0:
            action = Action.D
        elif q <= 0.25:
            action = Action.C
        elif self.previous_stock is not None and S > self.previous_stock:
            action = Action.D
        else:
            action = Action.C
        self.previous_stock = float(current_stock)
        return action

class Strategy_SELFINTERESTED_117(BaseStrategy):
    """
    Starts by cooperating, tracks opponent cooperation with a running estimate,
    and defects in the final round or when stock becomes scarce.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.b = 1.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = int(history.round_number)
        if t == 0:
            return Action.C
        n_opponents = max(self.n_players - 1, 1)
        x_prev = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        p = x_prev / n_opponents
        self.b = (self.b + p) / 2.0
        S = float(current_stock)
        if t >= self.n_rounds - 1:
            return Action.D
        if S <= self.capacity / 4.0:
            return Action.D
        if t >= self.n_rounds - 2:
            if x_prev == self.n_players - 1 and S >= self.capacity / 2.0:
                return Action.C
            return Action.D
        if self.b >= 2.0 / 3.0 and S >= self.capacity / 2.0:
            return Action.C
        if self.b >= 0.5 and S >= 3.0 * self.capacity / 4.0:
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_118(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Start with cooperation.
    - Defect on the final round.
    - Use stock-dependent thresholds and a persistence rule to avoid premature cooperation.
    - Defect immediately if the stock is depleted.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self._eps = 1e-12

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number + 1
        n = self.n
        r = self.r
        capacity = self.capacity
        S = float(current_stock)
        if t >= r:
            return Action.D
        if S <= 0.0:
            return Action.D
        if history.round_number == 0:
            return Action.C
        prev_my_action_c = bool(history.my_actions[-1])
        opp_prev = int(history.opponent_cooperators[-1])
        k_prev = opp_prev + (1 if prev_my_action_c else 0)
        if S <= 0.0 or capacity <= 0.0:
            k_keep = n
        else:
            ratio = S / capacity
            denom = 2.0 * ratio
            if denom <= self._eps:
                x_keep = 1.0
            else:
                radicand = max(0.0, 9.0 - 8.0 * ratio)
                x_keep = (3.0 - math.sqrt(radicand)) / denom
                if not math.isfinite(x_keep):
                    x_keep = 1.0
            k_keep = int(math.ceil(n * x_keep))
            if k_keep < 0:
                k_keep = 0
            elif k_keep > n:
                k_keep = n
        if t == r - 1:
            return Action.C if S < 0.4 * capacity and k_prev >= n - 1 else Action.D
        if S >= capacity - self._eps:
            return Action.C if k_prev == n else Action.D
        if S < 0.4 * capacity:
            decision = Action.C if k_prev >= n - 1 else Action.D
        elif S < 0.8 * capacity:
            decision = Action.C if k_prev >= k_keep else Action.D
        else:
            decision = Action.C if k_prev == n else Action.D
        if not prev_my_action_c and k_prev < k_keep and (S >= 0.4 * capacity):
            return Action.D
        return decision

class Strategy_SELFINTERESTED_119(BaseStrategy):
    """
    Common-pool strategy with EWMA-based opponent cooperation estimation,
    stock-preserving safety checks, and endgame defection.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.F = 0.5
        self.U = 0.85
        self.alpha = 0.6

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = int(self.game_description.n_players)
        r = int(self.game_description.n_rounds)
        capacity = float(self.game_description.capacity)
        if n < 2:
            return Action.C
        round_index = int(history.round_number)
        current_round = round_index + 1
        if current_round >= r:
            return Action.D
        if round_index == 0:
            return Action.C
        if current_stock <= 0.25 * capacity:
            return Action.C
        q = 1.0
        prev_rate = None
        n_opponents = max(n - 1, 1)
        opp_coops = history.opponent_cooperators
        num_hist = len(opp_coops)
        for t in range(num_hist):
            rate = float(opp_coops[t]) / n_opponents
            if prev_rate is not None:
                delta = rate - prev_rate
                if delta < -0.25:
                    q = max(0.0, q - 0.1)
                elif delta > 0.25:
                    q = min(1.0, q + 0.05)
            q = self.alpha * rate + (1.0 - self.alpha) * q
            q = max(0.0, min(1.0, q))
            prev_rate = rate
        d_hat = int(round((n - 1) * (1.0 - q)))
        d_hat = max(0, min(n - 1, d_hat))

        def next_stock(action_is_defect: bool) -> float:
            d = d_hat + (1 if action_is_defect else 0)
            d = max(0, min(n, d))
            remaining = current_stock * (n - d) / (2.0 * n)
            growth = 2.0 * remaining * (1.0 - remaining / capacity) if capacity > 0 else 0.0
            return min(remaining + growth, capacity)
        s_next_d = next_stock(True)
        s_next_c = next_stock(False)
        f_cap = self.F * capacity
        u_cap = self.U * capacity
        if s_next_c >= u_cap and s_next_d >= u_cap:
            return Action.D
        if s_next_d >= f_cap:
            return Action.D
        if s_next_c >= f_cap:
            return Action.C
        return Action.C

class Strategy_SELFINTERESTED_120(BaseStrategy):
    """
    Resource-conservative strategy with endgame defection, collapse recovery,
    and stateful trust rebuilding based on opponent cooperation trends.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.last_coop_ratio = 1.0
        self.mode = 'cooperate'
        self._prev_observed_rate = None
        self._increasing_streak = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_players = int(getattr(self.game_description, 'n_players', 0))
        n_rounds = int(getattr(self.game_description, 'n_rounds', 0))
        capacity = float(getattr(self.game_description, 'capacity', 0.0))
        round_number = int(getattr(history, 'round_number', 0))
        n_opponents = max(n_players - 1, 1)
        if round_number > 0 and len(history.opponent_cooperators) > 0:
            observed_count = float(history.opponent_cooperators[-1])
            observed_rate = observed_count / float(n_opponents)
            if observed_rate < 0.5:
                self.last_coop_ratio = 0.0
                self._increasing_streak = 0
            else:
                if observed_rate >= 1.0:
                    self.last_coop_ratio = 1.0
                if self._prev_observed_rate is not None and observed_rate > self._prev_observed_rate:
                    self._increasing_streak += 1
                else:
                    self._increasing_streak = 0
                if self._increasing_streak >= 2:
                    self.last_coop_ratio = observed_rate
            self._prev_observed_rate = observed_rate
        if round_number == 0:
            if capacity >= 2.0 * n_players and n_players > 2:
                self.mode = 'cooperate'
                return Action.C
            self.mode = 'defect'
            return Action.D
        if n_rounds - round_number <= 1:
            self.mode = 'defect'
            return Action.D
        stock = float(current_stock)
        if stock <= capacity / 8.0:
            if self.last_coop_ratio >= 1.0:
                self.mode = 'cooperate'
                return Action.C
            self.mode = 'defect'
            return Action.D
        if stock <= capacity / 4.0:
            if self.last_coop_ratio >= 0.5:
                self.mode = 'cooperate'
                return Action.C
            self.mode = 'defect'
            return Action.D
        if self.last_coop_ratio >= 2.0 / 3.0 and stock >= capacity / 2.0:
            self.mode = 'cooperate'
            return Action.C
        self.mode = 'defect'
        return Action.D

class Strategy_SELFINTERESTED_121(BaseStrategy):
    """
    Adaptive common-pool strategy with two modes:
    - harvest: defect by default
    - rebuild: cooperate by default

    It switches modes using the current stock level and the previous round's
    observed opponent cooperation rate, while forcing defection in the final
    two rounds and at special boundary states.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.mode = 'harvest'

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        remaining_rounds = r - history.round_number
        if remaining_rounds <= 2:
            self.mode = 'harvest'
            return Action.D
        if history.round_number == 0:
            self.mode = 'harvest'
            return Action.D
        capacity = float(self.game_description.capacity)
        stock = float(current_stock)
        if stock <= 0.0:
            self.mode = 'harvest'
            return Action.D
        if stock == capacity:
            self.mode = 'harvest'
            return Action.D
        last_q = int(history.opponent_cooperators[-1]) if history.round_number > 0 else 0
        n_opponents = max(n - 1, 1)
        if n == 2:
            f = 1.0 if last_q >= 1 else 0.0
        else:
            f = last_q / n_opponents
        s = stock / capacity if capacity > 0 else 0.0
        if stock <= capacity / 5.0:
            if f >= 2.0 / 3.0:
                self.mode = 'rebuild'
                return Action.C
            self.mode = 'harvest'
            return Action.D
        if s <= 1.0 / 3.0 and f >= 0.5:
            self.mode = 'rebuild'
        if s >= 2.0 / 3.0 or f < 0.5:
            self.mode = 'harvest'
        return Action.C if self.mode == 'rebuild' else Action.D

class Strategy_SELFINTERESTED_122(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Start by cooperating.
    - Defect in the final round.
    - Use current stock and last-round opponent cooperation rate to decide.
    - Apply a one-step conservative/aggressive adjustment when stock and cooperation trend together.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self._last_stock = None
        self._last_opponent_coop_frac = None

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_players = self.game_description.n_players
        n_opponents = max(1, n_players - 1)
        n_rounds = self.game_description.n_rounds
        capacity = float(self.game_description.capacity) if self.game_description.capacity else 1.0
        if history.round_number == 0:
            self._last_stock = float(current_stock)
            self._last_opponent_coop_frac = None
            return Action.C
        round_index = history.round_number + 1
        if round_index >= n_rounds:
            self._last_stock = float(current_stock)
            if len(history.opponent_cooperators) > 0:
                self._last_opponent_coop_frac = float(history.opponent_cooperators[-1]) / n_opponents
            return Action.D
        last_count = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        p = last_count / n_opponents
        s = float(current_stock) / capacity if capacity > 0 else 0.0
        if self._last_stock is not None and len(history.opponent_cooperators) > 1:
            prev_stock = float(self._last_stock)
            prev_count = int(history.opponent_cooperators[-2])
            prev_p = prev_count / n_opponents
            delta = 1.0 / n_opponents
            if float(current_stock) < prev_stock and p < prev_p:
                p = max(0.0, p - delta)
            elif float(current_stock) > prev_stock and p >= prev_p:
                p = min(1.0, p + delta)
        if float(current_stock) <= 0.0:
            action = Action.D
        elif s >= 2.0 / 3.0 and p >= 0.5:
            action = Action.D
        elif s >= 1.0 / 3.0 and p >= 2.0 / 3.0:
            action = Action.D
        elif s < 1.0 / 3.0:
            action = Action.C if p >= 1.0 / 3.0 else Action.D
        else:
            action = Action.C if p < 0.5 else Action.D
        self._last_stock = float(current_stock)
        self._last_opponent_coop_frac = p
        return action

class Strategy_SELFINTERESTED_123(BaseStrategy):
    """
    Threshold-based common-pool strategy:
    - Cooperate in round 1.
    - Defect in the final round.
    - In intermediate rounds, cooperate only when stock is high enough and
      the previous round's opponent cooperation rate was at least 1/2.
    - Maintain a defection mode after low cooperation until both conditions recover.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self._forced_defect = False
        self._last_observed_round = -1
        self._eps = 1e-12

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_rounds = self.game_description.n_rounds
        n_players = self.game_description.n_players
        capacity = float(self.game_description.capacity)
        round_number = history.round_number
        if round_number >= n_rounds - 1:
            return Action.D
        if round_number == 0:
            self._forced_defect = False
            self._last_observed_round = 0
            return Action.C
        if self._last_observed_round != round_number:
            last_coop_count = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
            m = max(n_players - 1, 1)
            if m == 1:
                coop_rate = 1.0 if last_coop_count >= 1 else 0.0
            else:
                coop_rate = last_coop_count / m
            high_stock = 0.75 * capacity
            if coop_rate < 0.5:
                self._forced_defect = True
            elif coop_rate >= 0.5 and current_stock >= high_stock:
                self._forced_defect = False
            self._last_observed_round = round_number
        low_stock = self._eps
        high_stock = 0.75 * capacity
        if current_stock <= low_stock:
            self._forced_defect = True
            return Action.D
        if self._forced_defect:
            return Action.D
        last_coop_count = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        m = max(n_players - 1, 1)
        if m == 1:
            coop_rate = 1.0 if last_coop_count >= 1 else 0.0
        else:
            coop_rate = last_coop_count / m
        if current_stock >= high_stock and coop_rate >= 0.5:
            return Action.C
        self._forced_defect = True
        return Action.D

class Strategy_SELFINTERESTED_124(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Cooperates only when stock is healthy and trust in opponents is sufficient.
    - Defects when the pool is depleted, cooperation collapses, or in the final round.
    - Maintains a simple trust score updated from observed opponent cooperation.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.trust = 0.5
        self.last_processed_round = 0
        self.last_c_hat = None
        self.last_opponent_cooperators = None
        self.capacity = float(game_description.capacity)
        self.s_coop = 0.5 * self.capacity
        self.s_safe = 0.4 * self.capacity
        self.s_low = 0.25 * self.capacity

    def _update_trust_from_history(self, history: PlayerHistory) -> None:
        current_round = history.round_number
        if current_round <= self.last_processed_round:
            return
        start_idx = self.last_processed_round
        end_idx = current_round
        m = max(1, self.game_description.n_players - 1)
        for idx in range(start_idx, end_idx):
            if idx < len(history.opponent_cooperators):
                k = int(history.opponent_cooperators[idx])
                c_hat = k / m
                self.last_c_hat = c_hat
                self.last_opponent_cooperators = k
                t = 0.7 * self.trust + 0.3 * c_hat
                if c_hat <= 1.0 / 3.0:
                    t = max(0.0, t - 0.25)
                if c_hat >= 2.0 / 3.0:
                    t = min(1.0, t + 0.1)
                self.trust = t
        self.last_processed_round = current_round

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        self._update_trust_from_history(history)
        round_number = history.round_number
        n_rounds = self.game_description.n_rounds
        if round_number >= n_rounds - 1:
            return Action.D
        if round_number == 0:
            return Action.C
        if current_stock <= self.s_low:
            return Action.D
        if current_stock < self.s_safe and self.last_c_hat is not None and (self.last_c_hat < 0.5):
            return Action.D
        if current_stock >= self.s_coop and self.trust >= 0.5 and (self.last_c_hat is not None) and (self.last_c_hat >= 0.5):
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_125(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Cooperate early if the pool is large enough.
    - Defect on the final round.
    - Otherwise, cooperate when stock is high and recent opponent cooperation is strong;
      defect when stock is low or opponents have recently been uncooperative.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(self.n - 1, 0)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        if round_number >= self.r - 1:
            return Action.D
        if round_number == 0:
            return Action.C if self.capacity >= 4.0 * self.n else Action.D
        stock = float(current_stock)
        if stock <= 0.0:
            return Action.D
        last_k = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        prev_k = int(history.opponent_cooperators[-2]) if len(history.opponent_cooperators) > 1 else last_k
        denom = self.n_opponents
        q_last = last_k / denom if denom > 0 else 0.5
        q_prev = prev_k / denom if denom > 0 else 0.5
        half_opponents = denom / 2.0
        if stock < self.capacity / 3.0:
            return Action.D
        if last_k < half_opponents:
            return Action.D
        if stock > 2.0 * self.capacity / 3.0 and (last_k >= half_opponents or prev_k >= half_opponents):
            return Action.C
        if stock >= self.capacity / 2.0:
            return Action.C
        if denom > 0:
            opp_expected_consumption = denom * (q_last * stock / (2.0 * self.n) + (1.0 - q_last) * stock / self.n)
        else:
            opp_expected_consumption = 0.0
        total_c = stock / (2.0 * self.n) + opp_expected_consumption
        total_d = stock / self.n + opp_expected_consumption
        remaining_c = max(stock - total_c, 0.0)
        remaining_d = max(stock - total_d, 0.0)
        next_stock_c = min(remaining_c + 2.0 * remaining_c * (1.0 - (remaining_c / self.capacity if self.capacity > 0 else 0.0)), self.capacity) if self.capacity > 0 else 0.0
        next_stock_d = min(remaining_d + 2.0 * remaining_d * (1.0 - (remaining_d / self.capacity if self.capacity > 0 else 0.0)), self.capacity) if self.capacity > 0 else 0.0
        v_c = stock / (2.0 * self.n) + (next_stock_c / (2.0 * self.n) if next_stock_c > 0 else 0.0)
        v_d = stock / self.n + (next_stock_d / (2.0 * self.n) if next_stock_d > 0 else 0.0)
        return Action.C if v_c >= v_d and q_last >= 0.5 and (q_prev >= 0.5 or stock > self.capacity / 2.0) else Action.D

class Strategy_SELFINTERESTED_126(BaseStrategy):
    """
    Adaptive common-pool strategy that tracks trust in opponent cooperation and
    switches between rebuilding and extracting based on stock level, trend, and
    recent cooperation.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.trust = 0.0
        self.mode = 'rebuild' if self.capacity <= self.capacity / 2 else 'extract'
        self.mode = 'rebuild' if self.capacity <= self.capacity / 2 else 'extract'
        self.mode = 'rebuild' if self.capacity <= self.capacity / 2 else 'extract'
        self.mode = 'extract'
        self.prev_stock = self.capacity
        self.high_coop_streak = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        if round_number == 0:
            self.prev_stock = float(current_stock)
            self.trust = 0.0
            self.mode = 'rebuild' if float(current_stock) <= self.capacity / 2.0 else 'extract'
            self.high_coop_streak = 0
            return Action.C
        n_opponents = max(self.n_players - 1, 1)
        last_coop_count = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        coop_rate = last_coop_count / n_opponents
        prev_stock = self.prev_stock
        stock_now = float(current_stock)
        self.trust = 0.7 * self.trust + 0.3 * coop_rate
        if coop_rate >= 0.7 and stock_now >= self.capacity / 2.0:
            self.high_coop_streak += 1
        else:
            self.high_coop_streak = 0
        if round_number == self.n_rounds - 1:
            self.prev_stock = stock_now
            return Action.D
        if stock_now < prev_stock or coop_rate < 0.4:
            self.mode = 'rebuild'
        elif self.high_coop_streak >= 2 and stock_now >= self.capacity / 2.0:
            self.mode = 'extract'
        if stock_now <= self.capacity / 3.0:
            action = Action.C
            self.mode = 'rebuild'
        elif self.mode == 'rebuild':
            if self.trust >= 0.5:
                action = Action.C
            elif stock_now < self.capacity / 2.0:
                action = Action.C
            else:
                action = Action.D
                self.mode = 'extract'
        elif self.trust >= 0.65 and stock_now >= self.capacity / 2.0:
            action = Action.C
        else:
            action = Action.D
        self.prev_stock = stock_now
        return action

class Strategy_SELFINTERESTED_127(BaseStrategy):
    """
    Cooperative-by-default, threshold-based common-pool strategy with punishment,
    recovery, and endgame defection bias.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.q_star = 0.5 + 1.0 / (2.0 * self.n_players)
        self.s_safe = self.capacity / 2.0
        self.s_crit = self.capacity / 4.0
        self._last_round_number = -1
        self._prev_stock = None
        self._last_q = None
        self._force_defect = False
        self._positive_q_streak = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number + 1
        T = self.n_rounds - t + 1
        if history.round_number != self._last_round_number:
            if history.round_number > 0:
                last_opp = int(history.opponent_cooperators[-1])
                n_opponents = max(self.n_players - 1, 1)
                q_prev = last_opp / n_opponents
                self._last_q = q_prev
                if q_prev > 0.0:
                    self._positive_q_streak += 1
                else:
                    self._positive_q_streak = 0
                    self._force_defect = True
                if q_prev < self.q_star:
                    self._force_defect = True
                if self._force_defect and self._positive_q_streak >= 2:
                    self._force_defect = False
            self._last_round_number = history.round_number
        if history.round_number == 0:
            self._prev_stock = float(current_stock)
            return Action.C
        n_opponents = max(self.n_players - 1, 1)
        q = int(history.opponent_cooperators[-1]) / n_opponents
        if q == 0.0:
            self._force_defect = True
            self._positive_q_streak = 0
        elif self._force_defect:
            if q > 0.0:
                self._positive_q_streak += 1
                if self._positive_q_streak >= 2:
                    self._force_defect = False
            else:
                self._positive_q_streak = 0
        prev_stock = self._prev_stock
        stock_falling_or_flat = prev_stock is not None and current_stock <= prev_stock + 1e-12
        self._prev_stock = float(current_stock)
        if T == 1:
            return Action.C if current_stock >= self.capacity else Action.D
        if T <= 2:
            if current_stock >= self.s_safe and q >= self.q_star and (not self._force_defect):
                return Action.C
            return Action.D
        if self._force_defect:
            return Action.D
        if current_stock <= self.s_crit:
            return Action.D
        if q < self.q_star:
            return Action.D
        if current_stock >= self.s_safe:
            if stock_falling_or_flat and q <= self.q_star + 0.05:
                return Action.D
            return Action.C
        p_c = current_stock / self.capacity if self.capacity > 0 else 0.0
        p_c = min(1.0, max(0.0, p_c))
        if stock_falling_or_flat and q <= self.q_star + 0.05:
            return Action.D
        return Action.C if random.random() < p_c else Action.D

class Strategy_SELFINTERESTED_128(BaseStrategy):
    """
    Trust-based common-pool strategy with cooperative, grim, and late-round tightening modes.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.trust = 1.0
        self.mode = 'cooperative'
        self._last_processed_round = 0
        self._coop_rates = []
        self._recent_coop_rates = []
        self._known_history_len = 0

    def _is_trust_sufficient(self) -> bool:
        n = self.game_description.n_players
        if n == 2:
            if len(self._coop_rates) == 0:
                return False
            if self._coop_rates[-1] < 1.0:
                return False
            if len(self._coop_rates) >= 2 and self._coop_rates[-1] < 1.0 and (self._coop_rates[-2] < 1.0):
                return False
            return True
        return self.trust >= 0.75

    def _is_late_round(self, current_round_number: int) -> bool:
        r = self.game_description.n_rounds
        if r == 2:
            return current_round_number >= 2
        return current_round_number > r - 3

    def _update_internal_state(self, history: PlayerHistory) -> None:
        start = self._last_processed_round
        end = history.round_number
        if start >= end:
            return
        n = self.game_description.n_players
        n_opponents = max(0, n - 1)
        for idx in range(start, end):
            k = int(history.opponent_cooperators[idx]) if idx < len(history.opponent_cooperators) else 0
            if n_opponents > 0:
                coop_rate = k / n_opponents
            else:
                coop_rate = 0.0
            self._coop_rates.append(coop_rate)
            self._recent_coop_rates.append(coop_rate)
            if len(self._recent_coop_rates) > 3:
                self._recent_coop_rates.pop(0)
            self.trust = 0.7 * self.trust + 0.3 * coop_rate
            if coop_rate < 0.5:
                self.mode = 'grim'
        self._last_processed_round = end

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        self._update_internal_state(history)
        n_rounds = self.game_description.n_rounds
        capacity = float(self.game_description.capacity)
        current_round_number = history.round_number + 1
        if history.round_number == 0:
            return Action.C
        if current_round_number == n_rounds:
            if current_stock >= 0.9 * capacity and self._is_trust_sufficient():
                return Action.C
            return Action.D
        if current_stock < 0.45 * capacity:
            return Action.D
        trust_ok = self._is_trust_sufficient()
        if self.mode == 'grim':
            if trust_ok and current_stock >= 0.7 * capacity:
                self.mode = 'cooperative'
            else:
                return Action.D
        if self._is_late_round(current_round_number):
            if current_stock >= 0.85 * capacity and (self.trust >= 0.85 if self.game_description.n_players != 2 else trust_ok):
                return Action.C
            return Action.D
        if current_stock >= 0.7 * capacity and trust_ok:
            return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_33(BaseStrategy):
    """
    Three-mode common-pool strategy:
    - protect when stock is fragile,
    - harvest/cooperate in unstable or recovering states,
    - opportunistically defect when stock is high and opponents are cooperative.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(0, self.n_players - 1)
        self.t_protect_base = 0.35 * self.capacity
        self.t_exploit = 0.65 * self.capacity
        self.last_stock = None
        self.last_h = None
        self.prev_h = None
        self.low_h_streak = 0
        self.drop_protect_rounds = 0
        self.defect_streak = 0
        self.stock_drop_streak = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number
        S = float(current_stock)
        if t > 0 and len(history.opponent_cooperators) > 0 and (self.n_opponents > 0):
            k = int(history.opponent_cooperators[-1])
            h = k / self.n_opponents
        else:
            h = 1.0
        if t > 0 and self.last_stock is not None:
            if self.last_stock - S > 0.2 * self.capacity:
                self.drop_protect_rounds = 2
            if S < self.last_stock:
                self.stock_drop_streak += 1
            else:
                self.stock_drop_streak = 0
        else:
            self.stock_drop_streak = 0
        if h < 1.0 / 3.0:
            self.low_h_streak += 1
        else:
            self.low_h_streak = 0
        if t > 0 and self.last_h is not None:
            if S >= (self.last_stock if self.last_stock is not None else S) and h >= 0.5:
                pass
        remaining = self.n_rounds - t
        final_third = t >= 2 * self.n_rounds / 3 if self.n_rounds > 0 else False
        t_protect = self.t_protect_base
        if final_third and self.last_h is not None:
            if t >= 2 and len(history.opponent_cooperators) >= 2 and (self.n_opponents > 0):
                h_prev = self.prev_h if self.prev_h is not None else h
                if h >= 2.0 / 3.0 and h_prev >= 2.0 / 3.0:
                    t_protect *= 0.5
        if t == 0:
            action = Action.C
        else:
            if self.defect_streak > 0 and S <= t_protect:
                action = Action.C
            elif self.drop_protect_rounds > 0:
                action = Action.C
                self.drop_protect_rounds -= 1
            elif remaining == 1:
                action = Action.D if S > t_protect else Action.C
            elif remaining <= 2:
                action = Action.C if S <= self.t_exploit else Action.D
            elif self.low_h_streak >= 2:
                action = Action.D if S > t_protect else Action.C
            elif S <= t_protect:
                action = Action.C
            elif S >= self.t_exploit:
                action = Action.D if h >= 0.5 else Action.C
            else:
                action = Action.C if h >= 0.5 else Action.D
            if action == Action.D:
                if S <= t_protect or h < 0.5 or self.stock_drop_streak >= 2:
                    action = Action.C
        if action == Action.D:
            self.defect_streak += 1
        else:
            self.defect_streak = 0
        self.prev_h = self.last_h
        self.last_h = h
        self.last_stock = S
        return action

class Strategy_OPPORTUNISTIC_34(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Cooperate in round 1.
    - Uses only the most recent opponent cooperation count and current stock.
    - Applies the projected next-stock decision rule with conservative tie-breaking.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)

    def _next_stock(self, current_stock: float, cooperators: int) -> float:
        cap = self.capacity
        n = self.n_players
        s = float(current_stock)
        if s < 0.0:
            s = 0.0
        if cap <= 0.0 or n <= 0:
            return 0.0
        x = s * float(cooperators) / (2.0 * float(n))
        growth = 2.0 * x * (1.0 - x / cap)
        return min(x + growth, cap)

    def _choose_with_tie_break(self, current_stock: float, next_c: float, next_d: float) -> Action:
        half_cap = self.capacity / 2.0
        both_below = next_c < half_cap and next_d < half_cap
        if both_below:
            return Action.C if current_stock <= half_cap else Action.D
        return Action.D if next_d >= half_cap else Action.C

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        n = self.n_players
        cap = self.capacity
        r = self.n_rounds
        k = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        if k < 0:
            k = 0
        if n > 1:
            if k > n - 1:
                k = n - 1
            q = k / float(n - 1)
        else:
            q = 0.0
        L = r - history.round_number
        if L <= 1:
            return Action.D
        s = float(current_stock)
        half_cap = cap / 2.0
        if s <= cap / 4.0:
            return Action.C
        next_c = self._next_stock(s, k + 1)
        next_d = self._next_stock(s, k)
        if q >= 2.0 / 3.0:
            if L >= 3:
                return Action.D
            if next_d < half_cap:
                if next_c < half_cap:
                    return Action.C if s <= half_cap else Action.D
                return Action.C
            return Action.D
        if q <= 1.0 / 3.0:
            if next_c >= half_cap:
                return Action.C
            if next_d < half_cap and next_c < half_cap:
                return Action.C if s <= half_cap else Action.D
            return Action.D
        if next_d >= half_cap:
            return Action.D
        if next_c < half_cap and next_d < half_cap:
            return Action.C if s <= half_cap else Action.D
        return Action.C

class Strategy_OPPORTUNISTIC_35(BaseStrategy):
    """
    Thresholded opportunistic common-pool strategy with adaptive cooperation tracking.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.m = max(1, self.n - 1)
        self.c_hat = 0.5
        self.trend = 0.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = int(history.round_number) + 1
        S = float(current_stock)
        if S <= 0.0:
            return Action.C
        if history.round_number == 0:
            if self.r <= 3 and self.capacity >= 1.75 * self.n:
                return Action.D
            return Action.C
        prev_k = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        obs = prev_k / self.m if self.m > 0 else 0.0
        self.c_hat = 0.7 * self.c_hat + 0.3 * obs
        self.trend = obs - self.c_hat
        if t >= self.r - 1:
            return Action.D if S > 0.0 else Action.C
        if obs < 0.25 and S > self.n:
            return Action.D
        if obs > 0.75 and S < 1.5 * self.n:
            return Action.C
        if S <= self.n:
            return Action.C
        if S >= 1.5 * self.n and self.c_hat >= 0.5:
            return Action.D
        trend_weight = 0.2 if t > self.r / 2.0 else 0.25
        T = 0.5 + trend_weight * self.trend + 0.15 * (S / self.capacity - 0.5 if self.capacity > 0 else 0.0)
        T = max(0.25, min(0.75, T))
        return Action.C if self.c_hat >= T else Action.D

class Strategy_OPPORTUNISTIC_36(BaseStrategy):
    """
    Cautious conditional cooperator:
    - Starts by cooperating.
    - Cooperates only under strong recent cooperation and healthy stock.
    - Defects quickly after signs of exploitation.
    - Uses a short defection cooldown after low cooperation.
    - Becomes conservative in the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.defect_cooldown = 0
        self._last_decision_round = -1

    def _n_opponents(self) -> int:
        return max(0, self.game_description.n_players - 1)

    def _coop_rate(self, coop_count: int) -> float:
        n_opponents = self._n_opponents()
        if n_opponents <= 0:
            return 0.0
        return coop_count / n_opponents

    def _all_last_k_ge_2_3(self, history: PlayerHistory, k: int) -> bool:
        if k <= 0:
            return True
        if history.round_number < k:
            return False
        n_opponents = self._n_opponents()
        if n_opponents <= 0:
            return False
        threshold_ok = 2 * n_opponents
        for count in history.opponent_cooperators[-k:]:
            if 3 * int(count) < threshold_ok:
                return False
        return True

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number
        n_rounds = self.game_description.n_rounds
        capacity = float(self.game_description.capacity) if self.game_description.capacity != 0 else 1.0
        if t == 0:
            self.defect_cooldown = 0
            self._last_decision_round = 0
            return Action.C
        if self._last_decision_round != t:
            if self.defect_cooldown > 0:
                self.defect_cooldown -= 1
            self._last_decision_round = t
        n_opponents = self._n_opponents()
        last_q_count = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        q = self._coop_rate(last_q_count)
        s = current_stock / capacity if capacity > 0 else 0.0
        last2_ge = self._all_last_k_ge_2_3(history, 2)
        last3_ge = self._all_last_k_ge_2_3(history, 3)
        if t == n_rounds - 1:
            if q == 1.0 and s >= 1.0 and last3_ge:
                self.defect_cooldown = 0
                return Action.C
            self.defect_cooldown = 0
            return Action.D
        if history.round_number >= 2:
            q_prev = self._coop_rate(int(history.opponent_cooperators[-2]))
            q_prev2 = self._coop_rate(int(history.opponent_cooperators[-3])) if history.round_number >= 3 else 0.0
            if q == 1.0 and q_prev == 1.0 and (s >= 0.75):
                self.defect_cooldown = 0
        if s < 1.0 / 3.0:
            return Action.D
        if q < 0.5:
            self.defect_cooldown = 2
            return Action.D
        if self.defect_cooldown > 0:
            return Action.D
        if s < 0.5:
            if q == 1.0 and last2_ge:
                return Action.C
            return Action.D
        if s >= 0.5 and q >= 2.0 / 3.0 and last2_ge:
            return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_37(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Cooperate in round 1.
    - Defect in the final round.
    - Cooperate when the stock is low and opponents cooperated strongly.
    - Enter a short cooldown after weak opponent cooperation.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.cooldown = 0
        self.last_round_coop_rate = 0.0
        self.last_seen_round = -1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_players = max(2, int(self.game_description.n_players))
        n_rounds = int(self.game_description.n_rounds)
        round_number = int(history.round_number)
        total_round_index = round_number + 1
        capacity = float(self.game_description.capacity)
        stock = float(current_stock)
        if round_number != self.last_seen_round:
            self.last_seen_round = round_number
        if round_number == 0:
            return Action.C
        opp_count = n_players - 1
        if opp_count > 0 and len(history.opponent_cooperators) > 0:
            prev_coop = float(history.opponent_cooperators[-1])
            self.last_round_coop_rate = prev_coop / float(opp_count)
        else:
            self.last_round_coop_rate = 0.0
        if total_round_index == n_rounds:
            return Action.D
        x = stock / capacity if capacity > 0 else 0.0
        if x <= 0.25:
            self.cooldown = 0
            return Action.C
        if self.cooldown > 0:
            self.cooldown -= 1
            return Action.D
        if self.last_round_coop_rate >= 2.0 / 3.0 and x <= 0.5:
            return Action.C
        if self.last_round_coop_rate < 1.0 / 3.0:
            self.cooldown = 1
        return Action.D

class Strategy_OPPORTUNISTIC_38(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - opens with cooperation
    - tracks a smoothed trust estimate from observed opponent cooperation
    - uses stock-dependent thresholds with small adjustments for recent behavior
    - defects in the final round
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self._trust = 1.0
        self._last_processed_round = -1
        self._last_stock = None

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = int(self.game_description.n_players)
        r = int(self.game_description.n_rounds)
        capacity = float(self.game_description.capacity)
        round_number = int(history.round_number)
        n_opponents = max(n - 1, 0)
        if round_number == 0:
            self._trust = 1.0
            self._last_processed_round = -1
            self._last_stock = float(current_stock)
            return Action.C
        if self._last_processed_round != round_number - 1:
            trust = 1.0
            for idx in range(round_number):
                if n_opponents > 0:
                    q = float(history.opponent_cooperators[idx]) / float(n_opponents)
                else:
                    q = 0.0
                trust = 0.7 * trust + 0.3 * q
            self._trust = float(trust)
            self._last_processed_round = round_number - 1
        else:
            if n_opponents > 0:
                q_last = float(history.opponent_cooperators[-1]) / float(n_opponents)
            else:
                q_last = 0.0
            self._trust = float(0.7 * self._trust + 0.3 * q_last)
            self._last_processed_round = round_number
        trust = float(self._trust)
        qs = []
        for idx in range(round_number):
            if n_opponents > 0:
                qs.append(float(history.opponent_cooperators[idx]) / float(n_opponents))
            else:
                qs.append(0.0)
        last_three_same = False
        if round_number >= 3:
            last_three_same = abs(qs[-1] - qs[-2]) <= 1e-12 and abs(qs[-2] - qs[-3]) <= 1e-12
        last_two_high = False
        last_two_low = False
        if round_number >= 2:
            last_two_high = qs[-1] >= 2.0 / 3.0 and qs[-2] >= 2.0 / 3.0
            last_two_low = qs[-1] <= 1.0 / 3.0 and qs[-2] <= 1.0 / 3.0
        adjusted_trust = trust
        if last_two_high:
            adjusted_trust += 1.0 / 6.0
        elif last_two_low:
            adjusted_trust -= 1.0 / 6.0
        adjusted_trust = max(0.0, min(1.0, adjusted_trust))
        if round_number >= r - 1:
            self._last_stock = float(current_stock)
            return Action.D
        stock_falling = False
        if self._last_stock is not None:
            stock_falling = float(current_stock) < float(self._last_stock) - 1e-12
        if last_three_same and stock_falling:
            self._last_stock = float(current_stock)
            return Action.D
        one_third = capacity / 3.0
        two_thirds = 2.0 * capacity / 3.0
        if current_stock <= one_third:
            action = Action.C if adjusted_trust >= 0.5 else Action.D
        elif current_stock < two_thirds:
            action = Action.D if adjusted_trust >= 2.0 / 3.0 else Action.C
        else:
            action = Action.D if adjusted_trust >= 0.5 else Action.C
        self._last_stock = float(current_stock)
        return action

class Strategy_OPPORTUNISTIC_39(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - cooperate in healthy, sustained-cooperation states
    - defect when the pool is stressed, cooperation is dropping, or in the endgame
    - use a one-shot recovery test after successful post-defection recovery signals
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self._high_threshold = self.capacity / 2.0
        self._medium_threshold = self.capacity / 4.0
        self._last_seen_round = -1
        self._last_stock = None
        self._last_action = Action.D
        self._recovery_test_pending = False
        self._recovery_lockout = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        stock = float(current_stock)
        n_opponents = max(self.n_players - 1, 1)
        if round_number > 0 and len(history.opponent_cooperators) > 0:
            k = int(history.opponent_cooperators[-1])
        else:
            k = 0
        k = max(0, min(k, n_opponents))
        p = k / n_opponents if n_opponents > 0 else 0.0
        opp = history.opponent_cooperators
        last_p = None
        prev_p = None
        if len(opp) >= 1:
            last_p = int(opp[-1]) / n_opponents if n_opponents > 0 else 0.0
        if len(opp) >= 2:
            prev_p = int(opp[-2]) / n_opponents if n_opponents > 0 else 0.0
        last_two_full = False
        if len(opp) >= 2:
            last_two_full = int(opp[-1]) == n_opponents and int(opp[-2]) == n_opponents
        cooperation_not_fallen_two = True
        if len(opp) >= 3:
            a = int(opp[-3])
            b = int(opp[-2])
            c = int(opp[-1])
            cooperation_not_fallen_two = not a > b > c
        very_high_stock = stock >= self.capacity * 0.75
        if round_number >= self.n_rounds - 1:
            self._last_seen_round = round_number
            self._last_stock = stock
            self._last_action = Action.D
            self._recovery_test_pending = False
            self._recovery_lockout = False
            return Action.D
        if round_number == self.n_rounds - 2:
            action = Action.D
            if stock >= self._high_threshold and last_p == 1.0 and (prev_p == 1.0) and very_high_stock:
                action = Action.C
            self._last_seen_round = round_number
            self._last_stock = stock
            self._last_action = action
            self._recovery_test_pending = False
            return action
        if self._recovery_test_pending:
            self._recovery_test_pending = False
            action = Action.C
            self._last_seen_round = round_number
            self._last_stock = stock
            self._last_action = action
            return action
        if self._recovery_lockout:
            if stock >= self._high_threshold and p >= 0.5 and cooperation_not_fallen_two:
                self._recovery_lockout = False
            else:
                self._last_seen_round = round_number
                self._last_stock = stock
                self._last_action = Action.D
                return Action.D
        if round_number == 0:
            action = Action.C if stock >= self._high_threshold else Action.D
            self._last_seen_round = round_number
            self._last_stock = stock
            self._last_action = action
            return action
        if self._last_action == Action.D and self._last_stock is not None:
            if stock > float(self._last_stock) and p == 1.0:
                self._recovery_test_pending = True
                action = Action.C
                self._last_seen_round = round_number
                self._last_stock = stock
                self._last_action = action
                return action
        if stock < self._medium_threshold:
            action = Action.D
        elif stock < self._high_threshold:
            action = Action.D
        elif p < 0.5:
            action = Action.D
        elif p >= 2.0 / 3.0:
            if last_two_full:
                action = Action.C
            else:
                action = Action.D if random.random() < 0.5 else Action.C
        elif cooperation_not_fallen_two:
            action = Action.C
        else:
            action = Action.D
        if stock >= self._high_threshold and p >= 0.5 and (not cooperation_not_fallen_two):
            action = Action.D
        if action == Action.D and self._last_action == Action.C and (self._recovery_test_pending is False):
            if stock < self._high_threshold or p < 1.0:
                self._recovery_lockout = True
        self._last_seen_round = round_number
        self._last_stock = stock
        self._last_action = action
        return action

class Strategy_OPPORTUNISTIC_40(BaseStrategy):
    """
    State-contingent threshold strategy with probe, reciprocity, and endgame acceleration.
    Defaults to cooperation only under strong, sustained cooperation and ample stock.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.T = int(math.ceil(self.r / 3))
        self.L = int(math.ceil(self.r / 5))
        self.permanent_defect = False
        self.last_decision: Action | None = None
        self.last_x: float | None = None
        self.consecutive_defections = 0
        self.last_was_full_coop = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number + 1
        stock = float(current_stock)
        n_opponents = max(0, self.n - 1)
        prev_opps = int(history.opponent_cooperators[-1]) if history.round_number > 0 else 0
        prev_x = prev_opps / n_opponents if n_opponents > 0 else 1.0
        prev_prev_x = None
        if history.round_number > 1:
            prev_prev_opps = int(history.opponent_cooperators[-2])
            prev_prev_x = prev_prev_opps / n_opponents if n_opponents > 0 else 1.0
        prev_my_action = bool(history.my_actions[-1]) if history.round_number > 0 else True
        x_t = prev_x
        x_bar = float(np.mean(history.opponent_cooperators / n_opponents)) if history.round_number > 0 and n_opponents > 0 else 1.0
        if history.round_number > 0 and n_opponents == 0:
            x_bar = 1.0
        final_window = t > self.r - self.L
        calibration_window = t <= self.T
        main_window = t > self.T and t <= self.r - self.L
        self.last_was_full_coop = prev_x == 1.0
        if self.consecutive_defections >= 2 and self.last_x is not None and (self.last_x < 0.5):
            self.permanent_defect = True
        if history.round_number == 0:
            self.last_decision = Action.C
            self.last_x = None
            self.consecutive_defections = 0
            return Action.C
        if self.permanent_defect:
            self.last_decision = Action.D
            self.last_x = x_t
            self.consecutive_defections += 1
            return Action.D
        if self.n == 2:
            if x_t == 1.0 and stock >= 0.85 * self.capacity and (not final_window):
                action = Action.C
            else:
                action = Action.D
        elif stock < 0.5 * self.capacity or x_t < 0.5:
            action = Action.D
        elif stock <= 2 * self.n and (not (x_t == 1.0 and t < self.r)):
            action = Action.D
        elif prev_my_action == Action.D:
            can_recover = x_t == 1.0 and stock >= 0.8 * self.capacity and (prev_prev_x == 1.0 if prev_prev_x is not None else True)
            action = Action.C if can_recover else Action.D
        elif final_window:
            if x_t == 1.0 and stock >= 0.85 * self.capacity and self.last_was_full_coop:
                action = Action.C
            else:
                action = Action.D
        elif calibration_window:
            if x_t >= 0.75 and stock >= 0.75 * self.capacity and (prev_opps >= 2):
                action = Action.C
            else:
                action = Action.D
        elif main_window:
            high_trust = x_bar >= 0.7
            stable_stock = stock >= 0.7 * self.capacity
            recent_slack = x_t >= 0.7
            action = Action.C if high_trust and stable_stock and recent_slack else Action.D
        else:
            action = Action.D
        if t == self.r and stock >= 0.85 * self.capacity and (not self.last_was_full_coop):
            action = Action.D
        if action == Action.D:
            self.consecutive_defections += 1
        else:
            self.consecutive_defections = 0
        self.last_decision = action
        self.last_x = x_t
        return action

class Strategy_OPPORTUNISTIC_41(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Cooperate in round 1.
    - Thereafter, cooperate only in strongly cooperative, high-stock, early-enough states.
    - Defect in the final round and generally when stock is low or cooperation weak.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(self.n_players - 1, 0)
        self.low_stock_threshold = self.capacity / 3.0
        self.high_stock_threshold = self.capacity / 2.0
        self.very_high_stock_threshold = 3.0 * self.capacity / 4.0
        self.coop_fraction_threshold = 2.0 / 3.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number + 1
        stock = float(current_stock)
        if history.round_number == 0:
            return Action.C
        if t >= self.n_rounds:
            return Action.D
        if stock <= self.low_stock_threshold:
            return Action.D
        if self.n_opponents <= 0:
            return Action.D
        past_counts = history.opponent_cooperators
        if len(past_counts) == 0:
            return Action.D
        recent_counts = past_counts[-3:]
        recent_q = [float(x) / float(self.n_opponents) for x in recent_counts]
        q_prev = recent_q[-1]
        m_t = float(np.mean(recent_q)) if len(recent_q) > 0 else 0.0
        rounds_left_including_current = self.n_rounds - t + 1
        if q_prev >= self.coop_fraction_threshold and m_t >= self.coop_fraction_threshold and (stock >= self.high_stock_threshold) and (rounds_left_including_current >= 3):
            return Action.C
        if q_prev >= 1.0 and stock >= self.very_high_stock_threshold and (rounds_left_including_current >= 2):
            return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_42(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Start by cooperating.
    - Defect when the stock is healthy and recent cooperation is strong.
    - Cooperate when stock is low, cooperation weakens, or endgame risk is high.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self._last_action: Action | None = None
        self._prev_action: Action | None = None
        self._last_stock: float | None = None

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = max(2, self.n)
        capacity = max(1.0, float(self.capacity))
        t = int(history.round_number)
        if t == 0:
            action = Action.C
            self._prev_action = self._last_action
            self._last_action = action
            self._last_stock = float(current_stock)
            return action
        stock = float(current_stock)
        prev_stock = self._last_stock if self._last_stock is not None else stock
        last_k = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        n_opponents = max(0, n - 1)
        base_threshold = math.ceil(0.6 * n_opponents)
        if t <= 2 and stock >= 0.9 * capacity:
            threshold = math.ceil(0.75 * n_opponents)
        else:
            threshold = base_threshold
        half_opponents = math.ceil(n_opponents / 2)
        if self._last_action == Action.C:
            implied_k = last_k + 1
        else:
            implied_k = last_k
        if t >= self.r - 1:
            action = Action.D if stock > 2 * n and last_k >= half_opponents else Action.C
        else:
            if prev_stock is not None and stock > prev_stock:
                action = self._last_action if self._last_action is not None else Action.C
            elif prev_stock is not None and stock < prev_stock and (stock < 0.8 * prev_stock):
                action = Action.C if implied_k <= threshold else Action.D
            elif stock <= 2 * n or stock <= 0.25 * capacity:
                action = Action.C
            elif implied_k >= threshold:
                action = Action.D
            else:
                action = Action.C
            if len(history.my_actions) >= 2 and len(history.opponent_cooperators) >= 1:
                last_two_my = history.my_actions[-2:]
                latest_k = int(history.opponent_cooperators[-1])
                if bool(last_two_my[-2]) is False and bool(last_two_my[-1]) is False:
                    if latest_k < threshold:
                        action = Action.C
                if bool(last_two_my[-2]) is True and bool(last_two_my[-1]) is True:
                    if latest_k >= threshold + 1:
                        action = Action.D
        self._prev_action = self._last_action
        self._last_action = action
        self._last_stock = stock
        return action

class Strategy_OPPORTUNISTIC_43(BaseStrategy):
    """
    Harvest early, preserve only under sustained cooperation and healthy stock.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.threshold = int(math.ceil((self.n - 1) / 2.0))
        self.mode = 'harvest'

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        if round_number == 0:
            self.mode = 'harvest'
            return Action.D
        if round_number >= self.r - 1:
            self.mode = 'harvest'
            return Action.D
        if current_stock <= self.capacity / 3.0:
            self.mode = 'harvest'
            return Action.D
        if round_number == 1:
            h_1 = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) >= 1 else 0
            if current_stock >= 3.0 * self.capacity / 4.0 and h_1 == self.n - 1:
                self.mode = 'preserve'
                return Action.C
            self.mode = 'harvest'
            return Action.D
        h_prev = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) >= 1 else 0
        h_prev2 = int(history.opponent_cooperators[-2]) if len(history.opponent_cooperators) >= 2 else 0
        stock_healthy = current_stock >= self.capacity / 2.0
        cooperation_sustained = h_prev >= self.threshold and h_prev2 >= self.threshold
        if self.mode == 'preserve':
            if stock_healthy and h_prev >= self.threshold:
                return Action.C
            self.mode = 'harvest'
            return Action.D
        if stock_healthy and cooperation_sustained:
            self.mode = 'preserve'
            return Action.C
        self.mode = 'harvest'
        return Action.D

class Strategy_OPPORTUNISTIC_44(BaseStrategy):
    """
    Adaptive common-pool strategy with:
    - initial cooperation,
    - exponentially weighted belief tracking (q),
    - recovery after low cooperation / low stock,
    - opportunistic defection against highly cooperative groups,
    - and a hard final-round defection bias.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.q = 1.0
        self._forced_defect_until_recovery = False
        self._opportunistic_defect_rounds = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        cap = self.capacity
        n_opponents = max(self.n_players - 1, 1)
        if round_number == 0:
            return Action.C
        last_coops = int(history.opponent_cooperators[-1]) if round_number > 0 else 0
        prev_coops = int(history.opponent_cooperators[-2]) if round_number > 1 else None
        p = last_coops / n_opponents if n_opponents > 0 else 0.0
        self.q = 0.7 * self.q + 0.3 * p
        if self._opportunistic_defect_rounds > 0 and p < 0.75:
            self._opportunistic_defect_rounds = 0
        if self._forced_defect_until_recovery and p >= 0.5:
            self._forced_defect_until_recovery = False
        if round_number >= self.n_rounds - 1:
            return Action.D
        remaining_rounds_including_current = self.n_rounds - round_number
        if remaining_rounds_including_current <= 3:
            if p == 1.0 and current_stock < cap / 4.0:
                return Action.C
            return Action.D
        if self._forced_defect_until_recovery:
            return Action.D
        if self._opportunistic_defect_rounds > 0:
            self._opportunistic_defect_rounds -= 1
            return Action.D
        if p < 0.5 and current_stock < cap / 3.0:
            if prev_coops == 0 and last_coops == 0:
                self._forced_defect_until_recovery = True
                return Action.D
            return Action.C
        if p >= 0.75 and current_stock > cap / 2.0:
            if p == 1.0 and current_stock > 0.8 * cap:
                self._opportunistic_defect_rounds = 2
            return Action.D
        if p >= 0.75 and (current_stock <= cap / 2.0 or self.q >= 0.8):
            return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_45(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Starts with cooperation.
    - Uses recent opponent cooperation rates to switch between exploitation,
      conditional cooperation, and punishment.
    - Applies a mild stock-based bias when current stock is clearly high/low.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(getattr(game_description, 'n_players', 2))
        self.n_rounds = int(getattr(game_description, 'n_rounds', 2))
        self.capacity = float(getattr(game_description, 'capacity', 1.0))
        self.n_opponents = max(1, self.n_players - 1)
        self.low_threshold = 1.0 / 3.0
        self.high_threshold = 2.0 / 3.0

    def _rate_from_count(self, coop_count: int) -> float:
        denom = self.n_opponents
        if denom <= 0:
            return 0.0
        return float(coop_count) / float(denom)

    def _recent_stats(self, history: PlayerHistory):
        rounds_seen = history.round_number
        if rounds_seen <= 0:
            return ([], 0.0, 0.0)
        rates = [self._rate_from_count(int(c)) for c in history.opponent_cooperators[:rounds_seen]]
        latest = rates[-1]
        m = min(5, len(rates))
        recent = float(np.mean(rates[-m:])) if m > 0 else latest
        return (rates, latest, recent)

    def _bias_action(self, base_action: Action, current_stock: float) -> Action:
        if self.capacity <= 0:
            return base_action
        ratio = float(current_stock) / float(self.capacity)
        if ratio >= 0.8:
            return Action.D
        if ratio <= 0.35:
            return Action.C
        return base_action

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number + 1
        rates, latest, recent = self._recent_stats(history)
        if t == 1:
            base = Action.C
            return self._bias_action(base, current_stock)
        opportunistic = False
        if len(rates) >= 2:
            if rates[-1] >= self.high_threshold and rates[-2] >= self.high_threshold:
                opportunistic = True
        if len(rates) >= 1 and rates[-1] >= 1.0:
            opportunistic = True
        if len(history.my_actions) >= 1:
            last_my_action = bool(history.my_actions[-1])
            if not last_my_action and latest <= self.low_threshold:
                return self._bias_action(Action.C, current_stock)
        if t >= max(1, self.n_rounds - 1):
            base = Action.D if latest >= 0.5 else Action.C
            if opportunistic and latest >= self.high_threshold:
                base = Action.D
            elif opportunistic and latest < self.high_threshold:
                opportunistic = False
            return self._bias_action(base, current_stock)
        if opportunistic and latest >= self.high_threshold:
            return self._bias_action(Action.D, current_stock)
        if recent >= self.high_threshold:
            base = Action.D
        elif recent <= self.low_threshold:
            base = Action.D if latest <= self.low_threshold else Action.C
        elif latest - recent >= 0.2:
            base = Action.D
        elif recent - latest >= 0.2:
            base = Action.C
        else:
            base = Action.D if latest >= 0.5 else Action.C
        return self._bias_action(base, current_stock)

class Strategy_OPPORTUNISTIC_46(BaseStrategy):
    """
    Cooperate initially, then adapt to the current stock level and the
    previous round's opponent cooperation rate.

    Rules:
    - Round 1: cooperate.
    - Last round: defect.
    - Preserve a depleted pool (stock <= capacity/4): cooperate.
    - Exploit a very healthy pool when opponents are at least majority cooperative:
      if stock >= 3*capacity/4 and opponent cooperation rate >= 1/2, defect.
    - If all opponents cooperated last round, defect unless the pool is at or below
      half capacity.
    - Otherwise cooperate when stock is at or below half capacity or when the
      opponent cooperation rate is below 1/2; defect otherwise.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.capacity = float(game_description.capacity)
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        if round_number == 0:
            return Action.C
        if round_number >= self.n_rounds - 1:
            return Action.D
        last_opponent_cooperators = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        n_opponents = max(self.n_players - 1, 1)
        c = last_opponent_cooperators / n_opponents
        s = float(current_stock)
        cap = self.capacity
        if s <= cap / 4.0:
            return Action.C
        if c == 1.0 and s > cap / 2.0:
            return Action.D
        if s >= 3.0 * cap / 4.0 and c >= 0.5:
            return Action.D
        if s <= cap / 2.0 or c < 0.5:
            return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_47(BaseStrategy):
    """
    Adaptive common-pool strategy that alternates between restoring the stock
    and harvesting it, based on inferred opponent cooperation and current stock.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.p_hat = 0.5
        self.mode = 'restore'
        self._last_seen_round = -1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = int(self.game_description.n_players)
        r = int(self.game_description.n_rounds)
        capacity = float(self.game_description.capacity)
        n_opponents = max(n - 1, 0)
        k_safe = math.ceil(n_opponents / 2) if n_opponents > 0 else 0
        round_index = int(history.round_number)
        t = round_index + 1
        L = r - t + 1
        if round_index == 0:
            return Action.C if capacity >= 3 * n else Action.D
        if t >= r:
            return Action.D
        c_last = None
        if len(history.opponent_cooperators) > 0:
            c_last = int(history.opponent_cooperators[-1])
        if round_index != self._last_seen_round and c_last is not None:
            denom = n_opponents if n_opponents > 0 else 1
            observed_fraction = c_last / denom
            self.p_hat = 0.7 * self.p_hat + 0.3 * observed_fraction
            if c_last >= k_safe:
                self.mode = 'restore'
            else:
                self.mode = 'harvest'
            self._last_seen_round = round_index
        if t == r - 1:
            if current_stock >= capacity / 2 and c_last is not None and (c_last >= k_safe):
                return Action.C
            return Action.D
        if current_stock <= capacity / 4:
            return Action.D
        if c_last is not None and c_last < k_safe:
            return Action.D
        if c_last is not None and c_last >= max(n - 2, 0):
            return Action.C if current_stock >= capacity / 2 else Action.D
        two_consecutive_good = False
        if len(history.opponent_cooperators) >= 2:
            c_prev = int(history.opponent_cooperators[-2])
            two_consecutive_good = c_prev >= k_safe and (c_last is not None and c_last >= k_safe)
        if two_consecutive_good:
            self.mode = 'restore'
        if self.mode == 'restore' and self.p_hat >= 0.5 and (current_stock > capacity / 4) and (not (L <= 2 and current_stock < 3 * capacity / 4)):
            return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_48(BaseStrategy):
    """
    State-contingent threshold strategy for the Common Pool Resource game.

    Behavior:
    - Cooperate in round 1.
    - Defect in the final round.
    - Use stock-sensitive and opponent-cooperation thresholds to switch between
      cooperation for rebuilding/probing and defection for exploitation/harvesting.
    - Maintain a short running average of opponent cooperation from the last up to
      three rounds when data are available.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.m = max(self.n - 1, 0)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.n
        r = self.r
        capacity = self.capacity
        m = self.m
        t = int(history.round_number) + 1
        T = r - t + 1
        if t == 1:
            return Action.C
        try:
            opp_hist = history.opponent_cooperators
            if opp_hist is None:
                return Action.D
        except Exception:
            return Action.D
        if T <= 1:
            return Action.D
        if capacity <= 0:
            p = 0.0
        else:
            p = float(current_stock) / capacity
        if p < 0.0:
            p = 0.0
        elif p > 1.0:
            p = 1.0
        if n == 2:
            last_opp = int(opp_hist[-1]) if len(opp_hist) > 0 else -1
            if last_opp == 1 and p < 0.75:
                return Action.C
            return Action.D
        try:
            last_k = int(opp_hist[-1]) if len(opp_hist) > 0 else 0
        except Exception:
            return Action.D
        if m <= 0:
            x = 0.0
        else:
            x = last_k / m
        recent = opp_hist[-3:] if len(opp_hist) > 0 else []
        if len(recent) > 0 and m > 0:
            a = float(np.mean(np.asarray(recent, dtype=float) / m))
        else:
            a = 0.0
        theta = 0.5 + 1.0 / (4.0 * m) if m > 0 else 1.0
        if p <= 0.5:
            return Action.C
        if p >= 0.75:
            if x == 0.0 and T > 2:
                return Action.C
            return Action.D
        if x < 0.5:
            if x == 0.0 and T > 2 and (p < 0.75):
                if T % 3 == 0:
                    return Action.C
                return Action.D
            if T > 2 and p < 0.75:
                return Action.C
            return Action.D
        if a >= 2.0 / 3.0 and p >= 0.5:
            return Action.D
        if a <= 1.0 / 3.0 and p <= 2.0 / 3.0:
            return Action.C
        if x >= theta:
            return Action.D
        if x < theta:
            return Action.C
        return Action.C if p < 2.0 / 3.0 else Action.D

class Strategy_OPPORTUNISTIC_49(BaseStrategy):
    """
    Estimate opponent cooperativeness and choose the action that balances
    immediate payoff with expected future stock value.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.alpha = 0.5
        self.q0 = 0.5

    def _next_stock(self, x: float) -> float:
        capacity = float(self.game_description.capacity)
        x = max(0.0, float(x))
        growth = 2.0 * x * (1.0 - x / capacity) if capacity > 0 else 0.0
        return min(x + growth, capacity)

    def _estimate_q(self, history: PlayerHistory) -> float:
        q = self.q0
        n_opponents = max(self.game_description.n_players - 1, 1)
        for observed_cooperators in history.opponent_cooperators:
            obs_rate = float(observed_cooperators) / float(n_opponents)
            q = self.alpha * q + (1.0 - self.alpha) * obs_rate
        return min(1.0, max(0.0, q))

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = int(self.game_description.n_players)
        r = int(self.game_description.n_rounds)
        capacity = float(self.game_description.capacity)
        S = float(current_stock)
        t = int(history.round_number) + 1
        if t == 1:
            return Action.C
        if t >= r:
            return Action.D
        if S <= 0.0:
            return Action.D
        q = self._estimate_q(history)
        denom_n = float(max(n, 1))
        lambda_t = float(r - t) / float(max(r - 1, 1))
        opp_cons = q * (S / (2.0 * denom_n)) + (1.0 - q) * (S / denom_n)
        S_C_pre = S - S / (2.0 * denom_n) - (n - 1) * opp_cons
        S_D_pre = S - S / denom_n - (n - 1) * opp_cons
        S_C = self._next_stock(S_C_pre)
        S_D = self._next_stock(S_D_pre)
        score_C = S / (2.0 * denom_n) + lambda_t * (S_C / capacity if capacity > 0 else 0.0)
        score_D = S / denom_n + lambda_t * (S_D / capacity if capacity > 0 else 0.0)
        if score_D >= score_C:
            return Action.D
        return Action.C

class Strategy_OPPORTUNISTIC_50(BaseStrategy):
    """
    Adaptive common-pool strategy that cooperates under low/unstable cooperation,
    defects when the pool is healthy and others are sustaining it, and adjusts a
    personal cooperation threshold based on recent group behavior.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = max(2, int(game_description.n_players))
        self.r = max(1, int(game_description.n_rounds))
        self.capacity = float(game_description.capacity)
        base_threshold = math.ceil(self.n / 2) + 1
        self.threshold = max(1, min(self.n - 1, base_threshold))

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.n
        r = self.r
        capacity = self.capacity
        t = history.round_number
        S = float(current_stock)
        if S < 0.0:
            S = 0.0
        elif S > capacity:
            S = capacity
        n_opponents = max(0, n - 1)

        def coop_threshold_base() -> int:
            return max(1, min(n - 1, int(self.threshold)))

        def stable_cooperators() -> int:
            return max(1, min(n - 1, math.ceil(n / 2)))

        def safe_cooperators() -> int:
            return max(1, min(n - 1, math.ceil(n / 2) + 1))

        def update_threshold_from_history() -> None:
            if t < 2 or n < 3:
                return
            last_k = int(history.opponent_cooperators[-1])
            prev_k = int(history.opponent_cooperators[-2])
            full_coop = last_k == n_opponents and prev_k == n_opponents
            weak_cutoff = math.ceil(n / 3)
            weak_coop = last_k <= weak_cutoff and prev_k <= weak_cutoff
            if full_coop:
                self.threshold = max(1, self.threshold - 1)
            if weak_coop:
                self.threshold = min(n - 1, self.threshold + 1)
        if t == 0:
            return Action.C if n == 2 else Action.D
        if t >= r - 1:
            return Action.D if S > 0.0 else Action.C
        update_threshold_from_history()
        k = int(history.opponent_cooperators[-1]) if t > 0 else 0
        low_stock = S < 0.4 * capacity
        high_stock = S > 0.75 * capacity
        if low_stock:
            return Action.D if k >= max(0, n - 2) else Action.C
        if high_stock:
            return Action.D if k >= stable_cooperators() else Action.C
        threshold = coop_threshold_base()
        if threshold < safe_cooperators():
            threshold = safe_cooperators()
        return Action.D if k >= threshold else Action.C

class Strategy_OPPORTUNISTIC_51(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Cooperate in the first round.
    - Defect in the final round.
    - In the penultimate round, cooperate only if the stock is at or below half capacity.
    - Otherwise, use stock thresholds and the previous round's opponent cooperation level
      to decide between cooperative restraint and aggressive extraction.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        m = max(self.n_players - 1, 1)
        self.m = m
        self.high = math.ceil(2 * m / 3)
        self.majority = math.ceil(m / 2)
        self.low_stock = self.capacity / 3.0
        self.mid_stock = 2.0 * self.capacity / 3.0
        self.half_capacity = self.capacity / 2.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number
        if t == 0:
            return Action.C
        if t >= self.n_rounds - 1:
            return Action.D
        if t == self.n_rounds - 2:
            return Action.C if current_stock <= self.half_capacity else Action.D
        c_last = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        S = float(current_stock)
        if S <= self.low_stock:
            return Action.C
        elif c_last >= self.high:
            return Action.D
        elif c_last >= self.majority and S >= self.mid_stock:
            return Action.D
        elif c_last < self.majority and S > self.half_capacity:
            return Action.D
        else:
            return Action.C

class Strategy_OPPORTUNISTIC_52(BaseStrategy):
    """
    Trust-based common pool strategy:
    - Start with cooperation to probe the group.
    - Track a smoothed trust score from observed opponent cooperation.
    - Cooperate only when trust, recent cooperation, and stock are all sufficiently high.
    - Defect when stock is low, cooperation weakens, or the endgame approaches.
    - Occasionally probe cooperation again after a clear rebound.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(self.n_players - 1, 0)
        self.trust_initial = 1.0

    def _cooperation_rate(self, opponent_cooperators: int) -> float:
        if self.n_opponents <= 0:
            return 0.0
        return float(opponent_cooperators) / float(self.n_opponents)

    def _compute_trust(self, history: PlayerHistory) -> float:
        trust = self.trust_initial
        rounds = history.round_number
        if rounds <= 0:
            return trust
        opp = history.opponent_cooperators
        for t in range(rounds):
            q_t = self._cooperation_rate(int(opp[t]))
            trust = 0.7 * trust + 0.3 * q_t
        return trust

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        rounds_played = history.round_number
        if rounds_played == 0:
            return Action.C
        if rounds_played >= self.n_rounds - 1:
            return Action.D
        stock = float(current_stock)
        cap = self.capacity
        if stock < 0.45 * cap:
            return Action.D
        trust = self._compute_trust(history)
        last_q = self._cooperation_rate(int(history.opponent_cooperators[-1]))
        prev_q = None
        if rounds_played >= 2:
            prev_q = self._cooperation_rate(int(history.opponent_cooperators[-2]))
        rounds_left_including_next = self.n_rounds - rounds_played
        if rounds_left_including_next <= 2:
            if last_q == 1.0 and stock >= 0.8 * cap:
                return Action.C
            return Action.D
        if prev_q is not None and last_q - prev_q >= 0.2 and (stock >= 0.6 * cap):
            return Action.C
        if trust >= 0.65 and last_q >= 0.6 and (stock >= 0.55 * cap):
            return Action.C
        if 0.35 <= trust < 0.65:
            if last_q >= 0.75 and stock >= 0.65 * cap:
                return Action.C
            return Action.D
        return Action.D

class Strategy_OPPORTUNISTIC_53(BaseStrategy):
    """
    Adaptive common-pool strategy:
    cooperate early, then condition cooperation on recent opponent cooperation,
    stock level, and last-round stock trend; defect in low-trust or final-round
    situations to exploit remaining stock.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(self.n_players - 1, 0)
        self.high_trust_threshold = 0.5
        self.low_stock_threshold_quarter = self.capacity / 4.0
        self.low_stock_threshold_third = self.capacity / 6.0
        self.low_stock_threshold_half = self.capacity / 2.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t0 = history.round_number
        if t0 == 0:
            return Action.C
        if t0 >= self.n_rounds - 2:
            return Action.D if current_stock > 0 else Action.D
        prev_opp_coops = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        if self.n_opponents <= 0:
            q = 0.0
        else:
            q = prev_opp_coops / self.n_opponents
        stock_after_rounds = []
        stock = self.capacity
        n = self.n_players
        for idx in range(len(history.my_actions)):
            my_action = bool(history.my_actions[idx])
            opp_coops = int(history.opponent_cooperators[idx]) if idx < len(history.opponent_cooperators) else 0
            opp_defs = self.n_opponents - opp_coops
            total_consumption = 0.0
            if my_action:
                total_consumption += stock / (2.0 * n)
            else:
                total_consumption += stock / n
            total_consumption += opp_coops * (stock / (2.0 * n))
            total_consumption += opp_defs * (stock / n)
            remaining = stock - total_consumption
            if remaining < 0.0:
                remaining = 0.0
            growth = 2.0 * remaining * (1.0 - remaining / self.capacity) if self.capacity > 0 else 0.0
            stock = remaining + growth
            if stock > self.capacity:
                stock = self.capacity
            if stock < 0.0:
                stock = 0.0
            stock_after_rounds.append(stock)
        nondecreasing_last_two = False
        fallen_two_consecutive = False
        if len(stock_after_rounds) >= 2:
            s1 = stock_after_rounds[-2]
            s2 = stock_after_rounds[-1]
            nondecreasing_last_two = s2 >= s1
            fallen_two_consecutive = s2 < s1
            if len(stock_after_rounds) >= 3:
                s0 = stock_after_rounds[-3]
                fallen_two_consecutive = s2 < s1 and s1 < s0
        if fallen_two_consecutive or q < self.high_trust_threshold:
            return Action.D
        if nondecreasing_last_two and q >= self.high_trust_threshold:
            return Action.C
        if q >= 1.0:
            return Action.C if current_stock >= self.low_stock_threshold_third else Action.D
        if q <= 1.0 / 3.0:
            return Action.D
        if q >= 1.0 / 2.0:
            return Action.C if current_stock >= self.low_stock_threshold_quarter else Action.D
        if q > 1.0 / 3.0:
            return Action.C if current_stock >= self.low_stock_threshold_half else Action.D
        return Action.D

class Strategy_OPPORTUNISTIC_54(BaseStrategy):
    """
    Probe in round 1, defect in the final round, and otherwise exploit when
    the recent opponent majority cooperated while conserving after defection.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.last_q = None
        self.coop_streak = 0
        self.defect_streak = 0
        self.last_seen_round = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        n_rounds = self.game_description.n_rounds
        n_players = self.game_description.n_players
        n_opponents = max(0, n_players - 1)
        if round_number == 0:
            self.last_q = None
            self.coop_streak = 0
            self.defect_streak = 0
            self.last_seen_round = 0
            return Action.C
        if round_number > self.last_seen_round and len(history.opponent_cooperators) > 0:
            recent_opponents = int(history.opponent_cooperators[-1])
            if n_opponents > 0:
                q = recent_opponents / n_opponents
            else:
                q = 0.0
            self.last_q = q
            if q >= 0.5:
                self.coop_streak += 1
                self.defect_streak = 0
            else:
                self.defect_streak += 1
                self.coop_streak = 0
            self.last_seen_round = round_number
        if round_number >= n_rounds - 1:
            return Action.D
        if self.coop_streak >= 1:
            return Action.D
        if self.defect_streak >= 1:
            return Action.C
        return Action.C

class Strategy_OPPORTUNISTIC_55(BaseStrategy):
    """
    Opportunistic common-pool strategy with smoothed cooperation estimates,
    short-memory streak detection, and conservative endgame behavior.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(1, self.n_players - 1)
        self._p_hat = 1.0
        self._processed_rounds = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.n_players
        n_opp = self.n_opponents
        cap = self.capacity
        t = int(history.round_number)
        r = self.n_rounds
        if t > self._processed_rounds:
            start = self._processed_rounds
            end = t
            for idx in range(start, end):
                k = int(history.opponent_cooperators[idx])
                rate = k / n_opp if n_opp > 0 else 0.0
                self._p_hat = 0.7 * self._p_hat + 0.3 * rate
            self._processed_rounds = t
        if t == 0:
            return Action.C
        if t >= r - 1:
            return Action.D
        last_k = int(history.opponent_cooperators[-1]) if t > 0 else 0
        prev_k = int(history.opponent_cooperators[-2]) if t > 1 else last_k
        last_rate = last_k / n_opp if n_opp > 0 else 0.0
        prev_rate = prev_k / n_opp if n_opp > 0 else 0.0
        half_opp = math.ceil(n_opp / 2)
        high_opp = math.ceil(0.8 * n_opp)
        low_opp = math.floor(n_opp / 3)
        window = min(3, t)
        if window > 0:
            recent = history.opponent_cooperators[-window:]
            u = float(np.mean(recent / n_opp)) if n_opp > 0 else 0.0
        else:
            u = 0.0
        low_stock = cap / 4.0
        high_stock = 3.0 * cap / 4.0
        mid_stock = cap / 3.0
        if current_stock <= low_stock:
            return Action.D
        two_recent_low = False
        if t >= 2:
            k1 = int(history.opponent_cooperators[-1])
            k2 = int(history.opponent_cooperators[-2])
            two_recent_low = k1 <= low_opp and k2 <= low_opp
        recovery_condition = last_k >= half_opp or (current_stock >= high_stock and self._p_hat >= 0.75)
        if two_recent_low and (not recovery_condition):
            return Action.D
        two_recent_high = False
        if t >= 2:
            k1 = int(history.opponent_cooperators[-1])
            k2 = int(history.opponent_cooperators[-2])
            two_recent_high = k1 >= high_opp and k2 >= high_opp
        if two_recent_high and current_stock > low_stock:
            return Action.C
        if t > 0 and last_k < half_opp:
            return Action.D
        if current_stock >= high_stock:
            return Action.C if self._p_hat >= 0.75 else Action.D
        if last_k >= half_opp and self._p_hat >= 0.5 and (current_stock >= mid_stock):
            return Action.C
        if last_k >= half_opp and self._p_hat >= 0.5 and (current_stock >= mid_stock):
            return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_56(BaseStrategy):
    """
    Threshold-and-escalation strategy for the Common Pool Resource Game.

    Starts cooperatively, exploits sustained high cooperation when the stock is healthy,
    conserves when cooperation weakens or the stock is scarce, and probes in mixed states.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.mode = 'probe'
        self.trust = 0.0
        self.bad_streak = 0
        self.good_streak = 0
        self.last_action = Action.C

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = max(2, self.n)
        n_opponents = max(1, n - 1)
        round_no = history.round_number
        if round_no == 0:
            self.mode = 'probe'
            self.trust = 0.0
            self.bad_streak = 0
            self.good_streak = 0
            self.last_action = Action.C
            return Action.C
        opp = history.opponent_cooperators
        my_actions = history.my_actions

        def clamp(x: float, lo: float, hi: float) -> float:
            return max(lo, min(hi, x))

        def coop_rate(idx: int) -> float:
            if idx < 0 or idx >= len(opp):
                return 0.0
            return float(opp[idx]) / float(n_opponents)

        def stock_mean_recent(k: int=2) -> float | None:
            return None
        x_prev = coop_rate(-1)
        good_streak = 0
        bad_streak = 0
        for i in range(len(opp)):
            x = float(opp[i]) / float(n_opponents)
            if x >= 0.75:
                good_streak += 1
                bad_streak = 0
            elif x <= 0.25:
                bad_streak += 1
                good_streak = 0
            else:
                good_streak = 0
                bad_streak = 0
        trust = 0.0
        for i in range(len(opp)):
            x = float(opp[i]) / float(n_opponents)
            trust = clamp(trust + (x - 0.5), -2.0, 2.0)
        prev_x = coop_rate(-2) if round_no >= 2 else None
        all_coop_two = round_no >= 2 and float(opp[-1]) == float(n_opponents) and (float(opp[-2]) == float(n_opponents))
        if round_no >= self.r - 1:
            if round_no >= 1 and x_prev >= 0.5:
                self.mode = 'exploit'
                self.last_action = Action.D
                return Action.D
            self.mode = 'conserve'
            self.last_action = Action.C
            return Action.C
        if round_no >= self.r - 2:
            if x_prev >= 0.5:
                self.mode = 'exploit'
                self.last_action = Action.D
                return Action.D
            self.mode = 'conserve'
            self.last_action = Action.C
            return Action.C
        if current_stock <= float(n) or bad_streak >= 2 or x_prev <= 0.25:
            self.mode = 'conserve'
        elif x_prev >= 0.75 and current_stock >= float(n) / 2.0 and (bad_streak == 0):
            self.mode = 'exploit'
        elif current_stock >= self.capacity * 0.9 and x_prev >= 0.5:
            self.mode = 'exploit'
        else:
            self.mode = 'probe'
        if x_prev >= 0.75 and current_stock >= float(n) / 2.0 and (bad_streak == 0):
            if all_coop_two and current_stock >= float(n):
                self.last_action = Action.D
                return Action.D
            if current_stock > float(n):
                self.last_action = Action.D
                return Action.D
        if x_prev <= 0.25 or bad_streak >= 2 or current_stock < float(n):
            self.last_action = Action.C
            return Action.C
        if current_stock <= 2.0 * float(n) and x_prev >= 0.5:
            self.last_action = Action.C
            return Action.C
        if 0.25 < x_prev < 0.75:
            if round_no % 2 == 1:
                self.last_action = Action.C
                return Action.C
            self.last_action = Action.D
            return Action.D
        if trust >= 0.5 and current_stock >= float(n):
            self.last_action = Action.D
            return Action.D
        self.last_action = Action.C
        return Action.C

class Strategy_OPPORTUNISTIC_57(BaseStrategy):
    """
    Stock-preserving baseline with opportunistic defection when the pool is
    healthy and opponents appear sustainable, plus defensive cooperation after
    sharp depletion or low observed cooperation.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.s_safe = self.capacity / 2.0
        self.s_low = self.capacity / 4.0
        self.s_critical = self.capacity / 8.0
        self.prev_stock = None
        self.force_coop_rounds = 0
        self.high_stock_streak = 0
        self.last_opponent_rate = None
        self.last_seen_round = -1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = int(history.round_number)
        c_hat = None
        if t > 0 and len(history.opponent_cooperators) >= t:
            opp_count = int(history.opponent_cooperators[-1])
            n_opponents = max(self.n - 1, 0)
            if n_opponents > 0:
                c_hat = opp_count / n_opponents
        stock_drop_large = False
        if self.prev_stock is not None:
            if self.prev_stock > 0:
                stock_drop_large = self.prev_stock - float(current_stock) > 0.5 * self.prev_stock
            else:
                stock_drop_large = False
        if c_hat is not None:
            self.last_opponent_rate = c_hat
            if c_hat < 0.5:
                self.force_coop_rounds = max(self.force_coop_rounds, 999999)
        if stock_drop_large:
            self.force_coop_rounds = max(self.force_coop_rounds, 2)
        if current_stock >= self.s_safe and (c_hat is not None and c_hat >= 0.75):
            self.high_stock_streak += 1
        else:
            self.high_stock_streak = 0
        if self.high_stock_streak >= 2 and current_stock >= self.s_safe:
            self.force_coop_rounds = 0
        if t == 0:
            if self.capacity >= 3.0 * self.n and self.n >= 3:
                action = Action.D
            elif self.r == 2 and current_stock == self.capacity:
                action = Action.C
            else:
                action = Action.C
            self.prev_stock = float(current_stock)
            self.last_seen_round = t
            return action
        if self.force_coop_rounds > 0:
            if self.force_coop_rounds < 999999:
                self.force_coop_rounds -= 1
            if current_stock > self.s_safe:
                self.force_coop_rounds = 0
            self.prev_stock = float(current_stock)
            self.last_seen_round = t
            return Action.C
        if c_hat is None:
            action = Action.C
        elif current_stock <= self.s_critical:
            action = Action.C
        elif t >= self.r - 1:
            action = Action.D if current_stock > 0 else Action.C
        elif self.n == 2:
            action = Action.D if current_stock >= self.s_safe and c_hat >= 1.0 else Action.C
        elif current_stock >= self.s_safe and c_hat >= 0.5:
            action = Action.D
        elif current_stock >= self.s_low and c_hat >= 0.75:
            action = Action.D
        else:
            action = Action.C
        if self.r == 2 and t == 1 and (current_stock == self.capacity) and (c_hat is None):
            action = Action.C
        self.prev_stock = float(current_stock)
        self.last_seen_round = t
        return action

class Strategy_OPPORTUNISTIC_58(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Cooperates in the first round.
    - Tracks opponent cooperation with a smoothed estimate qhat.
    - Defects in the final round.
    - Uses stock thresholds and recent/smoothed opponent behavior to switch
      between cooperation and defection, with late-game opportunism.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.qhat = 0.5
        self.floor_level = self.capacity / 4.0
        self.boom_level = self.capacity / 2.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        if round_number == 0:
            return Action.C
        n_opponents = max(self.n_players - 1, 1)
        last_k = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        observed_rate = last_k / n_opponents
        self.qhat = 0.7 * self.qhat + 0.3 * observed_rate
        rounds_left = self.n_rounds - round_number
        if rounds_left == 1:
            return Action.D
        S = float(current_stock)
        if rounds_left <= 3:
            if S >= self.boom_level:
                return Action.D
            return Action.C
        if S <= self.floor_level:
            return Action.C
        half_threshold = math.ceil(n_opponents / 2.0)
        if last_k >= half_threshold or self.qhat >= 0.5:
            return Action.D
        return Action.C

class Strategy_OPPORTUNISTIC_59(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Cooperates on round 1.
    - Defects on the final round.
    - In between, reacts to previous cooperation rate and stock health.
    - Uses a small trend adjustment based on the last two observed rounds.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = int(history.round_number)
        if t == 0:
            return Action.C
        if t >= self.r - 1:
            return Action.D
        n = self.n
        capacity = self.capacity
        if n <= 1:
            return Action.C
        k_prev = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        q_prev = k_prev / (n - 1) if n - 1 > 0 else 0.0
        h = float(current_stock) / capacity if capacity > 0 else 0.0
        if h <= 1.0 / (2.0 * n):
            action = Action.C
        elif q_prev >= 2.0 / 3.0 and h >= 1.0 / 3.0:
            action = Action.D
        elif q_prev <= 1.0 / 3.0 or h <= 1.0 / 4.0:
            action = Action.C
        elif k_prev >= (n - 1) / 2.0:
            action = Action.D
        else:
            action = Action.C
        if len(history.opponent_cooperators) >= 2:
            k_prev2 = int(history.opponent_cooperators[-2])
            delta_k = k_prev - k_prev2
            if delta_k > 0 and h >= 1.0 / 3.0 and (action == Action.C) and (q_prev >= 1.0 / 2.0):
                action = Action.D
            if (delta_k < 0 or h <= 1.0 / 4.0) and q_prev < 2.0 / 3.0:
                action = Action.C
        if current_stock <= 0:
            return Action.C
        return action

class Strategy_OPPORTUNISTIC_60(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Cooperate initially
    - Defect in the final round
    - Exploit sustained high cooperation when stock is healthy
    - Revert to cooperation when stock is weak or cooperation drops
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(self.n_players - 1, 1)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t_completed = int(history.round_number)
        t_current = t_completed + 1
        if t_current >= self.n_rounds:
            return Action.D
        if t_completed == 0:
            return Action.C
        cap = self.capacity
        stock = float(current_stock)
        low_stock = stock < 0.45 * cap
        high_stock = stock >= 0.65 * cap
        if stock <= 0.1 * cap:
            return Action.C
        if t_completed >= 1:
            last_opp_coop = int(history.opponent_cooperators[-1])
            if last_opp_coop >= self.n_players - 2 and high_stock:
                return Action.D
        h = min(3, t_completed)
        if h <= 0 or self.n_opponents <= 0:
            p_hat = 0.0
        else:
            recent = history.opponent_cooperators[-h:]
            total_recent = int(np.sum(recent)) if len(recent) > 0 else 0
            denom = float(h * self.n_opponents)
            p_hat = total_recent / denom if denom > 0 else 0.0
        high_coop = p_hat >= 0.75
        medium_coop = p_hat >= 0.5
        if low_stock:
            return Action.C
        if high_stock and high_coop:
            return Action.D
        if 0.45 * cap <= stock < 0.65 * cap and medium_coop:
            return Action.D
        return Action.C

class Strategy_OPPORTUNISTIC_61(BaseStrategy):
    """
    Conditional cooperator for the common pool resource game.
    Cooperates when the pool is healthy and opponents have recently been restrained,
    defects under exploitation, depletion, or in the final round unless conditions are excellent.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(1, self.n_players - 1)
        self.prev_processed_round = 0
        self.punishment_remaining = 0
        self.trust_score = 0
        self.consecutive_high_coop = 0
        self.previous_round_start_stock = self.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        current_stock = float(current_stock)
        if round_number > self.prev_processed_round and round_number > 0:
            last_q_count = int(history.opponent_cooperators[-1])
            q_prev = last_q_count / self.n_opponents if self.n_opponents > 0 else 0.0
            if q_prev >= 0.6:
                self.trust_score += 1
            if q_prev < 0.4:
                self.trust_score -= 2
            if q_prev >= 0.7:
                self.consecutive_high_coop += 1
            else:
                self.consecutive_high_coop = 0
            self.prev_processed_round = round_number
        if round_number == 0:
            self.previous_round_start_stock = current_stock
            return Action.C
        last_count = int(history.opponent_cooperators[-1]) if round_number > 0 else self.n_opponents
        q = last_count / self.n_opponents if self.n_opponents > 0 else 0.0
        stock_drop_prev = self.previous_round_start_stock - current_stock
        if stock_drop_prev < 0.0:
            stock_drop_prev = 0.0
        if round_number == self.n_rounds - 1:
            action = Action.C if current_stock >= 0.95 * self.capacity and q >= 0.8 else Action.D
            self.previous_round_start_stock = current_stock
            return action
        if current_stock >= 0.9 * self.capacity and self.consecutive_high_coop >= 2:
            if self.trust_score > 0:
                self.punishment_remaining = 0
                self.previous_round_start_stock = current_stock
                return Action.C
        if self.punishment_remaining > 0:
            if q >= 0.7 and current_stock >= 0.8 * self.capacity:
                self.punishment_remaining = 0
            else:
                self.punishment_remaining -= 1
                self.previous_round_start_stock = current_stock
                return Action.D
        if q < 0.4:
            self.punishment_remaining = 2
            self.previous_round_start_stock = current_stock
            return Action.D
        if current_stock >= 0.75 * self.capacity and q >= 0.6 and (stock_drop_prev <= 0.25 * self.capacity) and (self.trust_score > 0):
            self.previous_round_start_stock = current_stock
            return Action.C
        if q >= 0.5 and current_stock >= 0.7 * self.capacity and (self.trust_score > 0):
            self.previous_round_start_stock = current_stock
            return Action.C
        self.previous_round_start_stock = current_stock
        return Action.D

class Strategy_OPPORTUNISTIC_62(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Cooperates early when the pool is healthy.
    - Defects immediately in weak, fragile, or collapsing conditions.
    - Becomes more defensive after sharp drops in opponent cooperation.
    - Uses endgame protection to avoid being exploited late.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.safe = 0.7 * self.capacity
        self.fragile = 0.45 * self.capacity
        self.critical = 0.25 * self.capacity
        self._last_branch = 'neutral'
        self._last_seen_round = -1
        self._last_opponent_cooperators = None

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        r_left = self.r - round_number
        if round_number > 0 and round_number != self._last_seen_round:
            prev_coop = int(history.opponent_cooperators[-1])
            self._last_seen_round = round_number
            self._last_opponent_cooperators = prev_coop
            if round_number >= 2:
                prev_prev_coop = int(history.opponent_cooperators[-2])
                if prev_prev_coop - prev_coop >= 2:
                    if self._last_branch == 'coop':
                        self._last_branch = 'neutral'
                    elif self._last_branch == 'neutral':
                        self._last_branch = 'defect'
        if round_number == 0:
            if self.capacity >= 1.5 * self.n:
                self._last_branch = 'coop'
                return Action.C
            self._last_branch = 'defect'
            return Action.D
        c_prev = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        n_opponents = max(self.n - 1, 1)
        if self.n > 2:
            p_prev = c_prev / (self.n - 1)
        else:
            p_prev = 1.0 if c_prev >= 1 else 0.0
        if r_left <= min(3, self.r):
            if current_stock > self.safe and p_prev >= 2.0 / 3.0:
                self._last_branch = 'coop'
                return Action.C
            self._last_branch = 'defect'
            return Action.D
        if current_stock <= self.critical:
            self._last_branch = 'defect'
            return Action.D
        if current_stock <= self.fragile and p_prev < 0.5:
            self._last_branch = 'defect'
            return Action.D
        if current_stock <= self.safe:
            if p_prev >= 0.5:
                self._last_branch = 'coop'
                return Action.C
            self._last_branch = 'defect'
            return Action.D
        if p_prev >= 0.67:
            self._last_branch = 'coop'
            return Action.C
        if p_prev < 0.33:
            self._last_branch = 'defect'
            return Action.D
        if round_number % 2 == 1:
            self._last_branch = 'coop'
            return Action.C
        self._last_branch = 'defect'
        return Action.D

class Strategy_OPPORTUNISTIC_63(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Start by defecting.
    - Defect when the pool is healthy and cooperation was already sufficient.
    - Cooperate when the pool is low or cooperation is thin.
    - Default to defection on the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = max(2, int(game_description.n_players))
        self.r = max(1, int(game_description.n_rounds))
        self.k = float(game_description.capacity)

    def _projected_next_stock(self, current_stock: float, h: int, cooperate: bool) -> float:
        n = self.n
        k = self.k
        if k <= 0:
            return 0.0
        m = h + 1 if cooperate else h
        m = max(0, min(n, m))
        r = current_stock * m / (2.0 * n)
        next_stock = 3.0 * r - 2.0 * (r * r) / k
        if next_stock < 0.0:
            next_stock = 0.0
        if next_stock > k:
            next_stock = k
        return next_stock

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number + 1
        if t == 1:
            return Action.D
        if t == self.r:
            return Action.D
        k = self.k
        n = self.n
        if k <= 0.0:
            return Action.C
        s = float(current_stock)
        if s <= 0.2 * k:
            return Action.C
        opp = history.opponent_cooperators
        h = int(opp[-1]) if len(opp) > 0 else 0
        prev_h = int(opp[-2]) if len(opp) >= 2 else None
        threshold = math.ceil((n - 1) / 2)
        if prev_h is not None and prev_h == 0 and (h == 0):
            return Action.C
        if prev_h is not None and prev_h >= threshold and (h >= threshold):
            next_d = self._projected_next_stock(s, h, False)
            if next_d >= 0.7 * k:
                return Action.D
        next_d = self._projected_next_stock(s, h, False)
        next_c = self._projected_next_stock(s, h, True)
        if next_d >= 0.7 * k:
            return Action.D
        elif next_c < 0.35 * k:
            return Action.C
        elif h >= threshold:
            return Action.D
        else:
            return Action.C

class Strategy_OPPORTUNISTIC_64(BaseStrategy):
    """
    Common-pool strategy with cooperation tracking, late-game defection,
    and a short retaliation cooldown after sharp drops in cooperation.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self._last_seen_round = -1
        self._cooldown_rounds = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        n_rounds = self.n_rounds
        if round_number == 0:
            self._last_seen_round = 0
            self._cooldown_rounds = 0
            return Action.C
        if round_number != self._last_seen_round:
            self._last_seen_round = round_number
            opp_counts = history.opponent_cooperators
            n_opponents = max(self.n_players - 1, 1)
            f_t = 0.0
            if len(opp_counts) > 0:
                f_t = float(opp_counts[-1]) / float(n_opponents)
            if len(opp_counts) >= 2:
                f_prev = float(opp_counts[-2]) / float(n_opponents)
                m_t = 0.5 * (f_t + f_prev)
            else:
                m_t = f_t
            if f_t < 1.0 / 3.0:
                self._cooldown_rounds = 2
            elif f_t >= 2.0 / 3.0:
                self._cooldown_rounds = 0
            elif self._cooldown_rounds > 0:
                self._cooldown_rounds = max(0, self._cooldown_rounds - 1)
        opp_counts = history.opponent_cooperators
        n_opponents = max(self.n_players - 1, 1)
        f_t = 0.0
        if len(opp_counts) > 0:
            f_t = float(opp_counts[-1]) / float(n_opponents)
        if len(opp_counts) >= 2:
            f_prev = float(opp_counts[-2]) / float(n_opponents)
            m_t = 0.5 * (f_t + f_prev)
        else:
            m_t = f_t
        s_t = 0.0
        if self.capacity > 0:
            s_t = float(current_stock) / self.capacity
        rounds_left_including_current = n_rounds - round_number
        if rounds_left_including_current <= 2:
            if f_t >= 2.0 / 3.0 and s_t >= 0.25:
                return Action.C
            return Action.D
        if self._cooldown_rounds > 0:
            self._cooldown_rounds -= 1
            if f_t >= 2.0 / 3.0:
                self._cooldown_rounds = 0
            else:
                return Action.D
        if s_t <= 0.1:
            return Action.C if m_t >= 2.0 / 3.0 else Action.D
        if m_t >= 2.0 / 3.0 and f_t >= 0.5:
            return Action.C
        if m_t >= 0.5 and f_t >= 2.0 / 3.0:
            return Action.C
        if s_t >= 0.8 and m_t >= 2.0 / 3.0:
            return Action.C
        if 1.0 / 3.0 <= m_t < 2.0 / 3.0:
            return Action.D
        return Action.D

class Strategy_OPPORTUNISTIC_65(BaseStrategy):
    """
    Conservative common-pool strategy:
    cooperate early, defect under depletion or weak cooperation,
    and return to cooperation only after sustained recovery signals.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(self.n_players - 1, 0)
        self.coop_threshold = math.ceil(2 * self.n_opponents / 3) if self.n_opponents > 0 else 0
        self.low_coop_threshold = math.floor(self.n_opponents / 3) if self.n_opponents > 0 else 0
        self._processed_rounds = 0
        self._prev_stock = None
        self._prev_k = None
        self._good_streak = 0
        self._last_my_action = None

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        if round_number == 0:
            self._prev_stock = float(current_stock)
            self._prev_k = None
            self._good_streak = 0
            self._last_my_action = Action.C
            return Action.C
        start_idx = max(0, self._processed_rounds)
        end_idx = round_number
        for idx in range(start_idx, end_idx):
            k = int(history.opponent_cooperators[idx]) if idx < len(history.opponent_cooperators) else 0
            if k >= self.coop_threshold:
                self._good_streak += 1
            else:
                self._good_streak = 0
            self._prev_k = k
        self._processed_rounds = round_number
        prev_stock = self._prev_stock if self._prev_stock is not None else float(current_stock)
        prev_k = self._prev_k if self._prev_k is not None else 0
        if round_number >= self.n_rounds - 1:
            self._prev_stock = float(current_stock)
            self._last_my_action = Action.D
            return Action.D
        if current_stock <= self.capacity / 4.0:
            action = Action.D
        elif self.n_opponents > 0 and prev_k <= self.low_coop_threshold:
            action = Action.D
        elif current_stock >= 0.8 * self.capacity and prev_k == self.n_opponents:
            action = Action.C
        elif self._last_my_action == Action.D and prev_k == self.n_opponents and (current_stock >= self.capacity / 2.0):
            action = Action.C
        elif self._last_my_action == Action.D and self._good_streak >= 2 and (current_stock >= self.capacity / 2.0):
            action = Action.C
        elif current_stock >= self.capacity / 2.0 and prev_k >= self.coop_threshold and (current_stock >= 0.8 * prev_stock):
            action = Action.C
        else:
            action = Action.D
        self._prev_stock = float(current_stock)
        self._last_my_action = action
        return action

class Strategy_OPPORTUNISTIC_66(BaseStrategy):
    """
    Reserve-following common pool strategy.

    - Cooperates in round 1.
    - Defects in the final round.
    - Otherwise, predicts next stock under both possible own actions and
      defects whenever doing so keeps the stock on or above the reserve path.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)

    def _next_stock(self, stock: float, total_cooperators: int) -> float:
        n = self.n_players
        cap = self.capacity
        if n <= 0:
            return 0.0
        if stock <= 0.0:
            return 0.0
        remaining = stock * float(total_cooperators) / (2.0 * float(n))
        if remaining < 0.0:
            remaining = 0.0
        if cap <= 0.0:
            return remaining
        growth = 2.0 * remaining * (1.0 - remaining / cap)
        new_stock = remaining + growth
        if new_stock > cap:
            new_stock = cap
        if new_stock < 0.0:
            new_stock = 0.0
        return new_stock

    def _reserve(self, m: int) -> float:
        if m <= 1:
            return 0.0
        if self.n_rounds <= 1:
            return 0.0
        return self.capacity * float(m - 1) / float(self.n_rounds - 1)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number + 1
        m = self.n_rounds - history.round_number
        if history.round_number == 0:
            return Action.C
        if m <= 1 or current_stock <= 0.0:
            return Action.D
        if len(history.opponent_cooperators) == 0:
            c = self.n_players - 1
        else:
            c = int(history.opponent_cooperators[-1])
        n_opponents = self.n_players - 1
        if c < 0:
            c = 0
        if c > n_opponents:
            c = n_opponents
        reserve = self._reserve(m)
        s_d = self._next_stock(current_stock, c)
        s_c = self._next_stock(current_stock, c + 1)
        if c == 0:
            return Action.C
        if c == n_opponents:
            return Action.D
        if s_d >= reserve:
            return Action.D
        if s_c >= reserve:
            return Action.C
        return Action.C

class Strategy_OPPORTUNISTIC_67(BaseStrategy):
    """
    Thresholded state-based policy with harvest, stabilize, and extract modes.
    It cooperates when the group is sufficiently stable and the stock is healthy,
    defects in unstable / low-stock situations, and always defects on the last round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.last_mode = 'unknown'
        self.defect_streak = 0
        self.coop_streak = 0
        self.high_coop_streak = 0
        self.low_stock_streak = 0
        self.last_action = Action.D

    def _opponent_coop_rate(self, history: PlayerHistory) -> float:
        n_opponents = max(self.n - 1, 1)
        if history.round_number <= 0:
            return 0.0
        last_k = int(history.opponent_cooperators[-1])
        if last_k < 0:
            last_k = 0
        if last_k > n_opponents:
            last_k = n_opponents
        return last_k / n_opponents

    def _previous_opponent_coop_rate(self, history: PlayerHistory) -> float:
        n_opponents = max(self.n - 1, 1)
        if history.round_number < 2:
            return 0.0
        prev_k = int(history.opponent_cooperators[-2])
        if prev_k < 0:
            prev_k = 0
        if prev_k > n_opponents:
            prev_k = n_opponents
        return prev_k / n_opponents

    def _near_capacity(self, current_stock: float) -> bool:
        return current_stock >= 0.8 * self.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number
        n = self.n
        r = self.r
        cap = self.capacity
        S = float(current_stock)
        if not math.isfinite(S):
            S = cap
        if S < 0.0:
            S = 0.0
        if t > 0:
            last_my_action = bool(history.my_actions[-1])
            last_k = int(history.opponent_cooperators[-1])
            n_opponents = max(n - 1, 1)
            last_k = max(0, min(last_k, n_opponents))
            if last_my_action:
                self.coop_streak += 1
                self.defect_streak = 0
            else:
                self.defect_streak += 1
                self.coop_streak = 0
            if last_k == n_opponents:
                self.high_coop_streak += 1
            else:
                self.high_coop_streak = 0
            if S < cap / 4.0:
                self.low_stock_streak += 1
            else:
                self.low_stock_streak = 0
        if t >= r - 1:
            self.last_action = Action.D
            self.last_mode = 'extract'
            return Action.D
        if t == 0:
            action = Action.C if cap < 4.0 * n else Action.D
            self.last_action = action
            self.last_mode = 'harvest' if action == Action.C else 'extract'
            return action
        if n == 2:
            prev_k = int(history.opponent_cooperators[-1])
            if S > cap / 2.0 and prev_k >= 1:
                action = Action.C
            else:
                action = Action.D
            if S < cap / 4.0:
                action = Action.D
            self.last_action = action
            self.last_mode = 'stabilize' if action == Action.C else 'extract'
            return action
        if S < cap / 4.0:
            self.last_action = Action.D
            self.last_mode = 'extract'
            return Action.D
        if self.defect_streak >= 1 and self.low_stock_streak > 0:
            self.last_action = Action.D
            self.last_mode = 'extract'
            return Action.D
        q = self._opponent_coop_rate(history)
        prev_q = self._previous_opponent_coop_rate(history)
        if self.high_coop_streak >= 2 and self._near_capacity(S):
            if self.last_action == Action.C:
                action = Action.D
            else:
                action = Action.C if q >= 2.0 / 3.0 and S >= cap / 2.0 else Action.D
            self.last_action = action
            self.last_mode = 'extract' if action == Action.D else 'stabilize'
            return action
        if q >= 2.0 / 3.0 and S >= cap / 2.0:
            action = Action.C
            self.last_mode = 'stabilize'
        else:
            action = Action.D
            self.last_mode = 'extract'
        if prev_q >= 2.0 / 3.0 and q <= 1.0 / 3.0:
            action = Action.D
            self.last_mode = 'extract'
        self.last_action = action
        return action

class Strategy_OPPORTUNISTIC_68(BaseStrategy):
    """
    Conservative threshold strategy:
    - Cooperate in round 1.
    - Later, cooperate only when prior opponent cooperation is at least half and
      the stock is sufficiently high.
    - Defect early when stock is low or in the final round.
    - Uses recent cooperation as a tie-breaker when behavior is borderline.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self._high_stock_threshold = 0.75 * self.capacity
        self._low_stock_threshold = 0.4 * self.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        if round_number == 0:
            return Action.C
        if round_number >= self.n_rounds - 1:
            return Action.D
        if current_stock < self._low_stock_threshold:
            return Action.D
        last_opponent_count = int(history.opponent_cooperators[-1])
        n_opponents = max(self.n_players - 1, 1)
        last_p = last_opponent_count / n_opponents
        if last_p >= 0.5 and current_stock >= self._high_stock_threshold:
            return Action.C
        if last_opponent_count == n_opponents and current_stock >= self._high_stock_threshold:
            return Action.C
        recent_window = min(3, round_number)
        if recent_window > 0:
            recent_opponent_counts = history.opponent_cooperators[-recent_window:]
            if np.any(recent_opponent_counts == 0):
                if last_p < 0.5:
                    return Action.D
        if last_p > 0.5:
            return Action.C
        if last_p < 0.5:
            return Action.D
        return Action.D

class Strategy_OPPORTUNISTIC_69(BaseStrategy):
    """
    Adaptive trust-based strategy for the Common Pool Resource Game.

    - Opens with cooperation.
    - Tracks opponent cooperation via trust, streaks, and punishment timers.
    - Defects when stock becomes fragile or cooperation deteriorates.
    - Re-enters cooperation only under sustained healthy cooperation and stock.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.m = max(self.n_players - 1, 0)
        self.trust = 0
        self.zero_streak = 0
        self.full_streak = 0
        self.punish_timer = 0
        self.permanent_defect = False
        self.last_round_q = 0.0
        self.last_round_q_valid = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        if self.permanent_defect:
            return Action.D
        if round_number == 0:
            return Action.C
        if self.m > 0:
            last_opps = int(history.opponent_cooperators[-1])
            q = last_opps / self.m
        else:
            q = 0.0
        self.last_round_q = q
        self.last_round_q_valid = True
        if q == 0.0:
            self.zero_streak += 1
        else:
            self.zero_streak = 0
        if q == 1.0:
            self.full_streak += 1
        else:
            self.full_streak = 0
        if q == 1.0:
            self.trust = min(self.trust + 2, 4)
        elif q >= 2.0 / 3.0:
            self.trust = min(self.trust + 1, 4)
        elif q > 0.0:
            self.trust = max(self.trust - 1, -4)
        else:
            self.trust = max(self.trust - 2, -4)
        if self.zero_streak >= 2:
            self.permanent_defect = True
            return Action.D
        if self.punish_timer > 0:
            self.punish_timer -= 1
            if q <= 1.0 / 3.0:
                self.punish_timer = max(self.punish_timer, 2)
            return Action.D
        if current_stock < 0.25 * self.capacity:
            self.permanent_defect = True
            return Action.D
        if current_stock < 0.5 * self.capacity:
            if q <= 1.0 / 3.0:
                self.punish_timer = 2
            return Action.D
        if round_number >= self.n_rounds - 1:
            if self.trust > 0 and q == 1.0 and (current_stock >= 0.8 * self.capacity):
                return Action.C
            return Action.D
        if current_stock >= 0.8 * self.capacity and q >= 2.0 / 3.0 and (self.trust >= 1):
            action = Action.C
        else:
            action = Action.D
        if q == 1.0:
            if self.full_streak >= 2 and self.trust >= 2:
                action = Action.C
            elif self.full_streak >= 2 and self.trust < 2:
                action = Action.D
            elif self.trust >= 2:
                action = Action.C
            else:
                action = Action.D
        if q <= 1.0 / 3.0:
            self.punish_timer = 2
        if current_stock >= 0.9 * self.capacity and q >= 2.0 / 3.0 and (self.trust >= 1):
            if self.punish_timer == 0 and (not self.permanent_defect):
                action = Action.C
        return action

class Strategy_OPPORTUNISTIC_70(BaseStrategy):
    """
    State-contingent threshold strategy for a common pool resource game.

    Core behavior:
    - Cooperate when stock is low to preserve the pool.
    - Exploit high estimated cooperation when stock is safe.
    - Recover cooperation after defection-heavy rounds.
    - Defect in the endgame when the pool is still healthy.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(1, self.n - 1)

    def _coop_fraction(self, count: int) -> float:
        return float(count) / float(self.n_opponents) if self.n_opponents > 0 else 0.0

    def _estimate_p(self, coop_fracs: list[float]) -> float:
        """
        Estimate cooperation for the current round from prior-round fractions.
        coop_fracs: [f1, f2, ..., f_{t-1}]
        """
        m = len(coop_fracs)
        if m == 0:
            return 1.0
        if m == 1:
            return float(coop_fracs[-1])
        f_prev = float(coop_fracs[-1])
        f_prev2 = float(coop_fracs[-2])
        return 0.75 * f_prev + 0.25 * f_prev2

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = int(history.round_number) + 1
        n = self.n
        r = self.r
        stock = float(current_stock)
        if t == 1:
            return Action.C
        opp_counts = history.opponent_cooperators
        coop_fracs: list[float] = []
        for c in opp_counts:
            coop_fracs.append(self._coop_fraction(int(c)))
        p_t = self._estimate_p(coop_fracs)
        p_prev = None
        if len(coop_fracs) >= 2:
            p_prev = self._estimate_p(coop_fracs[:-1])
        elif len(coop_fracs) == 1:
            p_prev = 1.0
        last_frac = coop_fracs[-1] if coop_fracs else None
        prev_frac = coop_fracs[-2] if len(coop_fracs) >= 2 else None
        low_stock = 0.5 * n
        mid_stock = 1.0 * n
        high_stock = 1.5 * n
        if stock <= low_stock:
            return Action.C
        if t == r:
            if abs(stock - n) < 1e-12:
                return Action.D if p_t >= 0.75 else Action.C
            return Action.D if stock > low_stock else Action.C
        if last_frac is not None and abs(last_frac - 1.0) < 1e-12 and (stock > low_stock):
            return Action.D
        if last_frac is not None and abs(last_frac - 0.0) < 1e-12:
            if not (stock > high_stock and p_t >= 0.5):
                return Action.C
        if r - t + 1 <= 2 and stock > n:
            if p_t < 0.25:
                return Action.C if r - t + 1 == 2 else Action.D
            return Action.D
        action = Action.C
        if stock > low_stock and p_t >= 0.75:
            action = Action.D
        elif stock > high_stock and p_t < 0.25:
            action = Action.D
        elif low_stock < stock <= high_stock and 0.4 <= p_t < 0.75:
            action = Action.C
        elif stock > high_stock and 0.25 <= p_t < 0.4:
            action = Action.C
        elif stock > high_stock and p_t < 0.25:
            action = Action.D
        else:
            action = Action.C
        if abs(stock - n) < 1e-12:
            action = Action.D if p_t >= 0.75 else Action.C
        if p_prev is not None and p_t - p_prev >= 0.2:
            if action == Action.C and stock > n:
                action = Action.D
        if p_prev is not None and p_prev - p_t >= 0.2:
            if action == Action.D:
                action = Action.C
        if len(coop_fracs) == 0:
            return Action.C
        return action

class Strategy_OPPORTUNISTIC_71(BaseStrategy):
    """
    Adaptive common-pool strategy:
    cooperate in the first round, then cooperate only when stock is healthy
    and recent opponent cooperation suggests recovery or stability.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.capacity = float(game_description.capacity)
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self._last_stock: float | None = None

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number + 1
        stock = float(current_stock)
        cap = self.capacity
        if history.round_number == 0:
            self._last_stock = stock
            return Action.C
        n_opponents = max(self.n_players - 1, 1)
        prev_opponents = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        p = prev_opponents / n_opponents
        delta = 0.0
        if self._last_stock is not None:
            delta = stock - self._last_stock
        if stock <= cap / 3.0:
            self._last_stock = stock
            return Action.D
        if t == self.n_rounds:
            if stock > cap / 2.0 and p >= 0.5 and (delta >= 0.0):
                self._last_stock = stock
                return Action.C
            self._last_stock = stock
            return Action.D
        if stock >= cap / 2.0 and p >= 0.5 and (delta >= -cap / 4.0):
            self._last_stock = stock
            return Action.C
        self._last_stock = stock
        return Action.D

class Strategy_OPPORTUNISTIC_72(BaseStrategy):
    """
    Adaptive common-pool strategy:
    cooperate when the stock is healthy and others have shown restraint;
    defect under overuse, insufficient cooperation, low stock, or in the closing rounds
    unless the pool and recent cooperation are both sufficiently strong.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self._punish_until_recovery = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = float(self.game_description.capacity)
        round_number = int(history.round_number)
        t = round_number + 1
        if round_number == 0:
            self._punish_until_recovery = False
            return Action.C
        if current_stock <= 0.0:
            self._punish_until_recovery = False
            return Action.D
        opp_count = n - 1
        last_opp_coop = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else None
        if last_opp_coop is None or opp_count <= 0:
            q_prev = 0.0
        else:
            q_prev = last_opp_coop / opp_count
        if last_opp_coop is None:
            self._punish_until_recovery = False
            return Action.D
        half_capacity = capacity / 2.0
        quarter_capacity = capacity / 4.0
        three_quarter_capacity = 3.0 * capacity / 4.0
        if n == 2:
            applicable_threshold = 1.0
        elif current_stock <= quarter_capacity:
            applicable_threshold = 1.0
        elif current_stock < half_capacity:
            applicable_threshold = 2.0 / 3.0
        else:
            applicable_threshold = 0.5
        final_two_rounds = t >= max(1, r - 1)
        if q_prev == 1.0 and current_stock >= three_quarter_capacity and (not final_two_rounds):
            self._punish_until_recovery = False
            return Action.C
        if round_number > 0 and q_prev < 0.5:
            self._punish_until_recovery = True
            return Action.D
        if self._punish_until_recovery:
            recovered = q_prev >= applicable_threshold and current_stock >= half_capacity
            if recovered:
                self._punish_until_recovery = False
            else:
                return Action.D
        if final_two_rounds:
            if current_stock >= half_capacity and q_prev == 1.0:
                return Action.C
            self._punish_until_recovery = False
            return Action.D
        if current_stock > 0.0:
            if current_stock <= quarter_capacity:
                self._punish_until_recovery = False
                return Action.D
            if current_stock >= half_capacity and q_prev >= 0.5:
                self._punish_until_recovery = False
                return Action.C
            if current_stock < half_capacity and q_prev >= (2.0 / 3.0 if n != 2 else 1.0):
                self._punish_until_recovery = False
                return Action.C
        if q_prev < applicable_threshold:
            self._punish_until_recovery = True
        else:
            self._punish_until_recovery = False
        return Action.D

class Strategy_OPPORTUNISTIC_73(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Start with cooperation.
    - Tracks recent opponent cooperation over the last up to two rounds.
    - Defects late in the game, when opponents are cooperative and the stock is healthy,
      or when forecasted stock dynamics make defection at least as safe as cooperation.
    - Forces cooperation under low-stock conditions.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(0, self.n_players - 1)

    def _recent_q(self, history: PlayerHistory) -> float:
        rounds_seen = history.round_number
        if rounds_seen <= 0 or self.n_opponents <= 0:
            return 0.5
        last_count = int(history.opponent_cooperators[-1])
        if last_count >= self.n_opponents:
            return 1.0
        if last_count <= 0:
            return 0.0
        window_size = min(2, rounds_seen)
        start = rounds_seen - window_size
        counts = history.opponent_cooperators[start:rounds_seen]
        if len(counts) == 0:
            return 0.5
        q = float(np.mean(counts)) / float(self.n_opponents)
        if rounds_seen >= 2:
            prev_size = min(2, rounds_seen - window_size)
            if prev_size > 0:
                prev_start = rounds_seen - window_size - prev_size
                prev_counts = history.opponent_cooperators[prev_start:rounds_seen - window_size]
                if len(prev_counts) > 0:
                    prev_q = float(np.mean(prev_counts)) / float(self.n_opponents)
                    if prev_q - q >= 0.2:
                        return q
        return q

    def _next_stock(self, s: float, consumption: float) -> float:
        remaining = max(0.0, s - consumption)
        growth = 2.0 * remaining * (1.0 - remaining / self.capacity) if self.capacity > 0 else 0.0
        return min(remaining + growth, self.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number + 1
        if history.round_number == 0:
            return Action.C
        b = current_stock / self.capacity if self.capacity > 0 else 0.0
        if b < 0.1:
            return Action.C
        if t == self.n_rounds:
            return Action.D
        if b <= 0.25:
            return Action.C
        q = self._recent_q(history)
        if q >= 0.6 and b >= 0.45:
            return Action.D
        if q <= 0.35:
            return Action.C
        n = self.n_players
        s = float(current_stock)
        opp = self.n_opponents
        cons_c = s / (2.0 * n) + opp * q * (s / (2.0 * n)) + opp * (1.0 - q) * (s / n)
        cons_d = s / n + opp * q * (s / (2.0 * n)) + opp * (1.0 - q) * (s / n)
        s_next_c = self._next_stock(s, cons_c)
        s_next_d = self._next_stock(s, cons_d)
        if s_next_d >= 0.5 * self.capacity and s_next_d >= s_next_c:
            return Action.D
        return Action.C

class Strategy_OPPORTUNISTIC_74(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Start by cooperating.
    - Respond to observed cooperation with a stock-dependent threshold.
    - Defect in the final round when cooperation was sufficiently high.
    - Protect against collapse when stock is very low.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(self.n_players - 1, 1)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        if round_number == 0:
            return Action.C
        prev_coop_count = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        q_t = prev_coop_count / self.n_opponents
        prev_stock = None
        if len(history.my_actions) > 0 and len(history.my_payoffs) > 0:
            last_action = bool(history.my_actions[-1])
            last_payoff = float(history.my_payoffs[-1])
            if last_action:
                prev_stock = last_payoff * (2.0 * self.n_players)
            else:
                prev_stock = last_payoff * float(self.n_players)
        if round_number == self.n_rounds - 1:
            return Action.D if q_t >= 0.5 else Action.C
        low_stock_threshold = self.capacity / (4.0 * self.n_players)
        if current_stock <= low_stock_threshold:
            return Action.D
        if q_t <= 0.2:
            return Action.D
        if prev_coop_count == self.n_opponents and prev_stock is not None and (prev_stock > 0.0):
            if current_stock >= 0.85 * prev_stock:
                return Action.D
        if current_stock >= 0.85 * self.capacity:
            tau = 0.7
        elif current_stock >= 0.5 * self.capacity:
            tau = 0.5
        else:
            tau = 0.35
        return Action.C if q_t >= tau else Action.D

class Strategy_OPPORTUNISTIC_75(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Cooperates in round 1
    - Uses recent opponent cooperation, stock level, and endgame rules thereafter
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.observed_opponent_cooperations = []
        self.stock_start_history = []
        self.stock_change_history = []
        self.p_history = []
        self.last_p = 0.0

    def _weighted_recent_coop_rate(self, history: PlayerHistory) -> float:
        opp = history.opponent_cooperators
        if len(opp) == 0:
            return 0.0
        recent = opp[-3:]
        weights = [1, 2, 3][-len(recent):]
        weighted_sum = 0.0
        weight_total = 0.0
        for count, w in zip(recent, weights):
            weighted_sum += float(count) * float(w)
            weight_total += float(w)
        n_opponents = max(self.n_players - 1, 0)
        denom = float(n_opponents) * weight_total
        if denom <= 0.0:
            return 0.0
        p = weighted_sum / denom
        if p < 0.0:
            return 0.0
        if p > 1.0:
            return 1.0
        return p

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        r = max(self.n_rounds, 1)
        if len(self.stock_start_history) < round_number + 1:
            self.stock_start_history.append(float(current_stock))
        else:
            self.stock_start_history[round_number] = float(current_stock)
        if round_number == 0:
            self.last_p = 0.0
            self.p_history.append(self.last_p)
            return Action.C
        capacity = self.capacity
        s = float(current_stock) / capacity if capacity > 0.0 else 0.0
        s = 0.0 if s < 0.0 else 1.0 if s > 1.0 else s
        p = self._weighted_recent_coop_rate(history)
        prev_change = 0
        if len(self.stock_start_history) >= 2:
            prev_start = float(self.stock_start_history[-2])
            curr_start = float(self.stock_start_history[-1])
            diff = curr_start - prev_start
            if diff > 1e-12:
                prev_change = 1
            elif diff < -1e-12:
                prev_change = -1
            else:
                prev_change = 0
        last_round_opp = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        threshold_half = int(math.ceil(max(self.n_players - 1, 0) / 2.0))
        if round_number == r - 1:
            action = Action.D
        elif round_number == r - 2:
            action = Action.C if s <= 0.2 else Action.D
        elif s <= 0.4:
            action = Action.C
        elif s >= 0.6 and p >= 0.5:
            action = Action.D
        elif prev_change >= 0 and p >= 0.45:
            action = Action.D
        elif last_round_opp >= threshold_half:
            action = Action.D
        else:
            action = Action.C
        self.observed_opponent_cooperations.append(last_round_opp)
        self.stock_change_history.append(prev_change)
        self.last_p = p
        self.p_history.append(p)
        return action

class Strategy_OPPORTUNISTIC_76(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Starts with cooperation.
    - Rewards high and stable opponent cooperation.
    - Becomes stricter as cooperation falls or the game nears the end.
    - Defects in the final round, and usually in the final two rounds.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.high = 2.0 / 3.0
        self.mid = 1.0 / 2.0
        self.low = 1.0 / 3.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = int(history.round_number)
        n = max(self.n, 2)
        opp_count = max(n - 1, 1)
        if t == 0:
            return Action.C
        last_k = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        q = last_k / opp_count
        prev_q = None
        if len(history.opponent_cooperators) >= 2:
            prev_k = int(history.opponent_cooperators[-2])
            prev_q = prev_k / opp_count
        S = float(current_stock)
        rounds_remaining = self.r - t
        if rounds_remaining <= 0:
            return Action.D
        if rounds_remaining == 1:
            return Action.D
        action = Action.D
        recovery_lockout = False
        if q < self.low:
            recovery_lockout = True
        if recovery_lockout:
            if len(history.opponent_cooperators) >= 3:
                q2 = int(history.opponent_cooperators[-2]) / opp_count
                q3 = int(history.opponent_cooperators[-3]) / opp_count
                if q2 >= self.mid and q3 >= self.mid:
                    recovery_lockout = False
            if S >= 0.95 * self.capacity and q >= self.low:
                recovery_lockout = False
            if recovery_lockout:
                return Action.D
        if S <= 2.0 * n:
            action = Action.D
        elif q >= self.high:
            action = Action.C
        elif q >= self.mid:
            action = Action.C if S >= 0.75 * self.capacity else Action.D
        elif q >= self.low:
            action = Action.C if S >= 0.9 * self.capacity and prev_q is not None and (prev_q >= self.mid) else Action.D
        else:
            action = Action.D
        if q >= self.high and S >= 0.9 * self.capacity:
            action = Action.C
        if prev_q is not None:
            if q <= prev_q - 0.1:
                if action == Action.C:
                    action = Action.D
            elif q >= prev_q + 0.1 and S >= 0.8 * self.capacity:
                if action == Action.D:
                    action = Action.C
        if rounds_remaining <= 2:
            if not (q >= self.high and S >= 0.85 * self.capacity):
                action = Action.D
            else:
                action = Action.C
        return action

class Strategy_OPPORTUNISTIC_77(BaseStrategy):
    """
    Conditional threshold strategy with short retaliation memory and a final-round extraction phase.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self._dummy_state = None

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = int(self.game_description.n_players)
        r = int(self.game_description.n_rounds)
        rounds_played = int(history.round_number)
        if rounds_played == 0:
            return Action.C
        t = rounds_played + 1
        tail = r - t + 1
        opp_counts = history.opponent_cooperators
        n_opponents = max(n - 1, 1)
        retaliation_remaining = 0
        exploit_mode = False
        if rounds_played > 0:
            x_values = []
            for k in opp_counts:
                x = float(k) / float(n_opponents) if n_opponents > 0 else 0.5
                x_values.append(x)
                if retaliation_remaining > 0:
                    if x >= 2.0 / 3.0:
                        retaliation_remaining = 0
                    else:
                        retaliation_remaining = max(retaliation_remaining - 1, 0)
                if x < 1.0 / 3.0:
                    retaliation_remaining = 2
                if exploit_mode:
                    if x < 0.5:
                        exploit_mode = False
                elif x >= 3.0 / 4.0:
                    exploit_mode = True
            avg_x = float(np.mean(np.asarray(x_values, dtype=float))) if x_values else 0.5
            x_prev = x_values[-1] if x_values else 0.5
        else:
            avg_x = 0.5
            x_prev = 0.5
        if tail == 1:
            return Action.D
        if tail <= 2:
            if x_prev == 1.0:
                return Action.C
            return Action.D
        if retaliation_remaining > 0:
            if x_prev >= 2.0 / 3.0:
                retaliation_remaining = 0
            else:
                return Action.D
        if exploit_mode or x_prev >= 3.0 / 4.0:
            return Action.D
        threshold = 0.5 + 1.0 / (4.0 * n) + 1.0 / (10.0 * math.sqrt(max(t, 1)))
        if x_prev < 1.0 / 3.0:
            return Action.D
        if x_prev >= threshold and avg_x >= 0.5:
            return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_78(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - defects in healthy pools when cooperation is strong or persistent
    - cooperates under stress, collapse, or after large depletion
    - uses internal state to track collapse/protection modes and running cooperation rate
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(self.n_players - 1, 0)
        self.last_stock = None
        self.protect_mode = False
        self.collapse_mode = False
        self.coop_sum_since_reset = 0.0
        self.coop_rounds_since_reset = 0
        self.last_strong = False
        self.last_two_strong = False

    def _strong_threshold(self) -> int:
        return int(math.ceil(0.75 * self.n_opponents))

    def _weak_threshold(self) -> int:
        return int(math.floor(0.4 * self.n_opponents))

    def _running_coop_rate(self) -> float:
        if self.coop_rounds_since_reset <= 0 or self.n_opponents <= 0:
            return 0.0
        return float(self.coop_sum_since_reset) / float(self.coop_rounds_since_reset * self.n_opponents)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number + 1
        cap = self.capacity
        stock = float(current_stock)
        strong_thr = self._strong_threshold()
        weak_thr = self._weak_threshold()
        k_prev = None
        if history.round_number > 0 and len(history.opponent_cooperators) > 0:
            k_prev = int(history.opponent_cooperators[-1])
        k_prev_prev = None
        if history.round_number > 1 and len(history.opponent_cooperators) > 1:
            k_prev_prev = int(history.opponent_cooperators[-2])
        if stock < 0.25 * cap:
            self.collapse_mode = True
            self.protect_mode = True
            self.coop_sum_since_reset = 0.0
            self.coop_rounds_since_reset = 0
        elif self.collapse_mode and stock >= 0.4 * cap:
            self.collapse_mode = False
            if stock >= 0.4 * cap:
                self.protect_mode = False
        if self.last_stock is not None:
            if self.last_stock - stock >= 0.2 * cap:
                self.protect_mode = True
        if not self.collapse_mode and history.round_number > self.coop_rounds_since_reset:
            start_idx = self.coop_rounds_since_reset
            end_idx = history.round_number
            if self.n_opponents > 0:
                for idx in range(start_idx, end_idx):
                    k = int(history.opponent_cooperators[idx])
                    self.coop_sum_since_reset += float(k) / float(self.n_opponents)
                    self.coop_rounds_since_reset += 1
        c_hat = self._running_coop_rate()
        current_last_strong = False
        if k_prev is not None:
            current_last_strong = k_prev >= strong_thr
        self.last_two_strong = bool(self.last_strong and current_last_strong)
        self.last_strong = current_last_strong
        if history.round_number == 0:
            self.last_stock = stock
            return Action.D
        if t == self.n_rounds:
            action = Action.D if stock >= 0.4 * cap else Action.C
            self.last_stock = stock
            return action
        if self.collapse_mode:
            action = Action.C
            self.last_stock = stock
            return action
        if self.protect_mode:
            if stock >= 0.4 * cap:
                self.protect_mode = False
            else:
                self.last_stock = stock
                return Action.C
        if stock < 0.4 * cap:
            action = Action.C
            if k_prev is not None and k_prev <= weak_thr:
                if stock < 0.5 * cap:
                    action = Action.C
            self.last_stock = stock
            return action
        if self.last_two_strong and stock >= 0.6 * cap:
            action = Action.D
            self.last_stock = stock
            return action
        if 0.4 * cap <= stock < 0.75 * cap:
            if k_prev is not None and k_prev >= strong_thr:
                action = Action.D
            else:
                action = Action.C
            self.last_stock = stock
            return action
        if stock >= 0.75 * cap:
            if k_prev is not None and k_prev >= strong_thr or c_hat >= 0.6:
                action = Action.D
            else:
                action = Action.C
            self.last_stock = stock
            return action
        action = Action.C
        self.last_stock = stock
        return action

class Strategy_OPPORTUNISTIC_79(BaseStrategy):
    """
    Resource-aware cooperative strategy for the Common Pool Resource Game.

    - Cooperates in the first round.
    - Defects in the final round.
    - Uses recent opponent cooperation to estimate whether cooperation is sustainable.
    - Protects the resource when stock is low, but defects when the pool is strong
      and opponents have been sufficiently cooperative.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.L = 0.4 * self.capacity
        self.H = 0.7 * self.capacity
        self.M = 0.55 * self.capacity

    def _recent_q_bar(self, history: PlayerHistory) -> float:
        n_opponents = max(self.n - 1, 1)
        if history.round_number <= 0:
            return 1.0
        recent_counts = history.opponent_cooperators[-3:]
        if len(recent_counts) == 0:
            return 1.0
        qs = [float(c) / n_opponents for c in recent_counts]
        if len(qs) == 0:
            return 1.0
        return float(np.mean(qs))

    def _project_stock(self, current_stock: float, q_bar: float, my_action: Action) -> float:
        n = max(self.n, 2)
        s = max(0.0, float(current_stock))
        q = min(1.0, max(0.0, float(q_bar)))
        own_consumption = s / (2.0 * n) if my_action == Action.C else s / n
        opp_expected_consumption_each = q * (s / (2.0 * n)) + (1.0 - q) * (s / n)
        total_expected_consumption = own_consumption + (n - 1) * opp_expected_consumption_each
        remaining = max(0.0, s - total_expected_consumption)
        grown = remaining + 2.0 * remaining * (1.0 - remaining / self.capacity)
        return min(grown, self.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number
        if t == 0:
            return Action.C
        if t >= self.r - 1:
            return Action.D
        s = float(current_stock)
        q_bar = self._recent_q_bar(history)
        if s <= self.L:
            return Action.C
        if q_bar >= 2.0 / 3.0 and s >= self.M:
            return Action.D
        if q_bar <= 1.0 / 3.0:
            return Action.C if s <= self.H else Action.D
        projected_c = self._project_stock(s, q_bar, Action.C)
        projected_d = self._project_stock(s, q_bar, Action.D)
        if projected_d >= projected_c and s > self.L:
            return Action.D
        return Action.C

class Strategy_OPPORTUNISTIC_80(BaseStrategy):
    """
    Two-mode common-pool strategy:
    - Cooperate early and under stress to rebuild the stock.
    - Defect when the pool is healthy and opponents are cooperating sufficiently.
    - Always defect in the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.healthy_threshold = 0.75 * self.capacity
        self.stress_threshold = 0.5 * self.capacity
        self.coop_threshold = 0.6

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        if round_number == 0:
            return Action.C
        if round_number >= self.n_rounds - 1:
            return Action.D
        stock = float(current_stock)
        if stock <= 0.0:
            return Action.D
        opponent_count = max(self.n_players - 1, 1)
        prev_cooperators = 0
        if len(history.opponent_cooperators) > 0:
            prev_cooperators = int(history.opponent_cooperators[-1])
        q_prev = prev_cooperators / opponent_count
        if stock <= self.stress_threshold:
            if round_number == self.n_rounds - 2 and q_prev >= self.coop_threshold:
                return Action.D
            return Action.C
        if stock >= self.healthy_threshold and q_prev >= self.coop_threshold:
            return Action.D
        return Action.C

class Strategy_OPPORTUNISTIC_81(BaseStrategy):
    """
    Threshold-and-exploitation strategy for the common pool resource game.

    Core ideas:
    - Estimate opponent cooperation from recent history with a recency-weighted
      average of the last up to 3 rounds.
    - Cooperate when the pool is healthy and cooperation is sufficiently high.
    - Defect in low-cooperation, depleted-pool, or endgame situations.
    - Enter a short harvest mode after very low cooperation, and a short
      cooperative lock after a strong cooperative rebound.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.harvest_mode_rounds: int = 0
        self.coop_lock_rounds: int = 0
        self.opportunistic_defect_used: bool = False

    def _observed_coop_rate(self, history: PlayerHistory, round_index: int) -> float:
        n_opponents = max(self.n_players - 1, 1)
        count = int(history.opponent_cooperators[round_index])
        if count < 0:
            count = 0
        if count > n_opponents:
            count = n_opponents
        return count / n_opponents

    def _forecast_p(self, history: PlayerHistory) -> float:
        t = history.round_number
        if t == 0:
            return 1.0
        rates = []
        weights = []
        for back, weight in ((1, 3.0), (2, 2.0), (3, 1.0)):
            idx = t - back
            if idx >= 0:
                rates.append(self._observed_coop_rate(history, idx))
                weights.append(weight)
        if not weights:
            return 1.0
        w = float(sum(weights))
        if w <= 0.0:
            return 1.0
        return float(sum((r * wt for r, wt in zip(rates, weights)))) / w

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number
        r = self.n_rounds
        cap = self.capacity
        S = float(current_stock)
        if t == 0:
            return Action.C if S >= 0.75 * cap else Action.D
        p_t = self._forecast_p(history)
        last_p = self._observed_coop_rate(history, t - 1)
        prev_p = self._observed_coop_rate(history, t - 2) if t - 2 >= 0 else None
        if last_p < 1.0 / 3.0:
            self.harvest_mode_rounds = 2
        elif prev_p is not None and last_p >= 2.0 / 3.0 and (prev_p >= 2.0 / 3.0):
            self.harvest_mode_rounds = 0
            self.opportunistic_defect_used = False
        if last_p >= 2.0 / 3.0:
            if t - 1 >= 0:
                if S < 0.5 * cap:
                    self.coop_lock_rounds = max(self.coop_lock_rounds, 2)
        if self.coop_lock_rounds > 0:
            self.coop_lock_rounds -= 1
        if self.harvest_mode_rounds > 0:
            self.harvest_mode_rounds -= 1
        if t == r - 1:
            return Action.D
        if t >= r - 2 and (not (p_t >= 1.0 and S >= 0.5 * cap)):
            return Action.D
        if self.harvest_mode_rounds > 0:
            if p_t >= 0.5 and S >= 0.9 * cap:
                return Action.C
            return Action.D
        if self.coop_lock_rounds > 0:
            if p_t >= 2.0 / 3.0 and S >= 0.5 * cap:
                return Action.C
            return Action.D
        if p_t >= 2.0 / 3.0:
            env = 'high'
        elif p_t >= 1.0 / 3.0:
            env = 'mixed'
        else:
            env = 'low'
        recent_own_c = 0
        if t >= 1:
            recent_own_c += 1 if bool(history.my_actions[-1]) else 0
        if t >= 2:
            recent_own_c += 1 if bool(history.my_actions[-2]) else 0
        if env == 'low':
            return Action.D
        if env == 'high':
            if S > 0.8 * cap and (not self.opportunistic_defect_used):
                self.opportunistic_defect_used = True
                return Action.D
            if S >= 0.5 * cap:
                return Action.C
            return Action.D
        if S >= 0.75 * cap and recent_own_c >= 1:
            return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_82(BaseStrategy):
    """
    Adaptive common-pool strategy:
    start cautiously cooperative, reward sustained cooperation and healthy stock,
    punish low cooperation/overuse, and become more conservative in the endgame.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.last_stock: float | None = None
        self.last_opponent_coop_rate: float | None = None
        self.last_action: Action | None = None
        self.punishment_mode: bool = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number
        if t == 0:
            action = Action.C if self.capacity >= 1.5 * self.n_players else Action.D
            self.last_stock = float(current_stock)
            self.last_opponent_coop_rate = None
            self.last_action = action
            self.punishment_mode = False
            return action
        n_opponents = max(self.n_players - 1, 1)
        coop_last = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        q = coop_last / n_opponents
        h = float(current_stock) / self.capacity if self.capacity > 0 else 0.0
        prev_stock = self.last_stock if self.last_stock is not None else float(current_stock)
        stock_increased = float(current_stock) > prev_stock + 1e-12
        stock_decreased = float(current_stock) < prev_stock - 1e-12
        sharp_collapse = float(current_stock) <= 0.7 * prev_stock if prev_stock > 0 else False
        if q < 0.4:
            self.punishment_mode = True
        elif q >= 0.6 or h >= 0.5:
            self.punishment_mode = False
        if t >= self.n_rounds - 2:
            if h > 0.4 and q < 0.75:
                action = Action.D
            else:
                action = Action.C
            self.last_stock = float(current_stock)
            self.last_opponent_coop_rate = q
            self.last_action = action
            return action
        if q >= 0.8 and h >= 0.7:
            action = Action.C
        elif q <= 0.2 or sharp_collapse:
            action = Action.D
        elif self.punishment_mode and (not (q >= 0.6 or h >= 0.5)):
            action = Action.D
        elif q >= 0.7 and stock_increased:
            action = Action.C
        elif q <= 0.4 or h <= 0.3:
            action = Action.D
        elif q >= 0.6 and h >= 0.5:
            action = Action.C
        elif q > 0.5:
            action = Action.C
        elif q < 0.5:
            action = Action.D
        else:
            action = Action.C if h >= 0.5 else Action.D
        self.last_stock = float(current_stock)
        self.last_opponent_coop_rate = q
        self.last_action = action
        if stock_decreased and q < 0.4:
            self.punishment_mode = True
        return action

class Strategy_OPPORTUNISTIC_83(BaseStrategy):
    """
    State-triggered threshold strategy with staged exploitation and fallback
    cooperation when the pool becomes fragile.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = max(2, int(game_description.n_players))
        self.r = max(1, int(game_description.n_rounds))
        self.capacity = float(game_description.capacity)
        self.opponents = max(1, self.n - 1)
        self.half_threshold = 0.5 * self.opponents
        self.prev_mode = 'init'
        self.prev_payoff = None
        self.prev_stock = None
        self.prev_k = None
        self.consecutive_low_coop = 0
        self.consecutive_zero_coop = 0
        self.consecutive_low_payoff_high_k = 0
        self.forced_defect_next = False
        self.forced_coop_next = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number
        k_t = int(history.opponent_cooperators[-1]) if t > 0 else 0
        p_t = k_t / self.opponents if self.opponents > 0 else 0.0
        if t == 0:
            self.prev_mode = 'C'
            self.prev_stock = float(current_stock)
            self.prev_k = None
            self.prev_payoff = None
            return Action.C
        S = float(current_stock)
        near_capacity = S >= 0.75 * self.capacity
        low_stock = S <= 0.25 * self.capacity
        last_payoff = float(history.my_payoffs[-1]) if len(history.my_payoffs) > 0 else None
        prev_k = int(history.opponent_cooperators[-2]) if t > 1 and len(history.opponent_cooperators) > 1 else None
        if p_t < 0.5:
            self.consecutive_low_coop += 1
        else:
            self.consecutive_low_coop = 0
        if k_t == 0:
            self.consecutive_zero_coop += 1
        else:
            self.consecutive_zero_coop = 0
        if last_payoff is not None and self.prev_payoff is not None and (k_t >= self.half_threshold):
            if last_payoff < 0.75 * self.prev_payoff:
                self.consecutive_low_payoff_high_k += 1
            else:
                self.consecutive_low_payoff_high_k = 0
        else:
            self.consecutive_low_payoff_high_k = 0
        if t == self.r - 1:
            action = Action.C if k_t == self.opponents else Action.D
        else:
            if self.forced_coop_next:
                action = Action.C
                self.forced_coop_next = False
            elif self.forced_defect_next:
                action = Action.D
                self.forced_defect_next = False
            elif low_stock:
                if k_t == 0:
                    action = Action.D
                    self.forced_coop_next = True
                else:
                    action = Action.C
            elif near_capacity:
                action = Action.C if k_t == self.opponents else Action.D
            elif k_t >= self.half_threshold:
                action = Action.D
            elif self.consecutive_low_coop >= 2:
                action = Action.D
            elif prev_k is not None and prev_k < self.half_threshold:
                action = Action.D
            else:
                action = Action.C
            if action == Action.C and self.consecutive_low_payoff_high_k > 0 and (k_t >= self.half_threshold):
                action = Action.D
                self.forced_defect_next = True
        self.prev_mode = 'C' if action == Action.C else 'D'
        self.prev_stock = S
        self.prev_k = k_t
        self.prev_payoff = last_payoff if last_payoff is not None else self.prev_payoff
        return action

class Strategy_OPPORTUNISTIC_84(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Starts with cooperation.
    - Reacts to opponent cooperation rates and current stock.
    - Prioritizes final-round defection, low-stock recovery, and exploit opportunities.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(self.n_players - 1, 1)
        self._eps = 1e-12

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        if round_number == 0:
            return Action.C
        if len(history.opponent_cooperators) < 1:
            return Action.D if round_number >= self.n_rounds - 1 else Action.C
        if round_number == self.n_rounds - 1:
            last_q = float(history.opponent_cooperators[-1]) / float(self.n_opponents)
            return Action.D if last_q >= 0.25 else Action.C
        last_q = float(history.opponent_cooperators[-1]) / float(self.n_opponents)
        prev_q = None
        if len(history.opponent_cooperators) >= 2:
            prev_q = float(history.opponent_cooperators[-2]) / float(self.n_opponents)
        is_tie = abs(last_q - 0.5) <= self._eps
        if current_stock <= 0.25 * self.capacity:
            return Action.C
        if current_stock <= 0.35 * self.capacity:
            return Action.C
        if prev_q is not None and last_q <= 0.25 and (prev_q <= 0.25):
            return Action.C
        if prev_q is not None and last_q >= 0.6 and (prev_q >= 0.6) and (current_stock >= 0.4 * self.capacity):
            return Action.D
        if current_stock >= 0.85 * self.capacity and last_q >= 0.4:
            return Action.D
        if last_q >= 0.5 and current_stock >= 0.6 * self.capacity:
            return Action.D
        if is_tie:
            if current_stock < 0.8 * self.capacity:
                return Action.C
            return Action.D
        return Action.C

class Strategy_OPPORTUNISTIC_85(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Cooperate on the first round.
    - Defect on the final round.
    - In intermediate rounds, choose based on current stock and the most recent
      observed opponent cooperation rate.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.low_stock_threshold = 0.25 * self.capacity
        self.high_stock_threshold = 0.75 * self.capacity
        self.last_observed_coop_rate = None
        self.last_observed_cooperators = None
        self.last_round_seen = -1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        n_opponents = max(self.n_players - 1, 1)

        def observed_coop_rate() -> float:
            if round_number <= 0:
                return 0.0
            last_count = int(history.opponent_cooperators[-1])
            return max(0.0, min(1.0, last_count / n_opponents))
        rho = observed_coop_rate()
        if round_number > 0:
            self.last_observed_coop_rate = rho
            self.last_observed_cooperators = int(history.opponent_cooperators[-1])
            self.last_round_seen = round_number - 1
        if round_number == 0:
            return Action.C
        if round_number >= self.n_rounds - 1:
            return Action.D
        stock = float(current_stock)
        if stock <= self.low_stock_threshold:
            return Action.C if rho >= 0.5 else Action.D
        if stock >= self.high_stock_threshold:
            return Action.D if rho >= 2.0 / 3.0 else Action.C
        return Action.C if rho >= 2.0 / 3.0 else Action.D

class Strategy_OPPORTUNISTIC_86(BaseStrategy):
    """
    Cooperative unless the pool is weakening or opponent cooperation drops.
    Defects in terminal rounds unless the pool is exceptionally healthy and
    opponents were fully cooperative.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = int(history.round_number)
        if t == 0:
            return Action.C
        last_cooperators = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        n_opponents = max(self.n_players - 1, 1)
        q = last_cooperators / n_opponents
        action = Action.D
        if t == self.n_rounds:
            action = Action.D
        elif current_stock <= self.capacity / 2:
            action = Action.D
        elif q >= 0.7 and current_stock >= 0.6 * self.capacity:
            action = Action.C
        elif q <= 0.4:
            action = Action.D
        elif current_stock >= 0.75 * self.capacity:
            action = Action.C
        else:
            action = Action.D
        if t >= 2 and len(history.opponent_cooperators) >= 2:
            prev_cooperators = int(history.opponent_cooperators[-2])
            if last_cooperators <= prev_cooperators - 2:
                action = Action.D
        if t >= 2 and len(history.my_actions) >= 1:
            if not bool(history.my_actions[-1]) and last_cooperators == n_opponents and (current_stock > self.capacity / 2):
                action = Action.C
        if t >= self.n_rounds - 1:
            if not (current_stock >= 0.9 * self.capacity and q == 1):
                action = Action.D
        return action

class Strategy_OPPORTUNISTIC_87(BaseStrategy):
    """
    Common-pool strategy:
    - Start cooperatively only in games long enough to reward persistence.
    - Use recent opponent cooperation and stock health to decide whether to keep cooperating.
    - Defect in the last two rounds, except for a narrow second-to-last-round condition.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(0, self.n_players - 1)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number

        def opponent_coop_fraction(offset: int=1) -> float:
            idx = round_number - offset
            if idx < 0 or idx >= round_number:
                return 1.0 if round_number == 0 and self.n_rounds > 2 else 0.0
            if self.n_opponents <= 0:
                return 0.0
            coop_count = float(history.opponent_cooperators[idx])
            return coop_count / float(self.n_opponents)
        if round_number >= self.n_rounds - 1:
            return Action.D
        if round_number == self.n_rounds - 2:
            p_prev = opponent_coop_fraction(1)
            if p_prev == 1.0 and current_stock >= 0.9 * self.capacity:
                return Action.C
            return Action.D
        if round_number == 0:
            if self.n_rounds <= 2:
                return Action.D
            return Action.C
        p_prev = opponent_coop_fraction(1)
        if p_prev >= 0.75 and current_stock >= 0.25 * self.capacity:
            return Action.C
        if round_number >= 2:
            p_prev2 = opponent_coop_fraction(2)
            if p_prev < 0.5 and p_prev2 < 0.5:
                return Action.D
        if p_prev >= 0.5 and current_stock >= self.capacity / 3.0:
            return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_88(BaseStrategy):
    """
    Opportunistic common-pool strategy with harvest, exploit, and preserve modes.
    Uses recent opponent cooperation and stock level to choose between C and D.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(0, self.n_players - 1)
        self._last_stock = None
        self._last_coop_rate = None
        self._prev_coop_rate = None
        self._last_stock_trend = 0

    def _coop_rate(self, coop_count: int) -> float:
        if self.n_opponents <= 0:
            return 0.0
        return float(coop_count) / float(self.n_opponents)

    def _observed_rate(self, history: PlayerHistory) -> float:
        rn = history.round_number
        if rn <= 0 or len(history.opponent_cooperators) == 0:
            return 0.0
        last_rate = self._coop_rate(int(history.opponent_cooperators[-1]))
        if rn >= 2 and len(history.opponent_cooperators) >= 2:
            prev_rate = self._coop_rate(int(history.opponent_cooperators[-2]))
            return 0.5 * (last_rate + prev_rate)
        return last_rate

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number
        n = self.n_players
        cap = self.capacity
        S = float(current_stock)
        B = S / cap if cap > 0 else 0.0
        if t == 0:
            self._last_stock = S
            self._last_coop_rate = None
            self._prev_coop_rate = None
            self._last_stock_trend = 0
            return Action.D
        coop_rate = self._observed_rate(history)
        trend = 0
        if self._last_stock is not None:
            if S > self._last_stock + 1e-12:
                trend = 1
            elif S < self._last_stock - 1e-12:
                trend = -1
            else:
                trend = 0
        if S <= 2.0 * n:
            chosen = Action.D
        elif t >= max(0, self.n_rounds - 2):
            if B >= 0.9 and coop_rate >= 0.8 or (S >= 0.9 * cap and coop_rate >= 0.7):
                chosen = Action.C
            else:
                chosen = Action.D
        else:
            if B >= 0.8 and coop_rate >= 0.6:
                chosen = Action.C
            elif coop_rate >= 0.5 and S > 2.0 * n:
                chosen = Action.D
            elif coop_rate < 0.5 and S > 2.0 * n:
                chosen = Action.C if B >= 0.6 else Action.D
            elif 0.5 <= coop_rate < 0.6:
                chosen = Action.D if B >= 0.4 else Action.C
            elif 0.4 <= coop_rate < 0.5:
                chosen = Action.D if B >= 0.7 else Action.C
            else:
                chosen = Action.D
            if self._last_stock is not None:
                near_capacity_now = B >= 0.95
                near_capacity_prev = self._last_stock / cap >= 0.95 if cap > 0 else False
                if (trend >= 0 or near_capacity_now or near_capacity_prev) and coop_rate >= 0.5:
                    chosen = Action.D
                elif trend < 0 and coop_rate < 0.5:
                    chosen = Action.C if S > 2.0 * n and B >= 0.6 else Action.D
        if history.round_number == 1 and len(history.opponent_cooperators) == 1:
            if S > 2.0 * n and coop_rate < 0.5 and (B >= 0.6):
                chosen = Action.C
            else:
                chosen = Action.D
        self._prev_coop_rate = self._last_coop_rate
        self._last_coop_rate = coop_rate
        self._last_stock_trend = trend
        self._last_stock = S
        return chosen

class Strategy_OPPORTUNISTIC_89(BaseStrategy):
    """
    Adaptive common-pool strategy:
    start cooperatively, maintain cooperation under strong collective signals
    and healthy stock, but defect when cooperation weakens, stock declines,
    or the game enters the endgame.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.n
        r = self.r
        capacity = self.capacity
        if history.round_number == 0:
            return Action.C
        if current_stock <= 0:
            return Action.D
        t = history.round_number + 1
        prev_idx = history.round_number - 1
        opp_prev = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        prev_stock = float(current_stock)
        if len(history.my_payoffs) >= 2:
            prev_stock_proxy = float(max(current_stock, 0.0))
        else:
            prev_stock_proxy = float(current_stock)
        n_opponents = max(n - 1, 0)
        if n_opponents <= 0:
            return Action.C if current_stock >= 0.25 * capacity else Action.D
        q = opp_prev / n_opponents
        x = current_stock / capacity if capacity > 0 else 0.0
        if t >= r - 1:
            if q >= 1.0 and x >= 0.9:
                return Action.C
            return Action.D
        if opp_prev <= math.floor((n - 1) / 3):
            return Action.D
        if opp_prev >= math.ceil(2 * (n - 1) / 3) and x >= 0.8:
            return Action.C
        if opp_prev >= math.ceil((n - 1) / 2) and x < 0.9:
            if q < 2.0 / 3.0:
                return Action.D
        if x >= 0.8 and 0.5 <= q < 2.0 / 3.0:
            return Action.D
        if q >= 0.5 and x >= 0.25:
            return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_90(BaseStrategy):
    """
    Exploit-first, preserve-when-needed strategy for the common pool resource game.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)

    def _growth(self, x: float) -> float:
        cap = self.capacity
        x = max(0.0, min(float(x), cap))
        return min(x + 2.0 * x * (1.0 - x / cap), cap)

    def _p_hat(self, history: PlayerHistory) -> float:
        t = history.round_number
        n_opponents = max(self.n - 1, 1)
        if t <= 0:
            return 0.5
        total = float(np.sum(history.opponent_cooperators[:t]))
        denom = n_opponents * t + 2.0
        return (total + 1.0) / denom if denom > 0.0 else 0.5

    def _sharp_drop_recent(self, history: PlayerHistory) -> bool:
        counts = history.opponent_cooperators
        m = history.round_number
        if m < 2:
            return False
        if counts[m - 2] - counts[m - 1] >= 2:
            return True
        if m >= 3 and counts[m - 3] - counts[m - 2] >= 2:
            return True
        return False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number + 1
        n = self.n
        r = self.r
        cap = self.capacity
        S = float(current_stock)
        if t == 1:
            return Action.C
        if t == r:
            return Action.D
        if t == r - 1:
            if history.round_number >= 1:
                prev_c = int(history.opponent_cooperators[-1])
                if prev_c == n - 1 and S >= cap / 2.0:
                    return Action.C
            return Action.D
        if self._sharp_drop_recent(history):
            return Action.D
        p_hat = self._p_hat(history)
        if S <= cap / 4.0:
            return Action.C if p_hat >= 0.75 else Action.D
        if S >= 3.0 * cap / 4.0:
            if history.round_number >= 2:
                last_c = int(history.opponent_cooperators[-1])
                prev_c = int(history.opponent_cooperators[-2])
                if last_c == n - 1 and prev_c == n - 1:
                    return Action.C
            return Action.D
        opp_n = max(n - 1, 1)
        expected_opponent_consumption_if_C = p_hat * (S / (2.0 * n)) + (1.0 - p_hat) * (S / n)
        expected_opponent_consumption_if_D = expected_opponent_consumption_if_C
        S_prime_C = S - (S / (2.0 * n) + opp_n * expected_opponent_consumption_if_C)
        S_prime_D = S - (S / n + opp_n * expected_opponent_consumption_if_D)
        next_stock_C = self._growth(S_prime_C)
        next_stock_D = self._growth(S_prime_D)
        lam = (r - t) / r if r > 0 else 0.0
        U_C = S / (2.0 * n) + lam * next_stock_C
        U_D = S / n + lam * next_stock_D
        return Action.D if U_D >= U_C else Action.C

class Strategy_OPPORTUNISTIC_91(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Start cooperatively
    - Defect on the final round
    - Cooperate when stock is low
    - Exploit sustained cooperation
    - Mirror mixed environments
    - Conserve when opponents defect heavily
    - Use a small memory-based refinement when recent patterns are stable
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self._forced_cooperate_until_round = -1
        self._last_processed_round = -1
        self._seen_stocks: list[float] = []

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        n_players = self.game_description.n_players
        n_opponents = max(n_players - 1, 1)
        capacity = float(self.game_description.capacity)
        if round_number != self._last_processed_round:
            self._seen_stocks.append(float(current_stock))
            self._last_processed_round = round_number
        if round_number == 0:
            return Action.C
        if round_number >= self.game_description.n_rounds - 1:
            return Action.D
        last_opponent_cooperators = int(history.opponent_cooperators[-1])
        rho = last_opponent_cooperators / n_opponents if n_opponents > 0 else 0.0
        if len(history.opponent_cooperators) >= 2 and len(self._seen_stocks) >= 2:
            rho_prev1 = history.opponent_cooperators[-1] / n_opponents if n_opponents > 0 else 0.0
            rho_prev2 = history.opponent_cooperators[-2] / n_opponents if n_opponents > 0 else 0.0
            stock_prev1 = self._seen_stocks[-1]
            stock_prev2 = self._seen_stocks[-2]
            if rho_prev1 >= 0.6 and rho_prev2 >= 0.6 and (stock_prev1 > 0.6 * capacity) and (stock_prev2 > 0.6 * capacity):
                return Action.D
            if rho_prev1 < 0.4 and rho_prev2 < 0.4 or stock_prev1 < 0.4 * capacity or stock_prev2 < 0.4 * capacity:
                if round_number <= self._forced_cooperate_until_round:
                    return Action.C
                self._forced_cooperate_until_round = max(self._forced_cooperate_until_round, round_number + 1)
                return Action.C
        if round_number <= self._forced_cooperate_until_round:
            return Action.C
        if current_stock < 0.5 * capacity:
            return Action.C
        if rho >= 0.6:
            return Action.D
        if 0.3 <= rho < 0.6:
            if current_stock < 0.8 * capacity:
                return Action.C
            return Action.D
        if rho < 0.3:
            if current_stock < 0.9 * capacity:
                return Action.C
            return Action.D
        return Action.C

class Strategy_OPPORTUNISTIC_92(BaseStrategy):
    """
    Common-pool strategy:
    - Open with cooperation only briefly when the horizon allows it.
    - Defect on the final round.
    - In intermediate rounds, cooperate only when the stock is stressed
      and recent opponent cooperation has been sufficiently high.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.coop_est = 1.0
        self.last_recent = 1.0
        self.last_stock_ratio = 1.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_rounds = self.game_description.n_rounds
        n_players = self.game_description.n_players
        n_opponents = max(1, n_players - 1)
        if current_stock <= 0:
            self.last_stock_ratio = 0.0
            return Action.D
        t = history.round_number
        if t == 0:
            return Action.C if n_rounds > 2 else Action.D
        if t == n_rounds - 1:
            self.last_stock_ratio = current_stock / self.game_description.capacity if self.game_description.capacity > 0 else 0.0
            return Action.D
        lookback = min(3, t)
        if lookback <= 0:
            recent = self.coop_est
        else:
            recent_counts = history.opponent_cooperators[-lookback:]
            recent = float(np.mean(recent_counts)) / float(n_opponents)
        self.last_recent = recent
        capacity = self.game_description.capacity
        s = current_stock / capacity if capacity > 0 else 0.0
        self.last_stock_ratio = s
        if s <= 0.35 and recent >= 0.5:
            self.coop_est = recent
            return Action.C
        self.coop_est = recent
        return Action.D

class Strategy_OPPORTUNISTIC_93(BaseStrategy):
    """
    State-contingent threshold strategy for the Common Pool Resource Game.

    - Cooperate on the first round.
    - Defect when stock is too low.
    - Cooperate only when the previous round showed at least majority opponent
      cooperation and the current stock is in the cooperation band.
    - On the last round, cooperate only under the same recovery condition.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(0, self.n_players - 1)
        self.half_opponents = self.n_opponents / 2.0
        self.two_thirds_capacity = 2.0 / 3.0 * self.capacity
        self.one_third_capacity = self.capacity / 3.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number
        if t == 0:
            return Action.C
        stock = float(current_stock)
        if stock <= self.one_third_capacity:
            return Action.D
        prev_opponents = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        prev_majority_coop = prev_opponents >= self.half_opponents
        low2 = False
        high2 = False
        if len(history.opponent_cooperators) >= 2:
            last_two = history.opponent_cooperators[-2:]
            low2 = all((int(x) < self.half_opponents for x in last_two))
            high2 = all((int(x) >= 2.0 * self.n_opponents / 3.0 for x in last_two))
        if low2:
            return Action.D
        if high2 and stock >= self.two_thirds_capacity:
            return Action.C
        if t >= self.n_rounds - 1:
            return Action.C if prev_majority_coop and stock >= self.two_thirds_capacity else Action.D
        if prev_majority_coop and stock >= self.two_thirds_capacity:
            return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_94(BaseStrategy):
    """
    State-based threshold strategy for the Common Pool Resource Game.

    Starts cooperatively, exploits sustained cooperation when the stock and
    opponent behavior allow it, and pivots back to cooperation when the pool
    weakens or cooperation drops sharply.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = max(2, int(game_description.n_players))
        self.r = max(2, int(game_description.n_rounds))
        self.capacity = float(game_description.capacity)
        self._half_n = math.ceil(self.n / 2)
        self._last_threshold = 0.6
        self._last_regime = 'moderate'

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number + 1
        S = float(current_stock)
        n = self.n
        capacity = self.capacity

        def share_c(stock: float) -> float:
            return stock / (2.0 * n) if n > 0 else 0.0

        def share_d(stock: float) -> float:
            return stock / n if n > 0 else 0.0

        def regime_and_threshold(stock: float):
            if stock >= 0.75 * capacity:
                return ('abundant', 0.5)
            if stock >= 0.4 * capacity:
                return ('moderate', 0.6)
            return ('fragile', 0.8)
        if history.round_number == 0:
            self._last_threshold = 0.5
            self._last_regime = 'abundant' if S >= 0.75 * capacity else 'moderate' if S >= 0.4 * capacity else 'fragile'
            return Action.C
        c_last = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        c_prev = int(history.opponent_cooperators[-2]) if len(history.opponent_cooperators) > 1 else c_last
        my_last_action = bool(history.my_actions[-1])
        last_was_coop = my_last_action
        k_hat = c_last + 1 if last_was_coop else c_last
        k_hat = max(0, min(n, k_hat))
        rho = k_hat / n if n > 0 else 0.0
        regime, threshold = regime_and_threshold(S)
        self._last_threshold = threshold
        self._last_regime = regime
        sd = share_d(S)
        sc = share_c(S)
        if t >= self.r - 1:
            if t == self.r:
                return Action.D if sd >= sc else Action.C
            if regime == 'fragile':
                return Action.C if rho >= 0.8 else Action.D
            if S >= 0.5 * capacity and rho < 0.8:
                return Action.D
            return Action.D if sd >= sc else Action.C
        if c_prev - c_last >= 2:
            return Action.C
        prev_payoff_sum = float(history.my_payoffs[-1]) if len(history.my_payoffs) > 0 else 0.0
        prev_stock_estimate = None
        if len(history.my_payoffs) > 1:
            if prev_payoff_sum > 0 and S <= 0.75 * capacity * 0.75:
                if regime != 'fragile' or rho >= 0.8:
                    return Action.C
        if rho >= threshold:
            if sd > sc and rho >= 0.5:
                return Action.D
            if regime == 'fragile' and rho < 0.8:
                return Action.D
            if my_last_action is False:
                if rho >= threshold and regime != 'fragile':
                    return Action.D
            return Action.C
        if regime == 'fragile' and rho >= 0.8:
            return Action.C
        if c_last >= self._half_n and sd > sc:
            return Action.D
        if c_last >= n - 1 and regime != 'fragile':
            return Action.D
        return Action.D

class Strategy_OPPORTUNISTIC_95(BaseStrategy):
    """
    Threshold-based trigger strategy with stock-aware opportunism.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        n_players = int(getattr(game_description, 'n_players', 2))
        self.n_players = n_players
        self.n_opponents = max(0, n_players - 1)
        self.n_rounds = int(getattr(game_description, 'n_rounds', 1))
        self.capacity = float(getattr(game_description, 'capacity', 1.0))
        self.high_threshold = int(math.ceil(self.n_opponents * 2.0 / 3.0))
        self.low_threshold = int(math.floor(self.n_opponents / 3.0))
        self.mode = 'NORMAL'
        self.last_exploit_defect = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = int(history.round_number)
        if t == 0:
            self.mode = 'NORMAL'
            self.last_exploit_defect = False
            return Action.C
        opp_last = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        if t >= self.n_rounds - 1:
            if opp_last >= self.high_threshold:
                if t == self.n_rounds - 1:
                    return Action.D
                return Action.C
            return Action.D
        if current_stock < self.capacity / 4.0:
            self.mode = 'DEFEND'
            self.last_exploit_defect = False
            return Action.D
        if self.mode == 'DEFEND':
            if opp_last >= self.high_threshold:
                self.mode = 'NORMAL'
            else:
                return Action.D
        if opp_last <= self.low_threshold:
            self.mode = 'DEFEND'
            self.last_exploit_defect = False
            return Action.D
        if self.mode == 'EXPLOIT':
            if opp_last >= self.high_threshold and current_stock >= self.capacity / 2.0:
                self.last_exploit_defect = not self.last_exploit_defect
                return Action.D if self.last_exploit_defect else Action.C
            if opp_last < self.high_threshold:
                self.mode = 'DEFEND'
                self.last_exploit_defect = False
                return Action.D
            self.mode = 'NORMAL'
        if opp_last >= self.high_threshold and current_stock > 3.0 * self.capacity / 4.0:
            self.mode = 'NORMAL'
            self.last_exploit_defect = False
            return Action.C
        if opp_last >= self.high_threshold and current_stock >= self.capacity / 2.0:
            self.mode = 'EXPLOIT'
            self.last_exploit_defect = True
            return Action.D
        if opp_last >= self.high_threshold and current_stock >= self.capacity / 2.0:
            return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_96(BaseStrategy):
    """
    Opportunistic common-pool strategy:
    - start by cooperating
    - adapt to current stock, opponent cooperation, and endgame pressure
    - defend the pool when it is fragile, exploit when cooperation collapses
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.recovery_mode = False
        self.recovery_rounds_used = 0
        self.last_seen_round = -1
        self.last_opp_cooperators = None
        self.last_stock = None

    def _action_from_bool(self, cooperate: bool) -> Action:
        return Action.C if cooperate else Action.D

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        k = history.round_number
        S = float(current_stock)
        n = max(self.n, 2)
        capacity = self.capacity if self.capacity > 0 else 1.0
        half = capacity / 2.0
        third = capacity / 3.0
        quarter = capacity / 4.0
        three_quarters = 3.0 * capacity / 4.0
        if k == 0:
            self.recovery_mode = False
            self.recovery_rounds_used = 0
            self.last_seen_round = 0
            self.last_opp_cooperators = None
            self.last_stock = S
            return Action.C
        prev_opp = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        n_opponents = n - 1
        trend = 0
        if len(history.opponent_cooperators) >= 2:
            prev_prev_opp = int(history.opponent_cooperators[-2])
            if prev_opp > prev_prev_opp:
                trend = 1
            elif prev_opp < prev_prev_opp:
                trend = -1
        if k >= self.r - 1:
            self.recovery_mode = False
            self.recovery_rounds_used = 0
            self.last_seen_round = k
            self.last_opp_cooperators = prev_opp
            self.last_stock = S
            if k >= self.r:
                return Action.D
            if S >= three_quarters and prev_opp >= max(n_opponents - 1, 0):
                return Action.C
            return Action.D
        if S <= quarter:
            self.recovery_mode = False
            self.recovery_rounds_used = 0
            self.last_seen_round = k
            self.last_opp_cooperators = prev_opp
            self.last_stock = S
            return Action.D
        if S < half and prev_opp > n_opponents / 2.0:
            self.recovery_mode = True
            if self.recovery_rounds_used < 2:
                self.recovery_rounds_used += 1
                self.last_seen_round = k
                self.last_opp_cooperators = prev_opp
                self.last_stock = S
                return Action.C
        elif self.recovery_mode and self.last_stock is not None:
            if S <= self.last_stock:
                self.recovery_mode = False
                self.recovery_rounds_used = 0
        if len(history.opponent_cooperators) >= 2 and trend != 0:
            if trend > 0:
                action = Action.C
            else:
                action = Action.D
            if action == Action.C and S < half and (prev_opp < n_opponents - 1):
                action = Action.D
            if action == Action.D and S >= half and (prev_opp >= n_opponents - 1):
                action = Action.C
            self.last_seen_round = k
            self.last_opp_cooperators = prev_opp
            self.last_stock = S
            return action
        if S >= half:
            if prev_opp >= max(n_opponents - 1, 0):
                action = Action.C
            else:
                action = Action.D
        elif prev_opp >= max(n_opponents - 1, 0) and S >= third:
            action = Action.C
        else:
            action = Action.D
        if len(history.opponent_cooperators) == 1:
            action = Action.C if S >= half else Action.D
        if prev_opp <= n_opponents / 2.0 and S < three_quarters:
            action = Action.D
        elif prev_opp <= n_opponents / 2.0 and S >= three_quarters:
            action = Action.C if S >= three_quarters else Action.D
        self.last_seen_round = k
        self.last_opp_cooperators = prev_opp
        self.last_stock = S
        return action

class Strategy_OPPORTUNISTIC_97(BaseStrategy):
    """
    Three-mode common-pool strategy with exponentially smoothed cooperation
    estimate and reactive adjustments after fully cooperative or fully defective
    rounds.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self._E = 1.0
        self._last_processed_round = 0

    def _update_estimate_from_last_round(self, history: PlayerHistory) -> None:
        current_round = history.round_number
        n_players = self.game_description.n_players
        n_opponents = max(0, n_players - 1)
        if current_round <= 0:
            return
        start_idx = self._last_processed_round
        if start_idx < 0:
            start_idx = 0
        for t in range(start_idx, current_round):
            if t >= len(history.opponent_cooperators):
                break
            k_t = int(history.opponent_cooperators[t])
            if n_opponents > 0:
                c_t = float(k_t) / float(n_opponents)
            else:
                c_t = 0.0
            self._E = 0.7 * self._E + 0.3 * c_t
            if k_t == n_opponents:
                self._E = min(1.0, self._E + 0.1)
            elif k_t == 0:
                self._E = max(0.0, self._E - 0.25)
        self._last_processed_round = current_round

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_players = self.game_description.n_players
        capacity = float(self.game_description.capacity)
        round_number = history.round_number
        self._update_estimate_from_last_round(history)
        if round_number == 0:
            return Action.C
        last_k = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else -1
        n_opponents = max(0, n_players - 1)
        if n_opponents > 0 and last_k == n_opponents:
            if current_stock >= 0.5 * capacity:
                return Action.C
        if last_k == 0:
            if current_stock < 0.2 * capacity:
                return Action.C
            return Action.D
        if round_number >= max(0, self.game_description.n_rounds - 2):
            return Action.C if self._E >= 0.7 else Action.D
        if self._E >= 0.6 and current_stock >= 0.6 * capacity:
            return Action.C
        if self._E >= 0.45 and current_stock >= 0.8 * capacity:
            return Action.C
        if self._E >= 0.3 and current_stock >= 0.4 * capacity:
            return Action.D
        return Action.C

class Strategy_OPPORTUNISTIC_98(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Cooperate initially.
    - Track a smoothed estimate of opponent cooperation.
    - Defect under low stock, low cooperation, or near game end.
    - Cooperate only when the pool is healthy and cooperation is strong.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self._q_estimate = 1.0
        self._last_seen_rounds = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = float(self.game_description.capacity)
        round_number = history.round_number
        if round_number == 0:
            self._q_estimate = 1.0
            self._last_seen_rounds = 0
            return Action.C
        if round_number > self._last_seen_rounds:
            m = n - 1
            if m > 0 and len(history.opponent_cooperators) > 0:
                k = int(history.opponent_cooperators[-1])
                q = k / m
                if round_number == 1:
                    self._q_estimate = 1.0
                self._q_estimate = 0.7 * self._q_estimate + 0.3 * q
            self._last_seen_rounds = round_number
        q_est = self._q_estimate
        s = float(current_stock)
        t = round_number + 1
        if t >= r:
            return Action.D
        if s <= 2 * n:
            return Action.D
        if t >= r - 1:
            if q_est >= 0.8 and s > 0.6 * capacity:
                return Action.C
            return Action.D
        if q_est >= 0.75 and s > 0.5 * capacity:
            return Action.C
        if q_est >= 0.55 and s > 0.35 * capacity:
            return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_99(BaseStrategy):
    """
    Adaptive cooperation strategy for the Common Pool Resource Game.

    - Starts by cooperating.
    - Cooperates when opponents have shown sufficient restraint and stock is healthy.
    - Defects immediately after low cooperation, especially near the endgame.
    - Tracks recent cooperation rates to avoid repeated low-cooperation traps.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self._n_opponents = max(1, self.n_players - 1)
        self._last_rho_prev = None
        self._last_was_d = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number + 1
        S_t = float(current_stock)
        if S_t <= 0.0:
            self._last_rho_prev = 0.0
            self._last_was_d = True
            return Action.D
        if history.round_number == 0:
            self._last_rho_prev = None
            self._last_was_d = False
            return Action.C
        opp_count = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        opp_count = max(0, min(opp_count, self._n_opponents))
        rho_prev = opp_count / self._n_opponents if self._n_opponents > 0 else 0.0
        p_t = S_t / self.capacity if self.capacity > 0.0 else 0.0
        theta_t = 0.5 + 0.25 * (1.0 - p_t)
        is_last_round = t >= self.n_rounds
        repeated_low_coop = self._last_rho_prev is not None and rho_prev < 0.5 and (self._last_rho_prev < 0.5) and (abs(rho_prev - self._last_rho_prev) < 1e-12)
        if is_last_round:
            if rho_prev == 1.0 and S_t >= self.capacity / 2.0:
                action = Action.C
            else:
                action = Action.D
        elif rho_prev < 0.5:
            action = Action.D
        elif self._last_was_d and rho_prev >= 0.75 and (S_t >= self.capacity / 3.0):
            action = Action.C
        elif rho_prev == 1.0 and S_t >= self.capacity / 3.0:
            action = Action.C
        elif S_t >= 0.8 * self.capacity and rho_prev >= 0.75:
            action = Action.C
        elif repeated_low_coop:
            action = Action.D
        elif rho_prev >= 0.75 and S_t >= self.capacity / 3.0:
            action = Action.C
        elif rho_prev >= 0.5 and S_t >= self.capacity / 4.0 and (rho_prev >= theta_t):
            action = Action.C
        else:
            action = Action.D
        self._last_rho_prev = rho_prev
        self._last_was_d = action == Action.D
        return action

class Strategy_OPPORTUNISTIC_100(BaseStrategy):
    """
    Harvest-conservative strategy for the Common Pool Resource Game.

    - Cooperates in round 1.
    - Defects in the final round, when stock is depleted, or when stock is too low.
    - Uses opponent cooperation history to classify the previous environment as
      high, mixed, or low cooperation.
    - Retaliates quickly against exploitation and only recovers after sustained
      high cooperation.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(0, self.n_players - 1)
        self.high_threshold = math.ceil(2 * self.n_opponents / 3) if self.n_opponents > 0 else 0
        self.mixed_threshold = math.ceil(self.n_opponents / 3) if self.n_opponents > 0 else 0
        self.retaliation_threshold = math.ceil(self.n_opponents / 2) if self.n_opponents > 0 else 0
        self.opportunistic_used = False
        self.last_action = None
        self.high_cooperation_streak = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number + 1
        remaining_rounds = self.n_rounds - t + 1
        if history.round_number == 0:
            self.opportunistic_used = False
            self.high_cooperation_streak = 0
            self.last_action = Action.C
            return Action.C
        if current_stock <= 0.0 or t == self.n_rounds:
            self.last_action = Action.D
            return Action.D
        if current_stock < self.capacity / 3.0:
            self.last_action = Action.D
            return Action.D
        if len(history.opponent_cooperators) > 0:
            k = int(history.opponent_cooperators[-1])
        else:
            k = -1
        prev_action = Action.C if len(history.my_actions) > 0 and bool(history.my_actions[-1]) else Action.D
        high = k >= self.high_threshold if k >= 0 else False
        mixed = k >= self.mixed_threshold if k >= 0 else True
        low = k >= 0 and k < self.mixed_threshold
        streak = 0
        if len(history.opponent_cooperators) > 0:
            for idx in range(len(history.opponent_cooperators) - 1, -1, -1):
                kk = int(history.opponent_cooperators[idx])
                if kk >= self.high_threshold:
                    streak += 1
                else:
                    break
        self.high_cooperation_streak = streak
        if prev_action == Action.D:
            if self.high_cooperation_streak >= 2 and t != self.n_rounds:
                self.last_action = Action.C
                self.opportunistic_used = False
                return Action.C
            self.last_action = Action.D
            return Action.D
        if prev_action == Action.C and k >= 0 and (k < self.retaliation_threshold):
            self.last_action = Action.D
            self.opportunistic_used = False
            return Action.D
        if low:
            action = Action.D
        elif high:
            if remaining_rounds == 2:
                action = Action.C
            elif remaining_rounds > 2 and current_stock >= self.capacity / 2.0:
                action = Action.C
                self.opportunistic_used = False
            else:
                action = Action.D
        elif prev_action == Action.C and current_stock >= 3.0 * self.capacity / 4.0 and (remaining_rounds > 2) and (self.high_cooperation_streak >= 1) and (not self.opportunistic_used):
            action = Action.C
            self.opportunistic_used = True
        else:
            action = Action.D
        if action == Action.D and self.high_cooperation_streak >= 2 and (t != self.n_rounds):
            action = Action.C
            self.opportunistic_used = False
        self.last_action = action
        if action == Action.C and high:
            self.opportunistic_used = False
        return action

class Strategy_OPPORTUNISTIC_101(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - starts cooperative,
    - defects when the pool is healthy and cooperation is widespread,
    - reverts to cooperation under depletion or repeated downward trends,
    - uses a cautious endgame exploitation rule.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.half_opp_majority = max(1, math.ceil((self.n - 1) / 2))
        self.last_stock = None
        self.prev_stock = None
        self.last_action = None
        self.prev_action = None
        self.consecutive_down = 0
        self.consecutive_up = 0
        self.last_recovery_round = -1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        stock = float(current_stock)
        if round_number == 0:
            self.prev_stock = self.last_stock
            self.last_stock = stock
            self.prev_action = self.last_action
            self.last_action = Action.C
            self.consecutive_down = 0
            self.consecutive_up = 0
            return Action.C
        last_opp_coops = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        n_opponents = max(0, self.n - 1)
        if self.last_action == Action.C:
            q_t = (last_opp_coops + 1) / self.n if self.n > 0 else 0.0
        elif self.last_action == Action.D and n_opponents > 0:
            q_t = last_opp_coops / n_opponents
        else:
            q_t = 0.0
        trend = 'flat'
        if self.last_stock is not None:
            if stock > self.last_stock:
                trend = 'up'
            elif stock < self.last_stock:
                trend = 'down'
        if trend == 'down':
            self.consecutive_down += 1
            self.consecutive_up = 0
        elif trend == 'up':
            self.consecutive_up += 1
            self.consecutive_down = 0
        else:
            self.consecutive_down = 0
            self.consecutive_up = 0
        if self.last_stock is not None and self.last_stock <= 0.0 and (stock > self.capacity / 2):
            self.last_recovery_round = round_number
        if round_number >= self.r - 2:
            if round_number == self.r - 1 and stock < self.capacity / 3:
                action = Action.C
            elif stock >= self.capacity / 2:
                action = Action.D
            else:
                action = Action.C
        elif self.consecutive_down >= 2:
            action = Action.C
        elif self.consecutive_up >= 2 and last_opp_coops >= self.half_opp_majority:
            action = Action.D
        elif self.last_stock is not None and self.last_stock <= 0.0 and (stock <= self.capacity / 2):
            action = Action.C
        elif stock <= self.capacity / 4:
            if n_opponents > 0 and last_opp_coops >= self.half_opp_majority:
                action = Action.D
            else:
                action = Action.C
        elif stock >= 3 * self.capacity / 4:
            if n_opponents > 0 and last_opp_coops >= self.half_opp_majority:
                action = Action.D
            else:
                action = Action.C
        elif n_opponents > 0 and last_opp_coops > n_opponents / 2:
            action = Action.C
        elif n_opponents > 0 and last_opp_coops < n_opponents / 2:
            action = Action.D
        else:
            action = self.last_action if self.last_action is not None else Action.C
        if self.last_action == Action.D and action == Action.D:
            if not (self.consecutive_up >= 2 or (n_opponents > 0 and last_opp_coops >= self.half_opp_majority and (q_t >= 0.5))):
                if stock > self.capacity / 2 and self.consecutive_up < 2:
                    action = Action.C
        if stock <= self.capacity / 4 and action == Action.D:
            if not (n_opponents > 0 and last_opp_coops >= self.half_opp_majority):
                action = Action.C
        if self.last_stock is not None and self.last_stock <= 0.0 and (stock <= self.capacity / 2):
            action = Action.C
        self.prev_stock = self.last_stock
        self.last_stock = stock
        self.prev_action = self.last_action
        self.last_action = action
        return action

class Strategy_OPPORTUNISTIC_102(BaseStrategy):
    """
    Cooperative-build / exploit / punish strategy for the Common Pool Resource Game.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.mode = 'build'
        self.coop_streak = 0
        self.last_c_prev = None
        self.last_c_prev_prev = None

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = max(2, int(self.game_description.n_players))
        r = max(2, int(self.game_description.n_rounds))
        capacity = float(self.game_description.capacity) if self.game_description.capacity is not None else 0.0
        m = max(1, n - 1)
        k = math.ceil(m / 2)
        t = history.round_number + 1
        c_prev = k
        c_prev_prev = k
        if history.round_number >= 1:
            c_prev = int(history.opponent_cooperators[-1])
        if history.round_number >= 2:
            c_prev_prev = int(history.opponent_cooperators[-2])
        low_stock = capacity / 4.0 if capacity > 0 else 0.0
        mid_stock = capacity / 2.0 if capacity > 0 else 0.0
        high_stock = 3.0 * capacity / 4.0 if capacity > 0 else 0.0
        if history.round_number == 0:
            self.mode = 'build'
            self.coop_streak = 0
            self.last_c_prev = None
            self.last_c_prev_prev = None
            return Action.C
        if c_prev >= k:
            self.coop_streak += 1
        else:
            self.coop_streak = 0
            self.mode = 'punish'
        if t >= r - 1:
            if c_prev < k:
                action = Action.D
            elif current_stock >= mid_stock:
                action = Action.D
            else:
                action = Action.C
        elif self.mode == 'punish':
            if current_stock <= low_stock:
                action = Action.D
            elif c_prev >= k:
                self.mode = 'build'
                action = Action.C
            else:
                action = Action.D
        elif self.mode == 'exploit':
            if c_prev < k:
                self.mode = 'punish'
                action = Action.D
            elif current_stock >= high_stock:
                action = Action.D
            else:
                action = Action.C
        elif c_prev >= k:
            if c_prev_prev >= k:
                self.mode = 'exploit'
            action = Action.C
        else:
            self.mode = 'punish'
            action = Action.D
        if t >= r:
            if c_prev < k:
                action = Action.D
            else:
                action = Action.D if current_stock >= mid_stock else Action.C
        self.last_c_prev_prev = c_prev_prev
        self.last_c_prev = c_prev
        return action

class Strategy_OPPORTUNISTIC_103(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Cooperate initially
    - Defect in the final round
    - Otherwise react to recent opponent cooperation and current stock level
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(self.n_players - 1, 1)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        if round_number == 0:
            return Action.C
        if round_number >= self.n_rounds - 1:
            return Action.D
        recent_counts = history.opponent_cooperators[max(0, round_number - 3):round_number]
        if len(recent_counts) == 0:
            avg_rho = 0.5
        else:
            recent_fractions = [float(c) / float(self.n_opponents) for c in recent_counts]
            avg_rho = float(np.mean(recent_fractions)) if len(recent_fractions) > 0 else 0.5
        cap = self.capacity if self.capacity > 0 else 1.0
        s = float(current_stock) / cap
        if s <= 0.35:
            return Action.C
        if avg_rho < 0.45 and s <= 0.75:
            return Action.C
        if 0.45 <= avg_rho < 0.55 and s < 0.6:
            return Action.C
        if avg_rho >= 0.7 and s >= 0.6:
            return Action.D
        if 0.55 <= avg_rho < 0.7 and s >= 0.75:
            return Action.D
        if avg_rho < 0.45 and s > 0.75:
            return Action.D
        return Action.C if s < 0.5 else Action.D

class Strategy_OPPORTUNISTIC_104(BaseStrategy):
    """
    Threshold-based conditional strategy for the Common Pool Resource Game.

    Modes:
    - harvest/exploit when cooperation is weak or stock is collapsing
    - test/recover when cooperation is strong
    - adapt thresholds slightly based on cooperation trend
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.m = max(0, self.n - 1)
        self.base_low_stock_cutoff = 1.0 / (2.0 * max(1, self.n))
        self.last_q = None
        self.consecutive_high_q = 0
        self.consecutive_low_q = 0
        self.exploit_rounds_remaining = 0
        self.force_coop_next = False
        self.force_defect_until_recovery = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number + 1
        n = self.n
        r = self.r
        m = self.m
        cap = self.capacity if self.capacity > 0 else 1.0
        x = current_stock / cap
        if x < 0.0:
            x = 0.0
        elif x > 1.0:
            x = 1.0
        if history.round_number > 0 and m > 0:
            k_last = float(history.opponent_cooperators[-1])
            q_last = k_last / float(m)
        else:
            q_last = None
        if q_last is not None:
            if q_last >= 0.8:
                self.consecutive_high_q += 1
            else:
                self.consecutive_high_q = 0
            if q_last <= 0.2:
                self.consecutive_low_q += 1
            else:
                self.consecutive_low_q = 0
            if q_last == 1.0:
                self.force_coop_next = True
                self.force_defect_until_recovery = False
                self.exploit_rounds_remaining = 0
            elif q_last == 0.0:
                self.exploit_rounds_remaining = 2
                self.force_coop_next = False
                self.force_defect_until_recovery = False
            if self.last_q is not None:
                if q_last > self.last_q:
                    self._trend_adjustment = -0.05
                elif q_last < self.last_q:
                    self._trend_adjustment = 0.05
                else:
                    self._trend_adjustment = 0.0
            else:
                self._trend_adjustment = 0.0
            self.last_q = q_last
        else:
            self._trend_adjustment = 0.0
        if history.round_number == 0:
            return Action.C
        if t == r:
            if x >= 0.5:
                return Action.D
            if q_last == 0.0:
                return Action.D
            return Action.C
        if self.exploit_rounds_remaining > 0:
            self.exploit_rounds_remaining -= 1
            return Action.D
        if self.force_defect_until_recovery:
            if x <= 0.15 or (q_last is not None and q_last <= 0.5):
                return Action.D
            self.force_defect_until_recovery = False
        if self.force_coop_next and x > 0.15:
            self.force_coop_next = False
            return Action.C
        if q_last == 0.0:
            if x >= 0.75 and t <= r - 2:
                return Action.D
            return Action.D
        if q_last == 1.0:
            if x <= 0.15:
                return Action.D
            return Action.C
        if self.consecutive_high_q >= 2 and t != r:
            return Action.C
        if self.consecutive_low_q >= 2:
            if x < 0.15:
                self.force_defect_until_recovery = True
                return Action.D
            self.exploit_rounds_remaining = 2
            return Action.D
        adj = getattr(self, '_trend_adjustment', 0.0)
        if x <= self.base_low_stock_cutoff:
            return Action.C
        if x >= 0.75:
            threshold = 0.6 + adj
            if threshold < 0.0:
                threshold = 0.0
            elif threshold > 1.0:
                threshold = 1.0
            return Action.C if q_last >= threshold else Action.D
        if x >= 0.4:
            threshold = 0.5 + adj
            if threshold < 0.0:
                threshold = 0.0
            elif threshold > 1.0:
                threshold = 1.0
            return Action.C if q_last >= threshold else Action.D
        if x > 0.15:
            threshold = 0.7 + adj
            if threshold < 0.0:
                threshold = 0.0
            elif threshold > 1.0:
                threshold = 1.0
            return Action.C if q_last >= threshold else Action.D
        return Action.C if q_last == 1.0 else Action.D

class Strategy_OPPORTUNISTIC_105(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Opens with cooperation.
    - Uses the previous round's opponent cooperation rate and current stock.
    - Enters a conservative defecting/recovery phase when stock is low.
    - Requires one full qualifying recovery round (all opponents cooperated and stock high)
      before switching back to cooperation after a defecting phase.
    - Defects in the final two rounds.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self._in_defect_phase = False
        self._recovery_ready = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        cap = float(self.game_description.capacity)
        half_cap = 0.5 * cap
        quarter_cap = 0.25 * cap
        three_quarter_cap = 0.75 * cap
        round_num = history.round_number
        if round_num == 0:
            self._in_defect_phase = False
            self._recovery_ready = False
            return Action.C
        if round_num >= max(0, r - 2):
            self._in_defect_phase = True
            self._recovery_ready = False
            return Action.D
        last_opp_coops = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        n_opponents = max(0, n - 1)
        rho = last_opp_coops / n_opponents if n_opponents > 0 else 0.0
        if current_stock < quarter_cap:
            self._in_defect_phase = True
            self._recovery_ready = False
            return Action.D
        if self._in_defect_phase:
            if current_stock >= half_cap and rho >= 1.0:
                if self._recovery_ready:
                    self._in_defect_phase = False
                    self._recovery_ready = False
                    return Action.C
                self._recovery_ready = True
            else:
                self._recovery_ready = False
            return Action.D
        if current_stock >= three_quarter_cap and rho >= 0.5:
            return Action.C
        if current_stock >= half_cap and rho >= 2.0 / 3.0:
            return Action.C
        self._in_defect_phase = True
        self._recovery_ready = False
        return Action.D

class Strategy_OPPORTUNISTIC_106(BaseStrategy):
    """
    State-contingent threshold strategy with harvest/test/hold behavior.
    It cooperates first, then adapts to observed opponent cooperation and stock level.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.m = max(self.n - 1, 1)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number + 1
        if history.round_number == 0:
            return Action.C
        last_k = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        c = last_k / self.m if self.m > 0 else 0.0
        high = c >= 0.75
        medium = 0.4 <= c < 0.75
        low = c < 0.4
        has_two = len(history.opponent_cooperators) >= 2
        prev_c = int(history.opponent_cooperators[-2]) / self.m if has_two and self.m > 0 else None
        curr_c = c
        last_two_both_high = has_two and prev_c is not None and (prev_c >= 0.75) and (curr_c >= 0.75)
        last_two_both_low = has_two and prev_c is not None and (prev_c < 0.4) and (curr_c < 0.4)
        if t == self.r:
            if current_stock > self.capacity / 4 and (not high):
                action = Action.D
            else:
                action = Action.C
        elif current_stock <= self.capacity / 3:
            action = Action.C if high else Action.D
        elif current_stock <= 2 * self.capacity / 3:
            if high:
                action = Action.C
            elif medium and t <= self.r - 2:
                action = Action.C
            else:
                action = Action.D
        else:
            action = Action.C if high and t < self.r else Action.D
        if last_two_both_low:
            action = Action.D
        elif last_two_both_high:
            if not (current_stock > 2 * self.capacity / 3 and t >= self.r - 1):
                action = Action.C
        if has_two and prev_c is not None:
            delta = curr_c - prev_c
            if delta >= 0.25:
                if not (current_stock > 2 * self.capacity / 3 and t >= self.r - 1):
                    action = Action.C
            elif delta <= -0.25:
                action = Action.D
        if len(history.my_actions) > 0 and (not bool(history.my_actions[-1])):
            if high and current_stock <= 2 * self.capacity / 3:
                action = Action.C
            elif not high:
                action = Action.D
        if t == self.r:
            if current_stock > self.capacity / 4 and (not high):
                action = Action.D
            elif current_stock <= self.capacity / 4 and high:
                action = Action.C
        return action

class Strategy_OPPORTUNISTIC_107(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Start by cooperating.
    - Enter recovery when the pool is weak or opponents under-cooperate.
    - Defect opportunistically when the pool is healthy and cooperation is reliable.
    - Defect in the last round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_opponents = max(self.n_players - 1, 1)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.last_processed_round = 0
        self.ema_rho = None
        self.in_recovery = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        k = self.n_rounds - round_number
        if round_number > self.last_processed_round and round_number > 0:
            opp_count = int(history.opponent_cooperators[-1])
            rho = opp_count / self.n_opponents if self.n_opponents > 0 else 0.0
            if self.ema_rho is None:
                self.ema_rho = rho
            else:
                self.ema_rho = 0.7 * self.ema_rho + 0.3 * rho
            x_hist = float(current_stock) / self.capacity if self.capacity > 0 else 0.0
            if self.in_recovery and x_hist >= 0.65 and (rho >= 0.5):
                self.in_recovery = False
            self.last_processed_round = round_number
        if round_number == 0:
            return Action.C
        if k <= 1:
            return Action.D
        x = float(current_stock) / self.capacity if self.capacity > 0 else 0.0
        if round_number > 0:
            rho_last = int(history.opponent_cooperators[-1]) / self.n_opponents if self.n_opponents > 0 else 0.0
        else:
            rho_last = 1.0
        if x <= 0.45 or rho_last < 0.5:
            self.in_recovery = True
        elif self.in_recovery and x >= 0.65 and (rho_last >= 0.5):
            self.in_recovery = False
        if self.in_recovery:
            return Action.C

        def theta(remaining_rounds: int) -> float:
            if remaining_rounds > 3:
                return 0.75
            if remaining_rounds == 3:
                return 0.65
            if remaining_rounds == 2:
                return 0.55
            return 1.0
        thresh = theta(k)
        if x >= 0.6 and self.ema_rho is not None and (self.ema_rho >= thresh) and (rho_last >= thresh - 0.1):
            return Action.D
        return Action.C

class Strategy_OPPORTUNISTIC_108(BaseStrategy):
    """
    Adaptive common-pool strategy with trust tracking, scarcity-aware thresholds,
    and late-game edge handling.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.trust = 1.0
        self.mode = 'CONSERVE'
        self._last_processed_round = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_players = max(2, int(self.game_description.n_players))
        n_opponents = max(1, n_players - 1)
        capacity = float(self.game_description.capacity) if self.game_description.capacity is not None else 0.0
        current_round = int(history.round_number) + 1
        if history.round_number == 0:
            self._last_processed_round = 0
            return Action.C
        if self._last_processed_round < history.round_number:
            prev_count = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
            q = prev_count / n_opponents if n_opponents > 0 else 0.0
            if prev_count == 0:
                self.trust *= 0.5
            elif prev_count == n_opponents:
                self.trust = min(1.0, self.trust + 0.1)
            self.trust = 0.7 * self.trust + 0.3 * q
            self.trust = min(1.0, max(0.0, float(self.trust)))
            if q >= 0.75:
                self.mode = 'HARVEST'
            elif q <= 0.25:
                self.mode = 'CONSERVE'
            self._last_processed_round = history.round_number
        trust = float(self.trust)
        stock = float(current_stock)
        scarcity = stock / capacity if capacity > 0 else 0.0
        is_last_round = current_round == int(self.game_description.n_rounds)
        if stock <= capacity / 6.0 if capacity > 0 else False:
            if is_last_round:
                return Action.D if trust < 0.15 else Action.C
            return Action.C
        if is_last_round:
            return Action.D if trust >= 0.25 else Action.C
        if scarcity >= 0.8:
            return Action.D if trust >= 0.2 else Action.C
        elif scarcity >= 0.5:
            return Action.D if trust >= 0.5 else Action.C
        elif scarcity >= 0.3:
            return Action.C if trust < 0.6 else Action.D
        else:
            return Action.C if trust >= 0.35 else Action.D

class Strategy_OPPORTUNISTIC_109(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Cooperates initially to probe and preserve the stock.
    - Tracks consecutive cooperative vs exploitative signals from opponents.
    - Cooperates only when the stock is healthy and recent behavior is stable.
    - Defects quickly under sustained exploitation or low stock.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.trust = 0
        self.pressure = 0
        self.good_rounds = 0
        self.escalation_mode = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = max(2, int(self.game_description.n_players))
        capacity = float(self.game_description.capacity)
        rounds = int(self.game_description.n_rounds)
        n_opponents = max(0, n - 1)
        coop_threshold = math.ceil(n_opponents / 2) if n_opponents > 0 else 0
        t = history.round_number
        if t == 0:
            return Action.C
        try:
            k_prev = int(history.opponent_cooperators[-1])
        except Exception:
            k_prev = 0
        S = float(current_stock)
        if not math.isfinite(S):
            S = 0.0
        S = max(0.0, S)
        low_stock = S <= capacity / 4.0
        high_stock = S >= 3.0 * capacity / 4.0
        above_half = S > capacity / 2.0
        cooperative_signal = k_prev >= coop_threshold
        if cooperative_signal:
            self.trust += 1
            self.pressure = max(0, self.pressure - 1)
            if above_half:
                self.good_rounds += 1
            else:
                self.good_rounds = 0
        else:
            self.pressure += 1
            self.trust = 0
            self.good_rounds = 0
        if self.pressure >= 2:
            self.escalation_mode = True
        if self.escalation_mode:
            if self.good_rounds >= 2 and above_half:
                self.escalation_mode = False
                self.pressure = max(0, self.pressure - 1)
            else:
                action = Action.D
                if t == rounds - 1:
                    action = Action.C if high_stock and cooperative_signal else Action.D
                return action
        if low_stock:
            action = Action.D
        elif high_stock:
            action = Action.C if self.pressure == 0 and cooperative_signal else Action.D
        elif self.trust >= 2 and cooperative_signal and above_half:
            action = Action.C
        else:
            action = Action.D
        if t == rounds - 1:
            action = Action.C if high_stock and cooperative_signal else Action.D
        return action

class Strategy_OPPORTUNISTIC_110(BaseStrategy):
    """
    Threshold-based common pool resource strategy:
    - Cooperate initially.
    - Cooperate under low stock or when cooperation has dropped.
    - Defect when stock is healthy and prior cooperation is sufficiently high.
    - Defect in the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        n = max(2, int(game_description.n_players))
        capacity = float(game_description.capacity)
        self.k_high = math.ceil(2 * n / 3)
        self.k_low = math.ceil(n / 2)
        self.s_low = 0.45 * capacity
        self.s_high = 0.7 * capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        n_rounds = int(self.game_description.n_rounds)
        if round_number == 0:
            return Action.C
        if round_number >= n_rounds - 1:
            return Action.D
        stock = float(current_stock)
        prev_opp_cooperators = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        my_prev_action = bool(history.my_actions[-1]) if len(history.my_actions) > 0 else False
        k_prev = prev_opp_cooperators + (1 if my_prev_action else 0)
        if stock <= self.s_low:
            return Action.C
        elif stock >= self.s_high and k_prev >= self.k_high:
            return Action.D
        elif k_prev <= self.k_low:
            return Action.C
        elif not my_prev_action and k_prev < self.k_high:
            return Action.C
        else:
            return Action.D

class Strategy_OPPORTUNISTIC_111(BaseStrategy):
    """
    State-contingent threshold strategy for the Common Pool Resource Game.
    Modes: build, exploit, and protect.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.low_stock_streak = 0
        self.free_ride_window = 0
        self.last_observed_q = None
        self.prev_observed_q = None
        self.last_seen_round = -1
        self.toggle_exploit = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = float(self.game_description.capacity)
        t = history.round_number + 1
        m = max(1, n - 1)
        opp_counts = history.opponent_cooperators
        q_history = [float(c) / m for c in opp_counts] if len(opp_counts) > 0 else []
        q_bar = float(np.mean(q_history)) if len(q_history) > 0 else 0.0
        q_prev = q_history[-1] if len(q_history) >= 1 else 0.0
        q_prev_prev = q_history[-2] if len(q_history) >= 2 else q_prev
        if self.last_seen_round != history.round_number:
            if current_stock < capacity / 4.0:
                self.low_stock_streak += 1
            else:
                self.low_stock_streak = 0
            if len(q_history) > 0 and q_history[-1] >= 0.6:
                self.free_ride_window += 1
            else:
                self.free_ride_window = 0
            self.prev_observed_q = self.last_observed_q
            self.last_observed_q = q_prev
            self.last_seen_round = history.round_number
        if history.round_number == 0:
            return Action.C
        if current_stock <= 2.0 * n:
            if self.low_stock_streak >= 2:
                return Action.C
            return Action.D
        if t >= r - 1:
            return Action.D
        if self.low_stock_streak >= 2:
            if current_stock <= capacity / 3.0:
                return Action.C
        if self.prev_observed_q is not None and q_prev <= self.prev_observed_q - 0.25:
            return Action.D
        if current_stock >= 0.9 * capacity and q_bar >= 0.7 and (len(q_history) >= 3):
            self.toggle_exploit = not self.toggle_exploit
            return Action.D if self.toggle_exploit else Action.C
        if self.free_ride_window >= 2 and current_stock >= capacity / 2.0:
            self.free_ride_window = 0
            return Action.D
        expected_cooperators = max(0, round(m * max(q_prev, q_bar)))
        consume_c = current_stock / (2.0 * n)
        consume_d = current_stock / float(n)
        remaining_if_c = current_stock - consume_c - expected_cooperators * consume_c
        remaining_if_d = current_stock - consume_d - expected_cooperators * consume_c
        remaining_if_c = max(0.0, remaining_if_c)
        remaining_if_d = max(0.0, remaining_if_d)
        expected_next_stock_if_c = min(remaining_if_c + 2.0 * remaining_if_c * (1.0 - remaining_if_c / capacity), capacity)
        expected_next_stock_if_d = min(remaining_if_d + 2.0 * remaining_if_d * (1.0 - remaining_if_d / capacity), capacity)
        if q_bar >= 0.6 and current_stock >= capacity / 2.0:
            return Action.D
        if q_bar <= 0.4 and current_stock >= capacity / 3.0:
            return Action.C
        if expected_next_stock_if_d > expected_next_stock_if_c:
            return Action.D
        return Action.C

class Strategy_OPPORTUNISTIC_112(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Cooperate in round 1.
    - Protect the stock when it is low.
    - Reward broad cooperation, exploit stable high cooperation,
      and react quickly to sharp drops or rises in observed cooperation.
    - In the final round, defect unless stock is very low.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_opponents = max(self.n_players - 1, 1)
        self.capacity = float(game_description.capacity)
        self.last_observed_p = None
        self.last_observed_cooperators = None

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number
        S = float(current_stock)
        capacity = self.capacity
        if t == 0:
            self.last_observed_p = None
            self.last_observed_cooperators = None
            return Action.C
        coop_last = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        p = coop_last / self.n_opponents if self.n_opponents > 0 else 0.0
        if t == self.game_description.n_rounds - 1:
            return Action.D if S >= 0.25 * capacity else Action.C
        if S < 0.35 * capacity:
            action = Action.C
        elif len(history.opponent_cooperators) >= 2:
            coop_prev = int(history.opponent_cooperators[-2])
            change = coop_last - coop_prev
            threshold = max(1, int(math.ceil(self.n_opponents / 4)))
            if change <= -threshold:
                action = Action.D
            elif change >= threshold:
                action = Action.C
            else:
                action = self._base_decision(p, S, capacity)
        else:
            action = self._base_decision(p, S, capacity)
        self.last_observed_p = p
        self.last_observed_cooperators = coop_last
        return action

    def _base_decision(self, p: float, S: float, capacity: float) -> Action:
        if p >= 1.0:
            return Action.D if S >= 0.6 * capacity else Action.C
        if p <= 0.0:
            return Action.D if S >= 0.2 * capacity else Action.C
        if abs(p - 0.5) < 1e-12:
            return Action.D if S >= 0.5 * capacity else Action.C
        if p > 0.5:
            return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_113(BaseStrategy):
    """
    Adaptive common-pool strategy that cooperates when opponent cooperation
    appears sufficient to sustain the pool, defects under low stock pressure,
    and opportunistically free-rides on strong cooperation.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(0, self.n - 1)
        self._recent_q_values = []
        self._last_seen_round = -1

    def _clamp(self, x: float, lo: float, hi: float) -> float:
        return max(lo, min(hi, x))

    def _safe_q(self, opponent_cooperators: int) -> float:
        if self.n_opponents <= 0:
            return 1.0
        return float(opponent_cooperators) / float(self.n_opponents)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number
        stock = float(current_stock)
        cap = self.capacity if self.capacity > 0 else 1.0
        pressure = self._clamp(1.0 - stock / cap, 0.0, 1.0)
        if t == 0:
            if self.capacity > 0 and self.capacity / max(1, self.n) >= 4.0:
                return Action.C
            return Action.D
        last_k = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        q = self._safe_q(last_k)
        recent_window = history.opponent_cooperators[-3:] if len(history.opponent_cooperators) > 0 else []
        if len(recent_window) > 0 and self.n_opponents > 0:
            avg_q = float(np.mean(recent_window)) / float(self.n_opponents)
        else:
            avg_q = q
        q_eff = max(q, avg_q)
        threshold = self._clamp(0.25 + 0.5 * pressure, 0.25, 0.75)
        if t >= self.r - 1:
            if stock >= 0.75 * cap and q >= 1.0:
                return Action.C
            return Action.D
        if last_k == 0:
            return Action.D
        if self.n_opponents > 0 and last_k >= self.n_opponents:
            if stock >= 0.5 * cap:
                return Action.D
            return Action.C
        if stock <= 0.25 * cap:
            return Action.D
        if stock >= 0.75 * cap and q_eff >= 0.5:
            return Action.D
        if q_eff >= threshold:
            return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_114(BaseStrategy):
    """
    Cautious common-pool strategy:
    start cooperatively, reward sustained cooperation when the pool is healthy,
    and defect quickly when the pool weakens or cooperation collapses.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(0, self.n_players - 1)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = int(history.round_number)
        if t == 0:
            return Action.C
        if t >= self.n_rounds - 1:
            return Action.D
        capacity = self.capacity if self.capacity > 0 else 1.0
        x = float(current_stock) / capacity
        m = self.n_opponents if self.n_opponents > 0 else 1
        last_c = 0.0
        prev_c = None
        if len(history.opponent_cooperators) >= 1:
            last_c = float(history.opponent_cooperators[-1]) / float(m)
        if len(history.opponent_cooperators) >= 2:
            prev_c = float(history.opponent_cooperators[-2]) / float(m)
        if x < 0.35:
            action = Action.D
        elif x < 0.55:
            action = Action.C if last_c >= 0.75 else Action.D
        elif x < 0.85:
            action = Action.C if last_c >= 0.5 else Action.D
        else:
            action = Action.D if last_c <= 0.25 else Action.C
        if last_c >= 0.75 and x >= 0.55:
            action = Action.C
        if last_c <= 0.25 and x < 0.9:
            action = Action.D
        elif last_c <= 0.25 and x >= 0.9:
            action = Action.C
        if prev_c is not None:
            if last_c >= 0.75 and prev_c >= 0.75 and (x >= 0.5):
                action = Action.C
            if last_c <= 0.25 and prev_c <= 0.25 and (x < 0.9):
                action = Action.D
        return action

class Strategy_OPPORTUNISTIC_115(BaseStrategy):
    """
    State-contingent threshold strategy with early cooperation, conditional
    exploitation/punishment, recovery when cooperation is strong enough, and
    full extraction in the final two rounds.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(0, self.n_players - 1)
        self.half_capacity = self.capacity / 2.0
        self.half_coop_threshold = 0.5
        self.strong_coop_threshold = 2.0 / 3.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        if round_number == 0:
            return Action.C
        if round_number >= max(0, self.n_rounds - 2):
            return Action.D
        if len(history.opponent_cooperators) == 0:
            return Action.C
        last_opponent_cooperators = int(history.opponent_cooperators[-1])
        if self.n_opponents > 0:
            x_t = last_opponent_cooperators / self.n_opponents
        else:
            x_t = 1.0
        S_t = float(current_stock)
        if S_t < 0.0:
            S_t = 0.0
        very_low_stock = self.capacity * 0.25
        if x_t < self.half_coop_threshold:
            return Action.D
        if S_t >= self.half_capacity:
            return Action.C
        if S_t <= very_low_stock:
            return Action.C if x_t >= self.strong_coop_threshold else Action.D
        return Action.C if x_t >= self.strong_coop_threshold else Action.D

class Strategy_OPPORTUNISTIC_116(BaseStrategy):
    """
    Common pool resource strategy:
    - Round 1: defect
    - Middle rounds: respond to last-round opponent cooperation rate and current stock
    - Final round: defect
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.last_observed_opponent_cooperators = None

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        n_rounds = self.game_description.n_rounds
        n_opponents = max(n - 1, 1)
        if history.round_number > 0 and len(history.opponent_cooperators) > 0:
            self.last_observed_opponent_cooperators = int(history.opponent_cooperators[-1])
        if history.round_number == 0:
            return Action.D
        if history.round_number >= n_rounds - 1:
            return Action.D
        k = self.last_observed_opponent_cooperators
        if k is None:
            if len(history.opponent_cooperators) > 0:
                k = int(history.opponent_cooperators[-1])
            else:
                k = 0
        if k <= 0:
            return Action.D
        q = k / n_opponents
        if current_stock <= 2 * n:
            if q >= 0.5:
                return Action.C
            return Action.D
        if current_stock > 2 * n:
            if q >= 2 / 3 and current_stock <= 0.8 * self.game_description.capacity:
                return Action.C
            return Action.D
        return Action.D

class Strategy_OPPORTUNISTIC_117(BaseStrategy):
    """
    Adaptive common-pool strategy:
    start cooperative, cooperate when opponent cooperation is sufficiently high
    and the stock is healthy, punish persistent free-riding, and defect when the
    pool is low or cooperation drops below the threshold.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.threshold = int(math.ceil((self.n - 1) / 2.0))
        self.last_processed_round = 0
        self.streak_low = 0
        self.streak_high = 0
        self.avg_coop = 0.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        if round_number == 0:
            return Action.C
        signal = int(history.opponent_cooperators[-1])
        if round_number != self.last_processed_round:
            if signal >= self.threshold:
                self.streak_high += 1
                self.streak_low = 0
            else:
                self.streak_low += 1
                self.streak_high = 0
            if self.last_processed_round <= 0:
                self.avg_coop = float(signal)
            else:
                k = float(round_number)
                self.avg_coop = (self.avg_coop * (k - 1.0) + float(signal)) / k
            self.last_processed_round = round_number
        S = float(current_stock)
        cap = self.capacity if self.capacity > 0 else 1.0
        low_stock = cap / 8.0
        very_low_stock = cap / 4.0
        healthy_stock = 0.8 * cap
        if round_number >= self.rounds - 1:
            if S <= very_low_stock and signal < self.n - 2:
                return Action.D
            return Action.C if signal >= self.threshold else Action.D
        if S <= low_stock:
            return Action.C if signal >= self.n - 1 else Action.D
        if self.streak_low >= 2:
            return Action.C if signal >= self.threshold else Action.D
        if S >= healthy_stock and signal >= self.threshold - 1 and (self.streak_high >= 2):
            return Action.C
        if signal >= self.threshold and S > 0:
            return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_118(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Start with cooperation.
    - Defect in the final round.
    - In intermediate rounds, cooperate when enough opponents cooperated
      previously and the stock is stable or improving; otherwise defect.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self._last_stock = None
        self._last_round = None

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = int(self.game_description.n_players)
        total_rounds = int(self.game_description.n_rounds)
        round_number = int(history.round_number)
        if round_number >= max(total_rounds - 1, 0):
            self._last_stock = float(current_stock)
            self._last_round = round_number
            return Action.D
        if round_number == 0:
            self._last_stock = float(current_stock)
            self._last_round = round_number
            return Action.C
        c = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        stock = float(current_stock)
        prev_stock = None
        if self._last_stock is not None and self._last_round == round_number - 1:
            prev_stock = float(self._last_stock)
        if c >= n - 1:
            self._last_stock = stock
            self._last_round = round_number
            return Action.C
        capacity = float(self.game_description.capacity)
        threshold = int(math.ceil((n - 1) / 2))
        if prev_stock is not None:
            if stock < prev_stock:
                threshold += 1
            elif stock > prev_stock and c >= threshold:
                threshold -= 1
        if capacity > 0 and stock <= capacity / 4.0:
            threshold += 1
        if threshold < 0:
            threshold = 0
        elif threshold > n - 1:
            threshold = n - 1
        if capacity > 0 and stock <= capacity / 4.0 and (c < n - 1):
            action = Action.D
        else:
            action = Action.C if c >= threshold else Action.D
        self._last_stock = stock
        self._last_round = round_number
        return action

class Strategy_OPPORTUNISTIC_119(BaseStrategy):
    """
    Opportunistic common-pool strategy:
    - Start with cooperation.
    - Cooperate when opponents are strongly cooperative and stock is healthy.
    - Defect when stock is low, opponents are mostly defecting, or in the final round
      unless near-universal cooperation is observed.
    - Uses recent stock trend and persistence based on observed opponent cooperation.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(self.n_players - 1, 1)
        self.prev_stock_1 = None
        self.prev_stock_2 = None
        self.force_defect_until_relief = False
        self.force_cooperate_until_relief = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        if round_number == 0:
            self.prev_stock_2 = self.prev_stock_1
            self.prev_stock_1 = float(current_stock)
            return Action.C
        last_c = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        q = last_c / self.n_opponents if self.n_opponents > 0 else 0.0
        q_prev = None
        if len(history.opponent_cooperators) >= 2 and self.n_opponents > 0:
            q_prev = float(history.opponent_cooperators[-2]) / self.n_opponents
        low_coop_two_rounds = q_prev is not None and q_prev <= 0.5 and (q <= 0.5)
        high_coop_two_rounds = q_prev is not None and q_prev >= 2.0 / 3.0 and (q >= 2.0 / 3.0)
        if low_coop_two_rounds:
            self.force_defect_until_relief = True
            self.force_cooperate_until_relief = False
        if high_coop_two_rounds:
            self.force_cooperate_until_relief = True
            self.force_defect_until_relief = False
        stock_t = float(current_stock)
        rising_or_stable = self.prev_stock_1 is not None and stock_t >= self.prev_stock_1
        fallen_two_straight = self.prev_stock_1 is not None and self.prev_stock_2 is not None and (stock_t < self.prev_stock_1) and (self.prev_stock_1 < self.prev_stock_2)
        if round_number == self.n_rounds - 1:
            decision = Action.C if q == 1.0 and stock_t > self.capacity / 3.0 else Action.D
        elif self.force_defect_until_relief and (not (q >= 2.0 / 3.0 or stock_t > self.capacity / 2.0)):
            decision = Action.D
        elif self.force_cooperate_until_relief and (not (q < 0.5 or stock_t <= self.capacity / 4.0)):
            decision = Action.C
        elif stock_t <= self.capacity / 5.0:
            decision = Action.D
        elif q >= 2.0 / 3.0:
            decision = Action.C
        elif q <= 1.0 / 3.0:
            decision = Action.D
        elif rising_or_stable:
            decision = Action.C
        elif fallen_two_straight:
            decision = Action.D
        else:
            decision = Action.C if last_c >= self.n_opponents / 2.0 else Action.D
        self.prev_stock_2 = self.prev_stock_1
        self.prev_stock_1 = stock_t
        return decision

class Strategy_OPPORTUNISTIC_120(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - starts cooperative
    - tracks exponentially weighted opponent cooperation
    - tracks consecutive low-stock rounds
    - defects only from a strong cooperative/high-stock baseline
    - reverts to cooperation when stock is low or cooperation weakens
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.coop_rate = 0.5
        self.low_stock_streak = 0
        self._last_processed_round = 0

    def _update_internal_state(self, history: PlayerHistory, current_stock: float) -> None:
        """Update coop_rate and low_stock_streak using any newly observed round."""
        n_players = self.game_description.n_players
        n_opponents = max(0, n_players - 1)
        while self._last_processed_round < history.round_number:
            idx = self._last_processed_round
            opp_coops = int(history.opponent_cooperators[idx]) if idx < len(history.opponent_cooperators) else 0
            obs_rate = opp_coops / n_opponents if n_opponents > 0 else 0.0
            self.coop_rate = 0.7 * self.coop_rate + 0.3 * obs_rate
            if idx == history.round_number - 1:
                stock_obs = float(current_stock)
            else:
                stock_obs = float(current_stock)
            if stock_obs < 0.5 * self.game_description.capacity:
                self.low_stock_streak += 1
            else:
                self.low_stock_streak = 0
            self._last_processed_round += 1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        self._update_internal_state(history, current_stock)
        capacity = float(self.game_description.capacity)
        round_index_next = history.round_number + 1
        final_round_number = self.game_description.n_rounds
        stock = float(current_stock)
        if round_index_next == final_round_number:
            return Action.D
        if stock <= 0.0:
            return Action.C
        if stock <= 0.35 * capacity:
            return Action.C
        if self.low_stock_streak >= 2:
            return Action.C
        if self.coop_rate >= 0.7 and stock >= 0.75 * capacity:
            return Action.D
        if self.coop_rate >= 0.55 and stock >= 0.6 * capacity:
            return Action.D
        return Action.C

class Strategy_OPPORTUNISTIC_121(BaseStrategy):
    """
    State-contingent threshold strategy with build, exploit, and unwind modes.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self._last_round_seen = -1
        self._coop_obs_streak = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        if round_number == 0:
            self._last_round_seen = 0
            self._coop_obs_streak = 0
            return Action.C
        n_opponents = max(self.n_players - 1, 0)
        if n_opponents <= 0 or len(history.opponent_cooperators) == 0:
            x = 1.0
            opp_count = 0
        else:
            opp_count = int(history.opponent_cooperators[-1])
            x = opp_count / n_opponents
        prev_action = Action.C if bool(history.my_actions[-1]) else Action.D
        is_last_round = round_number == self.n_rounds - 1
        high_zone = current_stock >= 0.8 * self.capacity
        medium_or_above = current_stock >= 0.5 * self.capacity
        low_unwind = current_stock < 0.25 * self.capacity
        if x >= 2.0 / 3.0:
            self._coop_obs_streak += 1
        else:
            self._coop_obs_streak = 0
        if is_last_round:
            return Action.D if medium_or_above else Action.C
        if low_unwind:
            if opp_count == 0:
                return Action.D
            return Action.C
        if opp_count == 0:
            return Action.D
        if x <= 1.0 / 3.0:
            return Action.D
        if x >= 2.0 / 3.0:
            if self._coop_obs_streak < 2 and prev_action == Action.D:
                return Action.D
            if medium_or_above:
                return Action.C
            return Action.D if prev_action == Action.C else Action.C
        if high_zone:
            return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_122(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - starts cooperative,
    - tracks a smoothed cooperation score q,
    - exploits reliable cooperation when stock is healthy,
    - falls back to cooperation during low stock or collapse risk,
    - uses a cautious final-round decision.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.q = 1.0
        self.pending_collapse_coop_rounds = 0
        self._last_collapse_trigger_round = -1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = int(self.game_description.n_players)
        r = int(self.game_description.n_rounds)
        capacity = float(self.game_description.capacity)
        n_opponents = max(n - 1, 1)
        round_number = int(history.round_number)
        q = 1.0
        if round_number > 0:
            opp_coops = history.opponent_cooperators
            for c_t in opp_coops:
                frac = float(c_t) / n_opponents
                q = 0.7 * q + 0.3 * frac
        self.q = q
        low_threshold = (n - 1) / 3.0
        if round_number >= 2:
            last_two_low = float(history.opponent_cooperators[-1]) < low_threshold and float(history.opponent_cooperators[-2]) < low_threshold
            if last_two_low and self._last_collapse_trigger_round != round_number:
                self.pending_collapse_coop_rounds = 2
                self._last_collapse_trigger_round = round_number
        if round_number == 0:
            return Action.C
        if current_stock <= 2.0 * n:
            return Action.C
        if self.pending_collapse_coop_rounds > 0:
            self.pending_collapse_coop_rounds -= 1
            return Action.C
        if round_number >= 1 and float(history.opponent_cooperators[-1]) >= n - 1:
            return Action.C if current_stock <= 2.0 * n else Action.D
        if round_number == r - 1:
            return Action.D if self.q >= 0.5 else Action.C
        if self.q >= 0.65 and current_stock > n:
            return Action.D
        if self.q <= 0.35:
            return Action.C
        return Action.D if current_stock >= capacity / 2.0 else Action.C

class Strategy_OPPORTUNISTIC_123(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Starts cooperatively
    - Exploits when the pool is healthy and cooperation has been high
    - Falls back to cooperation when the stock becomes vulnerable
    - Tracks a simple trust state from observed cooperation
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self._trust_state = 1
        self._processed_rounds = 0

    def _update_trust_from_history(self, history: PlayerHistory) -> None:
        """
        Update internal trust state using any newly observed completed rounds.
        """
        total_rounds_seen = history.round_number
        start = self._processed_rounds
        end = total_rounds_seen
        n_players = max(2, int(self.game_description.n_players))
        n_opponents = max(1, n_players - 1)
        for t in range(start, end):
            if t < len(history.opponent_cooperators):
                coop_count = int(history.opponent_cooperators[t])
                q_t = coop_count / n_opponents
            else:
                q_t = 0.0
            if q_t >= 0.7:
                self._trust_state = min(2, self._trust_state + 1)
            elif q_t <= 0.3:
                self._trust_state = max(0, self._trust_state - 1)
        self._processed_rounds = total_rounds_seen

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        self._update_trust_from_history(history)
        n_players = max(2, int(self.game_description.n_players))
        n_rounds = max(2, int(self.game_description.n_rounds))
        capacity = float(self.game_description.capacity) if self.game_description.capacity else 1.0
        round_idx = history.round_number
        rho = float(current_stock) / capacity if capacity > 0 else 0.0
        n_opponents = max(1, n_players - 1)
        if round_idx > 0 and len(history.opponent_cooperators) >= round_idx:
            prev_coop_count = int(history.opponent_cooperators[round_idx - 1])
            q_prev = prev_coop_count / n_opponents
        else:
            q_prev = 0.0
        if round_idx >= n_rounds - 2:
            return Action.D if rho >= 0.5 else Action.C
        if round_idx == 0:
            return Action.C
        if round_idx == 1:
            return Action.D if q_prev >= 0.5 else Action.C
        if rho <= 0.2:
            return Action.C
        if rho >= 0.7:
            return Action.D if q_prev >= 0.5 else Action.C
        if 0.35 <= rho < 0.7:
            if self._trust_state >= 2:
                return Action.C if q_prev >= 0.6 else Action.D
            if self._trust_state <= 0:
                return Action.C if q_prev >= 0.8 else Action.D
            return Action.C if q_prev >= 0.7 else Action.D
        return Action.C if q_prev >= 0.4 else Action.D

class Strategy_OPPORTUNISTIC_124(BaseStrategy):
    """
    Contingent threshold strategy for the Common Pool Resource game.
    It cooperates early, conditionally cooperates when the pool is healthy,
    defects opportunistically in stable cooperative regimes, and retaliates
    when cooperation collapses.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(getattr(game_description, 'n_players', 0) or 0)
        self.r = int(getattr(game_description, 'n_rounds', 0) or 0)
        self.capacity = float(getattr(game_description, 'capacity', 0) or 0.0)
        self._last_action = Action.C
        self._last_seen_round = -1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.n if self.n >= 2 else 2
        r = self.r if self.r >= 1 else 1
        capacity = self.capacity if self.capacity > 0 else 1.0
        t = int(getattr(history, 'round_number', 0) or 0)
        stock = float(current_stock if current_stock is not None else 0.0)
        if stock < 0.0:
            stock = 0.0
        opp = history.opponent_cooperators
        c_t = int(opp[-1]) if t > 0 and len(opp) > 0 else 0
        previous_c_t = int(opp[-2]) if t > 1 and len(opp) > 1 else c_t
        n_opponents = max(n - 1, 0)

        def clamp_action(action: Action) -> Action:
            return Action.C if action == Action.C else Action.D

        def threshold_high() -> int:
            return int(math.ceil(0.75 * n_opponents))
        if t == 0:
            self._last_action = Action.C
            self._last_seen_round = t
            return Action.C
        if t >= r - 1:
            action = Action.C if stock >= 0.8 * capacity and c_t >= max(n - 2, 0) else Action.D
            self._last_action = action
            self._last_seen_round = t
            return action
        low_stock = stock < 0.4 * capacity
        medium_stock = 0.4 * capacity <= stock < 0.8 * capacity
        high_stock = stock >= 0.8 * capacity
        if low_stock:
            action = Action.C if c_t >= max(n - 2, 0) else Action.D
        elif medium_stock:
            action = Action.C if c_t >= max(n - 1, 0) else Action.D
        else:
            action = Action.C if c_t >= threshold_high() else Action.D
        if 1 <= t <= 3 and stock >= 0.8 * capacity and (c_t >= max(n - 2, 0)):
            action = Action.C
        if c_t >= max(n - 1, 0) and stock >= 0.6 * capacity:
            action = Action.D
        if t > 1 and c_t <= previous_c_t - 2:
            action = Action.D
        if action == Action.D and (c_t >= max(n - 1, 0) or stock < 0.3 * capacity):
            action = Action.C
        action = clamp_action(action)
        self._last_action = action
        self._last_seen_round = t
        return action

class Strategy_OPPORTUNISTIC_125(BaseStrategy):
    """
    Contingent threshold strategy with preservation/exploitation modes,
    trend-sensitive threshold shifts, and final-round simplification.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.opponents = max(self.n - 1, 0)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        S = float(current_stock)
        n = self.n
        capacity = self.capacity
        round_number = history.round_number
        if round_number >= self.rounds - 1:
            if S > 0:
                return Action.D
            return Action.C
        if S <= 0:
            return Action.C
        if round_number == 0:
            if n == 2:
                return Action.C
            return Action.D
        if self.opponents <= 0:
            return Action.C if S < 0.25 * capacity else Action.D
        last_coop = int(history.opponent_cooperators[-1])
        rho = last_coop / self.opponents
        t1 = 1.0 / 3.0
        t2 = 2.0 / 3.0
        if round_number >= 3:
            r0 = int(history.opponent_cooperators[-3]) / self.opponents
            r1 = int(history.opponent_cooperators[-2]) / self.opponents
            r2 = int(history.opponent_cooperators[-1]) / self.opponents
            delta1 = r1 - r0
            delta2 = r2 - r1
            if delta1 >= 0 and delta2 >= 0:
                t1, t2 = (0.23, 0.53)
            elif delta1 < 0 and delta2 < 0:
                t1, t2 = (0.43, 0.73)
        if S >= 0.9 * capacity:
            return Action.D
        if rho >= t2:
            return Action.D
        if rho >= t1:
            return Action.C if S >= 0.6 * capacity else Action.D
        return Action.C if S < 0.25 * capacity else Action.D

class Strategy_OPPORTUNISTIC_126(BaseStrategy):
    """
    Cautious sampler strategy for the Common Pool Resource Game.

    - Cooperate in round 1 to probe the environment.
    - Continue cooperating only in clearly cooperative, healthy states.
    - Defect immediately when cooperation falls below threshold, the stock weakens,
      or the game is nearing its end.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.coop_threshold = math.ceil(2 * self.n_players / 3)
        self.locked_defect = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        if round_number == 0:
            self.locked_defect = False
            return Action.C
        if current_stock <= 0:
            self.locked_defect = True
            return Action.D
        if round_number >= self.n_rounds - 1:
            self.locked_defect = True
            return Action.D
        last_opponent_cooperators = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        last_my_action = bool(history.my_actions[-1]) if len(history.my_actions) > 0 else False
        if last_my_action:
            k = last_opponent_cooperators + 1
        else:
            k = last_opponent_cooperators
        if self.locked_defect:
            if k >= self.coop_threshold and current_stock >= self.capacity / 2:
                self.locked_defect = False
            else:
                return Action.D
        if k == self.n_players and current_stock >= 3 * self.capacity / 4:
            return Action.C
        if k >= self.coop_threshold and current_stock >= self.capacity / 2:
            return Action.C
        self.locked_defect = True
        return Action.D

class Strategy_OPPORTUNISTIC_127(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Start by cooperating.
    - Defect in low-stock or low-cooperation environments.
    - Opportunistically defect once when the pool is healthy and cooperation is high.
    - After a defection wave, keep defecting until cooperation recovers or stock improves.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_opponents = max(self.n_players - 1, 1)
        self.capacity = float(game_description.capacity)
        self.defection_lock = False
        self.opportunistic_toggle = False
        self.last_forced_defection = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        if round_number == 0:
            self.defection_lock = False
            self.last_forced_defection = False
            return Action.C
        cap = self.capacity if self.capacity > 0 else 1.0
        x = float(current_stock) / cap
        opp_counts = history.opponent_cooperators
        q_last = 0.0
        if len(opp_counts) > 0:
            q_last = float(opp_counts[-1]) / self.n_opponents
        if len(opp_counts) >= 2:
            q_prev = float(opp_counts[-2]) / self.n_opponents
            q_bar = 0.5 * (q_prev + q_last)
        elif len(opp_counts) == 1:
            q_bar = q_last
        else:
            q_bar = 0.0
        if len(history.my_actions) > 0 and (not bool(history.my_actions[-1])) and (q_last < 0.5):
            self.defection_lock = True
        elif self.defection_lock and (x >= 0.5 or (len(opp_counts) >= 2 and q_last >= 0.67 and (q_prev >= 0.67))):
            self.defection_lock = False
        if self.defection_lock:
            return Action.D
        if round_number == self.game_description.n_rounds:
            return Action.D
        if x < 0.35:
            return Action.D
        if q_bar < 0.5:
            return Action.D
        if x >= 0.8 and q_bar >= 0.8:
            if not self.opportunistic_toggle:
                self.opportunistic_toggle = True
                self.last_forced_defection = True
                return Action.D
            self.opportunistic_toggle = False
            self.last_forced_defection = False
            return Action.C
        if x >= 0.5 and q_bar >= 0.67:
            self.opportunistic_toggle = False
            self.last_forced_defection = False
            return Action.C
        self.opportunistic_toggle = False
        self.last_forced_defection = False
        return Action.D

class Strategy_OPPORTUNISTIC_128(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Start with cooperation.
    - Use observed opponent cooperation rate and remaining rounds to decide.
    - Temporarily enter recovery mode after two consecutive low-cooperation rounds
      when the stock is depleted, in order to rebuild the pool.
    - Always defect in the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.recovery_mode = False
        self.last_round_entered_recovery = -1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        cap = float(self.game_description.capacity)
        round_number = history.round_number
        rem = r - round_number
        if round_number == 0:
            self.recovery_mode = False
            self.last_round_entered_recovery = -1
            return Action.C
        last_q = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        denom = max(1, n - 1)
        f_last = last_q / denom
        if f_last >= 0.5:
            self.recovery_mode = False
        low_coop_two_rounds = False
        if round_number >= 2 and len(history.opponent_cooperators) >= 2:
            q1 = int(history.opponent_cooperators[-1])
            q2 = int(history.opponent_cooperators[-2])
            f1 = q1 / denom
            f2 = q2 / denom
            low_coop_two_rounds = f1 <= 1.0 / 3.0 and f2 <= 1.0 / 3.0
        if not self.recovery_mode and low_coop_two_rounds and (current_stock <= cap / 3.0):
            self.recovery_mode = True
            self.last_round_entered_recovery = round_number
        if rem <= 1:
            return Action.D
        if rem == 2:
            if self.recovery_mode and current_stock <= cap / 3.0:
                return Action.C
            if f_last >= 0.5 or current_stock > cap / 4.0:
                return Action.D
            return Action.C
        if self.recovery_mode and current_stock <= cap / 3.0 and low_coop_two_rounds:
            return Action.C
        if f_last >= 2.0 / 3.0 and current_stock > cap / 2.0:
            return Action.D
        if f_last <= 1.0 / 3.0 and current_stock <= 2.0 * cap / 3.0:
            return Action.C
        if 1.0 / 3.0 < f_last < 2.0 / 3.0:
            prev_my_action = bool(history.my_actions[-1]) if len(history.my_actions) > 0 else True
            if not prev_my_action:
                return Action.D
            if prev_my_action and current_stock < cap / 2.0:
                return Action.C
            return Action.D
        return Action.D

class Strategy_INDIVIDUALISTIC_33(BaseStrategy):
    """
    Start with cooperation, then cooperate when stock is low or when a majority
    of opponents cooperated in the previous round. Defect on the final round and
    when the environment does not justify restraint.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(getattr(game_description, 'n_players', 0))
        self.n_rounds = int(getattr(game_description, 'n_rounds', 0))
        self.capacity = float(getattr(game_description, 'capacity', 0.0))
        self.n_opponents = max(self.n_players - 1, 0)
        self.majority_threshold = int(math.ceil(self.n_opponents / 2)) if self.n_opponents > 0 else 0
        cap = self.capacity if self.capacity > 0 else 1.0
        self.low_stock_threshold = cap / 3.0
        self.high_stock_threshold = 2.0 * cap / 3.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(getattr(history, 'round_number', 0))
        stock = float(current_stock) if current_stock is not None else 0.0
        if stock <= 0.0:
            return Action.D
        if round_number >= self.n_rounds - 1 and self.n_rounds > 0:
            return Action.D
        if round_number == 0:
            return Action.C
        if stock <= self.low_stock_threshold:
            return Action.C
        coop_prev = 0
        if hasattr(history, 'opponent_cooperators') and len(history.opponent_cooperators) > 0:
            try:
                coop_prev = int(history.opponent_cooperators[-1])
            except Exception:
                coop_prev = 0
        if coop_prev >= self.majority_threshold:
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_34(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Defect in the first and last rounds.
    - In intermediate rounds, cooperate when the pool is in danger or when
      opponent cooperation was unusually low.
    - Otherwise defect when the pool is healthy and opponents cooperate enough.
    - Track stock trends across calls to apply the extra adjustment for
      consecutive falling/rising stock.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self._prev_stock = None
        self._prev_prev_stock = None

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = int(self.game_description.n_players)
        r = int(self.game_description.n_rounds)
        capacity = float(self.game_description.capacity)
        round_number = int(history.round_number)
        prev_stock = self._prev_stock
        prev_prev_stock = self._prev_prev_stock
        falling_two = prev_prev_stock is not None and prev_stock is not None and (current_stock < prev_stock) and (prev_stock < prev_prev_stock)
        rising_two = prev_prev_stock is not None and prev_stock is not None and (current_stock > prev_stock) and (prev_stock > prev_prev_stock)
        if round_number == 0:
            action = Action.D
        elif r > 0 and round_number >= r - 1:
            action = Action.D
        else:
            k = 0
            if len(history.opponent_cooperators) > 0:
                k = int(history.opponent_cooperators[-1])
            half_ceil = math.ceil((n - 1) / 2) if n > 1 else 0
            third_floor = math.floor((n - 1) / 3) if n > 1 else 0
            if current_stock <= capacity / 3.0:
                action = Action.C
            elif current_stock >= 2.0 * capacity / 3.0 and k >= half_ceil:
                action = Action.D
            elif k <= third_floor:
                action = Action.C
            elif falling_two:
                action = Action.C
            else:
                action = Action.D
        self._prev_prev_stock = self._prev_stock
        self._prev_stock = float(current_stock)
        return action

class Strategy_INDIVIDUALISTIC_35(BaseStrategy):
    """
    Threshold-based stock preservation strategy with trust adaptation,
    temporary collapse response, and cooperative recovery.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.baseline = 0.5
        self.trust = 0.5
        self.collapse_remaining = 0
        self.high_coop_streak = 0
        self._processed_rounds = 0

    def _clamp(self, x: float, lo: float, hi: float) -> float:
        return max(lo, min(hi, x))

    def _update_from_history(self, history: PlayerHistory) -> None:
        """
        Absorb any newly observed completed rounds into internal state.
        """
        m = max(self.n - 1, 0)
        while self._processed_rounds < history.round_number:
            idx = self._processed_rounds
            k = float(history.opponent_cooperators[idx]) if idx < len(history.opponent_cooperators) else 0.0
            c_prev = k / m if m > 0 else None
            if m > 0 and c_prev is not None:
                self.trust = 0.7 * self.trust + 0.3 * c_prev
                if c_prev < 0.25:
                    self.collapse_remaining = 2
                    self.high_coop_streak = 0
                elif c_prev >= 0.75:
                    self.high_coop_streak += 1
                else:
                    self.high_coop_streak = 0
            else:
                self.high_coop_streak = 0
            self._processed_rounds += 1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = max(self.n, 2)
        current_stock = float(current_stock)
        self._update_from_history(history)
        round_idx = history.round_number
        final_round_idx = self.r - 1
        if round_idx == 0:
            return Action.C if self.capacity >= 4.0 * n and n > 2 else Action.D
        if round_idx == final_round_idx:
            return Action.D if current_stock > 0.0 else Action.C
        if self.collapse_remaining > 0:
            self.collapse_remaining -= 1
            return Action.D
        p = self._clamp(self.trust, 0.0, 1.0)
        opponent_factor = p / (2.0 * n) + (1.0 - p) / n
        x_C = 1.0 / (2.0 * n) + (n - 1) * opponent_factor
        x_D = 1.0 / n + (n - 1) * opponent_factor
        R_C = current_stock * (1.0 - x_C)
        R_D = current_stock * (1.0 - x_D)
        R_C = max(0.0, R_C)
        R_D = max(0.0, R_D)
        N_C = min(R_C + 2.0 * R_C * (1.0 - (R_C / self.capacity if self.capacity > 0 else 0.0)), self.capacity)
        N_D = min(R_D + 2.0 * R_D * (1.0 - (R_D / self.capacity if self.capacity > 0 else 0.0)), self.capacity)
        cooperate_if_possible = current_stock >= self.capacity / 2.0 and N_C >= N_D * (1.0 - 1.0 / (4.0 * n))
        return Action.C if cooperate_if_possible else Action.D

class Strategy_INDIVIDUALISTIC_36(BaseStrategy):
    """
    Self-interested threshold strategy for the Common Pool Resource Game.

    The strategy combines:
    - cautious opening cooperation,
    - stock-aware threshold cooperation,
    - short retaliation after low cooperation,
    - recovery when cooperation and stock are healthy,
    - late-game extraction.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(self.n_players - 1, 0)
        self.low_stock_floor = self.capacity / (2.0 * self.n_players) if self.n_players > 0 else 0.0
        self.coop_estimate = 0.5
        self.punish_rounds_remaining = 0
        self._last_seen_round = -1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = int(history.round_number)
        S = float(current_stock)
        if t > 0 and t != self._last_seen_round:
            last_k = int(history.opponent_cooperators[-1])
            m = self.n_opponents
            c = last_k / m if m > 0 else 1.0
            self.coop_estimate = 0.7 * self.coop_estimate + 0.3 * c
            if c <= 0.25:
                self.punish_rounds_remaining = 2
            elif self.punish_rounds_remaining > 0:
                self.punish_rounds_remaining -= 1
            self._last_seen_round = t
        if t == 0:
            if self.capacity <= 0:
                return Action.D
            if self.n_rounds > 2:
                return Action.C
            return Action.D
        if S <= 0.0:
            return Action.D
        if S <= self.low_stock_floor:
            return Action.D
        if t >= self.n_rounds - 1:
            return Action.D
        last_k = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else self.n_opponents
        m = self.n_opponents
        c = last_k / m if m > 0 else 1.0
        if self.n_rounds > 0:
            theta = 0.5 + 0.25 * (1.0 - t / self.n_rounds)
        else:
            theta = 0.5
        if t > 0.75 * self.n_rounds:
            if c == 1.0 and S >= 0.6 * self.capacity:
                return Action.C
            return Action.D
        if self.punish_rounds_remaining > 0:
            self.punish_rounds_remaining -= 1
            return Action.D
        if c >= 0.75 and S >= 0.5 * self.capacity:
            return Action.C
        effective_coop_signal = self.coop_estimate if t >= 3 else c
        if c == 1.0 and S >= 0.6 * self.capacity:
            return Action.C
        if S >= 0.35 * self.capacity and effective_coop_signal >= theta and (self.coop_estimate >= 0.6):
            return Action.C
        if S >= 0.5 * self.capacity and effective_coop_signal >= 0.7:
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_37(BaseStrategy):
    """
    Cautious common-pool strategy with trust tracking, recovery mode,
    and endgame defection.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.trust = 0
        self.mode = 'cautious'
        self.cautious_streak = 0
        self.force_defect_next = False
        self._processed_rounds = 0
        self._last_q = 0.5

    def _compute_q(self, history: PlayerHistory, round_index: int) -> float:
        n_players = int(self.game_description.n_players)
        n_opponents = max(n_players - 1, 1)
        if round_index < 0 or round_index >= history.round_number:
            return 0.5
        try:
            k = int(history.opponent_cooperators[round_index])
        except Exception:
            return 0.5
        if n_players <= 2:
            q = float(k)
        else:
            q = float(k) / float(n_opponents)
        if not math.isfinite(q):
            return 0.5
        if q < 0.0:
            return 0.0
        if q > 1.0:
            return 1.0
        return q

    def _process_new_history(self, history: PlayerHistory) -> None:
        total_rounds = history.round_number
        while self._processed_rounds < total_rounds:
            i = self._processed_rounds
            q = self._compute_q(history, i)
            self._last_q = q
            if q >= 2.0 / 3.0:
                self.trust += 1
            elif q <= 1.0 / 3.0:
                self.trust -= 2
            else:
                self.trust -= 1
            if self.trust > 3:
                self.trust = 3
            elif self.trust < -3:
                self.trust = -3
            if q < 0.5:
                self.mode = 'cautious'
                self.cautious_streak = 0
            elif self.mode == 'cautious':
                if q >= 2.0 / 3.0:
                    self.cautious_streak += 1
                    if self.cautious_streak >= 2:
                        self.mode = 'normal'
                else:
                    self.cautious_streak = 0
            if q <= 1.0 / 3.0:
                self.force_defect_next = True
            self._processed_rounds += 1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        self._process_new_history(history)
        n_rounds = int(self.game_description.n_rounds)
        n_players = int(self.game_description.n_players)
        capacity = float(self.game_description.capacity)
        next_round = history.round_number + 1
        is_final_round = next_round >= n_rounds
        if current_stock <= 0.0:
            return Action.D
        if history.round_number == 0:
            return Action.C
        q = self._last_q
        if not math.isfinite(q):
            q = 0.5
            self.mode = 'cautious'
        if self.force_defect_next and (not is_final_round):
            self.force_defect_next = False
            return Action.D
        if is_final_round:
            return Action.D
        if next_round == n_rounds - 1:
            if current_stock >= 0.8 * capacity and q >= 2.0 / 3.0:
                return Action.C
            return Action.D
        if self.mode == 'cautious' and self.cautious_streak < 2:
            return Action.D
        if current_stock >= 0.5 * capacity and self.trust >= 0 and (q >= 0.5):
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_38(BaseStrategy):
    """
    Conditional cooperation strategy for the Common Pool Resource Game.

    Cooperates when the stock is healthy and observed opponent cooperation is
    sufficiently high, defects when the stock is scarce or cooperation falls,
    and always defects in the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.coop_rate = 1.0
        self.lockout = 0
        self._last_seen_round = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_players = max(2, int(self.game_description.n_players))
        n_opponents = max(1, n_players - 1)
        n_rounds = int(self.game_description.n_rounds)
        capacity = float(self.game_description.capacity)
        round_number = int(history.round_number)
        while self._last_seen_round < round_number:
            idx = self._last_seen_round
            if idx < len(history.opponent_cooperators):
                c_t = int(history.opponent_cooperators[idx])
                c_t = max(0, min(c_t, n_opponents))
                round_coop = c_t / n_opponents
                self.coop_rate = 0.7 * self.coop_rate + 0.3 * round_coop
                if round_coop < 0.5:
                    self.lockout = 1
            self._last_seen_round += 1
        if round_number == 0:
            return Action.D if current_stock <= capacity / 3.0 else Action.C
        if round_number >= n_rounds - 1:
            return Action.D
        if self.lockout > 0:
            self.lockout -= 1
            return Action.D
        if current_stock <= capacity / 3.0:
            return Action.D
        if self.coop_rate < 0.5:
            self.lockout = 1
            return Action.D
        if round_number == n_rounds - 2:
            if current_stock >= 3.0 * capacity / 4.0 and self.coop_rate >= 2.0 / 3.0:
                return Action.C
            return Action.D
        return Action.C

class Strategy_INDIVIDUALISTIC_39(BaseStrategy):
    """
    Cooperative-by-default strategy with stock-aware punishment and recovery.

    - Starts cooperatively.
    - Tracks a simple cooperation score g from observed opponent behavior.
    - Uses temporary defection when the pool is overused or during punishment windows.
    - Returns to cooperation when opponents cooperate and the stock is healthy.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.g = 0
        self.punish_timer = 0
        self._last_processed_round = 0

    def _process_observed_rounds(self, history: PlayerHistory, current_stock: float) -> None:
        """
        Update internal state using any newly observed completed rounds.
        """
        start = self._last_processed_round
        end = history.round_number
        n_players = self.game_description.n_players
        n_opponents = max(n_players - 1, 1)
        cap = float(self.game_description.capacity)
        for t in range(start, end):
            opp_c = int(history.opponent_cooperators[t]) if t < len(history.opponent_cooperators) else 0
            q = opp_c / n_opponents
            my_action = bool(history.my_actions[t]) if t < len(history.my_actions) else True
            if q >= 2.0 / 3.0:
                self.g = min(self.g + 1, 3)
            elif q < 1.0 / 3.0:
                self.g = min(self.g + 2, 3)
            else:
                self.g = max(self.g - 1, 0)
            if not my_action and q >= 2.0 / 3.0 and (current_stock > cap / 2.0):
                self.punish_timer = 0
            elif self.punish_timer > 0:
                self.punish_timer = max(self.punish_timer - 1, 0)
        self._last_processed_round = end

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_rounds = self.game_description.n_rounds
        cap = float(self.game_description.capacity)
        if history.round_number == 0:
            return Action.C
        self._process_observed_rounds(history, current_stock)
        if history.round_number == n_rounds - 1:
            return Action.C if current_stock > cap / 2.0 else Action.D
        if self.punish_timer > 0:
            self.punish_timer = max(self.punish_timer - 1, 0)
            return Action.D
        prev_opp_c = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        n_opponents = max(self.game_description.n_players - 1, 1)
        q_prev = prev_opp_c / n_opponents
        if current_stock <= cap / 6.0:
            self.punish_timer = 2
            return Action.D
        if current_stock <= cap / 3.0:
            return Action.D
        if q_prev >= 2.0 / 3.0:
            return Action.C
        if q_prev < 1.0 / 3.0:
            return Action.D
        return Action.C if self.g < 2 else Action.D

class Strategy_INDIVIDUALISTIC_40(BaseStrategy):
    """
    State-driven threshold strategy with preserve, probe, and harvest behavior.
    Uses only aggregate opponent cooperation and current stock to decide.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.mode = 'preserve'
        self.baseline = 1 if game_description.n_players == 2 else 2
        self.trust = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        c = float(self.game_description.capacity)
        if history.round_number == 0:
            return Action.C
        t = history.round_number + 1
        prev_opponents = max(n - 1, 1)
        m = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        x = m / prev_opponents
        if x >= 0.75:
            self.trust = min(self.trust + 1, 3)
        elif x <= 0.25:
            self.trust = max(self.trust - 1, -3)
        if x == 0:
            self.trust = -3
        elif x == 1:
            self.trust = 3
        s = float(current_stock)
        low_stock = 0.25 * c
        mid_stock = 0.4 * c
        high_stock = 0.6 * c
        very_high_stock = 0.8 * c
        if s <= low_stock:
            return Action.C if x >= 0.5 else Action.D
        if t >= r - 1:
            return Action.C if x >= 0.5 and s >= mid_stock else Action.D
        if self.trust >= 2 and s >= high_stock:
            return Action.C
        if self.trust <= -2:
            return Action.D
        if s >= very_high_stock and x >= 0.5:
            return Action.C
        if s >= very_high_stock and x < 0.5:
            return Action.D
        if mid_stock <= s < very_high_stock:
            return Action.C if x >= 0.5 else Action.D
        return Action.D

class Strategy_INDIVIDUALISTIC_41(BaseStrategy):
    """
    Threshold-and-memory strategy for the Common Pool Resource Game.

    Default behavior is defecting, with cooperation reserved for high stock
    levels and strong recent cooperation from opponents. Trust is updated
    from the most recent observed round and is clamped to [-3, 3].
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.trust = 0
        self.forced_defect_rounds = 0
        self.late_game_coop_used = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.n_players
        cap = self.capacity
        round_number = history.round_number
        if round_number > 0 and len(history.opponent_cooperators) > 0:
            k_prev = int(history.opponent_cooperators[-1])
            if k_prev >= n - 2:
                self.trust = min(self.trust + 1, 3)
            if k_prev <= n - 4:
                self.trust = max(self.trust - 2, -3)
                self.forced_defect_rounds = max(self.forced_defect_rounds, 2)
        if self.forced_defect_rounds > 0:
            self.forced_defect_rounds -= 1
        stock = float(current_stock)
        final_two_rounds = round_number >= max(self.n_rounds - 2, 0)
        if round_number == 0:
            if n == 2:
                return Action.D
            if cap > 0 and stock >= cap:
                if cap >= 4.0 * n:
                    return Action.C
            return Action.D
        if final_two_rounds:
            if not self.late_game_coop_used and self.trust >= 2 and (cap > 0) and (stock >= 0.9 * cap):
                self.late_game_coop_used = True
                return Action.C
            return Action.D
        if self.forced_defect_rounds > 0:
            return Action.D
        if cap > 0 and stock <= cap / 3.0:
            return Action.D
        if self.trust <= -2:
            return Action.D
        if cap > 0 and self.trust >= 2 and (stock >= 0.8 * cap):
            return Action.C
        if len(history.opponent_cooperators) > 0:
            k_prev = int(history.opponent_cooperators[-1])
            if k_prev >= n - 1 and stock >= 0.7 * cap:
                return Action.C
            if k_prev == n - 2 and stock >= 0.85 * cap:
                return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_42(BaseStrategy):
    """
    Common-pool strategy with collapse protection, abundance harvesting,
    endgame defection, and a recovery override after sharp stock drops.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self._capacity = float(game_description.capacity)
        self._n_players = int(game_description.n_players)
        self._n_opponents = max(0, self._n_players - 1)
        self._previous_stock = self._capacity
        self._has_previous_stock = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number + 1
        r = int(self.game_description.n_rounds)
        s = float(current_stock)
        cap = self._capacity
        if history.round_number > 0 and self._n_opponents > 0:
            q = float(history.opponent_cooperators[-1]) / float(self._n_opponents)
        else:
            q = 0.0
        if self._has_previous_stock:
            delta_s = s - self._previous_stock
        else:
            delta_s = 0.0
        self._previous_stock = s
        self._has_previous_stock = True

        def middle_band_rule() -> Action:
            if q >= 0.5:
                return Action.C
            return Action.D
        if history.round_number == 0:
            return Action.C
        if t == r:
            return Action.D
        if t == r - 1:
            if s >= 0.7 * cap:
                return Action.D
            return middle_band_rule()
        if delta_s <= -0.15 * cap:
            if s < 0.6 * cap:
                return Action.C
        if s <= 0.4 * cap:
            return Action.C
        if s >= 0.8 * cap:
            return Action.D
        return middle_band_rule()

class Strategy_INDIVIDUALISTIC_43(BaseStrategy):
    """
    Stock-sensitive conditional cooperator for the common pool resource game.

    Cooperates early and only when the stock is healthy and recent opponent
    cooperation has been sufficiently high; otherwise defects, especially in
    low-stock or final-round situations.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        n_rounds = self.n_rounds
        n_players = self.n_players
        if round_number == 0:
            return Action.C
        if round_number >= n_rounds - 1:
            return Action.D
        if self.capacity <= 0:
            x_t = 0.0
        else:
            x_t = float(current_stock) / self.capacity
        opp_counts = history.opponent_cooperators
        n_opponents = max(n_players - 1, 1)
        recent_h = []
        history_len = len(opp_counts)
        for idx in range(max(0, history_len - 3), history_len):
            count = float(opp_counts[idx])
            h_val = count / n_opponents if n_opponents > 0 else 0.0
            if h_val < 0.0:
                h_val = 0.0
            elif h_val > 1.0:
                h_val = 1.0
            recent_h.append(h_val)
        if len(recent_h) == 0:
            m_t = 0.5
        else:
            m_t = float(np.mean(np.array(recent_h, dtype=float)))
        h_last = recent_h[-1] if len(recent_h) >= 1 else None
        h_prev = recent_h[-2] if len(recent_h) >= 2 else None
        if x_t <= 0.35:
            return Action.D
        if x_t >= 0.7:
            return Action.C if m_t >= 0.6 else Action.D
        if 0.45 <= x_t < 0.7:
            return Action.C if m_t >= 0.75 else Action.D
        if 0.35 < x_t < 0.45:
            if round_number < n_rounds - 1:
                if h_last == 1.0 and h_prev == 1.0:
                    return Action.C
            return Action.D
        return Action.D

class Strategy_INDIVIDUALISTIC_44(BaseStrategy):
    """
    Threshold-based common-pool strategy with adaptive strictness.
    Cooperates only when the pool is healthy, the recent cooperation trend is good,
    and the stock is not declining; otherwise defects to preserve payoff.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.min_threshold = 0.7 * self.capacity
        self.base_threshold = 0.75 * self.capacity
        self.max_threshold = 0.9 * self.capacity
        self.relax_level = 0.95 * self.capacity
        self.last_round_defect_level = 0.9 * self.capacity
        self.coop_majority_needed = math.ceil((self.n_players - 1) / 2)
        self.coop_threshold = self.base_threshold
        self.strict_mode = False
        self.last_processed_round = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number

        def prev_round_stock(index_from_end: int) -> float | None:
            idx = t - index_from_end
            if idx < 0 or idx >= t:
                return None
            action = bool(history.my_actions[idx])
            payoff = float(history.my_payoffs[idx])
            denom = 2.0 * self.n_players if action else float(self.n_players)
            if denom <= 0.0:
                return None
            return payoff * denom

        def update_threshold() -> None:
            if t <= self.last_processed_round:
                return
            s_prev = prev_round_stock(1)
            s_prev2 = prev_round_stock(2)
            my_last_action = bool(history.my_actions[-1]) if t >= 1 else False
            last_opp_coop = int(history.opponent_cooperators[-1]) if t >= 1 else 0
            if s_prev is not None:
                if my_last_action and current_stock < s_prev - 0.05 * self.capacity:
                    self.coop_threshold = min(self.coop_threshold + 0.05 * self.capacity, self.max_threshold)
                    self.strict_mode = True
                if s_prev >= self.relax_level and current_stock >= self.relax_level and (t >= 2) and (s_prev2 is not None) and (int(history.opponent_cooperators[-2]) >= self.coop_majority_needed) and (last_opp_coop >= self.coop_majority_needed):
                    self.coop_threshold = max(self.coop_threshold - 0.05 * self.capacity, self.min_threshold)
                    if self.coop_threshold <= self.base_threshold:
                        self.strict_mode = False
                if not my_last_action and current_stock > s_prev:
                    self.strict_mode = True
            self.last_processed_round = t
        update_threshold()
        if t == 0:
            return Action.C
        last_opp_coop = int(history.opponent_cooperators[-1]) if t >= 1 else 0
        s_prev = None
        s_prev2 = None
        if t >= 1:
            a1 = bool(history.my_actions[-1])
            p1 = float(history.my_payoffs[-1])
            s_prev = p1 * (2.0 * self.n_players if a1 else float(self.n_players))
        if t >= 2:
            a2 = bool(history.my_actions[-2])
            p2 = float(history.my_payoffs[-2])
            s_prev2 = p2 * (2.0 * self.n_players if a2 else float(self.n_players))
        is_last_round = t == self.n_rounds - 1
        if is_last_round:
            if current_stock < self.last_round_defect_level:
                return Action.D
            if last_opp_coop == self.n_players - 1:
                return Action.C
            return Action.D
        declining_two_rounds = False
        if s_prev is not None and s_prev2 is not None:
            declining_two_rounds = current_stock - s_prev < 0.0 and s_prev - s_prev2 < 0.0
        healthy_stock = current_stock >= self.coop_threshold
        cooperative_majority = last_opp_coop >= self.coop_majority_needed
        if healthy_stock and cooperative_majority and (not declining_two_rounds) and (not self.strict_mode):
            return Action.C
        if healthy_stock and cooperative_majority and (not declining_two_rounds) and self.strict_mode:
            if current_stock >= self.relax_level:
                return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_45(BaseStrategy):
    """
    Trust-based common-pool strategy:
    - Starts cautiously cooperative
    - Rewards high restraint with openness
    - Punishes overuse with defection
    - Always defects in low-stock or late-horizon situations
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.mode = 'CAUTIOUS'
        self.last_seen_round = -1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        round_number = history.round_number
        if round_number > 0 and self.last_seen_round != round_number - 1:
            opp_counts = history.opponent_cooperators
            last_opp_cooperators = int(opp_counts[-1]) if len(opp_counts) > 0 else 0
            n_opponents = max(n - 1, 1)
            x_last = last_opp_cooperators / n_opponents
            if x_last >= 0.75:
                if self.mode != 'PUNITIVE':
                    self.mode = 'OPEN'
                else:
                    self.mode = 'CAUTIOUS'
            elif x_last >= 0.5:
                self.mode = 'CAUTIOUS'
            else:
                self.mode = 'PUNITIVE'
            self.last_seen_round = round_number - 1
        if round_number == 0:
            self.last_seen_round = -1
            return Action.C
        if current_stock <= 0:
            return Action.D
        if current_stock <= n:
            return Action.D
        prev_opp_cooperators = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        n_opponents = max(n - 1, 1)
        x_prev = prev_opp_cooperators / n_opponents
        if round_number >= r - 1:
            if x_prev >= 1.0 and current_stock > n:
                return Action.C
            return Action.D
        if n == 2:
            if x_prev >= 1.0 and current_stock > n:
                return Action.C
            return Action.D
        if self.mode == 'OPEN':
            return Action.C
        if self.mode == 'CAUTIOUS':
            return Action.C if x_prev >= 0.5 else Action.D
        return Action.D

class Strategy_INDIVIDUALISTIC_46(BaseStrategy):
    """
    Adaptive common-pool strategy with two modes:
    - build: sustain and preserve stock
    - exploit: extract aggressively when cooperation or stock deteriorates
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.mode = 'build'
        self.last_switch_cause = None
        self.good_streak = 0
        self.low_coop_streak = 0
        self._last_seen_round = -1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_rounds = int(self.game_description.n_rounds)
        capacity = float(self.game_description.capacity)
        n_players = int(self.game_description.n_players)
        round_number = int(history.round_number)
        if round_number == 0:
            self.mode = 'build'
            self.last_switch_cause = None
            self.good_streak = 0
            self.low_coop_streak = 0
            self._last_seen_round = 0
            return Action.C
        if round_number >= max(0, n_rounds - 1):
            self._last_seen_round = round_number
            return Action.D
        last_coop_count = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        n_opponents = max(0, n_players - 1)
        if n_opponents <= 0:
            q = 1.0
        elif n_players == 2:
            q = 1.0 if last_coop_count > 0 else 0.0
        else:
            q = last_coop_count / float(n_opponents)
        S = float(current_stock)
        low_stock = S < 0.65 * capacity
        good_stock = S > 0.8 * capacity
        high_stock_for_restore = S > 0.8 * capacity
        low_coop = q < 0.5
        good_coop = q >= 0.5
        if self.mode == 'build':
            if low_stock or low_coop:
                self.mode = 'exploit'
                self.last_switch_cause = 'low_stock' if low_stock else 'low_coop'
                self.good_streak = 0
                self.low_coop_streak = 1 if low_coop else 0
            else:
                self.good_streak = 0
                self.low_coop_streak = 0
        else:
            if low_coop:
                self.low_coop_streak += 1
            else:
                self.low_coop_streak = 0
            if high_stock_for_restore and good_coop:
                self.good_streak += 1
            else:
                self.good_streak = 0
            if self.good_streak >= 2 and self.last_switch_cause in {'low_stock', 'low_coop'}:
                self.mode = 'build'
                self.last_switch_cause = None
                self.good_streak = 0
                self.low_coop_streak = 0
        if self.mode == 'build':
            action = Action.C if S <= 0.9 * capacity else Action.D
        elif S <= 0.4 * capacity and q >= 0.75:
            action = Action.C
        else:
            action = Action.D
        self._last_seen_round = round_number
        return action

class Strategy_INDIVIDUALISTIC_47(BaseStrategy):
    """
    Cooperative-by-default common-pool strategy with stock-sensitive escalation:
    - Cooperate in round 1.
    - Defect in the final round.
    - In between, cooperate only when stock is healthy and recent opponent cooperation
      has been sufficiently strong and stable.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)

    def _majority_threshold(self) -> int:
        n_opp = max(self.n_players - 1, 0)
        return n_opp // 2 + 1

    def _simulate_stock_history(self, history: PlayerHistory):
        """
        Reconstruct stock before and after each completed round using observed actions.
        Returns:
            stocks_before: list[float]
            stocks_after: list[float]
        """
        stocks_before = []
        stocks_after = []
        stock = self.capacity
        rounds_seen = history.round_number
        for t in range(rounds_seen):
            stocks_before.append(stock)
            my_coop = 1 if bool(history.my_actions[t]) else 0
            opp_coop = int(history.opponent_cooperators[t])
            coop_count = my_coop + opp_coop
            coop_count = max(0, min(self.n_players, coop_count))
            n_def = self.n_players - coop_count
            consumption = stock * (coop_count / (2.0 * self.n_players) + n_def / float(self.n_players))
            remaining = stock - consumption
            remaining = max(0.0, remaining)
            growth = 2.0 * remaining * (1.0 - remaining / self.capacity) if self.capacity > 0 else 0.0
            new_stock = min(remaining + growth, self.capacity)
            new_stock = max(0.0, new_stock)
            stocks_after.append(new_stock)
            stock = new_stock
        return (stocks_before, stocks_after)

    def _recent_majority_coop(self, history: PlayerHistory, k: int=2) -> bool:
        n_seen = history.round_number
        if n_seen < k:
            return False
        threshold = self._majority_threshold()
        for idx in range(n_seen - k, n_seen):
            if int(history.opponent_cooperators[idx]) < threshold:
                return False
        return True

    def _recent_non_falling_stock(self, stocks_after) -> bool:
        if len(stocks_after) < 2:
            return True
        return stocks_after[-1] >= stocks_after[-2] >= (stocks_after[-3] if len(stocks_after) >= 3 else stocks_after[-2])

    def _stock_increased_last_two_rounds(self, stocks_after) -> bool:
        if len(stocks_after) < 3:
            return False
        return stocks_after[-1] > stocks_after[-2] > stocks_after[-3]

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number
        n_opp = max(self.n_players - 1, 0)
        half_opp = n_opp / 2.0
        majority_threshold = self._majority_threshold()
        if t == 0:
            return Action.C
        if t >= self.n_rounds - 1:
            return Action.D
        stocks_before, stocks_after = self._simulate_stock_history(history)
        if current_stock < 0.4 * self.capacity:
            return Action.D
        consecutive_low = 0
        for idx in range(t - 1, -1, -1):
            if int(history.opponent_cooperators[idx]) < half_opp:
                consecutive_low += 1
            else:
                break
        if consecutive_low >= 2:
            if self._recent_majority_coop(history, 2) and current_stock >= 0.6 * self.capacity and self._recent_non_falling_stock(stocks_after):
                return Action.C
            return Action.D
        last_opp = int(history.opponent_cooperators[-1])
        if n_opp > 0 and last_opp * 2 == n_opp:
            if current_stock >= 0.8 * self.capacity and self._stock_increased_last_two_rounds(stocks_after):
                return Action.C
            return Action.D
        last_majority = last_opp >= majority_threshold
        prev_majority = False
        if t >= 2:
            prev_majority = int(history.opponent_cooperators[-2]) >= majority_threshold
        stable_stock = current_stock >= 0.6 * self.capacity
        not_falling = len(stocks_after) < 2 or stocks_after[-1] >= stocks_after[-2]
        if last_majority and prev_majority and stable_stock and not_falling:
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_48(BaseStrategy):
    """
    Common-pool strategy:
    - Cooperate in the first round.
    - Defect in the final round.
    - Otherwise, cooperate only when opponents were sufficiently cooperative
      and the stock remains healthy; defect when the stock is low or cooperation
      deteriorates.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.opponents = max(self.n_players - 1, 1)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        if round_number == 0:
            return Action.C
        if round_number >= self.n_rounds - 1:
            return Action.D
        last_opponent_cooperators = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        q = last_opponent_cooperators / self.opponents if self.opponents > 0 else 0.0
        S = float(current_stock)
        cap = self.capacity
        if S <= cap / 3.0:
            return Action.D
        if q >= 2.0 / 3.0 and S >= cap / 2.0:
            return Action.C
        if q <= 1.0 / 3.0:
            return Action.D
        if q > 1.0 / 3.0 and S >= 2.0 * cap / 3.0:
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_49(BaseStrategy):
    """
    Adaptive cooperation-estimation strategy for the Common Pool Resource game.

    - Starts by cooperating.
    - Maintains a smoothed estimate q of opponent cooperation.
    - Defects in the last round, when q is low, or when stock is weak.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.q = 1.0
        self._last_updated_round = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_players = self.game_description.n_players
        n_rounds = self.game_description.n_rounds
        capacity = float(self.game_description.capacity)
        round_number = history.round_number
        t = round_number + 1
        if round_number > 0 and self._last_updated_round < round_number:
            opp_count = int(history.opponent_cooperators[-1])
            n_opponents = max(1, n_players - 1)
            obs = opp_count / n_opponents
            self.q = 0.7 * self.q + 0.3 * obs
            self._last_updated_round = round_number
        if current_stock <= 0.0:
            return Action.D
        if t == n_rounds:
            return Action.D
        if t == 1:
            return Action.C
        if self.q <= 1.0 / 3.0:
            return Action.D
        if current_stock <= 0.35 * capacity:
            return Action.C if self.q >= 2.0 / 3.0 else Action.D
        if t <= n_rounds / 2.0:
            return Action.C if self.q >= 0.5 else Action.D
        if self.q >= 2.0 / 3.0 and current_stock >= 0.5 * capacity:
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_50(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Cooperate in round 1.
    - Rebuild when stock is low.
    - Defect when cooperation is strong enough to sustain extraction.
    - Otherwise compare projected next stock under C vs D and choose the better one.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self._half_capacity = self.capacity / 2.0
        self._n_minus_1 = self.n - 1
        self._floor_half_n = math.floor(self.n / 2)

    def _project_next_stock(self, current_stock: float, m: int, action: Action) -> float:
        n = self.n
        cap = self.capacity
        S = float(current_stock)
        if n <= 0:
            return S
        if action == Action.C:
            total_consumption = m * S / (2.0 * n) + (n - m) * S / n
        else:
            total_consumption = m * S / (2.0 * n) + (n - 1 - m) * S / n + S / n
        R = S - total_consumption
        if R < 0.0:
            R = 0.0
        growth = 2.0 * R * (1.0 - R / cap) if cap > 0.0 else 0.0
        next_stock = R + growth
        return min(next_stock, cap)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number
        n = self.n
        cap = self.capacity
        S = float(current_stock)
        if t == 0:
            return Action.C
        k = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        my_prev_coop = bool(history.my_actions[-1]) if len(history.my_actions) > 0 else False
        m = k + 1 if my_prev_coop else k
        if S <= self._half_capacity:
            return Action.C
        if m >= self._n_minus_1:
            return Action.D
        if m <= self._floor_half_n:
            return Action.C
        if t < self.r - 1:
            next_c = self._project_next_stock(S, m, Action.C)
            next_d = self._project_next_stock(S, m, Action.D)
            if next_c > next_d:
                return Action.C
            return Action.D
        return Action.D

class Strategy_INDIVIDUALISTIC_51(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Start cooperative.
    - Cooperate only under sustained recent cooperation and healthy stock.
    - Defect immediately under sharp cooperation drops or resource depletion.
    - Re-enter cooperation only after repeated evidence of renewed cooperation.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(self.n_players - 1, 0)
        self.forced_defection_remaining = 0
        self.low_stock_forced_defection = False
        self.last_cooperation_ratios = []
        self.last_observed_q = None
        self._last_processed_round = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        capacity = self.capacity if self.capacity > 0 else 1.0
        stock_ratio = current_stock / capacity
        last_q = None
        if round_number > 0 and len(history.opponent_cooperators) > 0:
            opp_count = int(history.opponent_cooperators[-1])
            if self.n_opponents > 0:
                last_q = opp_count / self.n_opponents
            else:
                last_q = 0.0
        if last_q is not None:
            self.last_observed_q = last_q
            self.last_cooperation_ratios.append(last_q)
            if len(self.last_cooperation_ratios) > 2:
                self.last_cooperation_ratios = self.last_cooperation_ratios[-2:]
        if round_number == 0:
            self._last_processed_round = round_number
            return Action.C
        if last_q is not None and last_q < 0.4:
            self.forced_defection_remaining = max(self.forced_defection_remaining, 2)
        if stock_ratio < 0.25:
            self.low_stock_forced_defection = True
        if self.low_stock_forced_defection:
            if stock_ratio >= 0.5 and last_q is not None and (last_q >= 0.6):
                recent = self.last_cooperation_ratios
                if len(recent) >= 2:
                    if recent[-1] >= 0.6 and recent[-2] >= 0.6:
                        self.low_stock_forced_defection = False
                elif len(recent) == 1:
                    pass
            if self.low_stock_forced_defection:
                self._last_processed_round = round_number
                return Action.D
        if self.forced_defection_remaining > 0:
            self.forced_defection_remaining -= 1
            self._last_processed_round = round_number
            return Action.D
        rounds_remaining_including_current = self.n_rounds - round_number
        if rounds_remaining_including_current == 1:
            if last_q is not None and last_q >= 0.8 and (stock_ratio >= 0.6):
                self._last_processed_round = round_number
                return Action.C
            self._last_processed_round = round_number
            return Action.D
        if rounds_remaining_including_current <= 2:
            if last_q is not None and last_q < 0.5:
                self._last_processed_round = round_number
                return Action.D
        recent_qs = self.last_cooperation_ratios[-2:]
        enough_recent_cooperation = True
        for q in recent_qs:
            if q < 0.5:
                enough_recent_cooperation = False
                break
        if last_q is not None and last_q >= 0.6 and (stock_ratio >= 0.45) and enough_recent_cooperation:
            self._last_processed_round = round_number
            return Action.C
        self._last_processed_round = round_number
        return Action.D

class Strategy_INDIVIDUALISTIC_52(BaseStrategy):
    """
    Self-interested stock-maximizing strategy for the Common Pool Resource Game.
    It forecasts next stock under cooperation/defection, then chooses the action
    with the higher continuation-adjusted return, with emergency and opportunism rules.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(self.n - 1, 0)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = max(int(self.n), 2)
        r = max(int(self.r), 1)
        capacity = float(self.capacity) if self.capacity > 0 else 1.0
        S = float(current_stock)
        if history.round_number == 0:
            q = 1.0
        else:
            last_c = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
            denom = max(n - 1, 1)
            q = last_c / denom
            if q < 0.0:
                q = 0.0
            elif q > 1.0:
                q = 1.0
        if S / capacity < 0.25:
            return Action.C
        if S / capacity >= 0.75 and q >= 0.5:
            return Action.D
        opponent_count = max(n - 1, 0)
        expected_opponent_consumption = opponent_count * (q * (S / (2.0 * n)) + (1.0 - q) * (S / n))

        def next_stock_after_my_action(my_consumption: float) -> float:
            total_consumption = my_consumption + expected_opponent_consumption
            remaining = S - total_consumption
            if remaining < 0.0:
                remaining = 0.0
            growth = 2.0 * remaining * (1.0 - remaining / capacity)
            new_stock = remaining + growth
            if new_stock > capacity:
                new_stock = capacity
            elif new_stock < 0.0:
                new_stock = 0.0
            return new_stock
        consumption_c = S / (2.0 * n)
        consumption_d = S / n
        s_c_next = next_stock_after_my_action(consumption_c)
        s_d_next = next_stock_after_my_action(consumption_d)
        beta = (r - history.round_number) / r
        if beta < 0.0:
            beta = 0.0
        u_c = consumption_c + beta * s_c_next
        u_d = consumption_d + beta * s_d_next
        if u_d > u_c:
            return Action.D
        return Action.C

class Strategy_INDIVIDUALISTIC_53(BaseStrategy):
    """
    Conservative-common-pool strategy:
    - Cooperates early and whenever the pool is depleted.
    - Defects in strong-stock / high-cooperation situations, especially near the end.
    - Tracks the last observed cooperation rate q from the previous round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.floor = self.capacity / 3.0
        self.high = 2.0 * self.capacity / 3.0
        self.probe_window = 2
        self.last_q = 0.0
        self.last_stock = self.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.n_players
        t = history.round_number
        stock = float(current_stock) if current_stock is not None else self.last_stock
        self.last_stock = stock
        if t > 0:
            opp_coop = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
            my_last = 1 if bool(history.my_actions[-1]) else 0
            total_coop = opp_coop + my_last
            self.last_q = total_coop / n if n > 0 else 0.0
        q = self.last_q
        rounds_remaining = self.n_rounds - t
        if t == 0:
            return Action.C
        if stock <= 0.0:
            return Action.D
        if rounds_remaining <= self.probe_window:
            return Action.D if stock > self.floor else Action.C
        if stock <= self.floor:
            return Action.C
        if q < 0.5:
            return Action.C
        if stock >= self.high and q >= 0.75:
            return Action.D
        return Action.C

class Strategy_INDIVIDUALISTIC_54(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Cooperate in round 1
    - Defect in the last round
    - Otherwise choose based on current stock and recent opponent cooperation
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(0, self.n_players - 1)
        self.majority = math.ceil(self.n_opponents / 2)
        self.last_k = self.n_opponents
        self.last_avg_k = float(self.n_opponents)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        if round_number == 0:
            return Action.C
        if round_number >= self.n_rounds - 1:
            return Action.D
        opp_hist = history.opponent_cooperators
        k_prev = int(opp_hist[-1]) if len(opp_hist) >= 1 else self.n_opponents
        k_prev2 = int(opp_hist[-2]) if len(opp_hist) >= 2 else self.n_opponents
        avg_k_prev = float(np.mean(opp_hist)) if len(opp_hist) >= 1 else float(self.n_opponents)
        self.last_k = k_prev
        self.last_avg_k = avg_k_prev
        cap = self.capacity
        stock = float(current_stock)
        if cap <= 0:
            return Action.D
        if stock <= cap / 3.0:
            return Action.C if k_prev >= self.majority else Action.D
        if stock <= 2.0 * cap / 3.0:
            return Action.C if k_prev == self.n_opponents and k_prev2 == self.n_opponents else Action.D
        return Action.C if k_prev == self.n_opponents and avg_k_prev >= 0.8 * self.n_opponents else Action.D

class Strategy_INDIVIDUALISTIC_55(BaseStrategy):
    """
    Cautious common-pool strategy:
    start conservatively, defect on clear exploitation,
    and only return to cooperation after sustained broad restraint.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(self.n_players - 1, 1)
        self.locked_defect = False
        self.last_processed_round = -1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        if round_number > self.last_processed_round:
            for t in range(max(self.last_processed_round + 1, 1), round_number):
                if t - 1 < len(history.opponent_cooperators):
                    opp_c = int(history.opponent_cooperators[t - 1])
                    q = opp_c / self.n_opponents
                    if q < 0.5:
                        self.locked_defect = True
                        break
            self.last_processed_round = round_number - 1
        if round_number >= self.n_rounds - 1:
            return Action.D
        if round_number == 0:
            return Action.C if self.n_players == 2 else Action.D
        if self.locked_defect:
            return Action.D
        last_idx = round_number - 1
        if last_idx < 0 or last_idx >= len(history.opponent_cooperators):
            return Action.D
        opp_c_last = int(history.opponent_cooperators[last_idx])
        q_last = opp_c_last / self.n_opponents
        pressure_last = (self.n_opponents - opp_c_last) / self.n_opponents
        if q_last < 0.5:
            self.locked_defect = True
            return Action.D
        if current_stock < 0.6 * self.capacity:
            return Action.D
        recovered = False
        if round_number >= 2 and len(history.opponent_cooperators) >= 2:
            opp_c_prev = int(history.opponent_cooperators[last_idx - 1])
            q_prev = opp_c_prev / self.n_opponents
            if q_prev >= 0.9 and q_last >= 0.9 and (current_stock >= 0.85 * self.capacity):
                recovered = True
        if recovered:
            return Action.C
        if current_stock >= 0.75 * self.capacity and q_last >= 0.75 and (pressure_last <= 0.25):
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_56(BaseStrategy):
    """
    Stock-sensitive conditional cooperator:
    starts by cooperating, ends by defecting, and otherwise cooperates only when
    recent opponent cooperation is high and the stock trajectory looks strong.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.m = max(0, self.n - 1)
        self.last_observed_coop_rate = None
        self.forced_defect_until_recovery = False
        self.last_stock_below_low = False
        self.perfect_coop_streak = 0
        self.extra_coop_granted = False
        self.last_action = None

    def _coop_rate_from_history(self, history: PlayerHistory) -> float:
        if history.round_number <= 0 or self.m <= 0:
            return 1.0
        if len(history.opponent_cooperators) == 0:
            return 1.0
        last_count = int(history.opponent_cooperators[-1])
        if last_count < 0:
            last_count = 0
        if last_count > self.m:
            last_count = self.m
        return last_count / self.m

    def _predict_next_stock(self, current_stock: float, my_action_is_cooperate: bool, coop_rate: float) -> float:
        S = float(current_stock)
        if S <= 0.0 or self.n <= 0:
            return 0.0
        n = float(self.n)
        m = float(self.m)
        coop_count = m * coop_rate
        defect_count = m - coop_count
        my_consumption = S / (2.0 * n) if my_action_is_cooperate else S / n
        total_consumption = coop_count * (S / (2.0 * n)) + defect_count * (S / n) + my_consumption
        remaining = S - total_consumption
        if remaining <= 0.0:
            return 0.0
        growth = 2.0 * remaining * (1.0 - remaining / self.capacity) if self.capacity > 0.0 else 0.0
        new_stock = remaining + growth
        if new_stock < 0.0:
            new_stock = 0.0
        if new_stock > self.capacity:
            new_stock = self.capacity
        return float(new_stock)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = int(history.round_number) + 1
        S = float(current_stock)
        low_stock = 0.4 * self.capacity
        high_stock = 0.6 * self.capacity
        very_high_stock = 0.8 * self.capacity
        coop_rate = self._coop_rate_from_history(history)
        if history.round_number > 0 and len(history.opponent_cooperators) > 0:
            last_count = int(history.opponent_cooperators[-1])
            if self.m > 0 and last_count >= self.m:
                self.perfect_coop_streak += 1
            else:
                self.perfect_coop_streak = 0
            if self.last_observed_coop_rate is not None:
                if self.last_observed_coop_rate - coop_rate >= 0.2:
                    self.forced_defect_until_recovery = True
            self.last_observed_coop_rate = coop_rate
        if self.forced_defect_until_recovery:
            threshold_now = 0.75 - 0.25 * (t - 1) / max(1, self.r - 1)
            if coop_rate >= threshold_now and S >= high_stock:
                self.forced_defect_until_recovery = False
        if S < low_stock:
            self.last_stock_below_low = True
        elif S >= high_stock:
            self.last_stock_below_low = False
        if self.last_stock_below_low and S < high_stock:
            self.last_action = Action.D
            return Action.D
        if history.round_number == 0:
            self.last_action = Action.C
            return Action.C
        if t >= self.r:
            self.last_action = Action.D
            return Action.D
        if self.forced_defect_until_recovery:
            self.last_action = Action.D
            return Action.D
        threshold = 0.75 - 0.25 * (t - 1) / max(1, self.r - 1)
        if self.perfect_coop_streak >= 2 and S > very_high_stock and (not self.extra_coop_granted):
            self.extra_coop_granted = True
            self.last_action = Action.C
            return Action.C
        predicted_c = self._predict_next_stock(S, True, coop_rate)
        predicted_d = self._predict_next_stock(S, False, coop_rate)
        if coop_rate >= threshold and S >= high_stock and (predicted_c >= very_high_stock) and (predicted_c >= predicted_d):
            action = Action.C
        else:
            action = Action.D
        self.last_action = action
        return action

class Strategy_INDIVIDUALISTIC_57(BaseStrategy):
    """
    Individualistic common-pool strategy:
    - Cooperate initially when feasible.
    - Defect in the final round.
    - On the penultimate round, cooperate only when stock is low.
    - Otherwise defect when recent cooperation is already sufficient,
      and cooperate when it is not.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        next_round = round_number + 1
        if next_round >= self.n_rounds:
            return Action.D
        if round_number == 0:
            if self.n_players > 0 and self.capacity / self.n_players >= 1.0:
                return Action.C
            return Action.D
        if current_stock <= 0.0:
            return Action.C
        if next_round == self.n_rounds - 1:
            return Action.C if current_stock <= self.capacity / 4.0 else Action.D
        c = 0
        if history.opponent_cooperators is not None and len(history.opponent_cooperators) > 0:
            c = int(history.opponent_cooperators[-1])
        my_prev_coop = False
        if history.my_actions is not None and len(history.my_actions) > 0:
            my_prev_coop = bool(history.my_actions[-1])
        x = c + 1 if my_prev_coop else c
        coop_rate = x / self.n_players if self.n_players > 0 else 0.0
        if current_stock <= self.capacity / 3.0:
            return Action.C
        if coop_rate >= 0.5:
            return Action.D
        return Action.C

class Strategy_INDIVIDUALISTIC_58(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Start by cooperating.
    - Track recent opponent cooperation and stock level.
    - Cooperate when the pool is healthy and opponents have been cooperative.
    - Defect when stock is scarce, cooperation falls, or the end of the game is near.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self._eps = 1e-09
        self._near_zero = 1e-06

    def _opponent_rate(self, k: int) -> float:
        n = self.n
        if n <= 2:
            return 1.0 if k > 0 else 0.0
        denom = max(1, n - 1)
        return float(k) / float(denom)

    def _next_stock_if(self, S: float, my_consume: float, p: float) -> float:
        n = self.n
        opp_count = max(0, n - 1)
        opp_consume = p * opp_count * (S / (2.0 * n)) + (1.0 - p) * opp_count * (S / n)
        remaining = S - (my_consume + opp_consume)
        if remaining < 0.0:
            remaining = 0.0
        growth = 2.0 * remaining * (1.0 - remaining / self.capacity)
        new_stock = remaining + growth
        if new_stock > self.capacity:
            new_stock = self.capacity
        if new_stock < 0.0:
            new_stock = 0.0
        return float(new_stock)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = int(history.round_number)
        S = float(current_stock)
        n = self.n
        r = self.r
        capacity = self.capacity
        if t == 0:
            return Action.C
        if S <= 0.0:
            return Action.C
        if S <= self._near_zero:
            return Action.D if t < r - 1 else Action.C
        k_prev = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        p = self._opponent_rate(k_prev)
        if t == r - 1:
            return Action.D if S > 0.0 else Action.C
        if S <= n:
            return Action.D
        if S >= capacity / 2.0:
            return Action.C
        e_c = self._next_stock_if(S, S / (2.0 * n), p)
        e_d = self._next_stock_if(S, S / n, p)
        if e_c > e_d + self._eps:
            choice = Action.C
        elif e_d > e_c + self._eps:
            choice = Action.D
        else:
            choice = Action.C if S >= 3.0 * n / 4.0 and p >= 0.5 else Action.D
        if len(history.my_actions) > 0:
            last_my_action = bool(history.my_actions[-1])
            last_payoff = float(history.my_payoffs[-1]) if len(history.my_payoffs) > 0 else 0.0
            prev_stock = S
            if last_my_action and p >= 0.5 and (prev_stock > n):
                choice = Action.C
            if not last_my_action and (p < 0.5 or prev_stock <= n or last_payoff <= 0.0):
                choice = Action.D
        return choice

class Strategy_INDIVIDUALISTIC_59(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Start with cooperation.
    - Defect when stock is low, cooperation is sparse, or cooperation/stock trends deteriorate.
    - End conservatively unless the environment remains clearly cooperative and well stocked.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.prev_round_stock: float | None = None
        self.prev_round_q: float | None = None
        self.cooperated_last_round: bool | None = None

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = int(self.game_description.n_players)
        r = int(self.game_description.n_rounds)
        capacity = float(self.game_description.capacity)
        round_number = int(history.round_number)
        current_round_index = round_number + 1
        if round_number == 0:
            action = Action.C
            self.prev_round_stock = float(current_stock)
            self.prev_round_q = None
            self.cooperated_last_round = True
            return action
        m = max(n - 1, 0)
        k = int(history.opponent_cooperators[-1]) if round_number > 0 else 0
        q = k / m if m > 0 else 1.0
        x = float(current_stock) / capacity if capacity > 0 else 0.0
        if round_number == 1:
            action = Action.C if x > 0.25 else Action.D
            self.prev_round_stock = float(current_stock)
            self.prev_round_q = q
            self.cooperated_last_round = action == Action.C
            return action
        if current_round_index == r:
            action = Action.C if x >= 0.5 and q >= 0.6 else Action.D
            self.prev_round_stock = float(current_stock)
            self.prev_round_q = q
            self.cooperated_last_round = action == Action.C
            return action
        if x <= 0.25 or q <= 0.35:
            action = Action.D
        else:
            trend_defect = False
            if self.cooperated_last_round and self.prev_round_q is not None:
                if self.prev_round_q - q >= 0.2:
                    trend_defect = True
            if self.prev_round_stock is not None and self.prev_round_stock > 0:
                if (self.prev_round_stock - float(current_stock)) / self.prev_round_stock >= 0.2:
                    trend_defect = True
            if trend_defect:
                action = Action.D
            else:
                action = Action.C
        self.prev_round_stock = float(current_stock)
        self.prev_round_q = q
        self.cooperated_last_round = action == Action.C
        return action

class Strategy_INDIVIDUALISTIC_60(BaseStrategy):
    """
    Trust-based common-pool strategy:
    - Start by cooperating to sample the environment.
    - Defect in the final round.
    - Cooperate only when stock is high and observed cooperation is strong.
    - Use the previous round's stock drop as an extra safety check in mid-range stock.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self._last_seen_stock = None

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        if round_number >= self.n_rounds - 1:
            self._last_seen_stock = float(current_stock)
            return Action.D
        if round_number == 0:
            self._last_seen_stock = float(current_stock)
            return Action.C
        T = 1.0
        n_opponents = max(self.n_players - 1, 1)
        for k_t in history.opponent_cooperators:
            coop_fraction = float(k_t) / float(n_opponents)
            T = 0.7 * T + 0.3 * coop_fraction
        stock = float(current_stock)
        cap = self.capacity
        lower_third = cap / 3.0
        upper_third = 2.0 * cap / 3.0
        strong_drop_threshold = cap / 8.0
        prev_drop = 0.0
        if self._last_seen_stock is not None:
            prev_drop = float(self._last_seen_stock) - stock
        if stock < lower_third:
            action = Action.D
        elif stock > upper_third:
            action = Action.C if T > 2.0 / 3.0 else Action.D
        elif lower_third < stock < upper_third:
            if T > 0.75 and prev_drop <= strong_drop_threshold:
                action = Action.C
            else:
                action = Action.D
        else:
            action = Action.D
        self._last_seen_stock = stock
        return action

class Strategy_INDIVIDUALISTIC_61(BaseStrategy):
    """
    Probe cooperatively, then continue cooperating only while the pool remains
    near capacity and opponents maintain at least half cooperation. Defect in
    the final round or immediately after signs of depletion / breakdown.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.reserve_threshold = max(2 * self.n_players, self.capacity / 3.0)
        self.half_opponents_threshold = 0.5
        self._eps = 1e-12

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number
        if t == 0:
            return Action.C
        if t >= self.n_rounds - 1:
            return Action.D
        S = float(current_stock)
        n_opponents = max(self.n_players - 1, 1)
        last_k = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        q = last_k / n_opponents
        my_last_action = bool(history.my_actions[-1]) if len(history.my_actions) > 0 else False
        previous_stock_after_round = S
        if S < self.reserve_threshold:
            return Action.D
        if q < self.half_opponents_threshold:
            return Action.D
        if my_last_action and previous_stock_after_round < 0.9 * self.capacity:
            return Action.D
        if not my_last_action and previous_stock_after_round < 0.8 * self.capacity:
            return Action.D
        return Action.C

class Strategy_INDIVIDUALISTIC_62(BaseStrategy):
    """
    State-based threshold strategy with preserve, punish, and harvest modes.
    Uses only the current stock and the last two observed aggregate cooperation counts.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(self.n_players - 1, 1)
        self.majority_threshold = math.ceil(self.n_opponents / 2)
        self.three_way_threshold = math.floor(self.n_opponents / 3)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        capacity = float(self.capacity)
        stock = float(current_stock)
        if round_number == 0:
            if self.n_rounds == 1:
                if stock > 0.8 * capacity:
                    return Action.C
                return Action.D
            return Action.C
        opp_hist = history.opponent_cooperators
        hist_len = len(opp_hist)

        def fallback_by_stock() -> Action:
            return Action.C if stock > 0.5 * capacity else Action.D
        if hist_len < 2:
            if round_number == self.n_rounds - 1:
                if opp_hist[-1] == self.n_opponents and stock >= 0.5 * capacity:
                    return Action.C
                return Action.D
            if stock > 0.75 * capacity:
                return Action.C
            if stock > 0.5 * capacity:
                return fallback_by_stock()
            if stock > 0.25 * capacity:
                return fallback_by_stock()
            return fallback_by_stock()
        c_prev = int(opp_hist[-1])
        c_prev2 = int(opp_hist[-2])
        rho = c_prev / self.n_opponents if self.n_opponents > 0 else 0.0
        rho_prev2 = c_prev2 / self.n_opponents if self.n_opponents > 0 else 0.0
        last_two_all_coop = c_prev >= self.majority_threshold and c_prev2 >= self.majority_threshold
        last_two_all_defectish = c_prev <= self.three_way_threshold or c_prev2 <= self.three_way_threshold
        if round_number == self.n_rounds - 1:
            if c_prev == self.n_opponents and stock >= 0.5 * capacity:
                return Action.C
            return Action.D
        if last_two_all_defectish:
            if not (stock > 0.9 * capacity and rho == 1.0):
                return Action.D
        if last_two_all_coop:
            if stock >= 0.25 * capacity:
                return Action.C
            return Action.D
        if stock <= 0.25 * capacity:
            if c_prev == self.n_opponents and c_prev2 == self.n_opponents:
                return Action.C
            return Action.D
        if stock <= 0.5 * capacity:
            if rho >= 0.5:
                return Action.C
            return Action.D
        if stock > 0.75 * capacity:
            return Action.C
        if stock > 0.5 * capacity:
            if rho >= 0.5:
                return Action.C
            return Action.D
        return fallback_by_stock()

class Strategy_INDIVIDUALISTIC_63(BaseStrategy):
    """
    Adaptive common-pool strategy:
    cooperate early and when the pool is strong and the group shows restraint,
    but defect when the stock weakens, cooperation is insufficient, or the game
    is nearing the end.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self._majority_threshold = int(math.ceil(max(self.n_players - 1, 0) / 2))
        self._last_stock: float | None = None
        self._forced_defect_until_round: int = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        capacity = self.capacity
        if self._last_stock is not None:
            if self._last_stock - current_stock > capacity / 6.0:
                self._forced_defect_until_round = max(self._forced_defect_until_round, round_number + 2)
        if round_number == 0:
            self._last_stock = float(current_stock)
            return Action.C
        if round_number >= self.n_rounds - 1:
            self._last_stock = float(current_stock)
            return Action.D
        if round_number < self._forced_defect_until_round:
            self._last_stock = float(current_stock)
            return Action.D
        last_round_cooperators = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        if last_round_cooperators < self._majority_threshold:
            self._last_stock = float(current_stock)
            return Action.D
        if current_stock <= capacity / 4.0:
            self._last_stock = float(current_stock)
            return Action.D
        if current_stock >= capacity and self._last_stock is not None and (self._last_stock >= capacity):
            self._last_stock = float(current_stock)
            return Action.C
        if current_stock >= 0.6 * capacity:
            self._last_stock = float(current_stock)
            return Action.C
        if current_stock >= 0.75 * capacity:
            self._last_stock = float(current_stock)
            return Action.C
        self._last_stock = float(current_stock)
        return Action.D

class Strategy_INDIVIDUALISTIC_64(BaseStrategy):
    """
    Conservative reciprocal strategy for the common pool resource game.

    Rules:
    - Cooperate initially.
    - Defect in the final round, or when stock is low.
    - Punish observed defection with one round of D.
    - Resume cooperation only when stock is healthy and recent behavior is nearly fully cooperative.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.trust = True
        self.punish_left = 0
        self._processed_rounds = 0
        self._consecutive_full_coop = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        if round_number == 0:
            self.trust = True
            self.punish_left = 0
            self._processed_rounds = 0
            self._consecutive_full_coop = 0
            return Action.C
        if self._processed_rounds < round_number:
            k = int(history.opponent_cooperators[-1]) if round_number > 0 else 0
            all_coop = k >= max(0, self.n - 1)
            if all_coop:
                self._consecutive_full_coop += 1
                self.trust = True
                if self._consecutive_full_coop >= 2 and current_stock > 0.75 * self.capacity:
                    self.punish_left = 0
            else:
                self._consecutive_full_coop = 0
                self.trust = False
                if self.punish_left < 1:
                    self.punish_left = 1
            self._processed_rounds = round_number
        rounds_remaining = self.r - round_number
        low_half = current_stock <= 0.5 * self.capacity
        very_low = current_stock <= 0.25 * self.capacity
        high_stock = current_stock > 0.75 * self.capacity
        last_k = int(history.opponent_cooperators[-1]) if round_number > 0 else 0
        last_all_coop = last_k >= max(0, self.n - 1)
        if rounds_remaining <= 1:
            return Action.D
        if very_low or low_half:
            return Action.D
        if self.punish_left > 0:
            self.punish_left -= 1
            self.trust = False
            return Action.D
        if rounds_remaining <= 2:
            if not (high_stock and last_all_coop):
                return Action.D
        if not last_all_coop:
            self.punish_left = max(self.punish_left, 1)
            self.trust = False
            return Action.D
        self.trust = True
        return Action.C

class Strategy_INDIVIDUALISTIC_65(BaseStrategy):
    """
    Guarded common-pool strategy:
    - Defect by default
    - Cooperate only after sustained high opponent cooperation,
      near-full stock, and enough remaining rounds
    - Tighten cooperation in the endgame and reset quickly on distrust
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.coop_streak = 0
        self.low_trust_streak = 0
        self.q_history = []
        self.low_stock_phase = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        total_rounds = self.game_description.n_rounds
        capacity = float(self.game_description.capacity)
        round_number = history.round_number
        remaining_rounds_including_current = total_rounds - round_number
        if round_number == 0:
            return Action.D
        n_opponents = max(1, n - 1)
        k = int(history.opponent_cooperators[-1])
        q = k / n_opponents
        self.q_history.append(q)
        if q >= 2.0 / 3.0:
            self.coop_streak += 1
            self.low_trust_streak = 0
        elif q <= 1.0 / 3.0:
            self.low_trust_streak += 1
            self.coop_streak = 0
        else:
            self.coop_streak = 0
            self.low_trust_streak = 0
        if current_stock < 0.7 * capacity:
            self.low_stock_phase = True
        if current_stock >= 0.9 * capacity and self.low_stock_phase:
            pass
        if remaining_rounds_including_current <= 1:
            return Action.D
        if current_stock < 0.85 * capacity or remaining_rounds_including_current <= 2 or self.low_trust_streak >= 1 or (current_stock < 0.7 * capacity):
            return Action.D
        if self.low_stock_phase and current_stock >= 0.9 * capacity:
            if self.coop_streak < 2:
                return Action.D
        if remaining_rounds_including_current <= 3:
            recent_q = self.q_history[-2:] if len(self.q_history) >= 2 else []
            if current_stock >= 0.95 * capacity and len(recent_q) == 2 and (recent_q[0] >= 0.75) and (recent_q[1] >= 0.75):
                return Action.C
            return Action.D
        if remaining_rounds_including_current >= 3 and current_stock >= 0.85 * capacity and (self.coop_streak >= 2) and (q >= 2.0 / 3.0):
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_66(BaseStrategy):
    """
    Cooperate early, then condition cooperation on stock health and aggregate
    opponent cooperation, while defecting in the final round or when the stock
    enters a vulnerable zone.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(self.n_players - 1, 1)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        if round_number == 0:
            return Action.C
        if round_number >= self.n_rounds - 1:
            return Action.D
        cap = self.capacity if self.capacity > 0 else 1.0
        x = float(current_stock) / cap
        if len(history.opponent_cooperators) > 0:
            coop_rates = np.asarray(history.opponent_cooperators, dtype=float) / float(self.n_opponents)
            h = float(np.mean(coop_rates)) if coop_rates.size > 0 else 1.0
            last_round_rate = float(coop_rates[-1]) if coop_rates.size > 0 else 1.0
        else:
            h = 1.0
            last_round_rate = 1.0
        if x >= 0.75:
            action = Action.C
        elif x >= 0.45:
            action = Action.C if h >= 0.5 else Action.D
        else:
            action = Action.D
        if last_round_rate >= 0.75 and x >= 0.45:
            action = Action.C
        if last_round_rate < 0.25:
            action = Action.D
        return action

class Strategy_INDIVIDUALISTIC_67(BaseStrategy):
    """
    Conservative extractor:
    - Defect by default.
    - Cooperate only when the pool is weak and observed cooperation is high enough
      to make preservation personally valuable.
    - Adds a lockout after repeated cooperation drops.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(self.n_players - 1, 1)
        self.last_stock: float | None = None
        self.last_q: float | None = None
        self.drop_lock: bool = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        stock_now = float(current_stock)
        if round_number == 0:
            self.last_stock = stock_now
            self.last_q = None
            self.drop_lock = False
            return Action.D
        if stock_now <= 0:
            self.last_stock = stock_now
            self.drop_lock = True
            return Action.D
        rounds_left = self.n_rounds - round_number
        if rounds_left <= 2:
            self.last_stock = stock_now
            if history.opponent_cooperators.size > 0:
                self.last_q = float(history.opponent_cooperators[-1]) / float(self.n_opponents)
            return Action.D
        opp_counts = history.opponent_cooperators
        last_count = int(opp_counts[-1])
        q_last = float(last_count) / float(self.n_opponents)
        if opp_counts.size >= 2:
            prev_count = int(opp_counts[-2])
            q_prev = float(prev_count) / float(self.n_opponents)
            q_bar = 0.5 * (q_last + q_prev)
        else:
            q_prev = q_last
            q_bar = q_last
        if self.last_stock is None:
            trend = 0.0
        else:
            trend = stock_now - float(self.last_stock)
        strong_signal = last_count >= self.n_opponents and self.last_stock is not None and (stock_now >= float(self.last_stock))
        if opp_counts.size >= 3:
            c0 = int(opp_counts[-3])
            c1 = int(opp_counts[-2])
            c2 = int(opp_counts[-1])
            if c2 < c1 and c1 < c0:
                self.drop_lock = True
        quarter = self.capacity / 4.0
        three_quarter = 3.0 * self.capacity / 4.0
        if stock_now <= quarter:
            threshold = 0.5
        elif stock_now <= three_quarter:
            threshold = 2.0 / 3.0
        else:
            threshold = 1.0
        if strong_signal and stock_now <= three_quarter:
            q_bar = max(q_bar, 2.0 / 3.0)
        if self.drop_lock:
            if q_bar < threshold:
                self.last_stock = stock_now
                self.last_q = q_last
                return Action.D
            self.drop_lock = False
        if stock_now <= quarter:
            action = Action.C if q_bar >= 0.5 else Action.D
        elif stock_now <= three_quarter:
            action = Action.C if q_bar >= 2.0 / 3.0 and trend >= 0.0 else Action.D
        else:
            action = Action.D
        self.last_stock = stock_now
        self.last_q = q_last
        return action

class Strategy_INDIVIDUALISTIC_68(BaseStrategy):
    """
    State-triggered threshold strategy with build, hold, and harvest modes.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.L = max(2, math.ceil(self.r / 5)) if self.r > 5 else 2
        self.H = max(2, math.ceil(self.r / 6)) if self.r > 5 else 2
        self.q_star = 1.0 if self.n == 2 else 0.5
        self._last_round_seen = -1
        self._momentum_block_remaining = 0
        self._recovery_remaining = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number
        if t == 0:
            self._last_round_seen = 0
            self._momentum_block_remaining = 0
            self._recovery_remaining = 0
            return Action.C
        n_opponents = max(1, self.n - 1)
        last_opponents_coop = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        q_prev = last_opponents_coop / n_opponents
        endgame = t > self.r - self.L
        prev_stock = None
        if len(history.my_payoffs) > 0 and len(history.my_actions) > 0:
            last_action = bool(history.my_actions[-1])
            last_payoff = float(history.my_payoffs[-1])
            prev_stock = last_payoff * (2.0 * self.n if last_action else self.n)
        recovery = False
        if prev_stock is not None and len(history.my_actions) > 0:
            if not bool(history.my_actions[-1]) and prev_stock - float(current_stock) > 0.2 * self.capacity:
                recovery = True
        low_run = 0
        for idx in range(len(history.opponent_cooperators) - 1, -1, -1):
            q_i = int(history.opponent_cooperators[idx]) / n_opponents
            if q_i < self.q_star:
                low_run += 1
            else:
                break
        momentum = low_run >= self.H
        if len(history.opponent_cooperators) > 0:
            if q_prev >= self.q_star and current_stock >= 0.5 * self.capacity:
                momentum = False
        if endgame:
            self._last_round_seen = t
            return Action.D
        if recovery:
            self._recovery_remaining = 2
        if self._recovery_remaining > 0:
            self._recovery_remaining -= 1
            self._last_round_seen = t
            return Action.C
        if momentum:
            self._momentum_block_remaining = self.H
        if self._momentum_block_remaining > 0:
            self._momentum_block_remaining -= 1
            self._last_round_seen = t
            return Action.D
        stock = float(current_stock)
        if stock < 0.45 * self.capacity:
            self._last_round_seen = t
            return Action.C
        if stock >= 0.75 * self.capacity:
            if self.n == 2:
                action = Action.C if last_opponents_coop >= 1 and stock >= 0.5 * self.capacity else Action.D
                self._last_round_seen = t
                return action
            if q_prev < self.q_star or stock >= 0.9 * self.capacity:
                self._last_round_seen = t
                return Action.D
            self._last_round_seen = t
            return Action.C
        if self.n == 2:
            action = Action.C if last_opponents_coop >= 1 and stock >= 0.5 * self.capacity else Action.D
            self._last_round_seen = t
            return action
        if q_prev >= self.q_star:
            self._last_round_seen = t
            return Action.C
        self._last_round_seen = t
        return Action.D

class Strategy_INDIVIDUALISTIC_69(BaseStrategy):
    """
    Conservative common-pool strategy:
    - Defect initially and in the final round.
    - Cooperate only when the pool is sufficiently low/medium and prior opponent
      cooperation indicates preservation is worthwhile.
    - Exploit a healthy pool with defection unless cooperation from others is too low.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(self.n_players - 1, 0)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        if round_number == 0:
            return Action.D
        if round_number >= self.n_rounds - 1:
            return Action.D
        if len(history.opponent_cooperators) == 0 or self.n_opponents <= 0:
            q = 0.0
            coop_count = 0
        else:
            coop_count = int(history.opponent_cooperators[-1])
            q = coop_count / self.n_opponents
        very_low_stock = current_stock <= self.capacity / 5.0
        low_stock = current_stock <= self.capacity / 3.0
        high_stock = current_stock >= 2.0 * self.capacity / 3.0
        if very_low_stock:
            return Action.C if q >= 0.5 else Action.D
        if low_stock:
            return Action.C if q >= 0.5 else Action.D
        if high_stock:
            return Action.D if q >= 1.0 / 3.0 else Action.C
        return Action.D if q >= 2.0 / 3.0 else Action.C

class Strategy_INDIVIDUALISTIC_70(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - starts by cooperating,
    - tracks a smoothed estimate of opponent cooperation,
    - defects in the final round,
    - cooperates to help recovery when stock is low,
    - otherwise responds to opponent behavior and stock health.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.avg_opp_coop = 1.0
        self.bad_streak = 0
        self._last_processed_round = -1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = int(self.game_description.n_players)
        r = int(self.game_description.n_rounds)
        round_num = int(history.round_number)
        capacity = float(self.game_description.capacity)
        if round_num > 0 and self._last_processed_round < round_num:
            n_opponents = max(0, n - 1)
            opp_count = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
            if n_opponents > 0:
                if n == 2:
                    opp_rate = 1.0 if opp_count >= 1 else 0.0
                else:
                    opp_rate = opp_count / n_opponents
                self.avg_opp_coop = 0.7 * self.avg_opp_coop + 0.3 * opp_rate
                if opp_rate < 0.5:
                    self.bad_streak += 1
                else:
                    self.bad_streak = 0
            self._last_processed_round = round_num
        if round_num == r - 1:
            return Action.D
        if round_num == 0:
            return Action.C
        if current_stock <= 0.25 * capacity:
            return Action.C
        if self.avg_opp_coop >= 0.5 and current_stock >= 0.4 * capacity:
            return Action.C
        if self.bad_streak >= 2 or current_stock >= 0.7 * capacity:
            return Action.D
        return Action.C

class Strategy_INDIVIDUALISTIC_71(BaseStrategy):
    """
    Cooperative-by-default common pool strategy with cautious/aggressive modes.
    Cooperates early, defects under low stock or weak group cooperation, and
    becomes more aggressive only after sustained high stock and high cooperation.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.mode = 'cautious'
        self._high_signal_streak = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_players = int(self.game_description.n_players)
        n_rounds = int(self.game_description.n_rounds)
        capacity = float(self.game_description.capacity)
        round_number = int(history.round_number)
        if round_number == 0:
            self.mode = 'cautious'
            self._high_signal_streak = 0
            return Action.C
        if round_number >= n_rounds - 1:
            return Action.D
        n_opponents = max(n_players - 1, 0)
        if n_opponents <= 0 or len(history.opponent_cooperators) == 0:
            return Action.C if current_stock > capacity / 2.0 else Action.D
        k_prev = int(history.opponent_cooperators[-1])
        q = k_prev / n_opponents if n_opponents > 0 else 0.0
        high_stock_now = current_stock >= capacity / 2.0
        high_coop_now = q >= 0.75
        if high_stock_now and high_coop_now:
            self._high_signal_streak += 1
        else:
            self._high_signal_streak = 0
        if current_stock < capacity / 2.0 or q < 0.75:
            self.mode = 'cautious'
        elif self._high_signal_streak >= 2:
            self.mode = 'aggressive'
        if current_stock <= n_players:
            return Action.D
        if q < 0.5:
            return Action.D
        if self.mode == 'cautious':
            return Action.C if q >= 0.75 else Action.D
        if self.mode == 'aggressive':
            return Action.C if q >= 0.75 and current_stock >= capacity / 2.0 else Action.D
        return Action.C if current_stock > capacity / 2.0 and q >= 0.75 else Action.D

class Strategy_INDIVIDUALISTIC_72(BaseStrategy):
    """
    Conservative common-pool strategy:
    - Cooperate on the first round.
    - Defect on the final round.
    - Otherwise, cooperate only when observed cooperation is sufficiently high
      relative to the current stock level.
    - Persist in defection after low-cooperation rounds until cooperation recovers
      or the stock becomes low enough to trigger a stricter conservation rule.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self._force_defect = False
        self._last_seen_round = -1
        n_players = int(game_description.n_players)
        self._n_opponents = max(n_players - 1, 1)
        capacity = float(game_description.capacity)
        self._low_stock_threshold = 0.35 * capacity
        self._high_stock_threshold = 0.95 * capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_rounds = int(self.game_description.n_rounds)
        round_number = int(history.round_number)
        if round_number != self._last_seen_round:
            if round_number > 0:
                last_opponent_coop_count = int(history.opponent_cooperators[-1])
                p_last = last_opponent_coop_count / self._n_opponents if self._n_opponents > 0 else 0.0
                if p_last < 0.5:
                    self._force_defect = True
                elif p_last >= 0.5:
                    self._force_defect = False
            self._last_seen_round = round_number
        if round_number == 0:
            return Action.C
        if round_number >= n_rounds - 1:
            return Action.D
        last_opponent_coop_count = int(history.opponent_cooperators[-1])
        p = last_opponent_coop_count / self._n_opponents if self._n_opponents > 0 else 0.0
        s = float(current_stock)
        capacity = float(self.game_description.capacity)
        if capacity <= 0:
            return Action.D
        if self._force_defect and s > self._low_stock_threshold and (p < 0.5):
            return Action.D
        if s <= self._low_stock_threshold:
            return Action.C if p >= 0.75 else Action.D
        if s >= self._high_stock_threshold:
            return Action.D
        theta = 0.5 + 0.25 * (1.0 - s / capacity)
        return Action.C if p >= theta else Action.D

class Strategy_INDIVIDUALISTIC_73(BaseStrategy):
    """
    Hard-start common-pool strategy:
    - Defect in the opening round and on the final round.
    - In between, cooperate only when the pool is at or below half capacity
      and opponents have been withholding cooperation.
    - If the pool just shrank in the previous round, temporarily force
      cooperation for one round when the stock is below half capacity.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(0, self.n_players - 1)
        self.half_capacity = self.capacity / 2.0
        self.half_opponents = self.n_opponents / 2.0
        self.last_stock = None
        self.last_action = Action.D
        self.last_opponent_coops = self.n_opponents

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        if round_number == 0:
            action = Action.D
        elif round_number >= self.n_rounds - 1:
            action = Action.D
        else:
            m = self.last_opponent_coops
            S = float(current_stock)
            previous_stock = self.last_stock
            stock_decreased = False
            if previous_stock is not None:
                stock_decreased = S < previous_stock
            if stock_decreased and S < self.half_capacity:
                action = Action.C
            elif S < self.half_capacity:
                if m < self.half_opponents:
                    action = Action.C
                else:
                    action = Action.D
            elif S > self.half_capacity:
                action = Action.D
            else:
                action = Action.C if m == 0 else Action.D
        if round_number > 0 and len(history.opponent_cooperators) > 0:
            self.last_opponent_coops = int(history.opponent_cooperators[-1])
        self.last_stock = float(current_stock)
        self.last_action = action
        return action

class Strategy_INDIVIDUALISTIC_74(BaseStrategy):
    """
    Adaptive cooperation strategy for the Common Pool Resource Game.

    - Starts cooperatively.
    - Uses the last one or two observed opponent cooperation rates to estimate
      whether cooperation is stable.
    - Cooperates only when stock is healthy and opponent cooperation appears
      sufficient to keep the pool in the replenishment region.
    - Becomes conservative in late rounds and after full-defection episodes.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(0, self.n_players - 1)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        if round_number == 0:
            return Action.C
        stock = float(current_stock)
        if not math.isfinite(stock):
            return Action.D
        opponents = history.opponent_cooperators
        recent_count = min(2, len(opponents))
        recent_rates = []
        if self.n_opponents > 0:
            for idx in range(len(opponents) - recent_count, len(opponents)):
                if idx >= 0:
                    recent_rates.append(float(opponents[idx]) / float(self.n_opponents))
        else:
            recent_rates = [0.0] * recent_count
        f_t = recent_rates[-1] if recent_rates else 0.0
        if len(recent_rates) >= 2:
            H_t = sum(recent_rates[-2:]) / 2.0
            q_t = 0.5 * f_t + 0.5 * H_t
        else:
            H_t = f_t
            q_t = f_t
        if stock <= 0.0:
            tau_s = 0.0
        else:
            tau_s = stock / (stock + 1.0)
            tau_s = min(1.0, max(0.0, tau_s))
        is_final_round = round_number >= self.n_rounds - 1
        if is_final_round:
            if stock >= self.n_players and f_t >= 1.0:
                return Action.C
            return Action.D
        if stock <= self.n_players:
            return Action.D
        if len(recent_rates) >= 1 and recent_rates[-1] <= 0.0:
            if len(recent_rates) < 2:
                return Action.D
            if not (recent_rates[-1] >= 0.5 and recent_rates[-2] >= 0.5 and (stock >= self.n_players)):
                return Action.D
        if stock >= self.capacity * 0.8 and q_t > 0.0:
            return Action.C
        if stock >= self.n_players and q_t >= tau_s:
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_75(BaseStrategy):
    """
    Conditional cooperation strategy for a common-pool resource game:
    start by cooperating, then defect when stock strain, low opponent cooperation,
    or exploitation signals indicate the pool is becoming unrecoverable.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.trend = 1.0
        self.pressure = 0.0
        self.last_processed_round = 0
        self.prev_stock_seen = self.capacity
        self.low_coop_streak = 0
        self.high_coop_streak = 0
        self.exploit_mode = False
        self.coop_mode = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        n = self.n
        capacity = self.capacity
        safe_stock = 0.55 * capacity
        high_stock = 0.8 * capacity
        low_trust = 0.6
        medium_trust = 0.75
        if round_number == 0:
            self.prev_stock_seen = current_stock
            return Action.C
        while self.last_processed_round < round_number:
            idx = self.last_processed_round
            obs = None
            if idx < len(history.opponent_cooperators):
                obs = history.opponent_cooperators[idx]
            if obs is not None:
                m_t = max(n - 1, 1)
                c_t = float(obs) / float(m_t)
                c_t = 0.0 if c_t < 0.0 else 1.0 if c_t > 1.0 else c_t
                self.trend = 0.7 * self.trend + 0.3 * c_t
                if capacity > 0:
                    self.pressure = 0.7 * self.pressure + 0.3 * (1.0 - current_stock / capacity)
                else:
                    self.pressure = 0.7 * self.pressure
                if c_t < 0.5:
                    self.low_coop_streak += 1
                else:
                    self.low_coop_streak = 0
                if c_t >= 0.75:
                    self.high_coop_streak += 1
                else:
                    self.high_coop_streak = 0
                if self.low_coop_streak >= 2:
                    self.exploit_mode = True
                if self.exploit_mode and c_t >= 0.75:
                    self.exploit_mode = False
                if self.high_coop_streak >= 2 and current_stock > 0.85 * capacity:
                    self.coop_mode = True
                if self.coop_mode and (not (current_stock > 0.85 * capacity and c_t >= 0.75)):
                    self.coop_mode = False
            self.last_processed_round += 1
        if n == 2 and len(history.opponent_cooperators) > 0:
            opp_last = bool(history.opponent_cooperators[-1] >= 1)
            if current_stock <= safe_stock or current_stock < 0.1 * capacity:
                self.prev_stock_seen = current_stock
                return Action.D
            if opp_last:
                if current_stock >= high_stock and self.trend >= medium_trust:
                    self.prev_stock_seen = current_stock
                    return Action.C
                self.prev_stock_seen = current_stock
                return Action.C
            self.prev_stock_seen = current_stock
            return Action.D
        if current_stock is None:
            return Action.D
        if current_stock <= 0.15 * capacity:
            self.prev_stock_seen = current_stock
            return Action.D
        if self.exploit_mode:
            if self.high_coop_streak >= 1 and current_stock > 0.85 * capacity:
                self.exploit_mode = False
            else:
                self.prev_stock_seen = current_stock
                return Action.D
        if self.coop_mode:
            if current_stock > 0.85 * capacity and self.high_coop_streak >= 2:
                self.prev_stock_seen = current_stock
                return Action.C
            self.coop_mode = False
        if round_number >= max(self.r - 2, 0):
            if current_stock < high_stock:
                self.prev_stock_seen = current_stock
                return Action.D
            if current_stock >= high_stock and self.trend >= medium_trust:
                self.prev_stock_seen = current_stock
                return Action.C
        if self.prev_stock_seen < safe_stock and current_stock > high_stock:
            if self.trend >= medium_trust:
                self.prev_stock_seen = current_stock
                return Action.C
            self.prev_stock_seen = current_stock
            return Action.D
        if current_stock <= safe_stock:
            self.prev_stock_seen = current_stock
            return Action.D
        if self.trend < low_trust:
            self.prev_stock_seen = current_stock
            return Action.D
        if self.pressure > 0.35 and self.trend < medium_trust:
            self.prev_stock_seen = current_stock
            return Action.D
        if current_stock >= high_stock and self.trend >= medium_trust:
            self.prev_stock_seen = current_stock
            return Action.C
        self.prev_stock_seen = current_stock
        return Action.C

class Strategy_INDIVIDUALISTIC_76(BaseStrategy):
    """
    Stock-sensitive, threshold-based cooperation strategy for the Common Pool Resource Game.

    Cooperates only when the pool is healthy, recent opponent cooperation is stable,
    and the game is not near its end. Defection is the default fallback.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(getattr(game_description, 'n_players', 0) or 0)
        self.n_rounds = int(getattr(game_description, 'n_rounds', 0) or 0)
        self.capacity = float(getattr(game_description, 'capacity', 0.0) or 0.0)
        self.n_opponents = max(0, self.n_players - 1)
        self.tau = max(0.55, 0.5 + 1.0 / (4.0 * self.n_players)) if self.n_players > 0 else 0.55
        self.H = 0.6 * self.capacity
        self.L = 0.35 * self.capacity
        self._last_stock = None
        self._last_round_number = None

    def _coop_fraction(self, coop_count: int) -> float:
        if self.n_opponents <= 0:
            return 0.0
        return float(coop_count) / float(self.n_opponents)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(getattr(history, 'round_number', 0) or 0)
        if round_number == 0:
            self._last_stock = float(current_stock)
            self._last_round_number = round_number
            return Action.C
        if current_stock <= self.L:
            self._last_stock = float(current_stock)
            self._last_round_number = round_number
            return Action.D
        if self.n_rounds > 0 and round_number >= max(0, self.n_rounds - 2):
            self._last_stock = float(current_stock)
            self._last_round_number = round_number
            return Action.D
        opp_hist = getattr(history, 'opponent_cooperators', None)
        if opp_hist is None or len(opp_hist) == 0:
            action = Action.C if current_stock >= self.H and 0.5 <= 0.5 else Action.D
            self._last_stock = float(current_stock)
            self._last_round_number = round_number
            return action
        try:
            recent_len = min(3, len(opp_hist))
            recent = opp_hist[-recent_len:]
            recent_fracs = [self._coop_fraction(int(x)) for x in recent]
            c_bar = float(np.mean(recent_fracs)) if len(recent_fracs) > 0 else 0.0
            prev_frac = self._coop_fraction(int(opp_hist[-1]))
        except Exception:
            self._last_stock = float(current_stock)
            self._last_round_number = round_number
            return Action.C if current_stock >= self.H else Action.D
        prev_stock_ok = self._last_stock is not None and float(self._last_stock) >= self.H
        prev_round_ok = self._last_round_number is not None and self._last_round_number == round_number - 1
        if current_stock >= self.H and prev_stock_ok and prev_round_ok and (prev_frac >= self.tau) and (c_bar >= self.tau):
            self._last_stock = float(current_stock)
            self._last_round_number = round_number
            return Action.C
        if current_stock >= self.H and c_bar >= self.tau and (round_number <= self.n_rounds - 3):
            self._last_stock = float(current_stock)
            self._last_round_number = round_number
            return Action.C
        self._last_stock = float(current_stock)
        self._last_round_number = round_number
        return Action.D

class Strategy_INDIVIDUALISTIC_77(BaseStrategy):
    """
    Adaptive common-pool strategy that prefers cooperation when stock is high,
    opponent cooperation is stable or improving, and one-step forecasts suggest
    cooperation preserves a healthier future stock trajectory.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(self.n - 1, 0)
        self.default_k_hat = self.n_opponents
        self.last_k_hat = self.default_k_hat
        self.prev_k_obs = None
        self.last_k_obs = None
        self.trend_up = False
        self.trend_down = False
        self.relax_threshold = False
        self.tighten_threshold = False

    def _predict_next_stock(self, stock: float, my_action: bool, k_hat: int) -> float:
        n = self.n
        cap = self.capacity
        if n <= 0 or cap <= 0:
            return max(0.0, float(stock))
        coop_share = stock / (2.0 * n)
        def_share = stock / n
        my_cons = coop_share if my_action else def_share
        opp_coop_cons = k_hat * coop_share
        opp_def_cons = max(self.n_opponents - k_hat, 0) * def_share
        total_cons = my_cons + opp_coop_cons + opp_def_cons
        remaining = stock - total_cons
        if remaining < 0.0:
            remaining = 0.0
        growth = 2.0 * remaining * (1.0 - remaining / cap)
        nxt = remaining + growth
        if nxt > cap:
            nxt = cap
        if nxt < 0.0:
            nxt = 0.0
        return nxt

    def _decision_rule(self, stock: float, k_hat: int) -> Action:
        n = self.n
        cap = self.capacity
        if cap <= 0:
            return Action.D
        if stock <= cap / 8.0:
            return Action.D
        if stock <= cap / 4.0:
            return Action.D
        if stock >= 0.95 * cap:
            if self.last_k_obs is None:
                return Action.C
            return Action.C if self.last_k_obs >= math.ceil(self.n_opponents / 2.0) else Action.D
        threshold_base = (n - 1) / 2.0
        if self.relax_threshold:
            threshold_base = (n - 3) / 2.0
        elif self.tighten_threshold:
            threshold_base = (n + 1) / 2.0
        if stock >= 0.75 * cap and k_hat >= threshold_base:
            return Action.C
        if stock >= 0.9 * cap:
            n_c = self._predict_next_stock(stock, True, k_hat)
            n_d = self._predict_next_stock(stock, False, k_hat)
            if n_c >= n_d:
                return Action.C
        return Action.D

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        stock = float(current_stock)
        cap = self.capacity
        if round_number > 0 and len(history.opponent_cooperators) >= round_number:
            current_k = int(history.opponent_cooperators[-1])
            current_k = max(0, min(current_k, self.n_opponents))
            self.prev_k_obs = self.last_k_obs
            self.last_k_obs = current_k
            if self.prev_k_obs is not None:
                self.trend_up = current_k > self.prev_k_obs
                self.trend_down = current_k < self.prev_k_obs
                if len(history.opponent_cooperators) >= 3:
                    k_minus_1 = int(history.opponent_cooperators[-2])
                    k_minus_2 = int(history.opponent_cooperators[-3])
                    if current_k > k_minus_1 and k_minus_1 > k_minus_2:
                        self.relax_threshold = True
                        self.tighten_threshold = False
                    elif current_k < k_minus_1 and k_minus_1 < k_minus_2:
                        self.tighten_threshold = True
                        self.relax_threshold = False
            self.last_k_hat = current_k
        else:
            current_k = self.default_k_hat
        k_hat = self.last_k_obs if self.last_k_obs is not None else self.default_k_hat
        if round_number == 0:
            return Action.C if cap >= 4.0 * self.n else Action.D
        if round_number == self.rounds - 1 and stock < cap / 2.0:
            return Action.D
        if self.trend_down and stock < 0.6 * cap:
            return Action.D
        if self.trend_up and stock > 0.8 * cap:
            return Action.C
        return self._decision_rule(stock, k_hat)

class Strategy_INDIVIDUALISTIC_78(BaseStrategy):
    """
    Defensive common-pool strategy:
    - Defect when the pool is endangered or opponents are uncooperative.
    - Cooperate only when stock is healthy and recent opponent cooperation is strong.
    - Uses only the most recent round plus a small adaptive bias.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self._eps = 1e-09
        self._prev_stock = None
        self._bias = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_players = max(2, int(self.game_description.n_players))
        capacity = float(self.game_description.capacity)
        n_opponents = max(1, n_players - 1)
        round_number = int(history.round_number)
        q = 0.0 if capacity <= 0 else float(current_stock) / capacity
        if round_number > 0 and len(history.opponent_cooperators) > 0:
            last_k = int(history.opponent_cooperators[-1])
            last_p = last_k / n_opponents
        else:
            last_k = None
            last_p = None
        if round_number > 0 and last_k is not None:
            if last_p < 0.5:
                self._bias = -1
            elif last_p >= 0.75:
                if self._prev_stock is not None and current_stock + self._eps >= self._prev_stock:
                    self._bias = 1
                else:
                    self._bias = 0
        if round_number == 0:
            self._prev_stock = float(current_stock)
            if current_stock >= capacity - self._eps:
                return Action.C
            if capacity > 0 and q < 0.7:
                return Action.D
            return Action.D
        if round_number >= int(self.game_description.n_rounds) - 1:
            if q >= 0.7 and last_p is not None and (abs(last_p - 1.0) <= self._eps):
                self._prev_stock = float(current_stock)
                return Action.C
            self._prev_stock = float(current_stock)
            return Action.D
        if q < 0.35:
            self._prev_stock = float(current_stock)
            return Action.D
        safe_threshold = 0.5
        recovery_threshold = 0.75
        if self._bias < 0:
            safe_threshold = 0.75
            recovery_threshold = 1.0
        elif self._bias > 0:
            safe_threshold = 0.5
            recovery_threshold = 0.75
        if q < 0.7:
            if last_p is not None and last_p + self._eps >= recovery_threshold:
                self._prev_stock = float(current_stock)
                return Action.C
            self._prev_stock = float(current_stock)
            return Action.D
        else:
            if last_p is not None and last_p + self._eps >= safe_threshold:
                self._prev_stock = float(current_stock)
                return Action.C
            self._prev_stock = float(current_stock)
            return Action.D

class Strategy_INDIVIDUALISTIC_79(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Start by cooperating.
    - In the last round, defect.
    - Otherwise, combine depletion thresholds, persistence/exploit-recovery rules,
      and a one-step stock projection to decide between C and D.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = max(2, int(game_description.n_players))
        self.n_rounds = max(2, int(game_description.n_rounds))
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(0, self.n_players - 1)
        self.t_low = self.capacity / 3.0
        self.t_high = 2.0 * self.capacity / 3.0
        self.k_low = math.floor(self.n_opponents / 3.0)
        self.k_high = math.ceil(2.0 * self.n_opponents / 3.0)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        if round_number == 0:
            return Action.C
        if round_number >= self.n_rounds - 1:
            return Action.D
        S = float(current_stock)
        if not math.isfinite(S):
            S = self.capacity
        if S < 0.0:
            S = 0.0
        elif S > self.capacity:
            S = self.capacity
        opp = history.opponent_cooperators
        last_k = int(opp[-1]) if len(opp) > 0 else 0
        prev_k = int(opp[-2]) if len(opp) > 1 else None
        if prev_k is not None and prev_k <= self.k_low and (last_k <= self.k_low):
            return Action.C
        if prev_k is not None and prev_k >= self.k_high and (last_k >= self.k_high):
            if S >= self.t_high:
                return Action.D
        if S <= self.t_low:
            return Action.C
        if S >= self.t_high and last_k >= self.k_high:
            return Action.D
        if last_k <= self.k_low:
            return Action.C
        n = self.n_players
        denom = 2.0 * n if n > 0 else 2.0
        r_c = S * (last_k + 1.0) / denom
        n_c = 3.0 * r_c - 2.0 * (r_c * r_c) / self.capacity if self.capacity > 0 else 0.0
        if not math.isfinite(n_c):
            n_c = 0.0
        n_c = min(n_c, self.capacity)
        if n_c < 0.0:
            n_c = 0.0
        r_d = S * last_k / denom
        n_d = 3.0 * r_d - 2.0 * (r_d * r_d) / self.capacity if self.capacity > 0 else 0.0
        if not math.isfinite(n_d):
            n_d = 0.0
        n_d = min(n_d, self.capacity)
        if n_d < 0.0:
            n_d = 0.0
        return Action.D if n_d >= self.t_low else Action.C

class Strategy_INDIVIDUALISTIC_80(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Start cooperatively.
    - Track trust from observed opponent cooperation.
    - Use a recovery mode after poor cooperation / low stock.
    - Apply stricter endgame cooperation requirements.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.mode = 'cooperative'
        self.trust = 1.0
        self.last_processed_round = -1

    def _simulate_stock_history(self, history: PlayerHistory) -> float:
        """
        Reconstruct stock evolution from the full observed history.
        Returns the stock level at the start of the current round.
        """
        capacity = float(self.game_description.capacity)
        n = int(self.game_description.n_players)
        stock = capacity
        rounds = history.round_number
        for t in range(rounds):
            if t >= len(history.my_actions):
                break
            my_action = bool(history.my_actions[t])
            opp_coop = int(history.opponent_cooperators[t]) if t < len(history.opponent_cooperators) else 0
            total_cooperators = opp_coop + (1 if my_action else 0)
            coop_consumption = stock / (2.0 * n)
            defect_consumption = stock / n
            total_consumption = opp_coop * coop_consumption + (1 if my_action else 0) * defect_consumption + 0.0
            remaining = stock - total_consumption
            if remaining < 0.0:
                remaining = 0.0
            growth = 2.0 * remaining * (1.0 - remaining / capacity) if capacity > 0 else 0.0
            stock = min(remaining + growth, capacity)
        return stock

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = int(self.game_description.n_players)
        r = int(self.game_description.n_rounds)
        capacity = float(self.game_description.capacity)
        round_idx = int(history.round_number)
        if round_idx == 0:
            self.mode = 'cooperative'
            self.trust = 1.0
            self.last_processed_round = -1
            return Action.C
        self.mode = 'cooperative'
        self.trust = 1.0
        simulated_stock = capacity
        n_opponents = max(n - 1, 1)
        for t in range(round_idx):
            my_action = bool(history.my_actions[t]) if t < len(history.my_actions) else False
            if t < len(history.opponent_cooperators):
                c_prev = int(history.opponent_cooperators[t])
                missing_obs = False
            else:
                c_prev = 0
                missing_obs = True
            if n == 2:
                coop_share = 0.5 if missing_obs and t == 0 else c_prev / n_opponents if n_opponents > 0 else 0.0
            else:
                coop_share = 0.5 if missing_obs and t == 0 else c_prev / n_opponents if n_opponents > 0 else 0.0
            if missing_obs and t == 0:
                observed_share = 0.5
                self.trust = 0.75 * self.trust + 0.25 * 0.5
            else:
                observed_share = coop_share
                self.trust = 0.75 * self.trust + 0.25 * observed_share
            coop_count = c_prev
            total_consumption = 0.0
            if n > 0:
                total_consumption = coop_count * (simulated_stock / (2.0 * n)) + (1.0 if my_action else 0.0) * (simulated_stock / n)
            remaining = simulated_stock - total_consumption
            if remaining < 0.0:
                remaining = 0.0
            growth = 2.0 * remaining * (1.0 - remaining / capacity) if capacity > 0 else 0.0
            simulated_stock = min(remaining + growth, capacity)
            stock_share_end = simulated_stock / capacity if capacity > 0 else 0.0
            if self.mode != 'recovering':
                if observed_share < 0.4 or stock_share_end < 0.35:
                    self.mode = 'recovering'
            elif observed_share >= 0.8 and stock_share_end >= 0.6:
                self.mode = 'cooperative'
        stock_share = 0.0 if capacity <= 0 else float(current_stock) / capacity
        if float(current_stock) <= 0.0:
            return Action.D
        if round_idx == 1 and len(history.opponent_cooperators) < 1:
            coop_share = 0.5
            trust = 0.5
        else:
            if len(history.opponent_cooperators) >= 1:
                c_prev = int(history.opponent_cooperators[-1])
                coop_share = c_prev / n_opponents if n_opponents > 0 else 0.0
            else:
                coop_share = 0.5
            trust = self.trust
        if n == 2:
            main_coop_ok = coop_share >= 1.0
            endgame_coop_ok = coop_share >= 1.0
        else:
            main_coop_ok = coop_share >= 0.6
            endgame_coop_ok = coop_share >= 1.0
        if round_idx >= max(r - 2, 0):
            if stock_share >= 0.75 and endgame_coop_ok and (trust >= 0.8):
                return Action.C
            return Action.D
        if self.mode == 'recovering':
            if coop_share >= 0.8 and stock_share >= 0.6:
                self.mode = 'cooperative'
            else:
                return Action.D
        if stock_share >= 0.5 and main_coop_ok and (trust >= 0.6):
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_81(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Starts by cooperating.
    - Maintains a smoothed cooperation score tau from observed opponent cooperation.
    - Defects when stock is depleted or at the final round.
    - Cooperates only when stock is healthy and recent opponent behavior is sufficiently cooperative.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self._tau = 1.0
        self._processed_rounds = 0
        self._n_opponents = max(0, self.game_description.n_players - 1)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        while self._processed_rounds < history.round_number:
            idx = self._processed_rounds
            if self._n_opponents > 0 and idx < len(history.opponent_cooperators):
                q_t = float(history.opponent_cooperators[idx]) / float(self._n_opponents)
            else:
                q_t = 0.0
            self._tau = 0.7 * self._tau + 0.3 * q_t
            self._processed_rounds += 1
        if history.round_number == 0:
            return Action.C
        if history.round_number >= self.game_description.n_rounds - 1:
            return Action.D
        capacity = float(self.game_description.capacity)
        if capacity <= 0.0:
            return Action.D
        stock_ratio = float(current_stock) / capacity
        if stock_ratio <= 0.55:
            return Action.D
        if stock_ratio >= 0.8 and self._tau >= 0.6:
            return Action.C
        if stock_ratio >= 0.65 and self._tau >= 0.75:
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_82(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Starts by cooperating.
    - Tracks smoothed opponent cooperation (q).
    - Defects under depletion, low cooperation, or late-game pressure.
    - Re-enters cooperation only after sustained recovery.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.q = 1.0
        self.prev_stock = None
        self.last_two_p = []
        self.defect_until_round = -1
        self._processed_rounds = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = float(self.game_description.capacity)
        t = history.round_number
        if t > self._processed_rounds and t > 0:
            denom = max(1, n - 1)
            last_p = float(history.opponent_cooperators[-1]) / float(denom)
            self.q = 0.7 * self.q + 0.3 * last_p
            self.last_two_p.append(last_p)
            if len(self.last_two_p) > 2:
                self.last_two_p = self.last_two_p[-2:]
            if last_p <= 0.25:
                self.defect_until_round = max(self.defect_until_round, t + 1)
            self._processed_rounds = t
        if t == 0:
            self.prev_stock = current_stock
            return Action.C
        s = float(current_stock)
        prev_s = self.prev_stock if self.prev_stock is not None else s
        stock_rising = s > prev_s

        def ge_with_tie(value: float, threshold: float) -> bool:
            if value > threshold:
                return True
            if value < threshold:
                return False
            return stock_rising
        recent_p = self.last_two_p[-1] if len(self.last_two_p) >= 1 else None
        recent_p_prev = self.last_two_p[-2] if len(self.last_two_p) >= 2 else None
        half_opponents = (n - 1) / 2.0
        if s <= 0.2 * capacity and (not (s >= 0.4 * capacity and self.q >= 0.5)):
            self.prev_stock = s
            return Action.D
        if t <= self.defect_until_round:
            self.prev_stock = s
            return Action.D
        if t == r - 1:
            if s >= 0.4 * capacity and ge_with_tie(self.q, 0.6):
                self.prev_stock = s
                return Action.C
            self.prev_stock = s
            return Action.D
        if s >= 0.7 * capacity and len(self.last_two_p) >= 2 and (recent_p is not None) and (recent_p_prev is not None) and (recent_p >= 0.5) and (recent_p_prev >= 0.5):
            self.prev_stock = s
            return Action.C
        if recent_p is not None and recent_p >= 1.0 and (s >= 0.5 * capacity):
            self.prev_stock = s
            return Action.C
        if t <= r / 3:
            coop_threshold = 0.6
            stock_threshold = 0.35 * capacity
            decision = ge_with_tie(self.q, coop_threshold) and s >= stock_threshold
        elif t <= 2 * r / 3:
            coop_threshold = 0.5
            stock_threshold = 0.35 * capacity
            decision = ge_with_tie(self.q, coop_threshold) and s >= stock_threshold
        else:
            coop_threshold = 0.4
            stock_threshold = 0.5 * capacity
            decision = ge_with_tie(self.q, coop_threshold) and s >= stock_threshold
        if not decision:
            self.prev_stock = s
            return Action.D
        if s < 0.35 * capacity or self.q < 0.5:
            self.prev_stock = s
            return Action.D
        self.prev_stock = s
        return Action.C

class Strategy_INDIVIDUALISTIC_83(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Starts by cooperating.
    - Tracks smoothed opponent cooperation (q), cooperation streaks, and collapses.
    - Enters emergency defect mode when stock is low.
    - Becomes more defensive after repeated low cooperation.
    - Defects in the final round and usually in the penultimate round unless conditions are strong.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.q = 1.0
        self.streak = 0
        self.collapse = 0
        self._processed_rounds = 0
        self._emergency_mode = False

    def _update_from_history(self, history: PlayerHistory) -> None:
        while self._processed_rounds < history.round_number:
            idx = self._processed_rounds
            n_opponents = max(self.game_description.n_players - 1, 1)
            p = float(history.opponent_cooperators[idx]) / float(n_opponents)
            self.q = 0.7 * self.q + 0.3 * p
            if p >= 0.5:
                self.streak += 1
                self.collapse = 0
            else:
                self.collapse += 1
                self.streak = 0
            self._processed_rounds += 1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        self._update_from_history(history)
        n_rounds = self.game_description.n_rounds
        capacity = float(self.game_description.capacity)
        round_number = history.round_number
        if round_number == 0:
            return Action.C
        if self._emergency_mode:
            if current_stock >= 0.45 * capacity:
                self._emergency_mode = False
            else:
                return Action.D
        if current_stock < 0.3 * capacity:
            self._emergency_mode = True
            return Action.D
        if round_number >= n_rounds - 1:
            return Action.D
        if self.collapse >= 2:
            return Action.D
        if round_number == n_rounds - 2:
            if current_stock >= 0.8 * capacity and self.q >= 0.75:
                return Action.C
            return Action.D
        if current_stock >= 0.6 * capacity and self.q >= 0.5 and (self.collapse == 0):
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_84(BaseStrategy):
    """
    Cooperate only when the pool is healthy and the previous round showed
    sufficiently cooperative behavior by opponents; otherwise defect.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(getattr(game_description, 'n_players', 0) or 0)
        self.n_rounds = int(getattr(game_description, 'n_rounds', 0) or 0)
        self.capacity = float(getattr(game_description, 'capacity', 0.0) or 0.0)
        self.half_capacity = self.capacity / 2.0
        self.opponent_threshold = int(math.ceil(max(self.n_players - 1, 0) / 2.0))

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = int(getattr(history, 'round_number', 0) or 0)
        stock = float(current_stock)
        if t == 0:
            return Action.C if stock >= self.half_capacity else Action.D
        if self.n_rounds > 0 and t == self.n_rounds - 1:
            last_cooperators = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
            if stock >= self.half_capacity and last_cooperators == max(self.n_players - 1, 0):
                return Action.C
            return Action.D
        last_cooperators = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        if stock >= self.half_capacity and last_cooperators >= self.opponent_threshold:
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_85(BaseStrategy):
    """
    Commons-preservation strategy:
    - Cooperate on the first round to test for mutual restraint.
    - Defect in the last round.
    - Otherwise cooperate only when stock is healthy and recent opponent cooperation has been consistently high.
    - Defect immediately under low-stock recovery or weak cooperation signals.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.last_q: float | None = None
        self.prev_q: float | None = None
        self.last_action: Action | None = None

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        n_rounds = self.n_rounds
        n_players = self.n_players
        if self.capacity > 0:
            s_t = float(current_stock) / self.capacity
        else:
            s_t = 0.0
        q_last = None
        q_prev = None
        if round_number >= 1:
            denom = max(n_players - 1, 1)
            q_last = float(history.opponent_cooperators[-1]) / denom
        if round_number >= 2:
            denom = max(n_players - 1, 1)
            q_prev = float(history.opponent_cooperators[-2]) / denom
        self.prev_q = self.last_q
        self.last_q = q_last
        if round_number == 0:
            self.last_action = Action.C
            return Action.C
        if round_number == n_rounds - 1:
            self.last_action = Action.D
            return Action.D
        if s_t < 1.0 / 4.0:
            self.last_action = Action.D
            return Action.D
        if s_t < 1.0 / 3.0:
            self.last_action = Action.D
            return Action.D
        if q_last is not None and q_last < 1.0 / 3.0:
            self.last_action = Action.D
            return Action.D
        if q_last is not None:
            recent_high = q_last >= 1.0 / 2.0
            older_high = q_prev is not None and q_prev >= 1.0 / 2.0
            stock_healthy = s_t >= 3.0 / 4.0
            if self.n_players == 2:
                if recent_high and s_t >= 1.0 / 3.0:
                    self.last_action = Action.C
                    return Action.C
                self.last_action = Action.D
                return Action.D
            if recent_high and (older_high or stock_healthy):
                self.last_action = Action.C
                return Action.C
        self.last_action = Action.D
        return Action.D

class Strategy_INDIVIDUALISTIC_86(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Starts by cooperating.
    - Defects when the stock is scarce or cooperation is weak.
    - Cooperates when the stock is healthy and cooperation is strong.
    - Uses simple two-round memory to react to declining/recovering cooperation.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(self.n_players - 1, 0)
        self.majority_threshold = math.ceil(self.n_opponents / 2) if self.n_opponents > 0 else 0
        self.my_last_action = None
        self.last_observed_cooperators = None
        self.previous_stock = None

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        capacity = self.capacity if self.capacity > 0 else 1.0
        half_q = capacity / 4.0
        three_quarters_q = 3.0 * capacity / 4.0
        observed_prev = 0
        if round_number > 0 and len(history.opponent_cooperators) > 0:
            observed_prev = int(history.opponent_cooperators[-1])
        if round_number == 0:
            action = Action.C
        else:
            if round_number == self.n_rounds - 1:
                if current_stock >= three_quarters_q and observed_prev >= self.majority_threshold:
                    action = Action.C
                else:
                    action = Action.D
            elif current_stock <= half_q:
                action = Action.D
            elif current_stock >= three_quarters_q:
                action = Action.C
            elif observed_prev >= self.majority_threshold:
                action = Action.C
            else:
                action = Action.D
            if round_number >= 2:
                prev_obs = self.last_observed_cooperators
                prev_stock = self.previous_stock
                if prev_obs is not None:
                    if self.my_last_action == Action.C:
                        if observed_prev < prev_obs:
                            action = Action.D
                    elif self.my_last_action == Action.D:
                        stock_recovered = False
                        if prev_stock is not None:
                            stock_recovered = current_stock > prev_stock
                        if observed_prev > prev_obs or stock_recovered:
                            action = Action.C
        self.my_last_action = action
        self.last_observed_cooperators = observed_prev
        self.previous_stock = float(current_stock)
        return action

class Strategy_INDIVIDUALISTIC_87(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Start by cooperating.
    - Track opponent cooperation fraction, stock ratio, and stock trend.
    - Follow recovery and endgame rules with persistent defections when needed.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self._n_opponents = max(1, self.n_players - 1)
        self._last_stock = float(self.capacity)
        self._low_stock_lock = False
        self._defect_next_due_low_h = False
        self._zero_stock_absorbing = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number + 1
        x = 0.0 if self.capacity <= 0 else float(current_stock) / self.capacity
        if history.round_number == 0:
            self._last_stock = float(current_stock)
            return Action.C
        prev_opponents = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        h = prev_opponents / self._n_opponents if self._n_opponents > 0 else 0.0
        trend = 1 if float(current_stock) > float(self._last_stock) else 0
        if current_stock <= 0.0 or self._zero_stock_absorbing:
            self._zero_stock_absorbing = True
            self._last_stock = float(current_stock)
            return Action.D
        if round_number >= self.n_rounds:
            self._last_stock = float(current_stock)
            return Action.D
        if round_number == self.n_rounds - 1:
            self._last_stock = float(current_stock)
            if h >= 3.0 / 4.0 and x >= 1.0 / 2.0:
                return Action.C
            return Action.D
        if round_number == self.n_rounds - 2:
            self._last_stock = float(current_stock)
            if abs(h - 1.0) <= 1e-12 and x >= 2.0 / 3.0:
                return Action.C
            return Action.D
        if x < 1.0 / 4.0:
            self._low_stock_lock = True
        if h < 1.0 / 3.0:
            self._defect_next_due_low_h = True
        if self._low_stock_lock and (x >= 1.0 / 3.0 and h >= 1.0 / 2.0):
            self._low_stock_lock = False
        if self._defect_next_due_low_h:
            self._defect_next_due_low_h = False
            self._last_stock = float(current_stock)
            return Action.D
        if self._low_stock_lock:
            self._last_stock = float(current_stock)
            return Action.D
        if round_number >= 2 and round_number <= self.n_rounds - 2:
            if h >= 1.0 / 2.0 and x >= 1.0 / 3.0 and (trend == 1 or x >= 1.0 / 2.0):
                self._last_stock = float(current_stock)
                return Action.C
            self._last_stock = float(current_stock)
            return Action.D
        self._last_stock = float(current_stock)
        if h >= 1.0 / 2.0 and x >= 1.0 / 3.0 and (trend == 1 or x >= 1.0 / 2.0):
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_88(BaseStrategy):
    """
    Adaptive cooperation/defection strategy for the Common Pool Resource Game.

    The strategy maintains an estimate q of opponents' cooperation rate and uses
    a one-step lookahead with a remaining-horizon weight to choose between C and D.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.q = 0.5
        self._processed_rounds = 0

    def _update_q_from_history(self, history: PlayerHistory) -> None:
        n = self.game_description.n_players
        target_rounds = history.round_number
        if target_rounds <= self._processed_rounds:
            return
        start = self._processed_rounds
        end = target_rounds
        for idx in range(start, end):
            c_t = int(history.opponent_cooperators[idx])
            if n > 2:
                t = idx + 1
                self.q = ((t - 1) * self.q + c_t / (n - 1)) / t
            else:
                self.q = float(c_t)
            if self.q < 0.0:
                self.q = 0.0
            elif self.q > 1.0:
                self.q = 1.0
        self._processed_rounds = target_rounds

    def _next_stock(self, current_stock: float, consumption: float) -> float:
        capacity = float(self.game_description.capacity)
        remaining = current_stock - consumption
        if remaining < 0.0:
            remaining = 0.0
        growth = 2.0 * remaining * (1.0 - remaining / capacity) if capacity > 0 else 0.0
        new_stock = remaining + growth
        if new_stock > capacity:
            new_stock = capacity
        elif new_stock < 0.0:
            new_stock = 0.0
        return new_stock

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        S = float(current_stock)
        if history.round_number > 0:
            self._update_q_from_history(history)
        if S <= 0.0:
            return Action.D
        t = history.round_number + 1
        if t >= r:
            return Action.D
        denom = max(r - 1, 1)
        beta_t = (r - t) / denom
        q = self.q
        cap = float(self.game_description.capacity)
        cons_c = S / (2.0 * n) * (1.0 + (n - 1) * (2.0 - q))
        r_c = S - cons_c
        if r_c < 0.0:
            r_c = 0.0
        s_c_next = self._next_stock(S, cons_c)
        cons_d = S / (2.0 * n) * (2.0 + (n - 1) * (2.0 - q))
        r_d = S - cons_d
        if r_d < 0.0:
            r_d = 0.0
        s_d_next = self._next_stock(S, cons_d)
        u_c = S / (2.0 * n) + beta_t * s_c_next
        u_d = S / n + beta_t * s_d_next
        if u_c > u_d:
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_89(BaseStrategy):
    """
    Adaptive common-pool strategy:
    cooperate when the stock is healthy and opponents are reciprocating,
    otherwise defect and only re-enter cooperation after recovery.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        if round_number == 0:
            return Action.C
        n_opponents = max(self.n_players - 1, 1)
        last_opponents = int(history.opponent_cooperators[-1])
        p_last = last_opponents / n_opponents
        recent_ps = []
        if round_number >= 1:
            recent_ps.append(p_last)
        if round_number >= 2:
            prev_opponents = int(history.opponent_cooperators[-2])
            recent_ps.append(prev_opponents / n_opponents)
        high_stock = current_stock >= 0.75 * self.capacity
        medium_stock = current_stock >= 0.5 * self.capacity
        low_stock = current_stock < 0.5 * self.capacity
        strong_coop = high_stock and p_last >= 0.5
        last_two_have_moderate_support = any((p >= 0.5 for p in recent_ps[:2]))
        defensive_coop = medium_stock and (not high_stock) and (p_last >= 0.75) and last_two_have_moderate_support
        if round_number >= self.n_rounds - 2:
            if high_stock and p_last >= 0.75:
                return Action.C
            return Action.D
        if low_stock or p_last < 0.5:
            return Action.D
        if strong_coop:
            return Action.C
        if defensive_coop:
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_90(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Round 1 cooperates.
    - Later rounds react to current stock and recent opponent cooperation.
    - Last round defects.
    - Uses short-term memory of the last two observed cooperation rates to
      identify strict/noncooperative and cooperative regimes.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(self.n_players - 1, 1)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number
        if t == 0:
            return Action.C
        if t >= self.n_rounds - 1:
            return Action.D
        last_coop_count = int(history.opponent_cooperators[-1])
        q = last_coop_count / self.n_opponents if self.n_opponents > 0 else 0.0
        prev_q = None
        if t >= 2:
            prev_coop_count = int(history.opponent_cooperators[-2])
            prev_q = prev_coop_count / self.n_opponents if self.n_opponents > 0 else 0.0
        strict_mode = prev_q is not None and prev_q < 0.5 and (q < 0.5)
        cooperative_mode = prev_q is not None and prev_q >= 2.0 / 3.0 and (q >= 2.0 / 3.0)
        c1 = self.capacity / 4.0
        c2 = self.capacity / 2.0
        if current_stock <= c1:
            if strict_mode:
                return Action.D
            return Action.C if q >= 0.5 else Action.D
        if current_stock <= c2:
            if cooperative_mode:
                return Action.D
            return Action.C if q >= 2.0 / 3.0 else Action.D
        if cooperative_mode:
            return Action.D
        return Action.D if q >= 0.5 else Action.C

class Strategy_INDIVIDUALISTIC_91(BaseStrategy):
    """
    Threshold-based common-pool strategy:
    - Cooperate in round 1.
    - Defect in the final round.
    - In intermediate rounds, cooperate only when the stock is low or
      moderately low with weak recent opponent cooperation; otherwise defect.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.lower_threshold = self.capacity / 3.0
        self.upper_threshold = self.capacity / 2.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        if round_number == 0:
            return Action.C
        if round_number >= self.n_rounds - 1:
            return Action.D
        opp = history.opponent_cooperators
        if len(opp) == 0:
            recent_avg = 0.0
        else:
            window = min(3, round_number)
            start = max(0, round_number - window)
            recent_slice = opp[start:round_number]
            recent_avg = float(np.mean(recent_slice)) if len(recent_slice) > 0 else 0.0
        if current_stock <= self.lower_threshold:
            return Action.C
        if current_stock <= self.upper_threshold:
            if recent_avg < (self.n_players - 1) / 2.0:
                return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_92(BaseStrategy):
    """
    State-contingent threshold strategy for the common pool resource game.

    - Cooperates in the first round.
    - Defects late game when little future remains.
    - Protects the pool when stock is low.
    - Otherwise adapts to the observed cooperation rate among opponents,
      with stock-based overrides and tie handling.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.m = max(self.n - 1, 0)
        self.low_stock_threshold = 2.0 * self.n / (self.n + 1.0) if self.n >= 1 else 0.0
        self.early_game_cutoff = self.r // 2

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = int(history.round_number) + 1
        S_t = float(current_stock)
        if t == 1:
            action = Action.C
        else:
            if len(history.opponent_cooperators) > 0 and self.m > 0:
                k_t = int(history.opponent_cooperators[-1])
                if k_t < 0:
                    k_t = 0
                elif k_t > self.m:
                    k_t = self.m
                c_t = k_t / self.m
            else:
                c_t = 0.0
            rounds_remaining = self.r - t + 1
            if rounds_remaining <= 2:
                action = Action.D if S_t > 0.0 else Action.C
            elif S_t < self.low_stock_threshold:
                action = Action.C
            else:
                if self.r > 1:
                    tau_t = max(0.35, 0.5 - 0.15 * ((t - 1) / (self.r - 1)))
                else:
                    tau_t = 0.35
                if c_t > tau_t:
                    action = Action.C
                elif c_t < tau_t:
                    action = Action.D
                else:
                    action = Action.C if t <= self.early_game_cutoff else Action.D
            if S_t >= 0.8 * self.capacity and c_t >= 0.5:
                action = Action.C
            if S_t <= 0.4 * self.capacity and c_t < 0.5:
                action = Action.D
        return action

class Strategy_INDIVIDUALISTIC_93(BaseStrategy):
    """
    Tit-for-threshold common-pool strategy:
    - Cooperate in round 1.
    - Defect in the final round.
    - In the penultimate round, cooperate only if stock is at least half capacity
      and the previous two rounds each had sufficiently high opponent cooperation.
    - Otherwise, cooperate only when stock is not too low and the previous round
      had sufficiently high opponent cooperation.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self._n_players = int(getattr(game_description, 'n_players', 0) or 0)
        self._n_rounds = int(getattr(game_description, 'n_rounds', 0) or 0)
        self._capacity = float(getattr(game_description, 'capacity', 0) or 0.0)
        self._n_opponents = max(self._n_players - 1, 0)
        self._coop_threshold = math.ceil(3 * self._n_opponents / 4) if self._n_opponents > 0 else 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(getattr(history, 'round_number', 0) or 0)
        if round_number == 0:
            return Action.C
        opp_counts = getattr(history, 'opponent_cooperators', None)
        if opp_counts is None or len(opp_counts) < 1:
            return Action.D
        current_round = round_number + 1
        if current_round == self._n_rounds:
            return Action.D

        def high_enough(count_value) -> bool:
            try:
                return int(count_value) >= self._coop_threshold
            except Exception:
                return False
        last_round_high = high_enough(opp_counts[-1])
        if current_round == self._n_rounds - 1:
            if len(opp_counts) < 2:
                return Action.D
            if current_stock < self._capacity / 2.0:
                return Action.D
            if high_enough(opp_counts[-1]) and high_enough(opp_counts[-2]):
                return Action.C
            return Action.D
        if current_stock <= self._capacity / 4.0:
            return Action.D
        if last_round_high:
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_94(BaseStrategy):
    """
    Cooperative only when the pool is healthy and recent opponent cooperation
    is high; defects in the final round, when the pool is depleted, or when
    cooperation among opponents drops below the required threshold.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self._n_players = int(game_description.n_players)
        self._n_opponents = max(self._n_players - 1, 0)
        self._capacity = float(game_description.capacity)
        self._n_rounds = int(game_description.n_rounds)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        if round_number == 0:
            return Action.C
        if current_stock <= 0.0:
            return Action.D
        if round_number >= self._n_rounds - 1:
            return Action.D
        prev_cooperators = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        if prev_cooperators <= 0:
            return Action.D
        q = prev_cooperators / self._n_opponents if self._n_opponents > 0 else 0.0
        x = current_stock / self._capacity if self._capacity > 0 else 0.0
        if x < 1.0 / 5.0:
            return Action.D
        if prev_cooperators >= self._n_opponents and x >= 1.0 / 2.0:
            return Action.C
        if x < 1.0 / 3.0:
            return Action.C if q >= 1.0 else Action.D
        if q >= 2.0 / 3.0 and x >= 1.0 / 3.0:
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_95(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Start by cooperating.
    - Track opponent cooperation with exponential smoothing.
    - Cooperate only when cooperation is sufficiently supported by both
      observed opponent behavior and the current stock level.
    - Defect in the final round to extract remaining value.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.coop_rate = 1.0
        self.last_stock = float(game_description.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        t = history.round_number + 1
        capacity = float(self.game_description.capacity)
        stock = float(current_stock)
        if history.round_number == 0:
            self.coop_rate = 1.0
            self.last_stock = stock
            return Action.C
        n_opponents = max(n - 1, 1)
        prev_opponents_coop = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        obs = prev_opponents_coop / n_opponents
        self.coop_rate = 0.7 * self.coop_rate + 0.3 * obs
        stock_ratio = stock / capacity if capacity > 0 else 0.0
        high_stock = stock_ratio >= 0.7
        medium_stock = 0.4 <= stock_ratio < 0.7
        low_stock = stock_ratio < 0.4
        if t == r:
            self.last_stock = stock
            return Action.D if stock > 0 else Action.C
        if high_stock:
            action = Action.C if self.coop_rate >= 0.8 else Action.D
        elif medium_stock:
            action = Action.C if self.coop_rate >= 0.7 else Action.D
        else:
            action = Action.C if self.coop_rate >= 0.75 else Action.D
        if self.coop_rate < 0.6 or stock < capacity / 3.0:
            action = Action.D
        self.last_stock = stock
        return action

class Strategy_INDIVIDUALISTIC_96(BaseStrategy):
    """
    Cooperative-by-default common pool strategy with threshold-based punishment,
    recovery, and endgame caution.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(self.n_players - 1, 0)
        self.threshold = self.capacity / 3.0
        self.half_opponents_ceil = math.ceil(self.n_opponents / 2.0)

    def _next_stock(self, current_stock: float, my_action: bool, opponent_cooperators: int) -> float:
        n = self.n_players
        if n <= 0:
            return current_stock
        coop_opp = max(0, min(int(opponent_cooperators), self.n_opponents))
        my_consumption = current_stock / (2.0 * n) if my_action else current_stock / n
        opp_coop_consumption = current_stock / (2.0 * n)
        opp_def_consumption = current_stock / n
        total_consumption = my_consumption
        total_consumption += coop_opp * opp_coop_consumption
        total_consumption += (self.n_opponents - coop_opp) * opp_def_consumption
        remaining = current_stock - total_consumption
        if remaining < 0.0:
            remaining = 0.0
        growth = 2.0 * remaining * (1.0 - remaining / self.capacity) if self.capacity > 0 else 0.0
        next_stock = remaining + growth
        return min(next_stock, self.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number
        n = self.n_players
        n_opponents = self.n_opponents
        if t == 0:
            return Action.C
        prev_opp_coop = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        prev_opp_coop = max(0, min(prev_opp_coop, n_opponents))
        current_opp_coop = prev_opp_coop
        if current_opp_coop < 0:
            current_opp_coop = 0
        if t == self.n_rounds - 1:
            if current_stock < self.threshold and current_opp_coop == n_opponents:
                return Action.C
            return Action.D
        if prev_opp_coop < self.half_opponents_ceil:
            return Action.D
        if current_stock >= 2.0 * self.threshold and prev_opp_coop >= self.half_opponents_ceil:
            return Action.C
        if current_stock < self.threshold:
            next_if_coop = self._next_stock(current_stock, True, current_opp_coop)
            if current_opp_coop == n_opponents and next_if_coop >= self.threshold:
                return Action.C
            return Action.D
        if current_opp_coop >= self.half_opponents_ceil:
            next_if_coop = self._next_stock(current_stock, True, current_opp_coop)
            if next_if_coop >= self.threshold:
                return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_97(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Cooperate on round 1.
    - Track estimated opponent cooperation q with exponential smoothing.
    - Cooperate only when cooperation is high enough, stock is healthy, and no
      short-term retaliation lockout is active.
    - Defect when the pool is depleted, in the final round, or after low
      observed cooperation.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.q = 1.0
        self.processed_rounds = 0
        self.low_coop_lock_until = -1

    def _update_beliefs(self, history: PlayerHistory) -> None:
        total_rounds_seen = int(history.round_number)
        n_opponents = max(1, self.game_description.n_players - 1)
        start = max(0, self.processed_rounds)
        end = min(total_rounds_seen, len(history.opponent_cooperators))
        for t in range(start, end):
            observed = int(history.opponent_cooperators[t])
            ratio = observed / n_opponents
            self.q = 0.7 * self.q + 0.3 * ratio
            if ratio < 0.5:
                self.low_coop_lock_until = max(self.low_coop_lock_until, t + 2)
        self.processed_rounds = max(self.processed_rounds, end)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_rounds = self.game_description.n_rounds
        capacity = float(self.game_description.capacity)
        current_round = int(history.round_number)
        if current_round == 0:
            return Action.C
        self._update_beliefs(history)
        try:
            if len(history.opponent_cooperators) == 0:
                return Action.D
        except Exception:
            return Action.D
        if current_round >= n_rounds - 1:
            return Action.D
        if current_stock < capacity / 6.0:
            if current_stock >= capacity / 3.0 and self.q >= 0.75:
                pass
            else:
                return Action.D
        if current_round <= self.low_coop_lock_until and self.q < 0.75:
            return Action.D
        x = 0.0 if capacity <= 0 else max(0.0, min(1.0, float(current_stock) / capacity))
        threshold = 0.55 + 0.25 * (1.0 - x)
        if current_stock >= capacity / 4.0 and self.q >= threshold:
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_98(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Start by cooperating.
    - Cooperate only when the pool and recent opponent cooperation look healthy.
    - Defect when stock is fragile or cooperation deteriorates.
    - Return to cooperation only after a clear recovery signal.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = max(2, int(game_description.n_players))
        self.n_rounds = max(1, int(game_description.n_rounds))
        self.capacity = float(game_description.capacity) if game_description.capacity > 0 else 1.0
        self.in_defection_phase = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number + 1
        n = self.n_players
        r = self.n_rounds
        if history.round_number == 0:
            self.in_defection_phase = False
            return Action.C
        opp = history.opponent_cooperators
        denom = max(1, n - 1)
        q_values = [float(x) / denom for x in opp.tolist()]
        window = min(3, len(q_values))
        q_bar = float(np.mean(q_values[-window:])) if window > 0 else 0.0
        q_last = q_values[-1] if len(q_values) >= 1 else 0.0
        q_prev = q_values[-2] if len(q_values) >= 2 else q_last
        q_prev2 = q_values[-3] if len(q_values) >= 3 else q_prev
        stock_ratio = current_stock / self.capacity if self.capacity > 0 else 0.0
        low_two = q_last < 0.4 and q_prev < 0.4 if len(q_values) >= 2 else q_last < 0.4
        recover = len(q_values) >= 2 and q_prev >= 0.7 and (q_last >= 0.7) and (stock_ratio >= 0.5)
        coop_test = stock_ratio >= 0.35 and q_bar >= 0.6 and (q_last >= 0.5)
        final_round = t == r
        final_two = t >= r - 1
        if len(history.my_actions) >= 1:
            last_my_action = bool(history.my_actions[-1])
            if not last_my_action and (not coop_test):
                self.in_defection_phase = True
            elif self.in_defection_phase and recover:
                self.in_defection_phase = False
        if stock_ratio < 0.35 or low_two:
            action = Action.D
        elif final_round:
            action = Action.C if q_bar >= 0.75 and stock_ratio >= 0.6 else Action.D
        elif final_two and self.in_defection_phase:
            action = Action.D
        elif self.in_defection_phase and (not recover):
            action = Action.D
        elif coop_test:
            action = Action.C
        else:
            action = Action.D
        if action == Action.D and (not coop_test):
            self.in_defection_phase = True
        elif self.in_defection_phase and recover:
            self.in_defection_phase = False
        return action

class Strategy_INDIVIDUALISTIC_99(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Tracks smoothed opponent cooperation with internal estimate m.
    - Cooperates early, then adapts to stock health and observed cooperation.
    - Defects in the final round and when stock is low.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.m = 1.0
        self.p = 1.0
        self._last_processed_round = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = max(2, int(self.game_description.n_players))
        r = max(1, int(self.game_description.n_rounds))
        capacity = float(self.game_description.capacity) if self.game_description.capacity else 1.0
        round_number = int(history.round_number)
        if round_number > 0 and self._last_processed_round < round_number:
            prev_cooperators = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
            n_opponents = max(1, n - 1)
            self.p = prev_cooperators / n_opponents
            self.m = 0.7 * self.m + 0.3 * self.p
            if prev_cooperators >= max(0, n - 2):
                self.m = max(self.m, 0.75)
            if prev_cooperators == 0:
                self.m = min(self.m, 0.2)
            self.m = max(0.0, min(1.0, self.m))
            self._last_processed_round = round_number
        if round_number == 0:
            return Action.C
        if round_number >= r - 1:
            return Action.D
        s = current_stock / capacity if capacity > 0 else 0.0
        s = max(0.0, min(1.0, s))
        if s <= 0.25:
            return Action.D
        if s >= 0.85:
            return Action.C if self.m >= 0.6 else Action.D
        if 0.5 <= s < 0.85:
            return Action.C if self.m >= 0.45 else Action.D
        if 0.25 < s < 0.5:
            return Action.C if self.m >= 0.3 else Action.D
        return Action.D

class Strategy_INDIVIDUALISTIC_100(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Cooperates initially
    - Defects in the final round
    - Uses stock and opponent cooperation to decide midgame cooperation
    - Applies a 2-round punishment after low cooperation
    - Applies a cooperation recovery after sustained high cooperation
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.punishment_counter = 0
        self.cooperation_streak = 0
        self.last_q = 1.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_players = int(self.game_description.n_players)
        n_rounds = int(self.game_description.n_rounds)
        capacity = float(self.game_description.capacity)
        round_number = int(history.round_number)
        if round_number == 0:
            self.last_q = 1.0
            self.cooperation_streak = 0
            self.punishment_counter = 0
            return Action.C
        n_opponents = max(n_players - 1, 1)
        last_opponents = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else n_opponents
        q = float(last_opponents) / float(n_opponents)
        self.last_q = q
        if q < 0.5:
            self.punishment_counter = 2
            self.cooperation_streak = 0
        elif q >= 0.75:
            self.cooperation_streak += 1
        else:
            self.cooperation_streak = 0
        if round_number >= n_rounds - 1:
            return Action.D
        if self.punishment_counter > 0:
            self.punishment_counter -= 1
            action = Action.D
        else:
            t_late_start = int(math.ceil(2 * n_rounds / 3))
            if round_number >= t_late_start:
                t_late = max(capacity / 1.5, 0.75 * capacity)
                action = Action.C if current_stock >= t_late and q >= 0.75 else Action.D
            else:
                sigmoid_term = 2.0 * n_players * (1.0 / (1.0 + math.exp(-4.0 * (q - 0.5))))
                t_mid = max(capacity / 2.0, sigmoid_term)
                action = Action.C if current_stock >= t_mid and q >= 0.5 else Action.D
        if self.punishment_counter == 0 and self.cooperation_streak >= 2 and (current_stock >= capacity / 2.0):
            action = Action.C
        return action

class Strategy_INDIVIDUALISTIC_101(BaseStrategy):
    """
    Cautious cooperation strategy for the common pool resource game.

    - Cooperates in round 1.
    - Defects in the final round.
    - Tracks recent opponent cooperation to enter/exit a defect mode.
    - Uses stock thresholds to stay conservative when the pool is weak.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(self.n_players - 1, 0)
        self.in_defect_mode = False
        self.recovery_streak = 0
        self.just_exited_defect_mode = False
        self.last_processed_round = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = int(history.round_number) + 1
        S = float(current_stock)
        if history.round_number == 0:
            self.in_defect_mode = False
            self.recovery_streak = 0
            self.just_exited_defect_mode = False
            self.last_processed_round = 0
            return Action.C
        start_idx = self.last_processed_round
        end_idx = history.round_number
        for idx in range(start_idx, end_idx):
            m = self.n_opponents
            k = int(history.opponent_cooperators[idx]) if idx < len(history.opponent_cooperators) else 0
            if m > 0:
                q = k / m
            else:
                q = 0.0
            if q < 0.5:
                self.in_defect_mode = True
                self.recovery_streak = 0
                self.just_exited_defect_mode = False
            elif self.in_defect_mode:
                self.recovery_streak += 1
                if self.recovery_streak >= 2:
                    self.in_defect_mode = False
                    self.just_exited_defect_mode = True
                    self.recovery_streak = 0
            else:
                self.recovery_streak = 0
        self.last_processed_round = history.round_number
        if t >= self.n_rounds:
            return Action.D
        m = self.n_opponents
        if m > 0 and len(history.opponent_cooperators) > 0:
            k_last = int(history.opponent_cooperators[-1])
            q = k_last / m
        else:
            q = 0.0
        p = S / self.capacity if self.capacity > 0 else 0.0
        _a = 0.35 + 0.3 * (1.0 - p)
        _b = 0.2 + 0.2 * (1.0 - p)
        _target = _a + _b * (1.0 - q)
        if S <= 0.0:
            return Action.D
        if S < 0.25 * self.capacity and (not (q == 1.0 and t < self.n_rounds)):
            return Action.D
        if self.in_defect_mode:
            return Action.D
        if q < 0.5:
            self.in_defect_mode = True
            self.recovery_streak = 0
            self.just_exited_defect_mode = False
            return Action.D
        if self.just_exited_defect_mode:
            self.just_exited_defect_mode = False
            return Action.C if p >= 0.4 else Action.D
        if t == 2:
            if q >= 0.5 and p >= 0.4:
                return Action.C
            return Action.D
        if t == 3 and q < 0.5:
            self.in_defect_mode = True
            self.recovery_streak = 0
            return Action.D
        if S > 0.0 and q >= 0.5 and (p >= 0.25) and (t < self.n_rounds):
            if S >= 0.5 * self.capacity or q >= 0.75:
                return Action.C
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_102(BaseStrategy):
    """
    Thresholded conditional-extraction strategy for the Common Pool Resource Game.

    Cooperates on the first round, then cooperates only when the stock is healthy
    and the previous round showed sufficient opponent cooperation. Defects in low
    stock, weak-cooperation, or endgame situations, with an additional hard switch
    to defect after sustained low cooperation.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(self.n_players - 1, 1)
        self.low_stock_threshold = self.capacity / 4.0
        self.high_stock_threshold = 3.0 * self.capacity / 4.0
        self.consecutive_low_cooperation_rounds = 0
        self.permanent_defect_mode = False
        self.last_processed_round = -1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        if round_number == 0:
            self.consecutive_low_cooperation_rounds = 0
            self.permanent_defect_mode = False
            self.last_processed_round = 0
            return Action.C
        prev_opponent_cooperators = int(history.opponent_cooperators[-1])
        prev_cooperation_rate = prev_opponent_cooperators / self.n_opponents if self.n_opponents > 0 else 0.0
        if prev_cooperation_rate < 0.5:
            self.consecutive_low_cooperation_rounds += 1
        else:
            self.consecutive_low_cooperation_rounds = 0
            self.permanent_defect_mode = False
        if self.consecutive_low_cooperation_rounds >= 2:
            self.permanent_defect_mode = True
        remaining_rounds = self.n_rounds - round_number
        stock = float(current_stock)
        low_threshold = self.low_stock_threshold
        high_threshold = self.high_stock_threshold
        if remaining_rounds <= 2:
            if stock >= high_threshold and prev_cooperation_rate >= 0.5 and (not self.permanent_defect_mode):
                return Action.C
            return Action.D
        if self.permanent_defect_mode and prev_cooperation_rate < 0.5:
            return Action.D
        if stock <= low_threshold:
            return Action.D
        if stock >= high_threshold:
            if prev_cooperation_rate >= 0.5:
                return Action.C
            return Action.D
        if stock > low_threshold and stock < high_threshold:
            if prev_cooperation_rate > 0.5:
                return Action.C
            return Action.D
        return Action.D

class Strategy_INDIVIDUALISTIC_103(BaseStrategy):
    """
    State-driven threshold strategy with recovery, maintenance, and extraction modes.

    - Starts cooperative.
    - Tracks a smoothed estimate p of opponent cooperation:
      p <- 0.7 * p + 0.3 * c
    - Cooperates when cooperation is sufficiently high or stock is pressured.
    - Defects only in healthy-stock, weak-cooperation, late-game situations.
    - Always defects in the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self._p = 1.0
        self._last_seen_round = 0

    def _recompute_smoothed_cooperation(self, history: PlayerHistory) -> float:
        n_players = int(self.game_description.n_players)
        n_opponents = max(0, n_players - 1)
        p = 1.0
        rounds = history.round_number
        if rounds <= 0:
            return p
        for t in range(rounds):
            if t < len(history.opponent_cooperators):
                opp_coop = int(history.opponent_cooperators[t])
            else:
                opp_coop = n_opponents
            if n_opponents > 0:
                c = opp_coop / n_opponents
            else:
                c = 1.0
            c = min(1.0, max(0.0, float(c)))
            p = 0.7 * p + 0.3 * c
        return p

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_rounds = int(self.game_description.n_rounds)
        round_number = int(history.round_number)
        if round_number == 0:
            self._p = 1.0
            self._last_seen_round = 0
            return Action.C
        if round_number != self._last_seen_round:
            self._p = self._recompute_smoothed_cooperation(history)
            self._last_seen_round = round_number
        capacity = float(self.game_description.capacity)
        if capacity <= 0.0:
            x = 0.0
        else:
            x = float(current_stock) / capacity
        x = min(1.0, max(0.0, x))
        p = min(1.0, max(0.0, float(self._p)))
        current_round_1based = round_number + 1
        remaining_after_current = n_rounds - current_round_1based
        if round_number >= n_rounds - 1:
            return Action.D
        if x <= 0.4:
            return Action.C
        if remaining_after_current <= 2 and x >= 0.65 and (p < 0.5):
            return Action.D
        if p >= 0.5 or x < 0.5:
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_104(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Cooperate in the first round.
    - Estimate opponent cooperation with exponential smoothing.
    - Cooperate in midgame only when cooperation is sufficiently likely and
      the projected stock under cooperation stays above a declining target.
    - Defect in collapse conditions and always defect in the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.q_est = 1.0
        self.last_round_seen = -1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = int(self.game_description.n_players)
        r = int(self.game_description.n_rounds)
        capacity = float(self.game_description.capacity)
        if n < 2 or r <= 1:
            return Action.C
        current_round = int(history.round_number)
        last_round_index = r - 1
        if current_round >= last_round_index:
            return Action.D
        if current_round == 0:
            self.q_est = 1.0
            self.last_round_seen = 0
            return Action.C
        q = 1.0
        m = n - 1
        if m <= 0:
            m = 1
        opp_coop = history.opponent_cooperators
        for k in opp_coop:
            frac = float(k) / float(m)
            q = 2.0 / 3.0 * q + 1.0 / 3.0 * frac
        self.q_est = q
        self.last_round_seen = current_round
        S = float(current_stock)
        q_prev = q
        if S <= capacity / 3.0:
            return Action.D

        def projected_stock(action: Action) -> float:
            opp_cons = S * (q_prev * m / (2.0 * n) + (1.0 - q_prev) * m / float(n))
            own_cons = S / (2.0 * n) if action == Action.C else S / float(n)
            total_cons = opp_cons + own_cons
            remaining = S - total_cons
            growth = 2.0 * remaining * (1.0 - remaining / capacity)
            new_stock = remaining + growth
            return min(new_stock, capacity)
        gc = projected_stock(Action.C)
        gd = projected_stock(Action.D)
        remaining_after_current = max(r - (current_round + 1), 0)
        denom = max(r - 1, 1)
        tau_t = 0.5 * (remaining_after_current / denom)
        target_stock = tau_t * capacity
        cooperate = q_prev >= 0.5 and gc >= target_stock and (gd < target_stock)
        if not cooperate and q_prev >= 0.75 and (S >= 0.75 * capacity):
            cooperate = True
        return Action.C if cooperate else Action.D

class Strategy_INDIVIDUALISTIC_105(BaseStrategy):
    """
    Cautious common-pool strategy:
    cooperate early only under strong stock and peer cooperation,
    defect aggressively when stock weakens, and re-enter cooperation
    only after clear recovery.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(self.n_players - 1, 1)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        capacity = self.capacity if self.capacity > 0 else 1.0
        s_t = float(current_stock) / capacity
        opp_count_current = 0
        if round_number > 0 and len(history.opponent_cooperators) > 0:
            opp_count_current = int(history.opponent_cooperators[-1])
        x_t = opp_count_current / self.n_opponents
        if round_number == 0:
            return Action.C
        if current_stock <= capacity / 4.0:
            return Action.D
        if current_stock <= capacity / 2.0:
            return Action.D
        if round_number >= 3:
            o0 = int(history.opponent_cooperators[-3])
            o1 = int(history.opponent_cooperators[-2])
            o2 = int(history.opponent_cooperators[-1])
            if o2 < o1 and o1 < o0:
                return Action.D
            if o2 > o1 and o1 > o0 and (s_t > 0.7):
                return Action.C
        if round_number == self.n_rounds - 1:
            return Action.C if s_t > 0.9 and x_t >= 1.0 else Action.D
        if round_number == self.n_rounds - 2:
            return Action.C if s_t > 0.8 and x_t > 0.8 else Action.D
        last_my_action = bool(history.my_actions[-1]) if len(history.my_actions) > 0 else True
        if not last_my_action:
            return Action.C if s_t > 0.85 and x_t > 0.75 else Action.D
        return Action.C if s_t > 0.7 and x_t > 0.6 else Action.D

class Strategy_INDIVIDUALISTIC_106(BaseStrategy):
    """
    Adaptive common-pool strategy with a smoothed cooperation index.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.p = 1.0
        self._processed_rounds = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = int(self.game_description.n_players)
        r = int(self.game_description.n_rounds)
        capacity = float(self.game_description.capacity)
        target = max(0, history.round_number - 1)
        while self._processed_rounds < target:
            idx = self._processed_rounds
            opps = int(history.opponent_cooperators[idx]) if idx < len(history.opponent_cooperators) else 0
            denom = max(1, n - 1)
            coop_rate = opps / denom
            self.p = 0.7 * self.p + 0.3 * coop_rate
            self._processed_rounds += 1
        if history.round_number == 0:
            return Action.C if n == 2 else Action.D
        if history.round_number == r - 1:
            return Action.D
        if history.round_number == r - 2:
            if current_stock <= capacity / 4.0 and self.p > 2.0 / 3.0:
                return Action.C
            return Action.D
        if current_stock <= capacity / 4.0:
            return Action.C if self.p > 0.5 else Action.D
        if current_stock < 3.0 * capacity / 4.0:
            return Action.C if self.p > 2.0 / 3.0 else Action.D
        return Action.D if self.p > 1.0 / 3.0 else Action.C

class Strategy_INDIVIDUALISTIC_107(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Opens cooperatively.
    - Tracks opponent cooperation with exponential smoothing.
    - Uses a forecast-based continuation score when possible.
    - Falls back to simple stock/opponent-threshold rules for robustness.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_opponents = max(0, self.n_players - 1)
        self.capacity = float(game_description.capacity)
        self.m_estimate = 0.5
        self.last_history_len = 0
        self.forced_defect_rounds = 0
        self.forced_cooperate_rounds = 0

    def _clamp_stock(self, stock: float) -> float:
        if stock < 0.0:
            return 0.0
        if stock > self.capacity:
            return self.capacity
        return stock

    def _next_stock(self, stock: float, own_consume: float, opp_consume_each: float, opp_count: int) -> float:
        stock = self._clamp_stock(stock)
        total_consumption = own_consume + opp_count * opp_consume_each
        remaining = stock - total_consumption
        if remaining < 0.0:
            remaining = 0.0
        growth = 2.0 * remaining * (1.0 - remaining / self.capacity) if self.capacity > 0.0 else 0.0
        new_stock = remaining + growth
        if new_stock > self.capacity:
            new_stock = self.capacity
        if new_stock < 0.0:
            new_stock = 0.0
        return new_stock

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        s_t = float(current_stock)
        s_t = self._clamp_stock(s_t)
        if round_number == 0:
            self.m_estimate = 0.5
            self.last_history_len = 0
            self.forced_defect_rounds = 0
            self.forced_cooperate_rounds = 0
            return Action.C
        m = 0.5
        opp_rates = []
        n_opps = self.n_opponents
        if n_opps > 0:
            for k in range(round_number):
                c_bar = int(history.opponent_cooperators[k])
                if c_bar < 0:
                    c_bar = 0
                elif c_bar > n_opps:
                    c_bar = n_opps
                x = c_bar / n_opps
                opp_rates.append(x)
                if k >= 0:
                    m = 0.7 * m + 0.3 * x
        self.m_estimate = m
        self.last_history_len = round_number
        if round_number >= int(self.game_description.n_rounds) - 1:
            return Action.D
        recent_two = opp_rates[-2:] if len(opp_rates) >= 2 else opp_rates[:]
        low_streak = len(recent_two) == 2 and recent_two[0] <= 1.0 / 3.0 and (recent_two[1] <= 1.0 / 3.0)
        high_streak = len(recent_two) == 2 and recent_two[0] >= 2.0 / 3.0 and (recent_two[1] >= 2.0 / 3.0)
        if low_streak:
            self.forced_defect_rounds = max(self.forced_defect_rounds, 2)
        if high_streak and s_t >= 0.5 * self.capacity:
            self.forced_cooperate_rounds = max(self.forced_cooperate_rounds, 2)
        if self.forced_defect_rounds > 0:
            self.forced_defect_rounds -= 1
            if s_t >= 0.4 * self.capacity and self.forced_defect_rounds <= 0:
                pass
            else:
                return Action.D
        if self.forced_cooperate_rounds > 0:
            self.forced_cooperate_rounds -= 1
            return Action.C
        if s_t < 0.25 * self.capacity:
            return Action.D
        if s_t < 0.4 * self.capacity:
            return Action.D
        n = self.n_players
        opp_count = self.n_opponents
        if n <= 1 or self.capacity <= 0.0:
            return Action.D
        opp_expected_consume = m * (s_t / (2.0 * n)) + (1.0 - m) * (s_t / n) if opp_count > 0 else 0.0
        cons_c = s_t / (2.0 * n) + opp_count * opp_expected_consume
        cons_d = s_t / n + opp_count * opp_expected_consume
        s_c = self._next_stock(s_t, s_t / (2.0 * n), opp_expected_consume, opp_count)
        s_d = self._next_stock(s_t, s_t / n, opp_expected_consume, opp_count)
        v_c = s_t / (2.0 * n) + 0.9 * (s_c / (2.0 * n))
        v_d = s_t / n + 0.9 * (s_d / n)
        if abs(m - 0.5) < 1e-12:
            if s_t >= 0.6 * self.capacity:
                return Action.C
            return Action.D
        if s_t >= 0.6 * self.capacity and m >= 0.5:
            return Action.C
        if v_c > v_d:
            return Action.C
        if v_d > v_c:
            return Action.D
        return Action.C if s_t >= 0.5 * self.capacity and m >= 0.5 else Action.D

class Strategy_INDIVIDUALISTIC_108(BaseStrategy):
    """
    Aggregate-memory common-pool strategy:
    - Starts cooperative.
    - Tracks current stock pressure and recent opponent cooperation rate.
    - Punishes sustained defection, but returns to cooperation quickly when
      opponents cooperate or stock becomes scarce.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(1, self.n_players - 1)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.n_players
        cap = self.capacity
        n_op = self.n_opponents
        t = int(history.round_number)
        if current_stock <= 0:
            return Action.C

        def q_from_count(count: int) -> float:
            return float(count) / float(n_op)

        def stock_next_if(choice_c: bool, coop_count: int) -> float:
            s = float(current_stock)
            if choice_c:
                remaining = s - s / (2.0 * n) - coop_count * s / (2.0 * n)
            else:
                remaining = s - s / n - coop_count * s / (2.0 * n)
            return min(remaining, cap)
        if t == 0:
            if n == 2:
                return Action.C
            if n >= cap / 2.0:
                return Action.D
            return Action.C
        last_count = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) >= 1 else 0
        last_q = q_from_count(last_count)
        prev_q = 0.0
        if len(history.opponent_cooperators) >= 2:
            prev_q = q_from_count(int(history.opponent_cooperators[-2]))
        if t == self.n_rounds - 1:
            if prev_q < 0.5:
                return Action.D
            if current_stock < 0.5 * cap:
                return Action.C
            return Action.D
        if n == 2:
            if len(history.opponent_cooperators) >= 2:
                if int(history.opponent_cooperators[-1]) == 0 and int(history.opponent_cooperators[-2]) == 0:
                    if current_stock <= 0.1 * cap:
                        return Action.C
                    return Action.D
            return Action.C
        if len(history.opponent_cooperators) == 0:
            last_q = 0.0
            prev_q = 0.0
        if current_stock <= 0.2 * cap:
            if last_q == 0.0:
                return Action.D
            return Action.C
        if len(history.opponent_cooperators) >= 2:
            if int(history.opponent_cooperators[-1]) == 0 and int(history.opponent_cooperators[-2]) == 0:
                if current_stock <= 0.1 * cap:
                    return Action.C
                return Action.D
        if last_q == 0.0:
            if current_stock <= 0.1 * cap:
                return Action.C
            return Action.D
        if last_q >= 0.5:
            if current_stock >= cap:
                return Action.C
            return Action.C
        if 0.2 <= last_q < 0.5:
            if current_stock >= 0.35 * cap:
                return Action.C
            return Action.D
        if last_q < 0.2:
            if current_stock >= 0.7 * cap:
                return Action.C
            return Action.D
        s_c = stock_next_if(True, last_count)
        s_d = stock_next_if(False, last_count)
        left = current_stock / (2.0 * n) + 0.25 * s_c
        right = current_stock / float(n) + 0.25 * s_d
        if left >= right:
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_109(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Starts with defection.
    - Tracks recent opponent cooperation with exponential smoothing.
    - Builds trust after two sufficiently cooperative rounds.
    - Cooperates only when expected cooperation and stock level justify it.
    - Defects in the last round, and falls back to defection if cooperation drops.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.coop_rate = 0.0
        self.trust = False
        self._last_obs_rate = 0.0
        self._high_coop_streak = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = int(self.game_description.n_players)
        r = int(self.game_description.n_rounds)
        capacity = float(self.game_description.capacity)
        if history.round_number == 0:
            return Action.D
        n_opponents = max(n - 1, 0)
        if n_opponents > 0:
            last_opps = int(history.opponent_cooperators[-1])
            obs_rate = last_opps / n_opponents
        else:
            obs_rate = 0.0
        self._last_obs_rate = obs_rate
        self.coop_rate = 0.7 * self.coop_rate + 0.3 * obs_rate
        high_threshold = math.ceil(n_opponents / 2) if n_opponents > 0 else 0
        if history.round_number >= 2 and n_opponents > 0:
            last_two = history.opponent_cooperators[-2:]
            if int(last_two[0]) >= high_threshold and int(last_two[1]) >= high_threshold:
                self.trust = True
        if n_opponents > 0 and obs_rate < n_opponents / 3.0:
            self.trust = False
            return Action.D
        if history.round_number >= max(r - 1, 0):
            return Action.D
        k = round(self.coop_rate * n_opponents)
        if k < 0:
            k = 0
        if k > n_opponents:
            k = n_opponents
        m_c = k + 1
        if self.trust and current_stock >= 0.8 * capacity:
            return Action.C
        if current_stock <= capacity / 2.0:
            threshold = math.ceil(n * capacity / current_stock) if current_stock > 0 else math.inf
            if m_c >= threshold:
                return Action.C
            return Action.D
        else:
            threshold = math.ceil(n / 2.0)
            if m_c >= threshold:
                return Action.C
            return Action.D

class Strategy_INDIVIDUALISTIC_110(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Starts with defection.
    - Tracks an exponentially smoothed estimate of opponent cooperation.
    - Uses stock level, recent trend, and endgame pressure to decide between C and D.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.rho = 0.5
        self.prev_stock = None
        self.high_rho_streak = 0
        self.low_rho_streak = 0
        self._processed_rounds = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_players = max(2, int(self.game_description.n_players))
        n_rounds = max(2, int(self.game_description.n_rounds))
        capacity = float(self.game_description.capacity) if self.game_description.capacity is not None else 0.0
        capacity = capacity if capacity > 0 else 1.0
        round_number = int(history.round_number)
        if round_number == 0:
            self.prev_stock = float(current_stock)
            self._processed_rounds = 0
            return Action.D
        start_idx = min(self._processed_rounds, round_number)
        opp_count = max(1, n_players - 1)
        for idx in range(start_idx, round_number):
            if idx < len(history.opponent_cooperators):
                k = int(history.opponent_cooperators[idx])
            else:
                break
            self.rho = 0.7 * self.rho + 0.3 * (float(k) / float(opp_count))
            if self.rho >= 2.0 / 3.0:
                self.high_rho_streak += 1
            else:
                self.high_rho_streak = 0
            if self.rho <= 1.0 / 3.0:
                self.low_rho_streak += 1
            else:
                self.low_rho_streak = 0
        self._processed_rounds = round_number
        stock_ratio = float(current_stock) / capacity if capacity > 0 else 0.0
        if stock_ratio < 0.0:
            stock_ratio = 0.0
        elif stock_ratio > 1.0:
            stock_ratio = 1.0
        trend = 0.0
        if self.prev_stock is not None:
            trend = float(current_stock) - float(self.prev_stock)
        remaining_after_this = n_rounds - (round_number + 1)
        action = Action.C
        if remaining_after_this <= 0:
            action = Action.D
        elif remaining_after_this <= 2:
            action = Action.C if stock_ratio <= 1.0 / 3.0 else Action.D
        elif stock_ratio <= 1.0 / 3.0:
            action = Action.C
        elif stock_ratio >= 2.0 / 3.0 and self.rho <= 0.5:
            action = Action.D
        elif trend < 0.0 and self.rho < 2.0 / 3.0:
            action = Action.D
        elif self.high_rho_streak >= 2 and stock_ratio >= 0.5:
            action = Action.D
        elif self.low_rho_streak >= 2 and stock_ratio <= 0.5:
            action = Action.C
        else:
            action = Action.C
        self.prev_stock = float(current_stock)
        return action

class Strategy_INDIVIDUALISTIC_111(BaseStrategy):
    """
    State-contingent threshold strategy with sustain, pressure, and harvest modes.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(self.n_players - 1, 1)
        self.harvest_mode_rounds_left = 0
        self.last_opponent_coop_rate = None

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number
        n_rounds = self.n_rounds
        cap = self.capacity if self.capacity > 0 else 1.0
        x = current_stock / cap
        p = 0.5
        if t > 0 and len(history.opponent_cooperators) > 0:
            last_k = int(history.opponent_cooperators[-1])
            p = last_k / self.n_opponents if self.n_opponents > 0 else 0.0
        recent_drop_in_p = False
        if len(history.opponent_cooperators) >= 2 and self.n_opponents > 0:
            prev_k = int(history.opponent_cooperators[-2])
            prev_p = prev_k / self.n_opponents
            if prev_p > 0 and p <= 2.0 / 3.0 * prev_p:
                recent_drop_in_p = True
        if self.harvest_mode_rounds_left > 0:
            self.harvest_mode_rounds_left -= 1
        if t > 0 and recent_drop_in_p:
            self.harvest_mode_rounds_left = 2
        if t == 0:
            self.last_opponent_coop_rate = None
            return Action.C
        if n_rounds > 0 and t == n_rounds - 1:
            self.last_opponent_coop_rate = p
            return Action.D if x < 1.0 else Action.C
        if n_rounds > 1 and t == n_rounds - 2:
            self.last_opponent_coop_rate = p
            return Action.C if x >= 0.8 and p >= 2.0 / 3.0 else Action.D
        if n_rounds > 3 and t >= n_rounds - 3 and (p < 0.5) and (x < 0.8):
            self.last_opponent_coop_rate = p
            return Action.D
        if x <= 0.2:
            self.last_opponent_coop_rate = p
            return Action.C
        if x >= 0.8:
            self.last_opponent_coop_rate = p
            return Action.C if p >= 2.0 / 3.0 else Action.D
        if self.harvest_mode_rounds_left > 0:
            self.last_opponent_coop_rate = p
            return Action.C if x < 0.2 else Action.D
        threshold = 0.5
        if p >= 2.0 / 3.0:
            threshold = 0.4
        elif p < 1.0 / 3.0:
            threshold = 0.6
        if p < 0.5:
            threshold = max(threshold, 0.6)
        action = Action.C if x >= threshold else Action.D
        self.last_opponent_coop_rate = p
        return action

class Strategy_INDIVIDUALISTIC_112(BaseStrategy):
    """
    Default-cooperative common-pool strategy with short-memory safeguards:
    - Cooperate on the first round.
    - Cooperate only when stock is healthy and recent opponent cooperation is stable.
    - Enter a short defensive mode after a weak-cooperation round.
    - Defect when stock is depleted or opponent behavior is unstable.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_opponents = max(0, self.n_players - 1)
        self.capacity = float(game_description.capacity)
        self.half_opponent_threshold = 0.5
        self.defensive_rounds = 2
        self.default_coop_threshold = self.capacity / 3.0
        self.aggressive_coop_threshold = self.capacity / 4.0
        self.low_stock_threshold = self.capacity / 5.0
        self.safe_stock_threshold = self.capacity / 2.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number
        if t == 0:
            return Action.C
        opp = history.opponent_cooperators
        last_idx = t - 1
        last_k = int(opp[last_idx]) if last_idx < len(opp) else 0
        if self.n_opponents > 0:
            p_last = last_k / self.n_opponents
        else:
            p_last = 1.0
        recent_count = min(3, t)
        start_idx = max(0, t - recent_count)
        recent_rates = []
        if self.n_opponents > 0:
            for idx in range(start_idx, t):
                k = int(opp[idx]) if idx < len(opp) else 0
                recent_rates.append(k / self.n_opponents)
            h_last = float(np.mean(recent_rates)) if recent_rates else 1.0
        else:
            h_last = 1.0
        in_defensive_mode = False
        if t >= 1:
            if p_last < self.half_opponent_threshold:
                in_defensive_mode = True
        if t >= 2 and (not in_defensive_mode) and (self.n_opponents > 0):
            prev_k = int(opp[last_idx - 1])
            p_prev = prev_k / self.n_opponents
            if p_prev < self.half_opponent_threshold:
                in_defensive_mode = True
        if current_stock <= self.low_stock_threshold:
            return Action.D
        if in_defensive_mode:
            if p_last == 1.0 and current_stock > self.safe_stock_threshold:
                return Action.C
            return Action.D
        if p_last < self.half_opponent_threshold or h_last < self.half_opponent_threshold:
            return Action.D
        if t == self.game_description.n_rounds - 1:
            if current_stock > self.aggressive_coop_threshold and p_last >= self.half_opponent_threshold:
                return Action.C
            return Action.D
        if current_stock > self.default_coop_threshold and p_last >= self.half_opponent_threshold and (h_last >= self.half_opponent_threshold):
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_113(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Starts with cooperation.
    - Tracks recent opponent cooperation using an EWMA.
    - Cooperates only when the stock is sufficiently healthy.
    - Defects in endgame, when stock is low, or when opponents have recently been uncooperative.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(self.n_players - 1, 1)
        self.m_bar = 1.0
        self._last_processed_round = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        capacity = self.capacity
        if round_number > self._last_processed_round:
            start = self._last_processed_round
            end = round_number
            for idx in range(start, end):
                q_t = int(history.opponent_cooperators[idx])
                q_t = max(0, min(q_t, self.n_opponents))
                m_t = q_t / self.n_opponents if self.n_opponents > 0 else 0.0
                self.m_bar = 0.7 * self.m_bar + 0.3 * m_t
            self._last_processed_round = round_number
        if round_number == 0:
            return Action.C
        if current_stock <= 0.0:
            return Action.D
        if round_number >= self.n_rounds - 1:
            return Action.D
        last_q = int(history.opponent_cooperators[-1]) if round_number > 0 else self.n_opponents
        last_q = max(0, min(last_q, self.n_opponents))
        last_m = last_q / self.n_opponents if self.n_opponents > 0 else 0.0
        if last_q == self.n_opponents:
            if current_stock >= 0.75 * capacity:
                self.m_bar = max(self.m_bar, 0.999999999)
                return Action.C
        if last_q == 0:
            if current_stock <= 0.5 * capacity:
                return Action.D
        if current_stock <= 0.25 * capacity:
            return Action.D
        expected_coop = max(self.m_bar, 0.0)
        threshold = capacity / 2.0 + capacity / 4.0 * expected_coop
        if last_m <= 0.0 and current_stock <= capacity / 2.0:
            return Action.D
        return Action.C if current_stock >= threshold else Action.D

class Strategy_INDIVIDUALISTIC_114(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Start by cooperating.
    - Defect in the final round or when the stock is depleted.
    - Punish insufficient opponent cooperation for two rounds.
    - Only cooperate when punishment has expired, cooperation has been
      sufficient for two consecutive rounds, and the stock is safe.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.punish = 0
        self.coop_streak = 0
        self.last_seen_round = -1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_players = max(2, int(self.game_description.n_players))
        n_opponents = max(0, n_players - 1)
        total_rounds = max(1, int(self.game_description.n_rounds))
        round_number = int(history.round_number)
        majority = math.ceil(n_opponents / 2) if n_opponents > 0 else 0
        if round_number == 0:
            self.punish = 0
            self.coop_streak = 0
            self.last_seen_round = 0
            return Action.C
        m = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        if m < majority:
            self.punish = 2
            self.coop_streak = 0
        else:
            self.coop_streak += 1
            if self.punish > 0:
                self.punish -= 1
        R = total_rounds - round_number
        if R <= 1:
            self.last_seen_round = round_number
            return Action.D
        if current_stock <= 0:
            self.last_seen_round = round_number
            return Action.D
        safe_divisor = max(2, R)
        capacity = float(self.game_description.capacity)
        safe_stock = max(2 * n_players, capacity / safe_divisor) if safe_divisor > 0 else 2 * n_players
        if self.punish == 0 and self.coop_streak >= 2 and (current_stock >= safe_stock) and (m >= majority):
            self.last_seen_round = round_number
            return Action.C
        self.last_seen_round = round_number
        return Action.D

class Strategy_INDIVIDUALISTIC_115(BaseStrategy):
    """
    Stock-aware cooperative strategy with deterministic punishment:
    - Cooperate by default when the stock is healthy and recent cooperation is high.
    - Enter a short punishment window after any low-cooperation round.
    - Re-enter cooperation only when the environment is disciplined again.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.target_stock = float(game_description.capacity) / 2.0
        self.cooperation_threshold = 2.0 / 3.0
        self.punishment_length = 2
        self._processed_rounds = 0
        self._punishment_remaining = 0
        self._last_observed_cooperation_fraction = 1.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_rounds = self.game_description.n_rounds
        n_players = self.game_description.n_players
        n_opponents = max(n_players - 1, 1)
        while self._processed_rounds < history.round_number:
            idx = self._processed_rounds
            coop_count = int(history.opponent_cooperators[idx])
            frac = coop_count / n_opponents
            self._last_observed_cooperation_fraction = frac
            if frac < self.cooperation_threshold:
                self._punishment_remaining = self.punishment_length
            self._processed_rounds += 1
        current_round = history.round_number
        if current_round == 0:
            action = Action.C if self.game_description.capacity >= 2 * n_players else Action.D
            return action
        if current_stock <= 0.0:
            action = Action.D
        elif self._punishment_remaining > 0:
            action = Action.D
        elif current_round == n_rounds - 1:
            prev_frac = self._last_observed_cooperation_fraction
            action = Action.C if prev_frac == 1.0 and current_stock >= self.target_stock else Action.D
        else:
            prev_frac = self._last_observed_cooperation_fraction
            action = Action.C if current_stock >= self.target_stock and prev_frac >= self.cooperation_threshold else Action.D
        if self._punishment_remaining > 0:
            self._punishment_remaining -= 1
        return action

class Strategy_INDIVIDUALISTIC_116(BaseStrategy):
    """
    Cooperative-by-default common-pool strategy with stock-aware caution,
    rolling opponent-cooperation estimation, punishment, and recovery logic.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = max(2, int(game_description.n_players))
        self.n_rounds = max(1, int(game_description.n_rounds))
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(1, self.n_players - 1)
        self.coop_estimate = 1.0
        self.processed_rounds = 0
        self.punishment_remaining = 0
        self.cautious_next_round = False
        self.last_observed_coop_rate = 1.0
        self.last_observed_all_zero = False
        self.last_my_action = Action.C

    def _clamp_stock(self, stock: float) -> float:
        stock = float(stock)
        if stock < 0.0:
            return 0.0
        if stock > self.capacity:
            return self.capacity
        return stock

    def _expected_next_stock(self, stock: float, self_play: Action, p_coop: float) -> float:
        s = self._clamp_stock(stock)
        p = float(p_coop)
        if p < 0.0:
            p = 0.0
        elif p > 1.0:
            p = 1.0
        own_cons = s / (2.0 * self.n_players) if self_play == Action.C else s / self.n_players
        opp_cons_c = s / (2.0 * self.n_players)
        opp_cons_d = s / self.n_players
        expected_opp_cons = self.n_opponents * (p * opp_cons_c + (1.0 - p) * opp_cons_d)
        remaining = s - own_cons - expected_opp_cons
        if remaining < 0.0:
            remaining = 0.0
        if remaining > self.capacity:
            remaining = self.capacity
        growth = 2.0 * remaining * (1.0 - remaining / self.capacity) if self.capacity > 0 else 0.0
        new_stock = remaining + growth
        if new_stock > self.capacity:
            new_stock = self.capacity
        if new_stock < 0.0:
            new_stock = 0.0
        return new_stock

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        current_round = round_number + 1
        stock = self._clamp_stock(current_stock)
        if round_number > self.processed_rounds:
            for idx in range(self.processed_rounds, round_number):
                if idx >= len(history.opponent_cooperators):
                    break
                k = int(history.opponent_cooperators[idx])
                if k < 0:
                    k = 0
                if k > self.n_opponents:
                    k = self.n_opponents
                rate = k / self.n_opponents if self.n_opponents > 0 else 0.0
                self.coop_estimate = 0.7 * self.coop_estimate + 0.3 * rate
                self.last_observed_coop_rate = rate
                self.last_observed_all_zero = k == 0
                if rate < 0.4:
                    self.punishment_remaining = 2
                elif self.punishment_remaining > 0:
                    self.punishment_remaining -= 1
                if idx < len(history.my_actions):
                    self.last_my_action = Action.C if bool(history.my_actions[idx]) else Action.D
                    self.cautious_next_round = self.last_my_action == Action.D
            self.processed_rounds = round_number
        if stock <= 0.0:
            self.last_my_action = Action.D
            self.cautious_next_round = True
            return Action.D
        if current_round == 1:
            self.last_my_action = Action.C
            return Action.C
        if current_round == self.n_rounds:
            if stock >= 0.8 * self.capacity and self.coop_estimate >= 0.75:
                self.last_my_action = Action.C
                return Action.C
            self.last_my_action = Action.D
            self.cautious_next_round = True
            return Action.D
        if self.cautious_next_round:
            if stock >= 0.75 * self.capacity and self.coop_estimate >= 0.7:
                self.last_my_action = Action.C
                self.cautious_next_round = False
                return Action.C
            self.last_my_action = Action.D
            self.cautious_next_round = True
            return Action.D
        if self.punishment_remaining > 0:
            if self.last_observed_coop_rate >= 0.7 and stock >= 0.5 * self.capacity:
                self.punishment_remaining = 0
                self.last_my_action = Action.C
                return Action.C
            self.punishment_remaining = max(0, self.punishment_remaining - 1)
            self.last_my_action = Action.D
            self.cautious_next_round = True
            return Action.D
        p_t = self.coop_estimate
        s_c = self._expected_next_stock(stock, Action.C, p_t)
        s_d = self._expected_next_stock(stock, Action.D, p_t)
        two_zero_consecutive = False
        if len(history.opponent_cooperators) >= 2:
            prev1 = int(history.opponent_cooperators[-1])
            prev2 = int(history.opponent_cooperators[-2])
            two_zero_consecutive = prev1 == 0 and prev2 == 0
        if stock >= 0.5 * self.capacity and self.coop_estimate >= 0.6 and (s_c >= 0.5 * self.capacity):
            self.last_my_action = Action.C
            return Action.C
        if stock < self.capacity / 3.0 or self.coop_estimate < 0.4 or two_zero_consecutive or (s_d > s_c and stock <= 0.5 * self.capacity):
            self.last_my_action = Action.D
            self.cautious_next_round = True
            return Action.D
        if stock >= 0.5 * self.capacity:
            self.last_my_action = Action.C
            return Action.C
        self.last_my_action = Action.D
        self.cautious_next_round = True
        return Action.D

class Strategy_INDIVIDUALISTIC_117(BaseStrategy):
    """
    Opportunistic threshold strategy with stock-preservation trigger.

    - Cooperates in round 1.
    - In later rounds, cooperates only when stock is healthy and observed opponent
      cooperation is strong enough relative to a dynamic threshold.
    - Defects in the last round if stock is positive.
    - Remembers whether the previous round was weak/insufficient cooperation, and
      requires at least one strongly cooperative round before resuming cooperation.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(getattr(game_description, 'n_players', 2))
        self.n_rounds = int(getattr(game_description, 'n_rounds', 2))
        self.capacity = float(getattr(game_description, 'capacity', 1.0))
        self.n_opponents = max(self.n_players - 1, 1)
        self.stock_threshold_ratio = 0.35
        self.strong_cooperation_ratio = 2.0 / 3.0
        self.require_recovery_round = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(getattr(history, 'round_number', 0))
        total_rounds = self.n_rounds
        if round_number == 0:
            self.require_recovery_round = False
            return Action.C
        if round_number >= total_rounds - 1:
            self.require_recovery_round = False
            return Action.D
        capacity = self.capacity if self.capacity > 0 else 1.0
        q_t = float(current_stock) / capacity
        last_opponents_coop = 0
        if len(history.opponent_cooperators) > 0:
            last_opponents_coop = int(history.opponent_cooperators[-1])
        K_t = last_opponents_coop / self.n_opponents if self.n_opponents > 0 else 0.0
        T_t = 0.5 + 0.25 * (1.0 - K_t)
        T_t = max(0.35, min(0.85, T_t))
        strong_coop = K_t >= self.strong_cooperation_ratio
        healthy_stock = q_t >= self.stock_threshold_ratio
        cooperative_enough = K_t >= T_t
        if q_t < self.stock_threshold_ratio:
            self.require_recovery_round = True
            return Action.D
        if self.require_recovery_round:
            if strong_coop and healthy_stock:
                self.require_recovery_round = False
                return Action.C
            return Action.D
        if healthy_stock and cooperative_enough:
            return Action.C
        self.require_recovery_round = True
        return Action.D

class Strategy_INDIVIDUALISTIC_118(BaseStrategy):
    """
    Pool-preservation strategy:
    - Cooperates in round 1.
    - In the final round, defects.
    - Otherwise, cooperates only when current stock and prior cooperation are sufficiently high.
    - Defects if the pool is weakening under weak cooperation.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(self.n_players - 1, 1)
        self.half_capacity = self.capacity / 2.0
        self.three_quarter_capacity = 3.0 * self.capacity / 4.0
        self.low_capacity_threshold = self.capacity / (2.0 * self.n_players)
        self.last_stock = None
        self.last_round_number = -1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        if round_number == 0:
            self.last_stock = float(current_stock)
            self.last_round_number = round_number
            return Action.C
        prev_stock = self.last_stock if self.last_stock is not None else float(current_stock)
        m = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        S = float(current_stock)
        if round_number >= self.n_rounds - 1:
            self.last_stock = S
            self.last_round_number = round_number
            return Action.D
        thresh_low = self.n_players - 2
        thresh_mid = math.ceil(2.0 * (self.n_players - 1) / 3.0)
        thresh_high = math.ceil((self.n_players - 1) / 2.0)
        if S <= self.low_capacity_threshold:
            decision = Action.C if m >= thresh_low else Action.D
        elif S <= self.half_capacity:
            decision = Action.C if m >= thresh_mid else Action.D
        elif S <= self.three_quarter_capacity:
            decision = Action.C if m >= thresh_high else Action.D
        else:
            decision = Action.C if m == self.n_players - 1 else Action.D
        if S < prev_stock and m <= math.ceil((self.n_players - 1) / 2.0):
            decision = Action.D
        if S >= self.capacity and m == self.n_players - 1:
            decision = Action.C
        self.last_stock = S
        self.last_round_number = round_number
        return decision

class Strategy_INDIVIDUALISTIC_119(BaseStrategy):
    """
    Self-protective threshold strategy with short memory of opponent cooperation.
    Starts cooperative, then uses recent cooperation to decide between preserving
    the pool or extracting immediate value.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = max(2, int(game_description.n_players))
        self.r = max(2, int(game_description.n_rounds))
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(1, self.n - 1)

    def _avg_recent_cooperation(self, history: PlayerHistory) -> float:
        rounds_played = history.round_number
        if rounds_played <= 0:
            return 1.0
        L = min(3, rounds_played)
        recent = history.opponent_cooperators[-L:]
        if len(recent) == 0:
            return 1.0
        denom = float(self.n_opponents) * float(len(recent))
        if denom <= 0.0:
            return 1.0
        return float(np.sum(recent)) / denom

    def _predict_next_stock(self, current_stock: float, my_action: Action, x_t: float) -> float:
        S = max(0.0, float(current_stock))
        cap = self.capacity
        n = float(self.n)
        n_opp = float(self.n_opponents)
        coop_cons = S / (2.0 * n)
        defect_cons = S / n
        expected_others = n_opp * (coop_cons * x_t + defect_cons * (1.0 - x_t))
        own_cons = coop_cons if my_action == Action.C else defect_cons
        q_total = expected_others + own_cons
        remaining = max(S - q_total, 0.0)
        growth = 2.0 * remaining * (1.0 - remaining / cap) if cap > 0.0 else 0.0
        next_stock = min(remaining + growth, cap)
        return max(0.0, next_stock)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number
        S_t = max(0.0, float(current_stock))
        cap = self.capacity
        eps = cap / (1000.0 * float(self.n)) if self.n > 0 else 0.0
        if t == 0:
            return Action.C
        m_t = self._avg_recent_cooperation(history)
        x_t = m_t
        if S_t <= 2.0 * float(self.n):
            return Action.D
        is_last_round = t >= self.r - 1
        if is_last_round:
            return Action.D if S_t > 0.0 else Action.C
        if S_t >= 0.9 * cap and m_t >= 0.4:
            return Action.C
        S_c = self._predict_next_stock(S_t, Action.C, x_t)
        S_d = self._predict_next_stock(S_t, Action.D, x_t)
        if m_t >= 0.75:
            return Action.D if S_d >= S_c - eps else Action.C
        elif m_t >= 0.4:
            return Action.C if S_c - S_d > 2.0 * eps else Action.D
        else:
            if S_t >= 0.9 * cap and S_c - S_d > 4.0 * eps:
                return Action.C
            return Action.D

class Strategy_INDIVIDUALISTIC_120(BaseStrategy):
    """
    Probe with cooperation, then adapt to anonymous cooperation and stock levels.
    Cooperate early only when the pool and recent cooperation remain healthy;
    defect at the final round, under depletion, or when behavior looks exploitative.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.c_prev = None
        self.prev_c_prev = None
        self.s = float(self.capacity)
        self.defect_lock = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        self.s = float(current_stock)
        if round_number == 0:
            self.c_prev = None
            self.prev_c_prev = None
            self.defect_lock = False
            return Action.C
        last_c = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        if self.c_prev is None:
            self.c_prev = last_c
        else:
            self.prev_c_prev = self.c_prev
            self.c_prev = last_c
        if self.s <= 0.0:
            self.defect_lock = True
            return Action.D
        if round_number >= self.r - 1:
            return Action.D
        opp_count = max(self.n - 1, 1)
        q = float(self.c_prev) / float(opp_count)
        x = self.s / self.capacity if self.capacity > 0 else 0.0
        if self.prev_c_prev is not None:
            cooperation_dropped = self.c_prev <= self.prev_c_prev - 1
        else:
            cooperation_dropped = False
        if cooperation_dropped and q < 1.0 and (x < 1.0):
            self.defect_lock = True
        if self.defect_lock and (q >= 1.0 and x >= 0.5):
            self.defect_lock = False
        if self.defect_lock:
            return Action.D
        if self.n == 2:
            if self.c_prev == 1 and x >= 0.5:
                return Action.C
            return Action.D
        if self.c_prev == self.n - 1:
            return Action.C
        if q >= 0.5 and x >= 0.5:
            return Action.C
        if q <= 1.0 / 3.0 or x <= 1.0 / 3.0:
            return Action.D
        return Action.D

class Strategy_INDIVIDUALISTIC_121(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Starts cooperatively.
    - Treats high opponent cooperation and high stock as recovery signals.
    - Switches to defection under low stock, weak cooperation, or punishment.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.mode = 'green'
        self.punishment_remaining = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_players = max(int(self.game_description.n_players), 2)
        n_opponents = max(n_players - 1, 1)
        capacity = float(self.game_description.capacity)
        round_number = int(history.round_number)
        if round_number == 0:
            self.mode = 'green'
            self.punishment_remaining = 0
            return Action.C
        last_opponents_coop = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        c_t = last_opponents_coop / n_opponents
        strong_coop = last_opponents_coop >= math.ceil(0.8 * n_opponents)
        mild_coop = last_opponents_coop >= math.ceil(0.7 * n_opponents)
        weak_coop = last_opponents_coop < math.ceil(0.5 * n_opponents)
        recovery_threshold = 0.75 * capacity
        caution_threshold = 0.6 * capacity
        hard_floor = 0.25 * capacity
        if current_stock >= recovery_threshold and c_t >= 0.6:
            self.mode = 'green'
        elif current_stock <= caution_threshold or c_t <= 0.4:
            self.mode = 'red'
        if weak_coop:
            self.punishment_remaining = max(self.punishment_remaining, 2)
        elif mild_coop:
            self.punishment_remaining = 0
        if round_number >= int(self.game_description.n_rounds) - 1:
            if current_stock >= 0.9 * capacity and strong_coop:
                return Action.C
            return Action.D
        if current_stock <= hard_floor:
            return Action.D
        if strong_coop and current_stock > recovery_threshold:
            self.mode = 'green'
            return Action.C
        if self.punishment_remaining > 0:
            self.punishment_remaining -= 1
            self.mode = 'red'
            return Action.D
        if self.mode == 'green':
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_122(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Start cooperative.
    - Defect in low-stock situations.
    - Cooperate in healthy pools only when opponents have recently cooperated enough.
    - Use recent stock trajectory and opponent cooperation history as an adaptive modifier.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.capacity = float(game_description.capacity)
        self.n_players = int(game_description.n_players)
        self.n_opponents = max(0, self.n_players - 1)
        self.observed_stocks = []

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number
        capacity = self.capacity
        n_opponents = self.n_opponents
        if len(self.observed_stocks) <= t:
            self.observed_stocks.append(float(current_stock))
        else:
            self.observed_stocks[t] = float(current_stock)
        if t == 0:
            return Action.C
        if t == self.game_description.n_rounds - 1:
            return Action.D
        critical_stock = capacity / 4.0
        safe_coop_stock = capacity / 2.0
        if n_opponents > 0 and len(history.opponent_cooperators) > 0:
            last_opp_coop_rate = float(history.opponent_cooperators[-1]) / float(n_opponents)
        else:
            last_opp_coop_rate = 0.0
        if current_stock <= critical_stock:
            action = Action.D
        elif current_stock >= safe_coop_stock:
            action = Action.C if last_opp_coop_rate >= 0.5 else Action.D
        else:
            prev_stock = self.observed_stocks[t - 1] if t - 1 < len(self.observed_stocks) else current_stock
            action = Action.C if last_opp_coop_rate >= 2.0 / 3.0 and current_stock >= prev_stock else Action.D
        m = min(3, t)
        if m > 0 and n_opponents > 0:
            recent_coop_rates = []
            start_idx = max(0, t - m)
            end_idx = t
            for idx in range(start_idx, min(end_idx, len(history.opponent_cooperators))):
                recent_coop_rates.append(float(history.opponent_cooperators[idx]) / float(n_opponents))
            coop_rate_recent = float(np.mean(recent_coop_rates)) if recent_coop_rates else 0.0
            if t - m >= 0 and t - m < len(self.observed_stocks):
                stock_trend = float(current_stock) - float(self.observed_stocks[t - m])
            else:
                stock_trend = 0.0
            if current_stock > critical_stock and current_stock < safe_coop_stock:
                if coop_rate_recent >= 2.0 / 3.0 and stock_trend > 0:
                    action = Action.C
                if coop_rate_recent <= 1.0 / 3.0 or stock_trend < 0:
                    action = Action.D
            elif current_stock <= critical_stock:
                action = Action.D
        return action

class Strategy_INDIVIDUALISTIC_123(BaseStrategy):
    """
    Cautious common-pool strategy:
    - Start with cooperation.
    - Cooperate only when stock is healthy and opponent defection is minimal.
    - Defect after notable defection or low-stock conditions.
    - Re-open cooperation cautiously after recovery.
    - Defect in the endgame, with a narrow penultimate-round exception.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(0, self.n_players - 1)
        self.in_punishment = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        S = float(current_stock)
        if self.n_players <= 1 or self.n_rounds <= 1:
            return Action.D
        if S <= 0.0:
            self.in_punishment = True
            return Action.D
        if round_number >= self.n_rounds - 1:
            self.in_punishment = True
            return Action.D
        if round_number == self.n_rounds - 2:
            prev_all_coop = False
            if round_number > 0 and len(history.opponent_cooperators) >= 2:
                prev_all_coop = int(history.opponent_cooperators[-1]) == self.n_opponents
            if S >= 0.9 * self.capacity and prev_all_coop:
                return Action.C
            self.in_punishment = True
            return Action.D
        if round_number == 0:
            self.in_punishment = False
            return Action.C
        k_t = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        k_t = max(0, min(k_t, self.n_opponents))
        m_t = self.n_opponents - k_t
        share_t = S / (2.0 * self.n_players)
        grab_t = S / float(self.n_players)
        opp_consumption = k_t * (S / (2.0 * self.n_players)) + m_t * (S / float(self.n_players))
        cons_C = share_t + opp_consumption
        cons_D = grab_t + opp_consumption
        S_after_C = S - cons_C
        S_after_D = S - cons_D
        if S <= 0.4 * self.capacity:
            self.in_punishment = True
            return Action.D
        if self.in_punishment:
            if m_t == 0 and S >= 0.7 * self.capacity:
                self.in_punishment = False
            else:
                return Action.D
        if m_t >= 2:
            self.in_punishment = True
            return Action.D
        core_allows_coop = (m_t == 0 or (m_t == 1 and S_after_C > 0.0)) and S_after_C >= 0.6 * self.capacity and (S >= 0.5 * self.capacity)
        if core_allows_coop:
            return Action.C
        if m_t == 0 and S >= 0.7 * self.capacity:
            return Action.C
        if m_t >= 1:
            return Action.D
        if grab_t > share_t:
            return Action.D
        return Action.C

class Strategy_INDIVIDUALISTIC_124(BaseStrategy):
    """
    Cautious common-pool strategy:
    - Opens cooperatively only in 2-player games.
    - Defects by default.
    - Cooperates only when stock is rich and recent opponent cooperation is strong.
    - Retaliates quickly against low cooperation and softens again only after sustained recovery.
    - Plays defensively in the final rounds.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.mode = 'cautious'
        self.punitive_timer = 0
        self.good_round_streak = 0
        self.last_processed_round = -1
        self.prev_stock = None
        self.prev_rho = None

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = int(history.round_number)
        n = self.n
        cap = self.capacity
        if t == 0:
            self.mode = 'cautious'
            self.punitive_timer = 0
            self.good_round_streak = 0
            self.last_processed_round = 0
            self.prev_stock = float(current_stock)
            self.prev_rho = None
            return Action.C if n == 2 else Action.D
        if t == self.last_processed_round:
            if t == 0:
                return Action.C if n == 2 else Action.D
        else:
            self.last_processed_round = t
        prev_idx = t - 1
        if prev_idx < 0 or prev_idx >= len(history.opponent_cooperators):
            return Action.D
        m = max(n - 1, 1)
        c_prev = int(history.opponent_cooperators[prev_idx])
        c_prev = max(0, min(c_prev, m))
        rho = c_prev / m
        prev_stock = self.prev_stock if self.prev_stock is not None else float(current_stock)
        current_stock = float(current_stock)
        near_same = False
        if prev_stock is not None:
            threshold = max(1e-12, 0.02 * cap)
            near_same = abs(current_stock - prev_stock) <= threshold
        stock_not_decreasing = prev_stock is None or current_stock >= prev_stock - max(1e-12, 0.01 * cap)
        good_now = rho >= 0.6 and current_stock > 0.75 * cap
        if good_now:
            self.good_round_streak += 1
        else:
            self.good_round_streak = 0
        if rho < 1 / 3:
            self.mode = 'punitive'
            self.punitive_timer = max(self.punitive_timer, 2)
            self.good_round_streak = 0
        elif rho < 0.5:
            self.mode = 'punitive'
            self.punitive_timer = max(self.punitive_timer, 2)
            self.good_round_streak = 0
        elif rho >= 0.6 and current_stock >= 0.75 * cap:
            if self.punitive_timer <= 0 and self.good_round_streak >= 2:
                self.mode = 'cooperative'
            elif self.mode != 'punitive':
                self.mode = 'cautious'
        elif self.mode != 'punitive':
            self.mode = 'cautious'
        rounds_left = self.r - t
        if rounds_left <= 1:
            if rho == 1 and abs(current_stock - cap) <= max(1e-12, 1e-09 * cap):
                action = Action.C
            else:
                action = Action.D
            self.prev_stock = current_stock
            self.prev_rho = rho
            return action
        if rounds_left == 2:
            if rho < 1 or current_stock < cap - max(1e-12, 1e-09 * cap):
                action = Action.D
            else:
                action = Action.C
            self.prev_stock = current_stock
            self.prev_rho = rho
            return action
        if self.punitive_timer > 0:
            self.punitive_timer -= 1
            self.mode = 'punitive'
            action = Action.D
        elif self.good_round_streak >= 2 and current_stock >= 0.75 * cap and (rho >= 0.6) and stock_not_decreasing:
            self.mode = 'cooperative'
            action = Action.C
        elif current_stock >= 0.75 * cap and rho >= 0.6 and (stock_not_decreasing or near_same):
            self.mode = 'cooperative'
            action = Action.C
        else:
            self.mode = 'cautious'
            action = Action.D
        if action == Action.C:
            if current_stock <= 0.75 * cap and rho < 1.0 or (current_stock <= 0.75 * cap and self.good_round_streak < 2):
                action = Action.D
        self.prev_stock = current_stock
        self.prev_rho = rho
        return action

class Strategy_INDIVIDUALISTIC_125(BaseStrategy):
    """
    Opportunistic conservation strategy:
    defects by default, cooperates only when stock is low enough and recent
    opponent cooperation suggests preservation is profitable.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = int(history.round_number) + 1
        last_round_idx = history.round_number - 1
        if t == 1 or t == self.n_rounds:
            return Action.D
        n_opponents = max(self.n_players - 1, 1)

        def coop_rate(round_idx: int) -> float | None:
            if round_idx < 0 or round_idx >= history.round_number:
                return None
            return float(history.opponent_cooperators[round_idx]) / float(n_opponents)
        q = coop_rate(last_round_idx)
        if q is None:
            return Action.D
        q_prev = coop_rate(last_round_idx - 1)
        cap = self.capacity
        S = float(current_stock)
        last_low_idx = -1
        last_reset_idx = -1
        for idx in range(history.round_number - 1, -1, -1):
            qq = coop_rate(idx)
            if qq is None:
                continue
            if qq >= 0.75:
                last_reset_idx = idx
                break
            if qq < 0.5:
                last_low_idx = idx
                break
        lock_active = False
        if last_low_idx >= 0 and last_low_idx > last_reset_idx:
            if history.round_number - 1 - last_low_idx < 2:
                lock_active = True
        if S >= 0.75 * cap:
            return Action.D
        if lock_active:
            if S <= 0.25 * cap and q >= 0.5:
                return Action.C
            return Action.D
        if S <= 0.25 * cap:
            return Action.C if q >= 0.5 else Action.D
        if S <= 0.5 * cap:
            if q >= 0.75 and q_prev is not None and (q_prev >= 0.5):
                return Action.C
            return Action.D
        return Action.D

class Strategy_INDIVIDUALISTIC_126(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Start cooperatively.
    - Remain cooperative only when stock is healthy and opponents are mostly cooperating.
    - Switch to defensive immediately upon weak cooperation or low stock.
    - Return to cooperation only after two consecutive sufficiently cooperative defensive rounds.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.mode = 'cooperative'
        self.last_coop_rate = None
        self.prev_coop_rate = None
        self.last_round_was_coop_enough = False
        self.consecutive_coop_enough = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        n_opponents = max(self.n - 1, 0)
        if round_number > 0 and len(history.opponent_cooperators) > 0:
            k_prev = int(history.opponent_cooperators[-1])
            if n_opponents > 0:
                coop_rate_prev = k_prev / n_opponents
            else:
                coop_rate_prev = 0.0
            self.prev_coop_rate = self.last_coop_rate
            self.last_coop_rate = coop_rate_prev
            self.last_round_was_coop_enough = coop_rate_prev >= 0.75
            if self.last_round_was_coop_enough:
                self.consecutive_coop_enough += 1
            else:
                self.consecutive_coop_enough = 0
            if coop_rate_prev < 0.5:
                self.mode = 'defensive'
        if round_number == 0:
            self.mode = 'cooperative'
            return Action.C
        if round_number >= self.r - 1:
            return Action.D
        stock = float(current_stock)
        if stock <= self.capacity / 3.0:
            self.mode = 'defensive'
            return Action.D
        coop_rate = self.last_coop_rate if self.last_coop_rate is not None else 0.0
        if self.mode == 'cooperative':
            if stock >= self.capacity / 2.0 and coop_rate >= 2.0 / 3.0:
                return Action.C
            self.mode = 'defensive'
            return Action.D
        can_cooperate = stock >= 2.0 * self.capacity / 3.0 and coop_rate >= 0.75 and (self.prev_coop_rate is not None) and (self.prev_coop_rate >= 0.75)
        if can_cooperate:
            if self.last_round_was_coop_enough:
                self.consecutive_coop_enough += 1
            else:
                self.consecutive_coop_enough = 1
            if self.consecutive_coop_enough >= 2:
                self.mode = 'cooperative'
            return Action.C
        self.consecutive_coop_enough = 0
        return Action.D

class Strategy_INDIVIDUALISTIC_127(BaseStrategy):
    """
    Stock-preserving threshold strategy with retaliation, recovery, and mild forgiveness.
    Cooperates initially, then conditions cooperation on stock health and observed restraint.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(1, self.n_players - 1)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number
        if t == 0:
            return Action.C
        cap = self.capacity if self.capacity > 0 else 1.0
        x = current_stock / cap
        prev_k = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        c = prev_k / self.n_opponents
        if x >= 0.5:
            threshold = 0.5
        else:
            threshold = 1.0 - x
        if t >= self.n_rounds - 1:
            if x < 0.5:
                return Action.D
            return Action.C if c == 1.0 else Action.D
        if x <= 0.125:
            return Action.D
        if x <= 0.25:
            return Action.D
        if c >= threshold:
            return Action.C
        if x >= 0.5:
            forgiven_threshold = threshold - 1.0 / self.n_opponents
            if c >= forgiven_threshold:
                return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_128(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Starts with cooperation.
    - Tracks a smoothed cooperation score Q.
    - Cooperates when stock is under pressure or cooperation has been strong.
    - Defects in the final round, and usually in the penultimate round unless
      the resource is near depletion and the group has been consistently cooperative.
    - Optionally enters a short defect lockout after a bad cooperation signal.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.Q = 1.0
        self._processed_rounds = 0
        self._forced_defect_rounds = 0
        self._last_stock_ratio = 1.0

    def _process_history(self, history: PlayerHistory) -> None:
        n_players = self.game_description.n_players
        n_opponents = max(n_players - 1, 1)
        rounds_seen = history.round_number
        if rounds_seen <= self._processed_rounds:
            return
        for t in range(self._processed_rounds, rounds_seen):
            opp_coop = int(history.opponent_cooperators[t]) if t < len(history.opponent_cooperators) else 0
            q_t = opp_coop / n_opponents
            self.Q = 0.6 * self.Q + 0.4 * q_t
            if q_t <= 0.5:
                if self.Q > 0.5:
                    self.Q = 0.5
                self._forced_defect_rounds = max(self._forced_defect_rounds, 2)
        self._processed_rounds = rounds_seen

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        self._process_history(history)
        n_rounds = self.game_description.n_rounds
        capacity = float(self.game_description.capacity)
        t = history.round_number
        stock_ratio = 0.0 if capacity <= 0 else current_stock / capacity
        self._last_stock_ratio = stock_ratio
        if t == 0:
            return Action.C
        if t == n_rounds - 1:
            return Action.D
        if t == n_rounds - 2:
            if stock_ratio <= 0.35 and self.Q >= 0.8:
                return Action.C
            return Action.D
        if self._forced_defect_rounds > 0:
            if stock_ratio <= 0.25:
                return Action.C
            self._forced_defect_rounds -= 1
            return Action.D
        if stock_ratio <= 0.25:
            return Action.C
        elif stock_ratio <= 0.7 and self.Q >= 0.75:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_109(BaseStrategy):
    """
    Selfish forward-looking extractor for the common pool resource game.

    - Estimates opponent cooperation from the previous round.
    - Uses a one-step recursive lookahead to compare cooperate vs defect.
    - Defaults to defect under low stock, late rounds, or low cooperation.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)
        self.n_opponents = max(0, self.n - 1)
        self.last_seen_round = -1
        self.last_stock = None
        self.last_opponent_cooperators = None
        self.last_p = 0.5

    def _safe_p_from_history(self, history: PlayerHistory) -> float:
        if history.round_number <= 0 or self.n_opponents <= 0:
            p = 0.5
        else:
            obs = float(history.opponent_cooperators[-1])
            p = obs / float(self.n_opponents)
        p = (p + 0.5) / 2.0
        if p < 0.0:
            p = 0.0
        elif p > 1.0:
            p = 1.0
        return p

    def _action_consumption(self, action: Action, stock: float) -> float:
        if action == Action.C:
            return stock / (2.0 * self.n)
        return stock / float(self.n)

    def _expected_next_stock(self, stock: float, my_action: Action, p: float) -> float:
        q = self._action_consumption(my_action, stock)
        opponent_expected = p * (stock / (2.0 * self.n)) + (1.0 - p) * (stock / float(self.n))
        remaining = stock - q - self.n_opponents * opponent_expected
        if remaining < 0.0:
            remaining = 0.0
        growth = 2.0 * remaining * (1.0 - remaining / self.capacity) if self.capacity > 0.0 else 0.0
        nxt = remaining + growth
        if nxt > self.capacity:
            nxt = self.capacity
        elif nxt < 0.0:
            nxt = 0.0
        return nxt

    def _score_action(self, stock: float, remaining_rounds: int, p: float, action: Action, depth: int=0) -> float:
        immediate = self._action_consumption(action, stock)
        if remaining_rounds <= 1:
            return immediate
        next_stock = self._expected_next_stock(stock, action, p)
        if depth >= 8:
            return immediate
        next_c = self._score_action(next_stock, remaining_rounds - 1, p, Action.C, depth + 1)
        next_d = self._score_action(next_stock, remaining_rounds - 1, p, Action.D, depth + 1)
        continuation = max(next_c, next_d)
        return immediate + continuation

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        remaining_rounds = self.r - round_number
        self.last_seen_round = round_number
        self.last_stock = float(current_stock)
        if remaining_rounds <= 1:
            self.last_p = self._safe_p_from_history(history)
            self.last_opponent_cooperators = int(history.opponent_cooperators[-1]) if round_number > 0 else None
            return Action.D
        if current_stock < self.capacity / 8.0:
            self.last_p = self._safe_p_from_history(history)
            self.last_opponent_cooperators = int(history.opponent_cooperators[-1]) if round_number > 0 else None
            return Action.D
        if current_stock < self.capacity / 4.0:
            self.last_p = self._safe_p_from_history(history)
            self.last_opponent_cooperators = int(history.opponent_cooperators[-1]) if round_number > 0 else None
            return Action.D
        p = self._safe_p_from_history(history)
        self.last_p = p
        if round_number > 0:
            prev_coop = int(history.opponent_cooperators[-1])
            self.last_opponent_cooperators = prev_coop
            if prev_coop < self.n_opponents / 2.0:
                return Action.D
        score_c = self._score_action(float(current_stock), remaining_rounds, p, Action.C)
        score_d = self._score_action(float(current_stock), remaining_rounds, p, Action.D)
        if round_number > 0:
            prev_coop = int(history.opponent_cooperators[-1])
            if prev_coop >= max(0, self.n - 2):
                return Action.C if score_c > score_d else Action.D
        if round_number == 0:
            if abs(score_c - score_d) <= 1e-12:
                return Action.D
        return Action.C if score_c > score_d else Action.D

class Strategy_BENEVOLENT_57(BaseStrategy):
    """
    Default-to-cooperate common-pool strategy that defects only in severe scarcity
    when recent opponent cooperation has also been low.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(getattr(game_description, 'n_players', 0))
        self.n_rounds = int(getattr(game_description, 'n_rounds', 0))
        self.capacity = float(getattr(game_description, 'capacity', 0.0))
        self._n_opponents = max(self.n_players - 1, 0)
        self._scarcity_threshold = self.capacity / 6.0 if self.capacity > 0 else 0.0
        self._cooperation_threshold = math.floor(self._n_opponents / 3)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(getattr(history, 'round_number', 0))
        if round_number == 0:
            return Action.C
        if self.n_rounds > 0 and round_number >= self.n_rounds - 1:
            return Action.C
        if current_stock <= 0:
            return Action.C
        c = 0
        if hasattr(history, 'opponent_cooperators') and len(history.opponent_cooperators) > 0:
            c = int(history.opponent_cooperators[-1])
        if current_stock <= self._scarcity_threshold and c <= self._cooperation_threshold:
            return Action.D
        return Action.C

class Strategy_SELFINTERESTED_35(BaseStrategy):
    """
    Adaptive common-pool strategy:
    - Start cooperatively to preserve stock and learn baseline cooperation.
    - Defect in the final round.
    - Cooperate when stock is low or when cooperation weakens sharply.
    - Defect when stock is high and opponents have been consistently cooperative.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.capacity = float(game_description.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = int(history.round_number)
        n_opponents = max(self.n_players - 1, 1)
        if round_number >= self.n_rounds - 1:
            return Action.D
        if round_number == 0 or len(history.opponent_cooperators) == 0:
            return Action.C
        available_rounds = len(history.opponent_cooperators)
        h = min(3, available_rounds)
        if h <= 0:
            rho_t = None
        else:
            recent = history.opponent_cooperators[-h:].astype(float) / float(n_opponents)
            rho_t = float(np.mean(recent)) if len(recent) > 0 else None
        previous_smooth = None
        last_rate = None
        if available_rounds >= 2:
            last_rate = float(history.opponent_cooperators[-1]) / float(n_opponents)
            prev_h = min(3, available_rounds - 1)
            if prev_h > 0:
                prev_recent = history.opponent_cooperators[-(prev_h + 1):-1].astype(float) / float(n_opponents)
                previous_smooth = float(np.mean(prev_recent)) if len(prev_recent) > 0 else None
        if previous_smooth is not None and last_rate is not None and (last_rate <= previous_smooth - 0.25):
            if current_stock == 0:
                return Action.C
            return Action.C
        if current_stock == 0:
            return Action.C
        if current_stock <= 0.45 * self.capacity:
            return Action.C
        if rho_t is None:
            return Action.C
        if current_stock >= 0.75 * self.capacity and rho_t >= 0.8:
            return Action.D
        if rho_t > 0.6:
            return Action.D
        return Action.C